sub new {
    my ($class) = @_;
    my $config = DesertCMS::Config->load;
    my $db = DesertCMS::DB->new(config => $config);
    my $auth = DesertCMS::Auth->new(config => $config, db => $db);
    my $content = DesertCMS::Content->new(config => $config, db => $db);
    my $media = DesertCMS::Media->new(config => $config, db => $db);
    my $sites = DesertCMS::Sites->new(config => $config, db => $db);
    my $blueprints = DesertCMS::Blueprints->new(config => $config, db => $db);
    my $shop = DesertCMS::Shop->new(config => $config, db => $db);
    my $service_plans = DesertCMS::ServicePlans->new(config => $config, db => $db);
    my $forms = DesertCMS::Forms->new(config => $config, db => $db);
    my $events = DesertCMS::Events->new(config => $config, db => $db);
    my $directory = DesertCMS::Directory->new(config => $config, db => $db);
    my $bookings = DesertCMS::Bookings->new(config => $config, db => $db);
    my $donations = DesertCMS::Donations->new(config => $config, db => $db);
    my $testimonials = DesertCMS::Testimonials->new(config => $config, db => $db);
    my $membership = DesertCMS::Membership->new(config => $config, db => $db, media => $media);
    my $newsletter = DesertCMS::Newsletter->new(config => $config, db => $db);
    my $federation = DesertCMS::Federation->new(config => $config, db => $db);
    my $contributor_requests = DesertCMS::ContributorRequests->new(config => $config, db => $db);
    my $comments = DesertCMS::Comments->new(config => $config, db => $db);
    my $ratings = DesertCMS::Ratings->new(config => $config, db => $db);
    my $operations = DesertCMS::Operations->new(config => $config, db => $db, sites => $sites);
    my $notifications = DesertCMS::Notifications->new(config => $config, db => $db);
    my $accounts = DesertCMS::Accounts->new(config => $config, db => $db);
    my $forums = DesertCMS::Forums->new(config => $config, db => $db, notifications => $notifications);
    my $social = DesertCMS::Social->new(config => $config, db => $db, notifications => $notifications);
    my $live_streaming = DesertCMS::LiveStreaming->new(config => $config, db => $db, notifications => $notifications);
    my $security_center = DesertCMS::SecurityCenter->new(config => $config, db => $db);
    my $dashboard = DesertCMS::Dashboard->new(config => $config, db => $db);

    return bless {
        config   => $config,
        db       => $db,
        auth     => $auth,
        content  => $content,
        media    => $media,
        sites    => $sites,
        blueprints => $blueprints,
        shop     => $shop,
        service_plans => $service_plans,
        forms    => $forms,
        events   => $events,
        directory => $directory,
        bookings => $bookings,
        donations => $donations,
        testimonials => $testimonials,
        membership => $membership,
        newsletter => $newsletter,
        federation => $federation,
        contributor_requests => $contributor_requests,
        comments => $comments,
        ratings  => $ratings,
        operations => $operations,
        accounts => $accounts,
        forums => $forums,
        social => $social,
        live_streaming => $live_streaming,
        notifications => $notifications,
        security_center => $security_center,
        dashboard => $dashboard,
    }, $class;
}

sub run {
    my ($self) = @_;

    DesertCMS::HTTP->reset_response_state;
    eval {
        $self->{config}->app_secret;
        $self->{db}->migrate_if_needed;
        apply_openbsd_sandbox($self->{config}, $self->{db});
        my $request = DesertCMS::HTTP->read_request(
            max_body_bytes => $self->{config}->get('max_request_body_bytes'),
        );
        return $self->_request_too_large($request) if $request->{body_too_large};
        $self->_dispatch($request);
        1;
    } or do {
        return if DesertCMS::HTTP->response_sent;
        my $err = $@ || 'unknown error';
        my %headers = (
            'Content-Type' => 'text/plain; charset=utf-8',
            security_headers(),
        );
        DesertCMS::HTTP->response(
            status  => 500,
            headers => \%headers,
            body    => "Internal Server Error\n$err\n",
        );
    };
}

sub _dispatch {
    my ($self, $request) = @_;
    my $path = $request->{path};
    $path =~ s{/+$}{};
    if ($self->_is_shop_host($request)) {
        $path = '/' if $path eq '';
        $request->{path} = $path;
        return $self->_dispatch_shop($request, '');
    }
    $path = '/admin' if $path eq '';
    $request->{path} = $path;

    if ($path eq '/admin/assets/admin.css') {
        return $self->_admin_css;
    }
    if ($path eq '/admin/assets/editor.js') {
        return $self->_editor_js;
    }
    if ($path eq '/admin/assets/map.js') {
        return $self->_map_js;
    }
    if ($path eq '/stripe' || $path =~ m{^/stripe/}) {
        return $self->_dispatch_shop($request, '');
    }
    if ($path eq '/shop' || $path =~ m{^/shop/}) {
        return $self->_dispatch_shop($request, '/shop');
    }
    if ($path eq '/events.ics') {
        return $request->{method} eq 'GET'
            ? $self->_events_ics($request)
            : $self->_method_not_allowed;
    }
    if ($path eq '/events' || $path =~ m{^/events/}) {
        return $self->_dispatch_events($request);
    }
    if ($path eq '/directory' || $path =~ m{^/directory/}) {
        return $self->_dispatch_directory($request);
    }
    if ($path eq '/bookings' || $path =~ m{^/bookings/}) {
        return $self->_dispatch_bookings($request);
    }
    if ($path eq '/members' || $path =~ m{^/members/}) {
        return $self->_dispatch_members($request);
    }
    if ($path eq '/account' || $path =~ m{^/account/}) {
        return $self->_dispatch_accounts($request);
    }
    if ($path eq '/forums' || $path =~ m{^/forums/}) {
        return $self->_dispatch_forums($request);
    }
    if ($path eq '/social' || $path =~ m{^/social/}) {
        return $self->_dispatch_social($request);
    }
    if ($path eq '/live' || $path =~ m{^/live/}) {
        return $self->_dispatch_live($request);
    }
    if ($path eq '/newsletter' || $path =~ m{^/newsletter/}) {
        return $self->_dispatch_newsletter($request);
    }
    if ($path eq '/donate' || $path =~ m{^/donate/}) {
        return $self->_dispatch_donations($request);
    }
    if ($path eq '/testimonials' || $path =~ m{^/testimonials/}) {
        return $self->_dispatch_testimonials($request);
    }
    if ($path eq '/forms' || $path =~ m{^/forms/}) {
        return $self->_dispatch_forms($request);
    }
    if ($path eq '/billing/stripe/webhook') {
        return $request->{method} eq 'POST'
            ? $self->_service_plan_stripe_webhook($request)
            : $self->_method_not_allowed;
    }
    if ($path =~ m{^/contributors/profile/([0-9a-fA-F]{64})$}) {
        my $token = lc $1;
        my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
        return $self->_not_found unless DesertCMS::Modules::enabled($settings, 'contributor_requests');
        return $request->{method} eq 'POST'
            ? $self->_contributor_profile_submit($request, $token)
            : $self->_contributor_profile_form($request, $token);
    }
    if ($path eq '/analytics/collect') {
        return $self->_analytics_collect($request);
    }
    if ($path eq '/comments/thread') {
        return $self->_comments_thread($request);
    }
    if ($path eq '/comments/create') {
        return $self->_comments_create($request);
    }
    if ($path eq '/comments/notifications') {
        return $self->_comments_notifications($request);
    }
    if ($path eq '/ratings/summary') {
        return $self->_ratings_summary($request);
    }
    if ($path eq '/ratings/vote') {
        return $self->_ratings_vote($request);
    }
    if ($path =~ m{^/postmark/webhook/([0-9a-fA-F]{48})$}) {
        return $self->_postmark_webhook($request, lc $1);
    }
    if ($path =~ m{^/admin/invite/([0-9a-fA-F]{64})$}) {
        my $token = lc $1;
        return $request->{method} eq 'POST'
            ? $self->_invite_accept_post($request, $token)
            : $self->_invite_accept_get($request, $token);
    }
    if ($path eq '/admin/login') {
        return $request->{method} eq 'POST'
            ? $self->_login_post($request)
            : $self->_login_get($request);
    }
    if ($path eq '/admin/password/forgot') {
        return $request->{method} eq 'POST'
            ? $self->_forgot_password_post($request)
            : $self->_forgot_password_get($request);
    }
    if ($path =~ m{^/admin/password/reset/([0-9a-fA-F]{64})$}) {
        my $token = lc $1;
        return $request->{method} eq 'POST'
            ? $self->_password_reset_post($request, $token)
            : $self->_password_reset_get($request, $token);
    }
    if ($path eq '/admin/logout') {
        return $self->_require_post($request, sub { $self->_logout_post($request) });
    }
    if ($path eq '/admin/account/setup') {
        return $request->{method} eq 'POST'
            ? $self->_require_post($request, sub { $self->_first_login_save($request, @_) })
            : $self->_require_login($request, sub { $self->_first_login_form($request, @_) });
