    if ($path eq '/admin/settings/invites/send') {
        return $self->_require_post($request, sub { $self->_settings_invite_send($request, @_) });
    }
    if ($path eq '/admin/settings/invites/revoke') {
        return $self->_require_post($request, sub { $self->_settings_invite_revoke($request, @_) });
    }
    if ($path eq '/admin/settings/sites/action') {
        return $self->_require_post($request, sub { $self->_settings_site_action($request, @_) });
    }
    if ($path eq '/admin/settings/sites/grant') {
        return $self->_require_post($request, sub { $self->_settings_site_grant_access($request, @_) });
    }
    if ($path eq '/admin') {
        return $self->_require_login($request, sub { $self->_dashboard($request, @_) });
    }

    return $self->_not_found;
}

sub _login_get {
    my ($self, $request, $message) = @_;
    my $safe_message = $message ? '<p class="notice error">' . escape_html($message) . '</p>' : '';
    my $body = <<"HTML";
<section class="panel auth-panel">
  <h1>Admin Login</h1>
  $safe_message
  <form method="post" action="/admin/login" class="stack">
    <label>
      <span>Username</span>
      <input name="username" autocomplete="username" required>
    </label>
    <label>
      <span>Password</span>
      <input name="password" type="password" autocomplete="current-password" required>
    </label>
    <button type="submit">Sign in</button>
  </form>
  <p class="auth-help"><a href="/admin/password/forgot">Forgot password?</a></p>
</section>
HTML

    return $self->_html_response('Admin Login', $body);
}

sub _login_post {
    my ($self, $request) = @_;
    my $client_ip = DesertCMS::HTTP::client_ip($request, $self->{config});
    my ($user, $reason) = $self->{auth}->authenticate(
        username   => $request->param('username'),
        password   => $request->param('password'),
        ip_address => $client_ip,
    );

    if (!$user) {
        my $message = $reason && $reason eq 'locked'
            ? 'Too many failed login attempts. Try again later.'
            : 'Invalid username or password.';
        return $self->_login_get($request, $message);
    }

    my ($token) = $self->{auth}->create_session(
        user       => $user,
        ip_address => $client_ip,
        user_agent => $request->{user_agent},
    );

    my %headers = (
        security_headers(),
        'Set-Cookie' => DesertCMS::HTTP->cookie_header(
            name   => $self->{config}->get('session_cookie'),
            value  => $token,
            secure => $self->{config}->get('secure_cookies') ? 1 : 0,
        ),
    );

    return DesertCMS::HTTP->redirect('/admin', \%headers);
}

sub _forgot_password_get {
    my ($self, $request, $message) = @_;
    my $safe_message = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $body = <<"HTML";
<section class="panel auth-panel">
  <h1>Reset Password</h1>
  <p>Enter the email address attached to this admin account.</p>
  $safe_message
  <form method="post" action="/admin/password/forgot" class="stack">
    <label>
      <span>Email</span>
      <input name="email" type="email" autocomplete="email" required>
    </label>
    <button type="submit">Send reset link</button>
  </form>
  <p class="auth-help"><a href="/admin/login">Back to login</a></p>
</section>
HTML
    return $self->_html_response('Reset Password', $body);
}

sub _forgot_password_post {
    my ($self, $request) = @_;
    my $message = 'If that email matches an admin account, a reset link has been sent.';
    eval {
        my $reset = $self->{auth}->create_password_reset_token_for_email(
            email      => $request->param('email'),
            ip_address => DesertCMS::HTTP::client_ip($request, $self->{config}),
        );
        if ($reset) {
            my $url = $self->_absolute_admin_url('/admin/password/reset/' . $reset->{token});
            my ($sent, $reason) = $self->_send_password_reset_email($reset->{email}, $url);
            $message = 'Reset link created, but email was not sent: ' . $reason
                unless $sent;
        }
        1;
    };
    return $self->_forgot_password_get($request, $message);
}

sub _password_reset_get {
    my ($self, $request, $token, $message) = @_;
    my $reset = $self->{auth}->password_reset_from_token($token);
    my $body;
    if (!$reset) {
        $body = q{
<section class="panel auth-panel">
  <h1>Reset Link Expired</h1>
  <p>This reset link is invalid, expired, or already used.</p>
  <p class="auth-help"><a href="/admin/password/forgot">Request a new link</a></p>
</section>
};
        return $self->_html_response('Reset Link Expired', $body);
    }

    my $notice = $message ? '<p class="notice error">' . escape_html($message) . '</p>' : '';
    my $username = escape_html($reset->{username} || '');
    $body = <<"HTML";
<section class="panel auth-panel">
  <h1>Choose New Password</h1>
  $notice
  <form method="post" action="/admin/password/reset/$token" class="stack">
    <label>
      <span>Username</span>
      <input name="username" value="$username" autocomplete="username" required>
    </label>
    <label>
      <span>New password</span>
      <input name="password" type="password" autocomplete="new-password" required>
    </label>
    <label>
      <span>Confirm new password</span>
      <input name="password_confirm" type="password" autocomplete="new-password" required>
    </label>
    <button type="submit">Save password</button>
  </form>
</section>
HTML
    return $self->_html_response('Choose New Password', $body);
}

sub _password_reset_post {
    my ($self, $request, $token) = @_;
    my $password = $request->param('password') || '';
    my $confirm = $request->param('password_confirm') || '';
    return $self->_password_reset_get($request, $token, 'Passwords do not match.')
        if $password ne $confirm;

    my $ok = eval {
        $self->{auth}->consume_password_reset_token(
            token    => $token,
            username => $request->param('username'),
            password => $password,
        );
        1;
    };
    if (!$ok) {
        return $self->_password_reset_get(
            $request,
            $token,
            _admin_action_error(
                'The password could not be reset.',
                'Check the username and reset link, then try again or request a new reset link.',
                $@
            )
        );
    }
    return $self->_login_get($request, 'Password updated. Sign in with the new credentials.');
}

sub _logout_post {
    my ($self, $request) = @_;
    my $cookie_name = $self->{config}->get('session_cookie');
    my $token = $request->cookie($cookie_name);
    $self->{auth}->revoke_session($token) if $token;

    my %headers = (
        security_headers(),
        'Set-Cookie' => DesertCMS::HTTP->cookie_header(
            name    => $cookie_name,
            value   => '',
            secure  => $self->{config}->get('secure_cookies') ? 1 : 0,
            max_age => 0,
        ),
    );
    return DesertCMS::HTTP->redirect('/admin/login', \%headers);
}

sub _first_login_form {
    my ($self, $request, $session, $session_token, $message) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $username = escape_html($session->{username} || '');
    my $safe_message = $message ? '<p class="notice error">' . escape_html($message) . '</p>' : '';
    my $body = <<"HTML";
<section class="panel auth-panel">
  <p class="eyebrow">First login</p>
  <h1>Set your admin account</h1>
  <p>This temporary login must be changed before the admin area is available.</p>
  $safe_message
  <form method="post" action="/admin/account/setup" class="stack">
    <input type="hidden" name="csrf_token" value="$csrf">
    <label>
      <span>Admin username</span>
      <input name="username" value="$username" autocomplete="username" required>
    </label>
    <label>
      <span>New password</span>
      <input name="password" type="password" autocomplete="new-password" required>
    </label>
    <label>
      <span>Confirm new password</span>
      <input name="password_confirm" type="password" autocomplete="new-password" required>
    </label>
    <button type="submit">Save admin account</button>
  </form>
</section>
HTML

    return $self->_html_response('Set Admin Account', $body, $session);
}

sub _first_login_save {
    my ($self, $request, $session, $session_token) = @_;
    my $username = $request->param('username') || '';
    my $password = $request->param('password') || '';
    my $confirm = $request->param('password_confirm') || '';

    return $self->_first_login_form($request, $session, $session_token, 'Passwords do not match.')
        if $password ne $confirm;

    my $ok = eval {
        $self->{auth}->update_admin_credentials(
            user_id  => $session->{user_id},
            username => $username,
            password => $password,
        );
        1;
    };
    if (!$ok) {
        my $message = _admin_action_error(
            'The first admin account could not be saved.',
            'Check the username and password, then try again.',
            $@
        );
        return $self->_first_login_form($request, $session, $session_token, $message);
    }

    return DesertCMS::HTTP->redirect('/admin', { security_headers() });
}

sub _analytics_collect {
    my ($self, $request) = @_;
    return $self->_method_not_allowed unless $request->{method} eq 'POST';

    eval {
        DesertCMS::Analytics::record($self->{config}, $self->{db}, $request);
        1;
    };

    return DesertCMS::HTTP->response(
        status  => 204,
        headers => {
            'Cache-Control' => 'no-store',
            'Content-Type'  => 'text/plain; charset=utf-8',
        },
        body => '',
    );
}

sub _comments_thread {
    my ($self, $request) = @_;
    return $self->_method_not_allowed unless $request->{method} eq 'GET';

    my $thread = eval {
        $self->{comments}->thread(content_id => $request->param('content_id'));
    };
    if (!$thread) {
        return $self->_json_response(404, {
            ok    => 0,
            error => _clean_error($@ || 'comments unavailable'),
        });
    }
    return $self->_json_response(200, {
        ok => 1,
        %{$thread},
    });
}

sub _comments_create {
    my ($self, $request) = @_;
    return $self->_method_not_allowed unless $request->{method} eq 'POST';

    if (length($request->param('website') || '')) {
        return $self->_json_response(200, {
            ok => 1,
            ignored => 1,
        });
    }

    my $result = eval {
        $self->{comments}->create(
            content_id       => $request->param('content_id'),
            parent_id        => $request->param('parent_id'),
            author_name      => $request->param('author_name'),
            body             => $request->param('body'),
            commenter_token  => $request->param('commenter_token'),
            request          => $request,
        );
    };
    if (!$result) {
        my $message = _clean_error($@ || 'comment could not be posted');
        my $status = $message =~ /too many|please wait/i ? 429 : 400;
        return $self->_json_response($status, {
            ok    => 0,
            error => $message,
        });
    }
    return $self->_json_response(200, $result);
}

sub _comments_notifications {
    my ($self, $request) = @_;
    return $self->_method_not_allowed unless $request->{method} eq 'POST';

    my $result = eval {
        $self->{comments}->notifications(
            commenter_token => $request->param('commenter_token'),
        );
    };
    return $self->_json_response(200, $result || { replies => [] });
}

sub _ratings_summary {
    my ($self, $request) = @_;
    return $self->_method_not_allowed unless $request->{method} eq 'GET';

    my $result = eval {
        $self->{ratings}->summary(
            content_id => $request->param('content_id'),
            request    => $request,
        );
    };
    if (!$result) {
        return $self->_json_response(404, {
            ok    => 0,
            error => _clean_error($@ || 'ratings unavailable'),
        });
    }
    return $self->_json_response(200, {
        ok => 1,
        %{$result},
    });
}

sub _ratings_vote {
    my ($self, $request) = @_;
    return $self->_method_not_allowed unless $request->{method} eq 'POST';

    my $result = eval {
        $self->{ratings}->vote(
            content_id => $request->param('content_id'),
            rating     => $request->param('rating'),
            request    => $request,
        );
    };
    if (!$result) {
        my $message = _clean_error($@ || 'rating could not be saved');
        return $self->_json_response(400, {
            ok    => 0,
            error => $message,
        });
    }
    return $self->_json_response(200, {
        ok => 1,
        %{$result},
    });
}

sub _dispatch_shop {
    my ($self, $request, $prefix) = @_;
    return $self->_not_found unless $self->{shop}->enabled;

    my $path = $request->{path} || '/';
    $path =~ s{/+$}{};
    $path = '/' if $path eq '';

    my $route = $path;
    if (length($prefix || '')) {
        return $self->_not_found unless $path eq $prefix || $path =~ m{\A\Q$prefix\E/};
        $route =~ s{\A\Q$prefix\E}{};
        $route = '/' if $route eq '';
    }

    if ($route eq '/') {
        return $request->{method} eq 'GET'
            ? $self->_shop_catalog($request, $prefix)
            : $self->_method_not_allowed;
    }
    if ($route eq '/checkout') {
        return $request->{method} eq 'POST'
            ? $self->_shop_checkout($request, $prefix)
            : $self->_method_not_allowed;
    }
    if ($route eq '/success') {
        return $request->{method} eq 'GET'
            ? $self->_shop_success($request, $prefix)
            : $self->_method_not_allowed;
    }
    if ($route eq '/cancel') {
        return $request->{method} eq 'GET'
            ? $self->_shop_cancel($request, $prefix)
            : $self->_method_not_allowed;
    }
    if ($route eq '/stripe/webhook') {
        return $request->{method} eq 'POST'
            ? $self->_shop_stripe_webhook($request)
            : $self->_method_not_allowed;
    }

    return $self->_not_found;
}

sub _dispatch_events {
    my ($self, $request) = @_;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    return $self->_not_found unless DesertCMS::Modules::enabled($settings, 'events');

    my $path = $request->{path} || '/events';
    $path =~ s{/+$}{};
    $path = '/events' if $path eq '';

    if ($path eq '/events') {
        return $request->{method} eq 'GET'
            ? $self->_events_index($request)
            : $self->_method_not_allowed;
    }
    if ($path eq '/events/stripe/webhook') {
        return $request->{method} eq 'POST'
            ? $self->_events_stripe_webhook($request)
            : $self->_method_not_allowed;
    }
    if ($path =~ m{\A/events/([^/]+)/([0-9]{4}-[0-9]{2}-[0-9]{2})/(rsvp|checkout|success|cancel)\z}) {
        my ($slug, $date, $action) = ($1, $2, $3);
        return $request->{method} eq 'POST'
            ? $self->_events_rsvp($request, $slug, $date)
            : $self->_method_not_allowed
            if $action eq 'rsvp';
        return $request->{method} eq 'POST'
            ? $self->_events_checkout($request, $slug, $date)
            : $self->_method_not_allowed
            if $action eq 'checkout';
        return $request->{method} eq 'GET'
            ? $self->_events_success($request, $slug, $date)
            : $self->_method_not_allowed
            if $action eq 'success';
        return $request->{method} eq 'GET'
            ? $self->_events_cancel($request, $slug, $date)
            : $self->_method_not_allowed;
    }
    if ($path =~ m{\A/events/([^/]+)/([0-9]{4}-[0-9]{2}-[0-9]{2})\z}) {
        return $request->{method} eq 'GET'
            ? $self->_events_detail($request, $1, $2)
            : $self->_method_not_allowed;
    }
    if ($path =~ m{\A/events/([^/]+)\z}) {
        return $request->{method} eq 'GET'
            ? $self->_events_detail($request, $1, undef)
            : $self->_method_not_allowed;
    }

    return $self->_not_found;
}

sub _events_index {
    my ($self, $request, $message, $is_error) = @_;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $title = $settings->{events_title} || 'Events';
    my $intro = $settings->{events_intro} || 'Upcoming events, calendars, RSVP opportunities, tickets, and location details.';
    my $safe_title = escape_html($title);
    my $safe_intro = escape_html($intro);
    my $notice = '';
    if (defined $message && length $message) {
        my $class = $is_error ? 'events-notice is-error' : 'events-notice';
        my $role = $is_error ? 'alert' : 'status';
        $notice = '<p class="' . $class . '" role="' . $role . '">' . escape_html($message) . '</p>';
    }
    my $cards = '';
    my $events = $self->{events}->upcoming_occurrences(limit => 80);
    for my $row (@{$events}) {
        my $event = {
            title => $row->{title},
            slug => $row->{slug},
            timezone => $row->{timezone},
            all_day => $row->{all_day},
            feature_image_path => $row->{feature_image_path},
        };
        my $date = escape_html($row->{occurrence_key} || DesertCMS::Events::occurrence_key($event, $row->{starts_at}));
        my $url = '/events/' . escape_html($row->{slug}) . "/$date/";
        my $event_title = escape_html($row->{title} || 'Event');
        my $summary = escape_html($row->{summary} || '');
        my $time = escape_html(DesertCMS::Events::format_time_label($event, $row->{starts_at}, $row->{ends_at}));
        my $location = escape_html($row->{location_label} || '');
        my $location_html = length $location ? qq{<span>$location</span>} : '';
        my $image = $row->{feature_image_path} || '';
        my $image_html = $self->_public_media_img_tag(
            $image,
            '',
            class => 'public-media-img',
            sizes => '(max-width: 760px) 100vw, 360px',
        ) || '<div class="event-card-date" aria-hidden="true">' . $date . '</div>';
        $cards .= <<"HTML";
<a class="event-card" href="$url">
  $image_html
  <div class="event-card-body">
    <span class="event-time">$time</span>
    <h2>$event_title</h2>
    <p>$summary</p>
    $location_html
  </div>
</a>
HTML
    }
    $cards ||= '<p class="events-empty">No upcoming events yet.</p>';
    my $content = <<"HTML";
<article class="content module-page events-page events-shell">
  <header class="events-heading">
    <p class="kicker">Events</p>
    <h1>$safe_title</h1>
    <p class="module-intro">$safe_intro</p>
    <a class="module-action-link" href="/events.ics">Subscribe with calendar</a>
  </header>
  $notice
  <section class="events-grid" aria-label="Upcoming events">
    $cards
  </section>
</article>
HTML
    my $html = DesertCMS::Renderer::render_module_page($self->{config}, $self->{db}, {
        title       => $title,
        description => $intro,
        path        => '/events/',
        content     => $content,
        context     => 'events',
    });
    return DesertCMS::HTTP->response(
        status => $is_error ? 400 : 200,
        headers => {
            'Content-Type' => 'text/html; charset=utf-8',
            security_headers(),
        },
        body => $html,
    );
}

sub _events_detail {
    my ($self, $request, $slug, $date, $message, $is_error) = @_;
    my $event = $self->{events}->by_slug($slug) or return $self->_not_found;
    my $occurrence = $date
        ? $self->{events}->occurrence_for_slug_date($slug, $date)
        : $self->{events}->occurrences_for_event($event->{id}, from => now() - 86400, limit => 1)->[0];
    $occurrence ||= $self->{events}->occurrences_for_event($event->{id}, limit => 1)->[0];
    return $self->_not_found unless $occurrence;

    my $occurrence_key = $occurrence->{occurrence_key} || DesertCMS::Events::occurrence_key($event, $occurrence->{starts_at});
    my $title = escape_html($event->{title} || 'Event');
    my $summary = escape_html($event->{summary} || '');
    my $body = escape_html($event->{body} || '');
    $body =~ s/\n/<br>/g;
    my $time = escape_html(DesertCMS::Events::format_time_label($event, $occurrence->{starts_at}, $occurrence->{ends_at}));
    my $recurrence = escape_html(DesertCMS::Events::recurrence_summary($event));
    my $location = escape_html($event->{location_label} || '');
    my $location_html = length $location ? qq{<div><dt>Location</dt><dd>$location</dd></div>} : '';
    my $map_link = '';
    if ($event->{location_enabled} && defined $event->{location_lat} && defined $event->{location_lng}) {
        my $lat = escape_html($event->{location_lat});
        my $lng = escape_html($event->{location_lng});
        $map_link = qq{<div><dt>Map</dt><dd><a href="/map/">View location</a><small>$lat, $lng</small></dd></div>};
    }
    my $notice = '';
    if (defined $message && length $message) {
        my $class = $is_error ? 'events-notice is-error' : 'events-notice';
        my $role = $is_error ? 'alert' : 'status';
        $notice = '<p class="' . $class . '" role="' . $role . '">' . escape_html($message) . '</p>';
    }
    my $rsvp_form = '';
    if ($event->{rsvp_enabled}) {
        my $counts = $self->{events}->rsvp_counts($event->{id}, $occurrence->{id});
        my $capacity = int($event->{rsvp_capacity} || 0);
        my $capacity_label = $capacity
            ? int($counts->{confirmed} || 0) . " / $capacity confirmed"
            : int($counts->{confirmed} || 0) . ' confirmed';
        my $action = '/events/' . escape_html($event->{slug}) . '/' . escape_html($occurrence_key) . '/rsvp';
        $rsvp_form = <<"HTML";
<section class="event-action-panel">
  <h2>RSVP</h2>
  <p class="muted">$capacity_label</p>
  <form method="post" action="$action" class="public-form event-rsvp-form">
    <div class="public-form-grid">
      <label class="public-field">
        <span>Name</span>
        <input name="name" maxlength="100" required>
      </label>
      <label class="public-field">
        <span>Email</span>
        <input name="email" type="email" maxlength="180" required>
      </label>
      <label class="public-field">
        <span>Guest count</span>
        <input name="guest_count" type="number" min="1" max="100" value="1">
      </label>
    </div>
    <label class="public-field public-field--full">
      <span>Notes</span>
      <textarea name="notes" rows="4" maxlength="1000"></textarea>
    </label>
    <label class="comment-honeypot">
      <span>Website</span>
      <input name="website" tabindex="-1" autocomplete="off">
    </label>
    <button type="submit">Send RSVP</button>
  </form>
</section>
HTML
    }
    my $ticket_panel = _events_ticket_panel($self, $event, $occurrence, $occurrence_key);
    my $schema = _event_schema_json($self->{config}, $event, $occurrence);
    my $content = <<"HTML";
<article class="content module-page events-page event-detail">
  <p class="kicker">Events</p>
  <h1>$title</h1>
  <p class="module-intro">$summary</p>
  $notice
  <dl class="event-meta">
    <div><dt>When</dt><dd>$time</dd></div>
    <div><dt>Repeats</dt><dd>$recurrence</dd></div>
    $location_html
    $map_link
  </dl>
  <div class="body event-body"><p>$body</p></div>
  $rsvp_form
  $ticket_panel
  <p><a href="/events/">Back to events</a></p>
  <script type="application/ld+json">$schema</script>
</article>
HTML
    my $html = DesertCMS::Renderer::render_module_page($self->{config}, $self->{db}, {
        title       => $event->{title},
        description => $event->{summary},
        path        => '/events/' . $event->{slug} . '/' . $occurrence_key . '/',
        content     => $content,
        context     => 'events',
    });
    return DesertCMS::HTTP->response(
        status => $is_error ? 400 : 200,
        headers => {
            'Content-Type' => 'text/html; charset=utf-8',
            security_headers(),
        },
        body => $html,
    );
}

sub _events_ticket_panel {
    my ($self, $event, $occurrence, $occurrence_key) = @_;
    return '' unless $event->{ticketing_enabled};
    my $tickets = $self->{events}->ticket_types($event->{id}, active_only => 1);
    return '<section class="event-action-panel"><h2>Tickets</h2><p class="events-empty">No tickets are available yet.</p></section>' unless @{$tickets};
    my $checkout_ready = $self->{events}->checkout_ready;
    my $action = '/events/' . escape_html($event->{slug}) . '/' . escape_html($occurrence_key) . '/checkout';
    my $rows = '';
    for my $ticket (@{$tickets}) {
        my $id = int($ticket->{id});
        my $name = escape_html($ticket->{name} || 'Ticket');
        my $description = escape_html($ticket->{description} || '');
        my $price = escape_html(DesertCMS::Events::price_label($ticket->{price_cents}, $ticket->{currency}));
        my $button = '';
        if ($checkout_ready && int($ticket->{price_cents} || 0) > 0) {
            $button = <<"HTML";
<form method="post" action="$action" class="event-ticket-form">
  <input type="hidden" name="ticket_type_id" value="$id">
  <label>
    <span>Quantity</span>
    <input name="quantity" type="number" min="1" max="20" value="1">
  </label>
  <label>
    <span>Email</span>
    <input name="customer_email" type="email" maxlength="180">
  </label>
  <button type="submit">Buy ticket</button>
</form>
HTML
        } elsif (int($ticket->{price_cents} || 0) > 0) {
            $button = '<p class="events-notice">Paid tickets are not available on this plan or payment setup.</p>';
        } else {
            $button = '<p class="muted">Free ticket. Use RSVP above to reserve a spot.</p>';
        }
        $rows .= <<"HTML";
<article class="event-ticket-option">
  <div>
    <strong>$name</strong>
    <span>$price</span>
    <p>$description</p>
  </div>
  $button
</article>
HTML
    }
    return <<"HTML";
<section class="event-action-panel">
  <h2>Tickets</h2>
  <div class="event-ticket-grid">$rows</div>
</section>
HTML
}

sub _events_rsvp {
    my ($self, $request, $slug, $date) = @_;
    my $event = $self->{events}->by_slug($slug) or return $self->_not_found;
    my $occurrence = $self->{events}->occurrence_for_slug_date($slug, $date) or return $self->_not_found;
    if (length($request->param('website') || '')) {
        return $self->_events_detail($request, $slug, $date, 'Thanks. Your RSVP has been received.', 0);
    }
    my $rsvp = eval {
        $self->{events}->submit_rsvp(
            event_id      => $event->{id},
            occurrence_id => $occurrence->{id},
            name          => $request->param('name'),
            email         => $request->param('email'),
            guest_count   => $request->param('guest_count'),
            notes         => $request->param('notes'),
            website       => $request->param('website'),
            request       => $request,
        );
    };
    return $self->_events_detail(
        $request,
        $slug,
        $date,
        $rsvp
            ? (($rsvp->{status} || '') eq 'waitlist' ? 'Thanks. You have been added to the waitlist.' : 'Thanks. Your RSVP has been confirmed.')
            : _admin_action_error('Your RSVP could not be sent.', 'Check the required fields and try again.', $@),
        $rsvp ? 0 : 1
    );
}

sub _events_checkout {
    my ($self, $request, $slug, $date) = @_;
    my $event = $self->{events}->by_slug($slug) or return $self->_not_found;
    my $occurrence = $self->{events}->occurrence_for_slug_date($slug, $date) or return $self->_not_found;
    my $checkout = eval {
        $self->{events}->create_checkout(
            event_id        => $event->{id},
            occurrence_id   => $occurrence->{id},
            ticket_type_id  => $request->param('ticket_type_id'),
            quantity        => $request->param('quantity'),
            customer_email  => $request->param('customer_email'),
            customer_name   => $request->param('customer_name'),
        );
    };
    return $checkout
        ? DesertCMS::HTTP->redirect($checkout->{url}, { security_headers() })
        : $self->_events_detail(
            $request,
            $slug,
            $date,
            _admin_action_error('Ticket checkout could not be started.', 'Choose an available ticket and try again.', $@),
            1
        );
}

sub _events_success {
    my ($self, $request, $slug, $date) = @_;
    my $order = $self->{events}->order($request->param('order'));
    my $back = escape_html('/events/' . $slug . '/' . $date . '/');
    my $body;
    if (!$order) {
        $body = <<"HTML";
<section class="events-shell event-message">
  <p class="kicker">Events</p>
  <h1>Order Not Found</h1>
  <p>This checkout could not be matched to an event ticket order.</p>
  <a class="shop-button" href="$back">Return to event</a>
</section>
HTML
        return $self->_shop_html_response('Order Not Found', $body, $back, 'Event ticket checkout status.');
    }
    my $title = escape_html($order->{event_title} || 'Event');
    my $ticket = escape_html($order->{ticket_name} || 'Ticket');
    my $status = escape_html($order->{status} || 'pending');
    my $total = escape_html(DesertCMS::Events::price_label($order->{amount_cents}, $order->{currency}));
    $body = <<"HTML";
<section class="events-shell event-message">
  <p class="kicker">Events</p>
  <h1>Thank You</h1>
  <dl class="shop-summary">
    <div><dt>Event</dt><dd>$title</dd></div>
    <div><dt>Ticket</dt><dd>$ticket</dd></div>
    <div><dt>Total</dt><dd>$total</dd></div>
    <div><dt>Status</dt><dd>$status</dd></div>
  </dl>
  <p>Stripe is confirming the payment. Confirmed ticket orders are added to the attendee list.</p>
  <a class="shop-button" href="$back">Return to event</a>
</section>
HTML
    return $self->_shop_html_response('Thank You', $body, $back, 'Event ticket checkout status.');
}

sub _events_cancel {
    my ($self, $request, $slug, $date) = @_;
    my $back = escape_html('/events/' . $slug . '/' . $date . '/');
    my $body = <<"HTML";
<section class="events-shell event-message">
  <p class="kicker">Events</p>
  <h1>Checkout Canceled</h1>
  <p>No ticket payment was recorded.</p>
  <a class="shop-button" href="$back">Return to event</a>
</section>
HTML
    return $self->_shop_html_response('Checkout Canceled', $body, $back, 'Event ticket checkout status.');
}

sub _events_stripe_webhook {
    my ($self, $request) = @_;
    my $ok = eval {
        $self->{events}->handle_webhook(
            payload   => $request->{body},
            signature => $request->{stripe_signature},
        );
        1;
    };
    return DesertCMS::HTTP->response(
        status  => $ok ? 200 : 400,
        headers => {
            'Content-Type' => 'application/json; charset=utf-8',
            'Cache-Control' => 'no-store',
        },
        body => encode_json({ ok => $ok ? 1 : 0 }),
    );
}

sub _events_ics {
    my ($self, $request) = @_;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    return $self->_not_found unless DesertCMS::Modules::enabled($settings, 'events');
    my $site_url = $self->{config}->get('site_url') || '';
    $site_url =~ s{/+\z}{};
    my $body = "BEGIN:VCALENDAR\r\nVERSION:2.0\r\nPRODID:-//DesertCMS//Events//EN\r\nCALSCALE:GREGORIAN\r\n";
    for my $row (@{ $self->{events}->upcoming_occurrences(limit => 500) }) {
        my $event = {
            title => $row->{title},
            slug => $row->{slug},
            timezone => $row->{timezone},
            all_day => $row->{all_day},
        };
        my $key = $row->{occurrence_key} || DesertCMS::Events::occurrence_key($event, $row->{starts_at});
        my $url = $site_url . '/events/' . ($row->{slug} || '') . "/$key/";
        $body .= "BEGIN:VEVENT\r\n";
        $body .= 'UID:event-' . int($row->{id}) . '@desertcms' . "\r\n";
        $body .= 'DTSTAMP:' . _ics_utc(time) . "\r\n";
        if ($row->{all_day}) {
            $body .= 'DTSTART;VALUE=DATE:' . _ics_date($row->{starts_at}, $row->{timezone}) . "\r\n";
            $body .= 'DTEND;VALUE=DATE:' . _ics_date($row->{ends_at}, $row->{timezone}) . "\r\n";
        } else {
            $body .= 'DTSTART:' . _ics_utc($row->{starts_at}) . "\r\n";
            $body .= 'DTEND:' . _ics_utc($row->{ends_at}) . "\r\n";
        }
        $body .= 'SUMMARY:' . _ics_text($row->{title} || 'Event') . "\r\n";
        $body .= 'DESCRIPTION:' . _ics_text($row->{summary} || '') . "\r\n" if length($row->{summary} || '');
        $body .= 'LOCATION:' . _ics_text($row->{location_label} || '') . "\r\n" if length($row->{location_label} || '');
        $body .= 'URL:' . _ics_text($url) . "\r\n";
        $body .= "END:VEVENT\r\n";
    }
    $body .= "END:VCALENDAR\r\n";
    return DesertCMS::HTTP->response(
        status => 200,
        headers => {
            'Content-Type' => 'text/calendar; charset=utf-8',
            security_headers(),
        },
        body => $body,
    );
}

sub _dispatch_directory {
    my ($self, $request) = @_;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    return $self->_not_found unless DesertCMS::Modules::enabled($settings, 'directory');
    my $path = $request->{path} || '/directory';
    $path =~ s{/+$}{};
    $path = '/directory' if $path eq '';

    if ($path eq '/directory') {
        return $request->{method} eq 'GET'
            ? $self->_directory_index($request, $settings)
            : $self->_method_not_allowed;
    }
    if ($path eq '/directory/submit') {
        return $self->_not_found unless _setting_truthy($settings->{directory_submissions_enabled});
        return $request->{method} eq 'POST'
            ? $self->_directory_submit($request, $settings)
            : ($request->{method} eq 'GET'
                ? $self->_directory_submit_page($request, $settings)
                : $self->_method_not_allowed);
    }
    if ($path =~ m{\A/directory/([^/]+)\z}) {
        return $request->{method} eq 'GET'
            ? $self->_directory_detail($request, $settings, $1)
            : $self->_method_not_allowed;
    }
    return $self->_not_found;
}

sub _directory_index {
    my ($self, $request, $settings, $message, $is_error) = @_;
    my $title = $settings->{directory_title} || 'Directory';
    my $intro = $settings->{directory_intro} || 'People, businesses, artists, contributors, vendors, members, places, organizations, and resources.';
    my $kind = $request ? ($request->param('kind') || '') : '';
    my $entries = $self->{directory}->published_entries(kind => $kind, limit => 500);
    my $kind_nav = _directory_public_kind_nav($self->{directory}->public_kinds, $kind);
    my $cards = join '', map { $self->_directory_public_card($_) } @{$entries};
    $cards ||= '<p class="events-empty">No directory entries yet.</p>';
    my $notice = $message ? '<p class="' . ($is_error ? 'events-notice is-error' : 'events-notice') . '">' . escape_html($message) . '</p>' : '';
    my $submit = _setting_truthy($settings->{directory_submissions_enabled})
        ? '<a class="module-action-link" href="/directory/submit/">Suggest a listing</a>'
        : '';
    my $safe_title = escape_html($title);
    my $safe_intro = escape_html($intro);
    my $body = <<"HTML";
<article class="content module-page directory-page directory-shell">
  <header class="events-heading">
    <p class="kicker">Directory</p>
    <h1>$safe_title</h1>
    <p class="module-intro">$safe_intro</p>
    $submit
  </header>
  $notice
  $kind_nav
  <section class="events-grid directory-grid" aria-label="Directory entries">
    $cards
  </section>
</article>
HTML
    return $self->_public_module_response(
        title       => $title,
        description => $intro,
        path        => '/directory/',
        content     => $body,
        context     => 'directory',
        status      => $is_error ? 400 : 200,
    );
}

sub _directory_detail {
    my ($self, $request, $settings, $slug, $message, $is_error) = @_;
    my $entry = $self->{directory}->by_slug($slug) or return $self->_not_found;
    my $title = escape_html($entry->{title} || 'Directory entry');
    my $summary = escape_html($entry->{summary} || '');
    my $kind = escape_html(DesertCMS::Directory::kind_label($entry->{kind}));
    my $body_text = escape_html($entry->{body} || '');
    $body_text =~ s/\n/<br>/g;
    my $image = $entry->{image_path} || '';
    my $image_html = $self->_public_media_img_tag(
        $image,
        '',
        class => 'directory-detail-image public-media-img',
        loading => 'eager',
        sizes => '(max-width: 760px) 100vw, 720px',
    );
    my $contact = _directory_contact_html($entry);
    my $terms = _directory_terms_html($entry);
    my $location = _directory_location_html($entry);
    my $notice = $message ? '<p class="' . ($is_error ? 'events-notice is-error' : 'events-notice') . '">' . escape_html($message) . '</p>' : '';
    my $body = <<"HTML";
<article class="content module-page directory-page directory-detail">
  <p class="kicker">$kind</p>
  <h1>$title</h1>
  <p class="module-intro">$summary</p>
  $notice
  $image_html
  <div class="body directory-body"><p>$body_text</p></div>
  $contact
  $location
  $terms
  <p><a href="/directory/">Back to directory</a></p>
</article>
HTML
    return $self->_public_module_response(
        title       => $entry->{title} || 'Directory entry',
        description => $entry->{summary} || '',
        path        => '/directory/' . ($entry->{slug} || '') . '/',
        content     => $body,
        context     => 'directory',
        status      => $is_error ? 400 : 200,
    );
}

sub _directory_submit_page {
    my ($self, $request, $settings, $message, $is_error) = @_;
    my $notice = $message ? '<p class="' . ($is_error ? 'events-notice is-error' : 'events-notice') . '">' . escape_html($message) . '</p>' : '';
    my $kind_options = _directory_kind_options('other');
    my $location_options = _location_kind_options('other');
    my $body = <<"HTML";
<article class="content module-page directory-page directory-submit">
  <p class="kicker">Directory</p>
  <h1>Suggest a Listing</h1>
  <p class="module-intro">Share a person, business, artist, vendor, member, place, organization, or resource for review.</p>
  $notice
  <form method="post" action="/directory/submit/" class="public-form">
    <div class="public-form-grid">
      <label class="public-field"><span>Name</span><input name="title" required maxlength="180"></label>
      <label class="public-field"><span>Type</span><select name="kind">$kind_options</select></label>
      <label class="public-field"><span>Email</span><input name="email" type="email" maxlength="180"></label>
      <label class="public-field"><span>Website</span><input name="website_url" type="url" maxlength="500"></label>
    </div>
    <label class="public-field public-field--full"><span>Summary</span><textarea name="summary" rows="3" maxlength="500"></textarea></label>
    <label class="public-field public-field--full"><span>Notes for review</span><textarea name="submission_note" rows="4" maxlength="1000"></textarea></label>
    <fieldset class="public-field public-field--full">
      <legend>Optional location</legend>
      <label><input type="checkbox" name="location_enabled" value="1"> Include on Map / Locations</label>
      <div class="public-form-grid">
        <label class="public-field"><span>Location label</span><input name="location_label" maxlength="300"></label>
        <label class="public-field"><span>Location type</span><select name="location_kind">$location_options</select></label>
        <label class="public-field"><span>Latitude</span><input name="location_lat" inputmode="decimal"></label>
        <label class="public-field"><span>Longitude</span><input name="location_lng" inputmode="decimal"></label>
      </div>
    </fieldset>
    <label class="comment-honeypot"><span>Website</span><input name="website" tabindex="-1" autocomplete="off"></label>
    <button type="submit">Submit for review</button>
  </form>
</article>
HTML
    return $self->_public_module_response(
        title       => 'Suggest a Listing',
        description => 'Suggest a directory listing for review.',
        path        => '/directory/submit/',
        content     => $body,
        context     => 'directory',
        status      => $is_error ? 400 : 200,
    );
}

sub _directory_submit {
    my ($self, $request, $settings) = @_;
    return $self->_directory_submit_page($request, $settings, 'Thanks. Your listing suggestion has been received for review.', 0)
        if length($request->param('website') || '');
    my $ok = eval {
        $self->{directory}->submit_public(
            _directory_entry_args_from_request($request),
            ip_address => $request->{remote_addr} || '',
            user_agent => $request->{user_agent} || '',
        );
        1;
    };
    return $ok
        ? $self->_directory_index($request, $settings, 'Thanks. Your listing suggestion has been received for review.', 0)
        : $self->_directory_submit_page(
            $request,
            $settings,
            _admin_action_error('The listing suggestion could not be received.', 'Check the required name, email, website, and location fields, then try again.', $@),
            1
        );
}

sub _directory_public_kind_nav {
    my ($kinds, $active) = @_;
    return '' unless @{$kinds || []};
    my $html = '<nav class="editor-nav directory-kind-nav" aria-label="Directory types"><a href="/directory/"' . (length($active || '') ? '' : ' class="active"') . '>All</a>';
    for my $row (@{$kinds}) {
        my $kind = $row->{kind} || 'other';
        my $label = escape_html(DesertCMS::Directory::kind_label($kind));
        my $count = int($row->{count} || 0);
        my $class = $kind eq ($active || '') ? ' class="active"' : '';
        $html .= qq{<a href="/directory/?kind=$kind"$class>$label <span>$count</span></a>};
    }
    $html .= '</nav>';
    return $html;
}

sub _directory_public_card {
    my ($self, $entry) = @_;
    my $slug = escape_html($entry->{slug} || '');
    my $title = escape_html($entry->{title} || 'Directory entry');
    my $summary = escape_html($entry->{summary} || '');
    my $kind = escape_html(DesertCMS::Directory::kind_label($entry->{kind}));
    my $image = $entry->{image_path} || '';
    my $image_html = $self->_public_media_img_tag(
        $image,
        '',
        class => 'public-media-img',
        sizes => '(max-width: 760px) 100vw, 360px',
    ) || '<div class="event-card-date" aria-hidden="true">' . substr($kind, 0, 1) . '</div>';
    my $location = escape_html($entry->{location_label} || '');
    my $location_html = length $location ? qq{<span>$location</span>} : '';
    return <<"HTML";
<a class="event-card directory-card" href="/directory/$slug/">
  $image_html
  <div class="event-card-body">
    <span class="event-time">$kind</span>
    <h2>$title</h2>
    <p>$summary</p>
    $location_html
  </div>
</a>
HTML
}

sub _directory_contact_html {
    my ($entry) = @_;
    my @items;
    push @items, [ 'Email', '<a href="mailto:' . escape_html($entry->{email}) . '">' . escape_html($entry->{email}) . '</a>' ] if length($entry->{email} || '');
    push @items, [ 'Phone', escape_html($entry->{phone}) ] if length($entry->{phone} || '');
    push @items, [ 'Website', '<a href="' . escape_html($entry->{website_url}) . '">' . escape_html($entry->{website_url}) . '</a>' ] if length($entry->{website_url} || '');
    push @items, [ 'Social', '<a href="' . escape_html($entry->{social_url}) . '">' . escape_html($entry->{social_url}) . '</a>' ] if length($entry->{social_url} || '');
    return '' unless @items;
    my $rows = join '', map { '<div><dt>' . escape_html($_->[0]) . '</dt><dd>' . $_->[1] . '</dd></div>' } @items;
    return qq{<dl class="event-meta directory-meta">$rows</dl>};
}

sub _directory_location_html {
    my ($entry) = @_;
    my @items;
    push @items, [ 'Address', escape_html($entry->{address}) ] if length($entry->{address} || '');
    push @items, [ 'Location', escape_html($entry->{location_label}) ] if length($entry->{location_label} || '');
    if ($entry->{location_enabled} && defined $entry->{location_lat} && defined $entry->{location_lng}) {
        push @items, [ 'Map', '<a href="/map/">View location</a><small>' . escape_html($entry->{location_lat}) . ', ' . escape_html($entry->{location_lng}) . '</small>' ];
    }
    return '' unless @items;
    my $rows = join '', map { '<div><dt>' . escape_html($_->[0]) . '</dt><dd>' . $_->[1] . '</dd></div>' } @items;
    return qq{<dl class="event-meta directory-meta">$rows</dl>};
}

sub _directory_terms_html {
    my ($entry) = @_;
    my @terms = grep { length } ($entry->{categories_text} || '', $entry->{tags_text} || '');
    return '' unless @terms;
    my $html = join '', map { '<span>' . escape_html($_) . '</span>' } map { split /\s*,\s*/, $_ } @terms;
    return qq{<div class="docs-card-tags directory-tags">$html</div>};
}

sub _dispatch_bookings {
    my ($self, $request) = @_;
    my $path = $request->{path} || '/bookings';
    $path =~ s{/+$}{};
    $path = '/bookings' if $path eq '';
    if ($path eq '/bookings/stripe/webhook') {
        return $request->{method} eq 'POST'
            ? $self->_bookings_stripe_webhook($request)
            : $self->_method_not_allowed;
    }

    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    return $self->_not_found unless DesertCMS::Modules::enabled($settings, 'bookings');

    if ($path eq '/bookings') {
        return $request->{method} eq 'GET'
            ? $self->_bookings_index($request, $settings)
            : $self->_method_not_allowed;
    }
    if ($path =~ m{\A/bookings/([^/]+)/request/([0-9]+)/(success|cancel)\z}) {
        my ($slug, $payment_id, $state) = ($1, $2, $3);
        return $request->{method} eq 'GET'
            ? ($state eq 'success'
                ? $self->_booking_deposit_success($request, $slug, $payment_id)
                : $self->_booking_deposit_cancel($request, $slug, $payment_id))
            : $self->_method_not_allowed;
    }
    if ($path =~ m{\A/bookings/([^/]+)/request\z}) {
        return $request->{method} eq 'POST'
            ? $self->_booking_request_submit($request, $settings, $1)
            : $self->_method_not_allowed;
    }
    if ($path =~ m{\A/bookings/([^/]+)\z}) {
        return $request->{method} eq 'GET'
            ? $self->_bookings_detail($request, $settings, $1)
            : $self->_method_not_allowed;
    }
    return $self->_not_found;
}

sub _bookings_index {
    my ($self, $request, $settings, $message, $is_error) = @_;
    my $title = $settings->{bookings_title} || 'Bookings';
    my $intro = $settings->{bookings_intro} || 'Request appointments, consultations, service sessions, venue time, or project meetings.';
    my $services = $self->{bookings}->published_services(limit => 500);
    my $cards = join '', map { $self->_booking_public_card($_) } @{$services};
    $cards ||= '<p class="events-empty">No booking services are available yet.</p>';
    my $notice = $message ? '<p class="' . ($is_error ? 'events-notice is-error' : 'events-notice') . '">' . escape_html($message) . '</p>' : '';
    my $safe_title = escape_html($title);
    my $safe_intro = escape_html($intro);
    my $body = <<"HTML";
<article class="content module-page bookings-page bookings-shell">
  <header class="events-heading">
    <p class="kicker">Bookings</p>
    <h1>$safe_title</h1>
    <p class="module-intro">$safe_intro</p>
  </header>
  $notice
  <section class="events-grid bookings-grid" aria-label="Booking services">
    $cards
  </section>
</article>
HTML
    return $self->_public_module_response(
        title       => $title,
        description => $intro,
        path        => '/bookings/',
        content     => $body,
        context     => 'bookings',
        status      => $is_error ? 400 : 200,
    );
}

sub _bookings_detail {
    my ($self, $request, $settings, $slug, $message, $is_error) = @_;
    my $service = $self->{bookings}->service_by_slug($slug) or return $self->_not_found;
    my $title = escape_html($service->{title} || 'Booking service');
    my $summary = escape_html($service->{summary} || '');
    my $kind = escape_html(DesertCMS::Bookings::service_kind_label($service->{service_kind}));
    my $body_text = escape_html($service->{body} || '');
    $body_text =~ s/\n/<br>/g;
    my $availability = escape_html($service->{availability_text} || '');
    $availability =~ s/\n/<br>/g;
    my $image = $service->{image_path} || '';
    my $image_html = $self->_public_media_img_tag(
        $image,
        '',
        class => 'directory-detail-image public-media-img',
        loading => 'eager',
        sizes => '(max-width: 760px) 100vw, 720px',
    );
    my $meta = _booking_public_meta($service);
    my $notice = $message ? '<p class="' . ($is_error ? 'events-notice is-error' : 'events-notice') . '">' . escape_html($message) . '</p>' : '';
    my $form = _booking_public_request_form($self, $service, $settings);
    my $availability_html = length $availability
        ? qq{<section class="event-action-panel"><h2>Availability</h2><p>$availability</p></section>}
        : '';
    my $body = <<"HTML";
<article class="content module-page bookings-page booking-detail">
  <p class="kicker">$kind</p>
  <h1>$title</h1>
  <p class="module-intro">$summary</p>
  $notice
  $image_html
  $meta
  <div class="body directory-body"><p>$body_text</p></div>
  $availability_html
  $form
  <p><a href="/bookings/">Back to bookings</a></p>
</article>
HTML
    return $self->_public_module_response(
        title       => $service->{title} || 'Booking service',
        description => $service->{summary} || '',
        path        => '/bookings/' . ($service->{slug} || '') . '/',
        content     => $body,
        context     => 'bookings',
        status      => $is_error ? 400 : 200,
    );
}

sub _booking_request_submit {
    my ($self, $request, $settings, $slug) = @_;
    my $service = $self->{bookings}->service_by_slug($slug) or return $self->_not_found;
    return $self->_bookings_detail($request, $settings, $slug, 'Thanks. Your booking request has been received for review.', 0)
        if length($request->param('website') || '');
    my $created = eval {
        $self->{bookings}->submit_request(
            _booking_request_args_from_request($request),
            service_id  => $service->{id},
            request     => $request,
            ip_address  => $request->{remote_addr} || '',
            user_agent  => $request->{user_agent} || '',
        );
    };
    if (!$created) {
        return $self->_bookings_detail(
            $request,
            $settings,
            $slug,
            _admin_action_error('The booking request could not be received.', 'Check your name, email, requested date, and notes, then try again.', $@),
            1
        );
    }
    if ($service->{deposit_enabled} && int($service->{deposit_amount_cents} || 0) > 0 && $self->{bookings}->checkout_ready) {
        my $checkout = eval { $self->{bookings}->create_deposit_checkout(request_id => $created->{id}) };
        return DesertCMS::HTTP->redirect($checkout->{url}, { security_headers() }) if $checkout && $checkout->{url};
        return $self->_bookings_detail(
            $request,
            $settings,
            $slug,
            'Your request was received, but deposit checkout could not start. The site owner can still review the request.',
            1
        );
    }
    return $self->_bookings_index($request, $settings, 'Thanks. Your booking request has been received for review.', 0);
}

sub _booking_deposit_success {
    my ($self, $request, $slug, $payment_id) = @_;
    my $payment = $self->{bookings}->payment_by_id($payment_id) or return $self->_not_found;
    return $self->_not_found unless ($payment->{service_slug} || '') eq $slug;
    my $title = escape_html($payment->{service_title} || 'Booking');
    my $status = escape_html($payment->{status} || 'pending');
    my $total = escape_html(DesertCMS::Bookings::price_label($payment->{amount_cents}, $payment->{currency}));
    my $back = escape_html('/bookings/' . $slug . '/');
    my $body = <<"HTML";
<section class="events-shell booking-message">
  <p class="kicker">Bookings</p>
  <h1>Request Received</h1>
  <dl class="shop-summary">
    <div><dt>Service</dt><dd>$title</dd></div>
    <div><dt>Deposit</dt><dd>$total</dd></div>
    <div><dt>Status</dt><dd>$status</dd></div>
  </dl>
  <p>Stripe is confirming the deposit. The booking request remains ready for review.</p>
  <a class="shop-button" href="$back">Return to booking</a>
</section>
HTML
    return $self->_shop_html_response('Request Received', $body, $back, 'Booking deposit status.');
}

sub _booking_deposit_cancel {
    my ($self, $request, $slug, $payment_id) = @_;
    my $payment = $self->{bookings}->payment_by_id($payment_id) or return $self->_not_found;
    return $self->_not_found unless ($payment->{service_slug} || '') eq $slug;
    my $back = escape_html('/bookings/' . $slug . '/');
    my $body = <<"HTML";
<section class="events-shell booking-message">
  <p class="kicker">Bookings</p>
  <h1>Deposit Canceled</h1>
  <p>No deposit payment was recorded. The booking request can still be reviewed by the site owner.</p>
  <a class="shop-button" href="$back">Return to booking</a>
</section>
HTML
    return $self->_shop_html_response('Deposit Canceled', $body, $back, 'Booking deposit status.');
}

sub _bookings_stripe_webhook {
    my ($self, $request) = @_;
    my $ok = eval {
        $self->{bookings}->handle_webhook(
            payload   => $request->{body},
            signature => $request->{stripe_signature},
        );
        1;
    };
    return DesertCMS::HTTP->response(
        status  => $ok ? 200 : 400,
        headers => {
            'Content-Type' => 'application/json; charset=utf-8',
            'Cache-Control' => 'no-store',
        },
        body => encode_json({ ok => $ok ? 1 : 0 }),
    );
}

sub _booking_public_card {
    my ($self, $service) = @_;
    my $slug = escape_html($service->{slug} || '');
    my $title = escape_html($service->{title} || 'Booking service');
    my $summary = escape_html($service->{summary} || '');
    my $kind = escape_html(DesertCMS::Bookings::service_kind_label($service->{service_kind}));
    my $image = $service->{image_path} || '';
    my $image_html = $self->_public_media_img_tag(
        $image,
        '',
        class => 'public-media-img',
        sizes => '(max-width: 760px) 100vw, 360px',
    ) || '<div class="event-card-date" aria-hidden="true">' . substr($kind, 0, 1) . '</div>';
    my $location = escape_html($service->{location_label} || '');
    my $location_html = length $location ? qq{<span>$location</span>} : '';
    return <<"HTML";
<a class="event-card booking-card" href="/bookings/$slug/">
  $image_html
  <div class="event-card-body">
    <span class="event-time">$kind</span>
    <h2>$title</h2>
    <p>$summary</p>
    $location_html
  </div>
</a>
HTML
}

sub _booking_public_meta {
    my ($service) = @_;
    my @items;
    push @items, [ 'Duration', int($service->{duration_minutes}) . ' minutes' ] if int($service->{duration_minutes} || 0) > 0;
    push @items, [ 'Pricing', escape_html($service->{price_note}) ] if length($service->{price_note} || '');
    push @items, [ 'Location', escape_html($service->{location_label}) ] if length($service->{location_label} || '');
    if ($service->{location_enabled} && defined $service->{location_lat} && defined $service->{location_lng}) {
        push @items, [ 'Map', '<a href="/map/">View location</a><small>' . escape_html($service->{location_lat}) . ', ' . escape_html($service->{location_lng}) . '</small>' ];
    }
    if ($service->{deposit_enabled} && int($service->{deposit_amount_cents} || 0) > 0) {
        push @items, [ 'Deposit', escape_html(DesertCMS::Bookings::price_label($service->{deposit_amount_cents}, $service->{deposit_currency})) ];
    }
    return '' unless @items;
    my $rows = join '', map { '<div><dt>' . escape_html($_->[0]) . '</dt><dd>' . $_->[1] . '</dd></div>' } @items;
    return qq{<dl class="event-meta directory-meta booking-meta">$rows</dl>};
}

sub _booking_public_request_form {
    my ($self, $service, $settings) = @_;
    return '<section class="event-action-panel"><h2>Request Booking</h2><p class="events-empty">Booking requests are paused right now.</p></section>'
        unless _setting_truthy($settings->{bookings_requests_enabled});
    my $slug = escape_html($service->{slug} || '');
    my $deposit_copy = '';
    my $button = 'Send booking request';
    if ($service->{deposit_enabled} && int($service->{deposit_amount_cents} || 0) > 0) {
        my $price = escape_html(DesertCMS::Bookings::price_label($service->{deposit_amount_cents}, $service->{deposit_currency}));
        if ($self->{bookings}->checkout_ready) {
            $deposit_copy = qq{<p class="muted">This service requests a $price deposit through Stripe after the request form is submitted.</p>};
            $button = 'Request booking and pay deposit';
        } else {
            $deposit_copy = qq{<p class="events-notice">A $price deposit is configured, but online deposits are not available on this plan or payment setup. Submit the request and the site owner can follow up.</p>};
        }
    }
    my $safe_button = escape_html($button);
    return <<"HTML";
<section class="event-action-panel">
  <h2>Request Booking</h2>
  $deposit_copy
  <form method="post" action="/bookings/$slug/request" class="public-form booking-request-form">
    <div class="public-form-grid">
      <label class="public-field"><span>Name</span><input name="name" maxlength="120" autocomplete="name" required></label>
      <label class="public-field"><span>Email</span><input name="email" type="email" maxlength="180" autocomplete="email" required></label>
      <label class="public-field"><span>Phone</span><input name="phone" maxlength="80" autocomplete="tel"></label>
      <label class="public-field"><span>Organization</span><input name="organization" maxlength="160" autocomplete="organization"></label>
      <label class="public-field"><span>Requested date</span><input name="requested_date" type="date" required></label>
      <label class="public-field"><span>Requested time</span><input name="requested_time" type="time"></label>
      <label class="public-field"><span>Preferred window</span><input name="preferred_window" maxlength="120" placeholder="Morning, afternoon, flexible"></label>
      <label class="public-field"><span>Party size</span><input name="party_size" type="number" min="1" max="100000"></label>
      <label class="public-field public-field--full"><span>Budget</span><input name="budget" maxlength="80" placeholder="Optional"></label>
    </div>
    <label class="public-field public-field--full"><span>Notes</span><textarea name="notes" rows="5" maxlength="3000" required></textarea></label>
    <label class="comment-honeypot"><span>Website</span><input name="website" tabindex="-1" autocomplete="off"></label>
    <button type="submit">$safe_button</button>
  </form>
</section>
HTML
}

sub _booking_request_args_from_request {
    my ($request) = @_;
    return (
        name             => $request->param('name'),
        email            => $request->param('email'),
        phone            => $request->param('phone'),
        organization     => $request->param('organization'),
        requested_date   => $request->param('requested_date'),
        requested_time   => $request->param('requested_time'),
        preferred_window => $request->param('preferred_window'),
        party_size       => $request->param('party_size'),
        budget           => $request->param('budget'),
        notes            => $request->param('notes'),
        website          => $request->param('website'),
    );
}

sub _dispatch_forms {
    my ($self, $request) = @_;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $path = $request->{path} || '/forms';
    $path =~ s{/+$}{};
    $path = '/forms' if $path eq '';

    if ($path eq '/forms/contributor-request') {
        return $self->_not_found unless DesertCMS::Modules::enabled($settings, 'contributor_requests');
        return $request->{method} eq 'POST'
            ? $self->_contributor_request_submit($request, $settings)
            : $self->_method_not_allowed;
    }
    if ($path eq '/forms/contributor-request/received') {
        return $self->_not_found unless DesertCMS::Modules::enabled($settings, 'contributor_requests');
        return $request->{method} eq 'GET'
            ? $self->_contributor_request_result_page('Contributor Request Received', 'Thanks. Your contributor request has been received.', 0)
            : $self->_method_not_allowed;
    }

    return $self->_not_found unless DesertCMS::Modules::enabled($settings, 'forms');

    if ($path eq '/forms') {
        return $request->{method} eq 'GET'
            ? $self->_forms_page($request, $settings)
            : $self->_method_not_allowed;
    }
    if ($path eq '/forms/submit') {
        return $request->{method} eq 'POST'
            ? $self->_forms_submit($request, $settings)
            : $self->_method_not_allowed;
    }

    return $self->_not_found;
}

sub _forms_page {
    my ($self, $request, $settings, $message, $is_error) = @_;
    $settings ||= DesertCMS::Settings::all($self->{config}, $self->{db});
    my $title = $settings->{forms_title} || 'Contact';
    my $intro = $settings->{forms_intro} || 'Send a message, request a quote, apply, complete an intake, or RSVP.';
    my $button = $settings->{forms_button_label} || 'Send message';
    my $safe_title = escape_html($title);
    my $safe_intro = escape_html($intro);
    my $safe_button = escape_html($button);
    my $selected_type = $request ? ($request->param('form_key') || $request->param('form_type') || 'contact') : 'contact';
    my $type_options = _forms_public_type_options($settings, $selected_type);
    my $name = escape_html($request ? ($request->param('name') || '') : '');
    my $email = escape_html($request ? ($request->param('email') || '') : '');
    my $phone = escape_html($request ? ($request->param('phone') || '') : '');
    my $organization = escape_html($request ? ($request->param('organization') || '') : '');
    my $subject = escape_html($request ? ($request->param('subject') || '') : '');
    my $body_text = escape_html($request ? ($request->param('message') || '') : '');
    my $preferred_date = escape_html($request ? ($request->param('preferred_date') || '') : '');
    my $event_date = escape_html($request ? ($request->param('event_date') || '') : '');
    my $guest_count = escape_html($request ? ($request->param('guest_count') || '') : '');
    my $budget = escape_html($request ? ($request->param('budget') || '') : '');
    my $uploads_enabled = _forms_truthy($settings->{forms_uploads_enabled});
    my $upload_mb = _forms_upload_mb($settings);
    my $upload_fields = $uploads_enabled ? <<"HTML" : '';
    <fieldset class="public-form-section public-form-section--wide">
      <legend>Files</legend>
      <p class="field-help public-form-section-help">Optional. Upload up to three supporting files, $upload_mb MB each. Supported files include images, PDFs, text, CSV, and Office documents.</p>
      <div class="public-upload-grid">
        <label class="public-upload-field">
          <span>File 1</span>
          <input type="file" name="attachment_1" accept=".jpg,.jpeg,.png,.webp,.gif,.pdf,.txt,.md,.csv,.tsv,.json,.doc,.docx,.xls,.xlsx,.ppt,.pptx" data-upload-preview>
          <span class="public-upload-preview" data-upload-preview-output></span>
        </label>
        <label class="public-upload-field">
          <span>File 2</span>
          <input type="file" name="attachment_2" accept=".jpg,.jpeg,.png,.webp,.gif,.pdf,.txt,.md,.csv,.tsv,.json,.doc,.docx,.xls,.xlsx,.ppt,.pptx" data-upload-preview>
          <span class="public-upload-preview" data-upload-preview-output></span>
        </label>
        <label class="public-upload-field">
          <span>File 3</span>
          <input type="file" name="attachment_3" accept=".jpg,.jpeg,.png,.webp,.gif,.pdf,.txt,.md,.csv,.tsv,.json,.doc,.docx,.xls,.xlsx,.ppt,.pptx" data-upload-preview>
          <span class="public-upload-preview" data-upload-preview-output></span>
        </label>
      </div>
    </fieldset>
HTML
    my $enctype = $uploads_enabled ? ' enctype="multipart/form-data"' : '';
    my $notice = '';
    if (defined $message && length $message) {
        my $class = $is_error ? 'forms-notice is-error' : 'forms-notice';
        my $role = $is_error ? 'alert' : 'status';
        $notice = '<p class="' . $class . '" role="' . $role . '">' . escape_html($message) . '</p>';
    }

    my $content = <<"HTML";
<article class="content module-page forms-page">
  <p class="kicker">Forms</p>
  <h1>$safe_title</h1>
  <p class="module-intro">$safe_intro</p>
  $notice
  <form method="post" action="/forms/submit" class="public-form"$enctype>
    <fieldset class="public-form-section">
      <legend>Request type</legend>
      <label class="public-field public-field--full">
        <span>What do you need?</span>
        <select name="form_key">$type_options</select>
      </label>
      <p class="field-help public-form-section-help">Choose the closest type. The details below cover contact messages, quote requests, applications, intake forms, and RSVPs.</p>
    </fieldset>
    <fieldset class="public-form-section">
      <legend>Contact details</legend>
      <div class="public-form-grid">
        <label class="public-field">
          <span>Name</span>
          <input name="name" value="$name" maxlength="100" autocomplete="name" required>
        </label>
        <label class="public-field">
          <span>Email</span>
          <input name="email" type="email" value="$email" maxlength="180" autocomplete="email" required>
        </label>
        <label class="public-field">
          <span>Phone</span>
          <input name="phone" value="$phone" maxlength="60" autocomplete="tel">
        </label>
        <label class="public-field">
          <span>Organization</span>
          <input name="organization" value="$organization" maxlength="160" autocomplete="organization">
        </label>
        <label class="public-field public-field--full">
          <span>Subject</span>
          <input name="subject" value="$subject" maxlength="160">
        </label>
      </div>
    </fieldset>
    <fieldset class="public-form-section">
      <legend>Request details</legend>
      <div class="public-form-grid">
        <label class="public-field">
          <span>Preferred date</span>
          <input name="preferred_date" type="date" value="$preferred_date">
        </label>
        <label class="public-field">
          <span>Event date</span>
          <input name="event_date" type="date" value="$event_date">
        </label>
        <label class="public-field">
          <span>Guest count</span>
          <input name="guest_count" type="number" min="0" max="99999" value="$guest_count">
        </label>
        <label class="public-field">
          <span>Budget</span>
          <input name="budget" value="$budget" maxlength="80" placeholder="Optional">
        </label>
      </div>
    </fieldset>
    <fieldset class="public-form-section public-form-section--wide">
      <legend>Message</legend>
      <label class="public-field public-count-field">
        <span>Details</span>
        <textarea name="message" rows="7" maxlength="5000" required data-character-counter data-counter-max="5000">$body_text</textarea>
        <small class="field-counter" data-counter-output>0 / 5000 characters</small>
      </label>
    </fieldset>
    $upload_fields
    <label class="comment-honeypot">
      <span>Website</span>
      <input name="website" tabindex="-1" autocomplete="off">
    </label>
    <button type="submit">$safe_button</button>
  </form>
</article>
HTML

    my $html = DesertCMS::Renderer::render_module_page($self->{config}, $self->{db}, {
        title       => $title,
        description => $intro,
        path        => '/forms/',
        content     => $content,
    });
    return DesertCMS::HTTP->response(
        status => 200,
        headers => {
            'Content-Type' => 'text/html; charset=utf-8',
            security_headers(),
        },
        body => $html,
    );
}

sub _forms_submit {
    my ($self, $request, $settings) = @_;
    if (length($request->param('website') || '')) {
        my $message = $settings->{forms_success_message} || 'Thanks. Your message has been received.';
        return $self->_forms_page(undef, $settings, $message, 0);
    }

    my $result = eval {
        $self->{forms}->submit(
            form_key       => $request->param('form_key'),
            name           => $request->param('name'),
            email          => $request->param('email'),
            phone          => $request->param('phone'),
            organization   => $request->param('organization'),
            subject        => $request->param('subject'),
            message        => $request->param('message'),
            preferred_date => $request->param('preferred_date'),
            event_date     => $request->param('event_date'),
            guest_count    => $request->param('guest_count'),
            budget         => $request->param('budget'),
            website        => $request->param('website'),
            request        => $request,
            settings       => $settings,
            attachments    => [
                grep { $_ } (
                    $request->upload('attachment_1'),
                    $request->upload('attachment_2'),
                    $request->upload('attachment_3'),
                )
            ],
        );
    };
    if (!$result) {
        return $self->_forms_page(
            $request,
            $settings,
            _admin_action_error(
                'Your message could not be sent.',
                'Check the required fields and try again.',
                $@
            ),
            1
        );
    }

    my $message = $settings->{forms_success_message} || 'Thanks. Your message has been received.';
    return $self->_forms_page(undef, $settings, $message, 0);
}

sub _contributor_request_submit {
    my ($self, $request, $settings) = @_;
    if (length($request->param('website') || '')) {
        return DesertCMS::HTTP->redirect('/forms/contributor-request/received', { security_headers() });
    }

    my $result = eval {
        $self->{contributor_requests}->submit(
            name    => $request->param('name'),
            email   => $request->param('email'),
            phone   => $request->param('phone'),
            age     => $request->param('age'),
            application_text => $request->param('application_text'),
            website => $request->param('website'),
            application_showcase_uploads => [
                grep { $_ } (
                    $request->upload('showcase_1'),
                    $request->upload('showcase_2'),
                    $request->upload('showcase_3'),
                )
            ],
            request => $request,
        );
    };

    if (!$result) {
        return $self->_contributor_request_form_response(
            $request,
            _admin_action_error(
                'Your contributor request could not be submitted.',
                'Check the required fields, then try again.',
                $@
            ),
            1
        );
    }

    return DesertCMS::HTTP->redirect('/forms/contributor-request/received', { security_headers() });
}

sub _contributor_request_form_response {
    my ($self, $request, $message, $is_error) = @_;
    my %values;
    for my $key (qw(name email phone age application_text)) {
        $values{$key} = $request ? ($request->param($key) || '') : '';
    }
    my $form = DesertCMS::Renderer::contributor_request_form_html({
        title        => 'Contributor Application',
        intro        => 'Send your contact details, optional sample images, and a short note about why you want to join.',
        button_label => 'Submit application',
        values       => \%values,
        message      => $message,
        is_error     => $is_error,
    });
    my $content = <<"HTML";
<article class="content module-page contributor-apply-page">
  <p class="kicker">Contributors</p>
  <h1>Apply To Become A Contributor</h1>
  <p class="module-intro">Submit your contributor request for review.</p>
  $form
</article>
HTML
    my $html = DesertCMS::Renderer::render_module_page($self->{config}, $self->{db}, {
        title       => 'Apply To Become A Contributor',
        description => 'Submit your contributor request for review.',
        path        => '/contributors/apply/',
        content     => $content,
    });
    return DesertCMS::HTTP->response(
        status => $is_error ? 400 : 200,
        headers => {
            'Content-Type' => 'text/html; charset=utf-8',
            security_headers(),
        },
        body => $html,
    );
}

sub _contributor_profile_form {
    my ($self, $request, $token, $message, $is_error) = @_;
    my $row = $self->{contributor_requests}->profile_by_token($token);
    return $self->_not_found unless $row;

    my $name = escape_html($row->{name} || 'Contributor');
    my $bio = escape_html($request ? ($request->param('bio') || $row->{bio} || '') : ($row->{bio} || ''));
    my $profile_photo_required = ($row->{profile_photo_path} || '') =~ /\S/ ? '' : 'required';
    my $showcase_required = @{DesertCMS::ContributorRequests::showcase_files($row)} ? '' : 'required';
    my $portrait_help = $profile_photo_required ? 'Required before your profile can be published.' : 'Leave blank to keep the current portrait.';
    my $sample_help = $showcase_required ? 'Upload at least one public sample.' : 'Leave blank to keep current samples, or upload replacements.';
    my $notice = '';
    if (defined $message && length $message) {
        my $class = $is_error ? 'forms-notice is-error' : 'forms-notice';
        my $role = $is_error ? 'alert' : 'status';
        $notice = '<p class="' . $class . '" role="' . $role . '">' . escape_html($message) . '</p>';
    }

    my $content = <<"HTML";
<article class="content module-page contributor-profile-page">
  <p class="kicker">Contributors</p>
  <h1>Complete Your Contributor Profile</h1>
  <p class="module-intro">$name, add the profile details that should appear in the public contributor directory.</p>
  $notice
  <ol class="public-onboarding-steps" aria-label="Contributor onboarding steps">
    <li class="is-complete"><span>Approved</span><small>Your contributor request was selected.</small></li>
    <li class="is-active"><span>Profile</span><small>Add the public bio and portrait for the contributor directory.</small></li>
    <li><span>Site Setup</span><small>Your hosted site is created from the selected blueprint.</small></li>
    <li><span>Plan</span><small>You start on the free tier and can upgrade from Billing.</small></li>
  </ol>
  <form method="post" action="/contributors/profile/$token" enctype="multipart/form-data" class="public-form contributor-profile-form">
    <fieldset class="public-form-section public-form-section--wide">
      <legend>Public bio</legend>
      <label class="public-field public-count-field">
        <span>Bio</span>
        <textarea name="bio" rows="7" minlength="150" maxlength="500" required data-character-counter data-counter-min="150" data-counter-max="500">$bio</textarea>
        <small class="field-counter" data-counter-output>0 / 500 characters</small>
        <small class="field-help">Write 150 to 500 characters for your public contributor card.</small>
      </label>
    </fieldset>
    <fieldset class="public-form-section">
      <legend>Profile media</legend>
      <div class="public-upload-grid">
        <label class="public-upload-field">
          <span>Portrait</span>
          <input name="photo" type="file" accept="image/jpeg,image/png,image/webp" $profile_photo_required data-upload-preview>
          <span class="public-upload-preview" data-upload-preview-output><span class="public-upload-thumb" aria-hidden="true"></span><small>No file selected</small></span>
          <small class="field-help">$portrait_help</small>
        </label>
        <label class="public-upload-field">
          <span>Sample</span>
          <input name="showcase_1" type="file" accept="image/jpeg,image/png,image/webp" $showcase_required data-upload-preview>
          <span class="public-upload-preview" data-upload-preview-output><span class="public-upload-thumb" aria-hidden="true"></span><small>No file selected</small></span>
          <small class="field-help">$sample_help</small>
        </label>
        <label class="public-upload-field">
          <span>Additional sample</span>
          <input name="showcase_2" type="file" accept="image/jpeg,image/png,image/webp" data-upload-preview>
          <span class="public-upload-preview" data-upload-preview-output><span class="public-upload-thumb" aria-hidden="true"></span><small>No file selected</small></span>
        </label>
        <label class="public-upload-field">
          <span>Additional sample</span>
          <input name="showcase_3" type="file" accept="image/jpeg,image/png,image/webp" data-upload-preview>
          <span class="public-upload-preview" data-upload-preview-output><span class="public-upload-thumb" aria-hidden="true"></span><small>No file selected</small></span>
        </label>
      </div>
    </fieldset>
    <label class="comment-honeypot">
      <span>Website</span>
      <input name="website" tabindex="-1" autocomplete="off">
    </label>
    <button type="submit">Save profile</button>
  </form>
</article>
HTML
    my $html = DesertCMS::Renderer::render_module_page($self->{config}, $self->{db}, {
        title       => 'Complete Contributor Profile',
        description => 'Complete your contributor profile.',
        path        => '/contributors/profile/',
        content     => $content,
    });
    return DesertCMS::HTTP->response(
        status => $is_error ? 400 : 200,
        headers => {
            'Content-Type' => 'text/html; charset=utf-8',
            security_headers(),
        },
        body => $html,
    );
}

sub _contributor_profile_submit {
    my ($self, $request, $token) = @_;
    if (length($request->param('website') || '')) {
        return $self->_contributor_profile_form($request, $token, 'Profile saved.', 0);
    }

    my $result = eval {
        $self->{contributor_requests}->complete_profile(
            token => $token,
            bio   => $request->param('bio'),
            photo => $request->upload('photo'),
            showcase_uploads => [
                grep { $_ } (
                    $request->upload('showcase_1'),
                    $request->upload('showcase_2'),
                    $request->upload('showcase_3'),
                )
            ],
            request => $request,
        );
    };
    if (!$result) {
        return $self->_contributor_profile_form(
            $request,
            $token,
            _admin_action_error(
                'Your contributor profile could not be saved.',
                'Check the bio length, portrait, and sample image requirements, then try again.',
                $@
            ),
            1
        );
    }

    $self->{content}->rebuild_all;
    return $self->_contributor_profile_form($request, $token, 'Profile saved. Your public contributor profile is ready for the contributors directory.', 0);
}

sub _contributor_request_result_page {
    my ($self, $title, $message, $is_error) = @_;
    my $safe_title = escape_html($title || 'Contributor Request');
    my $safe_message = escape_html($message || '');
    my $class = $is_error ? 'forms-notice is-error' : 'forms-notice';
    my $content = <<"HTML";
<article class="content module-page forms-page">
  <p class="kicker">Contributors</p>
  <h1>$safe_title</h1>
  <p class="$class">$safe_message</p>
  <p><a href="/">Return to the site</a></p>
</article>
HTML
    my $html = DesertCMS::Renderer::render_module_page($self->{config}, $self->{db}, {
        title       => $title,
        description => $message,
        path        => '/contributors/',
        content     => $content,
    });
    return DesertCMS::HTTP->response(
        status => $is_error ? 400 : 200,
        headers => {
            'Content-Type' => 'text/html; charset=utf-8',
            security_headers(),
        },
        body => $html,
    );
}

sub _shop_catalog {
    my ($self, $request, $prefix, $message) = @_;
    my $items = $self->{shop}->catalog_items;
    my $notice = $message ? '<p class="shop-notice">' . escape_html($message) . '</p>' : '';
    my $cards = '';
    my $checkout_path = _shop_route($prefix, '/checkout');
    my $checkout_ready = $self->{shop}->checkout_ready;

    for my $item (@{$items}) {
        my $title = escape_html($item->{title} || $item->{original_name} || 'Catalog item');
        my $description = escape_html($item->{description} || '');
        $description =~ s/\n/<br>/g;
        my $image = $item->{public_path} || '';
        my $alt = $item->{alt_text} || $item->{title} || '';
        my $kind = escape_html(DesertCMS::Shop->listing_kind_label($item->{listing_kind}));
        my $cta_label = escape_html($item->{cta_label} || 'Request info');
        my $cta_url = escape_html($item->{cta_url} || '');
        my $listing_id = int($item->{id});
        my $desc_html = length $description ? qq{<p>$description</p>} : '';
        my $image_html = $self->_public_media_img_tag(
            $image,
            $alt,
            class => 'public-media-img',
            sizes => '(max-width: 760px) 100vw, 360px',
        ) || '<div class="event-card-date" aria-hidden="true">' . substr($kind, 0, 1) . '</div>';
        my $buttons = '';
        if ($checkout_ready) {
            for my $option (@{DesertCMS::Shop->rights_options($item)}) {
                next unless $option->{enabled} || $option->{sold};
                my $type = escape_html($option->{type});
                my $label = escape_html($option->{label});
                my $price = escape_html($option->{price_label});
                my $detail = escape_html($option->{description});
                my $token = escape_html($self->{shop}->purchase_token($item, $option->{type}));
                my $button = escape_html('Buy ' . lc($option->{label}));
                if ($option->{sold}) {
                    $buttons .= qq{<div class="rights-option is-sold"><strong>$label</strong><span>Sold</span><small>$detail</small></div>};
                    next;
                }
                $buttons .= <<"HTML";
<form method="post" action="$checkout_path" class="rights-option rights-option--$type">
  <input type="hidden" name="listing_id" value="$listing_id">
  <input type="hidden" name="rights_type" value="$type">
  <input type="hidden" name="purchase_token" value="$token">
  <strong>$label</strong>
  <span>$price</span>
  <small>$detail</small>
  <button type="submit">$button</button>
</form>
HTML
            }
        }
        if (!length $buttons) {
            $buttons = length $cta_url
                ? qq{<a class="shop-button shop-button--catalog" href="$cta_url">$cta_label</a>}
                : qq{<span class="shop-button shop-button--catalog shop-button--muted">$cta_label</span>};
        }
        $cards .= <<"HTML";
<article class="shop-card">
  $image_html
  <div class="shop-card-body">
    <span class="shop-kind">$kind</span>
    <h2>$title</h2>
    $desc_html
    <div class="rights-grid">$buttons</div>
  </div>
</article>
HTML
    }
    $cards ||= '<p class="shop-empty">No catalog listings are published yet.</p>';
    my $header_copy = $checkout_ready
        ? 'Browse products, services, digital items, portfolio samples, and selected media. Some listings can be purchased directly when price options are shown.'
        : 'Browse products, services, digital items, portfolio samples, and selected media. Listings can point visitors to the next step with an inquiry link.';
    my $assurance = $checkout_ready
        ? '<p class="shop-assurance">Payments are handled by Stripe. A confirmed purchase records the selected rights for the item; full-rights purchases remove that listing from sale.</p>'
        : '';

    my $body = <<"HTML";
<article class="content module-page shop-page shop-shell">
  <header class="shop-heading">
    <p class="kicker">Shop / Catalog</p>
    <h1>Catalog</h1>
    <p>$header_copy Public previews are optimized derivatives; private source files remain private.</p>
    $assurance
  </header>
  $notice
  <section class="shop-grid" aria-label="Catalog listings">
    $cards
  </section>
</article>
HTML
    return $self->_shop_html_response('Shop / Catalog', $body, _shop_route($prefix, '/'), 'Product, service, media, and inquiry catalog.');
}

sub _shop_checkout {
    my ($self, $request, $prefix) = @_;
    my $checkout = eval {
        $self->{shop}->create_checkout(
            listing_id   => $request->param('listing_id'),
            rights_type  => $request->param('rights_type'),
            purchase_token => $request->param('purchase_token'),
            customer_email => $request->param('customer_email'),
        );
    };
    if (!$checkout) {
        return $self->_shop_catalog(
            $request,
            $prefix,
            _admin_action_error(
                'Checkout could not be started.',
                'Choose an available rights option and try again.',
                $@
            )
        );
    }
    return DesertCMS::HTTP->redirect($checkout->{url}, { security_headers() });
}

sub _shop_success {
    my ($self, $request, $prefix) = @_;
    my $order = $self->{shop}->order($request->param('order'));
    my $back = escape_html(_shop_route($prefix, '/'));
    my $body;
    if (!$order) {
        $body = <<"HTML";
<section class="shop-shell shop-message">
  <p class="kicker">Checkout</p>
  <h1>Order Not Found</h1>
  <p>This checkout could not be matched to a shop order.</p>
  <a class="shop-button" href="$back">Return to shop</a>
</section>
HTML
        return $self->_shop_html_response('Order Not Found', $body, _shop_route($prefix, '/success'), 'Shop checkout status.');
    }

    my $title = escape_html($order->{listing_title} || $order->{original_name} || 'Catalog item');
    my $rights = escape_html(DesertCMS::Shop->rights_label($order->{rights_type}));
    my $price = escape_html(DesertCMS::Shop::price_label($order->{amount_cents}, $order->{currency}));
    my $status = escape_html($order->{status} || 'pending');
    my $status_text = ($order->{status} || '') eq 'paid'
        ? 'Payment has been confirmed. The seller will follow up with the rights record and any delivery details.'
        : 'Stripe is still confirming this payment. Refresh this page in a moment if the status does not update.';
    $body = <<"HTML";
<section class="shop-shell shop-message">
  <p class="kicker">Checkout</p>
  <h1>Thank You</h1>
  <dl class="shop-summary">
    <div><dt>Item</dt><dd>$title</dd></div>
    <div><dt>Rights</dt><dd>$rights</dd></div>
    <div><dt>Total</dt><dd>$price</dd></div>
    <div><dt>Status</dt><dd>$status</dd></div>
  </dl>
  <p>$status_text</p>
  <a class="shop-button" href="$back">Return to shop</a>
</section>
HTML
    return $self->_shop_html_response('Thank You', $body, _shop_route($prefix, '/success'), 'Shop checkout status.');
}

sub _shop_cancel {
    my ($self, $request, $prefix) = @_;
    my $back = escape_html(_shop_route($prefix, '/'));
    my $body = <<"HTML";
<section class="shop-shell shop-message">
  <p class="kicker">Checkout</p>
  <h1>Checkout Canceled</h1>
  <p>No payment was recorded. The item remains available if another buyer has not purchased full rights.</p>
  <a class="shop-button" href="$back">Return to shop</a>
</section>
HTML
    return $self->_shop_html_response('Checkout Canceled', $body, _shop_route($prefix, '/cancel'), 'Shop checkout status.');
}

sub _shop_stripe_webhook {
    my ($self, $request) = @_;
    my $ok = eval {
        $self->{shop}->handle_webhook(
            payload   => $request->{body},
            signature => $request->{stripe_signature},
        );
        1;
    };
    return DesertCMS::HTTP->response(
        status  => $ok ? 200 : 400,
        headers => {
            'Content-Type' => 'application/json; charset=utf-8',
            'Cache-Control' => 'no-store',
        },
        body => encode_json({ ok => $ok ? 1 : 0 }),
    );
}

sub _service_plan_stripe_webhook {
    my ($self, $request) = @_;
    my $result = eval {
        $self->{service_plans}->handle_subscription_webhook(
            payload   => $request->{body},
            signature => $request->{stripe_signature},
        );
    };
    return DesertCMS::HTTP->response(
        status  => $result ? 200 : 400,
        headers => {
            'Content-Type' => 'application/json; charset=utf-8',
            'Cache-Control' => 'no-store',
        },
        body => encode_json($result || { ok => 0 }),
    );
}

sub _billing_page {
    my ($self, $request, $session, $session_token, $message) = @_;
    return DesertCMS::HTTP->redirect('/admin/settings/plans', { security_headers() })
        unless DesertCMS::Commerce::is_contributor_instance($self->{config});

    if (($request->param('stripe_connect') || '') eq 'return') {
        my $refresh = eval {
            my $context = $self->_contributor_billing_context(read_only => 0);
            $context->{service_plans}->refresh_connect_account_status(site_id => $context->{site_id});
        };
        $message ||= $refresh
            ? ($refresh->{charges_enabled} && $refresh->{payouts_enabled}
                ? 'Stripe payout account is ready for site payments.'
                : 'Stripe payout account status refreshed. Finish any remaining Stripe onboarding steps before taking site payments.')
            : _admin_action_error(
                'Stripe payout status could not be refreshed.',
                'Open Stripe onboarding again or try refreshing Billing later.',
                $@
            );
    }

    my $context = eval { $self->_contributor_billing_context };
    if (!$context) {
        my $safe_error = escape_html(_clean_error($@ || 'Billing is unavailable.'));
        my $body = <<"HTML";
<section class="editor-workspace">
  <section class="panel">
    <p class="eyebrow">Billing</p>
    <h1>Billing</h1>
    <p class="notice">$safe_error</p>
  </section>
</section>
HTML
        return $self->_html_response('Billing', $body, $session);
    }

    my $csrf = $self->{auth}->csrf_token($session_token);
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $site = $context->{site} || {};
    my $usage = $context->{usage} || {};
    my $current_plan = escape_html($site->{service_plan_name} || 'Free Tier');
    my $billing_status = _billing_status_pill($site->{billing_status});
    my $billing_email = escape_html($site->{billing_email} || $site->{owner_email} || '');
    my $current_price_cents = int($site->{monthly_price_cents} || 0);
    my $price_note = $current_price_cents > 0
        ? escape_html(_format_money($current_price_cents, $site->{currency}) . ' per month')
        : 'No monthly charge';
    my $period = $site->{billing_current_period_end}
        ? escape_html(_format_time($site->{billing_current_period_end}))
        : 'Not set';
    my $usage_html = _billing_usage_html($usage);
    my $plans_html = $self->_billing_plan_cards($context->{plans}, $site, $csrf);
    my $billing_onboarding = _billing_onboarding_flow($site);
    my $billing_readiness = $self->_billing_provider_readiness_strip($context);
    my $provider_overrides = $self->_billing_provider_overrides($context, $csrf);
    my $body = <<"HTML";
<section class="editor-workspace">
  <section class="panel">
    <div class="split">
      <div>
        <p class="eyebrow">Hosted Site</p>
        <h1>Billing</h1>
        <p>Manage this site's plan, usage, upgrade options, email sender, and payment setup.</p>
      </div>
    </div>
    $notice
    $billing_onboarding
    <section class="inspector-panel">
      <h2>Provider Readiness</h2>
      $billing_readiness
    </section>
    <section class="metric-grid">
      <article class="metric-card"><span>Current Plan</span><strong>$current_plan</strong><small>$price_note</small></article>
      <article class="metric-card"><span>Billing Status</span><strong>$billing_status</strong><small>$billing_email</small></article>
      <article class="metric-card"><span>Current Period</span><strong>$period</strong><small>Updated by Stripe webhooks</small></article>
    </section>
    <section class="inspector-panel">
      <h2>Usage</h2>
      $usage_html
    </section>
    <section class="inspector-panel">
      <h2>Available Plans</h2>
      <div class="billing-plan-grid">$plans_html</div>
    </section>
    $provider_overrides
  </section>
</section>
HTML

    return $self->_html_response('Billing', $body, $session);
}

sub _billing_checkout {
    my ($self, $request, $session, $session_token) = @_;
    return $self->_forbidden unless DesertCMS::Commerce::is_contributor_instance($self->{config});
    my $checkout = eval {
        my $context = $self->_contributor_billing_context;
        $context->{service_plans}->create_subscription_checkout(
            site_id     => $context->{site_id},
            plan_id     => $request->param('plan_id'),
            success_url => $self->_admin_absolute_url('/admin/billing?checkout=success'),
            cancel_url  => $self->_admin_absolute_url('/admin/billing?checkout=cancel'),
        );
    };
    if (!$checkout) {
        return $self->_billing_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The plan checkout could not be started.',
                'Choose an available paid plan and confirm Stripe is configured, then try again.',
                $@
            )
        );
    }
    return DesertCMS::HTTP->redirect($checkout->{url}, { security_headers() });
}

sub _billing_portal {
    my ($self, $request, $session, $session_token) = @_;
    return $self->_forbidden unless DesertCMS::Commerce::is_contributor_instance($self->{config});
    my $portal = eval {
        my $context = $self->_contributor_billing_context;
        $context->{service_plans}->create_portal_session(
            site_id     => $context->{site_id},
            return_url  => $self->_admin_absolute_url('/admin/billing'),
        );
    };
    if (!$portal) {
        return $self->_billing_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The billing portal could not be opened.',
                'Confirm this contributor site has a Stripe customer, then try again.',
                $@
            )
        );
    }
    return DesertCMS::HTTP->redirect($portal->{url}, { security_headers() });
}

sub _billing_postmark_save {
    my ($self, $request, $session, $session_token) = @_;
    return $self->_forbidden unless DesertCMS::Commerce::is_contributor_instance($self->{config});
    my $ok = eval {
        my $context = $self->_contributor_billing_context;
        my $site = $context->{site} || {};
        die "this service plan does not include custom Postmark sender signatures"
            unless _setting_truthy($site->{allow_postmark_sender_override});
        my $mode = _clean_postmark_sender_mode($request->param('postmark_sender_mode'));
        my %values = (postmark_sender_mode => $mode);
        if ($mode eq 'site') {
            my $from = _clean_email($request->param('postmark_from_email'));
            die "valid Postmark sender email is required" unless length $from;
            $values{postmark_from_email} = $from;
            my $token = $request->param('postmark_server_token');
            $values{postmark_server_token} = $token if defined $token && length $token;
            my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
            if (!length($settings->{postmark_webhook_token} || '')) {
                $values{postmark_webhook_token} = generate_webhook_token();
            }
        }
        DesertCMS::Settings::set_many($self->{config}, $self->{db}, \%values);
        1;
    };
    return $self->_billing_page(
        $request,
        $session,
        $session_token,
        $ok
            ? 'Postmark sender settings saved.'
            : _admin_action_error(
                'Postmark sender settings could not be saved.',
                'Confirm this plan includes custom sender signatures, then check the sender email and Postmark server token.',
                $@
            )
    );
}

sub _billing_stripe_connect {
    my ($self, $request, $session, $session_token) = @_;
    return $self->_forbidden unless DesertCMS::Commerce::is_contributor_instance($self->{config});
    my $connect = eval {
        my $context = $self->_contributor_billing_context(read_only => 0);
        $context->{service_plans}->create_connect_onboarding_link(
            site_id     => $context->{site_id},
            refresh_url => $self->_admin_absolute_url('/admin/billing/stripe/connect/refresh'),
            return_url  => $self->_admin_absolute_url('/admin/billing?stripe_connect=return'),
        );
    };
    if (!$connect) {
        return $self->_billing_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'Stripe payout onboarding could not be started.',
                'Confirm this plan includes site payments and that the platform Stripe account is configured.',
                $@
            )
        );
    }
    return DesertCMS::HTTP->redirect($connect->{url}, { security_headers() });
}

sub _billing_provider_readiness_strip {
    my ($self, $context) = @_;
    my $site = ($context || {})->{site} || {};
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $postmark_allowed = _setting_truthy($site->{allow_postmark_sender_override});
    my $postmark_mode = ($settings->{postmark_sender_mode} || '') eq 'site' ? 'site' : 'inherit';
    my $postmark_from = _clean_email($settings->{postmark_from_email});
    my $postmark_token = length($settings->{postmark_server_token} || '') ? 1 : 0;
    my $postmark_value = !$postmark_allowed
        ? '<span class="status-pill status-pill--neutral">Inherited</span>'
        : ($postmark_mode eq 'site'
            ? (length($postmark_from) && $postmark_token
                ? '<span class="status-pill ok">Custom ready</span>'
                : '<span class="status-pill warn">Needs sender</span>')
            : '<span class="status-pill ok">Custom available</span>');
    my $postmark_detail = !$postmark_allowed
        ? 'Uses the platform sender until this plan includes custom signatures.'
        : ($postmark_mode eq 'site'
            ? 'Custom sender signatures are enabled for this site.'
            : 'Plan includes custom sender signatures; currently inheriting platform email.');

    my $billing_status = $site->{billing_status} || 'comped';
    my $billing_value = _billing_status_pill($billing_status);
    my $billing_detail = length($site->{stripe_subscription_id} || '')
        ? 'Plan subscription is tracked by the platform Stripe account.'
        : 'Plan checkout and portal stay on the platform Stripe account.';

    my $stripe_allowed = _setting_truthy($site->{allow_stripe_connect});
    my $account_id = $settings->{stripe_connect_account_id} || $site->{stripe_connect_account_id} || '';
    my $charges_enabled = _setting_truthy($settings->{stripe_connect_charges_enabled} || $site->{stripe_connect_charges_enabled});
    my $payouts_enabled = _setting_truthy($settings->{stripe_connect_payouts_enabled} || $site->{stripe_connect_payouts_enabled});
    my $stripe_value = !$stripe_allowed
        ? '<span class="status-pill status-pill--neutral">Locked</span>'
        : (length($account_id)
            ? ($charges_enabled && $payouts_enabled
                ? '<span class="status-pill ok">Ready</span>'
                : '<span class="status-pill warn">Needs Stripe steps</span>')
            : '<span class="status-pill warn">Needs onboarding</span>');
    my $stripe_detail = !$stripe_allowed
        ? 'Site payments are locked by the current plan.'
        : (length($account_id)
            ? 'Connected payouts use the platform Stripe account with destination charges.'
            : 'Connect a Stripe payout account before enabling paid site features.');

    my $fee_percent = sprintf('%.2f', int($site->{stripe_platform_fee_bps} || $settings->{contributor_platform_fee_bps} || 0) / 100);
    $fee_percent =~ s/\.00\z//;
    my $fee_detail = $stripe_allowed
        ? 'Retained by the platform on contributor site payments.'
        : 'Applies only after a plan unlocks Stripe site payments.';

    return _settings_summary_strip(
        [ 'Plan Billing', $billing_value, $billing_detail ],
        [ 'Postmark Sender', $postmark_value, $postmark_detail ],
        [ 'Stripe Payouts', $stripe_value, $stripe_detail ],
        [ 'Platform Fee', '<span class="status-pill status-pill--neutral">' . escape_html($fee_percent) . '%</span>', $fee_detail ],
    );
}

sub _billing_provider_overrides {
    my ($self, $context, $csrf) = @_;
    my $site = $context->{site} || {};
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $postmark = resolved_postmark_settings($self->{config}, $self->{db}, $settings);
    my $postmark_allowed = _setting_truthy($site->{allow_postmark_sender_override});
    my $stripe_allowed = _setting_truthy($site->{allow_stripe_connect});
    my $safe_csrf = escape_html($csrf || '');
    my $postmark_source_label = $postmark->{source_label} || $postmark->{source} || 'Platform sender';
    $postmark_source_label =~ s/\bMaster CMS\b/Platform/g;
    $postmark_source_label =~ s/\bmaster\b/platform/ig;
    my $postmark_source = escape_html($postmark_source_label);
    my $postmark_from = escape_html($settings->{postmark_from_email} || '');
    my $postmark_mode = ($settings->{postmark_sender_mode} || '') eq 'site' ? 'site' : 'inherit';
    my $postmark_inherit_selected = $postmark_mode eq 'inherit' ? 'selected' : '';
    my $postmark_site_selected = $postmark_mode eq 'site' ? 'selected' : '';
    my $postmark_token_state = $settings->{postmark_server_token}
        ? '<span class="status-pill ok">Saved</span>'
        : '<span class="status-pill status-pill--neutral">Not saved</span>';
    my $postmark_form = $postmark_allowed ? <<"HTML" : _admin_empty_panel('Custom sender locked by plan.', 'Upgrade to a plan that includes custom Postmark sender signatures. Until then, email delivery inherits the platform sender.');
      <form method="post" action="/admin/billing/postmark/save" class="settings-form">
        <input type="hidden" name="csrf_token" value="$safe_csrf">
        <label>
          <span>Sender mode</span>
          <select name="postmark_sender_mode">
            <option value="inherit" $postmark_inherit_selected>Use inherited platform sender</option>
            <option value="site" $postmark_site_selected>Use custom site sender</option>
          </select>
        </label>
        <label>
          <span>Postmark sender email</span>
          <input name="postmark_from_email" type="email" value="$postmark_from" placeholder="sender\@example.com">
        </label>
        <label>
          <span>Postmark server token</span>
          <input name="postmark_server_token" type="password" autocomplete="new-password" placeholder="Leave blank to keep saved token">
        </label>
        <button type="submit" class="secondary">Save sender</button>
      </form>
HTML

    my $raw_account_id = $settings->{stripe_connect_account_id} || $site->{stripe_connect_account_id} || '';
    my $account_id = escape_html($raw_account_id);
    my $connect_status = escape_html($settings->{stripe_connect_onboarding_status} || $site->{stripe_connect_onboarding_status} || 'not started');
    my $charges_enabled = _setting_truthy($settings->{stripe_connect_charges_enabled} || $site->{stripe_connect_charges_enabled});
    my $payouts_enabled = _setting_truthy($settings->{stripe_connect_payouts_enabled} || $site->{stripe_connect_payouts_enabled});
    my $fee_percent = sprintf('%.2f', int($site->{stripe_platform_fee_bps} || $settings->{contributor_platform_fee_bps} || 0) / 100);
    $fee_percent =~ s/\.00\z//;
    my $connect_ready = length($raw_account_id) && $charges_enabled && $payouts_enabled;
    my $connect_state = $connect_ready
        ? '<span class="status-pill ok">Ready</span>'
        : (length($raw_account_id)
            ? '<span class="status-pill warn">Needs Stripe steps</span>'
            : ($stripe_allowed ? '<span class="status-pill warn">Needs onboarding</span>' : '<span class="status-pill status-pill--neutral">Locked</span>'));
    my $charges_state = $charges_enabled
        ? '<span class="status-pill ok">Enabled</span>'
        : '<span class="status-pill warn">Not enabled</span>';
    my $payouts_state = $payouts_enabled
        ? '<span class="status-pill ok">Enabled</span>'
        : '<span class="status-pill warn">Not enabled</span>';
    my $connect_action_label = length($raw_account_id) ? 'Continue Stripe onboarding' : 'Connect Stripe payouts';
    my $refresh_link = length($raw_account_id)
        ? '<a class="button-link secondary" href="/admin/billing?stripe_connect=return">Refresh payout status</a>'
        : '';
    my $stripe_action = $stripe_allowed ? <<"HTML" : _admin_empty_panel('Site payments locked by plan.', 'Upgrade to a plan that includes Stripe payouts. Service billing still runs through the platform billing account.');
      <div class="actions">
        <form method="post" action="/admin/billing/stripe/connect" class="inline-form">
          <input type="hidden" name="csrf_token" value="$safe_csrf">
          <button type="submit" class="secondary">$connect_action_label</button>
        </form>
        $refresh_link
      </div>
HTML

    return <<"HTML";
    <section class="inspector-panel">
      <h2>Platform Services</h2>
      <dl class="health-list health-list--compact fleet-provider-list">
        <div><dt>Postmark delivery</dt><dd><span class="status-pill status-pill--neutral">$postmark_source</span><small>Inherited unless this plan allows a custom sender signature.</small></dd></div>
        <div><dt>Stripe service billing</dt><dd><span class="status-pill status-pill--neutral">Platform</span><small>Plan subscriptions and billing portal stay on the platform account.</small></dd></div>
        <div><dt>Indexing defaults</dt><dd><span class="status-pill status-pill--neutral">Platform</span><small>Search submission providers remain platform-managed.</small></dd></div>
        <div><dt>Site operations</dt><dd><span class="status-pill status-pill--neutral">Platform</span><small>Backups, upgrades, provisioning, and maintenance are handled for you.</small></dd></div>
      </dl>
    </section>
    <section class="inspector-panel">
      <h2>Custom Postmark Sender</h2>
      <dl class="health-list health-list--compact">
        <div><dt>Plan</dt><dd>@{[$postmark_allowed ? '<span class="status-pill ok">Included</span>' : '<span class="status-pill status-pill--neutral">Upgrade required</span>']}</dd></div>
        <div><dt>Saved token</dt><dd>$postmark_token_state</dd></div>
      </dl>
      $postmark_form
    </section>
    <section class="inspector-panel">
      <h2>Stripe Site Payments</h2>
      <dl class="health-list health-list--compact">
        <div><dt>Plan</dt><dd>@{[$stripe_allowed ? '<span class="status-pill ok">Included</span>' : '<span class="status-pill status-pill--neutral">Upgrade required</span>']}</dd></div>
        <div><dt>Payout account</dt><dd>$connect_state<small>$account_id</small></dd></div>
        <div><dt>Onboarding</dt><dd><span class="status-pill status-pill--neutral">$connect_status</span></dd></div>
        <div><dt>Charges</dt><dd>$charges_state</dd></div>
        <div><dt>Payouts</dt><dd>$payouts_state</dd></div>
        <div><dt>Platform fee</dt><dd><span class="status-pill status-pill--neutral">$fee_percent%</span><small>Retained by the platform Stripe account on shop payments.</small></dd></div>
      </dl>
      $stripe_action
    </section>
HTML
}

sub _contributor_billing_context {
    my ($self, %options) = @_;
    my $site_id = $self->{config}->get('contributor_site_id') || '';
    $site_id =~ s/[^a-z0-9-]//g;
    die "contributor site id is not configured" unless length $site_id;
    my $master_config_path = $self->{config}->get('master_config_path') || '';
    die "master config path is not configured" unless length $master_config_path && -f $master_config_path;
    my $master_config = DesertCMS::Config->load($master_config_path);
    my $master_db = DesertCMS::DB->new(config => $master_config);
    my $master_settings = DesertCMS::Settings::all($master_config, $master_db);
    my $service_plans = DesertCMS::ServicePlans->new(
        config    => $master_config,
        db        => $master_db,
        read_only => exists $options{read_only} ? ($options{read_only} ? 1 : 0) : 1,
    );
    my $site = $service_plans->site_with_plan($site_id) or die "this hosted site is not registered with the platform";
    my $plans = $service_plans->list;
    return {
        site_id       => $site_id,
        site          => $site,
        plans         => $plans,
        usage         => $service_plans->site_usage($site),
        service_plans => $service_plans,
        master_settings => $master_settings,
    };
}

sub _billing_plan_cards {
    my ($self, $plans, $site, $csrf) = @_;
    my $current = int($site->{service_plan_id} || 0);
    my $safe_csrf = escape_html($csrf || '');
    my $has_customer = length($site->{stripe_customer_id} || '') ? 1 : 0;
    my $has_subscription = length($site->{stripe_subscription_id} || '') ? 1 : 0;
    my $html = '';
    for my $plan (@{$plans || []}) {
        my $id = int($plan->{id} || 0);
        next unless $id;
        my $name = escape_html($plan->{name} || '');
        my $description = escape_html($plan->{description} || '');
        my $price_cents = int($plan->{monthly_price_cents} || 0);
        my $price = $price_cents > 0
            ? escape_html(_format_money($price_cents, $plan->{currency}))
            : 'Free';
        my $price_detail = $price_cents > 0 ? 'per month' : 'included starter tier';
        my $is_current = $id == $current ? 1 : 0;
        my $is_free = $price_cents <= 0 ? 1 : 0;
        my $has_price_id = length($plan->{stripe_price_id} || '') ? 1 : 0;
        my $default_badge = int($plan->{is_default} || 0)
            ? '<span class="status-pill status-pill--neutral">Default tier</span>'
            : '';
        my $tier_badge = $is_current
            ? '<span class="status-pill ok">Current plan</span>'
            : ($is_free ? '<span class="status-pill status-pill--neutral">Free tier</span>' : '<span class="status-pill status-pill--neutral">Paid tier</span>');
        my $card_class = 'billing-plan-card' . ($is_current ? ' billing-plan-card--current' : '') . (!$is_current && !$is_free && !$has_price_id ? ' billing-plan-card--blocked' : '');
        my $aria_current = $is_current ? ' aria-current="true"' : '';
        my $media_limit = escape_html(int($plan->{media_quota_mb} || 0) . ' MB');
        my $upload_limit = escape_html(int($plan->{media_upload_limit_mb} || 0) . ' MB/file');
        my $post_limit = escape_html(int($plan->{post_quota} || 0) . ' posts');
        my $page_limit = escape_html(int($plan->{page_quota} || 0) . ' pages');
        my $gallery = int($plan->{allow_master_gallery} || 0) ? 'Eligible' : 'Not included';
        my $posts = int($plan->{allow_master_posts} || 0) ? 'Eligible' : 'Not included';
        my $features = _service_plan_feature_summary($plan);
        my $action_note = '';
        my $action = '';
        if ($is_current) {
            if (!$is_free && $has_customer) {
                $action_note = 'Stripe hosts upgrades, card changes, and cancellations.';
                $action = <<"HTML";
<form method="post" action="/admin/billing/portal" class="inline-form billing-plan-form">
  <input type="hidden" name="csrf_token" value="$safe_csrf">
  <button type="submit" class="button-link secondary">Manage or cancel in Stripe</button>
</form>
HTML
            } elsif (!$is_free) {
                $action_note = 'This paid tier is assigned by platform support.';
                $action = '<span class="status-pill status-pill--neutral">Managed manually</span>';
            } else {
                $action_note = 'Approved contributors start here until they choose a paid tier.';
                $action = '<span class="status-pill ok">Current free tier</span>';
            }
        } elsif ($is_free) {
            $action_note = ($has_customer || $has_subscription)
                ? 'Cancel the paid subscription in Stripe to return to this tier.'
                : 'This is the default starting tier for new contributor sites.';
            $action = '<span class="status-pill status-pill--neutral">Available</span>';
        } elsif (!$has_price_id) {
            $action_note = 'A recurring Stripe Price ID is required before contributors can choose this tier.';
            $action = '<span class="status-pill warn">Plan setup needed</span>';
        } else {
            $action = <<"HTML";
<form method="post" action="/admin/billing/checkout" class="inline-form billing-plan-form">
  <input type="hidden" name="csrf_token" value="$safe_csrf">
  <input type="hidden" name="plan_id" value="$id">
  <button type="submit" class="button-link">Choose $name</button>
</form>
HTML
            $action_note = 'Checkout opens in Stripe and activates only after the signed webhook returns.';
        }
        $html .= <<"HTML";
<article class="$card_class"$aria_current>
  <div class="billing-plan-card-head">
    <div>
    <h3>$name</h3>
    <p>$description</p>
  </div>
    <div class="billing-plan-badges">$tier_badge$default_badge</div>
  </div>
  <div class="billing-plan-price"><strong>$price</strong><small>$price_detail</small></div>
  <ul class="billing-plan-features">
    <li><span>Media storage</span><strong>$media_limit</strong></li>
    <li><span>Upload limit</span><strong>$upload_limit</strong></li>
    <li><span>Posts</span><strong>$post_limit</strong></li>
    <li><span>Pages</span><strong>$page_limit</strong></li>
    <li><span>Features</span><strong>$features</strong></li>
    <li><span>Platform Showcase</span><strong>$gallery</strong></li>
    <li><span>Platform Posts</span><strong>$posts</strong></li>
  </ul>
  <div class="billing-plan-action">
    $action
    <small>$action_note</small>
  </div>
</article>
HTML
    }
    return $html || _admin_empty_panel('No plans are available yet.', 'Platform support creates plans before hosted sites can compare or upgrade tiers.');
}

sub _billing_onboarding_flow {
    my ($site) = @_;
    my $plan = escape_html($site->{service_plan_name} || 'Free Tier');
    my $billing = escape_html($site->{billing_status} || 'comped');
    my $status = $site->{status} || '';
    my $status_label = escape_html($status || 'unknown');
    my $site_state = $status eq 'active' ? 'ok' : ($status eq 'pending_provision' ? 'status-pill--neutral' : 'warn');
    my $billing_state = ($site->{billing_status} || '') eq 'past_due' ? 'warn' : 'ok';
    return <<"HTML";
<section class="onboarding-flow onboarding-flow--billing" aria-label="Contributor billing onboarding">
  <div class="onboarding-flow-heading">
    <div>
      <h2>Plan</h2>
      <p>Your hosted site starts on the free tier. Paid plans increase the limits shown below.</p>
    </div>
  </div>
  <div class="onboarding-stage-grid onboarding-stage-grid--billing">
    <article class="onboarding-stage-card"><span>Site</span><strong><span class="status-pill $site_state">Status: $status_label</span></strong><small>Provisioning is handled by the platform.</small></article>
    <article class="onboarding-stage-card"><span>Current Plan</span><strong><span class="status-pill ok">$plan</span></strong><small>This plan controls media, post, and page limits.</small></article>
    <article class="onboarding-stage-card"><span>Billing</span><strong><span class="status-pill $billing_state">$billing</span></strong><small>Stripe webhooks update paid-plan status.</small></article>
  </div>
</section>
HTML
}

sub _admin_absolute_url {
    my ($self, $path) = @_;
    $path = '/' . ($path || '') unless ($path || '') =~ m{\A/};
    my $base = $self->{config}->get('site_url') || 'http://localhost';
    $base =~ s{/+\z}{};
    return $base . $path;
}

sub _postmark_webhook {
    my ($self, $request, $token) = @_;
    return $self->_method_not_allowed unless ($request->{method} || '') eq 'POST';
    my $result = record_postmark_webhook(
        $self->{config},
        $self->{db},
        token => $token,
        body  => $request->{body},
    );
    return $self->_json_response($result->{status} || 200, {
        ok         => $result->{ok} ? 1 : 0,
        event_type => $result->{event_type} || '',
        message_id => $result->{message_id} || '',
        error      => $result->{error} || '',
    });
}

sub _shop_html_response {
    my ($self, $title, $content, $path, $description) = @_;
    $path ||= '/shop/';
    $description ||= 'Shop / Catalog listings.';
    my $url = $self->{shop}->shop_url($path);
    my $body = DesertCMS::Renderer::render_module_page($self->{config}, $self->{db}, {
        title       => $title || 'Shop / Catalog',
        description => $description,
        path        => $path,
        url         => $url,
        content     => $content,
        context     => 'module',
    });
    return DesertCMS::HTTP->response(
        status  => 200,
        headers => {
            'Content-Type' => 'text/html; charset=utf-8',
            'Cache-Control' => 'no-store',
            security_headers(),
        },
        body => $body,
    );
}

sub _public_module_response {
    my ($self, %args) = @_;
    my $html = DesertCMS::Renderer::render_module_page($self->{config}, $self->{db}, {
        title       => $args{title} || 'DesertCMS',
        description => $args{description} || '',
        path        => $args{path} || '/',
        content     => $args{content} || '',
        context     => $args{context} || 'module',
    });
    return DesertCMS::HTTP->response(
        status  => $args{status} || 200,
        headers => {
            'Content-Type' => 'text/html; charset=utf-8',
            security_headers(),
        },
        body => $html,
    );
}

sub _dashboard {
    my ($self, $request, $session, $session_token) = @_;
    return $self->_contributor_dashboard($request, $session, $session_token)
        if DesertCMS::CapabilityPolicy::contributor_product_mode($self->{config});

    my $csrf = $self->{auth}->csrf_token($session_token);
    my $username = escape_html($session->{username});
    my $days = _dashboard_days($request->param('range') || $request->param('days'));
    my $view = _dashboard_view($request->param('view'));
    my $analytics = DesertCMS::Analytics::summary($self->{config}, $self->{db}, days => $days, daily_days => ($days > 30 ? 30 : $days), limit => 8);
    my $health = $self->_dashboard_health($analytics);
    my $dashboard_alerts = _dashboard_alerts($health, $analytics);
    my $daily_chart = $view eq 'table'
        ? _dashboard_daily_table($analytics->{daily})
        : _trend_chart($analytics->{daily}, 'No visits in this range.');
    my $popular_chart = _rank_chart(
        $analytics->{top_pages},
        sub { $_[0]->{path} || '/' },
        sub { int($_[0]->{visits} || 0) },
        'No public visits have been recorded yet.',
        sub { int($_[0]->{unique_ips} || 0) . ' unique IPs' },
    );
    if ($view eq 'table') {
        $popular_chart = _dashboard_page_table($analytics->{top_pages});
    }
    my $location_donut = _donut_chart($analytics->{locations}, 'country', 'visits', 'No visitor locations have been recorded yet.');
    my $city_locations = _table_rows($analytics->{city_locations}, [
        { label => 'Place',  value => 'location_label' },
        { label => 'Visits', value => 'visits' },
        { label => 'Unique', value => 'unique_ips' },
    ], 'No resolved visitor locations yet.');
    my $top_ips = _table_rows($analytics->{top_ips}, [
        { label => 'IP',        value => 'ip_label' },
        { label => 'Location',  value => 'location_label' },
        { label => 'Visits',    value => 'visits' },
        { label => 'Pages',     value => 'pages' },
        { label => 'Last seen', value => sub { _format_time($_[0]->{last_seen}) } },
    ], 'No visitor IPs have been recorded yet.');
    my $referrers = _rank_chart(
        $analytics->{referrers},
        sub { $_[0]->{referrer} || 'Direct' },
        sub { int($_[0]->{visits} || 0) },
        'No external referrers have been recorded yet.',
    );
    my $recent = _table_rows($analytics->{recent}, [
        { label => 'Time',     value => sub { _format_time($_[0]->{occurred_at}) } },
        { label => 'Path',     value => 'path' },
        { label => 'IP',       value => 'ip_label' },
        { label => 'Location', value => 'location_label' },
    ], 'No recent visits.');
    my $geo_coverage = _coverage_meter(
        $analytics->{geo_known_visits},
        $analytics->{visits},
        'Resolved visitor locations'
    );
    my $metrics = join '',
        _metric_card("Visits, $days days", $analytics->{visits}, "$analytics->{unique_ips} unique IPs", $analytics->{visits} ? 'ok' : 'neutral'),
        _metric_card('Visits, 24 hours', $analytics->{visits_24h}, "$analytics->{unique_ips_24h} unique IPs", $analytics->{visits_24h} ? 'ok' : 'neutral'),
        _metric_card('Geo coverage', $health->{geo_coverage_percent} . '%', "$analytics->{geo_unknown_visits} unresolved visits", ($analytics->{visits} && $analytics->{geo_unknown_visits}) ? 'warn' : ($analytics->{visits} ? 'ok' : 'neutral')),
        _metric_card('Published items', $health->{published_items}, "$health->{draft_items} drafts", $health->{published_items} ? 'ok' : 'neutral');
    my $post_action = $self->_posts_module_enabled
        ? '<a class="button-link secondary" href="/admin/posts/new">New post</a>'
        : '';
    my $analytics_controls = _dashboard_analytics_controls($days, $view);
    my $dashboard_widgets = $self->_dashboard_widget_grid($session, $analytics);
    my $daily_days = int($analytics->{daily_days} || 7);

    my $body = <<"HTML";
<section class="dashboard">
  <div class="panel dashboard-hero dashboard-hero--compact">
    <div>
      <p class="eyebrow">Signed in as $username</p>
      <h1>Analytics</h1>
      <p>Traffic, visitor locations, publishing status, and operational health.</p>
      $analytics_controls
    </div>
    <div class="actions">
      <a class="button-link" href="/admin/pages/new">New page</a>
      $post_action
      <a class="button-link secondary" href="/admin/editor">Editor</a>
      <form method="post" action="/admin/rebuild">
        <input type="hidden" name="csrf_token" value="$csrf">
        <button type="submit" class="secondary">Rebuild public site</button>
      </form>
    </div>
  </div>

  $dashboard_widgets

  <section class="dashboard-health-strip" aria-label="Site health">
    <div class="dashboard-health-title">
      <span>Site Health</span>
      <strong>Operational snapshot</strong>
    </div>
    <dl class="dashboard-health-list">
      @{[_dashboard_health_item('Analytics', $health->{analytics_status}, 'compact')]}
      @{[_dashboard_health_item('GeoIP', $health->{geoip_status}, 'wide')]}
      @{[_dashboard_health_item('Sitemap', $health->{sitemap_status}, 'standard')]}
      @{[_dashboard_health_item('Robots', $health->{robots_status}, 'standard')]}
      @{[_dashboard_health_item('Redirects', $health->{redirect_status}, 'standard')]}
      @{[_dashboard_health_item('Database', $health->{db_size}, 'compact')]}
      @{[_dashboard_health_item('Backups', $health->{backup_status}, 'wide')]}
      @{[_dashboard_health_item('Media', "$health->{media_assets} assets, $health->{media_with_alt} with alt", 'wide')]}
    </dl>
  </section>

  $dashboard_alerts

  <section class="metric-grid">
    $metrics
  </section>

  <section class="dashboard-main-grid">
    <section class="panel dashboard-card dashboard-card--full dashboard-card--tall">
      <div class="panel-heading">
        <div>
              <h2>Daily Trend</h2>
              <p>Daily visits and unique IPs across the last $daily_days day(s).</p>
        </div>
      </div>
      $daily_chart
    </section>

    <section class="dashboard-content-grid">
      <div class="dashboard-stack dashboard-stack--primary">
        <section class="panel dashboard-card dashboard-card--medium">
          <div class="panel-heading">
            <div>
              <h2>Popular Pages</h2>
              <p>Most visited public paths.</p>
            </div>
          </div>
          $popular_chart
        </section>

        <section class="panel dashboard-card dashboard-card--wide">
          <div class="panel-heading">
            <div>
              <h2>Visits Per IP</h2>
              <p>Repeat visitors and the pages they touch.</p>
            </div>
          </div>
          <div class="dashboard-table-wrap">
            <table class="content-table compact-table dashboard-table">
              <thead><tr><th>IP</th><th>Location</th><th>Visits</th><th>Pages</th><th>Last seen</th></tr></thead>
              <tbody>$top_ips</tbody>
            </table>
          </div>
        </section>
      </div>

      <div class="dashboard-stack dashboard-stack--secondary">
        <section class="panel dashboard-card dashboard-card--large">
          <div class="panel-heading">
            <div>
              <h2>Visitor Locations</h2>
              <p>Country mix and top resolved places.</p>
            </div>
          </div>
          $location_donut
          $geo_coverage
          <div class="dashboard-table-wrap">
            <table class="content-table compact-table mini-table dashboard-table">
              <thead><tr><th>Place</th><th>Visits</th><th>Unique</th></tr></thead>
              <tbody>$city_locations</tbody>
            </table>
          </div>
        </section>

        <section class="panel dashboard-card dashboard-card--medium">
          <div class="panel-heading">
            <div>
              <h2>Sources</h2>
              <p>External referrers.</p>
            </div>
          </div>
          $referrers
        </section>
      </div>
    </section>

    <section class="panel dashboard-card dashboard-card--full">
      <div class="panel-heading">
        <div>
          <h2>Recent Visits</h2>
          <p>Latest public page views.</p>
        </div>
      </div>
      <div class="dashboard-table-wrap">
        <table class="content-table compact-table dashboard-table">
          <thead><tr><th>Time</th><th>Path</th><th>IP</th><th>Location</th></tr></thead>
          <tbody>$recent</tbody>
        </table>
      </div>
    </section>
  </section>
</section>
HTML
    return $self->_html_response('Analytics', $body, $session);
}

sub _contributor_dashboard {
    my ($self, $request, $session, $session_token) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $dbh = $self->{db}->dbh;
    my $username = escape_html($session->{username} || '');
    my $site_name = escape_html($settings->{site_name} || $self->{config}->get('site_name') || 'Your site');
    my $site_url = $self->{config}->get('site_url') || '/';
    my $site_domain = escape_html($self->{config}->get('contributor_domain') || _url_host($self->{config}->get('site_url')) || '');
    my $page_count = _content_type_count($dbh, 'page');
    my $post_count = _content_type_count($dbh, 'post');
    my ($media_count, $media_bytes) = $dbh->selectrow_array(
        'SELECT COUNT(*), COALESCE(SUM(bytes), 0) FROM media_assets WHERE deleted_at IS NULL'
    );
    $media_count = int($media_count || 0);
    $media_bytes = int($media_bytes || 0);

    my @feature_modules = grep { ($_->{key} || '') ne 'contributor_requests' } @{ DesertCMS::Modules::catalog($settings, config => $self->{config}) };
    my $enabled_features = grep { $_->{enabled} } @feature_modules;
    my $available_features = grep { $_->{available} } @feature_modules;
    my @locked_features = grep { $_->{locked_by_plan} } @feature_modules;
    my $recent_rows = _contributor_recent_content_rows($self->{content}->list_items);
    my $feature_cards = _contributor_feature_cards(\@feature_modules, $self->{config});
    my $plan = $self->_contributor_home_plan_summary($settings, $page_count, $post_count, $media_bytes);
    my $checklist = _contributor_home_checklist(
        pages            => $page_count,
        posts            => $post_count,
        media            => $media_count,
        enabled_features => $enabled_features,
        billing_ready    => $plan->{billing_ready},
        site_url         => $self->{config}->get('site_url') || '',
    );
    my $plan_name = escape_html($plan->{name});
    my $plan_detail = escape_html($plan->{detail});
    my $billing_status = $plan->{status_html};
    my $usage_html = $plan->{usage_html};
    my $can_view_usage = _has_capability($self->{config}, $session, 'view_usage');
    my $upgrade_suggestions = _contributor_upgrade_suggestions(
        locked_features => \@locked_features,
        upgrade_reasons => $plan->{upgrade_reasons},
        can_view_usage  => $can_view_usage,
    );
    my $site_status = _file_status(File::Spec->catfile($self->{config}->get('public_root'), 'index.html'));
    my $media_label = escape_html(_format_bytes($media_bytes));
    my $site_identity = length $site_domain ? "$site_domain" : $site_url;
    $site_identity = escape_html($site_identity || 'Local contributor site');
    my $safe_csrf = escape_html($csrf);
    my $posts_enabled = $self->_posts_module_enabled;
    my $dashboard_actions = '';
    if (_has_capability($self->{config}, $session, 'edit_content')) {
        $dashboard_actions .= qq{<a class="button-link" href="/admin/pages/new">New page</a>};
        $dashboard_actions .= qq{<a class="button-link secondary" href="/admin/posts/new">New post</a>}
            if $posts_enabled;
        $dashboard_actions .= <<"HTML";
      <form method="post" action="/admin/rebuild">
        <input type="hidden" name="csrf_token" value="$safe_csrf">
        <button type="submit" class="secondary">Publish changes</button>
      </form>
HTML
    }
    if (_has_capability($self->{config}, $session, 'upload_media')) {
        $dashboard_actions .= qq{<a class="button-link secondary" href="/admin/media">Upload media</a>};
    }
    $dashboard_actions = length $dashboard_actions ? qq{<div class="actions">$dashboard_actions</div>} : '';
    my @quick_card_defs = (
        { href => '/admin/pages',                        eyebrow => 'Pages',  title => "$page_count pages",     body => 'Edit site structure and landing pages.',                           detail => 'Open Pages',     capability => 'view_content' },
        { href => '/admin/media',                        eyebrow => 'Media',  title => "$media_count assets",   body => 'Upload private sources and use optimized public derivatives.',     detail => "$media_label stored", capability => 'view_media' },
        { href => '/admin/site-settings?section=theme',  eyebrow => 'Design', title => 'Theme',                 body => 'Adjust public layout, typography, colors, and SEO basics.',       detail => 'Open Design',    capability => 'view_design' },
    );
    splice @quick_card_defs, 1, 0, {
        href => '/admin/posts', eyebrow => 'Posts', title => "$post_count posts",
        body => 'Publish dated updates and articles.', detail => 'Open Posts', capability => 'view_content'
    } if $posts_enabled;
    my $quick_cards = _capability_link_cards(
        $self->{config},
        $session,
        @quick_card_defs,
    );
    my $billing_link = $can_view_usage
        ? '<a class="button-link secondary" href="/admin/billing">Open Billing</a>'
        : '';
    my $locked_feature_count = scalar @locked_features;
    my $feature_metric_detail = $locked_feature_count
        ? "$available_features available, $locked_feature_count locked by plan"
        : "$available_features available on this plan";
    my $features_metric = _has_capability($self->{config}, $session, 'view_features')
        ? qq{<article class="metric-card"><span>Features</span><strong>$enabled_features enabled</strong><small>$feature_metric_detail</small></article>}
        : '';
    my $features_panel = '';
    if (_has_capability($self->{config}, $session, 'view_features')) {
        my $feature_manage_link = _has_capability($self->{config}, $session, 'enable_allowed_modules')
            ? '<a class="button-link secondary" href="/admin/settings/modules">Manage</a>'
            : '';
        $features_panel = <<"HTML";
        <section class="panel dashboard-card dashboard-card--medium">
          <div class="panel-heading">
            <div>
              <h2>Features</h2>
              <p>Available site features for this hosted site.</p>
            </div>
            $feature_manage_link
          </div>
          <div class="contributor-feature-list">$feature_cards</div>
        </section>
HTML
    }

    my $body = <<"HTML";
<section class="editor-workspace contributor-home">
  <section class="panel dashboard-hero dashboard-hero--compact">
    <div>
      <p class="eyebrow">Signed in as $username</p>
      <h1>Home</h1>
      <p>$site_name is managed as a hosted site. Build the public site here; platform maintenance is handled for you.</p>
    </div>
    $dashboard_actions
  </section>

  <section class="metric-grid">
    <article class="metric-card"><span>Site Status</span><strong>$site_status</strong><small>$site_identity</small></article>
    <article class="metric-card"><span>Current Plan</span><strong>$plan_name</strong><small>$plan_detail</small></article>
    <article class="metric-card"><span>Billing</span><strong>$billing_status</strong><small>Plans and limits live in Billing.</small></article>
    $features_metric
  </section>

  <section class="dashboard-main-grid">
    <section class="panel dashboard-card dashboard-card--full">
      <div class="panel-heading">
        <div>
          <h2>Usage</h2>
          <p>Plan limits for private source assets, posts, and pages.</p>
        </div>
        $billing_link
      </div>
      $usage_html
    </section>

    <section class="dashboard-content-grid">
      <div class="dashboard-stack dashboard-stack--primary">
        <section class="panel dashboard-card dashboard-card--medium">
          <div class="panel-heading">
            <div>
              <h2>Quick Edit</h2>
              <p>Common site-builder tasks.</p>
            </div>
          </div>
          <div class="workflow-grid contributor-quick-grid">
            $quick_cards
          </div>
        </section>

        <section class="panel dashboard-card dashboard-card--wide">
          <div class="panel-heading">
            <div>
              <h2>Recent Content</h2>
              <p>Latest pages and posts changed on this site.</p>
            </div>
          </div>
          <div class="dashboard-table-wrap">
            <table class="content-table compact-table dashboard-table">
              <thead><tr><th>Title</th><th>Type</th><th>Status</th><th>Updated</th></tr></thead>
              <tbody>$recent_rows</tbody>
            </table>
          </div>
        </section>
      </div>

      <div class="dashboard-stack dashboard-stack--secondary">
        <section class="panel dashboard-card dashboard-card--medium">
          <div class="panel-heading">
            <div>
              <h2>Setup Checklist</h2>
              <p>Finish the essentials for a usable public site.</p>
            </div>
          </div>
          $checklist
        </section>

        <section class="panel dashboard-card dashboard-card--medium">
          <div class="panel-heading">
            <div>
              <h2>Upgrade Suggestions</h2>
              <p>Plan changes that would unlock features or protect current usage.</p>
            </div>
            $billing_link
          </div>
          $upgrade_suggestions
        </section>

        $features_panel
      </div>
    </section>
  </section>
</section>
HTML
    return $self->_html_response('Home', $body, $session);
}

sub _contributor_home_plan_summary {
    my ($self, $settings, $page_count, $post_count, $media_bytes) = @_;
    my $context = eval { $self->_contributor_billing_context };
    if ($context) {
        my $site = $context->{site} || {};
        my $usage = $context->{usage} || {};
        my $usage_html = _billing_usage_html($usage);
        my $price_cents = int($site->{monthly_price_cents} || 0);
        my $detail = $price_cents > 0
            ? _format_money($price_cents, $site->{currency}) . ' per month'
            : 'No monthly charge';
        my @upgrade_reasons = _contributor_upgrade_reasons($site, $usage);
        return {
            name            => $site->{service_plan_name} || 'Free Tier',
            detail          => $detail,
            status_html     => _billing_status_pill($site->{billing_status}),
            usage_html      => $usage_html,
            upgrade_note    => _contributor_upgrade_note($site, $usage),
            upgrade_reasons => \@upgrade_reasons,
            billing_ready   => 1,
        };
    }

    my $media_quota = int($settings->{contributor_media_quota_mb} || 0);
    my $post_quota = int($settings->{contributor_post_quota} || 0);
    my $page_quota = int($settings->{contributor_page_quota} || 0);
    my $media_pct = $media_quota > 0 ? _percent($media_bytes, $media_quota * 1024 * 1024) : 0;
    my $post_pct = $post_quota > 0 ? _percent($post_count, $post_quota) : 0;
    my $page_pct = $page_quota > 0 ? _percent($page_count, $page_quota) : 0;
    my $usage_html = '<div class="billing-usage-grid">'
        . _usage_meter(_format_bytes($media_bytes) . ($media_quota ? ' of ' . $media_quota . ' MB media' : ' media'), $media_pct)
        . _usage_meter($post_count . ($post_quota ? ' of ' . $post_quota : '') . ' posts', $post_pct)
        . _usage_meter($page_count . ($page_quota ? ' of ' . $page_quota : '') . ' pages', $page_pct)
        . '</div>';
    return {
        name            => 'Plan unavailable',
        detail          => 'Platform billing context is not linked.',
        status_html     => '<span class="status-pill warn">Needs setup</span>',
        usage_html      => $usage_html,
        upgrade_note    => '<p class="notice">Connect this hosted site to platform billing to show current plan, billing status, and upgrade options.</p>',
        upgrade_reasons => [
            {
                label  => 'Setup',
                title  => 'Connect billing context',
                detail => 'Connect this hosted site to platform billing to show current plan, billing status, and upgrade options.',
            },
        ],
        billing_ready   => 0,
    };
}

sub _contributor_upgrade_reasons {
    my ($site, $usage) = @_;
    $site ||= {};
    $usage ||= {};
    my @reasons;
    push @reasons, {
        label  => 'Usage',
        title  => 'Media storage is near its limit',
        detail => 'Upgrade before private source assets reach the current media quota.',
    } if int($usage->{media_percent} || 0) >= 80;
    push @reasons, {
        label  => 'Usage',
        title  => 'Post count is near its limit',
        detail => 'Upgrade before publishing reaches the current post quota.',
    } if int($usage->{post_percent} || 0) >= 80;
    push @reasons, {
        label  => 'Usage',
        title  => 'Page count is near its limit',
        detail => 'Upgrade before site structure reaches the current page quota.',
    } if int($usage->{page_percent} || 0) >= 80;
    push @reasons, {
        label  => 'Billing',
        title  => 'Billing needs attention',
        detail => 'Update billing to keep the contributor site active.',
    } if ($site->{billing_status} || '') eq 'past_due';
    return @reasons;
}

sub _contributor_upgrade_note {
    my ($site, $usage) = @_;
    my @reasons = _contributor_upgrade_reasons($site, $usage);
    return '' unless @reasons;
    return '<p class="notice">Consider upgrading: ' . escape_html(join(', ', map { lcfirst($_->{title} || '') } @reasons)) . '.</p>';
}

sub _contributor_upgrade_suggestions {
    my (%args) = @_;
    my $locked_features = $args{locked_features} || [];
    my $upgrade_reasons = $args{upgrade_reasons} || [];
    my $can_view_usage = $args{can_view_usage} ? 1 : 0;
    my @items;

    for my $module (@{$locked_features}) {
        push @items, {
            label  => 'Feature',
            title  => 'Unlock ' . ($module->{label} || 'feature'),
            detail => $module->{description} || 'This feature is available on a higher plan.',
        };
    }
    push @items, @{$upgrade_reasons};

    return _admin_empty_panel(
        'No upgrade suggestions right now.',
        'This site is within its current plan and no locked features need attention.'
    ) unless @items;

    my $action = $can_view_usage
        ? '<a class="button-link secondary" href="/admin/billing">Compare plans</a>'
        : '';
    my $html = '<ul class="contributor-suggestion-list">';
    for my $item (@items) {
        my $label = escape_html($item->{label} || 'Plan');
        my $title = escape_html($item->{title} || 'Review plan');
        my $detail = escape_html($item->{detail} || 'Review the current plan for available upgrade options.');
        $html .= <<"HTML";
<li>
  <span>$label</span>
  <div>
    <strong>$title</strong>
    <small>$detail</small>
  </div>
  $action
</li>
HTML
    }
    $html .= '</ul>';
    return $html;
}

sub _contributor_recent_content_rows {
    my ($items) = @_;
    $items ||= [];
    my $html = '';
    my $count = 0;
    for my $item (@{$items}) {
        last if $count++ >= 5;
        my $id = int($item->{id} || 0);
        my $title = escape_html($item->{title} || 'Untitled');
        my $type = escape_html(_title_case_status($item->{type} || 'page'));
        my $status = escape_html(_title_case_status($item->{status} || 'draft'));
        my $updated = escape_html(_format_time($item->{updated_at}));
        $html .= <<"HTML";
<tr>
  <td data-label="Title"><a href="/admin/content/$id/edit">$title</a></td>
  <td data-label="Type">$type</td>
  <td data-label="Status"><span class="status-pill status-pill--neutral">$status</span></td>
  <td data-label="Updated">$updated</td>
</tr>
HTML
    }
    return $html || _admin_empty_row(4, 'No content yet.', 'Create a page or post to start building this site.');
}

sub _contributor_feature_cards {
    my ($modules, $config) = @_;
    my $html = '';
    for my $module (@{$modules || []}) {
        my $label = escape_html($module->{label} || '');
        my $state = _module_status_html($module, $config);
        my $detail = escape_html($module->{description} || 'Optional site feature.');
        my $path = escape_html($module->{public_path} || 'No public page');
        my $key = escape_html($module->{key} || '');
        $html .= qq{<article data-feature-key="$key"><strong>$label</strong>$state<small>$detail</small><small>$path</small></article>};
    }
    return $html || _admin_empty_panel('No features available.', 'The platform has not exposed any optional features for this site yet.');
}

sub _contributor_home_checklist {
    my (%args) = @_;
    my @items = (
        [ $args{pages} ? 1 : 0, 'Create core pages' ],
        [ $args{media} ? 1 : 0, 'Upload media assets' ],
        [ length($args{site_url} || '') ? 1 : 0, 'Confirm public URL' ],
        [ $args{enabled_features} ? 1 : 0, 'Choose site features' ],
        [ $args{billing_ready} ? 1 : 0, 'Review billing and limits' ],
    );
    my $html = '<ul class="contributor-checklist">';
    for my $item (@items) {
        my ($done, $label) = @{$item};
        my $class = $done ? 'is-done' : 'is-open';
        my $status = $done ? 'Done' : 'Open';
        $html .= '<li class="' . $class . '"><span>' . escape_html($status) . '</span><strong>' . escape_html($label) . '</strong></li>';
    }
    $html .= '</ul>';
    return $html;
}

sub _dashboard_health_item {
    my ($label, $value, $size) = @_;
    $size = _clean_choice($size, 'standard', qw(compact standard wide full));
    my $safe_label = escape_html($label || '');
    $value = '' unless defined $value;
    my $state = $value =~ /status-pill\s+warn/ ? 'warn'
        : $value =~ /status-pill\s+ok/ ? 'ok'
        : 'neutral';
    return qq{<div class="dashboard-health-item dashboard-health-item--$size dashboard-health-item--$state"><dt>$safe_label</dt><dd>$value</dd></div>};
}

sub _metric_card {
    my ($label, $value, $detail, $state) = @_;
    $state = _clean_choice($state, 'neutral', qw(ok warn neutral));
    my $safe_label = escape_html($label || '');
    my $safe_value = escape_html(defined $value ? $value : '');
    my $safe_detail = escape_html($detail || '');
    return qq{<article class="metric-card metric-card--$state"><span>$safe_label</span><strong>$safe_value</strong><small>$safe_detail</small></article>};
}

sub _dashboard_alerts {
    my ($health, $analytics) = @_;
    my @alerts;
    push @alerts, 'Analytics collection is disabled.' unless $health->{analytics_enabled};
    if (($health->{geoip_state} || '') eq 'warn') {
        push @alerts, $health->{geoip_alert} || 'GeoIP data needs attention.';
    }
    if (int(($analytics || {})->{visits} || 0) && int(($analytics || {})->{geo_unknown_visits} || 0)) {
        push @alerts, int($analytics->{geo_unknown_visits}) . ' visit(s) do not have a resolved location.';
    }
    push @alerts, 'Sitemap is missing from the public site.' unless $health->{sitemap_present};
    push @alerts, 'Robots.txt is missing from the public site.' unless $health->{robots_present};
    push @alerts, 'No backups have been recorded yet.' unless int($health->{backup_count} || 0) > 0;
    return '' unless @alerts;

    my $items = join '', map { '<li>' . escape_html($_) . '</li>' } @alerts;
    return qq{<section class="dashboard-alerts" aria-label="Analytics alerts"><div><span>Needs attention</span><strong>Dashboard alerts</strong></div><ul>$items</ul></section>};
}

sub _dashboard_health {
    my ($self, $analytics) = @_;
    my $dbh = $self->{db}->dbh;
    my ($published_items) = $dbh->selectrow_array(
        "SELECT COUNT(*) FROM content_items WHERE status = 'published' AND deleted_at IS NULL"
    );
    my ($draft_items) = $dbh->selectrow_array(
        "SELECT COUNT(*) FROM content_items WHERE status = 'draft' AND deleted_at IS NULL"
    );
    my ($media_assets) = $dbh->selectrow_array(
        'SELECT COUNT(*) FROM media_assets WHERE deleted_at IS NULL'
    );
    my ($media_with_alt) = $dbh->selectrow_array(
        "SELECT COUNT(*) FROM media_assets WHERE deleted_at IS NULL AND alt_text <> ''"
    );
    my ($backup_count, $last_backup) = $dbh->selectrow_array(
        'SELECT COUNT(*), MAX(created_at) FROM backups'
    );

    my $public_root = $self->{config}->get('public_root');
    my $sitemap = File::Spec->catfile($public_root, 'sitemap.xml');
    my $robots = File::Spec->catfile($public_root, 'robots.txt');
    my $redirects = File::Spec->catfile($public_root, 'redirects.httpd.conf');
    my $sitemap_present = -f $sitemap ? 1 : 0;
    my $robots_present = -f $robots ? 1 : 0;
    my $redirects_present = -f $redirects ? 1 : 0;
    my $db_path = $self->{config}->get('db_path');
    my $geoip = DesertCMS::GeoIP::status($self->{db});
    my $geo_coverage_percent = _percent($analytics->{geo_known_visits}, $analytics->{visits});
    my $geoip_status = '';
    my $geoip_state = 'warn';
    my $geoip_alert = '';
    if ($geoip->{count} && ($geoip->{format} || '') =~ /observed/i) {
        $geoip_status = '<span class="status-pill warn">Observed only</span><small>' . escape_html($geoip->{count} . ' ranges') . '</small>';
        $geoip_alert = 'GeoIP is using observed ranges only; import the full city database for stronger coverage.';
    } elsif ($geoip->{count}) {
        $geoip_status = '<span class="status-pill ok">' . escape_html($geoip->{count} . ' ranges') . '</span>';
        $geoip_state = 'ok';
    } else {
        $geoip_status = '<span class="status-pill warn">Not imported</span>';
        $geoip_alert = 'GeoIP data has not been imported.';
    }
    if (($geoip->{source} || '') =~ /DB-IP/i) {
        $geoip_status .= ' <small><a href="https://db-ip.com" rel="nofollow noopener">IP Geolocation by DB-IP</a></small>';
    }
    my $analytics_enabled = DesertCMS::Analytics::enabled($self->{config}) ? 1 : 0;

    return {
        published_items  => int($published_items || 0),
        draft_items      => int($draft_items || 0),
        media_assets     => int($media_assets || 0),
        media_with_alt   => int($media_with_alt || 0),
        geo_coverage_percent => $geo_coverage_percent,
        geoip_state      => $geoip_state,
        geoip_alert      => $geoip_alert,
        analytics_enabled => $analytics_enabled,
        sitemap_present  => $sitemap_present,
        robots_present   => $robots_present,
        redirects_present => $redirects_present,
        backup_count     => int($backup_count || 0),
        geoip_status     => $geoip_status,
        analytics_status => $analytics_enabled ? '<span class="status-pill ok">Collecting</span>' : '<span class="status-pill warn">Disabled</span>',
        sitemap_status   => _file_status($sitemap),
        robots_status    => _file_status($robots),
        redirect_status  => _file_status($redirects),
        db_size          => escape_html(_format_bytes(-s $db_path || 0)),
        backup_status    => escape_html(int($backup_count || 0) . ' total' . ($last_backup ? ', last ' . _format_time($last_backup) : '')),
    };
}

sub _table_rows {
    my ($rows, $columns, $empty) = @_;
    my $colspan = int(@{$columns});
    return qq{<tr class="dashboard-empty-row"><td colspan="$colspan">} . _dashboard_empty($empty || 'No data yet.') . '</td></tr>'
        unless @{$rows};

    my $html = '';
    for my $row (@{$rows}) {
        $html .= '<tr>';
        for my $column (@{$columns}) {
            my $value = ref $column->{value} eq 'CODE' ? $column->{value}->($row) : $row->{$column->{value}};
            my $label = defined $column->{label} && length $column->{label}
                ? ' data-label="' . escape_html($column->{label}) . '"'
                : '';
            $html .= '<td' . $label . '>' . escape_html($value) . '</td>';
        }
        $html .= '</tr>';
    }
    return $html;
}

sub _dashboard_empty {
    my ($message) = @_;
    return '<div class="dashboard-empty" role="status"><span class="dashboard-empty-mark"></span><strong>Waiting for data</strong><small>' . escape_html($message || 'Activity will appear here after the site receives traffic.') . '</small></div>';
}

sub _dashboard_days {
    my ($value) = @_;
    $value = lc($value || '30');
    return 1 if $value eq '24h';
    return 7 if $value eq '7d';
    return 30 if $value eq '30d';
    return 90 if $value eq '90d';
    return 365 if $value eq '365d';
    my $days = int($value || 30);
    return 7 if $days == 7;
    return 30 if $days == 30;
    return 90 if $days == 90;
    return 365 if $days == 365;
    return 30;
}

sub _dashboard_view {
    my ($value) = @_;
    return _clean_choice(lc($value || ''), 'chart', qw(chart table));
}

sub _dashboard_analytics_controls {
    my ($days, $view) = @_;
    my @ranges = (
        [ 1,   '24h' ],
        [ 7,   '7d' ],
        [ 30,  '30d' ],
        [ 90,  '90d' ],
        [ 365, '365d' ],
    );
    my $range_links = '';
    for my $range (@ranges) {
        my ($value, $label) = @{$range};
        my $class = $value == $days ? ' class="active" aria-current="page"' : '';
        my $safe_view = escape_html($view);
        $range_links .= qq{<a href="/admin?range=$value&view=$safe_view"$class>$label</a>};
    }
    my $chart_class = $view eq 'chart' ? ' class="active" aria-current="page"' : '';
    my $table_class = $view eq 'table' ? ' class="active" aria-current="page"' : '';
    return <<"HTML";
<div class="dashboard-controls" aria-label="Analytics controls">
  <nav aria-label="Time range">$range_links</nav>
  <nav aria-label="Graph view">
    <a href="/admin?range=$days&view=chart"$chart_class>Charts</a>
    <a href="/admin?range=$days&view=table"$table_class>Tables</a>
  </nav>
</div>
HTML
}

sub _dashboard_daily_table {
    my ($rows) = @_;
    my $body = _table_rows($rows || [], [
        { label => 'Day', value => 'day' },
        { label => 'Visits', value => 'visits' },
        { label => 'Unique IPs', value => 'unique_ips' },
    ], 'No daily analytics yet.');
    return qq{<div class="dashboard-table-wrap"><table class="content-table compact-table dashboard-table"><thead><tr><th>Day</th><th>Visits</th><th>Unique IPs</th></tr></thead><tbody>$body</tbody></table></div>};
}

sub _dashboard_page_table {
    my ($rows) = @_;
    my $body = _table_rows($rows || [], [
        { label => 'Path', value => 'path' },
        { label => 'Visits', value => 'visits' },
        { label => 'Unique IPs', value => 'unique_ips' },
    ], 'No page analytics yet.');
    return qq{<div class="dashboard-table-wrap"><table class="content-table compact-table dashboard-table"><thead><tr><th>Path</th><th>Visits</th><th>Unique IPs</th></tr></thead><tbody>$body</tbody></table></div>};
}

sub _dashboard_widget_grid {
    my ($self, $session, $analytics) = @_;
    my $widgets = $self->{dashboard}->widgets_for_user(
        user_id => $session ? $session->{user_id} : 0,
        role    => $session ? ($session->{role} || 'owner') : 'owner',
    );
    my $html = '';
    for my $widget (@{$widgets}) {
        next unless $widget->{enabled};
        next if ($widget->{capability} || '') && !_has_capability($self->{config}, $session, $widget->{capability});
        $html .= $self->_dashboard_widget_card($widget, $analytics);
    }
    return '' unless length $html;
    return qq{<section class="dashboard-widget-grid" aria-label="Custom dashboard widgets">$html</section>};
}

sub _dashboard_widget_card {
    my ($self, $widget, $analytics) = @_;
    my $key = $widget->{key} || '';
    my $label = escape_html($widget->{label} || $key);
    my $size = _dashboard_widget_size_class($widget->{size});
    my ($value, $detail, $href) = ('', '', '/admin/settings/dashboard');
    if ($key eq 'analytics_overview') {
        $value = int(($analytics || {})->{visits} || 0) . ' visits';
        $detail = int(($analytics || {})->{unique_ips} || 0) . ' unique IPs in ' . int(($analytics || {})->{days} || 30) . ' day(s)';
        $href = '/admin';
    } elsif ($key eq 'top_pages') {
        my $top = (($analytics || {})->{top_pages} || [])->[0] || {};
        $value = $top->{path} || 'No page visits';
        $detail = int($top->{visits} || 0) . ' visits';
        $href = '/admin?view=table';
    } elsif ($key eq 'top_ips') {
        my $top = (($analytics || {})->{top_ips} || [])->[0] || {};
        $value = $top->{ip_label} || 'No IP activity';
        $detail = int($top->{visits} || 0) . ' visits across ' . int($top->{pages} || 0) . ' page(s)';
        $href = '/admin?view=table';
    } elsif ($key eq 'security_summary') {
        my $checks = $self->{security_center}->run_checks;
        my $critical = grep { ($_->{status} || '') eq 'critical' } @{$checks};
        my $warning = grep { ($_->{status} || '') eq 'warning' } @{$checks};
        $value = int($critical) . ' critical';
        $detail = int($warning) . ' warning(s), read-only checks';
        $href = '/admin/settings/security';
    } elsif ($key eq 'notifications') {
        $value = $self->{notifications}->unread_count(audience => 'admin') . ' unread';
        $detail = 'Admin and module event inbox';
        $href = '/admin/notifications';
    } elsif ($key eq 'module_status') {
        my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
        my @modules = @{ DesertCMS::Modules::catalog($settings, config => $self->{config}) };
        my $enabled = grep { $_->{enabled} } @modules;
        $value = int($enabled) . ' enabled';
        $detail = scalar(@modules) . ' first-party features in catalog';
        $href = '/admin/settings/modules';
    } elsif ($key eq 'billing_usage') {
        $value = 'Billing';
        $detail = 'Plan, quotas, email, and payments';
        $href = '/admin/billing';
    } elsif ($key eq 'realtime_status') {
        my $status = DesertCMS::Realtime->service_status($self->{config});
        $value = $status->{enabled} ? 'Enabled' : 'Disabled';
        $detail = $status->{host} . ':' . $status->{port};
        $href = '/admin/settings/realtime';
    } else {
        $value = $label;
        $detail = 'Manifest-provided dashboard widget';
    }
    my $safe_value = escape_html($value);
    my $safe_detail = escape_html($detail);
    my $safe_href = escape_html($href);
    return qq{<a class="dashboard-widget dashboard-widget--$size" href="$safe_href"><span>$label</span><strong>$safe_value</strong><small>$safe_detail</small></a>};
}

sub _dashboard_widget_size_class {
    my ($size) = @_;
    return _clean_choice($size, 'medium', qw(small medium large wide));
}

sub _admin_icon {
    my ($name) = @_;
    my %paths = (
        comments => '<path d="M21 15a4 4 0 0 1-4 4H8l-5 3V7a4 4 0 0 1 4-4h10a4 4 0 0 1 4 4Z"/><path d="M8 9h8M8 13h5"/>',
        trash    => '<path d="M3 6h18"/><path d="M8 6V4h8v2"/><path d="M19 6l-1 14H6L5 6"/><path d="M10 11v5M14 11v5"/>',
    );
    my $path = $paths{$name} || $paths{comments};
    return qq{<svg class="admin-action-icon" viewBox="0 0 24 24" aria-hidden="true">$path</svg>};
}

sub _bar_chart {
    my ($rows, $label_key, $value_key, $empty) = @_;
    return _dashboard_empty($empty || 'No data yet.') unless @{$rows};

    my $max = 0;
    for my $row (@{$rows}) {
        my $value = int($row->{$value_key} || 0);
        $max = $value if $value > $max;
    }
    $max ||= 1;

    my $html = '<div class="bar-chart">';
    for my $row (@{$rows}) {
        my $label = escape_html($row->{$label_key} || 'Unknown');
        my $value = int($row->{$value_key} || 0);
        my $width = int(($value / $max) * 100);
        $width = 4 if $value > 0 && $width < 4;
        $html .= qq{<div class="bar-row"><span>$label</span><div class="bar-track"><i style="width: $width%"></i></div><strong>$value</strong></div>};
    }
    $html .= '</div>';
    return $html;
}

sub _trend_chart {
    my ($rows, $empty) = @_;
    my %by_day = map { ($_->{day} || '') => $_ } @{$rows};
    my @days;
    for my $offset (reverse 0 .. 6) {
        my $ts = now() - ($offset * 86400);
        my ($mday, $mon, $year) = (localtime($ts))[3, 4, 5];
        my $key = sprintf('%04d-%02d-%02d', $year + 1900, $mon + 1, $mday);
        my $row = $by_day{$key} || {};
        push @days, {
            key        => $key,
            label      => _short_day_label($ts),
            visits     => int($row->{visits} || 0),
            unique_ips => int($row->{unique_ips} || 0),
        };
    }
    my $total = 0;
    my $max = 0;
    for my $day (@days) {
        $total += $day->{visits};
        $max = $day->{visits} if $day->{visits} > $max;
    }
    return _dashboard_empty($empty || 'No data yet.') unless $total;
    $max ||= 1;

    my $html = '<div class="trend-chart">';
    for my $day (@days) {
        my $height = int(($day->{visits} / $max) * 100);
        $height = 2 if $day->{visits} > 0 && $height < 2;
        my $label = escape_html($day->{label});
        my $visits = int($day->{visits});
        my $unique = int($day->{unique_ips});
        $html .= qq{<div class="trend-day" style="--bar-height: $height%"><strong>$visits</strong><div class="trend-bar"><i></i></div><span>$label</span><small>$unique unique</small></div>};
    }
    $html .= '</div>';
    return $html;
}

sub _rank_chart {
    my ($rows, $label_cb, $value_cb, $empty, $detail_cb) = @_;
    return _dashboard_empty($empty || 'No data yet.') unless @{$rows};
    my $max = 0;
    for my $row (@{$rows}) {
        my $value = int($value_cb->($row) || 0);
        $max = $value if $value > $max;
    }
    return _dashboard_empty($empty || 'No data yet.') unless $max;

    my $html = '<div class="rank-chart">';
    for my $row (@{$rows}) {
        my $label = escape_html($label_cb->($row) || 'Unknown');
        my $value = int($value_cb->($row) || 0);
        my $width = int(($value / $max) * 100);
        $width = 5 if $value > 0 && $width < 5;
        my $detail = $detail_cb ? '<small>' . escape_html($detail_cb->($row) || '') . '</small>' : '';
        $html .= qq{<div class="rank-row"><div><span>$label</span>$detail</div><i class="rank-track"><b style="width: $width%"></b></i><strong>$value</strong></div>};
    }
    $html .= '</div>';
    return $html;
}

sub _donut_chart {
    my ($rows, $label_key, $value_key, $empty) = @_;
    return _dashboard_empty($empty || 'No data yet.') unless @{$rows};
    my $total = 0;
    for my $row (@{$rows}) {
        $total += int($row->{$value_key} || 0);
    }
    return _dashboard_empty($empty || 'No data yet.') unless $total;

    my @colors = qw(var(--chart-1) var(--chart-2) var(--chart-3) var(--chart-4) var(--chart-5) var(--chart-6));
    my @segments;
    my $angle = 0;
    my $legend = '';
    my $i = 0;
    for my $row (@{$rows}) {
        my $value = int($row->{$value_key} || 0);
        next unless $value > 0;
        my $sweep = ($value / $total) * 360;
        my $start = sprintf('%.2fdeg', $angle);
        $angle += $sweep;
        my $end = sprintf('%.2fdeg', $angle);
        my $color = $colors[$i % @colors];
        push @segments, "$color $start $end";
        my $label = escape_html($row->{$label_key} || 'Unknown');
        my $pct = _percent($value, $total);
        $legend .= qq{<li><span style="--dot-color: $color"></span><strong>$label</strong><em>$value visits, $pct%</em></li>};
        $i++;
    }
    my $gradient = @segments ? 'conic-gradient(' . join(', ', @segments) . ')' : 'var(--field)';
    my $safe_total = int($total);
    return qq{<div class="donut-summary"><div class="donut-chart" style="background: $gradient"><span>$safe_total</span><small>visits</small></div><ul class="donut-legend">$legend</ul></div>};
}

sub _coverage_meter {
    my ($known, $total, $label) = @_;
    my $pct = _percent($known, $total);
    my $unknown = int($total || 0) - int($known || 0);
    $unknown = 0 if $unknown < 0;
    my $safe_label = escape_html($label || 'Coverage');
    return qq{<div class="coverage-meter"><div><span>$safe_label</span><strong>$pct%</strong></div><i><b style="width: $pct%"></b></i><small>$unknown unresolved visits</small></div>};
}

sub _percent {
    my ($part, $total) = @_;
    $part = int($part || 0);
    $total = int($total || 0);
    return 0 if $total <= 0;
    my $pct = int(($part / $total) * 100 + 0.5);
    return 100 if $pct > 100;
    return $pct;
}

sub _short_day_label {
    my ($epoch) = @_;
    my @names = qw(Sun Mon Tue Wed Thu Fri Sat);
    my $wday = (localtime($epoch))[6];
    return $names[$wday] || '';
}

sub _file_status {
    my ($path) = @_;
    return '<span class="status-pill ok">Present</span>' if -f $path;
    return '<span class="status-pill warn">Missing</span>';
}

sub _search_status_summary {
    my ($status, $submitted_at, $error, $count) = @_;
    if (($status || '') eq 'submitted') {
        my $detail = 'Last submitted ' . escape_html(_format_time($submitted_at));
        $detail .= ', ' . int($count) . ' URLs' if defined $count && length $count;
        return qq{<span class="status-pill ok">Submitted</span><small>$detail</small>};
    }
    if (($status || '') eq 'failed') {
        my $safe_error = escape_html($error || 'Submission failed');
        return qq{<span class="status-pill warn">Needs attention</span><small>$safe_error</small>};
    }
    return '<span class="status-pill status-pill--neutral">Not submitted yet</span><small>Submit after the public site has been rebuilt.</small>';
}

sub _format_time {
    my ($epoch) = @_;
    return 'Never' unless $epoch;
    return scalar localtime($epoch);
}

sub _format_bytes {
    my ($bytes) = @_;
    $bytes ||= 0;
    return $bytes . ' B' if $bytes < 1024;
    return sprintf('%.1f KB', $bytes / 1024) if $bytes < 1024 * 1024;
    return sprintf('%.1f MB', $bytes / 1024 / 1024);
}

sub _editor_home {
    my ($self, $request, $session, $session_token) = @_;
    $self->_ensure_default_templates;
    my $dbh = $self->{db}->dbh;
    my $page_count = _content_type_count($dbh, 'page');
    my $post_count = _content_type_count($dbh, 'post');
    my ($media_count) = $dbh->selectrow_array('SELECT COUNT(*) FROM media_assets WHERE deleted_at IS NULL');
    my $safe_media_count = int($media_count || 0);
    my $template_count = scalar @{$self->_template_rows};
    my $nav_count = scalar @{DesertCMS::Navigation::list_items($self->{config}, $self->{db})};
    my $redirect_count = scalar @{DesertCMS::Redirects::list_rules($self->{config}, $self->{db})};
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $posts_enabled = $self->_posts_module_enabled;
    my $enabled_modules = 0;
    for my $module (@{DesertCMS::Modules::definitions($settings)}) {
        $enabled_modules++ if $module->{enabled};
    }
    my $is_contributor_product = DesertCMS::CapabilityPolicy::contributor_product_mode($self->{config});
    my $editor_nav = _editor_nav('overview', $self->{config}, $session, $settings);
