            ? '<a class="button-link secondary" href="/admin/posts/new">New post</a>'
            : '';
        $editor_actions = <<"HTML";
    <div class="actions">
      <a class="button-link" href="/admin/pages/new">New page</a>
      $post_action
    </div>
HTML
    }
    my @workflow_card_defs = $is_contributor_product ? (
        { href => '/admin/pages',             eyebrow => 'Pages',        title => 'Site pages',       body => 'Home, about, galleries, landing pages, and nested pages.',                      detail => "$page_count total",       capability => 'view_content' },
        { href => '/admin/posts',             eyebrow => 'Posts',        title => 'Updates',          body => 'Optional dated writing for news, articles, notes, and announcements.',          detail => "$post_count total",       capability => 'view_content' },
        { href => '/admin/media',             eyebrow => 'Media',        title => 'Media library',    body => 'Upload private source assets and publish optimized public derivatives.',       detail => "$safe_media_count assets", capability => 'view_media' },
        { href => '/admin/templates',         eyebrow => 'Layouts',      title => 'Reusable layouts', body => 'Save page structures and reuse them when creating new pages.',                  detail => "$template_count layouts",  capability => 'view_content' },
        { href => '/admin/navigation',        eyebrow => 'Menus',        title => 'Site menus',       body => 'Choose the links visitors use to move through the site.',                      detail => "$nav_count links",        capability => 'view_content' },
        { href => '/admin/redirects',         eyebrow => 'URLs',         title => 'URL redirects',    body => 'Send old public paths to the right current pages.',                            detail => "$redirect_count rules",   capability => 'view_content' },
        { href => '/admin/settings/modules',  eyebrow => 'Features',     title => 'Feature catalog',  body => 'Turn allowed feature areas on or off and open each feature setup page.',       detail => "$enabled_modules enabled", capability => 'view_features' },
        { href => '/admin/site-settings',     eyebrow => 'Site basics',  title => 'Identity and SEO', body => 'Set site identity, homepage defaults, search text, and public design defaults.', detail => 'Identity, search, design',  capability => 'view_design' },
    ) : (
        { href => '/admin/pages',             eyebrow => 'Pages',      title => 'Site pages',       body => 'Home, about, galleries, landing pages, and nested pages.',                  detail => "$page_count total",      capability => 'view_content' },
        { href => '/admin/posts',             eyebrow => 'Posts',      title => 'Field notes',      body => 'Optional dated writing. Use pages instead when an article should sit inside the site structure.', detail => "$post_count total", capability => 'view_content' },
        { href => '/admin/media',             eyebrow => 'Media',      title => 'Media library',    body => 'Upload private source assets and use optimized display derivatives.',       detail => "$safe_media_count assets", capability => 'view_media' },
        { href => '/admin/templates',         eyebrow => 'Templates',  title => 'Reusable layouts', body => 'Save page structures and reuse them when creating new pages.',               detail => "$template_count templates", capability => 'view_content' },
        { href => '/admin/navigation',        eyebrow => 'Navigation', title => 'Site menus',       body => 'Choose the links visitors use to move through the site.',                   detail => "$nav_count links",       capability => 'view_content' },
        { href => '/admin/redirects',         eyebrow => 'Redirects',  title => 'Moved URLs',       body => 'Send old public paths to the right current pages.',                         detail => "$redirect_count rules",  capability => 'view_content' },
        { href => '/admin/settings/modules',  eyebrow => 'Features',   title => 'Modules',          body => "Turn public feature areas on or off and open each module's focused settings.", detail => "$enabled_modules enabled", capability => 'view_features' },
        { href => '/admin/site-settings',     eyebrow => 'Site',       title => 'Site & SEO',       body => 'Set identity, homepage defaults, search metadata, indexing, and theme defaults.', detail => 'Identity, SEO, theme', capability => 'view_design' },
    );
    @workflow_card_defs = grep { $posts_enabled || ($_->{href} || '') ne '/admin/posts' } @workflow_card_defs;
    my $workflow_cards = _capability_link_cards($self->{config}, $session, @workflow_card_defs);
    my $hero_eyebrow = $is_contributor_product ? 'Site Builder' : 'Editor';
    my $hero_title = $is_contributor_product ? 'Build Your Site' : 'Build the Site';
    my $hero_intro = $is_contributor_product
        ? 'Create pages, publish updates, upload media, and shape how visitors move through the site.'
        : 'Work from the outside in: make pages, add media, then shape the navigation and redirects that connect everything.';

    my $body = <<"HTML";
<section class="editor-workspace">
  $editor_nav
  <section class="editor-hero panel">
    <div>
      <p class="eyebrow">$hero_eyebrow</p>
      <h1>$hero_title</h1>
      <p>$hero_intro</p>
    </div>
    $editor_actions
  </section>

  <section class="workflow-grid">
    $workflow_cards
  </section>
</section>
HTML
    return $self->_html_response('Editor', $body, $session);
}

sub _content_type_count {
    my ($dbh, $type) = @_;
    my ($count) = $dbh->selectrow_array(
        'SELECT COUNT(*) FROM content_items WHERE type = ? AND deleted_at IS NULL',
        undef,
        $type
    );
    return int($count || 0);
}

sub _posts_module_enabled {
    my ($self) = @_;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    return DesertCMS::Modules::enabled($settings, 'posts') ? 1 : 0;
}

sub _editor_nav {
    my ($active, $config, $session, $settings) = @_;
    my $role = $session ? $session->{role} : 'owner';
    my $is_contributor_product = $config && DesertCMS::CapabilityPolicy::contributor_product_mode($config);
    my $posts_enabled = $settings && exists $settings->{module_posts_enabled}
        ? DesertCMS::Modules::enabled($settings, 'posts')
        : 1;
    my %module_active = map { $_ => 1 } qw(
        modules posts shop map gallery showcase forms docs events directory bookings membership newsletter donations testimonials
        accounts live_streaming forums social notifications security_center
    );
    return '' if $module_active{$active || ''};
    my @links = $is_contributor_product ? (
        [ overview => '/admin/editor', 'Site Builder', 'view_content' ],
        [ pages    => '/admin/pages', 'Pages', 'view_content' ],
        [ posts    => '/admin/posts', 'Posts', 'view_content' ],
        [ media    => '/admin/media', 'Media', 'view_media' ],
        [ templates => '/admin/templates', 'Layouts', 'view_content' ],
        [ sections => '/admin/sections', 'Blocks', 'view_content' ],
        [ nav      => '/admin/navigation', 'Menus', 'view_content' ],
        [ redirects => '/admin/redirects', 'URL Redirects', 'view_content' ],
        [ site_settings => '/admin/site-settings', 'Site Basics', 'view_design' ],
        [ theme    => '/admin/site-settings?section=theme', 'Design', 'view_design' ],
    ) : (
        [ overview => '/admin/editor', 'Overview', 'view_content' ],
        [ pages    => '/admin/pages', 'Pages', 'view_content' ],
        [ posts    => '/admin/posts', 'Posts', 'view_content' ],
        [ media    => '/admin/media', 'Media', 'view_media' ],
        [ templates => '/admin/templates', 'Templates', 'view_content' ],
        [ sections => '/admin/sections', 'Sections', 'view_content' ],
        [ nav      => '/admin/navigation', 'Navigation', 'view_content' ],
        [ redirects => '/admin/redirects', 'Redirects', 'view_content' ],
        [ site_settings => '/admin/site-settings', 'Site &amp; SEO', 'view_design' ],
        [ theme    => '/admin/site-settings?section=theme', 'Theme', 'view_design' ],
    );
    my $label = $is_contributor_product ? 'Site builder sections' : 'Editor sections';
    my $html = qq{<nav class="editor-nav" aria-label="$label">};
    for my $link (@links) {
        my ($key, $href, $label, $capability) = @{$link};
        next if $key eq 'posts' && !$posts_enabled;
        next if $config && $capability
            && !DesertCMS::CapabilityPolicy::has($config, $role, $capability);
        my $class = $key eq ($active || '') ? ' class="active"' : '';
        $html .= qq{<a href="$href"$class>$label</a>};
    }
    $html .= '</nav>';
    return $html;
}

sub _module_setup_nav {
    my ($self, $active, $session, $settings) = @_;
    my $config = $self->{config};
    my $role = $session ? $session->{role} : 'owner';
    return '' unless DesertCMS::CapabilityPolicy::has($config, $role, 'view_features');
    $settings ||= eval { DesertCMS::Settings::all($config, $self->{db}) } || {};
    my $is_contributor_product = DesertCMS::CapabilityPolicy::contributor_product_mode($config);
    my %primary_setup_keys = map { $_ => 1 } qw(
        posts map shop events directory bookings membership newsletter donations testimonials gallery forms docs
        accounts live_streaming forums social notifications security_center
    );
    my @order = qw(posts events directory bookings membership newsletter donations testimonials shop accounts forums social live_streaming notifications security_center map gallery forms docs);
    my %order_index = map { $order[$_] => $_ } 0 .. $#order;
    my %by_key = map { ($_->{key} || '') => $_ } @{ DesertCMS::Modules::catalog($settings, config => $config) };
    my $normalized_active = $active || '';
    $normalized_active = 'gallery' if $normalized_active eq 'showcase';
    my %tool_setup_keys = map { $_ => 1 } qw(map gallery forms docs notifications security_center);
    my (@feature_links, @tool_links);
    for my $module (
        sort {
            ($order_index{$a->{key}} // 999) <=> ($order_index{$b->{key}} // 999)
                || ($a->{label} || '') cmp ($b->{label} || '')
        } grep {
            my $key = $_->{key} || '';
            $primary_setup_keys{$key}
                && length($_->{settings_path} || '')
                && (!$is_contributor_product || $_->{available} || $_->{enabled})
        } values %by_key
    ) {
        my $link = [ $module->{key}, $module->{settings_path}, $module->{label} ];
        if ($tool_setup_keys{$module->{key} || ''}) {
            push @tool_links, $link;
        } else {
            push @feature_links, $link;
        }
    }
    my $label = $is_contributor_product ? 'Feature setup pages' : 'Module setup pages';
    my $nav_label = $is_contributor_product ? 'Features' : 'Modules';
    my $catalog_label = $is_contributor_product ? 'Feature Catalog' : 'Module Catalog';
    my $catalog_hint = $is_contributor_product ? 'Plan feature parent' : 'Module parent';
    my $safe_nav_label = escape_html($nav_label);
    my $safe_catalog_hint = escape_html($catalog_hint);
    my $safe_catalog_label = escape_html($catalog_label);
    my $catalog_class = $normalized_active eq 'modules' ? ' class="module-setup-nav-home active" aria-current="page"' : ' class="module-setup-nav-home"';
    my $html = qq{<nav class="settings-section-nav settings-section-nav--sub module-setup-nav" aria-label="$label"><a href="/admin/settings/modules"$catalog_class><strong>$safe_nav_label</strong><small>$safe_catalog_label</small><span>$safe_catalog_hint</span></a><span class="module-setup-nav-groups">};
    my @groups = (
        [ modules => $is_contributor_product ? 'Product Features' : 'Core Modules', \@feature_links ],
        [ tools => $is_contributor_product ? 'Site Tools' : 'Site Tool Modules', \@tool_links ],
    );
    for my $group (@groups) {
        my ($group_key, $group_label, $links) = @{$group};
        next unless @{$links};
        my $safe_group_label = escape_html($group_label);
        $html .= qq{<span class="module-setup-nav-group module-setup-nav-group--$group_key" data-module-setup-group="$group_key"><span class="module-setup-nav-group-title">$safe_group_label</span><span class="module-setup-nav-links">};
        for my $link (@{$links}) {
            my ($key, $href, $label_text) = @{$link};
            my $safe_href = escape_html($href);
            my $safe_label = escape_html($label_text);
            my $class = $key eq $normalized_active ? ' class="active" aria-current="page"' : '';
            $html .= qq{<a href="$safe_href"$class>$safe_label</a>};
        }
        $html .= '</span></span>';
    }
    $html .= '</span></nav>';
    return $html;
}

sub _admin_editor_eyebrow {
    my ($config) = @_;
    return $config && DesertCMS::CapabilityPolicy::contributor_product_mode($config)
        ? 'Site Builder'
        : 'Editor';
}

sub _admin_feature_eyebrow {
    my ($config) = @_;
    return $config && DesertCMS::CapabilityPolicy::contributor_product_mode($config)
        ? 'Feature'
        : 'Module';
}

sub _template_rows {
    my ($self) = @_;
    return $self->{db}->dbh->selectall_arrayref(
        q{
            SELECT *
            FROM page_templates
            WHERE deleted_at IS NULL
            ORDER BY system_default DESC, name ASC, id ASC
        },
        { Slice => {} }
    );
}

sub _template_get {
    my ($self, $id) = @_;
    return undef unless $id;
    return $self->{db}->dbh->selectrow_hashref(
        'SELECT * FROM page_templates WHERE id = ? AND deleted_at IS NULL',
        undef,
        int($id)
    );
}

sub _ensure_default_templates {
    my ($self) = @_;
    my $dbh = $self->{db}->dbh;
    my $ts = now();
    _migrate_legacy_showcase_template($dbh, $ts);
    my ($count) = $dbh->selectrow_array('SELECT COUNT(*) FROM page_templates WHERE system_default = 1 AND deleted_at IS NULL');
    return if $count && $count >= 4;

    for my $template (@{_default_templates()}) {
        $dbh->do(
            q{
                INSERT OR IGNORE INTO page_templates
                    (name, slug, description, body_json, system_default, created_at, updated_at)
                VALUES (?, ?, ?, ?, 1, ?, ?)
            },
            undef,
            $template->{name},
            $template->{slug},
            $template->{description},
            encode_json($template->{blocks}),
            $ts,
            $ts
        );
    }
}

sub _migrate_legacy_showcase_template {
    my ($dbh, $ts) = @_;
    my $legacy = $dbh->selectrow_hashref(
        q{
            SELECT id
            FROM page_templates
            WHERE slug IN ('photo-gallery', 'media-gallery')
              AND name IN ('Photo Gallery', 'Media Gallery')
              AND system_default = 1
              AND deleted_at IS NULL
            ORDER BY CASE slug WHEN 'photo-gallery' THEN 0 ELSE 1 END
            LIMIT 1
        }
    ) or return;
    my ($conflict) = $dbh->selectrow_array(
        'SELECT id FROM page_templates WHERE slug = ? AND id <> ? LIMIT 1',
        undef,
        'media-showcase',
        $legacy->{id}
    );
    return if $conflict;
    my ($template) = grep { $_->{slug} eq 'media-showcase' } @{_default_templates()};
    return unless $template;
    $dbh->do(
        q{
            UPDATE page_templates
            SET name = ?, slug = ?, description = ?, body_json = ?, updated_at = ?
            WHERE id = ?
        },
        undef,
        $template->{name},
        $template->{slug},
        $template->{description},
        encode_json($template->{blocks}),
        $ts,
        $legacy->{id}
    );
}

