sub _content_list {
    my ($self, $request, $session, $session_token, %args) = @_;
    my $type = $args{type} && $args{type} eq 'post' ? 'post' : 'page';
    my $items = $self->{content}->list_items(type => $type);
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $rows = '';
    my $is_post = $type eq 'post';
    my $title = $is_post ? 'Posts' : 'Pages';
    my $heading = $is_post ? 'Posts' : 'Pages';
    my $description = $is_post
        ? 'Write field notes, announcements, and journal-style updates. Posts publish under the posts archive.'
        : 'Build the permanent structure of the site: home, about, showcase, service, and nested pages.';
    my $new_url = $is_post ? '/admin/posts/new' : '/admin/pages/new';
    my $new_label = $is_post ? 'New post' : 'New page';
    my $empty = $is_post
        ? [
            'No posts yet.',
            'Create a new post for field notes, announcements, or journal updates. Published posts will appear in the posts archive.',
        ]
        : [
            'No pages yet.',
            'Create a new page to build the public site structure. Published pages will appear here with their public paths.',
        ];
    my $active = $is_post ? 'posts' : 'pages';
    my $editor_nav = _editor_nav($active, $self->{config}, $session, DesertCMS::Settings::all($self->{config}, $self->{db}));
    my $message = $args{message} || '';
    $message = 'Deleted.' if !$message && $request->param('deleted');
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $comment_counts = $is_post
        ? $self->{comments}->counts_for_posts(map { $_->{id} } @{$items})
        : {};

    for my $item (@{$items}) {
        my $id = int($item->{id});
        my $title = escape_html($item->{title});
        my $status = escape_html($item->{status});
        my $public_path = escape_html(DesertCMS::Renderer::public_url_for($self->{db}, $item));
        my $updated = escape_html(_format_time($item->{updated_at}));
        my $kind = $is_post ? 'post' : 'page';
        my $comments_action = '';
        if ($is_post) {
            my $comment_count = int($comment_counts->{$id} || 0);
            $comments_action = qq{<a class="icon-link" href="/admin/content/$id/comments" aria-label="View comments for $title" title="Comments">}
                . _admin_icon('comments')
                . qq{<span class="icon-link-count">$comment_count</span></a>};
        }
        my $delete_action = qq{<form method="post" action="/admin/content/$id/delete" data-confirm-title="Delete this $kind?" data-confirm-message="This removes the $kind from the admin list and public output. Cancel now if you want to keep it." data-confirm-action="Delete" data-loading-label="Deleting...">}
            . qq{<input type="hidden" name="csrf_token" value="$csrf">}
            . qq{<button type="submit" class="icon-link icon-link--button icon-link--danger" aria-label="Delete $title" title="Delete">}
            . _admin_icon('trash')
            . qq{</button></form>};
        $rows .= <<"HTML";
<tr>
  <td data-label="Title"><a href="/admin/content/$id/edit">$title</a></td>
  <td data-label="Status">$status</td>
  <td data-label="Public Path"><code>$public_path</code></td>
  <td data-label="Updated">$updated</td>
  <td data-label="Actions" class="row-actions table-actions">
    <a href="/admin/content/$id/edit">Edit</a>
    $comments_action
    <form method="post" action="/admin/content/$id/publish">
      <input type="hidden" name="csrf_token" value="$csrf">
      <button type="submit" class="small">Publish</button>
    </form>
    $delete_action
  </td>
</tr>
HTML
    }

    $rows ||= _admin_empty_row(5, @{$empty});

    my $body = <<"HTML";
<section class="editor-workspace">
  $editor_nav
  <section class="panel">
    <div class="split">
      <div>
        <p class="eyebrow">@{[_admin_editor_eyebrow($self->{config})]}</p>
        <h1>$heading</h1>
        <p>$description</p>
      </div>
      <a class="button-link" href="$new_url">$new_label</a>
    </div>
    $notice
    <table class="content-table compact-table admin-card-table">
      <thead>
        <tr><th>Title</th><th>Status</th><th>Public Path</th><th>Updated</th><th></th></tr>
      </thead>
      <tbody>
        $rows
      </tbody>
    </table>
  </section>
</section>
HTML
    return $self->_html_response($title, $body, $session);
}

sub _content_comments {
    my ($self, $request, $session, $session_token, $content_id) = @_;
    return $self->_not_found unless $self->_posts_module_enabled;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $thread = eval {
        $self->{comments}->admin_thread(content_id => $content_id);
    };
    return $self->_not_found unless $thread;

    my $post_id = int($thread->{post}{id});
    my $post_title = escape_html($thread->{post}{title});
    my $post_status = escape_html($thread->{post}{status});
    my $post_url = escape_html($thread->{post}{url});
    my $notice = $request->param('removed')
        ? '<p class="notice">Comment removed.</p>'
        : '';
    my $editor_nav = _editor_nav('posts', $self->{config}, $session);

    my $items = '';
    for my $comment (@{$thread->{comments}}) {
        my $id = int($comment->{id});
        my $status = $comment->{status} || 'visible';
        my $status_class = $status eq 'deleted' ? 'warn' : 'ok';
        my $status_label = escape_html($status);
        my $author = escape_html($comment->{author_name} || 'Anonymous');
        my $created = escape_html(_format_time($comment->{created_at}));
        my $parent = $comment->{parent_id}
            ? '<span class="comment-admin-parent">Reply to #' . int($comment->{parent_id}) . '</span>'
            : '<span class="comment-admin-parent">Top-level comment</span>';
        my $body = escape_html($comment->{body} || '');
        $body =~ s/\n/<br>/g;
        my $delete = <<"HTML";
<form method="post" action="/admin/comments/$id/delete">
  <input type="hidden" name="csrf_token" value="$csrf">
  <button type="submit" class="danger small">Remove</button>
</form>
HTML

        $items .= <<"HTML";
<article class="comment-admin-item">
  <div class="comment-admin-main">
    <div class="comment-admin-meta">
      <strong>#$id $author</strong>
      <span class="status-pill $status_class">$status_label</span>
      $parent
      <time>$created</time>
    </div>
    <div class="comment-admin-body">$body</div>
  </div>
  <div class="comment-admin-actions">
    $delete
  </div>
</article>
HTML
    }
    $items ||= _admin_empty_panel(
        'No comments on this post yet.',
        'Public comments for this post will appear here after visitors submit them.'
    );

    my $body = <<"HTML";
<section class="editor-workspace">
  $editor_nav
  <section class="panel">
    <div class="split">
      <div>
        <p class="eyebrow">Posts</p>
        <h1>Comments</h1>
        <p>Super-user comment view for <strong>$post_title</strong>. Public path: <code>$post_url</code>. Status: $post_status.</p>
      </div>
      <div class="actions">
        <a class="button-link secondary" href="/admin/posts">Back to posts</a>
        <a class="button-link secondary" href="/admin/content/$post_id/edit">Edit post</a>
      </div>
    </div>
    $notice
    <div class="comment-admin-list">
      $items
    </div>
  </section>
</section>
HTML
    return $self->_html_response('Post Comments', $body, $session);
}

sub _comment_delete {
    my ($self, $request, $session, $session_token, $comment_id) = @_;
    my $deleted = eval {
        $self->{comments}->delete_comment(id => $comment_id);
    };
    return $self->_not_found unless $deleted;

    my $content_id = int($deleted->{content_id});
    return DesertCMS::HTTP->redirect("/admin/content/$content_id/comments?removed=1", { security_headers() });
}

sub _template_list {
    my ($self, $request, $session, $session_token) = @_;
    $self->_ensure_default_templates;
    my $editor_nav = _editor_nav('templates', $self->{config}, $session);
    my $rows = '';

    for my $template (@{$self->_template_rows}) {
        my $id = int($template->{id});
        my $name = escape_html($template->{name});
        my $description = escape_html($template->{description});
        my $kind = $template->{system_default} ? 'Starter' : 'Custom';
        my $updated = escape_html(_format_time($template->{updated_at}));
        $rows .= <<"HTML";
<tr>
  <td data-label="Name"><a href="/admin/templates/$id/edit">$name</a></td>
  <td data-label="Description">$description</td>
  <td data-label="Kind">$kind</td>
  <td data-label="Updated">$updated</td>
  <td data-label="Actions" class="row-actions table-actions">
    <a href="/admin/pages/new?template_id=$id">Use for page</a>
    <a href="/admin/templates/$id/edit">Edit</a>
  </td>
</tr>
HTML
    }

    $rows ||= _admin_empty_row(
        5,
        'No custom templates yet.',
        'Create a template when you want a reusable starting layout for new pages.'
    );

    my $body = <<"HTML";
<section class="editor-workspace">
  $editor_nav
  <section class="panel">
    <div class="split">
      <div>
        <p class="eyebrow">@{[_admin_editor_eyebrow($self->{config})]}</p>
        <h1>Templates</h1>
        <p>Reusable page layouts for starting common pages quickly. Templates are private admin tools until used to create a page.</p>
      </div>
      <a class="button-link" href="/admin/templates/new">New template</a>
    </div>
    <table class="content-table compact-table admin-card-table">
      <thead>
        <tr><th>Name</th><th>Description</th><th>Kind</th><th>Updated</th><th></th></tr>
      </thead>
      <tbody>
        $rows
      </tbody>
    </table>
  </section>
</section>
HTML
    return $self->_html_response('Templates', $body, $session);
}

sub _template_form {
    my ($self, $request, $session, $session_token, $id, $message) = @_;
    $self->_ensure_default_templates;
    my $template = $id ? $self->_template_get($id) : undef;
    return $self->_not_found if $id && !$template;

    my $csrf = $self->{auth}->csrf_token($session_token);
    my $action = $template ? "/admin/templates/$template->{id}/update" : '/admin/templates/create';
    my $heading = $template ? 'Edit Template' : 'New Template';
    my $name = escape_html($template ? $template->{name} : '');
    my $description = escape_html($template ? $template->{description} : '');
    my $body_json = escape_html($template ? $template->{body_json} : encode_json([{ type => 'text', text => '' }]));
    my $media_assets = $self->{media}->list_assets;
    my $site = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $site_name = escape_html($site->{site_name});
    my $site_brand = $self->_admin_site_brand_preview($site);
    my $site_description = escape_html($site->{site_description});
    my $media_json = escape_html(_builder_media_json($media_assets));
    my $resource_json = escape_html(_builder_resource_json($media_assets));
    my $content_reference_json = $self->_content_reference_json;
    my $section_json = $self->_builder_sections_json;
    my $preview_modes = _preview_mode_bar();
    my $toolbar = _builder_toolbar_html();
    my $updated_at = escape_html($template ? scalar localtime($template->{updated_at} || time) : 'Not saved yet');
    my $kind = $template && $template->{system_default} ? 'Starter template' : 'Custom template';
    my $notice = $message ? '<p class="notice error">' . escape_html($message) . '</p>' : '';

    my $body = <<"HTML";
<section class="composer">
  <div class="composer-topbar">
    <div>
      <p class="eyebrow">Templates</p>
      <h1>$heading</h1>
    </div>
    <div class="actions">
      <a class="button-link secondary" href="/admin/templates">Back to templates</a>
    </div>
  </div>
  $notice
  <form method="post" action="$action" class="composer-form">
    <input type="hidden" name="csrf_token" value="$csrf">
    <main class="visual-editor-shell">
$preview_modes
      <section class="preview-site-shell">
        <header class="preview-site-header">
          <a href="/" tabindex="-1">$site_brand</a>
          <nav><span>Home</span><span>Showcase</span></nav>
        </header>
        <article class="content visual-page">
          <p class="kicker">Template</p>
          <label class="visual-title-field">
            <span>Template name</span>
            <input name="name" value="$name" placeholder="Reusable layout" required>
          </label>
          <input type="hidden" name="body_json" id="body-json" value="$body_json">
          <section class="visual-block-editor body" id="block-editor" data-media="$media_json" data-resources="$resource_json" data-content="$content_reference_json" data-sections="$section_json">
$toolbar
            <div class="visual-blocks" data-blocks></div>
          </section>
        </article>
        <footer class="preview-site-footer">
          <strong>$site_name</strong>
          <span>$site_description</span>
        </footer>
      </section>
    </main>
    <aside class="editor-inspector post-settings-drawer">
      <section class="inspector-panel publish-panel">
        <h2>Template</h2>
        <div class="meta-list">
          <div><span>Kind</span><strong>$kind</strong></div>
          <div><span>Updated</span><strong>$updated_at</strong></div>
        </div>
        <button type="submit">Save template</button>
      </section>
      <section class="inspector-panel">
        <h2>Template Settings</h2>
        <label>
          <span>Description</span>
          <textarea name="description" rows="4" placeholder="When should this layout be used?">$description</textarea>
        </label>
        <p class="muted">Templates are starting points for new pages. Editing a template will not change pages already created from it.</p>
      </section>
    </aside>
  </form>
</section>
HTML
    return $self->_html_response($heading, $body, $session);
}

sub _template_create {
    my ($self, $request, $session, $session_token) = @_;
    my $template = eval { $self->_template_save(undef, $request) };
    if (!$template) {
        return $self->_template_form(
            $request,
            $session,
            $session_token,
            undef,
            _admin_action_error(
                'The template could not be saved.',
                'Add a template name and check the layout content, then try again.',
                $@
            )
        );
    }
    return DesertCMS::HTTP->redirect("/admin/templates/$template->{id}/edit", { security_headers() });
}

sub _template_update {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $template = eval { $self->_template_save($id, $request) };
    return $self->_not_found if !$template && !$self->_template_get($id);
    if (!$template) {
        return $self->_template_form(
            $request,
            $session,
            $session_token,
            $id,
            _admin_action_error(
                'The template could not be saved.',
                'Check the template name and layout content, then try again.',
                $@
            )
        );
    }
    return DesertCMS::HTTP->redirect("/admin/templates/$template->{id}/edit", { security_headers() });
}

sub _template_save {
    my ($self, $id, $request) = @_;
    my $name = _clean_template_text($request->param('name'), 120);
    die "template name is required" unless length $name;
    my $description = _clean_template_text($request->param('description'), 280);
    my $body_json = $self->{content}->normalize_body_json($request->param('body_json'), '');
    my $slug = $self->_template_unique_slug(slugify($name), $id);
    my $ts = now();
    my $dbh = $self->{db}->dbh;

    if ($id) {
        my $existing = $self->_template_get($id) or die "template not found";
        $dbh->do(
            q{
                UPDATE page_templates
                SET name = ?, slug = ?, description = ?, body_json = ?, updated_at = ?
                WHERE id = ? AND deleted_at IS NULL
            },
            undef,
            $name,
            $slug,
            $description,
            $body_json,
            $ts,
            $existing->{id}
        );
        return $self->_template_get($existing->{id});
    }

    $dbh->do(
        q{
            INSERT INTO page_templates
                (name, slug, description, body_json, system_default, created_at, updated_at)
            VALUES (?, ?, ?, ?, 0, ?, ?)
        },
        undef,
        $name,
        $slug,
        $description,
        $body_json,
        $ts,
        $ts
    );
    my $new_id = $dbh->sqlite_last_insert_rowid;
    return $self->_template_get($new_id);
}

sub _template_unique_slug {
    my ($self, $base, $id) = @_;
    $base = 'template' unless defined $base && length $base;
    my $slug = $base;
    my $i = 2;
    while (1) {
        my $row = $self->{db}->dbh->selectrow_hashref(
            'SELECT id FROM page_templates WHERE slug = ? AND deleted_at IS NULL',
            undef,
            $slug
        );
        return $slug if !$row || ($id && $row->{id} == $id);
        $slug = "$base-$i";
        $i++;
    }
}

sub _section_rows {
    my ($self) = @_;
    return $self->{db}->dbh->selectall_arrayref(
        q{
            SELECT *
            FROM builder_sections
            WHERE deleted_at IS NULL
            ORDER BY system_default DESC, name ASC, id ASC
        },
        { Slice => {} }
    );
}

sub _section_get {
    my ($self, $id) = @_;
    return undef unless $id;
    return $self->{db}->dbh->selectrow_hashref(
        'SELECT * FROM builder_sections WHERE id = ? AND deleted_at IS NULL',
        undef,
        int($id)
    );
}

sub _ensure_default_sections {
    my ($self) = @_;
    my $dbh = $self->{db}->dbh;
    my ($count) = $dbh->selectrow_array('SELECT COUNT(*) FROM builder_sections WHERE system_default = 1 AND deleted_at IS NULL');
    return if $count && $count >= 4;

    my $ts = now();
    for my $section (@{_default_sections()}) {
        $dbh->do(
            q{
                INSERT OR IGNORE INTO builder_sections
                    (name, slug, description, body_json, system_default, created_at, updated_at)
                VALUES (?, ?, ?, ?, 1, ?, ?)
            },
            undef,
            $section->{name},
            $section->{slug},
            $section->{description},
            encode_json($section->{blocks}),
            $ts,
            $ts
        );
    }
}

