sub _builder_sections_json {
    my ($self) = @_;
    $self->_ensure_default_sections;
    my @sections;
    for my $section (@{$self->_section_rows}) {
        my $blocks = eval { decode_json($section->{body_json} || '[]') } || [];
        $blocks = [] unless ref $blocks eq 'ARRAY';
        push @sections, {
            id          => int($section->{id} || 0),
            name        => $section->{name} || '',
            description => $section->{description} || '',
            blocks      => $blocks,
        };
    }
    return escape_html(encode_json(\@sections));
}

