    my $logo_src = escape_html($settings->{site_logo_nav_path} || $settings->{site_logo_path} || '');
    my $has_logo = length($logo_src) ? 1 : 0;
    my $brand_display = _clean_choice($settings->{site_brand_display}, 'auto', qw(auto logo logo-name name));
    my $brand_mode = $brand_display eq 'auto'
        ? ($has_logo ? 'logo' : 'name')
        : $brand_display;
    my $header_layout = _clean_choice($settings->{site_header_layout}, 'split', qw(split centered stacked compact));
    my $nav_style = _clean_choice($settings->{site_nav_style}, 'plain', qw(plain underline pills buttons));
    my $logo_size = _clean_choice($settings->{site_logo_size}, 'medium', qw(small medium large));
    my $footer_layout = _clean_choice($settings->{site_footer_layout}, 'standard', qw(standard compact minimal hidden));
    my $footer_order = _clean_choice($settings->{site_footer_order}, 'brand-nav-credit', qw(brand-nav-credit nav-brand-credit credit-brand-nav));
    my $footer_nav_enabled = $settings->{site_footer_nav_enabled} ? '1' : '0';
    my $footer_description_enabled = $settings->{site_footer_description_enabled} ? '1' : '0';
    my $footer_credit = _theme_preview_footer_credit($settings);
    my $default_mode = DesertCMS::SiteTheme::default_mode($settings);
    my $preview_light_active = $default_mode eq 'dark' ? '' : ' is-active';
    my $preview_dark_active = $default_mode eq 'dark' ? ' is-active' : '';
    my $preview_light_pressed = $default_mode eq 'dark' ? 'false' : 'true';
    my $preview_dark_pressed = $default_mode eq 'dark' ? 'true' : 'false';
    my $preview_modes = _preview_mode_bar();
    my $desktop_preview = _theme_preview_device_html(
        device                     => 'desktop',
        site_name                  => $site_name,
        site_description           => $site_description,
        logo_src                   => $logo_src,
