        header_layout              => $header_layout,
        nav_style                  => $nav_style,
        logo_size                  => $logo_size,
        footer_layout              => $footer_layout,
        footer_order               => $footer_order,
        footer_nav_enabled         => $footer_nav_enabled,
        footer_description_enabled => $footer_description_enabled,
        footer_credit              => $footer_credit,
    );
    my $mobile_preview = _theme_preview_device_html(
        device                     => 'mobile',
        site_name                  => $site_name,
        site_description           => $site_description,
        logo_src                   => $logo_src,
        brand_mode                 => $brand_mode,
        header_layout              => $header_layout,
        nav_style                  => $nav_style,
        logo_size                  => $logo_size,
        footer_layout              => $footer_layout,
        footer_order               => $footer_order,
        footer_nav_enabled         => $footer_nav_enabled,
        footer_description_enabled => $footer_description_enabled,
        footer_credit              => $footer_credit,
    );

    return <<"HTML";
      <section class="settings-subsection settings-subsection--first theme-builder-preview-panel">
        <div>
          <h3>Live Theme Preview</h3>
          <p class="muted">Header, footer, logo, typography, button, and card controls update here before saving.</p>
        </div>
        <div class="theme-preview-composer">
          <main class="visual-editor-shell theme-builder-preview-shell preview-mode--desktop theme-preview-mode--$default_mode" data-theme-preview data-theme-preview-mode="$default_mode" data-theme-preview-has-logo="$has_logo">
            <div class="theme-builder-preview-toolbar">
              $preview_modes
              <div class="preview-mode-bar preview-mode-bar--theme" data-theme-preview-mode-bar>
                <span>Mode</span>
                <button type="button" class="$preview_light_active" data-theme-preview-mode-button="light" aria-pressed="$preview_light_pressed">Light</button>
                <button type="button" class="$preview_dark_active" data-theme-preview-mode-button="dark" aria-pressed="$preview_dark_pressed">Dark</button>
              </div>
