    my $year = (localtime)[5] + 1900;
    if (length $credit) {
        $credit =~ s/\{\{year\}\}/$year/g;
        $credit =~ s/\{\{site_name\}\}/$name/g;
        return escape_html($credit);
    }
    return '&copy; ' . escape_html("$year $name");
}

