sub _builder_media_json {
    my ($media_assets) = @_;
    return encode_json([
        map {
            +{
                src         => $_->{public_path} || '',
                name        => $_->{seo_title} || $_->{original_name} || $_->{public_path} || '',
                filename    => $_->{original_name} || '',
                alt         => $_->{alt_text} || '',
                description => $_->{seo_description} || '',
                category    => $_->{category_text} || '',
                tags        => $_->{tags_text} || '',
                collections => $_->{collections_text} || '',
                type_label  => 'Image',
                search_text => DesertCMS::Media::media_search_text($_),
            }
        } grep {
            DesertCMS::Media::is_public_image_path($_->{public_path} || '')
        } @{ $media_assets || [] }
    ]);
}

sub _builder_resource_json {
    my ($media_assets) = @_;
    return encode_json([
        map {
            my $meta = eval { decode_json($_->{derivatives_json} || '{}') } || {};
            my $resource = ref $meta->{public_resource} eq 'HASH' ? $meta->{public_resource} : {};
            my $preview = ref $meta->{preview} eq 'HASH' ? $meta->{preview} : {};
            my $path = $_->{public_path} || '';
            my $byte_label = $resource->{byte_label} || $preview->{byte_label} || _format_bytes(int($_->{bytes} || 0));
            my $type_label = $resource->{label} || $preview->{type_label} || $preview->{label} || 'Resource file';
            +{
                src         => $path,
                name        => $_->{seo_title} || $_->{original_name} || $path,
                description => $_->{seo_description} || '',
                category    => $_->{category_text} || '',
                tags        => $_->{tags_text} || '',
                collections => $_->{collections_text} || '',
                filename    => $resource->{filename} || $_->{original_name} || '',
                extension   => $resource->{extension} || _media_extension_label($_->{original_name}),
                bytes       => int($_->{bytes} || 0),
                byte_label  => $byte_label,
                type_label  => $type_label,
                family_label => $preview->{family_label} || '',
                snippet     => $preview->{snippet} || '',
                search_text => DesertCMS::Media::media_search_text($_),
            }
        } grep {
            ($_->{public_path} || '') =~ m{\A/assets/resources/[0-9a-f]{64}\.[a-z0-9]+\z}
        } @{ $media_assets || [] }
    ]);
}

sub _section_list {
    my ($self, $request, $session, $session_token) = @_;
    $self->_ensure_default_sections;
    my $editor_nav = _editor_nav('sections', $self->{config}, $session);
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $notice = '';
    if ($request->param('deleted')) {
        $notice = '<p class="notice">Section deleted.</p>';
    } elsif ($request->param('starter')) {
        $notice = '<p class="notice error">Starter sections cannot be deleted.</p>';
    }
    my $rows = '';

    for my $section (@{$self->_section_rows}) {
        my $id = int($section->{id});
        my $name = escape_html($section->{name});
        my $description = escape_html($section->{description});
        my $kind = $section->{system_default} ? 'Starter' : 'Custom';
        my $updated = escape_html(_format_time($section->{updated_at}));
        my $delete = $section->{system_default}
            ? ''
            : qq{<form method="post" action="/admin/sections/$id/delete" data-confirm-title="Delete reusable section?" data-confirm-message="Pages that already used this section keep their saved blocks, but the section will no longer be available for new inserts." data-confirm-action="Delete" data-loading-label="Deleting..."><input type="hidden" name="csrf_token" value="$csrf"><button type="submit" class="small danger">Delete</button></form>};
        $rows .= <<"HTML";
<tr>
  <td data-label="Name"><a href="/admin/sections/$id/edit">$name</a></td>
  <td data-label="Description">$description</td>
  <td data-label="Kind">$kind</td>
  <td data-label="Updated">$updated</td>
  <td data-label="Actions" class="row-actions table-actions">
    <a href="/admin/sections/$id/edit">Edit</a>
    $delete
  </td>
</tr>
HTML
    }

    $rows ||= _admin_empty_row(
        5,
        'No reusable sections yet.',
        'Create a section when the same callout, intro, form block, or feature should be inserted on multiple pages.'
    );

    my $body = <<"HTML";
<section class="editor-workspace">
  $editor_nav
  <section class="panel">
    <div class="split">
      <div>
        <p class="eyebrow">@{[_admin_editor_eyebrow($self->{config})]}</p>
        <h1>Sections</h1>
        <p>Reusable page pieces for inserting the same callout, feature, introduction, or application block into many pages.</p>
      </div>
      <a class="button-link" href="/admin/sections/new">New section</a>
    </div>
    $notice
    <table class="content-table compact-table admin-card-table">
      <thead>
        <tr><th>Name</th><th>Description</th><th>Kind</th><th>Updated</th><th></th></tr>
      </thead>
      <tbody>
        $rows
      </tbody>
    </table>
  </section>
</section>
HTML
    return $self->_html_response('Sections', $body, $session);
}

sub _section_form {
    my ($self, $request, $session, $session_token, $id, $message) = @_;
    $self->_ensure_default_sections;
    my $section = $id ? $self->_section_get($id) : undef;
    return $self->_not_found if $id && !$section;

    my $csrf = $self->{auth}->csrf_token($session_token);
    my $action = $section ? "/admin/sections/$section->{id}/update" : '/admin/sections/create';
    my $heading = $section ? 'Edit Section' : 'New Section';
    my $name = escape_html($section ? $section->{name} : '');
    my $description = escape_html($section ? $section->{description} : '');
    my $body_json = escape_html($section ? $section->{body_json} : encode_json([{ type => 'text', text => '', spacing => 'default' }]));
    my $media_assets = $self->{media}->list_assets;
    my $site = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $site_name = escape_html($site->{site_name});
    my $site_brand = $self->_admin_site_brand_preview($site);
    my $site_description = escape_html($site->{site_description});
    my $media_json = escape_html(_builder_media_json($media_assets));
    my $resource_json = escape_html(_builder_resource_json($media_assets));
    my $content_reference_json = $self->_content_reference_json;
    my $section_json = $self->_builder_sections_json;
    my $preview_modes = _preview_mode_bar();
    my $toolbar = _builder_toolbar_html();
    my $updated_at = escape_html($section ? scalar localtime($section->{updated_at} || time) : 'Not saved yet');
    my $kind = $section && $section->{system_default} ? 'Starter section' : 'Custom section';
    my $notice = $message ? '<p class="notice error">' . escape_html($message) . '</p>' : '';

    my $body = <<"HTML";
<section class="composer">
  <div class="composer-topbar">
    <div>
      <p class="eyebrow">Sections</p>
      <h1>$heading</h1>
    </div>
    <div class="actions">
      <a class="button-link secondary" href="/admin/sections">Back to sections</a>
    </div>
  </div>
  $notice
  <form method="post" action="$action" class="composer-form">
    <input type="hidden" name="csrf_token" value="$csrf">
    <main class="visual-editor-shell">
$preview_modes
      <section class="preview-site-shell">
        <header class="preview-site-header">
          <a href="/" tabindex="-1">$site_brand</a>
          <nav><span>Home</span><span>Showcase</span></nav>
        </header>
        <article class="content visual-page">
          <p class="kicker">Reusable Section</p>
          <label class="visual-title-field">
            <span>Section name</span>
            <input name="name" value="$name" placeholder="Reusable section" required>
          </label>
          <input type="hidden" name="body_json" id="body-json" value="$body_json">
          <section class="visual-block-editor body" id="block-editor" data-media="$media_json" data-resources="$resource_json" data-content="$content_reference_json" data-sections="$section_json">
$toolbar
            <div class="visual-blocks" data-blocks></div>
          </section>
        </article>
        <footer class="preview-site-footer">
          <strong>$site_name</strong>
          <span>$site_description</span>
        </footer>
      </section>
    </main>
    <aside class="editor-inspector post-settings-drawer">
      <section class="inspector-panel publish-panel">
        <h2>Section</h2>
        <div class="meta-list">
          <div><span>Kind</span><strong>$kind</strong></div>
          <div><span>Updated</span><strong>$updated_at</strong></div>
        </div>
        <button type="submit">Save section</button>
      </section>
      <section class="inspector-panel">
        <h2>Section Settings</h2>
        <label>
          <span>Description</span>
          <textarea name="description" rows="4" placeholder="Where should this section be reused?">$description</textarea>
        </label>
        <p class="muted">Sections are copied into a page when inserted. Editing a section will not change pages that already use it.</p>
      </section>
    </aside>
  </form>
</section>
HTML
    return $self->_html_response($heading, $body, $session);
}

sub _section_create {
    my ($self, $request, $session, $session_token) = @_;
    my $section = eval { $self->_section_save(undef, $request) };
    if (!$section) {
        return $self->_section_form(
            $request,
            $session,
            $session_token,
            undef,
            _admin_action_error(
                'The reusable section could not be saved.',
                'Add a section name and check the block layout, then try again.',
                $@
            )
        );
    }
    return DesertCMS::HTTP->redirect("/admin/sections/$section->{id}/edit", { security_headers() });
}

sub _section_update {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $section = eval { $self->_section_save($id, $request) };
    return $self->_not_found if !$section && !$self->_section_get($id);
    if (!$section) {
        return $self->_section_form(
            $request,
            $session,
            $session_token,
            $id,
            _admin_action_error(
                'The reusable section could not be saved.',
                'Check the section name and block layout, then try again.',
                $@
            )
        );
    }
    return DesertCMS::HTTP->redirect("/admin/sections/$section->{id}/edit", { security_headers() });
}

sub _section_delete {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $section = $self->_section_get($id) or return $self->_not_found;
    return DesertCMS::HTTP->redirect('/admin/sections?starter=1', { security_headers() })
        if $section->{system_default};
    $self->{db}->dbh->do(
        'UPDATE builder_sections SET deleted_at = ?, updated_at = ? WHERE id = ? AND deleted_at IS NULL',
        undef,
        now(),
        now(),
        $section->{id}
    );
    return DesertCMS::HTTP->redirect('/admin/sections?deleted=1', { security_headers() });
}

sub _section_save {
    my ($self, $id, $request) = @_;
    my $name = _clean_template_text($request->param('name'), 120);
    die "section name is required" unless length $name;
    my $description = _clean_template_text($request->param('description'), 280);
    my $body_json = $self->{content}->normalize_body_json($request->param('body_json'), '');
    my $slug = $self->_section_unique_slug(slugify($name), $id);
    my $ts = now();
    my $dbh = $self->{db}->dbh;

    if ($id) {
        my $existing = $self->_section_get($id) or die "section not found";
        $dbh->do(
            q{
                UPDATE builder_sections
                SET name = ?, slug = ?, description = ?, body_json = ?, updated_at = ?
                WHERE id = ? AND deleted_at IS NULL
            },
            undef,
            $name,
            $slug,
            $description,
            $body_json,
            $ts,
            $existing->{id}
        );
        return $self->_section_get($existing->{id});
    }

    $dbh->do(
        q{
            INSERT INTO builder_sections
                (name, slug, description, body_json, system_default, created_at, updated_at)
            VALUES (?, ?, ?, ?, 0, ?, ?)
        },
        undef,
        $name,
        $slug,
        $description,
        $body_json,
        $ts,
        $ts
    );
    my $new_id = $dbh->sqlite_last_insert_rowid;
    return $self->_section_get($new_id);
}

sub _section_unique_slug {
    my ($self, $base, $id) = @_;
    $base = 'section' unless defined $base && length $base;
    my $slug = $base;
    my $i = 2;
    while (1) {
        my $row = $self->{db}->dbh->selectrow_hashref(
            'SELECT id FROM builder_sections WHERE slug = ? AND deleted_at IS NULL',
            undef,
            $slug
        );
        return $slug if !$row || ($id && $row->{id} == $id);
        $slug = "$base-$i";
        $i++;
    }
}

sub _clean_template_text {
    my ($value, $max) = @_;
    $value = '' unless defined $value;
    $value =~ s/^\s+|\s+$//g;
    $value =~ s/\s+/ /g;
    $max ||= 200;
    return substr($value, 0, $max);
}

sub _content_form {
    my ($self, $request, $session, $session_token, $id, $default_type) = @_;
    my $item = $id ? $self->{content}->get($id) : undef;
    return $self->_not_found if $id && !$item;

    my $csrf = $self->{auth}->csrf_token($session_token);
    my $action = $item ? "/admin/content/$item->{id}/update" : '/admin/content/create';
    my $publish_action = $item ? "/admin/content/$item->{id}/publish" : '';
    my $type = $item ? $item->{type} : ($default_type || $request->param('type') || 'page');
    $type = $type eq 'post' ? 'post' : 'page';
    return $self->_not_found if $type eq 'post' && !$self->_posts_module_enabled;
    my $heading = $item ? ($type eq 'post' ? 'Edit Post' : 'Edit Page') : ($type eq 'post' ? 'New Post' : 'New Page');
    my $title = escape_html($item ? $item->{title} : '');
    my $slug = escape_html($item ? $item->{slug} : '');
    my $excerpt = escape_html($item ? $item->{excerpt} : '');
    my $meta_title = escape_html($item ? $item->{meta_title} : '');
    my $meta_description = escape_html($item ? $item->{meta_description} : '');
    my $canonical_url = escape_html($item ? $item->{canonical_url} : '');
    my $feature_image_path = $item ? ($item->{feature_image_path} || '') : '';
    my $location_enabled_checked = $item && $item->{location_enabled} ? 'checked' : '';
    my $location_lat = $item && defined $item->{location_lat} ? escape_html(sprintf('%.6f', $item->{location_lat})) : '';
    my $location_lng = $item && defined $item->{location_lng} ? escape_html(sprintf('%.6f', $item->{location_lng})) : '';
    my $location_label = escape_html($item ? ($item->{location_label} || '') : '');
    my $location_kind_options = _location_kind_options($item ? ($item->{location_kind} || 'other') : 'other');
    my $tags_text = escape_html($item ? $self->{content}->tags_text($item->{id}) : '');
    my $collections_text = escape_html($item ? $self->{content}->collections_text($item->{id}) : '');
    my $access_policy = $item ? ($item->{access_policy} || 'public') : 'public';
    my $access_group_id = $item ? int($item->{access_group_id} || 0) : 0;
    my $status = escape_html($item ? $item->{status} : 'draft');
    my $updated_at = escape_html($item ? scalar localtime($item->{updated_at} || time) : 'Not saved yet');
    my $published_at = $item && $item->{published_at} ? escape_html(scalar localtime($item->{published_at})) : 'Not published yet';
    my $content_url_label = ($access_policy eq 'public') ? 'Public URL' : 'Member URL';
    my $content_url = '';
    if ($item && $item->{status} eq 'published') {
        if ($access_policy eq 'public') {
            $content_url = DesertCMS::Renderer::public_url_for($self->{db}, $item);
        } elsif ($access_policy eq 'members' || $access_policy eq 'group') {
            $content_url = '/members/content/' . ($item->{slug} || '');
        }
    }
    my $public_url = length($content_url) ? escape_html($content_url) : '';
    my $parent_id = $item ? int($item->{parent_id} || 0) : 0;
    my $show_in_nav_checked = $item && $item->{show_in_nav} ? 'checked' : '';
    my $nav_label = escape_html($item ? ($item->{nav_label} || '') : '');
    my $nav_order = escape_html($item ? ($item->{nav_order} || 100) : 100);
    my $parent_options = '<option value="">No parent page</option>';
    for my $page (@{$self->{content}->page_options(exclude_id => $item ? $item->{id} : 0)}) {
        my $id_value = int($page->{id});
        my $selected = $id_value == $parent_id ? 'selected' : '';
        my $label = escape_html(($page->{title} || 'Untitled') . ' (' . DesertCMS::Renderer::public_url_for($self->{db}, { %{$page}, type => 'page' }) . ', ' . ($page->{status} || 'draft') . ')');
        $parent_options .= qq{<option value="$id_value" $selected>$label</option>};
    }
    my $selected_template = undef;
    if (!$item && $type eq 'page') {
        $self->_ensure_default_templates;
