        </label>
        <input type="hidden" name="location_lat" value="$location_lat" data-location-lat>
        <input type="hidden" name="location_lng" value="$location_lng" data-location-lng>
        <div class="location-map" data-location-map>
          <script type="application/json" data-map-config>$location_map_config</script>
