        <div class="location-actions">
          <button type="button" class="secondary" data-location-clear>Clear pin</button>
        </div>
      </section>
HTML
    }
    my $access_panel = '';
    if ($membership_module_enabled) {
        my $access_options = _content_access_policy_options($access_policy);
        my $group_options = $self->_membership_group_options($access_group_id, 'No group selected');
