          <span>Tags</span>
          <input name="tags_text" value="$tags_text" placeholder="desert, prints, field notes">
        </label>
        <label>
          <span>Collections</span>
          <input name="collections_text" value="$collections_text" placeholder="Portfolio, 2026 series">
        </label>
      </section>
      <section class="inspector-panel">
        <h2>SEO</h2>
        <label>
          <span>Meta title</span>
          <input name="meta_title" value="$meta_title" maxlength="80" placeholder="Defaults to title">
        </label>
        <label>
          <span>Meta description</span>
          <textarea name="meta_description" rows="4" maxlength="180" placeholder="Defaults to excerpt">$meta_description</textarea>
        </label>
        <label>
          <span>Canonical URL</span>
          <input name="canonical_url" value="$canonical_url" placeholder="Optional absolute URL">
        </label>
        <div class="search-preview">
          <span>Search preview</span>
          <strong data-seo-preview-title>$title</strong>
          <p data-seo-preview-description>$excerpt</p>
        </div>
      </section>
    </aside>
  </form>
</section>
HTML

    return $self->_html_response($heading, $body, $session);
}

sub _content_create {
    my ($self, $request, $session) = @_;
    return $self->_not_found
        if ($request->param('type') || '') eq 'post' && !$self->_posts_module_enabled;
    my %location = $self->_content_location_args($request, undef);
    my %access = $self->_content_access_args($request, undef);
    my $item = $self->{content}->save(
        type           => $request->param('type'),
        title          => $request->param('title'),
        slug           => $request->param('slug'),
        parent_id      => $request->param('parent_id'),
        show_in_nav    => $request->param('show_in_nav'),
        nav_label      => $request->param('nav_label'),
        nav_order      => $request->param('nav_order'),
        excerpt        => $request->param('excerpt'),
        meta_title     => $request->param('meta_title'),
        meta_description => $request->param('meta_description'),
        canonical_url  => $request->param('canonical_url'),
        feature_image_path => $request->param('feature_image_path'),
        %location,
        %access,
        tags_text      => $request->param('tags_text'),
        collections_text => $request->param('collections_text'),
        body_json      => $request->param('body_json'),
        body_text      => $request->param('body_text'),
        author_user_id => $session->{user_id},
    );
    return DesertCMS::HTTP->redirect("/admin/content/$item->{id}/edit", { security_headers() });
}

sub _content_update {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $existing = $self->{content}->get($id);
    return $self->_not_found unless $existing;
    return $self->_not_found
        if ((($existing->{type} || '') eq 'post' || ($request->param('type') || '') eq 'post')
            && !$self->_posts_module_enabled);
    my %location = $self->_content_location_args($request, $existing);
    my %access = $self->_content_access_args($request, $existing);
    my $item = $self->{content}->save(
        id             => $id,
        type           => $request->param('type'),
        title          => $request->param('title'),
        slug           => $request->param('slug'),
        parent_id      => $request->param('parent_id'),
        show_in_nav    => $request->param('show_in_nav'),
        nav_label      => $request->param('nav_label'),
        nav_order      => $request->param('nav_order'),
        excerpt        => $request->param('excerpt'),
        meta_title     => $request->param('meta_title'),
        meta_description => $request->param('meta_description'),
        canonical_url  => $request->param('canonical_url'),
        feature_image_path => $request->param('feature_image_path'),
        %location,
        %access,
        tags_text      => $request->param('tags_text'),
        collections_text => $request->param('collections_text'),
        body_json      => $request->param('body_json'),
        body_text      => $request->param('body_text'),
        author_user_id => $session->{user_id},
    );
    return DesertCMS::HTTP->redirect("/admin/content/$item->{id}/edit", { security_headers() });
}

sub _content_access_args {
    my ($self, $request, $existing) = @_;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    if (DesertCMS::Modules::enabled($settings, 'membership')) {
        return (
            access_policy   => $request->param('access_policy'),
            access_group_id => $request->param('access_group_id'),
        );
    }

    return (
        access_policy   => $existing ? ($existing->{access_policy} || 'public') : 'public',
        access_group_id => $existing ? $existing->{access_group_id} : undef,
    );
}

sub _content_access_policy_options {
    my ($selected) = @_;
    $selected = lc($selected || 'public');
    my @options = (
        [ public  => 'Public' ],
        [ members => 'Members only' ],
        [ group   => 'Specific member group' ],
        [ private => 'Private / hidden' ],
    );
    return join '', map {
        my ($value, $label) = @{$_};
        my $is_selected = $value eq $selected ? ' selected' : '';
        '<option value="' . escape_html($value) . '"' . $is_selected . '>' . escape_html($label) . '</option>';
    } @options;
}

sub _content_location_args {
    my ($self, $request, $existing) = @_;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    if (DesertCMS::Modules::enabled($settings, 'map')) {
        return (
            location_enabled => $request->param('location_enabled'),
            location_lat     => $request->param('location_lat'),
            location_lng     => $request->param('location_lng'),
            location_label   => $request->param('location_label'),
            location_kind    => $request->param('location_kind'),
        );
    }

    return (
        location_enabled => $existing ? ($existing->{location_enabled} || 0) : 0,
        location_lat     => $existing ? $existing->{location_lat} : undef,
        location_lng     => $existing ? $existing->{location_lng} : undef,
        location_label   => $existing ? ($existing->{location_label} || '') : '',
        location_kind    => $existing ? ($existing->{location_kind} || 'other') : 'other',
    );
}

sub _location_kind_options {
    my ($selected) = @_;
    $selected = _location_kind_value($selected);
    my @options = (
        [ store           => 'Store' ],
        [ venue           => 'Venue' ],
        [ project         => 'Project location' ],
        [ historical_site => 'Historical site' ],
        [ event_location  => 'Event location' ],
        [ service_area    => 'Service area' ],
        [ other           => 'Other location' ],
    );
    return join '', map {
        my ($value, $label) = @{$_};
        my $is_selected = $value eq $selected ? ' selected' : '';
        '<option value="' . escape_html($value) . '"' . $is_selected . '>' . escape_html($label) . '</option>';
    } @options;
}

sub _location_kind_label {
    my ($kind) = @_;
    $kind = _location_kind_value($kind);
    my %labels = (
        store           => 'Store',
        venue           => 'Venue',
        project         => 'Project location',
        historical_site => 'Historical site',
        event_location  => 'Event location',
        service_area    => 'Service area',
        other           => 'Location',
    );
    return $labels{$kind} || 'Location';
}

sub _location_kind_value {
    my ($kind) = @_;
    $kind = lc($kind || '');
    $kind =~ s/[-\s]+/_/g;
    return $kind if $kind =~ /\A(?:store|venue|project|historical_site|event_location|service_area|other)\z/;
    return 'other';
}

sub _content_preview {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $item = $self->{content}->get($id);
    return $self->_not_found if !$item;
    return $self->_not_found if ($item->{type} || '') eq 'post' && !$self->_posts_module_enabled;
    my $html = DesertCMS::Renderer::render_item($self->{config}, $item, $self->{db});
    my $banner = '<div style="position:sticky;top:0;z-index:9999;padding:10px 16px;background:#171411;color:#fff;font:600 14px system-ui,sans-serif">Draft preview. This page has not necessarily been published.</div>';
    $html =~ s{<body>}{<body>\n$banner}i;
    return DesertCMS::HTTP->response(
        status  => 200,
        headers => {
            'Content-Type' => 'text/html; charset=utf-8',
            'X-Robots-Tag' => 'noindex',
            security_headers(),
        },
        body => $html,
    );
}

sub _content_publish {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $existing = $self->{content}->get($id);
    return $self->_not_found if $existing && ($existing->{type} || '') eq 'post' && !$self->_posts_module_enabled;
    my $item = eval {
        $self->{content}->publish(id => $id, author_user_id => $session->{user_id});
    };
    return $self->_not_found if !$item;
    my $target = ($item->{type} || '') eq 'post' ? '/admin/posts' : '/admin/pages';
    return DesertCMS::HTTP->redirect($target, { security_headers() });
}

sub _content_delete {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $item = $self->{content}->get($id);
    return $self->_not_found unless $item;
    return $self->_not_found if ($item->{type} || '') eq 'post' && !$self->_posts_module_enabled;

    my $target = ($item->{type} || '') eq 'post' ? '/admin/posts' : '/admin/pages';
    my $deleted = eval {
        $self->{content}->delete_item(id => $id, author_user_id => $session->{user_id});
    };
    if (!$deleted) {
        my $message = _admin_action_error(
            'The content item could not be deleted.',
            'Refresh the list to confirm it still exists, then try again.',
            $@
        );
        return $self->_content_list(
            $request,
            $session,
            $session_token,
            type    => (($item->{type} || '') eq 'post' ? 'post' : 'page'),
            message => $message,
        );
    }

    return DesertCMS::HTTP->redirect($target . '?deleted=1', { security_headers() });
}

sub _rebuild_public {
    my ($self, $request, $session) = @_;
    my $count = $self->{content}->rebuild_all;
    $self->_audit_admin_action(
        $session,
        action       => 'site.rebuilt',
        subject_type => 'site',
        details      => { published_items => int($count || 0) },
    );
    my $safe_count = int($count);
    my $return_label = DesertCMS::CapabilityPolicy::contributor_product_mode($self->{config}) ? 'Home' : 'Analytics';
    my $body = <<"HTML";
<section class="panel">
  <p class="eyebrow">Publish</p>
  <h1>Public site rebuilt</h1>
  <p>Rebuilt $safe_count published items and refreshed indexes.</p>
    <a class="button-link" href="/admin">$return_label</a>
</section>
HTML
    return $self->_html_response('Rebuild Complete', $body, $session);
}

sub _media_list {
    my ($self, $request, $session, $session_token, $message) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $active_filter = DesertCMS::Media::library_filter_key($request->param('filter'));
    my $search_query = DesertCMS::Media::library_search_query($request->param('q'));
    my @category_filter_terms = DesertCMS::Media::media_organization_terms($request->param('category'));
    my $category_filter = $category_filter_terms[0] || '';
    my @collection_filter_terms = DesertCMS::Media::media_organization_terms($request->param('collection'));
    my $collection_filter = $collection_filter_terms[0] || '';
    my $all_assets = $self->{media}->list_assets;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $resource_feature = $self->_module_feature_state($settings, 'resource_publishing');
    my $can_upload_media = _has_capability($self->{config}, $session, 'upload_media');
    my $can_download_sources = _has_capability($self->{config}, $session, 'download_media_sources');
    my $can_publish_media_resources = _has_capability($self->{config}, $session, 'publish_media_resources');
    my $can_delete_media_assets = _has_capability($self->{config}, $session, 'delete_media_assets');
    my $can_bulk_manage_media = _has_capability($self->{config}, $session, 'bulk_manage_media');
    my $can_publish_resources = $can_publish_media_resources && $resource_feature && $resource_feature->{enabled} ? 1 : 0;
    my ($resource_lock_text, $resource_lock_href, $resource_lock_label) = _media_resource_publish_lock($resource_feature);
    my $resource_lock_notice = !$can_publish_media_resources
        ? '<p class="muted">Your role can view media, but cannot publish public Resource downloads.</p>'
        : $can_publish_resources
        ? ''
        : '<p class="notice">' . escape_html($resource_lock_text) . ' <a href="' . escape_html($resource_lock_href) . '">' . escape_html($resource_lock_label) . '</a>.</p>';
    my $upload_limit_note = _media_upload_limit_note($self->{config}, $settings);
    my $quota_status_html = _media_quota_status_html($self->{config}, $settings, $all_assets);
