    } @{$all_assets};
    my $searched_assets = DesertCMS::Media::library_search_assets($all_assets, $search_query);
    my $organized_assets = DesertCMS::Media::library_filter_organization_assets(
        $searched_assets,
        category   => $category_filter,
        collection => $collection_filter,
    );
    my $filter_counts = DesertCMS::Media::library_filter_counts($organized_assets, \%usage_by_id);
    my $assets = DesertCMS::Media::library_filter_assets($organized_assets, $active_filter, \%usage_by_id);
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $editor_nav = _editor_nav('media', $self->{config}, $session);
    my $filter_tabs = _media_filter_tabs_html($active_filter, $filter_counts, $search_query, $category_filter, $collection_filter);
    my $safe_filter = escape_html($active_filter);
    my $safe_search_query = escape_html($search_query);
    my $safe_category_filter = escape_html($category_filter);
    my $safe_collection_filter = escape_html($collection_filter);
    my $search_form = _media_search_form_html(
        $active_filter,
        $search_query,
        scalar(@{$organized_assets}),
        scalar(@{$all_assets}),
        $category_filter,
        $collection_filter,
    );
    my $organization_filters = _media_organization_filters_html(
        $all_assets,
        $active_filter,
        $search_query,
        $category_filter,
        $collection_filter,
    );
    my $publish_option = $can_publish_resources
        ? '<option value="publish_resources">Publish selected resources</option>'
        : $can_publish_media_resources
        ? '<option value="publish_resources" disabled>Publish selected resources (locked)</option>'
        : '<option value="publish_resources" disabled>Publish selected resources (not allowed)</option>';
    my $unpublish_option = $can_publish_media_resources
        ? '<option value="unpublish_resources">Unpublish selected resources</option>'
        : '<option value="unpublish_resources" disabled>Unpublish selected resources (not allowed)</option>';
    my $delete_option = $can_delete_media_assets
        ? '<option value="delete_unused">Delete selected unused</option>'
        : '<option value="delete_unused" disabled>Delete selected unused (not allowed)</option>';
    my $metadata_option = $can_upload_media
        ? '<option value="apply_metadata">Apply metadata to selected</option>'
        : '<option value="apply_metadata" disabled>Apply metadata to selected (not allowed)</option>';
    my $bulk_note = !$can_bulk_manage_media
        ? 'Your role can view media, but cannot run bulk media actions.'
        : (!$can_publish_media_resources || !$can_delete_media_assets || !$can_upload_media)
        ? 'Only actions allowed by your media permissions are available.'
        : $can_publish_resources
        ? 'Metadata fields only apply when that action is selected. Blank metadata fields stay unchanged.'
        : $resource_lock_text . ' Existing public resources can still be unpublished.';
    my $bulk_toolbar = $can_bulk_manage_media ? <<"HTML" : '<p class="muted">Bulk media actions are not available for your role.</p>';
    <form id="media-bulk-form" method="post" action="/admin/media/bulk" class="media-bulk-toolbar" data-media-bulk-form data-confirm-title="Run bulk media action?" data-confirm-message="Selected media assets will be updated. Delete unused skips anything still referenced by content, shop listings, or orders." data-confirm-action="Run action" data-loading-label="Updating media...">
