      <input type="hidden" name="csrf_token" value="$csrf">
      <label>
        <span>Source asset</span>
        <input type="file" name="asset" accept="image/jpeg,image/png,image/webp,application/pdf,text/plain,text/markdown,text/csv,text/tab-separated-values,application/json,application/vnd.openxmlformats-officedocument.wordprocessingml.document,application/vnd.openxmlformats-officedocument.spreadsheetml.sheet,application/vnd.openxmlformats-officedocument.presentationml.presentation,audio/mpeg,audio/mp4,audio/x-m4a,audio/wav,audio/x-wav,audio/ogg,audio/webm,audio/flac,video/mp4,video/x-m4v,video/quicktime,video/webm,video/ogg,.pdf,.txt,.md,.markdown,.csv,.tsv,.json,.docx,.xlsx,.pptx,.mp3,.m4a,.wav,.ogg,.oga,.weba,.flac,.mp4,.m4v,.mov,.webm,.ogv" required>
        <small>@{[escape_html($upload_limit_note)]}</small>
      </label>
      <label>
        <span>Alt text or source note</span>
        <input name="alt_text" placeholder="Describe images for accessibility, or add an internal note for private files">
      </label>
      <label>
        <span>Media search title</span>
        <input name="seo_title" maxlength="90" placeholder="Optional title used by showcase/search surfaces">
      </label>
      <label>
        <span>Media search description</span>
        <textarea name="seo_description" rows="3" maxlength="220" placeholder="Optional short description for this asset"></textarea>
      </label>
      <label>
        <span>Category</span>
        <input name="category_text" maxlength="80" placeholder="Portfolio, archive, product...">
      </label>
      <label>
        <span>Tags</span>
        <input name="tags_text" placeholder="Comma-separated tags">
      </label>
      <label>
        <span>Collections</span>
        <input name="collections_text" placeholder="Comma-separated collections">
      </label>
      <button type="submit">Upload asset</button>
    </form>
HTML

    my $body = <<"HTML";
<section class="editor-workspace">
  $editor_nav
  <section class="panel">
    <div class="split">
      <div>
        <p class="eyebrow">@{[_admin_editor_eyebrow($self->{config})]}</p>
        <h1>Media Library</h1>
        <p>Source assets are private. Images generate public optimized derivatives; selected files can be published as public Resource blocks.</p>
      </div>
      <div class="actions">
        <a class="button-link secondary" href="/admin/media/lifecycle">Lifecycle audit</a>
      </div>
    </div>
    $notice
    $resource_lock_notice
    $quota_status_html
    $search_form
    $organization_filters
    $filter_tabs
    $bulk_toolbar
    $upload_form
    <div class="media-grid">
      $cards
    </div>
  </section>
</section>
HTML

