}

sub _media_lifecycle_page {
    my ($self, $request, $session, $session_token, $message) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $large_mb = _media_lifecycle_large_mb($request->param('large_mb'));
    my $retention_days = _media_lifecycle_retention_days($request->param('retention_days'));
    my $audit = eval { $self->{media}->lifecycle_audit(large_min_mb => $large_mb, retention_days => $retention_days) };
    if (!$audit) {
        $message = _admin_action_error(
            'The media lifecycle audit could not run.',
            'Check that the public assets and private source directories are readable, then try again.',
            $@
        );
        $audit = _media_lifecycle_empty_audit($large_mb, $retention_days);
    }

    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $editor_nav = _editor_nav('media', $self->{config}, $session);
    my $can_delete_media_assets = _has_capability($self->{config}, $session, 'delete_media_assets');
    my $can_bulk_manage_media = _has_capability($self->{config}, $session, 'bulk_manage_media');
    my $cleanup_notice = $can_delete_media_assets
        ? ''
        : '<p class="muted">Your role can review media lifecycle findings, but cannot clean up or delete media files.</p>';
    my $safe_large_mb = escape_html($large_mb);
    my $safe_retention_days = escape_html($retention_days);
    my $summary_html = _media_lifecycle_summary_html($audit->{summary});
    my $preview_jobs_html = _media_preview_jobs_panel_html(
        $self->{media}->preview_job_summary,
        $csrf,
        $can_bulk_manage_media,
    );
    my $missing_html = _media_lifecycle_section(
        title   => 'Missing Private Sources',
        detail  => 'Media rows whose private source file cannot be found. Review these manually before deleting or replacing the asset.',
        entries => $audit->{missing_sources},
        empty   => 'Every active media row has a private source file on disk.',
    );
    my $orphan_html = _media_lifecycle_section(
        title           => 'Orphaned Public Resources',
        detail          => 'Files under /assets/resources/ that are not referenced by an active public resource media row.',
        entries         => $audit->{orphaned_resources},
        empty           => 'No orphaned public resource files were found.',
        csrf            => $csrf,
        large_mb        => $large_mb,
        cleanup_action  => $can_delete_media_assets ? 'remove_orphaned_resources' : '',
        cleanup_label   => 'Remove orphaned resources',
        confirm_title   => 'Remove orphaned public resources?',
        confirm_message => 'This deletes public resource files that are not referenced by active media records. Private source files are not touched.',
    );
    my $derivative_html = _media_lifecycle_section(
        title           => 'Stale Image Derivatives',
        detail          => 'Generated image files under /assets/media/ that are no longer referenced by active image media rows.',
        entries         => $audit->{stale_derivatives},
        empty           => 'No stale public image derivatives were found.',
        csrf            => $csrf,
        large_mb        => $large_mb,
        cleanup_action  => $can_delete_media_assets ? 'remove_stale_derivatives' : '',
        cleanup_label   => 'Remove stale derivatives',
        confirm_title   => 'Remove stale image derivatives?',
        confirm_message => 'This deletes generated public image files that active media records no longer reference. Private source files are not touched.',
    );
    my $unused_html = _media_lifecycle_section(
        title           => 'Large Unused Media',
        detail          => 'Active media assets above the selected size threshold that are not referenced by pages, posts, shop listings, or order records.',
        entries         => $audit->{large_unused},
        empty           => 'No unused media assets exceed the selected threshold.',
        csrf            => $csrf,
        large_mb        => $large_mb,
        cleanup_action  => $can_delete_media_assets ? 'delete_large_unused' : '',
        cleanup_label   => 'Delete large unused media',
        confirm_title   => 'Delete large unused media?',
        confirm_message => 'This uses the normal media delete path and skips assets that become referenced before cleanup runs. Deleted private sources and generated public files cannot be restored without a backup.',
        danger          => 1,
    );
    my $retention_html = _media_lifecycle_section(
        title           => 'Retention Candidates',
        detail          => 'Old unused media assets that have private source files available. Cleanup creates a private retention archive before deleting them through the normal media delete path.',
        entries         => $audit->{retention_unused},
        empty           => 'No unused media assets are old enough for the selected retention window.',
        csrf            => $csrf,
        large_mb        => $large_mb,
        retention_days  => $retention_days,
        cleanup_action  => $can_delete_media_assets ? 'archive_old_unused' : '',
        cleanup_label   => 'Archive and delete old unused media',
        confirm_title   => 'Archive and delete old unused media?',
        confirm_message => 'This first creates a private media-retention archive under the configured backup directory, then deletes only assets that are still unused. Referenced assets and missing private sources are skipped.',
        danger          => 1,
    );

    my $body = <<"HTML";
<section class="editor-workspace">
  $editor_nav
  <section class="panel">
    <div class="split">
      <div>
        <p class="eyebrow">@{[_admin_editor_eyebrow($self->{config})]}</p>
        <h1>Media Lifecycle</h1>
        <p>Audit the private source asset store and public derivative folders before removing stale or unused media files.</p>
      </div>
      <div class="actions">
        <a class="button-link secondary" href="/admin/media">Back to Media</a>
      </div>
    </div>
    $notice
    $cleanup_notice
    $summary_html
    $preview_jobs_html
    <form method="get" action="/admin/media/lifecycle" class="settings-form settings-form--compact">
      <label>
        <span>Large unused threshold</span>
        <input type="number" min="1" max="1024" step="1" name="large_mb" value="$safe_large_mb">
        <small>Assets at or above this size are listed when they are unused.</small>
      </label>
      <label>
        <span>Retention window</span>
        <input type="number" min="1" max="3650" step="1" name="retention_days" value="$safe_retention_days">
        <small>Unused assets older than this many days are eligible for archive-first deletion.</small>
      </label>
      <button type="submit" class="secondary">Refresh audit</button>
    </form>
  </section>
  $missing_html
  $orphan_html
  $derivative_html
  $unused_html
  $retention_html
</section>
HTML

    return $self->_html_response('Media Lifecycle', $body, $session);
}

sub _media_lifecycle_cleanup {
    my ($self, $request, $session, $session_token) = @_;
    my $action = lc($request->param('cleanup_action') || '');
    $action =~ s/[^a-z_]+//g;
    my $large_mb = _media_lifecycle_large_mb($request->param('large_mb'));
    my $retention_days = _media_lifecycle_retention_days($request->param('retention_days'));
    my %labels = (
        remove_orphaned_resources => 'Removed orphaned public resources',
        remove_stale_derivatives  => 'Removed stale image derivatives',
        delete_large_unused       => 'Deleted large unused media',
        archive_old_unused        => 'Archived and deleted old unused media',
    );
    return $self->_media_lifecycle_page($request, $session, $session_token, 'Choose a valid media lifecycle cleanup action.')
        unless $labels{$action};

    my $result = eval {
        $self->{media}->cleanup_lifecycle(
            action         => $action,
            large_min_mb   => $large_mb,
            retention_days => $retention_days,
        );
    };
    if (!$result) {
        return $self->_media_lifecycle_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The media lifecycle cleanup could not run.',
                'Review the audit output and confirm the asset folders are writable, then try again.',
                $@
            )
        );
    }

    $self->_audit_admin_action(
        $session,
        action       => 'media.lifecycle_' . $action,
        subject_type => 'media_asset',
        details      => {
            changed  => int($result->{changed} || 0),
            skipped  => int($result->{skipped} || 0),
            bytes    => int($result->{bytes} || 0),
            large_mb => $large_mb,
            retention_days => $retention_days,
            archive_path => $result->{archive_path} || '',
        },
    );

    my $message = $labels{$action} . ': ' . int($result->{changed} || 0) . ' cleaned, ' . _format_bytes(int($result->{bytes} || 0)) . ' removed';
    $message .= ', ' . int($result->{skipped} || 0) . ' skipped' if int($result->{skipped} || 0);
    $message .= '. Archive: ' . ($result->{archive_path} || 'none') if $action eq 'archive_old_unused' && ($result->{archive_path} || '');
    if (my $errors = $result->{errors}) {
        $message .= '. ' . join(' ', map { _clean_error($_) } @{$errors}) if @{$errors};
    }
    $message .= '.';
    return $self->_media_lifecycle_page($request, $session, $session_token, $message);
}

sub _media_preview_queue {
    my ($self, $request, $session, $session_token) = @_;
    return $self->_media_lifecycle_page($request, $session, $session_token, 'Your role cannot queue media preview jobs.')
        unless _has_capability($self->{config}, $session, 'bulk_manage_media');

    my $result = eval { $self->{media}->enqueue_private_preview_jobs(reason => 'admin_retry', limit => 100) };
    if (!$result) {
        return $self->_media_lifecycle_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'Media preview jobs could not be queued.',
                'Check that the database is writable, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'media.preview_jobs_queued',
        subject_type => 'media_asset',
        details      => {
            queued  => int($result->{queued} || 0),
            skipped => int($result->{skipped} || 0),
        },
    );
    my $message = 'Queued ' . int($result->{queued} || 0) . ' media preview job(s).';
    $message .= ' ' . int($result->{skipped} || 0) . ' already had queued work.' if int($result->{skipped} || 0);
    return $self->_media_lifecycle_page($request, $session, $session_token, $message);
}

sub _media_preview_process {
    my ($self, $request, $session, $session_token) = @_;
    return $self->_media_lifecycle_page($request, $session, $session_token, 'Your role cannot process media preview jobs.')
        unless _has_capability($self->{config}, $session, 'bulk_manage_media');

    my $result = eval { $self->{media}->process_private_preview_jobs(limit => 10) };
    if (!$result) {
        return $self->_media_lifecycle_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'Media preview jobs could not be processed.',
                'Check private source paths and optional preview tooling, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'media.preview_jobs_processed',
        subject_type => 'media_asset',
        details      => {
            checked => int($result->{checked} || 0),
            done    => int($result->{done} || 0),
            failed  => int($result->{failed} || 0),
            skipped => int($result->{skipped} || 0),
        },
    );
    my $message = 'Processed ' . int($result->{checked} || 0) . ' media preview job(s): '
        . int($result->{done} || 0) . ' generated, '
        . int($result->{failed} || 0) . ' failed, '
        . int($result->{skipped} || 0) . ' skipped.';
    if (my $errors = $result->{errors}) {
        $message .= ' ' . join(' ', map { _clean_error($_) } @{$errors}) if @{$errors};
    }
    return $self->_media_lifecycle_page($request, $session, $session_token, $message);
}

sub _media_upload {
    my ($self, $request, $session, $session_token) = @_;
    my $upload = $request->upload('asset') || $request->upload('photo');
    if (!$upload) {
        return $self->_media_list($request, $session, $session_token, 'No media asset was selected. Choose a supported image, document, or resource file, then upload again.');
    }

    my $asset = eval {
        $self->{media}->store_upload(
            filename  => $upload->{filename},
            mime_type => $upload->{content_type},
            content   => $upload->{content},
            alt_text  => $request->param('alt_text'),
            seo_title => $request->param('seo_title'),
            seo_description => $request->param('seo_description'),
            category_text => $request->param('category_text'),
            tags_text => $request->param('tags_text'),
            collections_text => $request->param('collections_text'),
            uploaded_by_user_id => $session->{user_id},
            uploaded_by_username => $session->{username},
            uploaded_by_email => $session->{email},
        );
    };
    if (!$asset) {
        return $self->_media_list(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The media asset could not be uploaded.',
                'Check that the file is a supported image, document, or resource file and smaller than the upload limit, then try again.',
                $@
            )
        );
    }

    my $kind = DesertCMS::Media::asset_kind($asset);
    my $message = $kind eq 'image'
        ? 'Media asset uploaded and optimized derivatives generated.'
        : 'Media asset uploaded as a private source file. It is available only to signed-in admins.';
    return $self->_media_list($request, $session, $session_token, $message);
}

sub _media_download_source {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $download = eval { $self->{media}->source_download(id => $id) };
    return $self->_not_found unless $download && $download->{path};

    open my $fh, '<:raw', $download->{path} or return $self->_not_found;
    local $/;
    my $body = <$fh>;
    close $fh;

    $self->_audit_admin_action(
        $session,
        action       => 'media.source_downloaded',
        subject_type => 'media_asset',
        subject_id   => int($id || 0),
        details      => {
            filename => $download->{filename},
            mime     => $download->{mime},
            bytes    => int($download->{bytes} || 0),
        },
    );

    return DesertCMS::HTTP->response(
        status  => 200,
        headers => {
            'Content-Type'        => $download->{mime} || 'application/octet-stream',
            'Content-Disposition' => 'attachment; filename="' . _download_header_filename($download->{filename}) . '"',
            security_headers(),
        },
        body => $body,
    );
}

sub _media_private_preview {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $preview = eval { $self->{media}->private_preview(id => $id) };
    return $self->_not_found unless $preview && $preview->{path};

    open my $fh, '<:raw', $preview->{path} or return $self->_not_found;
    local $/;
    my $body = <$fh>;
    close $fh;

    return DesertCMS::HTTP->response(
        status  => 200,
        headers => {
            'Content-Type'        => $preview->{mime} || 'image/jpeg',
            'Content-Disposition' => 'inline; filename="' . _download_header_filename($preview->{filename}) . '"',
            'Cache-Control'       => 'private, no-store',
            security_headers(),
        },
        body => $body,
    );
}

sub _media_publish_resource {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $feature = $self->_module_feature_state($settings, 'resource_publishing');
    if (!$feature || !$feature->{enabled}) {
        my ($text) = _media_resource_publish_lock($feature);
        return $self->_media_list($request, $session, $session_token, $text);
    }
    my $ok = eval {
        $self->{media}->publish_resource(id => $id);
        $self->{content}->rebuild_all;
        1;
    };
    if (!$ok) {
        return $self->_media_list(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The resource could not be published.',
                'Check that the asset is a supported private source file and that the public assets directory is writable.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'media.resource_published',
        subject_type => 'media_asset',
        subject_id   => int($id || 0),
    );
    return $self->_media_list($request, $session, $session_token, 'Resource published. It can now be inserted into pages and posts.');
}

sub _media_unpublish_resource {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $ok = eval {
        $self->{media}->unpublish_resource(id => $id);
        $self->{content}->rebuild_all;
        1;
    };
    if (!$ok) {
        return $self->_media_list(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The resource could not be unpublished.',
                'Remove the resource from pages and posts first, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'media.resource_unpublished',
        subject_type => 'media_asset',
        subject_id   => int($id || 0),
    );
    return $self->_media_list($request, $session, $session_token, 'Resource unpublished. The private source asset remains available to admins.');
}

sub _media_bulk_action {
    my ($self, $request, $session, $session_token) = @_;
    my $action = lc($request->param('bulk_action') || '');
    $action =~ s/[^a-z_]+//g;
    my @ids = _media_bulk_selected_ids($request);
    return $self->_media_list($request, $session, $session_token, 'Select one or more media assets before running a bulk action.')
        unless @ids;

    my %allowed = map { $_ => 1 } qw(publish_resources unpublish_resources delete_unused apply_metadata);
    return $self->_media_list($request, $session, $session_token, 'Choose a valid bulk media action.')
        unless $allowed{$action};

    my %required_capability = (
        publish_resources   => 'publish_media_resources',
        unpublish_resources => 'publish_media_resources',
        delete_unused       => 'delete_media_assets',
        apply_metadata      => 'upload_media',
    );
    my %denied_message = (
        publish_resources   => 'Your role cannot publish public Resource downloads.',
        unpublish_resources => 'Your role cannot unpublish public Resource downloads.',
        delete_unused       => 'Your role cannot delete media assets.',
        apply_metadata      => 'Your role cannot edit media metadata.',
    );
    my $required_capability = $required_capability{$action};
    return $self->_media_list($request, $session, $session_token, 'Your role cannot run bulk media actions.')
        unless _has_capability($self->{config}, $session, 'bulk_manage_media');
    return $self->_media_list($request, $session, $session_token, $denied_message{$action})
        if $required_capability && !_has_capability($self->{config}, $session, $required_capability);

    if ($action eq 'publish_resources') {
        my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
        my $feature = $self->_module_feature_state($settings, 'resource_publishing');
        if (!$feature || !$feature->{enabled}) {
            my ($text) = _media_resource_publish_lock($feature);
            return $self->_media_list($request, $session, $session_token, $text);
        }
    }

    my $title = $request->param('bulk_seo_title');
    my $description = $request->param('bulk_seo_description');
    my $note = $request->param('bulk_alt_text');
    my $category = $request->param('bulk_category_text');
    my $tags = $request->param('bulk_tags_text');
    my $collections = $request->param('bulk_collections_text');
    my %metadata_fields = (
        seo_title       => defined($title) && $title =~ /\S/ ? $title : undef,
        seo_description => defined($description) && $description =~ /\S/ ? $description : undef,
        alt_text        => defined($note) && $note =~ /\S/ ? $note : undef,
        category_text   => defined($category) && $category =~ /\S/ ? $category : undef,
        tags_text       => defined($tags) && $tags =~ /\S/ ? $tags : undef,
        collections_text => defined($collections) && $collections =~ /\S/ ? $collections : undef,
    );
    if ($action eq 'apply_metadata' && !grep { defined } values %metadata_fields) {
        return $self->_media_list($request, $session, $session_token, 'Fill at least one bulk metadata field before applying it.');
    }

    my ($changed, $skipped, $errors, $rebuild_needed) = (0, 0, 0, 0);
    my @error_samples;
    for my $id (@ids) {
        my $ok = eval {
            if ($action eq 'publish_resources') {
                my $asset = $self->{media}->asset_by_id(id => $id);
                die "media asset not found" unless $asset;
                die "images already have public optimized derivatives" if DesertCMS::Media::asset_kind($asset) eq 'image';
                die "resource is already public" if DesertCMS::Media::public_policy($asset) eq 'public_resource_download';
                $self->{media}->publish_resource(asset => $asset);
                $rebuild_needed = 1;
            } elsif ($action eq 'unpublish_resources') {
                my $asset = $self->{media}->asset_by_id(id => $id);
                die "media asset not found" unless $asset;
                die "asset is not a public resource" unless DesertCMS::Media::public_policy($asset) eq 'public_resource_download';
                $self->{media}->unpublish_resource(asset => $asset);
                $rebuild_needed = 1;
            } elsif ($action eq 'delete_unused') {
                my $asset = $self->{media}->asset_by_id(id => $id);
                die "media asset not found" unless $asset;
                my $usage = $self->{media}->usage_for_asset(asset => $asset);
                die "asset is still in use" if int($usage->{content_count} || 0)
                    || int($usage->{shop_listing_count} || 0)
                    || int($usage->{shop_order_count} || 0);
                $self->{media}->delete_asset(id => $id);
            } elsif ($action eq 'apply_metadata') {
                my $asset = $self->{media}->asset_by_id(id => $id);
                die "media asset not found" unless $asset;
                $self->{media}->update_search_text(
                    id              => $id,
                    alt_text        => defined $metadata_fields{alt_text} ? $metadata_fields{alt_text} : ($asset->{alt_text} || ''),
                    seo_title       => defined $metadata_fields{seo_title} ? $metadata_fields{seo_title} : ($asset->{seo_title} || ''),
                    seo_description => defined $metadata_fields{seo_description} ? $metadata_fields{seo_description} : ($asset->{seo_description} || ''),
                    category_text   => defined $metadata_fields{category_text} ? $metadata_fields{category_text} : ($asset->{category_text} || ''),
                    tags_text       => defined $metadata_fields{tags_text} ? $metadata_fields{tags_text} : ($asset->{tags_text} || ''),
                    collections_text => defined $metadata_fields{collections_text} ? $metadata_fields{collections_text} : ($asset->{collections_text} || ''),
                );
                $rebuild_needed = 1;
            }
            1;
        };
        if ($ok) {
            $changed++;
        } else {
            $skipped++;
            $errors++;
            push @error_samples, _clean_error($@) if @error_samples < 3;
        }
    }

    my $rebuilt = 0;
    if ($changed && $rebuild_needed) {
        my $ok = eval {
            $self->{content}->rebuild_all;
            1;
        };
        if ($ok) {
            $rebuilt = 1;
        } else {
            push @error_samples, _clean_error($@) if @error_samples < 3;
        }
    }

    $self->_audit_admin_action(
        $session,
        action       => 'media.bulk_' . $action,
        subject_type => 'media_asset',
        details      => {
            selected => scalar(@ids),
            changed  => $changed,
            skipped  => $skipped,
            errors   => $errors,
            rebuilt  => $rebuilt,
        },
    );

    my $message = _media_bulk_action_label($action) . ": $changed updated";
    $message .= ", $skipped skipped" if $skipped;
    $message .= '.';
    $message .= ' Public site rebuilt.' if $rebuilt;
    $message .= ' ' . join(' ', @error_samples) if @error_samples;
    return $self->_media_list($request, $session, $session_token, $message);
}

sub _media_alt_update {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $ok = eval {
        $self->{media}->update_search_text(
            id       => $id,
            alt_text => $request->param('alt_text'),
            seo_title => $request->param('seo_title'),
            seo_description => $request->param('seo_description'),
            category_text => $request->param('category_text'),
            tags_text => $request->param('tags_text'),
            collections_text => $request->param('collections_text'),
        );
        $self->{content}->rebuild_all;
        1;
    };

    if (!$ok) {
        return $self->_media_list(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The media metadata could not be saved.',
                'Check the title, description, organization fields, and database write access, then try again.',
                $@
            )
        );
    }
    return $self->_media_list($request, $session, $session_token, 'Media metadata saved and public site rebuilt.');
}

sub _media_delete {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $ok = eval {
        $self->{media}->delete_asset(id => $id);
        1;
    };

    if (!$ok) {
        return $self->_media_list(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The media asset could not be deleted.',
                'Remove it from pages, posts, and shop listings first, then try again.',
                $@
            )
        );
    }
    return $self->_media_list($request, $session, $session_token, 'Media deleted. Any shop listing for it has been disabled.');
}

sub _module_shop_settings_page {
    my ($self, $request, $session, $session_token, $message) = @_;
    return $self->_shop_admin($request, $session, $session_token, $message);
}

sub _shop_admin {
    my ($self, $request, $session, $session_token, $message) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $shop_settings = $self->{shop}->settings;
    my $settings_nav = $self->_module_setup_nav('shop', $session, $shop_settings);
    my $commerce = DesertCMS::Commerce::readiness($self->{config}, $shop_settings);
    my $commerce_state = _fleet_state_pill($commerce->{state}, $commerce->{label});
    my $commerce_summary = escape_html($commerce->{summary});
    my $is_contributor_product = DesertCMS::CapabilityPolicy::contributor_product_mode($self->{config});
    my $payments_feature = $self->_module_feature_state($shop_settings, 'shop_payments');
    my $payments_feature_state = _module_status_html($payments_feature, $self->{config});
    my $payments_locked = $payments_feature && $payments_feature->{locked_by_plan} ? 1 : 0;
    my $checkout_allowed = DesertCMS::Commerce::checkout_allowed_by_plan($shop_settings);
    my $checkout_ready = $self->{shop}->checkout_ready;
    my $commerce_rows = _commerce_readiness_rows($commerce);
    my $shop_url = escape_html($self->{shop}->shop_url('/'));
    my $stripe_state = $shop_settings->{stripe_secret_key}
        ? '<span class="status-pill ok">Configured</span>'
        : '<span class="status-pill warn">Missing secret key</span>';
    my $webhook_state = $shop_settings->{stripe_webhook_secret}
        ? '<span class="status-pill ok">Configured</span>'
        : '<span class="status-pill warn">Missing webhook secret</span>';
    my $shop_feature = $self->_module_feature_state($shop_settings, 'shop');
    my $feature_state = _module_status_html($shop_feature, $self->{config});
    my $shop_toggle = _module_toggle_control($shop_feature, 'shop_enabled', 'Enable catalog', $self->{config});
    my $shop_config_enabled = DesertCMS::Commerce::shop_config_enabled($shop_settings);
    my $enabled_state = $self->{shop}->catalog_enabled
        ? ($checkout_ready
            ? '<span class="status-pill ok">Catalog and checkout ready</span>'
            : '<span class="status-pill ok">Catalog enabled</span>')
        : ($shop_config_enabled
            ? '<span class="status-pill warn">Catalog paused</span>'
            : '<span class="status-pill status-pill--neutral">Disabled</span>');
    my $purchase_token_checked = _setting_truthy($shop_settings->{shop_require_purchase_token}) ? 'checked' : '';
    my $webhook_endpoint = escape_html($self->{shop}->shop_url('/stripe/webhook'));
    my $payment_settings_note = '';
    if ($is_contributor_product) {
        $payment_settings_note = '<p class="muted">' . ($payments_locked ? 'Catalog listings stay available on this plan. Upgrade to unlock Stripe checkout and payout account setup.' : 'Site payments use the platform Stripe account. Use Billing to connect your payout account when the current plan includes site payments.') . '</p>';
    } else {
        $payment_settings_note = <<"HTML";
        <p class="muted">Stripe credentials, webhook signing, API endpoint, and the global commerce model are managed from <a href="/admin/settings/payments">Settings &gt; Payments</a>. Shop / Catalog uses those shared provider settings.</p>
        <a class="button-link secondary" href="/admin/settings/payments">Open payment settings</a>
HTML
    }
    my $cards = '';
    my $media_rows = $self->{shop}->admin_media_rows;
    my $item_count = scalar @{$media_rows};
    my $item_count_label = $item_count == 1 ? '1 item' : "$item_count items";
    my $contributor_filters = $self->{shop}->admin_contributor_filters($media_rows);
    my $contributor_select_options = join '', map {
        my $label = escape_html($_->{label});
        my $count = int($_->{count} || 0);
        my $count_label = $count == 1 ? '1 item' : "$count items";
        qq{<option value="$label">$label ($count_label)</option>};
    } @{$contributor_filters};
    my $contributor_search_options = join '', map {
        my $label = escape_html($_->{label});
        my $count = int($_->{count} || 0);
        my $count_label = $count == 1 ? '1 item' : "$count items";
        qq{<option value="$label" label="$count_label"></option>};
    } @{$contributor_filters};

    for my $row (@{$media_rows}) {
        my $id = int($row->{id});
        my $title = escape_html($row->{listing_title} || $row->{original_name} || '');
        my $description = escape_html($row->{listing_description} || '');
        my $currency = escape_html($row->{listing_currency} || 'usd');
        my $url = escape_html($row->{public_path} || '');
        my $alt = escape_html($row->{alt_text} || '');
        my $active = $row->{listing_active} ? 'checked' : '';
        my $personal_enabled = $row->{personal_enabled} ? 'checked' : '';
        my $commercial_enabled = $row->{commercial_enabled} ? 'checked' : '';
        my $full_enabled = $row->{full_rights_enabled} ? 'checked' : '';
        my $personal_price = escape_html(_admin_price($row->{personal_price_cents}));
        my $commercial_price = escape_html(_admin_price($row->{commercial_price_cents}));
        my $full_price = escape_html(_admin_price($row->{full_rights_price_cents}));
        my $listing_kind = $row->{listing_kind} || 'product';
        my $kind_options = '';
        for my $kind_def (
            [ product => 'Product' ],
            [ service => 'Service' ],
            [ digital => 'Digital item' ],
            [ portfolio_item => 'Portfolio item' ],
            [ inquiry_only => 'Inquiry only' ],
            [ other => 'Other' ],
        ) {
            my ($value, $label) = @{$kind_def};
            my $selected = $listing_kind eq $value ? 'selected' : '';
            $kind_options .= '<option value="' . escape_html($value) . "\" $selected>" . escape_html($label) . '</option>';
        }
        my $cta_label = escape_html($row->{cta_label} || 'Request info');
        my $cta_url = escape_html($row->{cta_url} || '');
        my $owner_html = _media_owner_html($row, $self->{config});
        my $contributor = $self->{shop}->admin_contributor_data($row);
        my $contributor_label = escape_html($contributor->{label});
        my $contributor_search = escape_html($contributor->{search});
        my $sold = $row->{full_rights_sold_at}
            ? '<p class="notice">Full rights have been sold. This listing is locked inactive.</p>'
            : '';
        my $listing_status = $row->{full_rights_sold_at}
            ? 'Full rights sold'
            : ($row->{listing_active} ? 'Live in shop' : ($row->{listing_id} ? 'Draft listing' : 'Not listed'));
        my $status_class = $row->{full_rights_sold_at}
            ? 'warn'
            : ($row->{listing_active} ? 'ok' : 'status-pill--neutral');
        my $payment_controls = '';
        if ($checkout_allowed) {
            $payment_controls = <<"HTML";
    <div class="price-grid" role="group" aria-label="Rights pricing">
      <label class="rights-price-row">
        <span class="rights-price-title"><strong>Personal</strong><small>Private display and non-commercial reference</small></span>
        <span class="rights-price-toggle"><input type="checkbox" name="personal_enabled" value="1" $personal_enabled> Sell</span>
        <span class="rights-price-input"><span>Price</span><input name="personal_price" value="$personal_price" inputmode="decimal" placeholder="75.00"></span>
      </label>
      <label class="rights-price-row">
        <span class="rights-price-title"><strong>Commercial</strong><small>Business, editorial, campaign, or publication use</small></span>
        <span class="rights-price-toggle"><input type="checkbox" name="commercial_enabled" value="1" $commercial_enabled> Sell</span>
        <span class="rights-price-input"><span>Price</span><input name="commercial_price" value="$commercial_price" inputmode="decimal" placeholder="350.00"></span>
      </label>
      <label class="rights-price-row">
        <span class="rights-price-title"><strong>Full rights</strong><small>Exclusive purchase that removes the item from sale</small></span>
        <span class="rights-price-toggle"><input type="checkbox" name="full_rights_enabled" value="1" $full_enabled> Sell</span>
        <span class="rights-price-input"><span>Price</span><input name="full_rights_price" value="$full_price" inputmode="decimal" placeholder="2500.00"></span>
      </label>
    </div>
HTML
        } else {
            $payment_controls = '<p class="notice">Shop Payments is not included on this plan. Listing type and inquiry CTA remain editable, but price fields and buy controls are locked.</p>';
        }
        $cards .= <<"HTML";
<article class="shop-admin-card" data-shop-item-card data-contributor-name="$contributor_label" data-contributor-search="$contributor_search">
  <div class="shop-admin-media">
    <img src="$url" alt="$alt">
    <span class="status-pill $status_class">$listing_status</span>
    $owner_html
    <code>$url</code>
  </div>
  <form method="post" action="/admin/settings/modules/shop/media/$id/save" class="shop-admin-form">
    <input type="hidden" name="csrf_token" value="$csrf">
    <div class="field-row">
      <label>
        <span>Listing title</span>
        <input name="title" value="$title" placeholder="Defaults to uploaded filename">
      </label>
      <label>
        <span>Listing type</span>
        <select name="listing_kind">$kind_options</select>
      </label>
    </div>
    <div class="field-row">
      <label>
        <span>Currency</span>
        <input name="currency" value="$currency" maxlength="3">
      </label>
      <label>
        <span>Inquiry CTA label</span>
        <input name="cta_label" value="$cta_label" placeholder="Request info">
      </label>
    </div>
    <label>
      <span>Inquiry CTA URL</span>
      <input name="cta_url" value="$cta_url" placeholder="/forms/ or https://example.com/contact">
    </label>
    <label>
      <span>Description</span>
      <textarea name="description" rows="3" placeholder="Product details, service notes, portfolio context, availability, or usage limits">$description</textarea>
    </label>
    <label class="checkbox-field">
      <input type="checkbox" name="active" value="1" $active>
      <span>Show this item in the catalog</span>
    </label>
    $sold
    $payment_controls
    <button type="submit">Save catalog listing</button>
  </form>
</article>
HTML
    }
    $cards ||= _admin_empty_panel(
        'No catalog items are ready yet.',
        'Upload media first. Each uploaded item can then become a product, service, portfolio, digital, or inquiry listing.'
    );

    my $orders = '';
    for my $order (@{$self->{shop}->recent_orders(limit => 20)}) {
        my $title = escape_html($order->{listing_title} || $order->{original_name} || 'Catalog item');
        my $rights = escape_html(DesertCMS::Shop->rights_label($order->{rights_type}));
        my $status = escape_html($order->{status});
        my $price = escape_html(DesertCMS::Shop::price_label($order->{amount_cents}, $order->{currency}));
        my $email = escape_html($order->{customer_email} || '');
        my $created = escape_html(_format_time($order->{created_at}));
        $orders .= qq{<tr><td data-label="Created">$created</td><td data-label="Item">$title</td><td data-label="Rights">$rights</td><td data-label="Total">$price</td><td data-label="Status">$status</td><td data-label="Email">$email</td></tr>};
    }
    $orders ||= _admin_empty_row(
        6,
        'No shop orders yet.',
        'Paid Stripe Checkout orders will appear here after a visitor purchases from a listing.'
    );
    my $feature_eyebrow = _admin_feature_eyebrow($self->{config});
    my $section_nav = _module_section_nav(
        'Shop / Catalog setup sections',
        [ '#module-overview', 'Overview' ],
        [ '#module-settings', 'Catalog Settings' ],
        [ '#module-listings', 'Listings' ],
        [ '#module-orders', 'Orders' ],
    );

    my $body = <<"HTML";
<section class="editor-workspace">
  $settings_nav
  <section class="panel" id="module-overview">
    <div class="split">
      <div>
        <p class="eyebrow">$feature_eyebrow</p>
        <h1>Shop / Catalog</h1>
        <p>Publish product, service, digital, portfolio, media, and inquiry listings at <code>/shop</code>. Private source files remain private; Stripe checkout appears only when Shop Payments is included and ready.</p>
      </div>
      <a class="button-link secondary" href="$shop_url">Open catalog</a>
    </div>
    $notice
    <dl class="health-list fleet-provider-list">
      <div><dt>Payments</dt><dd>$commerce_state<small>$commerce_summary</small></dd></div>
      <div><dt>Public path</dt><dd><code>/shop</code></dd></div>
      <div><dt>Stripe API</dt><dd>$stripe_state</dd></div>
      <div><dt>Stripe webhook</dt><dd>$webhook_state</dd></div>
    </dl>
    $section_nav
  </section>
  <section class="panel" id="module-settings">
    <h2>Catalog Settings</h2>
    <form method="post" action="/admin/settings/modules/shop/save" class="editor-form shop-settings-form">
      <input type="hidden" name="csrf_token" value="$csrf">
      <section class="inspector-panel">
        <h2>Payments</h2>
        $payment_settings_note
        <dl class="health-list health-list--compact fleet-provider-list">
          $commerce_rows
        </dl>
      </section>
      <section class="inspector-panel">
        <h2>Catalog and Checkout</h2>
        <dl class="health-list health-list--compact">
          <div><dt>Catalog feature</dt><dd>$feature_state</dd></div>
          <div><dt>Payment feature</dt><dd>$payments_feature_state</dd></div>
          <div><dt>Status</dt><dd>$enabled_state</dd></div>
          <div><dt>Webhook endpoint</dt><dd><code>$webhook_endpoint</code></dd></div>
        </dl>
        $shop_toggle
        <label class="checkbox-field">
          <input type="checkbox" name="shop_require_purchase_token" value="1" $purchase_token_checked>
          <span>Require signed purchase tokens</span>
        </label>
      </section>
      <button type="submit">Save shop settings</button>
    </form>
  </section>
  <section class="panel" id="module-listings">
    <h2>Listings</h2>
    <div class="shop-filter-bar" data-shop-filter>
      <label>
        <span>Filter by contributor</span>
        <select data-shop-contributor-select>
          <option value="">All contributors</option>
          $contributor_select_options
        </select>
      </label>
      <label>
        <span>Search contributors</span>
        <input type="search" list="shop-contributor-options" data-shop-contributor-filter placeholder="All contributors" autocomplete="off">
      </label>
      <datalist id="shop-contributor-options">
        $contributor_search_options
      </datalist>
      <button type="button" class="secondary small" data-shop-filter-clear>Clear</button>
      <span class="shop-filter-count" data-shop-filter-count>$item_count_label</span>
    </div>
