      $cards
    </div>
  </section>
  <section class="panel" id="module-orders">
    <h2>Orders</h2>
    <table class="content-table compact-table admin-card-table">
      <thead><tr><th>Created</th><th>Item</th><th>Rights</th><th>Total</th><th>Status</th><th>Email</th></tr></thead>
      <tbody>$orders</tbody>
    </table>
  </section>
</section>
HTML
    return $self->_html_response('Shop / Catalog', $body, $session);
}

sub _shop_settings_save {
    my ($self, $request, $session, $session_token) = @_;
    my $commerce_model = 'disabled';
    my $ok = eval {
        my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
        $commerce_model = $settings->{commerce_model} || 'disabled';
        my $enabled = _module_toggle_value(
            $self->_module_feature_state($settings, 'shop'),
            $request,
            'shop_enabled'
        );
        my %values = (
            module_shop_enabled => $enabled,
            shop_enabled => $enabled,
            shop_domain => '',
            shop_url => '',
            shop_require_purchase_token => $request->param('shop_require_purchase_token') ? 1 : 0,
        );
        DesertCMS::Settings::set_many($self->{config}, $self->{db}, \%values);
        $self->{shop}->clear_settings_cache;
        $self->{directory}->clear_settings_cache;
        $self->{content}->rebuild_all;
        1;
    };
    if ($ok) {
        $self->_audit_admin_action(
            $session,
            action       => 'settings.shop_saved',
            subject_type => 'settings',
            details      => {
                stripe_settings_touched => 0,
                commerce_model          => $commerce_model,
                rebuilt                 => 1,
            },
        );
    }
    return $self->_module_shop_settings_page(
        $request,
        $session,
        $session_token,
        $ok
            ? 'Shop / Catalog settings saved.'
            : _admin_action_error(
                'The Shop / Catalog settings could not be saved.',
                'Check the catalog toggle and purchase-token setting, then try again.',
                $@
            )
    );
}

sub _shop_listing_save {
    my ($self, $request, $session, $session_token, $media_asset_id) = @_;
    my $ok = eval {
        my $shop_settings = $self->{shop}->settings;
        my $payments_allowed = DesertCMS::Commerce::checkout_allowed_by_plan($shop_settings);
        my %listing_args = (
            media_asset_id       => $media_asset_id,
            title                => $request->param('title'),
            description          => $request->param('description'),
            listing_kind         => $request->param('listing_kind'),
            cta_label            => $request->param('cta_label'),
            cta_url              => $request->param('cta_url'),
            currency             => $request->param('currency'),
            active               => $request->param('active'),
        );
        if ($payments_allowed) {
            $listing_args{personal_enabled}    = $request->param('personal_enabled');
            $listing_args{personal_price}      = $request->param('personal_price');
            $listing_args{commercial_enabled}  = $request->param('commercial_enabled');
            $listing_args{commercial_price}    = $request->param('commercial_price');
            $listing_args{full_rights_enabled} = $request->param('full_rights_enabled');
            $listing_args{full_rights_price}   = $request->param('full_rights_price');
        }
        $self->{shop}->save_listing(%listing_args);
        1;
    };
    return $self->_module_shop_settings_page(
        $request,
        $session,
        $session_token,
        $ok
            ? 'Catalog listing saved.'
            : _admin_action_error(
                'The catalog listing could not be saved.',
                'Check the title, listing type, CTA, currency, and price fields, then try again.',
                $@
            )
    );
}

sub _module_directory_settings_page {
    my ($self, $request, $session, $session_token, $message) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $settings_nav = $self->_module_setup_nav('directory', $session, $settings);
    my $directory_feature = $self->_module_feature_state($settings, 'directory');
    my $enabled_state = _module_status_html($directory_feature, $self->{config});
    my $enabled_control = _module_toggle_control($directory_feature, 'module_directory_enabled', 'Enable Directory', $self->{config});
    my $directory_title = escape_html($settings->{directory_title} || 'Directory');
    my $directory_intro = escape_html($settings->{directory_intro} || 'People, businesses, artists, contributors, vendors, members, places, organizations, and resources.');
    my $submissions_checked = _setting_truthy($settings->{directory_submissions_enabled}) ? 'checked' : '';
    my $feature_eyebrow = _admin_feature_eyebrow($self->{config});
    my $is_contributor_product = DesertCMS::CapabilityPolicy::contributor_product_mode($self->{config});
    my $save_label = $is_contributor_product ? 'Save directory settings and rebuild' : 'Save Directory and rebuild';
    my $response_title = $is_contributor_product ? 'Directory Feature' : 'Directory Module';
    my $rows = $self->_directory_admin_rows($csrf);
    my $section_nav = _module_section_nav(
        'Directory setup sections',
        [ '#module-settings', 'Settings' ],
        [ '#module-entries', 'Entries' ],
    );

    my $body = <<"HTML";
<section class="editor-workspace">
  $settings_nav
  <section class="panel" id="module-settings">
    <div class="split">
      <div>
        <p class="eyebrow">$feature_eyebrow</p>
        <h1>Directory</h1>
        <p>Publish a generated <code>/directory/</code> for people, businesses, artists, contributors, vendors, members, places, organizations, and resources.</p>
      </div>
      <div class="button-row">
        <a class="button-link secondary" href="/directory/">Open directory</a>
        <a class="button-link secondary" href="/admin/settings/modules/directory/export">Export CSV</a>
