sub _module_directory_settings_save {
    my ($self, $request, $session, $session_token) = @_;
    my $ok = eval {
        my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
        DesertCMS::Settings::set_many($self->{config}, $self->{db}, {
            module_directory_enabled => _module_toggle_value($self->_module_feature_state($settings, 'directory'), $request),
            directory_title => _clean_module_text($request->param('directory_title'), 100, 'Directory'),
            directory_intro => _clean_module_text($request->param('directory_intro'), 500, 'People, businesses, artists, contributors, vendors, members, places, organizations, and resources.'),
            directory_submissions_enabled => $request->param('directory_submissions_enabled') ? 1 : 0,
        });
        $self->{directory}->clear_settings_cache;
        $self->{content}->rebuild_all;
        1;
    };
    if (!$ok) {
        return $self->_module_directory_settings_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The Directory settings could not be saved.',
                'Check the title, intro, submission setting, and feature availability, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'settings.module_directory_saved',
        subject_type => 'settings',
        details      => { rebuilt => 1 },
    );
    return $self->_module_directory_settings_page($request, $session, $session_token, 'Directory saved and public site rebuilt.');
}

