    my $slug = escape_html($entry ? $entry->{slug} : '');
    my $summary = escape_html($entry ? $entry->{summary} : '');
    my $body_text = escape_html($entry ? $entry->{body} : '');
    my $status = $entry ? ($entry->{status} || 'draft') : 'draft';
    my $kind = $entry ? ($entry->{kind} || 'other') : 'other';
    my $kind_options = _directory_kind_options($kind);
    my $status_options = _directory_status_options($status);
    my $feature_image_options = $self->_directory_feature_image_options($entry ? $entry->{image_path} : '');
    my $email = escape_html($entry ? $entry->{email} : '');
    my $phone = escape_html($entry ? $entry->{phone} : '');
    my $website_url = escape_html($entry ? $entry->{website_url} : '');
    my $social_url = escape_html($entry ? $entry->{social_url} : '');
    my $contact_label = escape_html($entry ? ($entry->{contact_label} || 'Contact') : 'Contact');
    my $address = escape_html($entry ? $entry->{address} : '');
    my $categories = escape_html($entry ? $entry->{categories_text} : '');
    my $tags = escape_html($entry ? $entry->{tags_text} : '');
    my $featured = $entry && $entry->{featured} ? 'checked' : '';
    my $sort_order = escape_html($entry ? ($entry->{sort_order} || 100) : 100);
    my $location_enabled = $entry && $entry->{location_enabled} ? 'checked' : '';
    my $location_lat = escape_html($entry ? $entry->{location_lat} : '');
    my $location_lng = escape_html($entry ? $entry->{location_lng} : '');
    my $location_label = escape_html($entry ? $entry->{location_label} : '');
    my $location_options = _location_kind_options($entry ? ($entry->{location_kind} || 'other') : 'other');
    my $submission_note = escape_html($entry ? $entry->{submission_note} : '');
    my $source = escape_html($entry ? ($entry->{source} || 'manual') : 'manual');
