sub _directory_create {
    my ($self, $request, $session, $session_token) = @_;
    return $self->_directory_save($request, $session, $session_token, undef);
}

sub _directory_update {
    my ($self, $request, $session, $session_token, $id) = @_;
    return $self->_directory_save($request, $session, $session_token, $id);
}

sub _directory_save {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $entry = eval {
        my %args = _directory_entry_args_from_request($request);
        $args{id} = $id if $id;
        my $saved = $self->{directory}->save_entry(%args);
        $self->{content}->rebuild_all;
        $saved;
    };
    if (!$entry) {
        return $self->_directory_form(
            $request,
            $session,
            $session_token,
            $id,
            _admin_action_error(
                'The directory entry could not be saved.',
                'Check the title, contact links, location, categories, and status, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => $id ? 'directory.updated' : 'directory.created',
        subject_type => 'directory_entry',
        subject_id   => $entry->{id},
        details      => { rebuilt => 1 },
    );
    return DesertCMS::HTTP->redirect('/admin/settings/modules/directory?notice=entry-saved', { security_headers() });
}

sub _directory_publish {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $ok = eval {
        my $entry = $self->{directory}->publish_entry($id);
        $self->{content}->rebuild_all;
        $self->_audit_admin_action(
            $session,
            action       => 'directory.published',
            subject_type => 'directory_entry',
            subject_id   => $entry->{id},
            details      => { rebuilt => 1 },
        );
        1;
    };
    return $self->_module_directory_settings_page(
        $request,
        $session,
        $session_token,
        $ok
            ? 'Directory entry published and public site rebuilt.'
            : _admin_action_error('The directory entry could not be published.', 'Check the entry and try again.', $@)
    );
}

sub _directory_archive {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $ok = eval {
        my $entry = $self->{directory}->archive_entry($id);
        $self->{content}->rebuild_all;
        $self->_audit_admin_action(
            $session,
            action       => 'directory.archived',
            subject_type => 'directory_entry',
            subject_id   => $entry->{id},
            details      => { rebuilt => 1 },
        );
        1;
    };
    return $self->_module_directory_settings_page(
        $request,
        $session,
        $session_token,
        $ok
            ? 'Directory entry archived and public site rebuilt.'
            : _admin_action_error('The directory entry could not be archived.', 'Refresh the Directory page and try again.', $@)
    );
}

sub _directory_export {
    my ($self, $request, $session, $session_token) = @_;
    return DesertCMS::HTTP->response(
        status => 200,
        headers => {
            'Content-Type' => 'text/csv; charset=utf-8',
            'Content-Disposition' => 'attachment; filename="directory-entries.csv"',
            security_headers(),
        },
        body => $self->{directory}->csv_export,
    );
}

sub _directory_admin_rows {
    my ($self, $csrf) = @_;
    my $rows = '';
    for my $entry (@{ $self->{directory}->list_admin }) {
        my $id = int($entry->{id});
        my $title = escape_html($entry->{title} || 'Directory entry');
        my $slug = escape_html($entry->{slug} || '');
        my $kind = escape_html(DesertCMS::Directory::kind_label($entry->{kind}));
        my $status_value = $entry->{status} || 'draft';
        my $state = $status_value eq 'published' ? 'ok' : ($status_value eq 'pending' ? 'warn' : 'neutral');
        my $status = _fleet_state_pill($state, _title_case_status($status_value));
        my $contact = escape_html($entry->{email} || $entry->{phone} || $entry->{website_url} || '');
        my $location = escape_html($entry->{location_label} || $entry->{address} || '');
        my $public = $status_value eq 'published'
            ? qq{<a class="button-link secondary button-link--compact" href="/directory/$slug/">Open</a>}
            : '';
        my $publish = $status_value eq 'published' ? '' : <<"HTML";
<form method="post" action="/admin/settings/modules/directory/$id/publish" class="inline-form">
  <input type="hidden" name="csrf_token" value="$csrf">
  <button type="submit" class="button-link secondary button-link--compact">Publish</button>
</form>
HTML
        $rows .= <<"HTML";
<tr>
  <td data-label="Entry"><strong>$title</strong><br><code>$slug</code></td>
  <td data-label="Type">$kind</td>
  <td data-label="Status">$status</td>
  <td data-label="Contact">$contact</td>
  <td data-label="Location">$location</td>
  <td data-label="Actions" class="table-actions">
    <a class="button-link secondary button-link--compact" href="/admin/settings/modules/directory/$id/edit">Edit</a>
    $public
    $publish
    <form method="post" action="/admin/settings/modules/directory/$id/archive" class="inline-form" data-confirm-title="Archive this entry?" data-confirm-message="The entry will leave the public directory, but its record stays in the database." data-confirm-action="Archive">
      <input type="hidden" name="csrf_token" value="$csrf">
      <button type="submit" class="button-link secondary button-link--compact button-link--warn">Archive</button>
    </form>
  </td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(6, 'No directory entries yet.', 'Create profiles or listings for people, businesses, places, organizations, and resources.');
}

sub _directory_kind_options {
    my ($selected) = @_;
    $selected ||= 'other';
    my @options = map { [ $_, DesertCMS::Directory::kind_label($_) ] } @{ DesertCMS::Directory::kinds() };
    return join '', map {
        my ($value, $label) = @{$_};
        my $is_selected = $value eq $selected ? ' selected' : '';
        '<option value="' . escape_html($value) . '"' . $is_selected . '>' . escape_html($label) . '</option>';
    } @options;
}

sub _directory_status_options {
    my ($selected) = @_;
    $selected ||= 'draft';
    my @options = (
        [ draft => 'Draft' ],
        [ pending => 'Pending review' ],
        [ published => 'Published' ],
        [ archived => 'Archived' ],
    );
    return join '', map {
        my ($value, $label) = @{$_};
        my $is_selected = $value eq $selected ? ' selected' : '';
        '<option value="' . escape_html($value) . '"' . $is_selected . '>' . escape_html($label) . '</option>';
    } @options;
}

sub _directory_feature_image_options {
    my ($self, $selected) = @_;
    my $rows = $self->{db}->dbh->selectall_arrayref(
        q{
            SELECT original_name, public_path
            FROM media_assets
            WHERE deleted_at IS NULL
              AND public_path LIKE '/assets/media/%'
            ORDER BY created_at DESC, id DESC
            LIMIT 200
        },
        { Slice => {} }
    );
    my $html = '<option value="">No image</option>';
    for my $row (@{$rows}) {
        next unless DesertCMS::Media::is_public_image_path($row->{public_path} || '');
        my $path = escape_html($row->{public_path} || '');
        my $name = escape_html($row->{original_name} || $row->{public_path} || 'Image');
        my $is_selected = ($row->{public_path} || '') eq ($selected || '') ? 'selected' : '';
        $html .= qq{<option value="$path" $is_selected>$name</option>};
    }
    return $html;
}

sub _directory_entry_args_from_request {
    my ($request) = @_;
    return (
        title                   => $request->param('title'),
        slug                    => $request->param('slug'),
        kind                    => $request->param('kind'),
        status                  => $request->param('status'),
        summary                 => $request->param('summary'),
        body                    => $request->param('body'),
        image_path              => $request->param('image_path'),
        email                   => $request->param('email'),
        phone                   => $request->param('phone'),
        website_url             => $request->param('website_url'),
        social_url              => $request->param('social_url'),
        contact_label           => $request->param('contact_label'),
        address                 => $request->param('address'),
        tags_text               => $request->param('tags_text'),
        categories_text         => $request->param('categories_text'),
        featured                => $request->param('featured'),
        sort_order              => $request->param('sort_order'),
        related_content_id      => $request->param('related_content_id'),
        related_event_id        => $request->param('related_event_id'),
        related_shop_listing_id => $request->param('related_shop_listing_id'),
        location_enabled        => $request->param('location_enabled'),
        location_lat            => $request->param('location_lat'),
        location_lng            => $request->param('location_lng'),
        location_label          => $request->param('location_label'),
        location_kind           => $request->param('location_kind'),
        submission_note         => $request->param('submission_note'),
    );
}

