sub _module_bookings_settings_save {
    my ($self, $request, $session, $session_token) = @_;
    my $ok = eval {
        my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
        DesertCMS::Settings::set_many($self->{config}, $self->{db}, {
            module_bookings_enabled => _module_toggle_value($self->_module_feature_state($settings, 'bookings'), $request),
            bookings_title => _clean_module_text($request->param('bookings_title'), 100, 'Bookings'),
            bookings_intro => _clean_module_text($request->param('bookings_intro'), 500, 'Request appointments, consultations, service sessions, venue time, or project meetings.'),
            bookings_requests_enabled => $request->param('bookings_requests_enabled') ? 1 : 0,
            bookings_notify_postmark_enabled => $request->param('bookings_notify_postmark_enabled') ? 1 : 0,
            bookings_notification_email => _clean_email($request->param('bookings_notification_email')),
        });
        $self->{bookings}->clear_settings_cache;
        $self->{content}->rebuild_all;
        1;
    };
    if (!$ok) {
        return $self->_module_bookings_settings_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The Bookings settings could not be saved.',
                'Check the title, intro, request setting, and notification email, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'settings.module_bookings_saved',
        subject_type => 'settings',
        details      => { rebuilt => 1 },
    );
    return $self->_module_bookings_settings_page($request, $session, $session_token, 'Bookings saved and public site rebuilt.');
}

