    my $title = escape_html($service ? $service->{title} : '');
    my $slug = escape_html($service ? $service->{slug} : '');
    my $summary = escape_html($service ? $service->{summary} : '');
    my $body_text = escape_html($service ? $service->{body} : '');
    my $availability = escape_html($service ? $service->{availability_text} : '');
    my $status = $service ? ($service->{status} || 'draft') : 'draft';
    my $published_selected = $status eq 'published' ? 'selected' : '';
