    my $feature_image_options = $self->_directory_feature_image_options($service ? $service->{image_path} : '');
    my $duration = escape_html($service ? ($service->{duration_minutes} || 0) : 0);
    my $price_note = escape_html($service ? $service->{price_note} : '');
    my $featured = $service && $service->{featured} ? 'checked' : '';
    my $sort_order = escape_html($service ? ($service->{sort_order} || 100) : 100);
    my $location_enabled = $service && $service->{location_enabled} ? 'checked' : '';
    my $location_lat = escape_html($service ? $service->{location_lat} : '');
    my $location_lng = escape_html($service ? $service->{location_lng} : '');
    my $location_label = escape_html($service ? $service->{location_label} : '');
    my $location_options = _location_kind_options($service ? ($service->{location_kind} || 'service_area') : 'service_area');
    my $payments_feature = $self->_module_feature_state($settings, 'booking_payments');
    my $payments_locked = $payments_feature && $payments_feature->{locked_by_plan} ? 1 : 0;
    my $deposit_enabled = $service && $service->{deposit_enabled} ? 'checked' : '';
    my $deposit_label = escape_html($service ? ($service->{deposit_label} || 'Deposit') : 'Deposit');
