sub _booking_service_create {
    my ($self, $request, $session, $session_token) = @_;
    return $self->_booking_service_save($request, $session, $session_token, undef);
}

sub _booking_service_update {
    my ($self, $request, $session, $session_token, $id) = @_;
    return $self->_booking_service_save($request, $session, $session_token, $id);
}

sub _booking_service_save {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $service = eval {
        my %args = _booking_service_args_from_request($request);
        $args{id} = $id if $id;
        my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
        my $payments_feature = $self->_module_feature_state($settings, 'booking_payments');
        if ($payments_feature && $payments_feature->{locked_by_plan}) {
            my $existing = $id ? $self->{bookings}->get_service($id) : undef;
            $args{deposit_enabled} = $existing ? $existing->{deposit_enabled} : 0;
            $args{deposit_label} = $existing ? $existing->{deposit_label} : 'Deposit';
            $args{deposit_amount_cents} = $existing ? $existing->{deposit_amount_cents} : 0;
            $args{deposit_currency} = $existing ? $existing->{deposit_currency} : 'usd';
        }
        my $saved = $self->{bookings}->save_service(%args);
        $self->{content}->rebuild_all;
        $saved;
    };
    if (!$service) {
        return $self->_booking_service_form(
            $request,
            $session,
            $session_token,
            $id,
            _admin_action_error(
                'The booking service could not be saved.',
                'Check the title, service type, availability, location, and deposit fields, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => $id ? 'bookings.service_updated' : 'bookings.service_created',
        subject_type => 'booking_service',
        subject_id   => $service->{id},
        details      => { rebuilt => 1 },
    );
    return DesertCMS::HTTP->redirect('/admin/settings/modules/bookings?notice=booking-service-saved', { security_headers() });
}

sub _booking_service_publish {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $ok = eval {
        my $service = $self->{bookings}->publish_service($id);
        $self->{content}->rebuild_all;
        $self->_audit_admin_action(
            $session,
            action       => 'bookings.service_published',
            subject_type => 'booking_service',
            subject_id   => $service->{id},
            details      => { rebuilt => 1 },
        );
        1;
    };
    return $self->_module_bookings_settings_page(
        $request,
        $session,
        $session_token,
        $ok
            ? 'Booking service published and public site rebuilt.'
            : _admin_action_error('The booking service could not be published.', 'Check the service and try again.', $@)
    );
}

sub _booking_service_archive {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $ok = eval {
        my $service = $self->{bookings}->archive_service($id);
        $self->{content}->rebuild_all;
        $self->_audit_admin_action(
            $session,
            action       => 'bookings.service_archived',
            subject_type => 'booking_service',
            subject_id   => $service->{id},
            details      => { rebuilt => 1 },
        );
        1;
    };
    return $self->_module_bookings_settings_page(
        $request,
        $session,
        $session_token,
        $ok
            ? 'Booking service archived and public site rebuilt.'
            : _admin_action_error('The booking service could not be archived.', 'Refresh the Bookings page and try again.', $@)
    );
}

sub _booking_request_status {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $ok = eval {
        $self->{bookings}->update_request_status(id => $id, status => $request->param('status'));
        1;
    };
    return $self->_module_bookings_settings_page(
        $request,
        $session,
        $session_token,
        $ok
            ? 'Booking request status updated.'
            : _admin_action_error('The booking request could not be updated.', 'Check the selected status and try again.', $@)
    );
}

sub _booking_requests_export {
    my ($self, $request, $session, $session_token) = @_;
    my $csv = $self->{bookings}->csv_export;
    return DesertCMS::HTTP->response(
        status  => 200,
        headers => {
            'Content-Type' => 'text/csv; charset=utf-8',
            'Content-Disposition' => 'attachment; filename="booking-requests.csv"',
            security_headers(),
        },
        body => $csv,
    );
}

sub _booking_service_admin_rows {
    my ($self, $csrf) = @_;
    my $rows = '';
    for my $service (@{ $self->{bookings}->list_admin }) {
        my $id = int($service->{id});
        my $title = escape_html($service->{title} || 'Booking service');
        my $slug = escape_html($service->{slug} || '');
        my $kind = escape_html(DesertCMS::Bookings::service_kind_label($service->{service_kind}));
        my $status = _fleet_state_pill(($service->{status} || '') eq 'published' ? 'ok' : 'neutral', _title_case_status($service->{status}));
        my $requests = int($service->{request_count} || 0);
        my $deposit = $service->{deposit_enabled}
            ? escape_html(DesertCMS::Bookings::price_label($service->{deposit_amount_cents}, $service->{deposit_currency}))
            : 'None';
        my $public = ($service->{status} || '') eq 'published'
            ? qq{<a class="button-link secondary button-link--compact" href="/bookings/$slug/">Open</a>}
            : '';
        my $publish = ($service->{status} || '') eq 'published' ? '' : <<"HTML";
<form method="post" action="/admin/settings/modules/bookings/$id/publish" class="inline-form">
  <input type="hidden" name="csrf_token" value="$csrf">
  <button type="submit" class="button-link secondary button-link--compact">Publish</button>
</form>
HTML
        $rows .= <<"HTML";
<tr>
  <td data-label="Service"><strong>$title</strong><br><code>$slug</code></td>
  <td data-label="Type">$kind</td>
  <td data-label="Status">$status</td>
  <td data-label="Requests">$requests</td>
  <td data-label="Deposit">$deposit</td>
  <td data-label="Actions" class="table-actions">
    <a class="button-link secondary button-link--compact" href="/admin/settings/modules/bookings/$id/edit">Edit</a>
    $public
    $publish
    <form method="post" action="/admin/settings/modules/bookings/$id/archive" class="inline-form" data-confirm-title="Archive this service?" data-confirm-message="The service will leave public booking pages, but request and payment history stays in the database." data-confirm-action="Archive">
      <input type="hidden" name="csrf_token" value="$csrf">
      <button type="submit" class="button-link secondary button-link--compact button-link--warn">Archive</button>
    </form>
  </td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(6, 'No booking services yet.', 'Create a service to publish public appointment or booking request forms.');
}

sub _booking_request_admin_rows {
    my ($self, $csrf) = @_;
    my $rows = '';
    for my $request (@{ $self->{bookings}->requests(limit => 200) }) {
        my $id = int($request->{id});
        my $created = escape_html(_format_time($request->{created_at}));
        my $service = escape_html($request->{service_title} || 'Booking service');
        my $requester = escape_html(($request->{name} || '') . ' <' . ($request->{email} || '') . '>');
        my $requested = escape_html(join ' ', grep { length } ($request->{requested_date} || '', $request->{requested_time} || '', $request->{preferred_window} || ''));
        my $deposit = escape_html($request->{deposit_status} || 'none');
        my $status = $request->{status} || 'new';
        my $status_label = escape_html(DesertCMS::Bookings::request_status_label($status));
        my $status_options = _booking_request_status_options($status);
        $rows .= <<"HTML";
<tr>
  <td data-label="Received">$created</td>
  <td data-label="Service">$service</td>
  <td data-label="Requester">$requester</td>
  <td data-label="Requested">$requested</td>
  <td data-label="Deposit">$deposit</td>
  <td data-label="Status">$status_label</td>
  <td data-label="Actions" class="table-actions">
    <form method="post" action="/admin/settings/modules/bookings/requests/$id/status" class="inline-form">
      <input type="hidden" name="csrf_token" value="$csrf">
      <select name="status">$status_options</select>
      <button type="submit" class="button-link secondary button-link--compact">Save</button>
    </form>
  </td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(7, 'No booking requests yet.', 'Public appointment and service requests will appear here.');
}

sub _booking_payment_admin_rows {
    my ($self) = @_;
    my $rows = '';
    for my $payment (@{ $self->{bookings}->recent_payments(limit => 25) }) {
        my $created = escape_html(_format_time($payment->{created_at}));
        my $service = escape_html($payment->{service_title} || 'Booking service');
        my $requester = escape_html(($payment->{customer_name} || '') . ' <' . ($payment->{customer_email} || '') . '>');
        my $total = escape_html(DesertCMS::Bookings::price_label($payment->{amount_cents}, $payment->{currency}));
        my $status = escape_html($payment->{status} || '');
        my $session = escape_html($payment->{stripe_checkout_session_id} || '');
        $rows .= qq{<tr><td data-label="Created">$created</td><td data-label="Service">$service</td><td data-label="Requester">$requester</td><td data-label="Total">$total</td><td data-label="Status">$status</td><td data-label="Stripe Session"><code>$session</code></td></tr>};
    }
    return $rows || _admin_empty_row(6, 'No booking deposit payments yet.', 'Stripe deposit records will appear here when Booking Deposits is included and ready.');
}

sub _booking_service_args_from_request {
    my ($request) = @_;
    return (
        title                => $request->param('title'),
        slug                 => $request->param('slug'),
        service_kind         => $request->param('service_kind'),
        status               => $request->param('status'),
        summary              => $request->param('summary'),
        body                 => $request->param('body'),
        image_path           => $request->param('image_path'),
        availability_text    => $request->param('availability_text'),
        duration_minutes     => $request->param('duration_minutes'),
        price_note           => $request->param('price_note'),
        deposit_enabled      => $request->param('deposit_enabled'),
        deposit_label        => $request->param('deposit_label'),
        deposit_amount       => $request->param('deposit_amount'),
        deposit_currency     => $request->param('deposit_currency'),
        featured             => $request->param('featured'),
        sort_order           => $request->param('sort_order'),
        location_enabled     => $request->param('location_enabled'),
        location_lat         => $request->param('location_lat'),
        location_lng         => $request->param('location_lng'),
        location_label       => $request->param('location_label'),
        location_kind        => $request->param('location_kind'),
    );
}

sub _booking_service_kind_options {
    my ($selected) = @_;
    my $html = '';
    for my $kind (@{ DesertCMS::Bookings::service_kinds() }) {
        my $safe = escape_html($kind);
        my $label = escape_html(DesertCMS::Bookings::service_kind_label($kind));
        my $is_selected = $kind eq ($selected || '') ? 'selected' : '';
        $html .= qq{<option value="$safe" $is_selected>$label</option>};
    }
    return $html;
}

sub _booking_request_status_options {
    my ($selected) = @_;
    my $html = '';
    for my $status (@{ DesertCMS::Bookings::request_statuses() }) {
        my $safe = escape_html($status);
        my $label = escape_html(DesertCMS::Bookings::request_status_label($status));
        my $is_selected = $status eq ($selected || '') ? 'selected' : '';
        $html .= qq{<option value="$safe" $is_selected>$label</option>};
    }
    return $html;
}

sub _module_events_settings_page {
    my ($self, $request, $session, $session_token, $message) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $settings_nav = $self->_module_setup_nav('events', $session, $settings);
    my $events_feature = $self->_module_feature_state($settings, 'events');
    my $payments_feature = $self->_module_feature_state($settings, 'event_payments');
    my $enabled_state = _module_status_html($events_feature, $self->{config});
    my $payments_state = _module_status_html($payments_feature, $self->{config});
    my $enabled_control = _module_toggle_control($events_feature, 'module_events_enabled', 'Enable Events', $self->{config});
    my $payment_readiness = $self->{events}->payment_readiness;
    my $payments_summary = _fleet_state_pill($payment_readiness->{state}, $payment_readiness->{label})
        . '<small>' . escape_html($payment_readiness->{summary}) . '</small>';
    my $events_title = escape_html($settings->{events_title} || 'Events');
    my $events_intro = escape_html($settings->{events_intro} || 'Upcoming events, calendars, RSVP opportunities, tickets, and location details.');
    my $notify_checked = _setting_truthy($settings->{events_notify_postmark_enabled}) ? 'checked' : '';
    my $notify_email = escape_html($settings->{events_notification_email} || '');
    my $feature_eyebrow = _admin_feature_eyebrow($self->{config});
    my $is_contributor_product = DesertCMS::CapabilityPolicy::contributor_product_mode($self->{config});
    my $save_label = $is_contributor_product ? 'Save events settings and rebuild' : 'Save Events and rebuild';
    my $response_title = $is_contributor_product ? 'Events Feature' : 'Events Module';
    my $event_rows = $self->_event_admin_rows($csrf);
    my $rsvp_rows = $self->_event_rsvp_rows($csrf);
    my $order_rows = $self->_event_order_rows;
    my $section_nav = _module_section_nav(
        'Events setup sections',
        [ '#module-settings', 'Calendar Settings' ],
        [ '#module-events', 'Events' ],
        [ '#module-rsvps', 'RSVPs' ],
        [ '#module-orders', 'Ticket Orders' ],
    );

    my $body = <<"HTML";
<section class="editor-workspace">
  $settings_nav
  <section class="panel" id="module-settings">
    <div class="split">
      <div>
        <p class="eyebrow">$feature_eyebrow</p>
        <h1>Events</h1>
        <p>Publish a generated <code>/events/</code> calendar with standalone event pages, RSVP, recurrence, location tie-ins, calendar export, and optional paid tickets.</p>
      </div>
      <div class="button-row">
        <a class="button-link secondary" href="/events/">Open events</a>
        <a class="button-link" href="/admin/settings/modules/events/new">New event</a>
      </div>
    </div>
    $notice
    $section_nav
    <form method="post" action="/admin/settings/modules/events/save" class="settings-form settings-form--wide">
      <input type="hidden" name="csrf_token" value="$csrf">
      <section class="inspector-panel">
        <h2>Calendar Settings</h2>
        <dl class="health-list health-list--compact">
          <div><dt>Public path</dt><dd><code>/events/</code></dd></div>
          <div><dt>Calendar export</dt><dd><code>/events.ics</code></dd></div>
          <div><dt>Status</dt><dd>$enabled_state</dd></div>
          <div><dt>Paid tickets</dt><dd>$payments_state</dd></div>
          <div><dt>Checkout readiness</dt><dd>$payments_summary</dd></div>
        </dl>
        $enabled_control
      </section>
      <section class="inspector-panel">
        <h2>Public Copy</h2>
        <label>
          <span>Title</span>
          <input name="events_title" value="$events_title" maxlength="100">
        </label>
        <label>
          <span>Intro</span>
          <textarea name="events_intro" rows="4" maxlength="500">$events_intro</textarea>
        </label>
      </section>
      <section class="inspector-panel">
        <h2>RSVP Notifications</h2>
        <label class="checkbox-field">
          <input type="checkbox" name="events_notify_postmark_enabled" value="1" $notify_checked>
