        </label>
        <label>
          <span>Notification recipient</span>
          <input name="events_notification_email" type="email" value="$notify_email" maxlength="180" placeholder="events&#64;example.com">
        </label>
      </section>
      <button type="submit">$save_label</button>
    </form>
  </section>
  <section class="panel">
    <div class="split">
      <div>
        <h2>Events</h2>
        <p class="muted">Create one-time or recurring events, then publish them to the public calendar.</p>
      </div>
