    </div>
    <table class="content-table compact-table admin-card-table">
      <thead><tr><th>Event</th><th>Status</th><th>Next</th><th>Occurrences</th><th>Actions</th></tr></thead>
      <tbody>$event_rows</tbody>
    </table>
  </section>
  <section class="panel" id="module-events">
    <h2>RSVPs</h2>
    <table class="content-table compact-table admin-card-table">
