</section>
HTML

    return $self->_html_response($response_title, $body, $session);
}

sub _module_events_settings_save {
    my ($self, $request, $session, $session_token) = @_;
    my $ok = eval {
        my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
        DesertCMS::Settings::set_many($self->{config}, $self->{db}, {
            module_events_enabled => _module_toggle_value($self->_module_feature_state($settings, 'events'), $request),
            events_title => _clean_module_text($request->param('events_title'), 100, 'Events'),
            events_intro => _clean_module_text($request->param('events_intro'), 500, 'Upcoming events, calendars, RSVP opportunities, tickets, and location details.'),
            events_notify_postmark_enabled => $request->param('events_notify_postmark_enabled') ? 1 : 0,
            events_notification_email => _clean_email($request->param('events_notification_email')),
        });
        $self->{events}->clear_settings_cache;
        $self->{content}->rebuild_all;
        1;
    };
    if (!$ok) {
        return $self->_module_events_settings_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The Events settings could not be saved.',
                'Check the calendar title, intro, and notification email, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'settings.module_events_saved',
        subject_type => 'settings',
        details      => { rebuilt => 1 },
    );
    return $self->_module_events_settings_page($request, $session, $session_token, 'Events saved and public site rebuilt.');
}

sub _event_form {
