    my $event = $id ? $self->{events}->get($id) : undef;
    return $self->_not_found if $id && !$event;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $settings_nav = $self->_module_setup_nav('events', $session, $settings);
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $action = $event ? '/admin/settings/modules/events/' . int($event->{id}) . '/update' : '/admin/settings/modules/events/create';
