    my $timezone = escape_html($event ? $event->{timezone} : 'UTC');
    my $starts_at = escape_html(_admin_datetime_value($event ? $event->{starts_at} : now() + 86400, $event ? $event->{timezone} : 'UTC'));
    my $ends_at = escape_html(_admin_datetime_value($event ? $event->{ends_at} : now() + 90000, $event ? $event->{timezone} : 'UTC'));
    my $all_day = $event && $event->{all_day} ? 'checked' : '';
    my $status = $event ? ($event->{status} || 'draft') : 'draft';
    my $published_selected = $status eq 'published' ? 'selected' : '';
    my $draft_selected = $status eq 'draft' ? 'selected' : '';
    my $archived_selected = $status eq 'archived' ? 'selected' : '';
    my $rrule = escape_html($event ? $event->{rrule} : '');
    my $rdate = escape_html($event ? $event->{rdate_text} : '');
