    my $rsvp_enabled = $event && $event->{rsvp_enabled} ? 'checked' : '';
    my $rsvp_capacity = escape_html($event ? $event->{rsvp_capacity} : 0);
    my $waitlist_enabled = !$event || $event->{waitlist_enabled} ? 'checked' : '';
    my $ticketing_enabled = $event && $event->{ticketing_enabled} ? 'checked' : '';
    my $ticket = $event ? ($self->{events}->ticket_types($event->{id})->[0] || {}) : {};
    my $ticket_name = escape_html($ticket->{name} || 'General admission');
    my $ticket_description = escape_html($ticket->{description} || '');
    my $ticket_price = escape_html(_admin_price($ticket->{price_cents}));
