    my $event_id_input = $ticket->{id} ? '<input type="hidden" name="ticket_id" value="' . int($ticket->{id}) . '">' : '';
    my $feature_image_options = _event_feature_image_options($self, $event ? $event->{feature_image_path} : '');
    my $heading = $event ? 'Edit Event' : 'New Event';
    my $form_section_nav = _module_section_nav(
