sub _event_create {
    my ($self, $request, $session, $session_token) = @_;
    return $self->_event_save($request, $session, $session_token, undef);
}

sub _event_update {
    my ($self, $request, $session, $session_token, $id) = @_;
    return $self->_event_save($request, $session, $session_token, $id);
}

sub _event_save {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $event = eval {
        my %args = _event_args_from_request($request);
        $args{id} = $id if $id;
        my $saved = $self->{events}->save_event(%args);
        if (length($request->param('ticket_name') || '') || $request->param('ticketing_enabled')) {
            $self->{events}->save_ticket_type(
                id          => $request->param('ticket_id'),
                event_id    => $saved->{id},
                name        => $request->param('ticket_name'),
                description => $request->param('ticket_description'),
                currency    => $request->param('ticket_currency'),
                price       => $request->param('ticket_price'),
                capacity    => $request->param('ticket_capacity'),
                active      => $request->param('ticket_active'),
            );
        }
        $self->{content}->rebuild_all;
        $saved;
    };
    if (!$event) {
        return $self->_event_form(
            $request,
            $session,
            $session_token,
            $id,
            _admin_action_error(
                'The event could not be saved.',
                'Check the title, dates, recurrence rule, location, RSVP, and ticket fields, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => $id ? 'events.updated' : 'events.created',
        subject_type => 'event',
        subject_id   => $event->{id},
        details      => { rebuilt => 1 },
    );
    return DesertCMS::HTTP->redirect('/admin/settings/modules/events?notice=event-saved', { security_headers() });
}

sub _event_publish {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $ok = eval {
        my $event = $self->{events}->publish_event($id);
        $self->{content}->rebuild_all;
        $self->_audit_admin_action(
            $session,
            action       => 'events.published',
            subject_type => 'event',
            subject_id   => $event->{id},
            details      => { rebuilt => 1 },
        );
        1;
    };
    return $self->_module_events_settings_page(
        $request,
        $session,
        $session_token,
        $ok
            ? 'Event published and public site rebuilt.'
            : _admin_action_error('The event could not be published.', 'Check the event and try again.', $@)
    );
}

sub _event_delete {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $ok = eval {
        my $event = $self->{events}->delete_event($id);
        $self->{content}->rebuild_all;
        $self->_audit_admin_action(
            $session,
            action       => 'events.deleted',
            subject_type => 'event',
            subject_id   => $event->{id},
            details      => { rebuilt => 1 },
        );
        1;
    };
    return $self->_module_events_settings_page(
        $request,
        $session,
        $session_token,
        $ok
            ? 'Event archived and public site rebuilt.'
            : _admin_action_error('The event could not be archived.', 'Refresh the Events page and try again.', $@)
    );
}

sub _event_rsvp_status {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $ok = eval {
        $self->{events}->update_rsvp_status(id => $id, status => $request->param('status'));
        1;
    };
    return $self->_module_events_settings_page(
        $request,
        $session,
        $session_token,
        $ok
            ? 'RSVP status updated.'
            : _admin_action_error('The RSVP could not be updated.', 'Check the selected status and try again.', $@)
    );
}

sub _event_admin_rows {
    my ($self, $csrf) = @_;
    my $rows = '';
    for my $event (@{ $self->{events}->list_admin }) {
        my $id = int($event->{id});
        my $title = escape_html($event->{title} || 'Event');
        my $slug = escape_html($event->{slug} || '');
        my $status = _fleet_state_pill(($event->{status} || '') eq 'published' ? 'ok' : 'neutral', _title_case_status($event->{status}));
        my $next = escape_html(_format_time($event->{next_occurrence_at} || $event->{starts_at}));
        my $count = int($event->{occurrence_count} || 0);
        my $public = ($event->{status} || '') eq 'published'
            ? qq{<a class="button-link secondary button-link--compact" href="/events/$slug/">Open</a>}
            : '';
        my $publish = ($event->{status} || '') eq 'published' ? '' : <<"HTML";
<form method="post" action="/admin/settings/modules/events/$id/publish" class="inline-form">
  <input type="hidden" name="csrf_token" value="$csrf">
  <button type="submit" class="button-link secondary button-link--compact">Publish</button>
</form>
HTML
        $rows .= <<"HTML";
<tr>
  <td data-label="Event"><strong>$title</strong><br><code>$slug</code></td>
  <td data-label="Status">$status</td>
  <td data-label="Next">$next</td>
  <td data-label="Occurrences">$count</td>
  <td data-label="Actions" class="table-actions">
    <a class="button-link secondary button-link--compact" href="/admin/settings/modules/events/$id/edit">Edit</a>
    $public
    $publish
    <form method="post" action="/admin/settings/modules/events/$id/delete" class="inline-form" data-confirm-title="Archive this event?" data-confirm-message="The event will leave public event pages, but RSVP and order history stays in the database." data-confirm-action="Archive">
      <input type="hidden" name="csrf_token" value="$csrf">
      <button type="submit" class="button-link secondary button-link--compact button-link--warn">Archive</button>
    </form>
  </td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(5, 'No events yet.', 'Create a one-time or recurring event to publish the public calendar.');
}

sub _event_rsvp_rows {
    my ($self, $csrf) = @_;
    my $rows = '';
    for my $event (@{ $self->{events}->list_admin }) {
        for my $rsvp (@{ $self->{events}->rsvps($event->{id}) }) {
            my $id = int($rsvp->{id});
            my $created = escape_html(_format_time($rsvp->{created_at}));
            my $title = escape_html($event->{title} || 'Event');
            my $guest = escape_html(($rsvp->{name} || '') . ' <' . ($rsvp->{email} || '') . '>');
            my $count = int($rsvp->{guest_count} || 1);
            my $status = escape_html($rsvp->{status} || '');
            my $confirmed = $status eq 'confirmed' ? 'selected' : '';
            my $waitlist = $status eq 'waitlist' ? 'selected' : '';
            my $canceled = $status eq 'canceled' ? 'selected' : '';
            $rows .= <<"HTML";
<tr>
  <td data-label="Received">$created</td>
  <td data-label="Event">$title</td>
  <td data-label="Guest">$guest</td>
  <td data-label="Count">$count</td>
  <td data-label="Status">$status</td>
  <td data-label="Actions" class="table-actions">
    <form method="post" action="/admin/settings/modules/events/rsvps/$id/status" class="inline-form">
      <input type="hidden" name="csrf_token" value="$csrf">
      <select name="status">
        <option value="confirmed" $confirmed>Confirmed</option>
        <option value="waitlist" $waitlist>Waitlist</option>
        <option value="canceled" $canceled>Canceled</option>
      </select>
      <button type="submit" class="button-link secondary button-link--compact">Save</button>
    </form>
  </td>
</tr>
HTML
        }
    }
    return $rows || _admin_empty_row(6, 'No RSVPs yet.', 'Free RSVP submissions will appear here.');
}

sub _event_order_rows {
    my ($self) = @_;
    my $rows = '';
    for my $order (@{ $self->{events}->recent_orders(limit => 25) }) {
        my $created = escape_html(_format_time($order->{created_at}));
        my $event = escape_html($order->{event_title} || 'Event');
        my $ticket = escape_html($order->{ticket_name} || 'Ticket');
        my $qty = int($order->{quantity} || 1);
        my $total = escape_html(DesertCMS::Events::price_label($order->{amount_cents}, $order->{currency}));
        my $status = escape_html($order->{status} || '');
        $rows .= qq{<tr><td data-label="Created">$created</td><td data-label="Event">$event</td><td data-label="Ticket">$ticket</td><td data-label="Quantity">$qty</td><td data-label="Total">$total</td><td data-label="Status">$status</td></tr>};
    }
    return $rows || _admin_empty_row(6, 'No ticket orders yet.', 'Paid Stripe ticket orders will appear here.');
}

