sub _event_feature_image_options {
    my ($self, $selected) = @_;
    my $rows = $self->{db}->dbh->selectall_arrayref(
        q{
            SELECT original_name, public_path
            FROM media_assets
            WHERE deleted_at IS NULL
              AND public_path LIKE '/assets/media/%'
            ORDER BY created_at DESC, id DESC
            LIMIT 200
        },
        { Slice => {} }
    );
    my $html = '<option value="">No feature image</option>';
    for my $row (@{$rows}) {
        next unless DesertCMS::Media::is_public_image_path($row->{public_path} || '');
        my $path = escape_html($row->{public_path} || '');
        my $name = escape_html($row->{original_name} || $row->{public_path} || 'Image');
        my $is_selected = ($row->{public_path} || '') eq ($selected || '') ? 'selected' : '';
        $html .= qq{<option value="$path" $is_selected>$name</option>};
    }
    return $html;
}

sub _admin_datetime_value {
    my ($epoch, $timezone) = @_;
    my $dt = eval { DesertCMS::DateTimeLite->from_epoch(epoch => int($epoch || 0), time_zone => $timezone || 'UTC') }
        || DesertCMS::DateTimeLite->from_epoch(epoch => int($epoch || 0), time_zone => 'UTC');
    return sprintf('%04d-%02d-%02dT%02d:%02d', $dt->year, $dt->month, $dt->day, $dt->hour, $dt->minute);
}

sub _admin_parse_datetime_value {
    my ($value, $timezone) = @_;
    $value = '' unless defined $value;
    $value =~ s/\A\s+|\s+\z//g;
    return undef unless length $value;
    return int($value) if $value =~ /\A[0-9]{9,12}\z/;
    my ($year, $month, $day, $hour, $minute, $second);
    if ($value =~ /\A([0-9]{4})-([0-9]{2})-([0-9]{2})(?:[T ]([0-9]{2}):([0-9]{2})(?::([0-9]{2}))?)?\z/) {
        ($year, $month, $day, $hour, $minute, $second) = (int($1), int($2), int($3), int($4 || 0), int($5 || 0), int($6 || 0));
    } else {
        die "scheduled time is invalid";
    }
    die "scheduled time is invalid"
        unless $month >= 1 && $month <= 12
        && $day >= 1 && $day <= 31
        && $hour >= 0 && $hour <= 23
        && $minute >= 0 && $minute <= 59
        && $second >= 0 && $second <= 59;
    my $dt = eval {
        DesertCMS::DateTimeLite->new(
            year => $year, month => $month, day => $day,
            hour => $hour, minute => $minute, second => $second,
            time_zone => $timezone || 'UTC',
        );
    };
    die "scheduled time is invalid" unless $dt;
    die "scheduled time is invalid"
        unless $dt->year == $year
        && $dt->month == $month
        && $dt->day == $day
        && $dt->hour == $hour
        && $dt->minute == $minute;
    return $dt->epoch;
}

sub _navigation_page {
    my ($self, $request, $session, $session_token, $message) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $text = DesertCMS::Navigation::as_text($self->{config}, $self->{db});
    $text = "Home | /" unless length $text;
    my $safe_text = escape_html($text);
    my $editor_nav = _editor_nav('nav', $self->{config}, $session);
    my $body = <<"HTML";
<section class="editor-workspace">
  $editor_nav
  <section class="panel">
    <div class="split">
      <div>
        <p class="eyebrow">@{[_admin_editor_eyebrow($self->{config})]}</p>
        <h1>Navigation</h1>
        <p>This directly controls the public nav bar. One item per line using <code>Label | /url/</code> or <code>Label | https://example.com</code>.</p>
      </div>
    </div>
    $notice
    <form method="post" action="/admin/navigation/save" class="editor-form">
      <input type="hidden" name="csrf_token" value="$csrf">
      <label>
        <span>Primary navigation</span>
