sub _navigation_save {
    my ($self, $request, $session, $session_token) = @_;
    my $ok = eval {
        DesertCMS::Navigation::replace_from_text($self->{config}, $self->{db}, $request->param('navigation_text'));
        $self->{content}->rebuild_all;
        1;
    };
    if (!$ok) {
