sub _backup_list {
    my ($self, $request, $session, $session_token, $message) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $backups = DesertCMS::Backup::list_backups($self->{config}, $self->{db});
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $rows = '';

    for my $backup (@{$backups}) {
        my $id = int($backup->{id});
        my $filename = escape_html($backup->{filename});
        my $created_at = scalar localtime($backup->{created_at});
        $created_at = escape_html($created_at);
        $rows .= <<"HTML";
<tr>
  <td data-label="Archive"><code>$filename</code></td>
  <td data-label="Created">$created_at</td>
  <td data-label="Actions" class="row-actions table-actions">
    <form method="post" action="/admin/backups/restore" data-confirm-title="Restore this backup?" data-confirm-message="This replaces the current database and site files with the selected archive. Create a fresh backup first if you need the current state." data-confirm-action="Restore" data-loading-label="Preparing...">
      <input type="hidden" name="csrf_token" value="$csrf">
      <input type="hidden" name="backup_id" value="$id">
      <button type="submit" class="small secondary">Restore</button>
    </form>
  </td>
</tr>
HTML
    }

    $rows ||= _admin_empty_row(
        3,
        'No backups yet.',
        'Create a backup to capture the database, private source assets, generated public files, and editable themes.'
    );

    my $body = <<"HTML";
<section class="panel">
  <div class="split">
    <div>
      <p class="eyebrow">Backups</p>
      <h1>Backup and Restore</h1>
      <p>Backups include the SQLite database, private source assets, generated public files, and themes.</p>
    </div>
    <form method="post" action="/admin/backups/create">
      <input type="hidden" name="csrf_token" value="$csrf">
      <button type="submit">Create backup</button>
    </form>
  </div>
  $notice
  <table class="content-table compact-table admin-card-table">
    <thead>
      <tr><th>Archive</th><th>Created</th><th></th></tr>
    </thead>
    <tbody>
      $rows
    </tbody>
  </table>
</section>
HTML
    return $self->_html_response('Backups', $body, $session);
}

sub _backup_create {
    my ($self, $request, $session, $session_token) = @_;
    my $path = eval {
        DesertCMS::Backup::create_backup($self->{config}, $self->{db}, $session->{user_id});
    };
    if (!$path) {
        return $self->_backup_list(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The backup could not be created.',
                'Check that the backup directory is writable, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'backup.created',
        subject_type => 'backup',
        details      => { path => $path },
    );
    return $self->_backup_list($request, $session, $session_token, 'Backup created.');
}

sub _backup_restore {
    my ($self, $request, $session, $session_token) = @_;
    my $id = int($request->param('backup_id') || 0);
    my $archive = DesertCMS::Backup::archive_for_id($self->{config}, $self->{db}, $id);
    if (!$archive) {
        return $self->_backup_list($request, $session, $session_token, 'Backup archive was not found.');
    }

    my $ok = eval {
        DesertCMS::Backup::restore_backup($self->{config}, $self->{db}, $archive, $session->{user_id});
    };
    if (!$ok) {
        return $self->_backup_list(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The backup could not be restored.',
                'Confirm the selected archive is present, then try the restore again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'backup.restored',
        subject_type => 'backup',
        subject_id   => $id,
        details      => { archive => $archive },
    );

    return DesertCMS::HTTP->redirect('/admin/backups', { security_headers() });
}

sub _theme_editor {
    my ($self, $request, $session, $session_token, $message) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $files = DesertCMS::Theme::read_files($self->{config});
    my $fields = '';
    my $i = 0;

    for my $file (@{$files}) {
        my $path = escape_html($file->{path});
        my $body = escape_html($file->{body});
        $fields .= <<"HTML";
<section class="theme-file">
  <input type="hidden" name="path_$i" value="$path">
  <label>
    <span>$path</span>
    <textarea name="body_$i" rows="14" spellcheck="false">$body</textarea>
  </label>
</section>
HTML
        $i++;
    }

    my $body = <<"HTML";
<section class="panel">
  <div class="split">
    <div>
      <p class="eyebrow">Theme</p>
      <h1>Default Theme</h1>
      <p>Edits are limited to public templates and CSS. Saving rebuilds all published pages.</p>
    </div>
  </div>
  $notice
  <form method="post" action="/admin/theme/save" class="theme-editor">
    <input type="hidden" name="csrf_token" value="$csrf">
    <input type="hidden" name="file_count" value="$i">
    $fields
    <button type="submit">Save theme and rebuild</button>
  </form>
</section>
HTML

    return $self->_html_response('Theme', $body, $session);
}

sub _theme_save {
    my ($self, $request, $session, $session_token) = @_;
    my $count = int($request->param('file_count') || 0);
    my $ok = eval {
        for my $i (0 .. $count - 1) {
            my $path = $request->param("path_$i");
            my $body = $request->param("body_$i");
            DesertCMS::Theme::save_file($self->{config}, $path, $body);
        }
        $self->{content}->rebuild_all;
        1;
    };

    if (!$ok) {
        return $self->_theme_editor(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The theme file could not be saved.',
                'Check that the file path is editable and the content is valid for that theme file, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'theme.saved',
        subject_type => 'theme',
        details      => { file_count => $count, rebuilt => 1 },
    );
    return $self->_theme_editor($request, $session, $session_token, 'Theme saved and public site rebuilt.');
}

sub _admin_site_brand_preview {
    my ($self, $site) = @_;
    my $name = escape_html($site->{site_name} || 'DesertCMS');
    my $logo = $site->{site_logo_nav_path} || $site->{site_logo_path} || '';
    return $name unless $logo =~ m{\A/assets/site/logo(?:-nav)?\.png\z};
    my $src = escape_html($logo);
    return qq{<img class="preview-site-logo" src="$src" alt="$name">};
}

sub _content_reference_json {
    my ($self, %args) = @_;
    my $exclude_id = int($args{exclude_id} || 0);
    my $rows = $self->{db}->dbh->selectall_arrayref(
        q{
            SELECT id, parent_id, type, title, slug, status, excerpt, feature_image_path, body_json, updated_at
            FROM content_items
            WHERE deleted_at IS NULL
            ORDER BY CASE status WHEN 'published' THEN 0 ELSE 1 END, type ASC, title ASC, id ASC
        },
        { Slice => {} }
    );
    my @items;
    for my $item (@{$rows}) {
        next if $exclude_id && int($item->{id}) == $exclude_id;
        my $type = ($item->{type} || '') eq 'post' ? 'post' : 'page';
        my $status = ($item->{status} || '') eq 'published' ? 'published' : 'draft';
        push @items, {
            id      => int($item->{id}),
            type    => $type,
            status  => $status,
            title   => $item->{title} || 'Untitled',
            url     => DesertCMS::Renderer::public_url_for($self->{db}, $item),
            image   => _admin_content_card_image($item),
            excerpt => _admin_first_content_paragraph($item),
            label   => ($item->{title} || 'Untitled') . ' (' . ucfirst($type) . ', ' . $status . ')',
        };
    }
    return escape_html(encode_json(\@items));
}

sub _admin_content_card_image {
    my ($item) = @_;
    my $feature = $item->{feature_image_path} || '';
    return $feature if DesertCMS::Media::is_public_image_path($feature);

    my $blocks = eval { decode_json($item->{body_json} || '[]') } || [];
    for my $block (@{$blocks}) {
        next unless ref $block eq 'HASH';
        next unless ($block->{type} || '') eq 'image' || ($block->{type} || '') eq 'image_text';
        my $src = $block->{src} || '';
        return $src if DesertCMS::Media::is_public_image_path($src);
    }
    return '';
}

sub _admin_first_content_paragraph {
    my ($item) = @_;
    my $blocks = eval { decode_json($item->{body_json} || '[]') } || [];
    for my $block (@{$blocks}) {
        next unless ref $block eq 'HASH';
        next unless ($block->{type} || '') eq 'text' || ($block->{type} || '') eq 'image_text';
        my $plain = DesertCMS::RichText::plain_text_from_rich_html($block->{html});
        $plain = $block->{text} || '' unless length $plain;
        my $paragraph = _admin_first_paragraph($plain);
        return _admin_short_excerpt($paragraph) if length $paragraph;
    }
    return _admin_short_excerpt($item->{excerpt} || '');
}

sub _admin_first_paragraph {
    my ($text) = @_;
    $text = '' unless defined $text;
    $text =~ s/\r\n?/\n/g;
    for my $paragraph (split /\n\s*\n/, $text) {
        $paragraph =~ s/^\s+|\s+$//g;
        $paragraph =~ s/\s+/ /g;
        return $paragraph if length $paragraph;
    }
    $text =~ s/^\s+|\s+$//g;
    $text =~ s/\s+/ /g;
    return $text;
}

sub _admin_short_excerpt {
    my ($text) = @_;
    $text = '' unless defined $text;
    $text =~ s/^\s+|\s+$//g;
    $text =~ s/\s+/ /g;
    return '' unless length $text;
    return $text if length($text) <= 180;
    $text = substr($text, 0, 177);
    $text =~ s/\s+\S*\z//;
    return $text . '...';
}

sub _admin_location_map_config {
    my ($self, $site, $item) = @_;
    my $has_location = $item && $item->{location_enabled} && defined $item->{location_lat} && defined $item->{location_lng};
    my $lat = $has_location ? 0 + $item->{location_lat} : 0 + ($site->{map_default_lat} || 34.5);
    my $lng = $has_location ? 0 + $item->{location_lng} : 0 + ($site->{map_default_lng} || -112);
    my @pins = $has_location ? ({
        title => $item->{title} || 'Selected location',
        label => $item->{location_label} || $item->{title} || 'Selected location',
        kind => $item->{location_kind} || 'other',
        kind_label => _location_kind_label($item->{location_kind} || 'other'),
        lat   => $lat,
        lng   => $lng,
    }) : ();
    return _json_script({
        picker => 1,
        pins   => \@pins,
        center => { lat => $lat, lng => $lng },
        zoom   => $has_location ? 10 : int($site->{map_default_zoom} || 5),
        default_layer => ($site->{map_default_layer} || 'satellite') eq 'street' ? 'street' : 'satellite',
        layers => _map_layers_for_site($site),
    });
}

sub _map_layers_for_site {
    my ($site) = @_;
    return {
        street => {
            label       => 'Map',
            url         => _clean_tile_url($site->{map_street_tile_url}, 'https://tile.openstreetmap.org/{z}/{x}/{y}.png'),
            attribution => $site->{map_street_attribution} || '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap contributors</a>',
        },
        satellite => {
            label       => 'Satellite',
            url         => _clean_tile_url($site->{map_satellite_tile_url}, 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}'),
            attribution => $site->{map_satellite_attribution} || 'Imagery &copy; Esri and its data providers',
        },
    };
}

sub _json_script {
    my ($data) = @_;
    my $json = encode_json($data);
    $json =~ s{<}{\\u003c}g;
    $json =~ s{>}{\\u003e}g;
    $json =~ s{&}{\\u0026}g;
    $json =~ s{\x{2028}}{\\u2028}g;
    $json =~ s{\x{2029}}{\\u2029}g;
    return $json;
}

sub _site_settings_section {
    my ($request, $fallback) = @_;
    my $section = '';
    if ($request) {
        $section = $request->param('setting_section') || $request->param('section') || '';
    }
    $section = $fallback || 'identity' unless length $section;
    return _clean_choice($section, 'identity', qw(identity search indexing theme));
}

sub _indexing_override_allowed {
    my ($config, $settings) = @_;
    return 1 unless DesertCMS::CapabilityPolicy::contributor_product_mode($config);
    return _setting_truthy($settings->{contributor_allow_indexing_override});
}

sub _site_settings_section_nav {
    my ($active, $include_indexing) = @_;
    $include_indexing = 1 unless defined $include_indexing;
    my @sections = (
        [ identity => '/admin/site-settings?section=identity', 'Identity' ],
        [ search   => '/admin/site-settings?section=search', 'Search &amp; Discovery' ],
        [ theme    => '/admin/site-settings?section=theme', 'Theme &amp; Layout' ],
    );
    splice @sections, 2, 0, [ indexing => '/admin/site-settings?section=indexing', 'Indexing' ]
        if $include_indexing;
    my $html = '<nav class="settings-section-nav" aria-label="Site &amp; SEO sections">';
    for my $section (@sections) {
        my ($key, $href, $label) = @{$section};
        my $class = $key eq ($active || '') ? ' class="active"' : '';
        $html .= qq{<a href="$href"$class>$label</a>};
    }
    $html .= '</nav>';
    return $html;
}

sub _site_settings_page {
    my ($self, $request, $session, $session_token, $message, $active_section) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $is_contributor_product = DesertCMS::CapabilityPolicy::contributor_product_mode($self->{config});
    $message ||= _contributors_notice($request);
    my $indexing_override_allowed = _indexing_override_allowed($self->{config}, $settings);
    my $requested_section = _site_settings_section($request, $active_section);
    if ($requested_section eq 'indexing' && !$indexing_override_allowed) {
        $requested_section = 'search';
        $message ||= 'Search-engine submission settings are inherited from the platform for this plan.';
    }
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $site_name = escape_html($settings->{site_name});
    my $site_description = escape_html($settings->{site_description});
    my $site_meta_title = escape_html($settings->{site_meta_title});
    my $site_meta_description = escape_html($settings->{site_meta_description});
    my $preview_meta_title = escape_html($settings->{site_meta_title} || $settings->{site_name});
    my $preview_meta_description = escape_html($settings->{site_meta_description} || $settings->{site_description} || 'No default description yet.');
    my $site_url = escape_html($self->{config}->get('site_url') || 'http://localhost');
    my $sitemap_url = escape_html(DesertCMS::SEO::sitemap_url($self->{config}));
    my $robots_url = escape_html(DesertCMS::SEO::robots_url($self->{config}));
    my $google_client_id = escape_html($settings->{google_oauth_client_id});
    my $google_property = escape_html($settings->{google_search_console_property} || $self->{config}->get('site_url') || 'http://localhost');
    my $google_connected = DesertCMS::SEO::google_connected($settings);
    my $google_status = $google_connected
        ? '<span class="status-pill ok">Connected</span>'
        : '<span class="status-pill warn">Not connected</span>';
    my $google_connected_detail = $google_connected
        ? 'Connected ' . escape_html(_format_time($settings->{google_oauth_connected_at}))
        : 'Add OAuth credentials, save, then connect a Google account.';
    my $google_secret_placeholder = length($settings->{google_oauth_client_secret} || '')
        ? 'Saved. Leave blank to keep existing secret.'
        : 'Google OAuth client secret';
    my $google_submit_status = _search_status_summary(
        $settings->{google_sitemap_last_status},
        $settings->{google_sitemap_last_submitted_at},
        $settings->{google_sitemap_last_error}
    );
    my $indexnow_checked = $settings->{indexnow_enabled} ? 'checked' : '';
    my $indexnow_key = escape_html($settings->{indexnow_key});
    my $indexnow_status = $settings->{indexnow_enabled}
        ? '<span class="status-pill ok">Enabled</span>'
        : '<span class="status-pill warn">Disabled</span>';
    my $indexnow_submit_status = _search_status_summary(
        $settings->{indexnow_last_status},
        $settings->{indexnow_last_submitted_at},
        $settings->{indexnow_last_error},
        $settings->{indexnow_last_url_count}
    );
    my $google_action_html = $google_connected
        ? '<button type="submit" class="secondary" form="google-disconnect-form">Disconnect Google</button>'
        : '<a class="button-link secondary" href="/admin/site-settings/google/start">Connect Google account</a>';
    my $favicon = escape_html($settings->{favicon_path});
    my $logo = escape_html($settings->{site_logo_path});
    my $logo_nav = escape_html($settings->{site_logo_nav_path} || $settings->{site_logo_path});
    my $logo_admin = escape_html($settings->{site_logo_admin_path} || $settings->{site_logo_nav_path} || $settings->{site_logo_path});
    my $social = escape_html($settings->{social_image_path});
    my $background = escape_html($settings->{site_background_image_path});
    my $homepage_id = int($settings->{homepage_content_id} || 0);
    my $homepage_options = '<option value="">Auto: page with slug home or index</option>';
    for my $page (@{$self->{content}->page_options}) {
        my $id = int($page->{id});
        my $selected = $id == $homepage_id ? 'selected' : '';
        my $url = DesertCMS::Renderer::public_url_for($self->{db}, { %{$page}, type => 'page' });
        my $label = escape_html(($page->{title} || 'Untitled') . ' (' . $url . ', ' . ($page->{status} || 'draft') . ')');
        $homepage_options .= qq{<option value="$id" $selected>$label</option>};
    }
    my $favicon_preview = $favicon ? qq{<img class="settings-thumb settings-thumb--icon" src="$favicon" alt="">} : '<span class="muted">No favicon set</span>';
    my $logo_preview = $logo_nav ? qq{
          <div class="settings-logo-preview-grid">
            <figure>
              <span>Header</span>
              <img class="settings-thumb settings-thumb--logo" src="$logo_nav" alt="">
            </figure>
            <figure>
              <span>@{[$is_contributor_product ? 'App' : 'Admin']}</span>
              <img class="settings-thumb settings-thumb--logo settings-thumb--logo-admin" src="$logo_admin" alt="">
            </figure>
          </div>
        } : '<span class="muted">No logo set. The site name will be used.</span>';
    my $social_preview = $social ? qq{<img class="settings-thumb" src="$social" alt="">} : '<span class="muted">No default social image set</span>';
    my $background_preview = $background ? qq{<img class="settings-thumb settings-thumb--background" src="$background" alt="">} : '<span class="muted">No background image set</span>';
    my $light_theme_choices = $self->_theme_preset_choices($settings, 'light');
    my $dark_theme_choices = $self->_theme_preset_choices($settings, 'dark');
    my $custom_color_fields = $self->_custom_theme_fields($settings);
    my $custom_theme_name = escape_html($settings->{theme_custom_name} || 'Custom Theme');
    my $default_mode = DesertCMS::SiteTheme::default_mode($settings);
    my $default_light_selected = $default_mode eq 'dark' ? '' : 'selected';
    my $default_dark_selected = $default_mode eq 'dark' ? 'selected' : '';
    my $header_layout_options = _select_options($settings->{site_header_layout}, [
        [ split    => 'Split: brand left, nav right' ],
        [ centered => 'Centered brand and nav' ],
        [ stacked  => 'Stacked: brand above nav' ],
        [ compact  => 'Compact header' ],
    ]);
    my $brand_display_options = _select_options($settings->{site_brand_display}, [
