    my $logo_size = _clean_choice($settings->{site_logo_size}, 'medium', qw(small medium large));
    my $logo_fit = _clean_choice($settings->{site_logo_fit}, 'contain', qw(contain cover));
    my $logo_focal_x = _clean_int_range($settings->{site_logo_focal_x}, 0, 100, 50);
    my $logo_focal_y = _clean_int_range($settings->{site_logo_focal_y}, 0, 100, 50);
    my $logo_max_width = _clean_optional_int_range($settings->{site_logo_max_width_px}, 80, 640);
    my $logo_max_height = _clean_optional_int_range($settings->{site_logo_max_height_px}, 24, 180);
