    my $font_options = DesertCMS::FontPackages::font_options($self->{config});
    my $heading_font_options = _font_select_options($settings->{theme_heading_font}, $font_options, 'serif');
    my $body_font_options = _font_select_options($settings->{theme_body_font}, $font_options, 'serif');
    my $ui_font_options = _font_select_options($settings->{theme_ui_font}, $font_options, 'sans');
    my $font_package_panel = $self->_font_package_panel($settings, contributor_product => $is_contributor_product);
    my $heading_scale_options = _select_options($settings->{theme_heading_scale}, [
        [ compact  => 'Compact headings' ],
        [ standard => 'Standard headings' ],
        [ large    => 'Large headings' ],
    ]);
    my $body_scale_options = _select_options($settings->{theme_body_scale}, [
        [ compact  => 'Compact body' ],
        [ standard => 'Standard body' ],
