    ]);
    my $button_style_options = _select_options($settings->{theme_button_style}, [
        [ solid   => 'Solid buttons' ],
        [ outline => 'Outline buttons' ],
        [ soft    => 'Soft buttons' ],
    ]);
    my $button_radius_options = _select_options($settings->{theme_button_radius}, [
