HTML
    my $theme_builder_preview = _theme_builder_preview($settings, $theme_appearance_controls);
    my $section = $requested_section;
    my $editor_nav = _editor_nav($section eq 'theme' ? 'theme' : 'site_settings', $self->{config}, $session);
