    my %section_title = (
        identity => ['Identity', 'Site name, description, homepage, logo, and favicon.'],
        search   => ['Search & Discovery', 'Default SEO title, description, and social sharing image.'],
        indexing => ['Indexing', 'Google Search Console, IndexNow, and sitemap submission.'],
        theme    => [$is_contributor_product ? 'Design' : 'Theme & Layout', 'Colors, visitor mode, header, navigation, spacing, and footer.'],
    );
    my ($section_heading, $section_intro) = @{$section_title{$section}};
