        ? '<span class="status-pill ok">Ready</span>'
        : '<span class="status-pill warn">No logo</span>';
    my $logo_detail = $logo_nav ? 'Header and admin logo derivatives are available.' : 'Upload a logo on the Identity page.';
    $logo_detail = $is_contributor_product
        ? ($logo_nav ? 'Header and app logo derivatives are available.' : 'Upload a logo on the Identity page.')
        : $logo_detail;
    my $indexing_summary = !$indexing_override_allowed
        ? '<span class="status-pill status-pill--neutral">Inherited</span>'
        : (($google_connected || $settings->{indexnow_enabled})
            ? '<span class="status-pill ok">Configured</span>'
            : '<span class="status-pill warn">Needs setup</span>');
    my $indexing_detail = !$indexing_override_allowed
        ? 'Search-engine provider submission is managed by the platform for this plan.'
        : 'Google ' . ($google_connected ? 'connected' : 'not connected')
            . ', IndexNow ' . ($settings->{indexnow_enabled} ? 'enabled' : 'disabled') . '.';
    my @site_summary_items = (
        [ 'Current page', "<strong>$safe_section_heading</strong>", $safe_section_intro ],
        [ 'Canonical site', "<code>$site_url</code>", 'Used for sitemap, robots, and search submissions.' ],
        [ 'Logo', $logo_summary, $logo_detail ],
        [ 'Visitor mode', "<span class=\"status-pill status-pill--neutral\">$theme_mode_summary</span>", 'Default public theme mode.' ],
    );
    splice @site_summary_items, 3, 0, [ 'Indexing', $indexing_summary, $indexing_detail ]
        if $indexing_override_allowed || DesertCMS::CapabilityPolicy::contributor_product_mode($self->{config});
    my $site_summary = _settings_summary_strip(@site_summary_items);
    my $section_content = '';
    my $extra_forms = '';

    if ($section eq 'identity') {
        $section_content = <<"HTML";
      <label>
        <span>Site name</span>
        <input name="site_name" value="$site_name" required>
