      <div class="field-row">
        <label>
          <span>Header logo</span>
          <input type="file" name="site_logo" accept="image/jpeg,image/png,image/webp">
        </label>
        <div class="settings-preview">$logo_preview</div>
      </div>
      <div class="field-row">
        <label>
          <span>Favicon</span>
          <input type="file" name="favicon" accept="image/jpeg,image/png,image/webp">
        </label>
        <div class="settings-preview">$favicon_preview</div>
      </div>
HTML
    } elsif ($section eq 'search') {
        $section_content = <<"HTML";
      <p class="muted">These defaults apply across this site/domain. Individual pages, posts, media assets, and shop listings can override their own search text.</p>
      <div class="health-list health-list--compact search-health">
        <div><dt>Canonical site</dt><dd><code>$site_url</code></dd></div>
        <div><dt>Sitemap</dt><dd><a href="$sitemap_url">$sitemap_url</a></dd></div>
