sub _site_settings_save {
    my ($self, $request, $session, $session_token) = @_;
    my $section = _site_settings_section($request);
    my $current_settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    if ($section eq 'indexing' && !_indexing_override_allowed($self->{config}, $current_settings)) {
        return $self->_site_settings_page(
            $request,
            $session,
            $session_token,
            'Search-engine submission settings are inherited from the platform for this plan.',
            'search'
        );
    }
    my $ok = eval {
        my $settings = $current_settings;
        my %values;

        if ($section eq 'identity') {
            %values = (
                site_name           => $request->param('site_name'),
                site_description    => $request->param('site_description'),
                homepage_content_id => $request->param('homepage_content_id'),
            );
            my $logo = $request->upload('site_logo');
            if ($logo) {
                $values{site_logo_path} = DesertCMS::Settings::store_site_image(
                    $self->{config},
                    kind      => 'site_logo',
                    mime_type => $logo->{content_type},
                    content   => $logo->{content},
                );
                my %logo_paths = DesertCMS::Settings::site_logo_derivative_paths();
                $values{site_logo_nav_path} = $logo_paths{site_logo_nav_path};
                $values{site_logo_admin_path} = $logo_paths{site_logo_admin_path};
            }

            my $favicon = $request->upload('favicon');
            if ($favicon) {
                $values{favicon_path} = DesertCMS::Settings::store_site_image(
                    $self->{config},
                    kind      => 'favicon',
                    mime_type => $favicon->{content_type},
                    content   => $favicon->{content},
                );
            }
        } elsif ($section eq 'search') {
            %values = (
                site_meta_title       => $request->param('site_meta_title'),
                site_meta_description => $request->param('site_meta_description'),
            );
            my $social = $request->upload('social_image');
            if ($social) {
                $values{social_image_path} = DesertCMS::Settings::store_site_image(
                    $self->{config},
                    kind      => 'social_image',
                    mime_type => $social->{content_type},
                    content   => $social->{content},
                );
            }
        } elsif ($section eq 'indexing') {
            my $google_secret = $request->param('google_oauth_client_secret');
            $google_secret = $settings->{google_oauth_client_secret}
                unless defined $google_secret && length $google_secret;
            %values = (
                google_oauth_client_id => $request->param('google_oauth_client_id'),
                google_oauth_client_secret => $google_secret,
                google_search_console_property => $request->param('google_search_console_property'),
                indexnow_enabled      => $request->param('indexnow_enabled') ? 1 : 0,
                indexnow_key          => $request->param('indexnow_key'),
            );
        } else {
            %values = (
                site_header_layout    => _clean_choice($request->param('site_header_layout'), 'split', qw(split centered stacked compact)),
                site_brand_display    => _clean_choice($request->param('site_brand_display'), 'auto', qw(auto logo logo-name name)),
                site_logo_size        => _clean_choice($request->param('site_logo_size'), 'medium', qw(small medium large)),
                site_logo_fit         => _clean_choice($request->param('site_logo_fit'), 'contain', qw(contain cover)),
                site_logo_focal_x     => _clean_int_range($request->param('site_logo_focal_x'), 0, 100, 50),
                site_logo_focal_y     => _clean_int_range($request->param('site_logo_focal_y'), 0, 100, 50),
                site_logo_max_width_px => _clean_optional_int_range($request->param('site_logo_max_width_px'), 80, 640),
                site_logo_max_height_px => _clean_optional_int_range($request->param('site_logo_max_height_px'), 24, 180),
                site_nav_style        => _clean_choice($request->param('site_nav_style'), 'plain', qw(plain underline pills buttons)),
                site_homepage_layout  => _clean_choice($request->param('site_homepage_layout'), 'standard', qw(standard editorial gallery landing)),
                site_content_width    => _clean_choice($request->param('site_content_width'), 'standard', qw(narrow standard wide full)),
                site_spacing_scale    => _clean_choice($request->param('site_spacing_scale'), 'comfortable', qw(compact comfortable spacious)),
                site_footer_layout    => _clean_choice($request->param('site_footer_layout'), 'standard', qw(standard compact minimal hidden)),
                site_footer_order     => _clean_choice($request->param('site_footer_order'), 'brand-nav-credit', qw(brand-nav-credit nav-brand-credit credit-brand-nav)),
                site_footer_nav_enabled => $request->param('site_footer_nav_enabled') ? 1 : 0,
                site_footer_description_enabled => $request->param('site_footer_description_enabled') ? 1 : 0,
                site_footer_credit    => _clean_template_text($request->param('site_footer_credit'), 160),
                theme_heading_font    => DesertCMS::FontPackages::clean_font_id($request->param('theme_heading_font'), 'serif'),
                theme_body_font       => DesertCMS::FontPackages::clean_font_id($request->param('theme_body_font'), 'serif'),
                theme_ui_font         => DesertCMS::FontPackages::clean_font_id($request->param('theme_ui_font'), 'sans'),
                theme_heading_scale   => _clean_choice($request->param('theme_heading_scale'), 'standard', qw(compact standard large)),
                theme_body_scale      => _clean_choice($request->param('theme_body_scale'), 'standard', qw(compact standard large)),
                theme_button_style    => _clean_choice($request->param('theme_button_style'), 'solid', qw(solid outline soft)),
                theme_button_radius   => _clean_choice($request->param('theme_button_radius'), 'soft', qw(square soft pill)),
                theme_card_style      => _clean_choice($request->param('theme_card_style'), 'outlined', qw(flat outlined raised)),
                theme_card_radius     => _clean_choice($request->param('theme_card_radius'), 'soft', qw(square soft round)),
                font_package_repo     => DesertCMS::FontPackages::clean_repo($request->param('font_package_repo')),
                theme_unsplash_enabled => $request->param('theme_unsplash_enabled') ? 1 : 0,
                unsplash_access_key   => _clean_template_text($request->param('unsplash_access_key'), 200),
                theme_background_effect => _clean_choice($request->param('theme_background_effect'), 'none', qw(none wash grain vignette)),
                theme_motion_effect   => _clean_choice($request->param('theme_motion_effect'), 'none', qw(none subtle lift)),
                theme_lighting_effect => _clean_choice($request->param('theme_lighting_effect'), 'none', qw(none soft glow)),
                theme_box_transparency => _clean_int_range($request->param('theme_box_transparency'), 0, 80, 0),
                theme_outline_transparency => _clean_int_range($request->param('theme_outline_transparency'), 0, 80, 0),
                theme_box_shape       => _clean_choice($request->param('theme_box_shape'), 'soft', qw(square soft round pill)),
                theme_gradient_style  => _clean_choice($request->param('theme_gradient_style'), 'none', qw(none accent split sheen)),
                theme_light_preset    => $self->_clean_theme_preset($request->param('theme_light_preset'), 'light'),
                theme_dark_preset     => $self->_clean_theme_preset($request->param('theme_dark_preset'), 'dark'),
                theme_default_mode    => ($request->param('theme_default_mode') || '') eq 'dark' ? 'dark' : 'light',
                theme_custom_name     => _clean_template_text($request->param('theme_custom_name'), 80) || 'Custom Theme',
                theme_custom_mode     => ($request->param('theme_default_mode') || '') eq 'dark' ? 'dark' : 'light',
            );
            $values{theme_preset} = $values{theme_default_mode} eq 'dark'
                ? $values{theme_dark_preset}
                : $values{theme_light_preset};
            _apply_theme_preset_recommended_fonts(\%values, $settings);

            my $defaults = DesertCMS::SiteTheme::custom_settings_defaults();
            for my $name (qw(ink muted paper panel field line accent accent_dark support button_ink)) {
                my $key = "theme_custom_$name";
                $values{$key} = $self->_clean_theme_color($request->param($key), $defaults->{$key});
            }

            my $background = $request->upload('site_background');
            if ($background) {
                $values{site_background_image_path} = DesertCMS::Settings::store_site_image(
                    $self->{config},
                    kind      => 'site_background',
                    mime_type => $background->{content_type},
                    content   => $background->{content},
                );
            }
        }

        DesertCMS::Settings::set_many($self->{config}, $self->{db}, \%values);
        $self->{content}->rebuild_all;
        1;
    };

    if (!$ok) {
        return $self->_site_settings_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The site settings could not be saved.',
                'Check the current section for invalid values or oversized uploads, then try again.',
                $@
            ),
            $section
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'settings.site_saved',
        subject_type => 'settings',
        details      => { rebuilt => 1 },
    );
    return $self->_site_settings_page($request, $session, $session_token, 'Site settings saved and public site rebuilt.', $section);
}

sub _site_settings_google_start {
    my ($self, $request, $session, $session_token) = @_;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    return $self->_forbidden
        unless _indexing_override_allowed($self->{config}, $settings);
    my $url = eval {
        DesertCMS::SEO::google_auth_url(
            $self->{config},
            $settings,
            state => $self->{auth}->csrf_token($session_token),
        );
    };
    if (!$url) {
        return $self->_site_settings_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'Google Search Console sign-in could not start.',
                'Check the client ID, client secret, redirect URI, and site URL, then try again.',
                $@
            ),
            'indexing'
        );
    }
    return DesertCMS::HTTP->redirect($url, { security_headers() });
}

sub _site_settings_google_callback {
    my ($self, $request, $session, $session_token) = @_;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    return $self->_forbidden
        unless _indexing_override_allowed($self->{config}, $settings);
    my $state = $request->param('state') || '';
    if (!$self->{auth}->verify_csrf($session_token, $state)) {
        return $self->_site_settings_page($request, $session, $session_token, 'Google sign-in was rejected because the security state did not match. Start the connection again from Indexing.', 'indexing');
    }
    my $error = $request->param('error') || '';
    if (length $error) {
        return $self->_site_settings_page($request, $session, $session_token, 'Google connection canceled: ' . $error, 'indexing');
    }
    my $ok = eval {
        DesertCMS::SEO::exchange_google_code(
            $self->{config},
            $self->{db},
            code => $request->param('code'),
        );
        1;
    };
    if (!$ok) {
        return $self->_site_settings_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'Google Search Console could not be connected.',
                'Start the sign-in again and confirm this site is allowed to submit its sitemap.',
                $@
            ),
            'indexing'
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'provider.google_search_console_connected',
        subject_type => 'provider',
        details      => { provider => 'google_search_console' },
    );
    return $self->_site_settings_page($request, $session, $session_token, 'Google account connected for Search Console sitemap submission.', 'indexing');
}

sub _site_settings_google_disconnect {
    my ($self, $request, $session, $session_token) = @_;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    return $self->_forbidden
        unless _indexing_override_allowed($self->{config}, $settings);
    my $ok = eval {
        DesertCMS::SEO::disconnect_google($self->{config}, $self->{db});
        1;
    };
    return $self->_site_settings_page(
        $request,
        $session,
        $session_token,
        _admin_action_error(
            'Google Search Console could not be disconnected.',
            'Refresh the page and try disconnecting again.',
            $@
        ),
        'indexing'
    )
        unless $ok;
    $self->_audit_admin_action(
        $session,
        action       => 'provider.google_search_console_disconnected',
        subject_type => 'provider',
        details      => { provider => 'google_search_console' },
    );
    return $self->_site_settings_page($request, $session, $session_token, 'Google account disconnected.', 'indexing');
}

sub _site_settings_submit_search_engines {
    my ($self, $request, $session, $session_token) = @_;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    return $self->_forbidden
        unless _indexing_override_allowed($self->{config}, $settings);
    my @messages;
    my $ok = eval {
        $self->{content}->rebuild_all;
        push @messages, 'Public sitemap rebuilt.';
        $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
        if (DesertCMS::SEO::google_connected($settings)) {
            my $google = DesertCMS::SEO::submit_google_sitemap($self->{config}, $self->{db});
            push @messages, "$google->{engine} accepted sitemap submission.";
        } else {
            push @messages, 'Google skipped because no account is connected.';
        }
        if ($settings->{indexnow_enabled}) {
            my $indexnow = DesertCMS::SEO::submit_indexnow($self->{config}, $self->{db});
            push @messages, "$indexnow->{engine} accepted $indexnow->{urls} URL(s).";
        } else {
            push @messages, 'IndexNow skipped because it is disabled.';
        }
        1;
    };
    if (!$ok) {
        return $self->_site_settings_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'Search-engine submission did not complete.',
                'Check Google Search Console and IndexNow settings, then submit the sitemaps again.',
                $@
            ),
            'indexing'
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'provider.search_engines_submitted',
        subject_type => 'provider',
        details      => { messages => \@messages },
    );
    return $self->_site_settings_page($request, $session, $session_token, join(' ', @messages), 'indexing');
}

sub _site_settings_fonts_refresh {
    my ($self, $request, $session, $session_token) = @_;
    my $repo = DesertCMS::FontPackages::clean_repo($request->param('font_package_repo'));
    my $catalog;
    my $ok = eval {
        DesertCMS::Settings::set_many($self->{config}, $self->{db}, {
            font_package_repo => $repo,
        });
        $catalog = DesertCMS::FontPackages::refresh_catalog($self->{config}, package_repo => $repo);
        1;
    };
    if (!$ok) {
        return $self->_site_settings_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The OpenBSD font catalog could not be refreshed.',
                'Check the package repository URL and that the font helper is installed, then refresh again.',
                $@
            ),
            'theme'
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'theme.font_catalog_refreshed',
        subject_type => 'settings',
        details      => {
            status       => $catalog->{status} || '',
            package_repo => $repo,
            packages     => scalar @{ $catalog->{packages} || [] },
        },
    );
    my $message = ($catalog->{status} || '') eq 'ok'
        ? 'OpenBSD font package catalog refreshed.'
        : _admin_action_error(
            'The OpenBSD font catalog could not be refreshed.',
            'Check the package repository URL and root worker setup, then refresh again.',
            $catalog->{error} || 'pkg_info could not read packages.'
        );
    return $self->_site_settings_page($request, $session, $session_token, $message, 'theme');
}

sub _site_settings_fonts_install {
    my ($self, $request, $session, $session_token) = @_;
    my $repo = DesertCMS::FontPackages::clean_repo($request->param('font_package_repo'));
    my $package = DesertCMS::FontPackages::clean_package($request->param('font_package'));
    if (!length $package) {
        return $self->_site_settings_page($request, $session, $session_token, 'Choose a valid OpenBSD font package to install.', 'theme');
    }

    my $job;
    my $ok = eval {
        DesertCMS::Settings::set_many($self->{config}, $self->{db}, {
            font_package_repo => $repo,
        });
        $job = DesertCMS::FontPackages::queue_install(
            $self->{config},
            package => $package,
            package_repo => $repo,
            submitted_by_user_id => $session->{user_id},
            submitted_by_username => $session->{username},
        );
        1;
    };
    if (!$ok) {
        return $self->_site_settings_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The font package install could not be queued.',
                'Choose a package from the refreshed catalog and confirm the root worker is installed, then try again.',
                $@
            ),
            'theme'
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'theme.font_package_install_queued',
        subject_type => 'settings',
        subject_id   => $package,
        details      => {
            job_id       => $job->{id},
            package      => $package,
            package_repo => $repo,
        },
    );
    return $self->_site_settings_page($request, $session, $session_token, "Queued OpenBSD font package install for $package.", 'theme');
}

sub _settings_nav {
    my ($self, $active, $session) = @_;
    my $role = $session ? $session->{role} : 'owner';
    if (DesertCMS::CapabilityPolicy::contributor_product_mode($self->{config})) {
        my @contributor_links = (
            [ dashboard => '/admin/settings/dashboard', 'Dashboard', 'view_home' ],
            [ account => '/admin/settings/account', 'Account', 'manage_account' ],
            [ help    => '/admin/help',             'Help',    'view_home' ],
        );
        my $html = '<nav class="editor-nav" aria-label="Account sections">';
        for my $link (@contributor_links) {
            my ($key, $href, $label, $capability) = @{$link};
            next if $capability
                && !DesertCMS::CapabilityPolicy::has($self->{config}, $role, $capability);
            my $class = $key eq ($active || '') ? ' class="active"' : '';
            $html .= qq{<a href="$href"$class>$label</a>};
        }
        $html .= '</nav>';
        return $html;
    }
    my %active_group = (
        governance => 'account',
        federation => 'account',
        blueprints => 'contributors',
        plans      => 'contributors',
        sites      => 'contributors',
    );
    my $nav_active = $active_group{$active || ''} || ($active || '');
    my $contributor_href = '';
    for my $candidate (
        [ review_contributors           => '/admin/settings/contributors' ],
        [ view_blueprints               => '/admin/settings/blueprints' ],
        [ view_service_plans            => '/admin/settings/plans' ],
        [ manage_contributor_lifecycle  => '/admin/settings/sites' ],
    ) {
        my ($capability, $href) = @{$candidate};
        if (DesertCMS::CapabilityPolicy::has($self->{config}, $role, $capability)) {
            $contributor_href = $href;
            last;
        }
    }
    my @links = (
        [ overview     => '/admin/settings',                'Overview',           'view_settings' ],
        [ dashboard    => '/admin/settings/dashboard',      'Dashboard',          'view_home' ],
        [ control      => '/admin/settings/master-control', 'Master Control',     'view_master_control' ],
        [ payments     => '/admin/settings/payments',       'Payments',           'view_master_control' ],
        [ account      => '/admin/settings/account',        'Admin Account',      'manage_account' ],
    );
    push @links, [ contributors => $contributor_href, 'Contributor', '' ] if length $contributor_href;
    push @links, (
        [ security    => '/admin/settings/security',      'Security',           'view_security_center' ],
        [ realtime    => '/admin/settings/realtime',      'Realtime',           'view_realtime' ],
        [ upgrade      => '/admin/settings/upgrade',        'Upgrade',            'run_upgrades' ],
        [ operations   => '/admin/settings/operations',     'Operations',         'view_operations' ],
    );
    my $html = '<nav class="editor-nav" aria-label="Settings sections">';
    for my $link (@links) {
        my ($key, $href, $label, $capability) = @{$link};
        next if $capability
            && !DesertCMS::CapabilityPolicy::has($self->{config}, $role, $capability);
        my $class = $key eq $nav_active ? ' class="active"' : '';
        $html .= qq{<a href="$href"$class>$label</a>};
    }
    $html .= '</nav>';
    return $html;
}

sub _settings_subnav {
    my ($self, $active, $session, $label, @links) = @_;
    my $role = $session ? $session->{role} : 'owner';
    my $safe_label = escape_html($label || 'Settings subsections');
    my $html = qq{<nav class="settings-section-nav settings-section-nav--sub" aria-label="$safe_label">};
    for my $link (@links) {
        my ($key, $href, $text, $capability) = @{$link};
        next if $capability
            && !DesertCMS::CapabilityPolicy::has($self->{config}, $role, $capability);
        my $class = $key eq ($active || '') ? ' class="active"' : '';
        my $safe_text = escape_html($text || '');
        $html .= qq{<a href="$href"$class>$safe_text</a>};
    }
    $html .= '</nav>';
    return $html;
}

sub _module_section_nav {
    my ($label, @links) = @_;
    return '' unless @links > 1;
    my $safe_label = escape_html($label || 'Feature setup sections');
    my $html = qq{<nav class="settings-section-nav settings-section-nav--sub module-section-nav" aria-label="$safe_label">};
    for my $link (@links) {
        my ($href, $text) = @{$link};
        next unless defined $href && length $href;
        my $safe_href = escape_html($href);
        my $safe_text = escape_html($text || '');
        $html .= qq{<a href="$safe_href">$safe_text</a>};
    }
    $html .= '</nav>';
    return $html;
}

sub _admin_account_nav {
    my ($self, $active, $session) = @_;
    return $self->_settings_subnav(
        $active,
        $session,
        'Admin account sections',
        [ account    => '/admin/settings/account',    'Login',            'manage_account' ],
        [ governance => '/admin/settings/governance', 'Governance',       'view_governance' ],
        [ federation => '/admin/settings/federation', 'Federated Review', 'view_federated' ],
    );
}

sub _contributor_settings_nav {
    my ($self, $active, $session) = @_;
    return $self->_settings_subnav(
        $active,
        $session,
        'Contributor sections',
        [ contributors => '/admin/settings/contributors', 'Requests & Email',  'review_contributors' ],
        [ blueprints   => '/admin/settings/blueprints',   'Blueprints',        'view_blueprints' ],
        [ plans        => '/admin/settings/plans',        'Service Plans',     'view_service_plans' ],
        [ sites        => '/admin/settings/sites',        'Contributor Sites', 'manage_contributor_lifecycle' ],
    );
}

sub _help_page {
    my ($self, $request, $session, $session_token) = @_;
    my $is_contributor_product = DesertCMS::CapabilityPolicy::contributor_product_mode($self->{config});
    return $self->_contributor_help_page($request, $session, $session_token)
        if $is_contributor_product;
    my $settings_nav = $is_contributor_product ? $self->_settings_nav('help', $session) : '';
    my $eyebrow = 'Support';
    my $heading = 'DesertCMS Help';
    my $intro = 'Use the documentation and operational screens for setup, recovery, and support work.';
    my $cards = _capability_link_cards(
        $self->{config},
        $session,
        { href => '/admin/editor',            eyebrow => 'Build',    title => 'Site Builder', body => 'Edit pages, posts, menus, layouts, redirects, and media.',       detail => 'Content tools', capability => 'view_content' },
        { href => '/admin/settings/modules',  eyebrow => 'Features', title => 'Feature Catalog', body => 'Review enabled, available, locked, and master-managed features.', detail => 'Plan-gated features', capability => 'view_features' },
        { href => '/admin/billing',           eyebrow => 'Billing',  title => 'Plan and Usage', body => 'Review your plan, quotas, usage, upgrades, email, and payments.', detail => 'Hosted account', capability => 'view_usage' },
        { href => '/admin/settings/account',  eyebrow => 'Account',  title => 'Login Settings', body => 'Update your username, account email, or password.',              detail => 'Personal access', capability => 'manage_account' },
    );
    my $docs_link = '<a class="button-link secondary" href="/docs/">Open documentation</a>';

    my $body = <<"HTML";
<section class="editor-workspace">
  $settings_nav
  <section class="panel">
    <div class="split">
      <div>
        <p class="eyebrow">$eyebrow</p>
        <h1>$heading</h1>
        <p>$intro</p>
      </div>
      <div class="actions">
        $docs_link
      </div>
    </div>
    <div class="workflow-grid">
      $cards
    </div>
  </section>
</section>
HTML

    return $self->_html_response('Help', $body, $session);
}

sub _contributor_help_page {
    my ($self, $request, $session, $session_token) = @_;
    my $settings_nav = $self->_settings_nav('help', $session);
    my $surface = $self->_contributor_account_help_surface($session, full => 1);
    my $body = <<"HTML";
<section class="editor-workspace">
  $settings_nav
  <section class="panel">
    <div class="split">
      <div>
        <p class="eyebrow">Help</p>
        <h1>Account and Help</h1>
        <p>Plan details, support contacts, documentation, billing help, and platform status for this hosted site.</p>
      </div>
      <div class="actions">
        <a class="button-link secondary" href="/docs/">Open docs</a>
        <a class="button-link" href="/admin/billing">Billing help</a>
      </div>
    </div>
    $surface
  </section>
</section>
HTML
    return $self->_html_response('Help', $body, $session);
}

sub _contributor_account_help_surface {
    my ($self, $session, %options) = @_;
    my $context = $self->_contributor_support_context($session);
    my $surface_class = $options{full}
        ? 'contributor-help-surface contributor-help-surface--full'
        : 'contributor-help-surface contributor-help-surface--compact';
    my $summary = _settings_summary_strip(
        [ 'Current Plan', '<strong>' . escape_html($context->{plan_name}) . '</strong>', $context->{plan_detail} ],
        [ 'Billing', $context->{billing_status_html}, $context->{billing_detail} ],
        [ 'Support Contact', $context->{support_html}, $context->{support_detail} ],
        [ 'Platform Status', $context->{platform_status_html}, $context->{platform_detail} ],
    );
    my $usage = $context->{usage_html};
    my $docs_cards = _contributor_help_cards($context);
    my $platform_rows = _contributor_platform_rows($context);
    my $billing_help = _contributor_billing_help($context);
    my $full_sections = $options{full} ? <<"HTML" : '';
    <section class="inspector-panel">
      <h2>Plan and Usage</h2>
      $usage
    </section>
    <section class="inspector-panel">
      <h2>Billing Help</h2>
      $billing_help
    </section>
    <section class="inspector-panel">
      <h2>Platform Status</h2>
      <dl class="health-list health-list--compact fleet-provider-list">
        $platform_rows
      </dl>
    </section>
HTML
    return <<"HTML";
    <div class="$surface_class">
      $summary
      <section class="workflow-grid">
        $docs_cards
      </section>
      $full_sections
    </div>
HTML
}

sub _contributor_support_context {
    my ($self, $session) = @_;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $billing_context = eval { $self->_contributor_billing_context };
    my $billing_error = $billing_context ? '' : _clean_error($@ || 'Billing context is unavailable.');
    my $site = $billing_context ? ($billing_context->{site} || {}) : {};
    my $usage = $billing_context ? ($billing_context->{usage} || {}) : {};
    my $master_settings = $billing_context ? ($billing_context->{master_settings} || {}) : {};
    my $support_email = _support_contact_email($master_settings, $settings, $session);
    my $support_html = length($support_email)
        ? '<a href="mailto:' . escape_html($support_email) . '">' . escape_html($support_email) . '</a>'
        : '<span class="status-pill status-pill--neutral">Not configured</span>';
    my $support_detail = length($support_email)
        ? 'Use this for account, billing, and platform support.'
        : 'Ask platform support to configure a support email.';
    my $plan_name = $site->{service_plan_name} || ($billing_context ? 'Free Tier' : 'Plan unavailable');
    my $price = int($site->{monthly_price_cents} || 0) > 0
        ? _format_money($site->{monthly_price_cents}, $site->{currency}) . ' per month'
        : 'No monthly charge';
    my $plan_detail = $billing_context ? $price : $billing_error;
    my $billing_status = $billing_context ? ($site->{billing_status} || 'comped') : 'unlinked';
    my $billing_status_html = $billing_context
        ? _billing_status_pill($billing_status)
        : '<span class="status-pill warn">Unavailable</span>';
    my $billing_detail = $billing_context
        ? (($site->{billing_email} || $site->{owner_email}) ? 'Billing email: ' . ($site->{billing_email} || $site->{owner_email}) : 'Billing email not set.')
        : $billing_error;
    my $site_status = $billing_context ? ($site->{status} || 'active') : 'unlinked';
    my $platform_status_html = $billing_context
        ? '<span class="status-pill ok">' . escape_html(_title_case_status($site_status)) . '</span>'
        : '<span class="status-pill warn">Unlinked</span>';
    my $platform_detail = $billing_context
        ? 'Provisioning, maintenance, indexing defaults, and upgrades are handled by the platform.'
        : 'Connect this hosted site to the platform to show live status.';
    my $usage_html = $usage->{available}
        ? '<div class="billing-usage-grid">'
            . _usage_meter(_format_bytes($usage->{media_bytes}) . ' of ' . int($usage->{media_quota_mb} || 0) . ' MB media', $usage->{media_percent})
            . _usage_meter(int($usage->{post_count} || 0) . ' of ' . int($usage->{post_quota} || 0) . ' posts', $usage->{post_percent})
            . _usage_meter(int($usage->{page_count} || 0) . ' of ' . int($usage->{page_quota} || 0) . ' pages', $usage->{page_percent})
            . '</div>'
        : '<p class="muted">' . escape_html($usage->{reason} || $billing_error || 'Usage is unavailable right now.') . '</p>';
    return {
        billing_context => $billing_context,
        billing_error => $billing_error,
        site => $site,
        settings => $settings,
        master_settings => $master_settings,
        support_email => $support_email,
        support_html => $support_html,
        support_detail => $support_detail,
        plan_name => $plan_name,
        plan_detail => $plan_detail,
        billing_status_html => $billing_status_html,
        billing_detail => $billing_detail,
        platform_status_html => $platform_status_html,
        platform_detail => $platform_detail,
        usage_html => $usage_html,
    };
}

sub _support_contact_email {
    my ($master_settings, $settings, $session) = @_;
    for my $source ($master_settings || {}, $settings || {}) {
        for my $key (qw(contributor_request_recipient_email postmark_from_email)) {
            my $email = _clean_email($source->{$key});
            return $email if length $email;
        }
    }
    return _clean_email($session ? $session->{email} : '');
}

sub _contributor_help_cards {
    my ($context) = @_;
    my $support_href = length($context->{support_email}) ? 'mailto:' . escape_html($context->{support_email}) : '/admin/help';
    my @cards = (
        { href => '/docs/site-owner-guide/', eyebrow => 'Docs', title => 'Site Owner Guide', body => 'Day-to-day help for pages, posts, media, design, features, and publishing.', detail => 'Open docs' },
        { href => '/docs/content-design-and-media/', eyebrow => 'Docs', title => 'Content and Design Help', body => 'Editing, theme, layout, navigation, media, and Resource Download guidance.', detail => 'Design reference' },
        { href => '/admin/billing', eyebrow => 'Billing', title => 'Plan and Billing', body => 'Compare plans, review usage, manage subscriptions, and connect paid provider options.', detail => $context->{plan_name} },
        { href => $support_href, eyebrow => 'Support', title => 'Contact Support', body => 'Get help with account access, billing, email sending, payments, or platform-managed services.', detail => length($context->{support_email}) ? $context->{support_email} : 'Support email not configured' },
    );
    return join '', map {
        my $href = escape_html($_->{href});
        my $eyebrow = escape_html($_->{eyebrow});
        my $title = escape_html($_->{title});
        my $body = escape_html($_->{body});
        my $detail = escape_html($_->{detail});
        <<"HTML";
    <a class="workflow-card" href="$href">
      <span>$eyebrow</span>
      <strong>$title</strong>
      <p>$body</p>
      <small>$detail</small>
    </a>
HTML
    } @cards;
}

sub _contributor_billing_help {
    my ($context) = @_;
    my $site = $context->{site} || {};
    my $period = $site->{billing_current_period_end}
        ? escape_html(_format_time($site->{billing_current_period_end}))
        : 'Not set';
    my $current = escape_html($context->{plan_name});
    my $billing_detail = escape_html($context->{billing_detail});
    return <<"HTML";
      <dl class="health-list health-list--compact">
        <div><dt>Current plan</dt><dd><strong>$current</strong><small>@{[escape_html($context->{plan_detail})]}</small></dd></div>
        <div><dt>Billing status</dt><dd>$context->{billing_status_html}<small>$billing_detail</small></dd></div>
        <div><dt>Current period</dt><dd><span class="status-pill status-pill--neutral">$period</span><small>Stripe webhooks update this after plan changes.</small></dd></div>
      </dl>
      <div class="actions">
        <a class="button-link" href="/admin/billing">Open Billing</a>
        <a class="button-link secondary" href="/docs/billing-and-provider-options/">Billing and provider docs</a>
      </div>
HTML
}

sub _contributor_platform_rows {
    my ($context) = @_;
    my $site = $context->{site} || {};
    my $settings = $context->{settings} || {};
    my $site_status = escape_html(_title_case_status($site->{status} || ($context->{billing_context} ? 'active' : 'unlinked')));
    my $postmark = ($settings->{postmark_sender_mode} || '') eq 'site' ? 'Custom sender' : 'Platform sender';
    my $stripe = _setting_truthy($settings->{contributor_allow_stripe_connect}) ? 'Plan can connect payouts' : 'Platform billing only';
    my $indexing = _setting_truthy($settings->{contributor_allow_indexing_override}) ? 'Custom indexing allowed' : 'Platform-managed';
    return <<"HTML";
        <div><dt>Site status</dt><dd>$context->{platform_status_html}<small>$site_status</small></dd></div>
        <div><dt>Postmark</dt><dd><span class="status-pill status-pill--neutral">@{[escape_html($postmark)]}</span><small>Email delivery follows the current plan.</small></dd></div>
        <div><dt>Stripe</dt><dd><span class="status-pill status-pill--neutral">@{[escape_html($stripe)]}</span><small>Service billing stays on the platform account.</small></dd></div>
        <div><dt>Indexing</dt><dd><span class="status-pill status-pill--neutral">@{[escape_html($indexing)]}</span><small>Search submission providers are plan-gated.</small></dd></div>
        <div><dt>Maintenance</dt><dd><span class="status-pill status-pill--neutral">Platform-managed</span><small>Backups, provisioning, upgrades, and maintenance are handled by platform support.</small></dd></div>
HTML
}

sub _has_capability {
    my ($config, $session, $capability) = @_;
    my $role = $session ? $session->{role} : 'owner';
    return DesertCMS::CapabilityPolicy::has($config, $role, $capability);
}

sub _capability_link_cards {
    my ($config, $session, @cards) = @_;
    my $html = '';
    for my $card (@cards) {
        my $capability = $card->{capability} || '';
        next if length $capability && !_has_capability($config, $session, $capability);
        my $href = escape_html($card->{href} || '#');
        my $eyebrow = escape_html($card->{eyebrow} || '');
        my $title = escape_html($card->{title} || '');
        my $body = escape_html($card->{body} || '');
        my $detail = escape_html($card->{detail} || '');
        $html .= <<"HTML";
    <a class="workflow-card" href="$href">
      <span>$eyebrow</span>
      <strong>$title</strong>
      <p>$body</p>
      <small>$detail</small>
    </a>
HTML
    }
    return $html || '<p class="muted">No actions are available for this role.</p>';
}

sub _settings_summary_strip {
    my (@items) = @_;
    my $html = '<dl class="settings-summary-strip">';
    for my $item (@items) {
        my ($label, $value, $detail) = @{$item};
        my $safe_label = escape_html($label || '');
        $value = '' unless defined $value;
        $detail = '' unless defined $detail;
        my $safe_detail = escape_html($detail);
        my $detail_html = length $safe_detail ? "<small>$safe_detail</small>" : '';
        $html .= <<"HTML";
<div>
  <dt>$safe_label</dt>
  <dd>$value$detail_html</dd>
</div>
HTML
    }
    $html .= '</dl>';
    return $html;
}

sub _settings_dashboard_page {
    my ($self, $request, $session, $session_token, $message) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $settings_nav = $self->_settings_nav('dashboard', $session);
    my $widgets = $self->{dashboard}->widgets_for_user(
        user_id => $session ? $session->{user_id} : 0,
        role    => $session ? ($session->{role} || 'owner') : 'owner',
    );
    my $rows = '';
    for my $widget (@{$widgets}) {
        my $key = $widget->{key} || next;
        my $safe_key = escape_html($key);
        my $label = escape_html($widget->{label} || $key);
        my $capability = $widget->{capability} || '';
        my $allowed = length($capability) ? _has_capability($self->{config}, $session, $capability) : 1;
        my $checked = $widget->{enabled} && $allowed ? 'checked' : '';
        my $disabled = $allowed ? '' : 'disabled';
        my $capability_label = length($capability) ? '<code>' . escape_html($capability) . '</code>' : '<span class="muted">No capability gate</span>';
        my $position = int($widget->{position} || 100);
        my $size_options = _dashboard_size_options($widget->{size});
        my $state = $allowed ? '<span class="status-pill ok">Available</span>' : '<span class="status-pill warn">Not allowed</span>';
        $rows .= <<"HTML";
<article class="dashboard-widget-option">
  <label class="checkbox-field">
    <input type="checkbox" name="widget_${safe_key}_enabled" value="1" $checked $disabled>
    <span><strong>$label</strong><small>$capability_label</small></span>
  </label>
  <div class="field-row">
    <label><span>Size</span><select name="widget_${safe_key}_size" $disabled>$size_options</select></label>
    <label><span>Position</span><input name="widget_${safe_key}_position" value="$position" inputmode="numeric" $disabled></label>
  </div>
  $state
</article>
HTML
    }
    $rows ||= _admin_empty_panel('No dashboard widgets registered.', 'Module manifests provide dashboard widgets as v3 modules are enabled.');
    my $body = <<"HTML";
<section class="editor-workspace">
  $settings_nav
  <section class="panel">
    <div class="split">
      <div>
        <p class="eyebrow">Dashboard</p>
        <h1>Dashboard Widgets</h1>
        <p>Choose the quick-peek widgets that appear above analytics on the admin dashboard. Widget availability follows role capabilities and enabled modules.</p>
      </div>
      <a class="button-link secondary" href="/admin">Open dashboard</a>
    </div>
    $notice
    <form method="post" action="/admin/settings/dashboard" class="settings-form settings-form--wide">
      <input type="hidden" name="csrf_token" value="$csrf">
      <section class="dashboard-widget-option-grid">
        $rows
      </section>
      <button type="submit">Save dashboard widgets</button>
    </form>
  </section>
</section>
HTML
    return $self->_html_response('Dashboard Settings', $body, $session);
}

sub _settings_dashboard_save {
    my ($self, $request, $session, $session_token) = @_;
    my (%enabled, %sizes, %positions);
    for my $widget (@{ $self->{dashboard}->widget_catalog }) {
        my $key = $widget->{key} || next;
        next if ($widget->{capability} || '') && !_has_capability($self->{config}, $session, $widget->{capability});
        $enabled{$key} = $request->param("widget_${key}_enabled") ? 1 : 0;
        $sizes{$key} = _dashboard_widget_size_class($request->param("widget_${key}_size") || $widget->{size});
        $positions{$key} = int($request->param("widget_${key}_position") || 100);
    }
    $self->{dashboard}->save_widgets(
        user_id => $session ? $session->{user_id} : 0,
        role    => $session ? ($session->{role} || 'owner') : 'owner',
        values  => {
            enabled   => \%enabled,
            sizes     => \%sizes,
            positions => \%positions,
        },
    );
    $self->_audit_admin_action(
        $session,
        action       => 'settings.dashboard_saved',
        subject_type => 'settings',
        details      => { widgets => [ sort keys %enabled ] },
    );
    return $self->_settings_dashboard_page($request, $session, $session_token, 'Dashboard widgets saved.');
}

sub _dashboard_size_options {
    my ($selected) = @_;
    $selected = _dashboard_widget_size_class($selected);
    my @options = (
        [ small  => 'Small' ],
        [ medium => 'Medium' ],
        [ large  => 'Large' ],
        [ wide   => 'Wide' ],
    );
    return join '', map {
        my ($value, $label) = @{$_};
        my $is_selected = $value eq $selected ? ' selected' : '';
        '<option value="' . $value . '"' . $is_selected . '>' . $label . '</option>';
    } @options;
}

sub _manifest_value_list {
    my ($values, $empty) = @_;
    return '<p class="muted">' . escape_html($empty || 'Nothing registered.') . '</p>'
        unless $values && ref($values) eq 'ARRAY' && @{$values};
    my $html = '<ul class="v3-manifest-list">';
    for my $value (@{$values}) {
        $html .= '<li><code>' . escape_html(_manifest_scalar($value)) . '</code></li>';
    }
    $html .= '</ul>';
    return $html;
}

sub _manifest_object_list {
    my ($items, $fields, $empty) = @_;
    return '<p class="muted">' . escape_html($empty || 'Nothing registered.') . '</p>'
        unless $items && ref($items) eq 'ARRAY' && @{$items};
    my $html = '<div class="v3-manifest-list v3-manifest-list--objects">';
    for my $item (@{$items}) {
        next unless ref($item) eq 'HASH';
        my $title = escape_html($item->{label} || $item->{key} || $item->{path} || 'Item');
        $html .= "<article><strong>$title</strong><dl>";
        for my $field (@{$fields || []}) {
            next unless exists $item->{$field} && defined $item->{$field} && length _manifest_scalar($item->{$field});
            my $safe_field = escape_html($field);
            my $safe_value = escape_html(_manifest_scalar($item->{$field}));
            $html .= "<div><dt>$safe_field</dt><dd><code>$safe_value</code></dd></div>";
        }
        $html .= '</dl></article>';
    }
    $html .= '</div>';
    return $html;
}

sub _manifest_scalar {
    my ($value) = @_;
    return '' unless defined $value;
    return join ', ', @{$value} if ref($value) eq 'ARRAY';
    return join ', ', map { $_ . '=' . ($value->{$_} // '') } sort keys %{$value} if ref($value) eq 'HASH';
    return "$value";
}

