    my ($pending_invites) = $dbh->selectrow_array(q{SELECT COUNT(*) FROM contributor_invites WHERE status = 'pending'});
    my ($queue_open) = $dbh->selectrow_array(q{SELECT COUNT(*) FROM site_provisioning_queue WHERE status IN ('queued', 'running')});
