sub _settings_master_control_repair_paths {
    my ($self, $request, $session, $session_token) = @_;
    my $result = eval { $self->{sites}->repair_openbsd_paths };
    if (!$result) {
        return $self->_settings_master_control_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'Stored contributor paths could not be repaired.',
                'Confirm the master domain root and contributor domain root settings, then try Repair stored paths again.',
                $@
            )
        );
    }
    my $count = int($result->{updated} || 0);
    $self->_audit_admin_action(
        $session,
        action       => 'master_control.paths_repaired',
        subject_type => 'contributor_site',
        details      => { updated => $count, sites => $result->{sites} || [] },
    );
    return DesertCMS::HTTP->redirect(
        "/admin/settings/master-control?notice=paths-repaired&count=$count",
        { security_headers() }
    );
}

sub _settings_master_control_create_missing_backups {
    my ($self, $request, $session, $session_token) = @_;
    my ($created, $skipped, @errors) = (0, 0);
    my $fleet = $self->{sites}->fleet_status(check_dns => 0, check_tls => 0, app_version => DesertCMS::Version::current());
    for my $site (@{$fleet->{sites} || []}) {
        next if ($site->{status} || '') eq 'destroyed' || ($site->{status} || '') eq 'destroy_pending';
        if (int($site->{backups}{count} || 0) > 0) {
            $skipped++;
            next;
        }
        my $config_path = $site->{config_path} || '';
        if (!length $config_path || !-f $config_path) {
            push @errors, ($site->{site_id} || 'site') . ': config path is missing';
            next;
        }
        my $ok = eval {
            my $site_config = DesertCMS::Config->load($config_path);
            my $site_db = DesertCMS::DB->new(config => $site_config);
            $site_db->migrate;
            DesertCMS::Backup::create_backup($site_config, $site_db, $session->{user_id});
            1;
        };
        if ($ok) {
            $created++;
        } else {
            my $site_id = $site->{site_id} || 'site';
            my $err = $@ || 'backup failed';
            $err =~ s/\s+/ /g;
            push @errors, "$site_id: $err";
        }
    }
    my $error_count = scalar @errors;
    $self->_audit_admin_action(
        $session,
        action       => 'master_control.missing_backups_created',
        subject_type => 'contributor_site',
        details      => { created => $created, skipped => $skipped, errors => $error_count },
    );
    my $notice = $error_count ? 'backups-partial' : 'backups-created';
    return DesertCMS::HTTP->redirect(
        "/admin/settings/master-control?notice=$notice&created=$created&skipped=$skipped&errors=$error_count",
        { security_headers() }
    );
}

sub _settings_provisioning_job_page {
    my ($self, $request, $session, $session_token, $id, $message) = @_;
    my $job = $self->{sites}->queue_job($id) or return $self->_not_found;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $settings_nav = $self->_settings_nav('control', $session);
    $message ||= _provisioning_job_notice($request);
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $events = $self->{sites}->queue_events($job->{id});
    my $event_rows = _provisioning_event_rows($events);
    my $job_id = int($job->{id});
    my $site_id = escape_html($job->{site_id} || '');
    my $action = escape_html(_title_case_status($job->{action} || 'job'));
    my $status = _queue_status_pill($job->{status});
    my $created = escape_html(_format_time($job->{created_at}));
    my $updated = escape_html(_format_time($job->{updated_at}));
    my $completed = escape_html(_format_time($job->{completed_at}));
    my $error = escape_html($job->{error_text} || '');
    my $details = escape_html($job->{details_json} || '{}');
    my $retry = '';
    if (($job->{status} || '') eq 'failed') {
        $retry = <<"HTML";
<form method="post" action="/admin/settings/master-control/provisioning/$job_id/retry">
  <input type="hidden" name="csrf_token" value="$csrf">
  <button type="submit" class="secondary">Retry job</button>
</form>
HTML
    }
    my $error_panel = '';
    if (length $error) {
        $error_panel = <<"HTML";
    <section class="inspector-panel">
      <h2>Failure</h2>
      <p class="muted">The worker stopped before this job finished. Fix the item described below, then use Retry job to queue a clean retry.</p>
      <pre class="mono-block">$error</pre>
    </section>
HTML
    }

    my $body = <<"HTML";
<section class="editor-workspace">
  $settings_nav
  <section class="panel">
    <div class="split">
      <div>
        <p class="eyebrow">Provisioning</p>
        <h1>Job #$job_id</h1>
        <p>Review the root-worker steps for this contributor subCMS action.</p>
      </div>
      <div class="actions">
        <a class="button-link secondary" href="/admin/settings/master-control">Back to Master Control</a>
        $retry
      </div>
    </div>
    $notice
    <section class="inspector-panel">
      <h2>Job Summary</h2>
      <dl class="health-list health-list--compact">
        <div><dt>Site</dt><dd>$site_id</dd></div>
        <div><dt>Action</dt><dd>$action</dd></div>
        <div><dt>Status</dt><dd>$status</dd></div>
        <div><dt>Created</dt><dd>$created</dd></div>
        <div><dt>Updated</dt><dd>$updated</dd></div>
        <div><dt>Completed</dt><dd>$completed</dd></div>
      </dl>
    </section>
    $error_panel
    <section class="inspector-panel">
      <h2>Step Log</h2>
      <table class="content-table compact-table admin-card-table">
        <thead><tr><th>Step</th><th>Status</th><th>Time</th><th>Message</th></tr></thead>
        <tbody>$event_rows</tbody>
      </table>
    </section>
    <section class="inspector-panel">
      <h2>Queued Details</h2>
      <pre class="mono-block">$details</pre>
    </section>
  </section>
</section>
HTML

    return $self->_html_response("Provisioning Job #$job_id", $body, $session);
}

sub _settings_provisioning_job_retry {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $retry = eval {
        $self->{sites}->retry_failed_queue_job(
            id                 => $id,
            created_by_user_id => $session->{user_id},
        );
    };
    if (!$retry) {
        return $self->_settings_provisioning_job_page(
            $request,
            $session,
            $session_token,
            $id,
            _admin_action_error(
                'The provisioning retry could not be queued.',
                'Check that the original job is still failed, then try Retry job again.',
                $@
            )
        );
    }
    my $new_id = int($retry->{id});
    $self->_audit_admin_action(
        $session,
        action       => 'provisioning.retry_queued',
        subject_type => 'site_provisioning_queue',
        subject_id   => $new_id,
        details      => { failed_job_id => int($id || 0), site_id => $retry->{site_id} || '' },
    );
    return DesertCMS::HTTP->redirect(
        "/admin/settings/master-control/provisioning/$new_id?notice=retry-queued",
        { security_headers() }
    );
}

sub _master_control_notice {
    my ($request) = @_;
    return '' unless $request;
    my $notice = $request->param('notice') || '';
    if ($notice eq 'paths-repaired') {
        my $count = int($request->param('count') || 0);
        return $count
            ? "Stored OpenBSD paths repaired for $count contributor site(s)."
            : 'No missing stored OpenBSD paths needed repair.';
    }
    if ($notice eq 'backups-created' || $notice eq 'backups-partial') {
        my $created = int($request->param('created') || 0);
        my $skipped = int($request->param('skipped') || 0);
        my $errors = int($request->param('errors') || 0);
        return "Created $created contributor backup(s) and skipped $skipped site(s) that already had backups"
            . ($errors ? ". $errors site(s) still need attention; open Master Control to review their path or backup status." : '.');
    }
    return '';
}

sub _provisioning_job_notice {
    my ($request) = @_;
    return '' unless $request;
    my $notice = $request->param('notice') || '';
    return 'Retry queued as a new provisioning job.' if $notice eq 'retry-queued';
    return '';
}

sub _contributors_notice {
    my ($request) = @_;
    return '' unless $request;
    my $notice = $request->param('notice') || '';
    return 'Contributor settings saved.' if $notice eq 'contributors-saved';
    return 'Postmark test email sent.' if $notice eq 'postmark-test-sent';
    return 'The Postmark test email was not sent. Open the Delivery Log, fix the sender/token/HTTPS transport issue shown there, then send another test.' if $notice eq 'postmark-test-failed';
    return 'Postmark webhook endpoint token rotated.' if $notice eq 'postmark-webhook-rotated';
    return 'Contributor request approved. Provisioning was queued and the profile completion link was emailed to the applicant.' if $notice eq 'request-approved-email-sent';
    return 'The request was approved and provisioning was queued, but the profile completion email was not sent. Open the Delivery Log, fix the email issue, then grant or resend access after email is healthy.' if $notice eq 'request-approved-email-failed';
    return 'Contributor request denied and the applicant email was sent.' if $notice eq 'request-denied-email-sent';
    return 'The request was denied, but the applicant email was not sent. Open the Delivery Log, fix the email issue, then contact the applicant manually if needed.' if $notice eq 'request-denied-email-failed';
    return '';
}

sub _provider_health_cards {
    my ($self, $settings, $tenant_isolation, $fleet) = @_;
    my $site_host = _url_host($self->{config}->get('site_url'));
    my $domain_root = $settings->{contributor_domain_root} || $site_host;
    my $postmark_ready = ($settings->{postmark_from_email} || '') && ($settings->{postmark_server_token} || '');
    my $review_inbox_ready = ($settings->{contributor_request_recipient_email} || '') ? 1 : 0;
    my $commerce = DesertCMS::Commerce::payment_hub_readiness($self->{config}, $settings);
    my $google_ready = ($settings->{google_oauth_refresh_token} || '') && ($settings->{google_search_console_property} || '');
    my $indexnow_enabled = $settings->{indexnow_enabled} ? 1 : 0;
    my $indexnow_ready = $indexnow_enabled && ($settings->{indexnow_key} || '');
    my $workers_ready = _root_worker_scripts_present();
    my $missing_backups = 0;
    for my $site (@{($fleet || {})->{sites} || []}) {
        next unless ($site->{status} || '') eq 'active';
        $missing_backups++ unless int(($site->{backups} || {})->{count} || 0) > 0;
    }

    my @cards = (
        [
            'Master domain',
            $site_host ? 'ok' : 'warn',
            $site_host ? 'Configured' : 'Missing',
            $site_host || 'Set site_url in the instance config.',
        ],
        [
            'Contributor root',
            $domain_root ? 'ok' : 'warn',
            $domain_root ? 'Configured' : 'Missing',
            $domain_root ? '*.' . $domain_root : 'Save contributor_domain_root for subCMS provisioning.',
        ],
        [
            'Root workers',
            $workers_ready ? 'ok' : 'warn',
            $workers_ready ? 'Scripts present' : 'Missing scripts',
            $workers_ready
                ? 'Install cron for site queue, upgrade, font package, and operations workers.'
                : 'The site queue, upgrade, font package, and operations worker scripts must be installed before launch.',
        ],
        [
            'Backups',
            $missing_backups ? 'warn' : 'ok',
            $missing_backups ? 'Needs backups' : 'Covered',
            $missing_backups ? "$missing_backups active contributor site(s) have no backup yet." : 'Active contributor sites have at least one backup.',
        ],
        [
            'Postmark',
            $postmark_ready && $review_inbox_ready ? 'ok' : 'warn',
            $postmark_ready && $review_inbox_ready ? 'Ready' : 'Needs setup',
            $postmark_ready
                ? ($review_inbox_ready ? 'Sender, recipient, and token saved.' : 'Add a request receiving email.')
                : 'Save sender email and server token.',
        ],
        [
            'Commerce / Stripe',
            $commerce->{state},
            $commerce->{label},
            $commerce->{summary},
        ],
        [
            'Google Search Console',
            $google_ready ? 'ok' : 'neutral',
            $google_ready ? 'Connected' : 'Not connected',
            $google_ready ? ($settings->{google_search_console_property} || '') : 'Connect from Editor > Site & SEO > Indexing.',
        ],
        [
            'IndexNow',
            $indexnow_ready ? 'ok' : ($indexnow_enabled ? 'neutral' : 'neutral'),
            $indexnow_ready ? 'Enabled' : ($indexnow_enabled ? 'Key pending' : 'Disabled'),
            $indexnow_ready ? 'Key saved for sitemap submission.' : ($indexnow_enabled ? 'A key can be generated on submission.' : 'Enable per site when it should submit URLs.'),
        ],
        [
            'Tenant Isolation',
            ($tenant_isolation || {})->{status} || 'warn',
            ($tenant_isolation || {})->{label} || 'Needs review',
            ($tenant_isolation || {})->{summary} || 'Run the isolation audit before launch.',
        ],
    );

    return join '', map { _provider_health_card(@{$_}) } @cards;
}

sub _root_worker_scripts_present {
    my $root = File::Spec->catdir(dirname(__FILE__), '..', '..');
    return -f File::Spec->catfile($root, 'tools', 'openbsd-apply-site-queue.pl')
        && -f File::Spec->catfile($root, 'tools', 'openbsd-apply-upgrade.pl')
        && -f File::Spec->catfile($root, 'tools', 'openbsd-apply-font-packages.pl')
        && -f File::Spec->catfile($root, 'tools', 'openbsd-operations-worker.pl');
}

sub _provider_health_card {
    my ($title, $state, $label, $detail) = @_;
    my $safe_title = escape_html($title);
    my $safe_detail = escape_html($detail || '');
    return '<div><dt>' . $safe_title . '</dt><dd>'
        . _fleet_state_pill($state, $label)
        . '<small>' . $safe_detail . '</small></dd></div>';
}

