    my $postmark_endpoint = length($settings->{postmark_webhook_token} || '')
        ? '<code>' . escape_html($self->_absolute_url('/postmark/webhook/' . $settings->{postmark_webhook_token})) . '</code>'
        : '<span class="muted">Save contributor email settings to generate a Postmark webhook endpoint.</span>';
    my $stripe_checkout_endpoint = escape_html($self->_absolute_url('/stripe/webhook'));
    my $stripe_billing_endpoint = escape_html($self->_absolute_url('/billing/stripe/webhook'));
    my $commerce_summary = escape_html($commerce->{summary} || 'Review Stripe checkout readiness before enabling paid modules.');

    return <<"HTML";
<div class="provider-readiness-detail-grid">
  <section class="provider-readiness-detail">
    <div class="provider-readiness-heading">
      <div>
        <h3>Email / Postmark</h3>
        <p>Sender, HTTPS transport, test delivery, and bounce/spam webhook readiness.</p>
      </div>
      <a class="button-link secondary" href="/admin/settings/contributors">Email setup</a>
    </div>
    <dl class="health-list health-list--compact provider-check-list">
      $email_rows
    </dl>
    <div class="provider-endpoint-row">
      <strong>Postmark webhook endpoint</strong>
      $postmark_endpoint
      <small>Use this URL in Postmark bounce and spam complaint webhooks.</small>
    </div>
  </section>
  <section class="provider-readiness-detail">
    <div class="provider-readiness-heading">
      <div>
        <h3>Payments / Stripe</h3>
        <p>$commerce_summary</p>
      </div>
      <div class="provider-readiness-actions">
        <a class="button-link secondary" href="/admin/settings/payments">Payment settings</a>
        <a class="button-link secondary" href="/admin/settings/plans">Service plans</a>
      </div>
    </div>
    <dl class="health-list health-list--compact provider-check-list">
      $commerce_rows
    </dl>
    <div class="provider-endpoint-grid">
      <div class="provider-endpoint-row">
        <strong>Checkout webhook endpoint</strong>
        <code>$stripe_checkout_endpoint</code>
        <small>Use this for Shop / Catalog, Events, Bookings, Membership, and Donations checkout fulfillment.</small>
      </div>
      <div class="provider-endpoint-row">
        <strong>Service billing webhook endpoint</strong>
        <code>$stripe_billing_endpoint</code>
        <small>Use this for hosted SubCMS plan checkout, subscription updates, and cancellation events.</small>
      </div>
    </div>
  </section>
</div>
HTML
}

sub _provider_readiness_check_rows {
    my ($checks, %args) = @_;
    my $label_key = $args{label_key} || 'label';
    my $status_key = $args{status_key} || 'status';
    my $html = '';
    for my $check (@{$checks || []}) {
        my $label = escape_html($check->{$label_key} || '');
        my $status = $check->{$status_key} || '';
        my $detail = escape_html($check->{detail} || '');
        $html .= '<div><dt>' . $label . '</dt><dd>'
            . _fleet_state_pill($check->{state} || 'neutral', $status)
            . '<small>' . $detail . '</small></dd></div>';
    }
    return $html || '<div><dt>Readiness</dt><dd><span class="status-pill warn">Unknown</span><small>No provider checks were available.</small></dd></div>';
}

sub _commerce_model_options {
    my ($selected) = @_;
    $selected = DesertCMS::Commerce::normalize_model($selected) || 'disabled';
    my $html = '';
    for my $option (@{DesertCMS::Commerce::model_options()}) {
        my $value = escape_html($option->{value});
        my $label = escape_html($option->{label});
        my $summary = escape_html($option->{summary});
        my $checked = $option->{value} eq $selected ? 'checked' : '';
        $html .= <<"HTML";
<label class="commerce-model-option">
  <input type="radio" name="commerce_model" value="$value" $checked>
  <span><strong>$label</strong><small>$summary</small></span>
</label>
HTML
    }
    return $html;
}

sub _commerce_readiness_rows {
    my ($readiness) = @_;
    return join '', map {
        _provider_health_card($_->{title}, $_->{state}, $_->{label}, $_->{detail})
    } @{($readiness || {})->{checks} || []};
}

sub _tenant_isolation_rows {
    my ($audit) = @_;
    my $rows = '';
    for my $check (@{($audit || {})->{checks} || []}) {
        my $label = escape_html($check->{label} || '');
        my $detail = escape_html($check->{detail} || '');
        my $pill = _fleet_state_pill($check->{state} || 'neutral', ($check->{state} || '') eq 'ok' ? 'OK' : 'Review');
        $rows .= <<"HTML";
<tr>
  <td data-label="Check">$label</td>
  <td data-label="Status">$pill</td>
  <td data-label="Detail">$detail</td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(3, 'No tenant isolation checks were run.', 'Run the tenant-isolation audit after contributor provider settings are saved.');
}

sub _master_fleet_health_groups {
    my ($sites) = @_;
    my %groups = (
        failed    => [],
        attention => [],
        healthy   => [],
    );
    for my $site (@{$sites || []}) {
        my $state = _master_site_health_state($site);
        $state = 'attention' unless exists $groups{$state};
        push @{$groups{$state}}, $site;
    }
    return \%groups;
}

sub _master_site_health_state {
    my ($site) = @_;
    my $status = $site->{status} || '';
    my $queue_status = $site->{queue} ? ($site->{queue}{status} || '') : '';
    return 'failed' if $queue_status eq 'failed';
    return 'failed' if $status =~ /failed/i;
    return 'attention' if $queue_status eq 'queued' || $queue_status eq 'running';
    return 'attention' if $status ne 'active';
    return 'attention' if $site->{alerts} && @{$site->{alerts}};
    return 'healthy';
}

sub _master_site_health_pill {
    my ($site) = @_;
    return _fleet_state_pill('neutral', 'Disabled') if ($site->{status} || '') eq 'disabled';
    my $state = _master_site_health_state($site);
    return _fleet_state_pill('warn', 'Failed') if $state eq 'failed';
    return _fleet_state_pill('warn', 'Needs Attention') if $state eq 'attention';
    return _fleet_state_pill('ok', 'Healthy');
}

sub _master_fleet_overview {
    my ($fleet, $groups, $app_version) = @_;
    $groups ||= {};
    my $healthy = scalar @{$groups->{healthy} || []};
    my $attention = scalar @{$groups->{attention} || []};
    my $failed = scalar @{$groups->{failed} || []};
    my $total = int($fleet->{total} || 0);
    my $active = int($fleet->{active} || 0);
    my $pending = int($fleet->{pending} || 0);
    my $disabled = int($fleet->{disabled} || 0);
    my $queue_open = int($fleet->{queue_open} || 0);
    my $queue_failed = int($fleet->{queue_failed} || 0);
    my $alerts = int($fleet->{alerts} || 0);
    my ($overall_class, $overall_label, $overall_detail) = ('healthy', 'Healthy', 'No failed provisioning jobs are visible.');
    if ($failed) {
        ($overall_class, $overall_label, $overall_detail) = ('failed', 'Failed', 'Review failed sites first, then retry from the job detail.');
    } elsif ($attention) {
        ($overall_class, $overall_label, $overall_detail) = ('attention', 'Needs Attention', 'Open work or warnings are present, but no failed job is blocking the fleet.');
    }
    my $overall_pill_class = $overall_class eq 'healthy' ? 'ok' : 'warn';
    my $queue_state = $queue_failed ? 'warn' : ($queue_open ? 'status-pill--neutral' : 'ok');
    return <<"HTML";
<section class="master-control-overview" id="master-control-overview" aria-label="Fleet summary">
  <div class="master-control-score master-control-score--$overall_class">
    <span>Fleet status</span>
    <strong>$overall_label</strong>
    <small>$overall_detail</small>
  </div>
  <dl class="master-control-metrics">
    <div><dt>Healthy</dt><dd><span class="status-pill ok">$healthy</span><small>Clear checks</small></dd></div>
    <div><dt>Needs Attention</dt><dd><span class="status-pill warn">$attention</span><small>Warnings or open work</small></dd></div>
    <div><dt>Failed</dt><dd><span class="status-pill warn">$failed</span><small>Blocked jobs</small></dd></div>
    <div><dt>Total Sites</dt><dd><strong>$total</strong><small>$active active, $disabled disabled, $pending pending</small></dd></div>
    <div><dt>Provisioning</dt><dd><span class="status-pill $queue_state">$queue_open open</span><small>$queue_failed failed job(s)</small></dd></div>
    <div><dt>Alerts</dt><dd><span class="status-pill $overall_pill_class">$alerts</span><small>Path, DNS, TLS, backup, and queue checks</small></dd></div>
    <div><dt>Version</dt><dd><span class="status-pill status-pill--neutral">v$app_version</span><small>Shared app code</small></dd></div>
  </dl>
</section>
HTML
}

sub _master_control_maintenance_actions {
    my ($csrf) = @_;
    return <<"HTML";
<section class="master-maintenance-strip" id="master-control-maintenance" aria-label="Fleet maintenance">
  <div>
    <strong>Fleet maintenance</strong>
    <p>Use these only when the summary reports missing paths or missing backups. Failed provisioning jobs have their own retry controls.</p>
  </div>
  <form method="post" action="/admin/settings/master-control/repair-paths">
    <input type="hidden" name="csrf_token" value="$csrf">
    <button type="submit" class="button-link secondary">Repair stored paths</button>
  </form>
  <form method="post" action="/admin/settings/master-control/create-missing-backups">
    <input type="hidden" name="csrf_token" value="$csrf">
    <button type="submit" class="button-link secondary">Create missing backups</button>
  </form>
</section>
HTML
}

sub _master_fleet_rows {
    my ($self, $sites, $empty_message, %args) = @_;
    my $rows = '';
    for my $site (@{$sites || []}) {
        my $domain = escape_html($site->{domain} || '');
        my $site_id = escape_html($site->{site_id} || '');
        my $display_name = escape_html($site->{display_name} || '');
        my $owner = escape_html($site->{owner_email} || '');
        my $owner_html = $owner ? qq{<a href="mailto:$owner">$owner</a>} : '<span class="muted">No owner email</span>';
        $owner_html = "<strong>$display_name</strong><br>$owner_html" if length $display_name;
        my $status = _site_status_pill($site->{status});
        my $health = _master_site_health_pill($site);
        my $last_rebuild = escape_html(_format_time($site->{last_rebuild}));
        my $last_login = escape_html(_format_time($site->{last_login}));
        my $paths = _fleet_paths_html($site->{paths});
        my $dns_tls = '<div class="fleet-status-stack">'
            . '<div><span>DNS</span>' . _fleet_state_pill($site->{dns}{state}, $site->{dns}{label}) . '<small>' . escape_html($site->{dns}{detail} || '') . '</small></div>'
            . '<div><span>TLS</span>' . _fleet_state_pill($site->{tls}{state}, $site->{tls}{label}) . '<small>' . escape_html($site->{tls}{detail} || '') . '</small></div>'
            . '</div>';
        my $queue = _queue_summary_html($site->{queue}, $args{csrf});
        my $backups = _backup_summary_html($site->{backups});
        my $disk = escape_html(_format_bytes($site->{disk}{bytes} || 0));
        my $files = int($site->{disk}{files} || 0);
        my $version = escape_html($site->{version} || 'unknown');
        my $alerts = _fleet_alerts_html($site->{alerts});
        my $site_url = $domain ? qq{<a href="https://$domain/">$domain</a>} : '<span class="muted">No domain</span>';
        $rows .= <<"HTML";
<tr>
  <td data-label="Site"><div class="fleet-site-identity"><strong>$site_url</strong><span class="muted">$site_id</span>$owner_html</div></td>
  <td data-label="Health"><div class="fleet-cell-stack">$health$status<small>Last rebuild $last_rebuild</small><small>Last login $last_login</small></div></td>
  <td data-label="Operations"><div class="fleet-cell-stack">$dns_tls$queue</div></td>
  <td data-label="Storage"><div class="fleet-cell-stack">$paths$backups<small><strong>$disk</strong> across $files files</small><small>Running v$version</small></div></td>
  <td data-label="Alerts">$alerts</td>
</tr>
HTML
    }
    $empty_message ||= 'No contributor subCMS sites have been created yet.';
    my $empty_detail = $args{empty_detail} || (
        $empty_message =~ /disabled/i
            ? 'Contributor sites moved through Disable will appear here until they are enabled or destroyed.'
            : 'Approved contributor requests and manual site registrations will appear here after provisioning starts.'
    );
    return $rows || _admin_empty_row(5, $empty_message, $empty_detail);
}

sub _split_disabled_sites {
    my ($sites) = @_;
    my (@active, @disabled);
    for my $site (@{$sites || []}) {
        if (($site->{status} || '') eq 'disabled') {
            push @disabled, $site;
        } else {
            push @active, $site;
        }
    }
    return (\@active, \@disabled);
}

sub _fleet_paths_html {
    my ($paths) = @_;
    my @items = (
        [ 'Config', $paths->{config} ],
        [ 'Data',   $paths->{data} ],
        [ 'Public', $paths->{public} ],
        [ 'DB',     $paths->{db} ],
    );
    my $html = '<dl class="fleet-mini-list">';
    for my $item (@items) {
        my ($label, $state) = @{$item};
        $html .= '<div><dt>' . escape_html($label) . '</dt><dd>'
            . _fleet_state_pill($state->{state}, $state->{label})
            . '</dd></div>';
    }
    $html .= '</dl>';
    return $html;
}

sub _site_status_pill {
    my ($status) = @_;
    $status ||= 'unknown';
    my $state = $status eq 'active' ? 'ok'
        : $status eq 'disabled' || $status eq 'destroyed' ? 'neutral'
        : 'warn';
    return _fleet_state_pill($state, _title_case_status($status));
}

sub _queue_summary_html {
    my ($queue, $csrf) = @_;
    return _fleet_state_pill('neutral', 'No jobs') unless $queue;
    my $job_id = int($queue->{id} || 0);
    my $action = escape_html(_title_case_status($queue->{action} || 'job'));
    my $updated = escape_html(_format_time($queue->{updated_at}));
    my $error = ($queue->{error_text} || '') ne ''
        ? '<small>' . escape_html($queue->{error_text}) . '</small>'
        : '';
    my $actions = '';
    if ($job_id > 0) {
        $actions .= qq{<a class="button-link secondary button-link--compact" href="/admin/settings/master-control/provisioning/$job_id">Review job</a>};
        if (($queue->{status} || '') eq 'failed' && defined $csrf) {
            $actions .= <<"HTML";
<form method="post" action="/admin/settings/master-control/provisioning/$job_id/retry" class="inline-form">
  <input type="hidden" name="csrf_token" value="$csrf">
  <button type="submit" class="button-link secondary button-link--compact button-link--warn">Retry failed job</button>
</form>
HTML
        }
        $actions = qq{<div class="fleet-inline-actions">$actions</div>};
    }
    return '<div class="fleet-status-stack"><div><span>' . $action . '</span>'
        . _queue_status_pill($queue->{status})
        . '<small>' . $updated . '</small>' . $error . $actions . '</div></div>';
}

sub _queue_status_pill {
    my ($status) = @_;
    $status ||= 'unknown';
    my $state = $status eq 'done' ? 'ok'
        : $status eq 'failed' ? 'warn'
        : 'neutral';
    return _fleet_state_pill($state, _title_case_status($status));
}

sub _queue_event_status_pill {
    my ($status) = @_;
    $status ||= 'info';
    my $state = $status eq 'done' ? 'ok'
        : $status eq 'failed' ? 'warn'
        : 'neutral';
    return _fleet_state_pill($state, _title_case_status($status));
}

sub _provisioning_event_rows {
    my ($events) = @_;
    my $rows = '';
    for my $event (@{$events || []}) {
        my $step = escape_html($event->{step_label} || $event->{step_key} || 'Event');
        my $status = _queue_event_status_pill($event->{status});
        my $created = escape_html(_format_time($event->{created_at}));
        my $message = escape_html($event->{message} || '');
        $rows .= <<"HTML";
<tr>
  <td data-label="Step">$step</td>
  <td data-label="Status">$status</td>
  <td data-label="Time">$created</td>
  <td data-label="Message">$message</td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(4, 'No step events yet.', 'The root worker will append DNS, TLS, config, database, admin, email, rebuild, and httpd events as the job runs.');
}

sub _backup_summary_html {
    my ($backups) = @_;
    my $count = int($backups->{count} || 0);
    my $latest = escape_html(_format_time($backups->{latest}));
    my $state = $count ? 'ok' : 'warn';
    return '<div class="fleet-status-stack"><div><span>' . $count . ' total</span>'
        . _fleet_state_pill($state, $count ? 'Present' : 'Missing')
        . '<small>Latest ' . $latest . '</small></div></div>';
}

sub _fleet_alerts_html {
    my ($alerts) = @_;
    return _fleet_state_pill('ok', 'Clear') unless $alerts && @{$alerts};
    my $html = '<ul class="fleet-alert-list">';
    for my $alert (@{$alerts}) {
        $html .= '<li>' . escape_html($alert) . '</li>';
    }
    $html .= '</ul>';
    return $html;
}

sub _fleet_state_pill {
    my ($state, $label) = @_;
    $state ||= 'neutral';
    my $class = $state eq 'ok' ? 'ok'
        : $state eq 'warn' ? 'warn'
        : 'status-pill--neutral';
    return '<span class="status-pill ' . $class . '">' . escape_html($label || 'Unknown') . '</span>';
}

sub _admin_empty_row {
    my ($columns, $title, $detail) = @_;
    $columns = int($columns || 1);
    $columns = 1 if $columns < 1;
    my $safe_title = escape_html($title || 'No records yet.');
    my $safe_detail = escape_html($detail || '');
    my $detail_html = length $safe_detail ? "<small>$safe_detail</small>" : '';
    return qq{<tr class="admin-empty-row"><td colspan="$columns"><div class="admin-empty-state"><strong>$safe_title</strong>$detail_html</div></td></tr>};
}

sub _admin_empty_panel {
    my ($title, $detail) = @_;
    my $safe_title = escape_html($title || 'Nothing here yet.');
    my $safe_detail = escape_html($detail || '');
    my $detail_html = length $safe_detail ? "<small>$safe_detail</small>" : '';
    return qq{<div class="admin-empty-state" role="status"><strong>$safe_title</strong>$detail_html</div>};
}

sub _admin_action_error {
    my ($summary, $next_step, $raw_error) = @_;
    my $message = _clean_error($raw_error || '');
    $summary ||= 'The action could not be completed.';
    $next_step ||= 'Review the settings and try again.';
    return $summary . ' ' . $next_step . (length $message ? ' Details: ' . $message : '');
}

sub _title_case_status {
    my ($value) = @_;
    $value = '' unless defined $value;
    $value =~ s/_/ /g;
    $value =~ s/\b([a-z])/\U$1/g;
    return $value || 'Unknown';
}

sub _settings_account_page {
    my ($self, $request, $session, $session_token, $message) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $is_contributor_product = DesertCMS::CapabilityPolicy::contributor_product_mode($self->{config});
    my $settings_nav = $self->_settings_nav('account', $session);
    my $account_nav = $is_contributor_product ? '' : $self->_admin_account_nav('account', $session);
    my $admin_username = escape_html($session->{username} || '');
    my $admin_email = escape_html($session->{email} || '');
    my $eyebrow = $is_contributor_product ? 'Account' : 'Settings';
    my $heading = $is_contributor_product ? 'Account' : 'Admin Account';
    my $intro = $is_contributor_product
        ? 'Manage your login, account email, plan help, and platform support for this hosted site.'
        : 'Manage your own administrator login for this CMS.';
    my $support_surface = $is_contributor_product ? $self->_contributor_account_help_surface($session) : '';
    my $save_label = $is_contributor_product ? 'Save account' : 'Save admin account';
    my $panel_class = $is_contributor_product ? 'panel contributor-account-panel' : 'panel';
    my $form_class = $is_contributor_product ? 'settings-form contributor-account-form' : 'settings-form';

    my $body = <<"HTML";
<section class="editor-workspace">
  $settings_nav
  $account_nav
  <section class="$panel_class">
    <div class="split">
      <div>
        <p class="eyebrow">$eyebrow</p>
        <h1>$heading</h1>
        <p>$intro</p>
      </div>
    </div>
    $notice
    $support_surface
    <form method="post" action="/admin/settings/admin-account" class="$form_class">
      <input type="hidden" name="csrf_token" value="$csrf">
      <section class="inspector-panel">
        <h2>Login</h2>
        <label>
          <span>Username</span>
          <input name="username" value="$admin_username" autocomplete="username" required>
        </label>
        <label>
          <span>Account email</span>
          <input name="email" type="email" value="$admin_email" autocomplete="email">
        </label>
      </section>
      <section class="inspector-panel">
        <h2>Password</h2>
        <div class="field-row">
          <label>
            <span>New password</span>
            <input name="password" type="password" autocomplete="new-password" placeholder="Leave blank to keep current password">
          </label>
          <label>
            <span>Confirm password</span>
            <input name="password_confirm" type="password" autocomplete="new-password">
          </label>
        </div>
      </section>
      <button type="submit">$save_label</button>
    </form>
  </section>
</section>
HTML

    return $self->_html_response($is_contributor_product ? 'Account' : 'Admin Account', $body, $session);
}

sub _settings_governance_page {
    my ($self, $request, $session, $session_token, $message) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $settings_nav = $self->_settings_nav('governance', $session);
    my $account_nav = $self->_admin_account_nav('governance', $session);
    my $scope = DesertCMS::Governance::scope($self->{config});
    my $can_manage = DesertCMS::CapabilityPolicy::has($self->{config}, $session->{role}, 'manage_governance') ? 1 : 0;
    my $scope_label = $scope eq 'contributor' ? 'Contributor subCMS' : 'Master CMS';
    my $role_cards = _governance_role_cards($scope);
    my $user_rows = $self->_governance_user_rows($csrf, $scope, $session, $can_manage);
    my $audit_rows = $self->_governance_audit_rows;
    my $role_options = _governance_role_options($scope, $scope eq 'contributor' ? 'contributor' : 'support');
    my $section_nav = _module_section_nav(
        'Governance sections',
        [ '#governance-roles', 'Role Model' ],
        [ '#governance-users', 'Admin Users' ],
        [ '#governance-grant', 'Grant Access' ],
        [ '#governance-audit', 'Audit Log' ],
    );
    my $grant_form = $can_manage ? <<"HTML" : '<p class="muted">Only owners can grant or disable admin access.</p>';
      <form method="post" action="/admin/settings/governance/users/grant" class="settings-form">
        <input type="hidden" name="csrf_token" value="$csrf">
        <div class="field-row">
          <label>
            <span>Username</span>
            <input name="username" autocomplete="off" required>
          </label>
          <label>
            <span>Email</span>
            <input name="email" type="email" autocomplete="off" required>
          </label>
        </div>
        <label>
          <span>Role</span>
          <select name="role">$role_options</select>
        </label>
        <button type="submit">Grant access</button>
      </form>
HTML

    my $body = <<"HTML";
<section class="editor-workspace">
  $settings_nav
  $account_nav
  <section class="panel">
    <div class="split">
      <div>
        <p class="eyebrow">Governance</p>
        <h1>Roles and Audit</h1>
        <p>Scoped access for $scope_label users and a durable record of sensitive admin actions.</p>
      </div>
    </div>
    $notice
    $section_nav
    <section class="inspector-panel" id="governance-roles">
      <h2>Role Model</h2>
      <dl class="health-list">
        $role_cards
      </dl>
    </section>
    <section class="inspector-panel" id="governance-users">
      <h2>Admin Users</h2>
      <table class="content-table compact-table admin-card-table">
        <thead><tr><th>User</th><th>Role</th><th>Email</th><th>Status</th><th>Updated</th><th>Actions</th></tr></thead>
        <tbody>$user_rows</tbody>
      </table>
    </section>
    <section class="inspector-panel" id="governance-grant">
      <h2>Grant Access</h2>
      $grant_form
    </section>
    <section class="inspector-panel" id="governance-audit">
      <h2>Recent Audit Log</h2>
      <table class="content-table compact-table admin-card-table">
        <thead><tr><th>When</th><th>Actor</th><th>Action</th><th>Subject</th><th>Details</th></tr></thead>
        <tbody>$audit_rows</tbody>
      </table>
    </section>
  </section>
</section>
HTML

    return $self->_html_response('Governance', $body, $session);
}

sub _settings_governance_grant {
    my ($self, $request, $session, $session_token) = @_;
    my $temporary_password = random_hex(12);
    my ($email, $username, $role);
    my ($sent, $reason) = (0, '');
    my $ok = eval {
        $email = $request->param('email') || '';
        $username = $request->param('username') || '';
        $role = $request->param('role') || '';
        my $id = $self->{auth}->grant_admin_access(
            username      => $username,
            email         => $email,
            role          => $role,
            password      => $temporary_password,
            actor_user_id => $session->{user_id},
        );
        my $scope = DesertCMS::Governance::scope($self->{config});
        my $safe_role = DesertCMS::Governance::role_label($role, $scope);
        my $base = $self->{config}->get('site_url') || 'http://localhost';
        $base =~ s{/+\z}{};
        my $login_url = "$base/admin/login";
        my $site_name = DesertCMS::Settings::all($self->{config}, $self->{db})->{site_name}
            || $self->{config}->get('site_name')
            || 'DesertCMS';
        ($sent, $reason) = send_postmark(
            $self->{config},
            $self->{db},
            to         => $email,
            email_type => 'admin_access_grant',
            subject    => "Access to $site_name",
            text_body  => join("\n\n",
                "You have been granted $safe_role access to $site_name.",
                "Admin URL: $login_url",
                "Username: $username",
                "Temporary password: $temporary_password",
                "Sign in and change your password from Admin Account."
            ),
            html_body  => '<p>You have been granted '
                . escape_html($safe_role)
                . ' access to '
                . escape_html($site_name)
                . '.</p><p><strong>Admin URL:</strong> <a href="'
                . escape_html($login_url)
                . '">'
                . escape_html($login_url)
                . '</a><br><strong>Username:</strong> '
                . escape_html($username)
                . '<br><strong>Temporary password:</strong> '
                . escape_html($temporary_password)
                . '</p>',
        );
        $self->_audit_admin_action(
            $session,
            action       => 'governance.access_granted',
            subject_type => 'admin_user',
            subject_id   => $id,
            details      => { username => $username, email => $email, role => $role, emailed => $sent ? 1 : 0 },
        );
        1;
    };
    if (!$ok) {
        return $self->_settings_governance_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'Admin access could not be granted.',
                'Check the email address and selected role, then try again.',
                $@
            )
        );
    }
    my $message = $sent
        ? "Access granted and emailed to $email."
        : "Access granted, but email was not sent: " . ($reason || 'email failed') . ". Temporary password: $temporary_password";
    return $self->_settings_governance_page($request, $session, $session_token, $message);
}

sub _settings_governance_disable {
    my ($self, $request, $session, $session_token) = @_;
    my $ok = eval {
        $self->{auth}->disable_admin_user(
            id            => $request->param('user_id'),
            actor_user_id => $session->{user_id},
        );
        1;
    };
    if (!$ok) {
        return $self->_settings_governance_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The admin user could not be disabled.',
                'Refresh the page to confirm the user is still active, then try again.',
                $@
            )
        );
    }
    return $self->_settings_governance_page($request, $session, $session_token, 'Admin user disabled and active sessions revoked.');
}

sub _governance_role_cards {
    my ($scope) = @_;
    my $html = '';
    for my $definition (@{ DesertCMS::Governance::role_definitions($scope) }) {
        my $label = escape_html($definition->{label});
        my $role = escape_html($definition->{role});
        my $description = escape_html($definition->{description});
        $html .= qq{<div><dt>$label</dt><dd><code>$role</code><small>$description</small></dd></div>};
    }
    return $html;
}

sub _governance_role_options {
    my ($scope, $selected) = @_;
    my $html = '';
    $selected = DesertCMS::Governance::normalize_role($selected, $scope);
    for my $definition (@{ DesertCMS::Governance::role_definitions($scope) }) {
        my $role = escape_html($definition->{role});
        my $label = escape_html($definition->{label});
        my $is_selected = $definition->{role} eq $selected ? 'selected' : '';
        $html .= qq{<option value="$role" $is_selected>$label</option>};
    }
    return $html;
}

sub _governance_user_rows {
    my ($self, $csrf, $scope, $session, $can_manage) = @_;
    my $rows = '';
    for my $user (@{ $self->{auth}->list_admin_users }) {
        my $id = int($user->{id});
        my $username = escape_html($user->{username} || '');
        my $email = escape_html($user->{email} || '');
        my $role = DesertCMS::Governance::normalize_role($user->{role}, $scope);
        my $role_label = escape_html(DesertCMS::Governance::role_label($role, $scope));
        my $role_code = escape_html($role);
        my $updated = escape_html(_format_time($user->{updated_at}));
        my $status = defined $user->{disabled_at}
            ? '<span class="status-pill warn">Disabled</span>'
            : (($user->{force_password_change} || 0)
                ? '<span class="status-pill warn">Password setup</span>'
                : '<span class="status-pill ok">Active</span>');
        my $actions = '';
        if ($can_manage && !defined $user->{disabled_at} && int($session->{user_id} || 0) != $id) {
            $actions = <<"HTML";
<form method="post" action="/admin/settings/governance/users/disable" class="inline-form" data-confirm-title="Disable this admin user?" data-confirm-message="The user will lose admin access until an owner restores access. Your own account is not affected." data-confirm-action="Disable" data-loading-label="Disabling...">
  <input type="hidden" name="csrf_token" value="$csrf">
  <input type="hidden" name="user_id" value="$id">
  <button type="submit" class="small danger">Disable</button>
</form>
HTML
        }
        $actions ||= '<span class="muted">-</span>';
        $rows .= <<"HTML";
<tr>
  <td data-label="User"><strong>$username</strong></td>
  <td data-label="Role">$role_label<br><code>$role_code</code></td>
  <td data-label="Email">$email</td>
  <td data-label="Status">$status</td>
  <td data-label="Updated">$updated</td>
  <td data-label="Actions" class="table-actions">$actions</td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(6, 'No admin users yet.', 'Grant access when another owner, operator, reviewer, curator, or support user should help manage this CMS.');
}

sub _governance_audit_rows {
    my ($self) = @_;
    my $rows = '';
    for my $row (@{ $self->{auth}->audit_rows(limit => 100) }) {
        my $when = escape_html(_format_time($row->{created_at}));
        my $actor = escape_html($row->{actor_username} || 'system');
        my $action = escape_html($row->{action} || '');
        my $subject = escape_html(join '#', grep { defined $_ && length $_ } ($row->{subject_type} || '', $row->{subject_id} || ''));
        my $details = escape_html(_governance_details_text($row->{details}));
        $rows .= <<"HTML";
<tr>
  <td data-label="When">$when</td>
  <td data-label="Actor">$actor</td>
  <td data-label="Action"><code>$action</code></td>
  <td data-label="Subject">$subject</td>
  <td data-label="Details">$details</td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(5, 'No audit activity yet.', 'Master actions such as approvals, access grants, provider changes, rebuilds, backups, and site lifecycle actions will appear here.');
}

sub _governance_details_text {
    my ($details) = @_;
    return '' unless $details && ref $details eq 'HASH';
    my @pairs;
    for my $key (sort keys %{$details}) {
        my $value = $details->{$key};
        if (ref $value) {
            $value = eval { encode_json($value) } || '';
        }
        $value = '' unless defined $value;
        push @pairs, "$key=$value" if length "$value";
    }
    return join ', ', @pairs;
}

sub _settings_federation_page {
    my ($self, $request, $session, $session_token, $message) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $settings_nav = $self->_settings_nav('federation', $session);
    my $account_nav = $self->_admin_account_nav('federation', $session);
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $counts = $self->{federation}->counts;
    my $pending_rows = $self->_federation_rows('pending', $csrf);
    my $approved_rows = $self->_federation_rows('approved', $csrf);
    my $rejected_rows = $self->_federation_rows('rejected', $csrf);
    my $pending = int($counts->{pending} || 0);
    my $approved = int($counts->{approved} || 0);
    my $rejected = int($counts->{rejected} || 0);
    my $pending_media = int($counts->{pending_media} || 0);
    my $pending_posts = int($counts->{pending_posts} || 0);
    my $section_nav = _module_section_nav(
        'Federated review sections',
        [ '#federation-summary', 'Summary' ],
        [ '#federation-pending', 'Pending Review' ],
        [ '#federation-approved', 'Approved' ],
        [ '#federation-rejected', 'Rejected' ],
    );

    my $body = <<"HTML";
<section class="editor-workspace">
  $settings_nav
  $account_nav
  <section class="panel">
    <div class="split">
      <div>
        <p class="eyebrow">Federated Review</p>
        <h1>Contributor Content Review</h1>
        <p>Scan active contributor subCMS sites and approve public assets or posts before they appear on the platform Showcase and Posts pages.</p>
      </div>
      <form method="post" action="/admin/settings/federation/refresh">
        <input type="hidden" name="csrf_token" value="$csrf">
        <button type="submit" class="secondary">Scan contributor sites</button>
      </form>
    </div>
    $notice
    $section_nav
    <section class="metric-grid" id="federation-summary">
      <article class="metric-card"><span>Pending</span><strong>$pending</strong><small>$pending_media images, $pending_posts posts</small></article>
      <article class="metric-card"><span>Approved</span><strong>$approved</strong><small>Visible when contributor surfacing is enabled</small></article>
      <article class="metric-card"><span>Rejected</span><strong>$rejected</strong><small>Hidden from master surfaces</small></article>
      <article class="metric-card"><span>Source</span><strong>SubCMS</strong><small>Read-only from contributor databases</small></article>
    </section>
    <section class="inspector-panel" id="federation-pending">
      <h2>Pending Review</h2>
      <table class="content-table compact-table admin-card-table">
        <thead><tr><th>Item</th><th>Contributor</th><th>Seen</th><th>Preview</th><th>Actions</th></tr></thead>
        <tbody>$pending_rows</tbody>
      </table>
    </section>
    <section class="inspector-panel" id="federation-approved">
      <h2>Approved</h2>
      <table class="content-table compact-table admin-card-table">
        <thead><tr><th>Item</th><th>Contributor</th><th>Reviewed</th><th>Preview</th><th>Actions</th></tr></thead>
        <tbody>$approved_rows</tbody>
      </table>
    </section>
    <section class="inspector-panel" id="federation-rejected">
      <h2>Rejected</h2>
      <table class="content-table compact-table admin-card-table">
        <thead><tr><th>Item</th><th>Contributor</th><th>Reviewed</th><th>Preview</th><th>Actions</th></tr></thead>
        <tbody>$rejected_rows</tbody>
      </table>
    </section>
  </section>
</section>
HTML

    return $self->_html_response('Federated Content Review', $body, $session);
}

sub _settings_federation_refresh {
    my ($self, $request, $session, $session_token) = @_;
    my $result = eval { $self->{federation}->refresh_queue };
    if (!$result) {
        return $self->_settings_federation_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'Contributor content could not be scanned.',
                'Check that contributor sites are active and readable, then scan again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'federation.scan_completed',
        subject_type => 'federated_content',
        details      => $result,
    );
    my $message = 'Contributor scan completed: '
        . int($result->{discovered} || 0) . ' discovered, '
        . int($result->{inserted} || 0) . ' new, '
        . int($result->{updated} || 0) . ' refreshed.';
    return $self->_settings_federation_page($request, $session, $session_token, $message);
}

sub _settings_federation_review {
    my ($self, $request, $session, $session_token) = @_;
    my $status = $request->param('status') || '';
    my $row = eval {
        $self->{federation}->review(
            id                  => $request->param('review_id'),
            status              => $status,
            note                => $request->param('review_note'),
            reviewed_by_user_id => $session->{user_id},
        );
    };
    if (!$row) {
        return $self->_settings_federation_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The contributor content review could not be saved.',
                'Refresh the queue to confirm the item is still available, then try again.',
                $@
            )
        );
    }
    eval { $self->{content}->rebuild_all; };
    $self->_audit_admin_action(
        $session,
        action       => 'federation.content_' . ($row->{status} || 'pending'),
        subject_type => 'federated_content',
        subject_id   => int($row->{id} || 0),
        details      => {
            source_site_id => $row->{source_site_id} || '',
            source_type    => $row->{source_type} || '',
            source_id      => int($row->{source_id} || 0),
            title          => $row->{title} || '',
        },
    );
    my $message = 'Federated item marked ' . ($row->{status} || 'pending') . ' and public output rebuilt.';
    return $self->_settings_federation_page($request, $session, $session_token, $message);
}

sub _federation_rows {
    my ($self, $status, $csrf) = @_;
    my $rows = '';
    for my $row (@{ $self->{federation}->rows(status => $status, limit => 100) }) {
        my $id = int($row->{id});
        my $type = ($row->{source_type} || '') eq 'post' ? 'Post' : 'Image';
        my $title = escape_html($row->{title} || '(Untitled)');
        my $summary = escape_html($row->{summary} || '');
        my $summary_html = length $summary ? "<small>$summary</small>" : '';
        my $site = escape_html($row->{source_site_id} || '');
        my $domain = escape_html($row->{source_domain} || '');
        my $when = $status eq 'pending'
            ? escape_html(_format_time($row->{last_seen_at}))
            : escape_html(_format_time($row->{reviewed_at}));
        my $time_label = $status eq 'pending' ? 'Seen' : 'Reviewed';
        my $url = escape_html($row->{source_url} || '');
        my $preview = length $url ? qq{<a href="$url">$url</a>} : '<span class="muted">No preview URL</span>';
        if ($row->{source_missing_at}) {
            $preview .= '<br><span class="muted">Source no longer available</span>';
        }
        my $actions = _federation_action_forms($id, $status, $csrf);
        $rows .= <<"HTML";
<tr>
  <td data-label="Item"><span class="status-pill">$type</span><br><strong>$title</strong>$summary_html</td>
  <td data-label="Contributor">$site<br><span class="muted">$domain</span></td>
  <td data-label="$time_label">$when</td>
  <td data-label="Preview">$preview</td>
  <td data-label="Actions" class="table-actions">$actions</td>
</tr>
HTML
    }
    my %empty = (
        pending  => [
            'No contributor content is waiting for review.',
            'Scan contributor sites to find new assets and posts that can be approved for the platform Showcase or Posts pages.',
        ],
        approved => [
            'No contributor content has been approved yet.',
            'Approved photos and posts appear here and can be surfaced on the master site when contributor surfacing is enabled.',
        ],
        rejected => [
            'No contributor content has been rejected.',
            'Items rejected during review appear here and stay hidden from master-site surfaces.',
        ],
    );
    my $copy = $empty{$status} || [ 'No contributor content in this list.', 'Scan contributor sites to refresh the review queue.' ];
    return $rows || _admin_empty_row(5, $copy->[0], $copy->[1]);
}

sub _federation_action_forms {
    my ($id, $status, $csrf) = @_;
    my @buttons;
    if ($status ne 'approved') {
        push @buttons, [ approved => 'Approve', '' ];
    }
    if ($status ne 'rejected') {
        push @buttons, [ rejected => 'Reject', 'danger' ];
    }
    if ($status ne 'pending') {
        push @buttons, [ pending => 'Return to pending', 'secondary' ];
    }
    my $html = '';
    for my $button (@buttons) {
        my ($next, $label, $class) = @{$button};
        my $safe_next = escape_html($next);
        my $safe_label = escape_html($label);
        my $safe_class = $class ? ' class="small ' . escape_html($class) . '"' : ' class="small"';
        $html .= <<"HTML";
<form method="post" action="/admin/settings/federation/review" class="inline-form">
  <input type="hidden" name="csrf_token" value="$csrf">
  <input type="hidden" name="review_id" value="$id">
  <input type="hidden" name="status" value="$safe_next">
  <button type="submit"$safe_class>$safe_label</button>
</form>
HTML
    }
    return $html || '<span class="muted">-</span>';
}

sub _settings_contributors_page {
    my ($self, $request, $session, $session_token, $message) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $settings_nav = $self->_settings_nav('contributors', $session);
    my $contributor_nav = $self->_contributor_settings_nav('contributors', $session);
    my $suggested_contributor_root = _url_host($self->{config}->get('site_url')) || 'example.com';
    my $contributor_domain_root = escape_html($settings->{contributor_domain_root} || '');
    my $contributor_root_placeholder = escape_html($suggested_contributor_root);
    my $postmark_from_placeholder = escape_html("name\@$suggested_contributor_root");
    my $postmark_review_placeholder = escape_html("review\@$suggested_contributor_root");
    my $postmark_from_email = escape_html($settings->{postmark_from_email});
    my $contributor_request_recipient_email = escape_html($settings->{contributor_request_recipient_email} || '');
    my $postmark_token_state = $settings->{postmark_server_token}
        ? '<span class="status-pill ok">Token saved</span>'
        : '<span class="status-pill warn">No token saved</span>';
    my $sender_mode = ($settings->{postmark_sender_mode} || '') eq 'inherit' ? 'inherit' : 'site';
    my $site_sender_selected = $sender_mode eq 'site' ? 'selected' : '';
    my $inherit_sender_selected = $sender_mode eq 'inherit' ? 'selected' : '';
    my $readiness = email_readiness($self->{config}, $self->{db});
    my $readiness_rows = $self->_postmark_readiness_rows($readiness);
    my $resolved = $readiness->{resolved} || {};
    my $resolved_sender = escape_html($resolved->{from_email} || 'Not configured');
    my $resolved_source = escape_html($resolved->{source_label} || 'This CMS instance');
    my $webhook_token = $settings->{postmark_webhook_token} || '';
    my $webhook_endpoint = length $webhook_token
        ? escape_html($self->_absolute_url('/postmark/webhook/' . $webhook_token))
        : '<span class="muted">Save contributor settings to generate a webhook endpoint.</span>';
    my $template_rows = $self->_postmark_template_preview_rows;
    my $delivery_rows = $self->_email_delivery_rows;
    my $request_rows = $self->_contributor_request_rows($csrf);
    my $invite_rows = $self->_contributor_invite_rows($csrf);
    my $blueprint_options = $self->_blueprint_options();
    my $onboarding_flow = $self->_contributor_onboarding_flow;
    my $delivery_failure_panel = $self->_delivery_failure_panel;
    my $dbh = $self->{db}->dbh;
    my ($pending_requests) = $dbh->selectrow_array(q{SELECT COUNT(*) FROM contributor_requests WHERE status IN ('new', 'reviewing')});
    my ($approved_requests) = $dbh->selectrow_array(q{
        SELECT COUNT(*)
        FROM contributor_requests r
        WHERE r.status = 'approved'
          AND EXISTS (
              SELECT 1
              FROM contributor_sites s
              WHERE ((s.site_id <> '' AND s.site_id = r.site_id)
                  OR (s.domain <> '' AND s.domain = r.domain))
                AND s.status IN ('pending_provision', 'active', 'disabled', 'destroy_pending')
          )
    });
    my ($archived_requests) = $dbh->selectrow_array(q{
        SELECT COUNT(*)
        FROM contributor_requests r
        WHERE r.status = 'approved'
          AND NOT EXISTS (
              SELECT 1
              FROM contributor_sites s
              WHERE (s.site_id <> '' AND s.site_id = r.site_id)
                 OR (s.domain <> '' AND s.domain = r.domain)
          )
          AND EXISTS (
              SELECT 1
              FROM archived_sites a
              WHERE lower(a.owner_email) = lower(r.email)
                AND a.archived_at >= COALESCE(r.approved_at, r.submitted_at)
          )
    });
    my ($pending_invites) = $dbh->selectrow_array(q{SELECT COUNT(*) FROM contributor_invites WHERE status = 'pending'});
    my ($delivery_failures) = $dbh->selectrow_array(q{SELECT COUNT(*) FROM email_delivery_logs WHERE status IN ('failed', 'bounced', 'spam', 'complaint')});
    my $readiness_warnings = 0;
    for my $check (@{ $readiness->{checks} || [] }) {
        $readiness_warnings++ if ($check->{state} || '') eq 'warn';
    }
    my $email_summary = $readiness_warnings
        ? '<span class="status-pill warn">Needs attention</span>'
        : '<span class="status-pill ok">Ready</span>';
    my $requests_summary = int($pending_requests || 0)
        ? '<span class="status-pill warn">Needs review</span>'
        : '<span class="status-pill ok">Clear</span>';
    my $delivery_summary = int($delivery_failures || 0)
        ? '<span class="status-pill warn">' . int($delivery_failures || 0) . ' issue(s)</span>'
        : '<span class="status-pill ok">Clean</span>';
    my $contributors_summary = _settings_summary_strip(
        [ 'Email setup', $email_summary, $readiness_warnings ? "$readiness_warnings readiness check(s) need attention." : 'Postmark checks are ready.' ],
        [ 'Requests', $requests_summary, int($pending_requests || 0) . ' waiting, ' . int($approved_requests || 0) . ' approved active/disabled, ' . int($archived_requests || 0) . ' archived.' ],
        [ 'Invites', '<strong>' . int($pending_invites || 0) . '</strong>', 'Pending contributor invitations.' ],
        [ 'Delivery log', $delivery_summary, 'Failed, bounced, spam, or complaint events.' ],
    );

    my $body = <<"HTML";
<section class="editor-workspace">
  $settings_nav
  $contributor_nav
  <section class="panel">
    <div class="split">
      <div>
        <p class="eyebrow">Settings</p>
        <h1>Contributors</h1>
        <p>Configure invitations and email delivery for contributor sites.</p>
      </div>
    </div>
    $notice
    $contributors_summary
    $onboarding_flow
    <form method="post" action="/admin/settings/save" class="settings-form">
      <input type="hidden" name="csrf_token" value="$csrf">
      <section class="inspector-panel">
        <h2>Email Deliverability</h2>
        <p class="muted">Use this checklist to verify the Postmark sender, test delivery, and configure bounce/spam webhook reporting.</p>
        <dl class="health-list fleet-provider-list">
          $readiness_rows
        </dl>
        <div class="field-row">
          <label>
            <span>Sender mode</span>
            <select name="postmark_sender_mode">
              <option value="site" $site_sender_selected>Use this site's sender</option>
              <option value="inherit" $inherit_sender_selected>Inherit master sender for this subCMS</option>
            </select>
          </label>
          <div class="settings-preview">
            <strong>Resolved sender</strong>
            <p>$resolved_sender</p>
            <small>$resolved_source</small>
          </div>
        </div>
        <label>
          <span>Send email</span>
          <input name="postmark_from_email" value="$postmark_from_email" placeholder="$postmark_from_placeholder">
        </label>
        <label>
          <span>Receiving email for contributor requests</span>
          <input name="contributor_request_recipient_email" type="email" value="$contributor_request_recipient_email" placeholder="$postmark_review_placeholder">
        </label>
        <label>
          <span>Postmark server token</span>
          <input name="postmark_server_token" type="password" autocomplete="new-password" placeholder="Leave blank to keep saved token">
        </label>
        <div class="settings-preview">$postmark_token_state</div>
        <div class="settings-preview">
          <strong>Postmark bounce/spam webhook</strong>
          <code>$webhook_endpoint</code>
          <small>Use this URL for Postmark bounce and spam complaint webhooks.</small>
        </div>
        <div class="settings-form-actions settings-form-actions--sticky">
          <button type="submit">Save contributor settings</button>
        </div>
      </section>
    </form>
    <form method="post" action="/admin/settings/contributors/rotate-webhook-token" class="hidden-form" id="postmark-rotate-token-form">
      <input type="hidden" name="csrf_token" value="$csrf">
    </form>
    <section class="inspector-panel">
      <h2>Test Email</h2>
      <form method="post" action="/admin/settings/contributors/test-email" class="field-row">
        <input type="hidden" name="csrf_token" value="$csrf">
        <label>
          <span>Send test to</span>
          <input name="test_email" type="email" placeholder="you\@example.com" required>
        </label>
        <button type="submit">Send Postmark test</button>
        <button type="submit" class="secondary" form="postmark-rotate-token-form">Rotate webhook token</button>
      </form>
    </section>
    <form method="post" action="/admin/settings/save" class="settings-form">
      <input type="hidden" name="csrf_token" value="$csrf">
      <section class="inspector-panel">
        <h2>Domains</h2>
        <label>
          <span>Contributor domain root</span>
          <input name="contributor_domain_root" value="$contributor_domain_root" placeholder="$contributor_root_placeholder">
        </label>
        <div class="settings-form-actions settings-form-actions--sticky">
          <button type="submit">Save domain settings</button>
        </div>
      </section>
    </form>
    <section class="inspector-panel">
      <h2>Template Preview</h2>
      <div class="template-preview-list">$template_rows</div>
    </section>
    <section class="inspector-panel">
      <h2>Delivery Log</h2>
      $delivery_failure_panel
      <div class="delivery-log-scroll" aria-label="Delivery log entries">
        <table class="content-table compact-table admin-card-table delivery-log-table">
          <thead><tr><th>When</th><th>Type</th><th>Status</th><th>Recipient</th><th>Subject</th><th>Reason</th></tr></thead>
          <tbody>$delivery_rows</tbody>
        </table>
      </div>
    </section>
    <section class="inspector-panel">
      <h2>Requests</h2>
      <p class="muted">Public contributor request submissions appear here for review, approval, or denial.</p>
      <table class="content-table compact-table admin-card-table">
        <thead><tr><th>Name</th><th>Email</th><th>Status</th><th>Submitted</th><th>Actions</th></tr></thead>
        <tbody>$request_rows</tbody>
      </table>
    </section>
    <section class="inspector-panel">
      <h2>Invite Contributor</h2>
      <form method="post" action="/admin/settings/invites/send" class="stack">
        <input type="hidden" name="csrf_token" value="$csrf">
        <label>
          <span>Email</span>
          <input name="email" type="email" required>
        </label>
        <label>
          <span>Message</span>
          <textarea name="message" rows="3"></textarea>
        </label>
        <label>
          <span>Contributor blueprint</span>
          <select name="blueprint_id">$blueprint_options</select>
        </label>
        <button type="submit">Send invite</button>
      </form>
    </section>
    <section class="inspector-panel">
      <h2>Recent Invites</h2>
      <table class="content-table compact-table admin-card-table">
        <thead><tr><th>Email</th><th>Status</th><th>Blueprint</th><th>Domain</th><th>Actions</th></tr></thead>
        <tbody>$invite_rows</tbody>
      </table>
    </section>
  </section>
</section>
HTML

    return $self->_html_response('Contributors', $body, $session);
}

sub _postmark_readiness_rows {
    my ($self, $readiness) = @_;
    my $html = '';
    for my $check (@{ $readiness->{checks} || [] }) {
        my $label = escape_html($check->{label} || '');
        my $state = ($check->{state} || '') eq 'ok' ? 'ok' : (($check->{state} || '') eq 'neutral' ? 'status-pill--neutral' : 'warn');
        my $status = escape_html($check->{status} || '');
        my $detail = escape_html($check->{detail} || '');
        $html .= <<"HTML";
<div><dt>$label</dt><dd><span class="status-pill $state">$status</span><small>$detail</small></dd></div>
HTML
    }
    return $html || '<div><dt>Postmark</dt><dd><span class="status-pill warn">Not configured</span><small>Save sender settings to begin.</small></dd></div>';
}

sub _postmark_template_preview_rows {
    my ($self) = @_;
    my $templates = postmark_template_previews($self->{config}, $self->{db});
    my $html = '';
    for my $template (@{$templates}) {
        my $label = escape_html($template->{label} || '');
        my $subject = escape_html($template->{subject} || '');
        my $text = escape_html($template->{text} || '');
        $html .= <<"HTML";
<article class="template-preview-card">
  <span>$label</span>
  <strong>$subject</strong>
  <pre>$text</pre>
</article>
HTML
    }
    return $html || _admin_empty_panel('No email template previews yet.', 'Save contributor email settings to show the request, approval, denial, invite, and access email previews.');
}

sub _email_delivery_rows {
    my ($self) = @_;
    my $rows = email_delivery_logs($self->{config}, $self->{db}, limit => 25);
    my $html = '';
    for my $row (@{$rows}) {
        my $when = escape_html(_format_time($row->{created_at}));
        my $type = escape_html($row->{email_type} || '');
        my $status = escape_html($row->{status} || '');
        my $class = ($row->{status} || '') =~ /\A(?:sent|delivered|opened|clicked)\z/ ? 'ok'
            : (($row->{status} || '') =~ /\A(?:failed|bounced|spam|complaint)\z/ ? 'warn' : 'status-pill--neutral');
        my $to = escape_html($row->{to_email} || '');
        my $subject = escape_html($row->{subject} || '');
        my $reason = escape_html($row->{reason} || '');
        $html .= <<"HTML";
<tr>
  <td data-label="When">$when</td>
  <td data-label="Type"><code>$type</code></td>
  <td data-label="Status"><span class="status-pill $class">$status</span></td>
  <td data-label="Recipient">$to</td>
  <td data-label="Subject">$subject</td>
  <td data-label="Reason">$reason</td>
</tr>
HTML
    }
    return $html || _admin_empty_row(6, 'No delivery events yet.', 'Send a Postmark test email or process a contributor request to populate this log.');
}

sub _delivery_failure_panel {
    my ($self) = @_;
    my $failures = eval {
        $self->{db}->dbh->selectall_arrayref(
            q{
                SELECT *
                FROM email_delivery_logs
                WHERE status IN ('failed', 'bounced', 'spam', 'complaint')
                ORDER BY updated_at DESC, id DESC
                LIMIT 4
            },
            { Slice => {} }
        );
    } || [];
    return '' unless @{$failures};

    my $items = '';
    for my $row (@{$failures}) {
        my $type = escape_html($row->{email_type} || 'email');
        my $to = escape_html($row->{to_email} || 'unknown recipient');
        my $status = escape_html($row->{status} || 'failed');
        my $reason = escape_html($row->{reason} || 'No provider detail was recorded.');
        my $when = escape_html(_format_time($row->{updated_at} || $row->{created_at}));
        $items .= <<"HTML";
<li>
  <span class="status-pill warn">$status</span>
  <strong>$type</strong>
  <small>$to - $when</small>
  <em>$reason</em>
</li>
HTML
    }

    return <<"HTML";
<div class="admin-alert-panel onboarding-alert" role="alert">
  <div>
    <strong>Email delivery needs attention</strong>
    <p>Contributor onboarding emails are not reliably leaving the CMS. Fix these before approving more applicants.</p>
  </div>
  <ul>$items</ul>
</div>
HTML
}

sub _contributor_onboarding_flow {
    my ($self) = @_;
    my $dbh = $self->{db}->dbh;
    my ($new_requests) = $dbh->selectrow_array(q{SELECT COUNT(*) FROM contributor_requests WHERE status = 'new'});
    my ($reviewing_requests) = $dbh->selectrow_array(q{SELECT COUNT(*) FROM contributor_requests WHERE status = 'reviewing'});
    my ($profile_pending) = $dbh->selectrow_array(q{
        SELECT COUNT(*)
        FROM contributor_requests r
        WHERE r.status = 'approved'
          AND r.profile_completed_at IS NULL
          AND EXISTS (
              SELECT 1
              FROM contributor_sites s
              WHERE ((s.site_id <> '' AND s.site_id = r.site_id)
                  OR (s.domain <> '' AND s.domain = r.domain))
                AND s.status IN ('pending_provision', 'active', 'disabled', 'destroy_pending')
          )
    });
    my ($profile_complete) = $dbh->selectrow_array(q{
        SELECT COUNT(*)
        FROM contributor_requests r
        WHERE r.status = 'approved'
          AND r.profile_completed_at IS NOT NULL
          AND EXISTS (
              SELECT 1
              FROM contributor_sites s
              WHERE ((s.site_id <> '' AND s.site_id = r.site_id)
                  OR (s.domain <> '' AND s.domain = r.domain))
                AND s.status IN ('pending_provision', 'active', 'disabled')
          )
    });
    my ($queue_open) = $dbh->selectrow_array(q{SELECT COUNT(*) FROM site_provisioning_queue WHERE status IN ('queued', 'running')});
    my ($queue_failed) = $dbh->selectrow_array(q{SELECT COUNT(*) FROM site_provisioning_queue WHERE status = 'failed'});
    my ($billing_ready) = $dbh->selectrow_array(q{
        SELECT COUNT(*)
        FROM contributor_sites
        WHERE status IN ('pending_provision', 'active', 'disabled')
          AND service_plan_id IS NOT NULL
    });
    my ($billing_past_due) = $dbh->selectrow_array(q{
        SELECT COUNT(*)
        FROM contributor_sites
        WHERE status IN ('pending_provision', 'active', 'disabled')
          AND billing_status = 'past_due'
    });

    my $pending_review = int($new_requests || 0) + int($reviewing_requests || 0);
    my @stages = (
        {
            label  => 'Request',
            state  => $pending_review ? 'warn' : 'ok',
            metric => $pending_review . ' waiting',
            detail => 'New and reviewing applications.',
        },
        {
            label  => 'Review',
            state  => int($reviewing_requests || 0) ? 'warn' : 'status-pill--neutral',
            metric => int($reviewing_requests || 0) . ' in review',
            detail => 'Open the request before approving or denying.',
        },
        {
            label  => 'Profile',
            state  => int($profile_pending || 0) ? 'warn' : 'ok',
            metric => int($profile_pending || 0) . ' pending',
            detail => int($profile_complete || 0) . ' completed public profile(s).',
        },
        {
            label  => 'Provision',
            state  => int($queue_failed || 0) ? 'warn' : (int($queue_open || 0) ? 'status-pill--neutral' : 'ok'),
            metric => int($queue_open || 0) . ' open',
            detail => int($queue_failed || 0) . ' failed job(s).',
        },
        {
            label  => 'Billing',
            state  => int($billing_past_due || 0) ? 'warn' : 'ok',
            metric => int($billing_ready || 0) . ' assigned',
            detail => int($billing_past_due || 0) . ' past due site(s).',
        },
    );

    my $cards = join '', map { _onboarding_stage_card($_) } @stages;
    return <<"HTML";
<section class="onboarding-flow" aria-label="Contributor onboarding flow">
  <div class="onboarding-flow-heading">
    <div>
      <h2>Contributor Onboarding</h2>
      <p>Track each applicant from public request through profile, provisioning, and service tier.</p>
    </div>
    <a class="button-link secondary" href="/admin/settings/master-control">Open provisioning queue</a>
  </div>
  <div class="onboarding-stage-grid">$cards</div>
</section>
HTML
}

sub _onboarding_stage_card {
    my ($stage) = @_;
    my $label = escape_html($stage->{label} || '');
    my $state = $stage->{state} || 'status-pill--neutral';
    $state = 'ok' if $state eq 'done';
    $state = 'warn' if $state eq 'active';
    $state = 'status-pill--neutral' unless $state =~ /\A(?:ok|warn|status-pill--neutral)\z/;
    my $metric = escape_html($stage->{metric} || '');
    my $detail = escape_html($stage->{detail} || '');
    return <<"HTML";
<article class="onboarding-stage-card">
  <span>$label</span>
  <strong><span class="status-pill $state">$metric</span></strong>
  <small>$detail</small>
</article>
HTML
}

