sub _settings_blueprints_save {
    my ($self, $request, $session, $session_token) = @_;
    my $ok = eval {
        $self->{blueprints}->save(
            id => $request->param('blueprint_id'),
            name => $request->param('name'),
            slug => $request->param('slug'),
            description => $request->param('description'),
            category => $request->param('category'),
            is_default => $request->param('is_default') ? 1 : 0,
            module_posts_enabled => $request->param('module_posts_enabled') ? 1 : 0,
            module_map_enabled => $request->param('module_map_enabled') ? 1 : 0,
            module_shop_enabled => $request->param('module_shop_enabled') ? 1 : 0,
            module_gallery_enabled => $request->param('module_gallery_enabled') ? 1 : 0,
            module_forms_enabled => $request->param('module_forms_enabled') ? 1 : 0,
            module_contributor_requests_enabled => $request->param('module_contributor_requests_enabled') ? 1 : 0,
            module_docs_enabled => $request->param('module_docs_enabled') ? 1 : 0,
            module_directory_enabled => $request->param('module_directory_enabled') ? 1 : 0,
            module_bookings_enabled => $request->param('module_bookings_enabled') ? 1 : 0,
            module_membership_enabled => $request->param('module_membership_enabled') ? 1 : 0,
            module_newsletter_enabled => $request->param('module_newsletter_enabled') ? 1 : 0,
            module_donations_enabled => $request->param('module_donations_enabled') ? 1 : 0,
            module_testimonials_enabled => $request->param('module_testimonials_enabled') ? 1 : 0,
            module_accounts_enabled => $request->param('module_accounts_enabled') ? 1 : 0,
            module_live_streaming_enabled => $request->param('module_live_streaming_enabled') ? 1 : 0,
            module_forums_enabled => $request->param('module_forums_enabled') ? 1 : 0,
            module_social_enabled => $request->param('module_social_enabled') ? 1 : 0,
            module_notifications_enabled => $request->param('module_notifications_enabled') ? 1 : 0,
            module_security_center_enabled => $request->param('module_security_center_enabled') ? 1 : 0,
            theme_default_mode => $request->param('theme_default_mode'),
            theme_light_preset => $request->param('theme_light_preset'),
            theme_dark_preset => $request->param('theme_dark_preset'),
            media_quota_mb => $request->param('media_quota_mb'),
            post_quota => $request->param('post_quota'),
            page_quota => $request->param('page_quota'),
            allow_master_gallery => $request->param('allow_master_gallery') ? 1 : 0,
            allow_master_posts => $request->param('allow_master_posts') ? 1 : 0,
            site_meta_title => $request->param('site_meta_title'),
            site_meta_description => $request->param('site_meta_description'),
            default_pages_text => $request->param('default_pages_text'),
        );
        1;
    };
    if (!$ok) {
        return $self->_settings_blueprints_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The contributor blueprint could not be saved.',
                'Check the blueprint name, quotas, default pages, and module choices, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'contributor_blueprint.saved',
        subject_type => 'contributor_blueprint',
        details      => { name => $request->param('name') || '', slug => $request->param('slug') || '' },
    );
    return $self->_settings_blueprints_page($request, $session, $session_token, 'Contributor blueprint saved.');
}

sub _blueprint_rows {
    my ($self, $selected_id) = @_;
    my $rows = '';
    for my $blueprint (@{$self->{blueprints}->list}) {
        my $id = int($blueprint->{id});
        my $name = escape_html($blueprint->{name});
        my $category = escape_html(DesertCMS::Blueprints::vertical_label($blueprint->{category}));
        my $default = $blueprint->{is_default} ? '<span class="status-pill ok">Default</span>' : '';
        my @modules;
        push @modules, 'Posts' if $blueprint->{module_posts_enabled};
        push @modules, 'Map / Locations' if $blueprint->{module_map_enabled};
        push @modules, 'Showcase' if $blueprint->{module_gallery_enabled};
        push @modules, 'Shop' if $blueprint->{module_shop_enabled};
        push @modules, 'Forms' if $blueprint->{module_forms_enabled};
        push @modules, 'Requests' if $blueprint->{module_contributor_requests_enabled};
        push @modules, 'Docs' if $blueprint->{module_docs_enabled};
        push @modules, 'Directory' if $blueprint->{module_directory_enabled};
        push @modules, 'Bookings' if $blueprint->{module_bookings_enabled};
        push @modules, 'Membership' if $blueprint->{module_membership_enabled};
        push @modules, 'Newsletter' if $blueprint->{module_newsletter_enabled};
        push @modules, 'Donations' if $blueprint->{module_donations_enabled};
        push @modules, 'Testimonials' if $blueprint->{module_testimonials_enabled};
        push @modules, 'Accounts' if $blueprint->{module_accounts_enabled} || $blueprint->{module_social_enabled};
        push @modules, 'Live Streaming' if $blueprint->{module_live_streaming_enabled};
        push @modules, 'Forums' if $blueprint->{module_forums_enabled};
        push @modules, 'Social' if $blueprint->{module_social_enabled};
        push @modules, 'Notifications' if $blueprint->{module_notifications_enabled};
        push @modules, 'Security Center' if $blueprint->{module_security_center_enabled};
        my $modules = escape_html(@modules ? join(', ', @modules) : 'None');
        my $quotas = int($blueprint->{media_quota_mb} || 0) . ' MB, '
            . int($blueprint->{post_quota} || 0) . ' posts, '
            . int($blueprint->{page_quota} || 0) . ' pages';
        my $surface = ($blueprint->{allow_master_gallery} ? 'Assets' : '')
            . (($blueprint->{allow_master_gallery} && $blueprint->{allow_master_posts}) ? ' and ' : '')
            . ($blueprint->{allow_master_posts} ? 'Posts' : '');
        $surface = 'Disabled' unless length $surface;
        my $selected = $selected_id && int($selected_id) == $id ? '<span class="status-pill">Editing</span>' : '';
        $rows .= <<"HTML";
<tr>
  <td data-label="Name"><strong>$name</strong><br>$default $selected</td>
  <td data-label="Vertical">$category</td>
  <td data-label="Modules">$modules</td>
  <td data-label="Quotas">$quotas</td>
  <td data-label="Master Surfacing">$surface</td>
  <td data-label="Actions" class="table-actions"><a class="button-link secondary" href="/admin/settings/blueprints?id=$id">Edit</a></td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(6, 'No contributor blueprints yet.', 'Create a blueprint to define default pages, modules, theme choices, quotas, permissions, and master surfacing before approving contributors.');
}

sub _blueprint_options {
    my ($self, $selected_id) = @_;
    my $blueprints = $self->{blueprints}->list;
    my ($default) = grep { $_->{is_default} } @{$blueprints};
    $selected_id = $default->{id} if (!$selected_id && $default);
    my $html = '';
    for my $blueprint (@{$blueprints}) {
        my $id = int($blueprint->{id});
        my $label = DesertCMS::Blueprints::vertical_label($blueprint->{category});
        my $name = escape_html("$label - " . ($blueprint->{name} || 'Blueprint'));
        my $selected = int($selected_id || 0) == $id ? 'selected' : '';
        $html .= qq{<option value="$id" $selected>$name</option>};
    }
    return $html;
}

sub _blueprint_category_options {
    my ($selected_id) = @_;
    $selected_id ||= 'photographer';
    my $html = '';
    for my $category (@{DesertCMS::Blueprints::vertical_categories()}) {
        my $id = escape_html($category->{id});
        my $label = escape_html($category->{label});
        my $selected = $selected_id eq $category->{id} ? 'selected' : '';
        $html .= qq{<option value="$id" $selected>$label</option>};
    }
    return $html;
}

sub _settings_plans_page {
    my ($self, $request, $session, $session_token, $message) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $settings_nav = $self->_settings_nav('plans', $session);
    my $contributor_nav = $self->_contributor_settings_nav('plans', $session);
    my $plans = $self->{service_plans}->list;
    my $selected = $self->{service_plans}->get($request->param('id')) || {};
    my $editing = $selected->{id} ? 1 : 0;
    my $usage_sites = $self->{service_plans}->fleet_usage;
    my $summary = $self->{service_plans}->usage_summary($usage_sites);
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $readiness = $self->{service_plans}->billing_readiness($settings, $plans);
    my $rows = $self->_service_plan_rows($plans, $selected->{id}, $csrf);
    my $usage_rows = $self->_service_plan_usage_rows($usage_sites);
    my $plan_options = _service_plan_options($plans, $selected->{id});
    my $assignment_plan_options = _service_plan_options($plans, undef);
    my $site_options = _service_site_options($usage_sites);
    my $billing_status_options = _billing_status_options('comped');
    my $blueprint_options = $self->_blueprint_options($selected->{blueprint_id});

    my $id = int($selected->{id} || 0);
    my $name = escape_html($selected->{name} || '');
    my $slug = escape_html($selected->{slug} || '');
    my $description = escape_html($selected->{description} || '');
    my $price = escape_html(_price_dollars($selected->{monthly_price_cents}));
    my $currency = escape_html($selected->{currency} || 'usd');
    my $stripe_price = escape_html($selected->{stripe_price_id} || '');
    my $media_quota = int($selected->{media_quota_mb} || 512);
    my $media_upload_limit = int($selected->{media_upload_limit_mb} || 64);
    my $post_quota = int($selected->{post_quota} || 100);
    my $page_quota = int($selected->{page_quota} || 20);
    my $default_checked = $selected->{is_default} ? 'checked' : '';
    my $gallery_checked = $editing ? ($selected->{allow_master_gallery} ? 'checked' : '') : 'checked';
    my $posts_checked = $editing ? ($selected->{allow_master_posts} ? 'checked' : '') : 'checked';
    my $postmark_override_checked = $editing && $selected->{allow_postmark_sender_override} ? 'checked' : '';
    my $stripe_connect_checked = $editing && $selected->{allow_stripe_connect} ? 'checked' : '';
    my $indexing_override_checked = $editing && $selected->{allow_indexing_override} ? 'checked' : '';
    my $platform_fee_percent = escape_html(sprintf('%.2f', int($selected->{stripe_platform_fee_bps} || 0) / 100));
    $platform_fee_percent =~ s/\.00\z//;
    my $feature_checkboxes = _service_plan_feature_checkboxes(
        $editing
            ? DesertCMS::Modules::feature_map_for_plan($selected)
            : DesertCMS::Modules::feature_map_from_values({}, {})
    );
    my $heading = $editing ? 'Edit Service Plan' : 'New Service Plan';
    my $subhead = $editing
        ? 'Update the hosted service package. Existing sites keep their current limits until the plan is assigned again.'
        : 'Create a hosted service package that can be assigned to contributor subCMS sites.';

    my $total_sites = int($summary->{sites} || 0);
    my $assigned = int($summary->{assigned} || 0);
    my $past_due = int($summary->{past_due} || 0);
    my $quota_warnings = int($summary->{quota_warnings} || 0);
    my $monthly = escape_html(_format_money($summary->{monthly_cents}, 'usd'));
    my $stripe_state = $readiness->{stripe_ready}
        ? _fleet_state_pill('ok', 'Ready')
        : _fleet_state_pill('warn', 'Needs setup');
    my $stripe_detail = $readiness->{stripe_ready}
        ? 'Stripe key and webhook secret are saved.'
        : 'Set the Stripe key and webhook secret in Settings > Payments before taking payments.';
    my $price_state = (!$readiness->{priced_plans} || $readiness->{priced_plans} == $readiness->{priced_with_stripe})
        ? _fleet_state_pill('ok', 'Mapped')
        : _fleet_state_pill('warn', 'Missing price IDs');
    my $price_detail = int($readiness->{priced_with_stripe} || 0) . ' of ' . int($readiness->{priced_plans} || 0) . ' paid plan(s) have Stripe Price IDs.';
    my $plan_sections = _module_section_nav(
        'Service plan sections',
        [ '#service-plans-overview',   'Overview' ],
        [ '#service-plans-readiness',  'Billing Readiness' ],
        [ '#service-plans-list',       'Plans' ],
        [ '#service-plans-edit',       'Plan Editor' ],
        [ '#service-plans-features',   'Plan Features' ],
        [ '#service-plans-providers',  'Provider Overrides' ],
        [ '#service-plans-assignment', 'Assign Plan' ],
        [ '#service-plans-usage',      'Fleet Usage' ],
    );

    my $body = <<"HTML";
<section class="editor-workspace">
  $settings_nav
  $contributor_nav
  <section class="panel">
    <div class="split">
      <div>
        <p class="eyebrow">Service Layer</p>
