    <section class="metric-grid" id="service-plans-overview" aria-label="Service plan overview">
      <article class="metric-card"><span>Contributor Sites</span><strong>$total_sites</strong><small>$assigned assigned to a plan</small></article>
      <article class="metric-card"><span>Monthly Active</span><strong>$monthly</strong><small>Active or trialing sites only</small></article>
      <article class="metric-card"><span>Past Due</span><strong>$past_due</strong><small>Sites needing billing review</small></article>
      <article class="metric-card"><span>Quota Warnings</span><strong>$quota_warnings</strong><small>Sites at 90% or more of a limit</small></article>
    </section>
    <section class="inspector-panel" id="service-plans-readiness">
