        <div><dt>Stripe API</dt><dd>$stripe_state<small>$stripe_detail</small></dd></div>
        <div><dt>Paid Plan Prices</dt><dd>$price_state<small>$price_detail</small></dd></div>
      </dl>
    </section>
    <section class="inspector-panel" id="service-plans-list">
      <h2>Plans</h2>
