        <tbody>$rows</tbody>
      </table>
    </section>
    <form method="post" action="/admin/settings/plans/save" class="settings-form settings-form--wide">
      <input type="hidden" name="csrf_token" value="$csrf">
      <input type="hidden" name="plan_id" value="$id">
      <section class="inspector-panel" id="service-plans-edit">
        <h2>$heading</h2>
        <p class="muted">$subhead</p>
        <div class="field-row">
          <label>
            <span>Name</span>
            <input name="name" value="$name" placeholder="Standard Service" required>
          </label>
          <label>
            <span>Slug</span>
            <input name="slug" value="$slug" placeholder="standard-service">
          </label>
        </div>
        <label>
          <span>Description</span>
          <textarea name="description" rows="3">$description</textarea>
        </label>
        <label class="checkbox-field">
          <input type="checkbox" name="is_default" value="1" $default_checked>
          <span>Use as the default service plan</span>
        </label>
      </section>
      <section class="inspector-panel">
        <h2>Billing</h2>
        <div class="field-row">
          <label>
            <span>Monthly price</span>
            <input name="monthly_price_dollars" inputmode="decimal" value="$price" placeholder="0.00">
          </label>
          <label>
            <span>Currency</span>
            <input name="currency" value="$currency" maxlength="3">
          </label>
        </div>
        <label>
          <span>Stripe Price ID</span>
          <input name="stripe_price_id" value="$stripe_price" placeholder="price_...">
        </label>
      </section>
      <section class="inspector-panel" id="service-plans-provisioning">
        <h2>Provisioning Defaults</h2>
        <label>
          <span>Recommended blueprint</span>
          <select name="blueprint_id">$blueprint_options</select>
        </label>
        <div class="field-row">
          <label>
            <span>Media quota MB</span>
            <input name="media_quota_mb" type="number" min="1" max="102400" value="$media_quota">
          </label>
          <label>
            <span>Per-file upload MB</span>
            <input name="media_upload_limit_mb" type="number" min="1" max="1024" value="$media_upload_limit">
          </label>
