    <section class="inspector-panel" id="service-plans-usage">
      <h2>Fleet Usage</h2>
      <table class="content-table compact-table service-usage-table admin-card-table">
        <thead><tr><th>Site</th><th>Plan</th><th>Billing</th><th>Media</th><th>Posts</th><th>Pages</th></tr></thead>
        <tbody>$usage_rows</tbody>
      </table>
    </section>
  </section>
</section>
HTML

    return $self->_html_response('Service Plans', $body, $session);
}

sub _settings_plans_save {
    my ($self, $request, $session, $session_token) = @_;
    my %feature_args = map {
        ('feature_' . $_ . '_included') => ($request->param('feature_' . $_ . '_included') ? 1 : 0)
    } grep { $_ ne 'contributor_requests' } @{ DesertCMS::Modules::feature_keys() };
    my $plan = eval {
        $self->{service_plans}->save(
            id => $request->param('plan_id'),
            name => $request->param('name'),
            slug => $request->param('slug'),
            description => $request->param('description'),
            is_default => $request->param('is_default') ? 1 : 0,
            monthly_price_dollars => $request->param('monthly_price_dollars'),
            currency => $request->param('currency'),
            stripe_price_id => $request->param('stripe_price_id'),
            blueprint_id => $request->param('blueprint_id'),
            media_quota_mb => $request->param('media_quota_mb'),
            media_upload_limit_mb => $request->param('media_upload_limit_mb'),
            post_quota => $request->param('post_quota'),
            page_quota => $request->param('page_quota'),
            allow_master_gallery => $request->param('allow_master_gallery') ? 1 : 0,
            allow_master_posts => $request->param('allow_master_posts') ? 1 : 0,
            allow_postmark_sender_override => $request->param('allow_postmark_sender_override') ? 1 : 0,
            allow_stripe_connect => $request->param('allow_stripe_connect') ? 1 : 0,
            allow_indexing_override => $request->param('allow_indexing_override') ? 1 : 0,
            stripe_platform_fee_percent => $request->param('stripe_platform_fee_percent'),
            %feature_args,
        );
    };
    if (!$plan) {
        return $self->_settings_plans_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The service plan could not be saved.',
                'Check the plan name, price, Stripe Price ID, quotas, and blueprint, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'service_plan.saved',
        subject_type => 'service_plan',
        subject_id   => int($plan->{id} || 0),
        details      => { name => $plan->{name} || '', slug => $plan->{slug} || '' },
    );
    return $self->_settings_plans_page($request, $session, $session_token, 'Service plan saved.');
}

sub _settings_plans_default {
    my ($self, $request, $session, $session_token) = @_;
    my $plan = eval { $self->{service_plans}->set_default($request->param('plan_id')) };
    if (!$plan) {
        return $self->_settings_plans_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The default service plan could not be changed.',
                'Refresh the page to confirm the plan still exists, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'service_plan.default_set',
        subject_type => 'service_plan',
        subject_id   => int($plan->{id} || 0),
        details      => { name => $plan->{name} || '' },
    );
    return $self->_settings_plans_page($request, $session, $session_token, 'Default service plan updated.');
}

sub _settings_plans_assign {
    my ($self, $request, $session, $session_token) = @_;
    my $site = eval {
        $self->{service_plans}->assign_site(
            site_id => $request->param('site_id'),
            plan_id => $request->param('plan_id'),
            billing_status => $request->param('billing_status'),
            billing_email => $request->param('billing_email'),
            stripe_customer_id => $request->param('stripe_customer_id'),
            stripe_subscription_id => $request->param('stripe_subscription_id'),
        );
    };
    if (!$site) {
        return $self->_settings_plans_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The service plan could not be assigned.',
                'Choose an active contributor site and a saved service plan, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'service_plan.assigned',
        subject_type => 'contributor_site',
        details      => {
            site_id => $site->{site_id} || '',
            plan_id => int($site->{service_plan_id} || 0),
            billing_status => $site->{billing_status} || '',
            plan_sync => $site->{plan_sync} || {},
        },
    );
    my $sync = $site->{plan_sync} || {};
    my $message = $sync->{synced}
        ? 'Service plan assigned and contributor quota settings synced.'
        : 'Service plan assigned. Contributor quota sync skipped: ' . ($sync->{reason} || 'not available') . '.';
    return $self->_settings_plans_page($request, $session, $session_token, $message);
}

sub _service_plan_feature_checkboxes {
    my ($features) = @_;
    $features ||= {};
    my @groups = (
        {
            label => 'Public site features',
            detail => 'Primary contributor surfaces that add public pages or hosted-site workflows.',
            keys => [qw(shop events directory bookings membership newsletter donations testimonials)],
        },
        {
            label => 'Accounts and community',
            detail => 'Unified identity, community, realtime social surfaces, and notification adapters.',
            keys => [qw(posts accounts live_streaming forums social notifications)],
        },
        {
            label => 'Payments and deposits',
            detail => 'Stripe-backed checkout entitlements. These still require Stripe site payments in Provider Overrides.',
            keys => [qw(shop_payments event_payments booking_payments membership_payments donation_payments)],
        },
        {
            label => 'Publishing utilities',
            detail => 'Supporting content, map, form, documentation, showcase, and download capabilities.',
            keys => [qw(map gallery forms docs resource_publishing)],
        },
    );
    my %module_by_key = map { ($_->{key} || '') => $_ } @{ DesertCMS::Modules::definitions({}) };
    my %rendered;
    my $html = '';
    for my $group (@groups) {
        my $safe_label = escape_html($group->{label});
        my $safe_detail = escape_html($group->{detail});
        my $items = '';
        for my $feature_key (@{ $group->{keys} || [] }) {
            my $module = $module_by_key{$feature_key} or next;
            $rendered{$feature_key} = 1;
            $items .= _service_plan_feature_checkbox($module, $features);
        }
        next unless length $items;
        $html .= <<"HTML";
          <section class="service-plan-feature-group" aria-label="$safe_label">
            <div class="service-plan-feature-group-head">
              <h3>$safe_label</h3>
              <p>$safe_detail</p>
            </div>
            <div class="service-plan-feature-grid">
$items            </div>
          </section>
HTML
    }
    my $other = '';
    for my $module (@{ DesertCMS::Modules::definitions({}) }) {
        my $feature_key = $module->{key} || '';
        next if !$feature_key || $feature_key eq 'contributor_requests' || $rendered{$feature_key};
        $other .= _service_plan_feature_checkbox($module, $features);
    }
    if (length $other) {
        $html .= <<"HTML";
          <section class="service-plan-feature-group" aria-label="Other entitlements">
            <div class="service-plan-feature-group-head">
              <h3>Other entitlements</h3>
              <p>Additional feature flags added by installed modules.</p>
            </div>
            <div class="service-plan-feature-grid">
$other            </div>
          </section>
HTML
    }
    return qq{        <div class="service-plan-feature-groups">\n$html        </div>};
}

sub _service_plan_feature_checkbox {
    my ($module, $features) = @_;
    my $raw_key = $module->{key} || '';
    my $key = escape_html($raw_key);
    my $label = escape_html($module->{label});
    my $description = escape_html($module->{description});
    my $checked = $features->{$raw_key} ? 'checked' : '';
    return <<"HTML";
              <label class="checkbox-field service-plan-feature-option" data-plan-feature-key="$key">
                <input type="checkbox" name="feature_${key}_included" value="1" $checked>
                <span>$label<small>$description</small></span>
              </label>
HTML
}

sub _service_plan_feature_summary {
    my ($plan) = @_;
    my $features = DesertCMS::Modules::feature_map_for_plan($plan);
    my @included;
    for my $module (@{ DesertCMS::Modules::definitions({}) }) {
        next if ($module->{key} || '') eq 'contributor_requests';
        push @included, escape_html($module->{label}) if $features->{ $module->{key} };
    }
    return @included ? join(', ', @included) : '<span class="muted">No contributor-managed features</span>';
}

sub _service_plan_rows {
    my ($self, $plans, $selected_id, $csrf) = @_;
    my $rows = '';
    for my $plan (@{$plans || []}) {
        my $id = int($plan->{id} || 0);
        my $name = escape_html($plan->{name} || '');
        my $default = $plan->{is_default} ? '<span class="status-pill ok">Default</span>' : '';
        my $selected = $selected_id && int($selected_id) == $id ? '<span class="status-pill">Editing</span>' : '';
        my $price = escape_html(_format_money($plan->{monthly_price_cents}, $plan->{currency}));
        my $blueprint_name = $plan->{blueprint_name} || 'Default';
        my $blueprint_vertical = $plan->{blueprint_category}
            ? DesertCMS::Blueprints::vertical_label($plan->{blueprint_category})
            : '';
        my $blueprint = escape_html(length $blueprint_vertical ? "$blueprint_vertical - $blueprint_name" : $blueprint_name);
        my $limits = int($plan->{media_quota_mb} || 0) . ' MB, '
            . int($plan->{media_upload_limit_mb} || 0) . ' MB/file, '
            . int($plan->{post_quota} || 0) . ' posts, '
            . int($plan->{page_quota} || 0) . ' pages';
        my $features = _service_plan_feature_summary($plan);
        my @provider_features;
        push @provider_features, 'Custom Postmark' if $plan->{allow_postmark_sender_override};
        push @provider_features, 'Custom indexing' if $plan->{allow_indexing_override};
        if ($plan->{allow_stripe_connect}) {
            my $fee = sprintf('%.2f', int($plan->{stripe_platform_fee_bps} || 0) / 100);
            $fee =~ s/\.00\z//;
            push @provider_features, "Stripe payouts ($fee% platform fee)";
        }
        my $provider_features = @provider_features
            ? escape_html(join(', ', @provider_features))
            : '<span class="muted">Inherited providers only</span>';
        my $stripe = length($plan->{stripe_price_id} || '')
            ? escape_html($plan->{stripe_price_id})
            : '<span class="muted">No Stripe Price ID</span>';
        my $default_form = '';
        if (!$plan->{is_default}) {
            $default_form = <<"HTML";
<form method="post" action="/admin/settings/plans/default" class="inline-form">
  <input type="hidden" name="csrf_token" value="$csrf">
  <input type="hidden" name="plan_id" value="$id">
  <button type="submit" class="button-link secondary">Make default</button>
</form>
HTML
        }
        $rows .= <<"HTML";
<tr>
  <td data-label="Name"><strong>$name</strong><br>$default $selected</td>
  <td data-label="Price">$price</td>
  <td data-label="Blueprint">$blueprint</td>
  <td data-label="Limits">$limits</td>
  <td data-label="Features">$features</td>
  <td data-label="Provider">$provider_features</td>
  <td data-label="Stripe">$stripe</td>
  <td data-label="Actions" class="table-actions"><a class="button-link secondary" href="/admin/settings/plans?id=$id">Edit</a>$default_form</td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(8, 'No service plans have been created yet.', 'Create a free default plan before contributor sites start accepting upgrades.');
}

sub _service_plan_usage_rows {
    my ($self, $sites) = @_;
    my $rows = '';
    for my $site (@{$sites || []}) {
        my $domain = escape_html($site->{domain} || '');
        my $site_id = escape_html($site->{site_id} || '');
        my $plan = escape_html($site->{service_plan_name} || 'Unassigned');
        my $price = escape_html(_format_money($site->{monthly_price_cents}, $site->{currency}));
        my $billing = _billing_status_pill($site->{billing_status});
        my $billing_email = escape_html($site->{billing_email} || $site->{owner_email} || '');
        my $billing_html = "$billing<br><span class=\"muted\">$billing_email</span>";
        my $usage = $site->{usage} || {};
        my ($media, $posts, $pages);
        if ($usage->{available}) {
            $media = _usage_meter(_format_bytes($usage->{media_bytes}) . ' of ' . int($usage->{media_quota_mb} || 0) . ' MB', $usage->{media_percent});
            $posts = _usage_meter(int($usage->{post_count} || 0) . ' of ' . int($usage->{post_quota} || 0), $usage->{post_percent});
            $pages = _usage_meter(int($usage->{page_count} || 0) . ' of ' . int($usage->{page_quota} || 0), $usage->{page_percent});
        } else {
            my $reason = escape_html($usage->{reason} || 'usage unavailable');
            $media = $posts = $pages = '<span class="muted">' . $reason . '</span>';
        }
        $rows .= <<"HTML";
<tr>
  <td data-label="Site"><strong><a href="https://$domain/">$domain</a></strong><br><span class="muted">$site_id</span></td>
  <td data-label="Plan">$plan<br><span class="muted">$price</span></td>
  <td data-label="Billing">$billing_html</td>
  <td data-label="Media">$media</td>
  <td data-label="Posts">$posts</td>
  <td data-label="Pages">$pages</td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(6, 'No contributor sites are ready for service-plan tracking.', 'Approved contributor sites appear here after they are provisioned.');
}

sub _service_plan_options {
    my ($plans, $selected_id) = @_;
    my $html = '';
    for my $plan (@{$plans || []}) {
        my $id = int($plan->{id} || 0);
        my $name = escape_html($plan->{name} || '');
        my $selected = int($selected_id || 0) == $id ? 'selected' : '';
        $html .= qq{<option value="$id" $selected>$name</option>};
    }
    return $html || '<option value="">Create a service plan first</option>';
}

sub _service_site_options {
    my ($sites) = @_;
    my $html = '';
    for my $site (@{$sites || []}) {
        my $site_id = escape_html($site->{site_id} || '');
        my $domain = escape_html($site->{domain} || '');
        $html .= qq{<option value="$site_id">$domain</option>};
    }
    return $html || '<option value="">No active contributor sites yet</option>';
}

sub _billing_status_options {
    my ($selected) = @_;
    my @statuses = qw(comped trialing active past_due canceled);
    my $html = '';
    for my $status (@statuses) {
        my $label = escape_html(_title_case_status($status));
        my $safe = escape_html($status);
        my $is_selected = ($selected || '') eq $status ? 'selected' : '';
        $html .= qq{<option value="$safe" $is_selected>$label</option>};
    }
    return $html;
}

sub _billing_status_pill {
    my ($status) = @_;
    $status ||= 'comped';
    my $state = $status eq 'active' || $status eq 'trialing' ? 'ok'
        : $status eq 'past_due' ? 'warn'
        : 'neutral';
    return _fleet_state_pill($state, _title_case_status($status));
}

sub _billing_usage_html {
    my ($usage) = @_;
    $usage ||= {};
    return '<p class="muted">' . escape_html($usage->{reason} || 'Usage is unavailable right now.') . '</p>'
        unless $usage->{available};

    my $media_quota_label = int($usage->{media_quota_mb} || 0) > 0
        ? int($usage->{media_quota_mb}) . ' MB'
        : 'plan limit';
    my $html = '<div class="billing-usage-stack"><div class="billing-usage-grid">'
        . _usage_meter(_format_bytes($usage->{media_bytes}) . ' of ' . $media_quota_label . ' media', $usage->{media_percent})
        . _usage_meter(int($usage->{post_count} || 0) . ' of ' . int($usage->{post_quota} || 0) . ' posts', $usage->{post_percent})
        . _usage_meter(int($usage->{page_count} || 0) . ' of ' . int($usage->{page_quota} || 0) . ' pages', $usage->{page_percent})
        . '</div>'
        . _billing_media_breakdown_html($usage)
        . _billing_media_pressure_notice_html($usage)
        . '</div>';
    return $html;
}

sub _billing_media_breakdown_html {
    my ($usage) = @_;
    my $remaining = int($usage->{media_quota_bytes} || 0) > 0
        ? _format_bytes($usage->{media_remaining_bytes})
        : 'Upgrade to raise storage';
    my $upload_limit = int($usage->{media_upload_limit_bytes} || 0) > 0
        ? _format_bytes($usage->{media_upload_limit_bytes})
        : 'Plan default';
    my $resource_downloads = $usage->{resource_publishing_included}
        ? 'Included'
        : 'Requires upgrade';
    my @items = (
        [ 'Total assets', int($usage->{media_count} || 0), _format_bytes($usage->{media_bytes}), 'All active source assets counted against the plan.' ],
        [ 'Images', int($usage->{media_image_count} || 0), _format_bytes($usage->{media_image_bytes}), 'Private image sources with public optimized derivatives.' ],
        [ 'Documents/files', int($usage->{media_document_count} || 0), _format_bytes($usage->{media_document_bytes}), 'Documents, data files, audio, video, and resource source assets.' ],
        [ 'Public resources', int($usage->{media_resource_count} || 0), _format_bytes($usage->{media_resource_bytes}), 'Published downloads available to Resource blocks.' ],
        [ 'Private source only', int($usage->{media_private_count} || 0), _format_bytes($usage->{media_private_bytes}), 'Stored files that are not publicly surfaced.' ],
        [ 'Upload limit', '', $upload_limit, 'Largest source asset allowed per upload on the current plan and server cap.' ],
        [ 'Resource Downloads', '', $resource_downloads, 'Controls whether new private source files can be published publicly.' ],
        [ 'Remaining storage', '', $remaining, 'Storage left on the current plan.' ],
    );
    my $html = '<dl class="billing-media-breakdown" aria-label="Media storage breakdown">';
    for my $item (@items) {
        $html .= _billing_media_breakdown_item(@{$item});
    }
    $html .= '</dl>';
    return $html;
}

sub _billing_media_breakdown_item {
    my ($label, $count, $value, $detail) = @_;
    my $safe_label = escape_html($label || '');
    my $safe_count = defined($count) && "$count" ne '' ? '<span>' . escape_html($count) . '</span>' : '';
    my $safe_value = escape_html($value || '0 B');
    my $safe_detail = escape_html($detail || '');
    return qq{<div><dt>$safe_label</dt><dd>$safe_count<strong>$safe_value</strong><small>$safe_detail</small></dd></div>};
}

sub _usage_meter {
    my ($label, $pct) = @_;
    $pct = int($pct || 0);
    $pct = 100 if $pct > 100;
    $pct = 0 if $pct < 0;
    my $state = $pct >= 90 ? ' warn' : '';
    return '<div class="usage-meter' . $state . '"><div><span>'
        . escape_html($label)
        . '</span><strong>'
        . $pct
        . '%</strong></div><i><b style="width: '
        . $pct
        . '%"></b></i></div>';
}

sub _price_dollars {
    my ($cents) = @_;
    $cents = int($cents || 0);
    return sprintf('%.2f', $cents / 100);
}

sub _format_money {
    my ($cents, $currency) = @_;
    $cents = int($cents || 0);
    $currency = uc($currency || 'usd');
    return $currency . ' ' . sprintf('%.2f', $cents / 100);
}

sub _theme_options {
    my ($self, $selected, $mode) = @_;
    $mode = $mode && $mode eq 'dark' ? 'dark' : 'light';
    $selected = $self->_clean_theme_preset($selected, $mode);
    my $html = '';
    for my $preset (@{DesertCMS::SiteTheme::presets_for_mode($mode)}) {
        my $id = escape_html($preset->{id});
        my $name = escape_html($preset->{name});
        my $checked = $selected eq $preset->{id} ? 'selected' : '';
        $html .= qq{<option value="$id" $checked>$name</option>};
    }
    return $html;
}

sub _settings_sites_page {
    my ($self, $request, $session, $session_token, $message) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    $message ||= _sites_notice($request);
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $settings_nav = $self->_settings_nav('sites', $session);
    my $contributor_nav = $self->_contributor_settings_nav('sites', $session);
    my $site_rows = $self->_contributor_site_rows($csrf, 'active');
    my $disabled_site_rows = $self->_contributor_site_rows($csrf, 'disabled');
    my $archived_site_rows = $self->_archived_site_rows(eval { $self->{sites}->list_archived_sites(limit => 100) } || []);
    my $queue_rows = $self->_contributor_queue_rows($csrf);

    my $body = <<"HTML";
<section class="editor-workspace">
  $settings_nav
  $contributor_nav
  <section class="panel">
    <div class="split">
      <div>
        <p class="eyebrow">Settings</p>
        <h1>Contributor Sites</h1>
        <p>Manage contributor subdomains and queued deployment actions.</p>
      </div>
      <a class="button-link secondary" href="/admin/settings/contributors">Invite contributor</a>
    </div>
    $notice
    <section class="inspector-panel">
      <h2>Active Sites</h2>
      <table class="content-table compact-table admin-card-table">
        <thead><tr><th>Site</th><th>Owner</th><th>Blueprint</th><th>Status</th><th>Actions</th></tr></thead>
        <tbody>$site_rows</tbody>
      </table>
    </section>
    <section class="inspector-panel">
      <h2>Disabled Sites</h2>
      <table class="content-table compact-table admin-card-table">
        <thead><tr><th>Site</th><th>Owner</th><th>Blueprint</th><th>Status</th><th>Actions</th></tr></thead>
        <tbody>$disabled_site_rows</tbody>
      </table>
    </section>
    <section class="inspector-panel">
      <h2>Archived Sites</h2>
      <table class="content-table compact-table admin-card-table">
        <thead><tr><th>Contributor</th><th>Domain</th><th>Archive</th><th>Archived</th><th>Size</th></tr></thead>
        <tbody>$archived_site_rows</tbody>
      </table>
    </section>
    <section class="inspector-panel">
      <h2>Provisioning Queue</h2>
      <table class="content-table compact-table admin-card-table">
        <thead><tr><th>Site</th><th>Action</th><th>Status</th><th>Last step</th><th>Updated</th><th>Actions</th></tr></thead>
        <tbody>$queue_rows</tbody>
      </table>
    </section>
  </section>
</section>
HTML

    return $self->_html_response('Contributor Sites', $body, $session);
}

sub _sites_notice {
    my ($request) = @_;
    return '' unless $request;
    my $notice = $request->param('notice') || '';
    return 'Site action queued.' if $notice eq 'site-action-queued';
    return 'Contributor site access granted and emailed.' if $notice eq 'site-access-granted';
    return 'Contributor site access was created, but email was not sent. Check the Delivery Log before retrying email.' if $notice eq 'site-access-email-failed';
    return '';
}

sub _settings_modules_page {
    my ($self, $request, $session, $session_token, $message) = @_;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $settings_nav = $self->_module_setup_nav('modules', $session, $settings);
    my $is_contributor_product = DesertCMS::CapabilityPolicy::contributor_product_mode($self->{config});
    my $surface_eyebrow = $is_contributor_product ? 'Features' : 'Settings';
    my $surface_heading = $is_contributor_product ? 'Features' : 'Modules';
    my $surface_intro = $is_contributor_product
        ? 'Features available on your plan. Turn included features on or off, review locked upgrades, and open setup for each feature.'
        : 'A module is an optional first-party feature bundle. Enabling one can add a public subpage, generated assets, and its own admin controls.';
    my $catalog_label = $is_contributor_product ? 'Feature Catalog' : 'Module Catalog';
    my $workspace_heading = $is_contributor_product ? 'Feature setup' : 'Module setup';
    my $workspace_intro = $is_contributor_product
        ? 'Feature setup pages open below the feature navigation with status, copy, routing, and plan-aware controls kept together.'
        : 'Module setup pages open below the module navigation with status, copy, routing, and module-specific controls kept together.';
    my $managed_label = $is_contributor_product ? 'Managed by platform' : 'Managed by master';
    my $managed_detail = $is_contributor_product
        ? 'Platform-controlled features inherited by this hosted site.'
        : 'Platform-controlled features inherited from the master CMS.';
    my $enabled_detail = $is_contributor_product
        ? 'Site features currently generating public output or tools.'
        : 'Feature bundles currently generating public output or admin tools.';
    my $public_pages_detail = $is_contributor_product
        ? 'Enabled features with public routes.'
        : 'Enabled modules with public routes.';
    my $total_detail = $is_contributor_product
        ? 'First-party site features.'
        : 'First-party DesertCMS feature modules.';
    my $response_title = $is_contributor_product ? 'Features' : 'Modules';
    my ($enabled_count, $available_count, $locked_count, $managed_count, $public_page_count) = (0, 0, 0, 0, 0);
    for my $module (@{DesertCMS::Modules::catalog($settings, config => $self->{config})}) {
        if ($module->{enabled}) {
            $enabled_count++;
            $public_page_count++ if length($module->{public_path} || '');
        }
        $available_count++ if $module->{available};
        $locked_count++ if $module->{locked_by_plan};
        $managed_count++ if $module->{managed_by_master};
    }
    my $module_total = scalar @{DesertCMS::Modules::feature_keys()};
    my $modules_summary = _settings_summary_strip(
        [ 'Enabled', "<strong>$enabled_count</strong>", $enabled_detail ],
        [ 'Available', "<strong>$available_count</strong>", 'Features this role can manage on the current plan.' ],
        [ 'Locked by plan', "<strong>$locked_count</strong>", 'Features that require a plan upgrade before they can be enabled.' ],
        [ $managed_label, "<strong>$managed_count</strong>", $managed_detail ],
        [ 'Public pages', "<strong>$public_page_count</strong>", $public_pages_detail ],
        [ 'Total features', "<span class=\"status-pill status-pill--neutral\">$module_total catalogued</span>", $total_detail ],
    );

    my $body = <<"HTML";
<section class="editor-workspace">
  $settings_nav
  <section class="panel">
    <div class="split">
      <div>
        <p class="eyebrow">$surface_eyebrow</p>
        <h1>$surface_heading</h1>
        <p>$surface_intro</p>
      </div>
    </div>
    $notice
    $modules_summary
    <section class="inspector-panel module-catalog-landing" id="module-catalog-workspace">
      <div class="split">
        <div>
          <p class="eyebrow">$catalog_label</p>
          <h2>$workspace_heading</h2>
          <p>$workspace_intro</p>
        </div>
        <span class="status-pill status-pill--neutral">$module_total catalogued</span>
      </div>
    </section>
  </section>
</section>
HTML

    return $self->_html_response($response_title, $body, $session);
}

sub _settings_modules_save {
    my ($self, $request, $session, $session_token) = @_;
    my $ok = eval {
        my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
        my %values;
        for my $module (@{ DesertCMS::Modules::catalog($settings, config => $self->{config}) }) {
            my $setting_key = $module->{setting_key} || '';
            next unless length $setting_key;
            my $enabled = _module_toggle_value($module, $request);
            $values{$setting_key} = $enabled;
            $values{shop_enabled} = $enabled if ($module->{key} || '') eq 'shop';
        }
        DesertCMS::Settings::set_many($self->{config}, $self->{db}, \%values);
        $self->{shop}->clear_settings_cache;
        $self->{bookings}->clear_settings_cache;
        $self->{membership}->clear_settings_cache;
        $self->{newsletter}->clear_settings_cache;
        $self->{content}->rebuild_all;
        1;
    };

    if (!$ok) {
        my $is_contributor_product = DesertCMS::CapabilityPolicy::contributor_product_mode($self->{config});
        return $self->_settings_modules_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                $is_contributor_product ? 'The feature settings could not be saved.' : 'The module settings could not be saved.',
                $is_contributor_product ? 'Check the selected features and rebuild permissions, then try again.' : 'Check the selected modules and rebuild permissions, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'settings.modules_saved',
        subject_type => 'settings',
        details      => { rebuilt => 1 },
    );
    return $self->_settings_modules_page(
        $request,
        $session,
        $session_token,
        DesertCMS::CapabilityPolicy::contributor_product_mode($self->{config})
            ? 'Features saved and public site rebuilt.'
            : 'Modules saved and public site rebuilt.'
    );
}

sub _admin_accounts_page {
    my ($self, $request, $session, $session_token, $message) = @_;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    return $self->_not_found unless DesertCMS::Modules::enabled($settings, 'accounts');
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $settings_nav = $self->_module_setup_nav('accounts', $session, $settings);
    my $accounts = $self->{accounts}->list_accounts(limit => 250);
    my $groups = $self->{accounts}->groups;
    my $audit_events = $self->{accounts}->audit_events(limit => 50);
    my $active = scalar grep { ($_->{status} || '') eq 'active' } @{$accounts};
    my $moderated = scalar grep { ($_->{status} || '') eq 'moderated' || ($_->{status} || '') eq 'pending' } @{$accounts};
    my $disabled = scalar grep { ($_->{status} || '') eq 'disabled' } @{$accounts};
    my $identity_count = 0;
    $identity_count += int($_->{identity_count} || 0) for @{$accounts};
    my $summary = _settings_summary_strip(
        [ 'Active', "<strong>$active</strong>", 'Accounts allowed to sign in.' ],
        [ 'Moderation', "<strong>$moderated</strong>", 'Pending or moderated accounts.' ],
        [ 'Disabled', "<strong>$disabled</strong>", 'Accounts blocked from sign-in.' ],
        [ 'SSO identities', "<strong>$identity_count</strong>", 'Linked Google/OIDC provider subjects.' ],
        [ 'Groups', '<strong>' . scalar(@{$groups}) . '</strong>', 'Reusable account groups for Forums, Social, Shop, and streaming.' ],
    );
    my $rows = $self->_admin_account_rows($accounts, $csrf);
    my $group_rows = $self->_admin_account_group_rows($groups);
    my $audit_rows = $self->_admin_account_audit_rows($audit_events);
    my $section_nav = _module_section_nav(
        'Account module sections',
        [ '#accounts-list', 'Accounts' ],
        [ '#accounts-create', 'Create Account' ],
        [ '#accounts-groups', 'Groups' ],
        [ '#accounts-sso', 'SSO' ],
        [ '#accounts-audit', 'Audit' ],
    );
    my $body = <<"HTML";
<section class="editor-workspace">
  $settings_nav
  <section class="panel">
    <div class="split">
      <div>
        <p class="eyebrow">@{[_admin_feature_eyebrow($self->{config})]}</p>
        <h1>Accounts</h1>
        <p>Unified public identity for Shop carts, order history, Forums, Social, Live Streaming chat, notification preferences, and public profiles.</p>
      </div>
      <a class="button-link secondary" href="/account">Open public account</a>
    </div>
    $notice
    $summary
    $section_nav
    <section class="inspector-panel" id="accounts-list">
      <h2>Public Accounts</h2>
      <table class="content-table compact-table admin-card-table">
        <thead><tr><th>Account</th><th>Status</th><th>Groups</th><th>SSO</th><th>Last Login</th><th>Actions</th></tr></thead>
        <tbody>$rows</tbody>
      </table>
    </section>
    <section class="inspector-panel" id="accounts-create">
      <h2>Create Account</h2>
      <form method="post" action="/admin/accounts/create" class="settings-form settings-form--wide">
        <input type="hidden" name="csrf_token" value="$csrf">
        <div class="settings-grid settings-grid--two">
          <label><span>Email</span><input name="email" type="email" autocomplete="email" required></label>
          <label><span>Username</span><input name="username" autocomplete="username"></label>
          <label><span>Display name</span><input name="display_name" autocomplete="name"></label>
          <label><span>Status</span><select name="status">@{[_account_status_options('active')]}</select></label>
          <label><span>Password</span><input name="password" type="password" autocomplete="new-password" minlength="10" required></label>
          <label><span>Confirm password</span><input name="password_confirm" type="password" autocomplete="new-password" minlength="10" required></label>
        </div>
        <button type="submit">Create account</button>
      </form>
    </section>
    <section class="inspector-panel" id="accounts-groups">
      <h2>Groups</h2>
      <table class="content-table compact-table admin-card-table">
        <thead><tr><th>Name</th><th>Slug</th><th>Accounts</th><th>Description</th></tr></thead>
        <tbody>$group_rows</tbody>
      </table>
      <form method="post" action="/admin/accounts/groups/create" class="settings-form settings-form--wide">
        <input type="hidden" name="csrf_token" value="$csrf">
        <div class="settings-grid settings-grid--two">
          <label><span>Name</span><input name="name" required></label>
          <label><span>Slug</span><input name="slug"></label>
        </div>
        <label><span>Description</span><textarea name="description" rows="3"></textarea></label>
        <button type="submit">Create group</button>
      </form>
    </section>
    <section class="inspector-panel" id="accounts-sso">
      <h2>SSO Providers</h2>
      <p class="muted">Local password accounts are active now. Google and generic OIDC identities are stored in <code>user_identities</code>; provider client settings are managed through the Accounts module contract before OAuth callback activation.</p>
    </section>
    <section class="inspector-panel" id="accounts-audit">
      <h2>Recent Account Security Events</h2>
      <table class="content-table compact-table admin-card-table">
        <thead><tr><th>Event</th><th>Account</th><th>Provider</th><th>When</th><th>Details</th></tr></thead>
        <tbody>$audit_rows</tbody>
      </table>
    </section>
  </section>
</section>
HTML
    return $self->_html_response('Accounts', $body, $session);
}

sub _admin_accounts_create {
    my ($self, $request, $session, $session_token) = @_;
    return $self->_admin_accounts_page($request, $session, $session_token, 'Passwords do not match.')
        unless ($request->param('password') || '') eq ($request->param('password_confirm') || '');
    my $account = eval {
        $self->{accounts}->create_account(
            email        => $request->param('email'),
            username     => $request->param('username'),
            display_name => $request->param('display_name'),
            password     => $request->param('password'),
            status       => $request->param('status') || 'active',
        );
    };
    if (!$account) {
        return $self->_admin_accounts_page($request, $session, $session_token, $@ || 'The account could not be created.');
    }
    $self->_audit_admin_action(
        $session,
        action       => 'accounts.created',
        subject_type => 'account',
        subject_id   => $account->{id},
        details      => { email => $account->{email}, status => $account->{status} },
    );
    return $self->_admin_accounts_page($request, $session, $session_token, 'Account created.');
}

sub _admin_accounts_status {
    my ($self, $request, $session, $session_token) = @_;
    my $account = eval {
        $self->{accounts}->set_status(
            id              => $request->param('account_id'),
            status          => $request->param('status'),
            moderation_note => $request->param('moderation_note'),
            admin_user_id   => $session->{user_id},
        );
    };
    if (!$account) {
        return $self->_admin_accounts_page($request, $session, $session_token, $@ || 'The account status could not be saved.');
    }
    $self->_audit_admin_action(
        $session,
        action       => 'accounts.status_saved',
        subject_type => 'account',
        subject_id   => $account->{id},
        details      => { status => $account->{status} },
    );
    return $self->_admin_accounts_page($request, $session, $session_token, 'Account status saved.');
}

sub _admin_account_group_create {
    my ($self, $request, $session, $session_token) = @_;
    my $group = eval {
        $self->{accounts}->save_group(
            name        => $request->param('name'),
            slug        => $request->param('slug'),
            description => $request->param('description'),
        );
    };
    if (!$group) {
        return $self->_admin_accounts_page($request, $session, $session_token, $@ || 'The group could not be created.');
    }
    $self->_audit_admin_action(
        $session,
        action       => 'accounts.group_saved',
        subject_type => 'account_group',
        subject_id   => $group->{id},
        details      => { slug => $group->{slug} },
    );
    return $self->_admin_accounts_page($request, $session, $session_token, 'Account group saved.');
}

sub _admin_account_rows {
    my ($self, $accounts, $csrf) = @_;
    my $rows = '';
    for my $account (@{$accounts || []}) {
        my $id = int($account->{id} || 0);
        my $name = escape_html($account->{display_name} || $account->{username} || $account->{email});
        my $email = escape_html($account->{email} || '');
        my $username = escape_html($account->{username} || '');
        my $status = escape_html($account->{status} || 'active');
        my $groups = escape_html($account->{group_names} || 'No groups');
        my $identity_count = int($account->{identity_count} || 0);
        my $last_login = escape_html(_format_time($account->{last_login_at}));
        my $note = escape_html($account->{moderation_note} || '');
        my $options = _account_status_options($account->{status});
        $rows .= <<"HTML";
<tr>
  <td data-label="Account"><strong>$name</strong><br><span class="muted">$email</span><br><code>$username</code></td>
  <td data-label="Status"><span class="status-pill">$status</span></td>
  <td data-label="Groups">$groups</td>
  <td data-label="SSO">$identity_count</td>
  <td data-label="Last Login">$last_login</td>
  <td data-label="Actions">
    <form method="post" action="/admin/accounts/status" class="inline-form">
      <input type="hidden" name="csrf_token" value="$csrf">
      <input type="hidden" name="account_id" value="$id">
      <select name="status">$options</select>
      <input name="moderation_note" value="$note" placeholder="Moderation note">
      <button type="submit" class="button-link secondary button-link--compact">Save</button>
    </form>
  </td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(6, 'No public accounts yet.', 'Created accounts and SSO identities will appear here.');
}

sub _admin_account_group_rows {
    my ($self, $groups) = @_;
    my $rows = '';
    for my $group (@{$groups || []}) {
        my $name = escape_html($group->{name} || '');
        my $slug = escape_html($group->{slug} || '');
        my $description = escape_html($group->{description} || '');
        my $count = int($group->{account_count} || 0);
        $rows .= <<"HTML";
<tr>
  <td data-label="Name"><strong>$name</strong></td>
  <td data-label="Slug"><code>$slug</code></td>
  <td data-label="Accounts">$count</td>
  <td data-label="Description">$description</td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(4, 'No account groups yet.', 'Groups can be reused by Forums, Social, Live Streaming chat, Shop, and notification preferences.');
}

sub _admin_account_audit_rows {
    my ($self, $events) = @_;
    my $rows = '';
    for my $event (@{$events || []}) {
        my $type = escape_html($event->{event_type} || '');
        my $account = int($event->{account_id} || 0) || '<span class="muted">Unknown</span>';
        $account = "#$account" if $account =~ /\A[0-9]+\z/;
        my $provider = escape_html($event->{provider} || 'local');
        my $when = escape_html(_format_time($event->{created_at}));
        my $details = $event->{details} && ref($event->{details}) eq 'HASH'
            ? join(', ', map { escape_html($_ . '=' . ($event->{details}{$_} // '')) } sort keys %{ $event->{details} })
            : '';
        $details ||= '<span class="muted">No details</span>';
        $rows .= <<"HTML";
<tr>
  <td data-label="Event"><code>$type</code></td>
  <td data-label="Account">$account</td>
  <td data-label="Provider">$provider</td>
  <td data-label="When">$when</td>
  <td data-label="Details">$details</td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(5, 'No account audit events yet.', 'Login, logout, SSO, provider link, and moderation events will appear here.');
}

sub _account_status_options {
    my ($selected) = @_;
    $selected = lc($selected || 'active');
    my @options = (
        [ active    => 'Active' ],
        [ pending   => 'Pending' ],
        [ moderated => 'Moderated' ],
        [ disabled  => 'Disabled' ],
    );
    return join '', map {
        my ($value, $label) = @{$_};
        my $is_selected = $value eq $selected ? ' selected' : '';
        '<option value="' . escape_html($value) . '"' . $is_selected . '>' . escape_html($label) . '</option>';
    } @options;
}

sub _v3_module_admin_path {
    my ($key) = @_;
    return {
        accounts       => '/admin/accounts',
        forums         => '/admin/forums',
        social         => '/admin/social',
        live_streaming => '/admin/live',
    }->{$key || ''} || '';
}

sub _admin_forums_page {
    my ($self, $request, $session, $session_token, $message) = @_;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    return $self->_not_found unless DesertCMS::Modules::enabled($settings, 'forums');
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $settings_nav = $self->_module_setup_nav('forums', $session, $settings);
    my $categories = $self->{forums}->categories(include_hidden => 1);
    my $topics = $self->{forums}->latest_topics(limit => 50);
    my $reports = $self->{forums}->reports(status => 'open');
    my $category_rows = $self->_admin_forum_category_rows($categories, $csrf);
    my $topic_rows = $self->_admin_forum_topic_rows($topics, $csrf);
    my $report_rows = $self->_admin_forum_report_rows($reports, $csrf);
    my $summary = _settings_summary_strip(
        [ 'Categories', '<strong>' . scalar(@{$categories}) . '</strong>', 'Open, locked, hidden, account-only, and moderator-only forum areas.' ],
        [ 'Recent topics', '<strong>' . scalar(@{$topics}) . '</strong>', 'Latest public topics across categories.' ],
        [ 'Open reports', '<strong>' . scalar(@{$reports}) . '</strong>', 'Topic and reply reports waiting for moderator review.' ],
        [ 'Identity', '<span class="status-pill ok">Accounts required</span>', 'Topic and reply writes use unified public accounts.' ],
        [ 'Notifications', '<span class="status-pill status-pill--neutral">forums.*</span>', 'Topic, reply, mention, report, and moderation events flow to the central bus.' ],
    );
    my $body = <<"HTML";
<section class="editor-workspace">
  $settings_nav
  <section class="panel">
    <div class="split">
      <div>
        <p class="eyebrow">@{[_admin_feature_eyebrow($self->{config})]}</p>
        <h1>Forums</h1>
        <p>Categories, topics, replies, moderation, permissions, reporting, and notifications backed by unified Accounts.</p>
      </div>
      <a class="button-link secondary" href="/forums">Open forums</a>
    </div>
    $notice
    $summary
    <section class="inspector-panel">
      <h2>Categories</h2>
      <table class="content-table compact-table admin-card-table">
        <thead><tr><th>Category</th><th>Status</th><th>Visibility</th><th>Position</th><th>Topics</th><th>Posts</th><th>Actions</th></tr></thead>
        <tbody>$category_rows</tbody>
      </table>
    </section>
    <section class="inspector-panel">
      <h2>Create Category</h2>
      <form method="post" action="/admin/forums/categories/create" class="settings-form settings-form--wide">
        <input type="hidden" name="csrf_token" value="$csrf">
        <div class="settings-grid settings-grid--two">
          <label><span>Title</span><input name="title" required></label>
          <label><span>Slug</span><input name="slug"></label>
          <label><span>Position</span><input name="position" type="number" value="100"></label>
          <label><span>Status</span><select name="status">@{[_forum_category_status_options('open')]}</select></label>
          <label><span>Visibility</span><select name="visibility">@{[_forum_category_visibility_options('public')]}</select></label>
        </div>
        <label><span>Description</span><textarea name="description" rows="3"></textarea></label>
        <button type="submit">Create category</button>
      </form>
    </section>
    <section class="inspector-panel">
      <h2>Recent Topics</h2>
      <table class="content-table compact-table admin-card-table">
        <thead><tr><th>Topic</th><th>Category</th><th>Status</th><th>Replies</th><th>Actions</th></tr></thead>
        <tbody>$topic_rows</tbody>
      </table>
    </section>
    <section class="inspector-panel">
      <h2>Report Queue</h2>
      <table class="content-table compact-table admin-card-table">
        <thead><tr><th>Report</th><th>Target</th><th>Status</th><th>Reporter</th><th>Actions</th></tr></thead>
        <tbody>$report_rows</tbody>
      </table>
    </section>
  </section>
</section>
HTML
    return $self->_html_response('Forums', $body, $session);
}

sub _admin_forum_category_create {
    my ($self, $request, $session, $session_token) = @_;
    my $category = eval {
        $self->{forums}->save_category(
            title       => $request->param('title'),
            slug        => $request->param('slug'),
            description => $request->param('description'),
            position    => $request->param('position'),
            status      => $request->param('status'),
            visibility  => $request->param('visibility'),
        );
    };
    return $self->_admin_forums_page($request, $session, $session_token, $@ || 'The forum category could not be saved.') unless $category;
    $self->_audit_admin_action($session, action => 'forums.category_saved', subject_type => 'forum_category', subject_id => $category->{id}, details => { slug => $category->{slug} });
    return $self->_admin_forums_page($request, $session, $session_token, 'Forum category saved.');
}

sub _admin_forum_category_update {
    my ($self, $request, $session, $session_token) = @_;
    my $existing = $self->{forums}->category_by_id($request->param('category_id'));
    return $self->_admin_forums_page($request, $session, $session_token, 'The forum category was not found.') unless $existing;
    my $category = eval {
        $self->{forums}->save_category(
            id          => $existing->{id},
            title       => $existing->{title},
            slug        => $existing->{slug},
            description => $existing->{description},
            position    => $request->param('position'),
            status      => $request->param('status'),
            visibility  => $request->param('visibility'),
        );
    };
    return $self->_admin_forums_page($request, $session, $session_token, $@ || 'The forum category policy could not be saved.') unless $category;
    $self->_audit_admin_action($session, action => 'forums.category_policy_saved', subject_type => 'forum_category', subject_id => $category->{id}, details => { status => $category->{status}, visibility => $category->{visibility}, position => int($category->{position} || 0) });
    return $self->_admin_forums_page($request, $session, $session_token, 'Forum category policy saved.');
}

