sub _module_map_settings_save {
    my ($self, $request, $session, $session_token) = @_;
    my $ok = eval {
        my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
        DesertCMS::Settings::set_many($self->{config}, $self->{db}, {
            module_map_enabled  => _module_toggle_value($self->_module_feature_state($settings, 'map'), $request),
            map_street_tile_url => _clean_tile_url($request->param('map_street_tile_url'), 'https://tile.openstreetmap.org/{z}/{x}/{y}.png'),
            map_street_attribution => _clean_map_attribution($request->param('map_street_attribution'), '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap contributors</a>'),
            map_satellite_tile_url => _clean_tile_url($request->param('map_satellite_tile_url'), 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}'),
            map_satellite_attribution => _clean_map_attribution($request->param('map_satellite_attribution'), 'Imagery &copy; Esri and its data providers'),
            map_default_layer => ($request->param('map_default_layer') || '') eq 'satellite' ? 'satellite' : 'street',
            map_default_lat   => _clean_map_coordinate($request->param('map_default_lat'), -90, 90, '34.500000'),
            map_default_lng   => _clean_map_coordinate($request->param('map_default_lng'), -180, 180, '-112.000000'),
            map_default_zoom  => _clean_map_zoom($request->param('map_default_zoom')),
        });
        $self->{content}->rebuild_all;
        1;
    };

    if (!$ok) {
        return $self->_module_map_settings_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The Map / Locations settings could not be saved.',
                'Check the tile URLs, attribution, default coordinates, and zoom level, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'settings.module_map_saved',
        subject_type => 'settings',
        details      => { rebuilt => 1 },
    );
    return $self->_module_map_settings_page($request, $session, $session_token, 'Map / Locations saved and public site rebuilt.');
}

