</section>
HTML

    return $self->_html_response($response_title, $body, $session);
}

sub _module_forms_settings_save {
    my ($self, $request, $session, $session_token) = @_;
    my $ok = eval {
        my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
        DesertCMS::Settings::set_many($self->{config}, $self->{db}, {
            module_forms_enabled => _module_toggle_value($self->_module_feature_state($settings, 'forms'), $request),
            forms_title => _clean_module_text($request->param('forms_title'), 100, 'Contact'),
            forms_intro => _clean_module_text($request->param('forms_intro'), 500, 'Send a message, request a quote, apply, complete an intake, or RSVP.'),
            forms_button_label => _clean_module_text($request->param('forms_button_label'), 80, 'Send message'),
            forms_success_message => _clean_module_text($request->param('forms_success_message'), 200, 'Thanks. Your message has been received.'),
            forms_enabled_types => _clean_enabled_form_types($request),
            forms_uploads_enabled => $request->param('forms_uploads_enabled') ? 1 : 0,
            forms_max_upload_mb => _clean_forms_upload_mb($request->param('forms_max_upload_mb')),
            forms_notify_postmark_enabled => $request->param('forms_notify_postmark_enabled') ? 1 : 0,
            forms_notification_email => _clean_email($request->param('forms_notification_email')),
        });
        $self->{content}->rebuild_all;
        1;
    };

    if (!$ok) {
        return $self->_module_forms_settings_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The Forms module settings could not be saved.',
                'Check the form title, intro, and button text, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'settings.module_forms_saved',
        subject_type => 'settings',
        details      => { rebuilt => 1 },
    );
    return $self->_module_forms_settings_page($request, $session, $session_token, 'Forms module saved and public site rebuilt.');
}

sub _module_docs_settings_page {
    my ($self, $request, $session, $session_token, $message) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $settings_nav = $self->_module_setup_nav('docs', $session, $settings);
    my $docs_feature = $self->_module_feature_state($settings, 'docs');
    my $enabled_state = _module_status_html($docs_feature, $self->{config});
    my $enabled_control = _module_toggle_control($docs_feature, 'module_docs_enabled', 'Enable Docs / Resource Hub', $self->{config});
    my $docs_title = escape_html($settings->{docs_title} || 'Resource Hub');
    my $docs_intro = escape_html($settings->{docs_intro} || '');
    my $configured_source = escape_html($settings->{docs_source_dir} || '');
    my $docs = DesertCMS::Docs->new(config => $self->{config});
    my $resolved_source = escape_html($docs->docs_dir($settings));
    my $documents = $docs->documents(settings => $settings);
    my $doc_count = scalar @{$documents};
    my $doc_count_label = $doc_count == 1 ? '1 resource file' : "$doc_count resource files";
    my $public_count = scalar grep { $_->{public_access} } @{$documents};
    my $held_count = $doc_count - $public_count;
    my $public_count_label = $public_count == 1 ? '1 public page' : "$public_count public pages";
    my $held_count_label = $held_count == 1 ? '1 held resource' : "$held_count held resources";
    my %resource_types = map { ($_->{resource_type} || 'Documentation') => 1 } @{$documents};
    my $resource_type_count = scalar keys %resource_types;
    my $resource_type_label = $resource_type_count == 1 ? '1 resource type' : "$resource_type_count resource types";
    my $doc_rows = '';
    for my $doc (@{$documents}) {
        my $title = escape_html($doc->{title});
        my $type = escape_html($doc->{resource_type} || 'Documentation');
        my $section = escape_html($doc->{audience} || 'General');
        my $url = escape_html($doc->{url});
        my $source = escape_html($doc->{source_rel});
        my $output = $doc->{public_access}
            ? qq{<a href="$url">$url</a>}
            : '<span class="status-pill status-pill--neutral">Held in admin</span>';
        $doc_rows .= qq{<tr><td data-label="Title">$title</td><td data-label="Type">$type</td><td data-label="Section">$section</td><td data-label="Source"><code>$source</code></td><td data-label="Public output">$output</td></tr>};
    }
    $doc_rows ||= _admin_empty_row(
        5,
        'No resource files found.',
        'Add Markdown files to the configured source directory, or leave the source blank to use the bundled DesertCMS resource hub.'
    );
    my $feature_eyebrow = _admin_feature_eyebrow($self->{config});
    my $is_contributor_product = DesertCMS::CapabilityPolicy::contributor_product_mode($self->{config});
    my $save_label = $is_contributor_product ? 'Save resource hub settings and rebuild' : 'Save Docs / Resource Hub and rebuild';
    my $response_title = $is_contributor_product ? 'Docs / Resource Hub Feature' : 'Docs / Resource Hub Module';
    my $docs_intro_text = $is_contributor_product
        ? 'Catalog guides, FAQs, member resources, help articles, and archive materials from approved Markdown files. Only public resources generate <code>/docs/</code> pages.'
        : 'Catalog server-side Markdown resources and publish public entries into the generated <code>/docs/</code> resource hub. Member and private entries can be served through Membership / Gated Content when that module is enabled. Raw HTML is escaped before publishing.';
    my $section_nav = _module_section_nav(
        'Docs / Resource Hub setup sections',
        [ '#docs-status', 'Status' ],
        [ '#docs-copy', 'Copy & Source' ],
        [ '#docs-catalog', 'Resource Catalog' ],
    );

    my $body = <<"HTML";
<section class="editor-workspace">
  $settings_nav
  <section class="panel">
    <div class="split">
      <div>
        <p class="eyebrow">$feature_eyebrow</p>
        <h1>Docs / Resource Hub</h1>
        <p>$docs_intro_text</p>
      </div>
      <a class="button-link secondary" href="/docs/">Open resource hub</a>
    </div>
    $notice
    $section_nav
    <form method="post" action="/admin/settings/modules/docs/save" class="settings-form settings-form--wide">
      <input type="hidden" name="csrf_token" value="$csrf">
      <section class="inspector-panel" id="docs-status">
        <h2>Status</h2>
        <dl class="health-list health-list--compact">
          <div><dt>Public path</dt><dd><code>/docs/</code></dd></div>
          <div><dt>Status</dt><dd>$enabled_state</dd></div>
          <div><dt>Files found</dt><dd>$doc_count_label</dd></div>
          <div><dt>Public output</dt><dd>$public_count_label</dd></div>
          <div><dt>Held resources</dt><dd>$held_count_label</dd></div>
          <div><dt>Resource types</dt><dd>$resource_type_label</dd></div>
          <div><dt>Resolved source</dt><dd><code>$resolved_source</code></dd></div>
        </dl>
        $enabled_control
      </section>
      <section class="inspector-panel" id="docs-copy">
        <h2>Resource Hub Copy</h2>
        <label>
          <span>Title</span>
          <input name="docs_title" value="$docs_title" maxlength="100">
        </label>
        <label>
          <span>Intro</span>
          <textarea name="docs_intro" rows="4" maxlength="500">$docs_intro</textarea>
        </label>
        <label>
          <span>Markdown source directory</span>
          <input name="docs_source_dir" value="$configured_source" placeholder="Leave blank to use the bundled docs directory">
        </label>
        <p class="muted">Leave the source blank for the bundled application <code>docs/</code> directory. Use an absolute path only when maintaining Markdown under a server data directory. Only <code>access: Public</code> resources generate public pages; member and private resources are available from the member portal when Membership is enabled.</p>
      </section>
      <button type="submit">$save_label</button>
    </form>
  </section>
  <section class="panel" id="docs-catalog">
    <h2>Resource Catalog</h2>
    <table class="content-table admin-card-table">
      <thead><tr><th>Title</th><th>Type</th><th>Section</th><th>Source</th><th>Public output</th></tr></thead>
      <tbody>$doc_rows</tbody>
    </table>
  </section>
</section>
HTML

    return $self->_html_response($response_title, $body, $session);
}

