sub _dispatch_newsletter {
    my ($self, $request) = @_;
    my $path = $request->{path} || '/newsletter';
    $path =~ s{/+$}{};
    $path = '/newsletter' if $path eq '';
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    return $self->_not_found unless DesertCMS::Modules::enabled($settings, 'newsletter');
    if ($path eq '/newsletter') {
        return $request->{method} eq 'GET'
            ? $self->_newsletter_index($request, $settings)
            : $self->_method_not_allowed;
    }
    if ($path eq '/newsletter/subscribe') {
        return $request->{method} eq 'POST'
            ? $self->_newsletter_subscribe($request, $settings)
            : $self->_method_not_allowed;
    }
    if ($path =~ m{\A/newsletter/unsubscribe/([0-9]+)/([0-9a-fA-F]+)\z}) {
        return $request->{method} eq 'GET'
            ? $self->_newsletter_unsubscribe($request, $settings, $1, $2)
            : $self->_method_not_allowed;
    }
    return $self->_not_found;
}

sub _newsletter_index {
    my ($self, $request, $settings, $message, $is_error) = @_;
    my $title = $settings->{newsletter_title} || 'Newsletter';
    my $intro = $settings->{newsletter_intro} || 'Subscribe for announcements, recent posts, events, resources, and site updates.';
    my $consent = $settings->{newsletter_consent_text} || 'I agree to receive email updates from this site. I can unsubscribe at any time.';
    my $safe_title = escape_html($title);
    my $safe_intro = escape_html($intro);
    my $safe_consent = escape_html($consent);
    my $notice = $message ? '<p class="' . ($is_error ? 'events-notice is-error' : 'events-notice') . '">' . escape_html($message) . '</p>' : '';
    my $signup = _setting_truthy($settings->{newsletter_signup_enabled})
        ? <<"HTML"
  <section class="event-action-panel newsletter-signup-panel">
    <h2>Subscribe</h2>
    <form method="post" action="/newsletter/subscribe" class="public-form newsletter-form">
      <div class="public-form-grid">
        <label class="public-field"><span>Email</span><input name="email" type="email" maxlength="254" autocomplete="email" required></label>
        <label class="public-field"><span>Name</span><input name="display_name" maxlength="140" autocomplete="name"></label>
      </div>
      <p class="muted newsletter-consent">$safe_consent</p>
      <input type="hidden" name="consent_text" value="$safe_consent">
      <label class="comment-honeypot"><span>Website</span><input name="website" tabindex="-1" autocomplete="off"></label>
      <button type="submit">Subscribe</button>
    </form>
  </section>
HTML
        : '<section class="event-action-panel newsletter-signup-panel"><h2>Subscribe</h2><p class="events-empty">Newsletter signup is paused right now.</p></section>';
    my $body = <<"HTML";
<article class="content module-page newsletter-page events-shell">
  <header class="events-heading">
    <p class="kicker">Newsletter</p>
    <h1>$safe_title</h1>
    <p class="module-intro">$safe_intro</p>
  </header>
  $notice
  $signup
</article>
HTML
    return $self->_newsletter_public_response($title, $intro, '/newsletter/', $body, $is_error ? 400 : 200);
}

sub _newsletter_subscribe {
    my ($self, $request, $settings) = @_;
    return $self->_newsletter_index($request, $settings, 'Thanks. Please check your inbox for future updates.', 0)
        if length($request->param('website') || '');
    my $ok = eval {
        $self->{newsletter}->subscribe(
            email        => $request->param('email'),
            display_name => $request->param('display_name'),
            consent_text => $request->param('consent_text'),
            ip_address   => $request->{remote_addr} || $request->{ip_address} || '',
            user_agent   => $request->{user_agent} || '',
        );
        1;
    };
    return $self->_newsletter_index(
        $request,
        $settings,
        $ok
            ? 'Thanks. You are subscribed.'
            : _admin_action_error('The subscription could not be saved.', 'Check the email address and try again.', $@),
        $ok ? 0 : 1
    );
}

sub _newsletter_unsubscribe {
    my ($self, $request, $settings, $id, $token) = @_;
    my $ok = $self->{newsletter}->unsubscribe(id => $id, token => lc($token));
    return $self->_newsletter_index(
        $request,
        $settings,
        $ok ? 'You have been unsubscribed.' : 'This unsubscribe link is not valid or has already been changed.',
        $ok ? 0 : 1
    );
}

sub _newsletter_public_response {
    my ($self, $title, $description, $path, $content, $status) = @_;
    my $html = DesertCMS::Renderer::render_module_page($self->{config}, $self->{db}, {
        title       => $title,
        description => $description,
        path        => $path,
        content     => $content,
        context     => 'newsletter',
    });
    return DesertCMS::HTTP->response(
        status  => $status || 200,
        headers => {
            'Content-Type' => 'text/html; charset=utf-8',
            security_headers(),
        },
        body => $html,
    );
}

