        <label><span>Status</span><select name="status"><option value="draft">Draft</option><option value="ready">Ready to send</option></select></label>
        <button type="submit">Generate digest draft</button>
      </section>
    </form>
    <table class="content-table compact-table admin-card-table">
      <thead><tr><th>Announcement</th><th>Status</th><th>Preview</th><th>Updated</th><th>Actions</th></tr></thead>
      <tbody>$announcement_rows</tbody>
    </table>
  </section>

  <section class="panel" id="module-history">
    <h2>Send History</h2>
    <table class="content-table compact-table admin-card-table">
      <thead><tr><th>When</th><th>Announcement</th><th>Email</th><th>Status</th><th>Message</th></tr></thead>
      <tbody>$history_rows</tbody>
    </table>
  </section>
</section>
HTML
    return $self->_html_response($response_title, $body, $session);
}

sub _module_newsletter_settings_save {
    my ($self, $request, $session, $session_token) = @_;
    my $ok = eval {
        my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
        DesertCMS::Settings::set_many($self->{config}, $self->{db}, {
            module_newsletter_enabled => _module_toggle_value($self->_module_feature_state($settings, 'newsletter'), $request),
            newsletter_title => _clean_module_text($request->param('newsletter_title'), 100, 'Newsletter'),
            newsletter_intro => _clean_module_text($request->param('newsletter_intro'), 500, 'Subscribe for announcements, recent posts, events, resources, and site updates.'),
            newsletter_consent_text => _clean_module_text($request->param('newsletter_consent_text'), 500, 'I agree to receive email updates from this site. I can unsubscribe at any time.'),
            newsletter_signup_enabled => $request->param('newsletter_signup_enabled') ? 1 : 0,
            newsletter_default_tags => _clean_module_text($request->param('newsletter_default_tags'), 300, ''),
        });
        $self->{newsletter}->clear_settings_cache;
        $self->{content}->rebuild_all;
        1;
    };
    return $self->_module_newsletter_settings_page(
        $request,
        $session,
        $session_token,
        $ok
            ? 'Newsletter saved and public site rebuilt.'
            : _admin_action_error('The Newsletter settings could not be saved.', 'Check the title, intro, consent text, and signup setting, then try again.', $@)
    );
}

sub _newsletter_subscriber_save {
    my ($self, $request, $session, $session_token) = @_;
    my $ok = eval {
        $self->{newsletter}->save_subscriber(
            email        => $request->param('email'),
            display_name => $request->param('display_name'),
            status       => $request->param('status'),
            tags_text    => $request->param('tags_text'),
            segments_text => $request->param('segments_text'),
            consent_text => 'Added by admin',
            source       => 'manual',
            confirmed_at => now(),
        );
        1;
    };
    return $self->_module_newsletter_settings_page(
        $request,
        $session,
        $session_token,
        $ok
            ? 'Subscriber saved.'
            : _admin_action_error('The subscriber could not be saved.', 'Check the email, tags, segments, and status, then try again.', $@)
    );
}

sub _newsletter_announcement_save {
    my ($self, $request, $session, $session_token) = @_;
    my $ok = eval {
        $self->{newsletter}->save_announcement(
            id           => $request->param('id'),
            title        => $request->param('title'),
            subject      => $request->param('subject'),
            status       => $request->param('status'),
            manual_body  => $request->param('manual_body'),
            source_posts => $request->param('source_posts') ? 1 : 0,
            source_events => $request->param('source_events') ? 1 : 0,
            source_directory => $request->param('source_directory') ? 1 : 0,
            source_shop => $request->param('source_shop') ? 1 : 0,
        );
        1;
    };
    return $self->_module_newsletter_settings_page(
        $request,
        $session,
        $session_token,
        $ok
            ? 'Newsletter digest draft generated.'
            : _admin_action_error('The newsletter draft could not be saved.', 'Check the title, subject, and manual text, then try again.', $@)
    );
}

sub _newsletter_announcement_send {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $summary;
    my $ok = eval {
        $summary = $self->{newsletter}->send_announcement(id => $id);
        1;
    };
    my $message = $ok
        ? "Newsletter sent to $summary->{sent} subscriber(s); $summary->{failed} failed."
        : _admin_action_error('The newsletter could not be sent.', 'Subscriber capture and export still work. Resolve the delivery readiness message, then send again.', $@);
    return $self->_module_newsletter_settings_page($request, $session, $session_token, $message);
}

sub _newsletter_export {
    my ($self, $request, $session, $session_token) = @_;
    return DesertCMS::HTTP->response(
        status => 200,
        headers => {
            'Content-Type' => 'text/csv; charset=utf-8',
            'Content-Disposition' => 'attachment; filename="newsletter-subscribers.csv"',
            security_headers(),
        },
        body => $self->{newsletter}->csv_export,
    );
}

sub _newsletter_subscriber_rows {
    my ($self) = @_;
    my $rows = '';
    for my $subscriber (@{ $self->{newsletter}->subscribers(limit => 250) }) {
        my $email = escape_html($subscriber->{email} || '');
        my $name = escape_html($subscriber->{display_name} || '');
        my $status = _fleet_state_pill(($subscriber->{status} || '') eq 'active' ? 'ok' : 'neutral', _title_case_status($subscriber->{status}));
        my $tags = escape_html($subscriber->{tags_text} || '');
        my $segments = escape_html($subscriber->{segments_text} || '');
        my $updated = escape_html(_format_time($subscriber->{updated_at}));
        $rows .= <<"HTML";
<tr>
  <td data-label="Subscriber"><strong>$email</strong><br><span class="muted">$name</span></td>
  <td data-label="Status">$status</td>
  <td data-label="Tags">$tags</td>
  <td data-label="Segments">$segments</td>
  <td data-label="Updated">$updated</td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(5, 'No newsletter subscribers yet.', 'Public signup and manual subscribers will appear here.');
}

sub _newsletter_announcement_rows {
    my ($self, $csrf) = @_;
    my $rows = '';
    for my $announcement (@{ $self->{newsletter}->announcements(limit => 100) }) {
        my $id = int($announcement->{id});
        my $title = escape_html($announcement->{title} || 'Newsletter announcement');
        my $subject = escape_html($announcement->{subject} || '');
        my $status_value = $announcement->{status} || 'draft';
        my $status = _fleet_state_pill($status_value eq 'sent' ? 'ok' : ($status_value eq 'ready' ? 'warn' : 'neutral'), _title_case_status($status_value));
        my $preview = escape_html(substr($announcement->{preview_text} || '', 0, 220));
        my $updated = escape_html(_format_time($announcement->{updated_at}));
        my $send = ($status_value eq 'ready' || $status_value eq 'draft') ? <<"HTML" : '';
<form method="post" action="/admin/settings/modules/newsletter/announcements/$id/send" class="inline-form" data-confirm-title="Send newsletter?" data-confirm-message="This sends the current preview to all active subscribers if Postmark is ready." data-confirm-action="Send">
  <input type="hidden" name="csrf_token" value="$csrf">
  <button type="submit" class="button-link secondary button-link--compact">Send</button>
</form>
HTML
        $rows .= <<"HTML";
<tr>
  <td data-label="Announcement"><strong>$title</strong><br><span class="muted">$subject</span></td>
  <td data-label="Status">$status</td>
  <td data-label="Preview"><small>$preview</small></td>
  <td data-label="Updated">$updated</td>
  <td data-label="Actions" class="table-actions">$send</td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(5, 'No newsletter drafts yet.', 'Generate a digest draft from manual text and recent site activity.');
}

sub _newsletter_history_rows {
    my ($self) = @_;
    my $rows = '';
    for my $history (@{ $self->{newsletter}->send_history(limit => 50) }) {
        my $when = escape_html(_format_time($history->{created_at}));
        my $title = escape_html($history->{announcement_title} || 'Newsletter');
        my $email = escape_html($history->{email} || '');
        my $status = _fleet_state_pill(($history->{status} || '') eq 'sent' ? 'ok' : 'warn', _title_case_status($history->{status}));
        my $message = escape_html($history->{error} || $history->{postmark_message_id} || '');
        $rows .= qq{<tr><td data-label="When">$when</td><td data-label="Announcement">$title</td><td data-label="Email">$email</td><td data-label="Status">$status</td><td data-label="Message">$message</td></tr>};
    }
    return $rows || _admin_empty_row(5, 'No newsletter sends yet.', 'Send attempts and Postmark failures will appear here.');
}

sub _dispatch_donations {
    my ($self, $request) = @_;
    my $path = $request->{path} || '/donate';
    $path =~ s{/+$}{} unless $path eq '/donate/';
    $path = '/donate' if $path eq '';
    if ($path eq '/donate/stripe/webhook') {
        return $request->{method} eq 'POST'
            ? $self->_donations_stripe_webhook($request)
            : $self->_method_not_allowed;
    }
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    return $self->_not_found unless DesertCMS::Modules::enabled($settings, 'donations');
    if ($path eq '/donate') {
        return $request->{method} eq 'GET'
            ? $self->_donations_index($request, $settings)
            : $self->_method_not_allowed;
    }
    if ($path =~ m{\A/donate/([^/]+)/checkout\z}) {
        return $request->{method} eq 'POST'
            ? $self->_donation_checkout($request, $settings, $1)
            : $self->_method_not_allowed;
    }
    if ($path =~ m{\A/donate/([^/]+)/(thank-you|cancel)\z}) {
        return $request->{method} eq 'GET'
            ? $self->_donation_status_page($request, $settings, $1, $2)
            : $self->_method_not_allowed;
    }
    if ($path =~ m{\A/donate/([^/]+)\z}) {
        return $request->{method} eq 'GET'
            ? $self->_donation_detail($request, $settings, $1)
            : $self->_method_not_allowed;
    }
    return $self->_not_found;
}

sub _donations_public_response {
    my ($self, %args) = @_;
    my $html = DesertCMS::Renderer::render_module_page($self->{config}, $self->{db}, {
        title       => $args{title},
        description => $args{description} || '',
        path        => $args{path} || '/donate/',
        content     => $args{content} || '',
        context     => 'donations',
    });
    return DesertCMS::HTTP->response(
        status  => $args{status} || 200,
        headers => {
            'Content-Type' => 'text/html; charset=utf-8',
            security_headers(),
        },
        body => $html,
    );
}

sub _donations_index {
    my ($self, $request, $settings, $message, $is_error) = @_;
    my $title = $settings->{donations_title} || 'Donate';
    my $intro = $settings->{donations_intro} || 'Support current campaigns, community projects, events, archives, artists, and public work.';
    my $notice = $message ? '<p class="' . ($is_error ? 'notice error' : 'notice') . '">' . escape_html($message) . '</p>' : '';
    my $cards = '';
    for my $campaign (@{ $self->{donations}->published_campaigns(limit => 500) }) {
        $cards .= $self->_donation_campaign_card($campaign);
    }
    $cards ||= '<p class="donation-empty">No fundraising campaigns yet.</p>';
    my $safe_title = escape_html($title);
    my $safe_intro = escape_html($intro);
    my $body = <<"HTML";
<article class="content module-page donations-page donations-shell">
  <header class="donations-hero">
    <div class="donations-hero-copy">
      <p class="kicker">Donations / Fundraising</p>
      <h1>$safe_title</h1>
      <p class="donations-hero-intro">$safe_intro</p>
      <div class="donations-hero-actions">
        <a class="donation-primary-link" href="#donation-campaigns">View campaigns</a>
        <span>Secure checkout opens from each campaign page.</span>
      </div>
    </div>
    <aside class="donations-how-card" aria-label="How donations work">
      <span class="donations-card-label">How to give</span>
      <div class="donations-steps" role="list">
        <div role="listitem"><span>1</span><p><b>Choose a campaign</b><small>Pick the fund or project you want to support.</small></p></div>
        <div role="listitem"><span>2</span><p><b>Select an amount</b><small>Use a suggested amount or enter a custom gift.</small></p></div>
        <div role="listitem"><span>3</span><p><b>Donate securely</b><small>Checkout opens through the configured Stripe payment flow.</small></p></div>
      </div>
    </aside>
  </header>
  $notice
  <section class="donations-campaigns" id="donation-campaigns" aria-label="Fundraising campaigns">
    <div class="donations-section-heading">
      <p class="kicker">Active campaigns</p>
      <h2>Choose where your support goes</h2>
    </div>
    <div class="donations-grid">
      $cards
    </div>
  </section>
</article>
HTML
    return $self->_donations_public_response(
        title       => $title,
        description => $intro,
        path        => '/donate/',
        content     => $body,
        status      => $is_error ? 400 : 200,
    );
}

sub _donation_detail {
    my ($self, $request, $settings, $slug, $message, $is_error) = @_;
    my $campaign = $self->{donations}->campaign_by_slug($slug) or return $self->_not_found;
    my $title = escape_html($campaign->{title} || 'Donation campaign');
    my $summary = escape_html($campaign->{summary} || '');
    my $body_text = DesertCMS::Donations::campaign_body_html($campaign->{body} || $campaign->{summary} || '');
    my $image = $campaign->{image_path} || '';
    my $image_tag = DesertCMS::Media::is_public_image_path($image)
        ? $self->_public_media_img_tag($image, '', sizes => '(max-width: 760px) 100vw, 460px', loading => 'eager')
        : '';
    my $image_html = length $image_tag ? qq{<figure class="donation-detail-media">$image_tag</figure>} : '';
    my $progress = $self->_donation_progress_html($campaign);
    my $form = $self->_donation_form_html($campaign);
    my $notice = $message ? '<p class="' . ($is_error ? 'notice error' : 'notice') . '">' . escape_html($message) . '</p>' : '';
    my $body = <<"HTML";
<article class="content module-page donations-page donation-detail">
  <header class="donation-detail-hero">
    <div class="donation-detail-copy">
      <p class="kicker">Donations / Fundraising</p>
      <h1>$title</h1>
      <p class="donation-summary">$summary</p>
    </div>
    $image_html
  </header>
  <section class="donation-priority" aria-label="Donate to $title">
    <div class="donation-priority-copy">
      <p class="kicker">Give now</p>
      <h2>Support this campaign</h2>
      <p>Choose a suggested amount or enter a custom donation, then continue through secure Stripe checkout.</p>
    </div>
    <div class="donation-priority-actions">
      $notice
      $form
      $progress
    </div>
  </section>
  <section class="donation-story" aria-labelledby="donation-story-heading">
    <div class="donation-story-heading">
      <p class="kicker">Campaign story</p>
      <h2 id="donation-story-heading">Where your donation goes</h2>
    </div>
    <div class="body donation-body">$body_text</div>
  </section>
  <p class="donation-back"><a href="/donate/">Back to all campaigns</a></p>
</article>
HTML
    return $self->_donations_public_response(
        title       => $campaign->{title} || 'Donation campaign',
        description => $campaign->{summary} || '',
        path        => '/donate/' . ($campaign->{slug} || $slug || '') . '/',
        content     => $body,
        status      => $is_error ? 400 : 200,
    );
}

sub _donation_checkout {
    my ($self, $request, $settings, $slug) = @_;
    my $campaign = $self->{donations}->campaign_by_slug($slug) or return $self->_not_found;
    my $checkout = eval {
        $self->{donations}->create_checkout(
            campaign_id    => $campaign->{id},
            amount         => $request->param('amount') || $request->param('custom_amount'),
            donor_email    => $request->param('donor_email'),
            donor_name     => $request->param('donor_name'),
            donor_message  => $request->param('donor_message'),
            anonymous      => $request->param('anonymous'),
        );
    };
    if (!$checkout) {
        return $self->_donation_detail(
            $request,
            $settings,
            $slug,
            $@ || 'Donation checkout could not be started.',
            1
        );
    }
    return DesertCMS::HTTP->redirect($checkout->{url}, { security_headers() });
}

sub _donation_status_page {
    my ($self, $request, $settings, $slug, $status) = @_;
    my $campaign = $self->{donations}->campaign_by_slug($slug) or return $self->_not_found;
    my $title = $status eq 'thank-you' ? 'Thank you' : 'Donation canceled';
    my $message = $status eq 'thank-you'
        ? 'Thanks. Your donation is being confirmed by Stripe.'
        : 'Donation checkout was canceled. You can return to the campaign when ready.';
    my $safe_campaign = escape_html($campaign->{title} || 'campaign');
    my $safe_slug = escape_html($campaign->{slug} || '');
    my $safe_message = escape_html($message);
    my $body = <<"HTML";
<article class="content module-page donations-page donation-status">
  <section class="donation-status-card">
    <p class="kicker">Donations / Fundraising</p>
    <h1>$title</h1>
    <p>$safe_message</p>
    <a class="donation-return-link" href="/donate/$safe_slug/">Return to $safe_campaign</a>
  </section>
</article>
HTML
    return $self->_donations_public_response(
        title       => $title,
        description => $message,
        path        => '/donate/' . ($campaign->{slug} || $slug || '') . '/' . $status,
        content     => $body,
    );
}

sub _donations_stripe_webhook {
    my ($self, $request) = @_;
    my $ok = eval {
        $self->{donations}->handle_webhook(
            payload   => $request->{body} || '',
            signature => $request->{stripe_signature} || '',
        );
        1;
    };
    return DesertCMS::HTTP->response(
        status  => $ok ? 200 : 400,
        headers => {
            'Content-Type' => 'application/json',
            security_headers(),
        },
        body => $ok ? '{"ok":true}' : '{"ok":false}',
    );
}

sub _donation_campaign_card {
    my ($self, $campaign) = @_;
    my $slug = escape_html($campaign->{slug} || '');
    my $title = escape_html($campaign->{title} || 'Campaign');
    my $summary = escape_html($campaign->{summary} || '');
    my $raised = escape_html(DesertCMS::Donations::price_label($campaign->{raised_cents}, $campaign->{currency}));
    my $goal = int($campaign->{goal_amount_cents} || 0);
    my $goal_label = $goal > 0 && $campaign->{show_goal}
        ? ' of ' . escape_html(DesertCMS::Donations::price_label($goal, $campaign->{currency}))
        : '';
    my $pct = $goal > 0 && $campaign->{show_goal} ? DesertCMS::Donations::progress_percent($campaign) : 0;
    my $meter = $goal > 0 && $campaign->{show_goal}
        ? qq{<div class="donation-meter" aria-hidden="true"><span style="width: $pct%"></span></div>}
        : '';
    my $image = $campaign->{image_path} || '';
    my $image_tag = DesertCMS::Media::is_public_image_path($image)
        ? $self->_public_media_img_tag($image, '', sizes => '(max-width: 760px) 100vw, 360px')
        : '';
    my $image_html = length $image_tag
        ? qq{<span class="donation-card-media">$image_tag</span>}
        : qq{<span class="donation-card-media donation-card-media--empty" aria-hidden="true"><span>Give</span></span>};
    return <<"HTML";
<a class="donation-card" href="/donate/$slug/">
  $image_html
  <div class="donation-card-body">
    <span class="donation-card-top"><span class="donation-card-kicker">Campaign</span><span class="donation-card-open">Open campaign</span></span>
    <h3>$title</h3>
    <p>$summary</p>
    <span class="donation-card-progress">
      <strong>$raised raised$goal_label</strong>
      $meter
    </span>
    <span class="donation-card-action">Give to this campaign</span>
  </div>
</a>
HTML
}

sub _public_media_img_tag {
    my ($self, $src, $alt, %opts) = @_;
    return '' unless DesertCMS::Media::is_public_image_path($src);
    my $asset = $self->{db}->dbh->selectrow_hashref(
        q{
            SELECT public_path, alt_text, seo_title, seo_description, width, height, derivatives_json
            FROM media_assets
            WHERE deleted_at IS NULL
              AND public_path = ?
            LIMIT 1
        },
        undef,
        $src
    ) || {};
    return '' unless $asset->{public_path};
    $alt = $asset->{alt_text} || '' unless defined $alt && length $alt;
    my @attrs = (
        'src="' . escape_html($src) . '"',
        'alt="' . escape_html($alt) . '"',
        'loading="' . escape_html($opts{loading} || 'lazy') . '"',
        'decoding="async"',
    );
    if (int($asset->{width} || 0) > 0 && int($asset->{height} || 0) > 0) {
        push @attrs, 'width="' . int($asset->{width}) . '"';
        push @attrs, 'height="' . int($asset->{height}) . '"';
    }
    my $srcset = _public_media_srcset($asset);
    if (length $srcset) {
        push @attrs, 'srcset="' . escape_html($srcset) . '"';
        push @attrs, 'sizes="' . escape_html($opts{sizes} || '(max-width: 760px) 100vw, 1120px') . '"';
    }
    push @attrs, 'class="' . escape_html($opts{class}) . '"' if defined $opts{class} && length $opts{class};
    return '<img ' . join(' ', @attrs) . '>';
}

sub _public_media_srcset {
    my ($asset) = @_;
    return '' unless $asset && defined $asset->{derivatives_json} && length $asset->{derivatives_json};
    my $derivatives = eval { decode_json($asset->{derivatives_json}) } || {};
    my $sizes = ref $derivatives->{sizes} eq 'ARRAY' ? $derivatives->{sizes} : [];
    my %seen;
    my @entries;
    for my $size (sort { int($a->{width} || 0) <=> int($b->{width} || 0) } grep { ref $_ eq 'HASH' } @{$sizes}) {
        my $path = $size->{path} || '';
        my $width = int($size->{width} || 0);
        next unless DesertCMS::Media::is_public_image_variant_path($path);
        next unless $width > 0;
        next if $seen{$width}++;
        push @entries, "$path ${width}w";
    }
    return @entries > 1 ? join(', ', @entries) : '';
}

sub _donation_progress_html {
    my ($self, $campaign) = @_;
    my $raised = escape_html(DesertCMS::Donations::price_label($campaign->{raised_cents}, $campaign->{currency}));
    my $goal = int($campaign->{goal_amount_cents} || 0);
    my $show_goal = $goal > 0 && $campaign->{show_goal} ? 1 : 0;
    my $goal_label = $show_goal ? escape_html(DesertCMS::Donations::price_label($goal, $campaign->{currency})) : '';
    my $pct = DesertCMS::Donations::progress_percent($campaign);
    my $count = int($campaign->{paid_donation_count} || 0);
    my $donation_count = $count == 1 ? '1 donation recorded' : "$count donations recorded";
    my $goal_text = $show_goal ? "of $goal_label goal" : 'raised so far';
    my $meter = $show_goal
        ? qq{<div class="donation-meter" role="progressbar" aria-label="Donation progress" aria-valuemin="0" aria-valuemax="100" aria-valuenow="$pct"><span style="width: $pct%"></span></div><small>$pct% funded</small>}
        : '';
    return <<"HTML";
<section class="donation-progress-panel" aria-label="Campaign progress">
  <div>
    <span>Raised</span>
    <strong>$raised</strong>
    <small>$goal_text</small>
  </div>
  $meter
  <p>$donation_count</p>
</section>
HTML
}

sub _donation_form_html {
    my ($self, $campaign) = @_;
    my $readiness = $self->{donations}->payment_readiness;
    return '<section class="donation-panel donation-panel--unavailable"><p class="donation-panel-kicker">Online giving</p><h2>Online donations are not available</h2><p>'
        . escape_html($readiness->{summary})
        . '</p></section>' unless $readiness->{checkout_enabled};
    my $slug = escape_html($campaign->{slug} || '');
    my $amount_options = '';
    my $first = 1;
    for my $amount (@{ DesertCMS::Donations::suggested_amounts($campaign) }) {
        my $value = escape_html(sprintf('%.2f', $amount / 100));
        my $label = escape_html(DesertCMS::Donations::price_label($amount, $campaign->{currency}));
        my $checked = $first ? 'checked' : '';
        $first = 0;
        $amount_options .= qq{<label class="donation-amount-option"><input type="radio" name="amount" value="$value" $checked><span>$label</span></label>};
    }
    if ($campaign->{allow_custom_amount}) {
        $amount_options .= qq{<label class="donation-custom-amount"><span>Custom amount</span><input name="custom_amount" inputmode="decimal" placeholder="25.00"></label>};
    }
    $amount_options ||= qq{<label class="donation-custom-amount"><span>Amount</span><input name="custom_amount" inputmode="decimal" placeholder="25.00" required></label>};
    my $message_field = $campaign->{donor_message_enabled}
        ? '<label class="public-field public-field--full"><span>Message optional</span><textarea name="donor_message" rows="3"></textarea></label>'
        : '';
    return <<"HTML";
<section class="donation-panel">
  <p class="donation-panel-kicker">Donate online</p>
  <h2>Choose an amount</h2>
  <p class="donation-panel-intro">Use secure Stripe checkout for this campaign. You can review the donation before payment.</p>
  <form method="post" action="/donate/$slug/checkout" class="public-form donation-form">
    <fieldset class="donation-amounts">
      <legend>Donation amount</legend>
      <div class="donation-amount-grid">$amount_options</div>
    </fieldset>
    <div class="donation-donor-grid">
      <label><span>Name optional</span><input name="donor_name" maxlength="160"></label>
      <label><span>Email optional</span><input name="donor_email" type="email" maxlength="180"></label>
    </div>
    $message_field
    <label class="checkbox-field public-field--full"><input type="checkbox" name="anonymous" value="1"><span>Show my donation as anonymous</span></label>
    <button type="submit">Donate securely with Stripe</button>
    <p class="donation-secure-note">Your payment is processed by Stripe; DesertCMS records the campaign, amount, and receipt status.</p>
  </form>
</section>
HTML
}

sub _module_donations_settings_page {
    my ($self, $request, $session, $session_token, $message) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $settings_nav = $self->_module_setup_nav('donations', $session, $settings);
    my $donations_feature = $self->_module_feature_state($settings, 'donations');
    my $payments_feature = $self->_module_feature_state($settings, 'donation_payments');
    my $enabled_state = _module_status_html($donations_feature, $self->{config});
    my $payments_state = _module_status_html($payments_feature, $self->{config});
    my $enabled_control = _module_toggle_control($donations_feature, 'module_donations_enabled', 'Enable Donations / Fundraising', $self->{config});
    my $payment_readiness = $self->{donations}->payment_readiness;
    my $payments_summary = _fleet_state_pill($payment_readiness->{state}, $payment_readiness->{label})
        . '<small>' . escape_html($payment_readiness->{summary}) . '</small>';
    my $donations_title = escape_html($settings->{donations_title} || 'Donate');
    my $donations_intro = escape_html($settings->{donations_intro} || 'Support current campaigns, community projects, events, archives, artists, and public work.');
    my $feature_eyebrow = _admin_feature_eyebrow($self->{config});
    my $is_contributor_product = DesertCMS::CapabilityPolicy::contributor_product_mode($self->{config});
    my $save_label = $is_contributor_product ? 'Save donation settings and rebuild' : 'Save Donations and rebuild';
    my $response_title = $is_contributor_product ? 'Donations Feature' : 'Donations Module';
    my $campaign_rows = $self->_donation_campaign_admin_rows($csrf);
    my $donation_rows = $self->_donation_admin_rows;
    my $section_nav = _module_section_nav(
        'Donations setup sections',
        [ '#module-settings', 'Settings' ],
        [ '#module-campaigns', 'Campaigns' ],
        [ '#module-records', 'Donation Records' ],
    );

    my $body = <<"HTML";
<section class="editor-workspace">
  $settings_nav
  <section class="panel" id="module-settings">
    <div class="split">
      <div>
        <p class="eyebrow">$feature_eyebrow</p>
        <h1>Donations / Fundraising</h1>
        <p>Publish a generated <code>/donate/</code> fundraising area with campaigns, suggested amounts, custom donations, donor messages, goal progress, Stripe Checkout, marketplace payouts, and donor export.</p>
      </div>
      <div class="button-row">
        <a class="button-link secondary" href="/donate/">Open donations</a>
        <a class="button-link secondary" href="/admin/settings/modules/donations/export">Export CSV</a>
        <a class="button-link" href="/admin/settings/modules/donations/new">New campaign</a>
      </div>
    </div>
    $notice
    $section_nav
    <form method="post" action="/admin/settings/modules/donations/save" class="settings-form settings-form--wide">
      <input type="hidden" name="csrf_token" value="$csrf">
      <section class="inspector-panel">
        <h2>Donation Settings</h2>
        <dl class="health-list health-list--compact">
          <div><dt>Public path</dt><dd><code>/donate/</code></dd></div>
          <div><dt>Status</dt><dd>$enabled_state</dd></div>
          <div><dt>Payment feature</dt><dd>$payments_state</dd></div>
          <div><dt>Payment readiness</dt><dd>$payments_summary</dd></div>
        </dl>
        $enabled_control
      </section>
      <section class="inspector-panel">
        <h2>Public Copy</h2>
        <label>
          <span>Title</span>
          <input name="donations_title" value="$donations_title" maxlength="100">
        </label>
        <label>
          <span>Intro</span>
          <textarea name="donations_intro" rows="4" maxlength="500">$donations_intro</textarea>
        </label>
      </section>
      <button type="submit">$save_label</button>
    </form>
  </section>
  <section class="panel" id="module-orders">
    <div class="split">
      <div>
        <h2>Campaigns</h2>
        <p class="muted">Create standalone fundraising campaigns with goals, suggested amounts, donor messages, and optional Stripe checkout.</p>
      </div>
      <a class="button-link" href="/admin/settings/modules/donations/new">New campaign</a>
    </div>
    <table class="content-table compact-table admin-card-table">
      <thead><tr><th>Campaign</th><th>Status</th><th>Raised</th><th>Donations</th><th>Actions</th></tr></thead>
      <tbody>$campaign_rows</tbody>
    </table>
  </section>
  <section class="panel" id="module-campaigns">
    <h2>Donation Records</h2>
    <table class="content-table compact-table admin-card-table">
      <thead><tr><th>Created</th><th>Campaign</th><th>Donor</th><th>Total</th><th>Status</th><th>Stripe Session</th></tr></thead>
      <tbody>$donation_rows</tbody>
    </table>
  </section>
</section>
HTML
    return $self->_html_response($response_title, $body, $session);
}

sub _module_donations_settings_save {
    my ($self, $request, $session, $session_token) = @_;
    my $ok = eval {
        my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
        DesertCMS::Settings::set_many($self->{config}, $self->{db}, {
            module_donations_enabled => _module_toggle_value($self->_module_feature_state($settings, 'donations'), $request),
            donations_title => _clean_module_text($request->param('donations_title'), 100, 'Donate'),
            donations_intro => _clean_module_text($request->param('donations_intro'), 500, 'Support current campaigns, community projects, events, archives, artists, and public work.'),
        });
        $self->{donations}->clear_settings_cache;
        $self->{content}->rebuild_all;
        1;
    };
    if (!$ok) {
        return $self->_module_donations_settings_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The Donations settings could not be saved.',
                'Check the title, intro, and feature setting, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'settings.module_donations_saved',
        subject_type => 'settings',
        details      => { rebuilt => 1 },
    );
    return $self->_module_donations_settings_page($request, $session, $session_token, 'Donations saved and public site rebuilt.');
}

sub _donation_campaign_form {
    my ($self, $request, $session, $session_token, $id, $message) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $campaign = $id ? $self->{donations}->get_campaign($id) : undef;
    return $self->_not_found if $id && !$campaign;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $settings_nav = $self->_module_setup_nav('donations', $session, $settings);
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $action = $campaign ? '/admin/settings/modules/donations/' . int($campaign->{id}) . '/update' : '/admin/settings/modules/donations/create';
    my $heading = $campaign ? 'Edit Donation Campaign' : 'New Donation Campaign';
    my $title = escape_html($campaign ? $campaign->{title} : '');
    my $slug = escape_html($campaign ? $campaign->{slug} : '');
    my $summary = escape_html($campaign ? $campaign->{summary} : '');
    my $body_text = escape_html($campaign ? $campaign->{body} : '');
    my $status = $campaign ? ($campaign->{status} || 'draft') : 'draft';
    my $published_selected = $status eq 'published' ? 'selected' : '';
    my $draft_selected = $status eq 'draft' ? 'selected' : '';
    my $archived_selected = $status eq 'archived' ? 'selected' : '';
    my $feature_image_options = $self->_directory_feature_image_options($campaign ? $campaign->{image_path} : '');
    my $goal_amount = escape_html(_admin_price($campaign ? $campaign->{goal_amount_cents} : 0));
    my $currency = escape_html($campaign ? ($campaign->{currency} || 'usd') : 'usd');
    my $suggested = escape_html($campaign ? ($campaign->{suggested_amounts_text} || '25.00, 50.00, 100.00') : '25.00, 50.00, 100.00');
    my $custom = !$campaign || $campaign->{allow_custom_amount} ? 'checked' : '';
    my $messages = !$campaign || $campaign->{donor_message_enabled} ? 'checked' : '';
    my $show_goal = !$campaign || $campaign->{show_goal} ? 'checked' : '';
    my $featured = $campaign && $campaign->{featured} ? 'checked' : '';
    my $sort_order = escape_html($campaign ? ($campaign->{sort_order} || 100) : 100);
    my $payments_feature = $self->_module_feature_state($settings, 'donation_payments');
    my $payments_locked = $payments_feature && $payments_feature->{locked_by_plan} ? 1 : 0;
    my $payments_notice = $payments_locked
        ? '<p class="notice">Donation Payments is locked on this plan. Campaign pages and donor export stay available, but public checkout is hidden until the site upgrades.</p>'
        : '<p class="muted">Stripe Checkout is shown publicly only when Donation Payments and payment readiness are both available.</p>';
    my $form_section_nav = _module_section_nav(
        'Donation campaign editor sections',
        [ '#donation-campaign', 'Campaign' ],
        [ '#donation-fundraising', 'Fundraising' ],
        [ '#donation-display', 'Display' ],
    );

    my $body = <<"HTML";
<section class="editor-workspace">
  $settings_nav
  <section class="panel">
    <div class="split">
      <div>
        <p class="eyebrow">Donations</p>
        <h1>$heading</h1>
        <p>Create a public campaign page with goal progress, suggested amounts, custom donations, and donor messages.</p>
      </div>
      <a class="button-link secondary" href="/admin/settings/modules/donations">Back to donations</a>
    </div>
    $notice
    $form_section_nav
    <form method="post" action="$action" class="settings-form settings-form--wide">
      <input type="hidden" name="csrf_token" value="$csrf">
      <section class="inspector-panel" id="donation-campaign">
        <h2>Campaign</h2>
        <div class="field-row">
          <label>
            <span>Title</span>
            <input name="title" value="$title" required maxlength="180">
          </label>
          <label>
            <span>Slug</span>
            <input name="slug" value="$slug" maxlength="160" placeholder="Generated from title">
          </label>
        </div>
        <div class="field-row">
          <label>
            <span>Status</span>
            <select name="status">
              <option value="draft" $draft_selected>Draft</option>
              <option value="published" $published_selected>Published</option>
              <option value="archived" $archived_selected>Archived</option>
            </select>
          </label>
          <label>
            <span>Feature image</span>
            <select name="image_path">$feature_image_options</select>
          </label>
        </div>
        <label>
          <span>Summary</span>
          <textarea name="summary" rows="3" maxlength="500">$summary</textarea>
        </label>
        <label>
          <span>Description</span>
          <textarea name="body" rows="8">$body_text</textarea>
        </label>
      </section>
      <section class="inspector-panel" id="donation-fundraising">
        <h2>Fundraising</h2>
        $payments_notice
        <div class="field-row">
          <label>
            <span>Goal amount</span>
            <input name="goal_amount" value="$goal_amount" inputmode="decimal" placeholder="5000.00">
          </label>
          <label>
            <span>Currency</span>
            <input name="currency" value="$currency" maxlength="3">
          </label>
        </div>
        <label>
          <span>Suggested amounts</span>
          <input name="suggested_amounts" value="$suggested" placeholder="25.00, 50.00, 100.00">
        </label>
        <label class="checkbox-field"><input type="checkbox" name="allow_custom_amount" value="1" $custom><span>Allow custom amount</span></label>
        <label class="checkbox-field"><input type="checkbox" name="donor_message_enabled" value="1" $messages><span>Allow donor messages</span></label>
        <label class="checkbox-field"><input type="checkbox" name="show_goal" value="1" $show_goal><span>Show campaign goal/progress</span></label>
      </section>
      <section class="inspector-panel" id="donation-display">
        <h2>Display</h2>
        <div class="field-row">
          <label>
            <span>Sort order</span>
            <input name="sort_order" value="$sort_order" inputmode="numeric">
          </label>
          <label class="checkbox-field">
            <input type="checkbox" name="featured" value="1" $featured>
            <span>Feature this campaign</span>
          </label>
        </div>
      </section>
      <button type="submit">Save campaign</button>
    </form>
  </section>
</section>
HTML
    return $self->_html_response($heading, $body, $session);
}

sub _donation_campaign_create {
    my ($self, $request, $session, $session_token) = @_;
    return $self->_donation_campaign_save($request, $session, $session_token, undef);
}

sub _donation_campaign_update {
    my ($self, $request, $session, $session_token, $id) = @_;
    return $self->_donation_campaign_save($request, $session, $session_token, $id);
}

sub _donation_campaign_save {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $campaign = eval {
        my $saved = $self->{donations}->save_campaign(
            id                    => $id,
            title                 => $request->param('title'),
            slug                  => $request->param('slug'),
            status                => $request->param('status'),
            summary               => $request->param('summary'),
            body                  => $request->param('body'),
            image_path            => $request->param('image_path'),
            goal_amount           => $request->param('goal_amount'),
            currency              => $request->param('currency'),
            suggested_amounts     => $request->param('suggested_amounts'),
            allow_custom_amount   => $request->param('allow_custom_amount'),
            donor_message_enabled => $request->param('donor_message_enabled'),
            show_goal             => $request->param('show_goal'),
            featured              => $request->param('featured'),
            sort_order            => $request->param('sort_order'),
        );
        $self->{content}->rebuild_all;
        $saved;
    };
    if (!$campaign) {
        return $self->_donation_campaign_form(
            $request,
            $session,
            $session_token,
            $id,
            _admin_action_error(
                'The donation campaign could not be saved.',
                'Check the title, amount fields, status, and suggested amounts, then try again.',
                $@
            )
        );
    }
    return DesertCMS::HTTP->redirect('/admin/settings/modules/donations?notice=campaign-saved', { security_headers() });
}

sub _donation_campaign_status {
    my ($self, $request, $session, $session_token, $id, $action) = @_;
    my $ok = eval {
        if ($action eq 'publish') {
            $self->{donations}->publish_campaign($id);
        } else {
            $self->{donations}->archive_campaign($id);
        }
        $self->{content}->rebuild_all;
        1;
    };
    return $self->_module_donations_settings_page(
        $request,
        $session,
        $session_token,
        $ok
            ? ($action eq 'publish' ? 'Donation campaign published and public site rebuilt.' : 'Donation campaign archived and public site rebuilt.')
            : _admin_action_error('The donation campaign status could not be changed.', 'Refresh the Donations page and try again.', $@)
    );
}

sub _donation_export {
    my ($self, $request, $session, $session_token) = @_;
    return DesertCMS::HTTP->response(
        status => 200,
        headers => {
            'Content-Type' => 'text/csv; charset=utf-8',
            'Content-Disposition' => 'attachment; filename="donations.csv"',
            security_headers(),
        },
        body => $self->{donations}->csv_export,
    );
}

sub _donation_campaign_admin_rows {
    my ($self, $csrf) = @_;
    my $rows = '';
    for my $campaign (@{ $self->{donations}->campaigns_admin }) {
        my $id = int($campaign->{id});
        my $title = escape_html($campaign->{title} || 'Donation campaign');
        my $slug = escape_html($campaign->{slug} || '');
        my $status = escape_html($campaign->{status} || 'draft');
        my $raised = escape_html(DesertCMS::Donations::price_label($campaign->{raised_cents}, $campaign->{currency}));
        my $goal = int($campaign->{goal_amount_cents} || 0) > 0
            ? ' / ' . escape_html(DesertCMS::Donations::price_label($campaign->{goal_amount_cents}, $campaign->{currency}))
            : '';
        my $count = int($campaign->{donation_count} || 0);
        my $publish = ($campaign->{status} || '') eq 'published'
            ? ''
            : qq{<form method="post" action="/admin/settings/modules/donations/$id/publish" class="inline-form"><input type="hidden" name="csrf_token" value="$csrf"><button type="submit" class="button-link secondary button-link--compact">Publish</button></form>};
        my $archive = ($campaign->{status} || '') eq 'archived'
            ? ''
            : qq{<form method="post" action="/admin/settings/modules/donations/$id/archive" class="inline-form" data-confirm-title="Archive this campaign?" data-confirm-message="The campaign will leave the public donations page, but donor records stay in the database." data-confirm-action="Archive"><input type="hidden" name="csrf_token" value="$csrf"><button type="submit" class="button-link secondary button-link--compact">Archive</button></form>};
        $rows .= <<"HTML";
<tr>
  <td data-label="Campaign"><strong>$title</strong><br><small>/donate/$slug/</small></td>
  <td data-label="Status"><span class="status-pill status-pill--neutral">$status</span></td>
  <td data-label="Raised">$raised$goal</td>
  <td data-label="Donations">$count</td>
  <td data-label="Actions" class="table-actions"><a class="button-link secondary button-link--compact" href="/admin/settings/modules/donations/$id/edit">Edit</a>$publish$archive</td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(5, 'No donation campaigns yet.', 'Create a campaign to publish the public /donate/ fundraising surface.');
}

sub _donation_admin_rows {
    my ($self) = @_;
    my $rows = '';
    for my $donation (@{ $self->{donations}->recent_donations(limit => 100) }) {
        my $created = escape_html(_format_time($donation->{created_at}));
        my $campaign = escape_html($donation->{campaign_title} || 'Campaign');
        my $donor = $donation->{anonymous} ? 'Anonymous' : escape_html($donation->{donor_name} || $donation->{donor_email} || 'Donor');
        my $total = escape_html(DesertCMS::Donations::price_label($donation->{amount_cents}, $donation->{currency}));
        my $status = escape_html($donation->{status} || 'pending');
        my $session = escape_html($donation->{stripe_checkout_session_id} || '');
        $rows .= <<"HTML";
<tr>
  <td data-label="Created">$created</td>
  <td data-label="Campaign">$campaign</td>
  <td data-label="Donor">$donor</td>
  <td data-label="Total">$total</td>
  <td data-label="Status"><span class="status-pill status-pill--neutral">$status</span></td>
  <td data-label="Stripe Session"><code>$session</code></td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(6, 'No donation records yet.', 'Stripe Checkout donation records will appear here.');
}

sub _dispatch_testimonials {
    my ($self, $request) = @_;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    return $self->_not_found unless DesertCMS::Modules::enabled($settings, 'testimonials');
    my $path = $request->{path} || '/testimonials';
    $path =~ s{/+$}{};
    $path = '/testimonials' if $path eq '';

    if ($path eq '/testimonials') {
        return $request->{method} eq 'GET'
            ? $self->_testimonials_index($request, $settings)
            : $self->_method_not_allowed;
    }
    if ($path eq '/testimonials/submit') {
        return $self->_not_found unless _setting_truthy($settings->{testimonials_submissions_enabled});
        return $request->{method} eq 'POST'
            ? $self->_testimonial_submit($request, $settings)
            : ($request->{method} eq 'GET'
                ? $self->_testimonial_submit_page($request, $settings)
                : $self->_method_not_allowed);
    }
    return $self->_not_found;
}

sub _testimonials_index {
    my ($self, $request, $settings, $message, $is_error) = @_;
    my $title = $settings->{testimonials_title} || 'Testimonials';
    my $intro = $settings->{testimonials_intro} || 'Reviews, recommendations, client stories, customer feedback, and community praise.';
    my $cards = join '', map { $self->_testimonial_public_card($_) } @{ $self->{testimonials}->published_testimonials(limit => 500) };
    $cards ||= '<p class="events-empty">No testimonials yet.</p>';
    my $submit = _setting_truthy($settings->{testimonials_submissions_enabled})
        ? '<a class="module-action-link" href="/testimonials/submit/">Share a testimonial</a>'
        : '';
    my $notice = $message ? '<p class="' . ($is_error ? 'events-notice is-error' : 'events-notice') . '">' . escape_html($message) . '</p>' : '';
    my $safe_title = escape_html($title);
    my $safe_intro = escape_html($intro);
    my $body = <<"HTML";
<article class="content module-page testimonials-page directory-shell">
  <header class="events-heading">
    <p class="kicker">Testimonials / Reviews</p>
    <h1>$safe_title</h1>
    <p class="module-intro">$safe_intro</p>
    $submit
  </header>
  $notice
  <section class="events-grid directory-grid testimonials-grid" aria-label="Testimonials and reviews">
    $cards
  </section>
</article>
HTML
    return $self->_testimonials_public_response($title, $intro, '/testimonials/', $body, $is_error ? 400 : 200);
}

sub _testimonial_submit_page {
    my ($self, $request, $settings, $message, $is_error) = @_;
    my $notice = $message ? '<p class="' . ($is_error ? 'events-notice is-error' : 'events-notice') . '">' . escape_html($message) . '</p>' : '';
    my $rating_options = _testimonial_rating_options('');
    my $body = <<"HTML";
<article class="content module-page testimonials-page testimonial-submit">
  <p class="kicker">Testimonials / Reviews</p>
  <h1>Share a Testimonial</h1>
  <p class="module-intro">Send a review, recommendation, client story, customer comment, or community note for approval.</p>
  $notice
  <form method="post" action="/testimonials/submit/" class="public-form">
    <div class="public-form-grid">
      <label class="public-field"><span>Name</span><input name="author_name" required maxlength="180"></label>
      <label class="public-field"><span>Email optional</span><input name="email" type="email" maxlength="180"></label>
      <label class="public-field"><span>Title or role optional</span><input name="author_title" maxlength="180"></label>
      <label class="public-field"><span>Organization optional</span><input name="organization" maxlength="180"></label>
      <label class="public-field"><span>Rating optional</span><select name="rating">$rating_options</select></label>
    </div>
    <label class="public-field public-field--full"><span>Short testimonial</span><textarea name="quote" rows="4" maxlength="1200" required></textarea></label>
    <label class="public-field public-field--full"><span>Additional notes optional</span><textarea name="body" rows="4" maxlength="4000"></textarea></label>
    <label class="comment-honeypot"><span>Website</span><input name="website" tabindex="-1" autocomplete="off"></label>
    <button type="submit">Submit for review</button>
  </form>
</article>
HTML
    return $self->_testimonials_public_response('Share a Testimonial', 'Submit a testimonial for approval.', '/testimonials/submit/', $body, $is_error ? 400 : 200);
}

sub _testimonial_submit {
    my ($self, $request, $settings) = @_;
    return $self->_testimonial_submit_page($request, $settings, 'Thanks. Your testimonial has been received for review.', 0)
        if length($request->param('website') || '');
    my $ok = eval {
        $self->{testimonials}->submit_public(
            author_name     => $request->param('author_name'),
            author_title    => $request->param('author_title'),
            organization    => $request->param('organization'),
            email           => $request->param('email'),
            quote           => $request->param('quote'),
            body            => $request->param('body'),
            rating          => $request->param('rating'),
            ip_address      => $request->{remote_addr} || $request->{ip_address} || '',
            user_agent      => $request->{user_agent} || '',
        );
        1;
    };
    return $ok
        ? $self->_testimonials_index($request, $settings, 'Thanks. Your testimonial has been received for review.', 0)
        : $self->_testimonial_submit_page(
            $request,
            $settings,
            _admin_action_error('The testimonial could not be received.', 'Check the name, quote, email, and rating, then try again.', $@),
            1
        );
}

sub _testimonials_public_response {
    my ($self, $title, $description, $path, $content, $status) = @_;
    return DesertCMS::HTTP->response(
        status  => $status || 200,
        headers => {
            'Content-Type' => 'text/html; charset=utf-8',
            security_headers(),
        },
        body => DesertCMS::Renderer::render_module_page($self->{config}, $self->{db}, {
            title       => $title,
            description => $description,
            path        => $path,
            content     => $content,
            context     => 'testimonials',
        }),
    );
}

sub _testimonial_public_card {
    my ($self, $row) = @_;
    my $author = escape_html($row->{author_name} || 'Reviewer');
    my $quote = escape_html($row->{quote} || '');
    my $body = escape_html($row->{body} || '');
    $body =~ s/\n/<br>/g;
    my $body_html = length $body ? "<p>$body</p>" : '';
    my $byline = _testimonial_byline($row);
    my $rating = _testimonial_rating_html($row->{rating});
    my $source = escape_html(DesertCMS::Testimonials::source_type_label($row->{source_type}));
    my $related = escape_html($row->{related_directory_title} || $row->{related_booking_title} || '');
    my $related_html = length $related ? "<small>Related to $related</small>" : '';
    my $image = $row->{image_path} || '';
    my $image_html = $self->_public_media_img_tag(
        $image,
        '',
        class => 'public-media-img',
        sizes => '(max-width: 760px) 100vw, 360px',
    ) || '<div class="event-card-date" aria-hidden="true">' . substr($author, 0, 1) . '</div>';
    return <<"HTML";
<article class="event-card directory-card testimonial-card">
  $image_html
  <div class="event-card-body">
    <span class="event-time">$source</span>
    <blockquote>$quote</blockquote>
    $body_html
    $rating
    <h2>$author</h2>
    $byline
    $related_html
  </div>
</article>
HTML
}

sub _testimonial_byline {
    my ($row) = @_;
    my @parts = grep { length } ($row->{author_title} || '', $row->{organization} || '');
    return '' unless @parts;
    return '<p class="muted">' . escape_html(join ', ', @parts) . '</p>';
}

sub _testimonial_rating_html {
    my ($rating) = @_;
    my $label = DesertCMS::Testimonials::rating_label($rating);
    return '' unless length $label;
    return '<p class="event-time testimonial-rating">' . escape_html($label) . '</p>';
}

sub _module_testimonials_settings_page {
    my ($self, $request, $session, $session_token, $message) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $settings_nav = $self->_module_setup_nav('testimonials', $session, $settings);
    my $feature = $self->_module_feature_state($settings, 'testimonials');
    my $enabled_state = _module_status_html($feature, $self->{config});
    my $enabled_control = _module_toggle_control($feature, 'module_testimonials_enabled', 'Enable Testimonials / Reviews', $self->{config});
    my $title = escape_html($settings->{testimonials_title} || 'Testimonials');
    my $intro = escape_html($settings->{testimonials_intro} || 'Reviews, recommendations, client stories, customer feedback, and community praise.');
    my $submissions_checked = _setting_truthy($settings->{testimonials_submissions_enabled}) ? 'checked' : '';
    my $feature_eyebrow = _admin_feature_eyebrow($self->{config});
    my $is_contributor_product = DesertCMS::CapabilityPolicy::contributor_product_mode($self->{config});
    my $save_label = $is_contributor_product ? 'Save testimonials settings and rebuild' : 'Save Testimonials and rebuild';
    my $response_title = $is_contributor_product ? 'Testimonials Feature' : 'Testimonials Module';
    my $rows = $self->_testimonial_admin_rows($csrf);
    my $section_nav = _module_section_nav(
        'Testimonials setup sections',
        [ '#module-settings', 'Settings' ],
        [ '#module-testimonials', 'Testimonials' ],
    );

    my $body = <<"HTML";
<section class="editor-workspace">
  $settings_nav
  <section class="panel" id="module-settings">
    <div class="split">
      <div>
        <p class="eyebrow">$feature_eyebrow</p>
        <h1>Testimonials / Reviews</h1>
        <p>Publish approved testimonials, reviews, recommendations, client stories, customer feedback, community praise, and moderated public submissions at <code>/testimonials/</code>.</p>
      </div>
      <div class="button-row">
        <a class="button-link secondary" href="/testimonials/">Open testimonials</a>
        <a class="button-link secondary" href="/admin/settings/modules/testimonials/export">Export CSV</a>
        <a class="button-link" href="/admin/settings/modules/testimonials/new">New testimonial</a>
      </div>
    </div>
    $notice
    $section_nav
    <form method="post" action="/admin/settings/modules/testimonials/save" class="settings-form settings-form--wide">
      <input type="hidden" name="csrf_token" value="$csrf">
      <section class="inspector-panel">
        <h2>Status</h2>
        <dl class="health-list health-list--compact">
          <div><dt>Public path</dt><dd><code>/testimonials/</code></dd></div>
          <div><dt>Status</dt><dd>$enabled_state</dd></div>
        </dl>
        $enabled_control
      </section>
      <section class="inspector-panel">
        <h2>Public Copy</h2>
        <label>
          <span>Title</span>
          <input name="testimonials_title" value="$title" maxlength="100">
        </label>
        <label>
          <span>Intro</span>
          <textarea name="testimonials_intro" rows="4" maxlength="500">$intro</textarea>
        </label>
      </section>
      <section class="inspector-panel">
        <h2>Submissions</h2>
        <label class="checkbox-field">
          <input type="checkbox" name="testimonials_submissions_enabled" value="1" $submissions_checked>
          <span>Accept public testimonials<small>Submissions are held as pending until reviewed and approved.</small></span>
        </label>
      </section>
      <button type="submit">$save_label</button>
    </form>
  </section>
  <section class="panel" id="module-records">
    <div class="split">
      <div>
        <h2>Testimonials</h2>
        <p class="muted">Review public submissions, add manual praise, connect testimonials to directory entries or booking services, and choose which items publish publicly.</p>
      </div>
      <a class="button-link" href="/admin/settings/modules/testimonials/new">New testimonial</a>
    </div>
    <table class="content-table compact-table admin-card-table">
      <thead><tr><th>Testimonial</th><th>Source</th><th>Status</th><th>Rating</th><th>Related</th><th>Actions</th></tr></thead>
      <tbody>$rows</tbody>
    </table>
  </section>
</section>
HTML
    return $self->_html_response($response_title, $body, $session);
}

sub _module_testimonials_settings_save {
    my ($self, $request, $session, $session_token) = @_;
    my $ok = eval {
        my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
        DesertCMS::Settings::set_many($self->{config}, $self->{db}, {
            module_testimonials_enabled => _module_toggle_value($self->_module_feature_state($settings, 'testimonials'), $request),
            testimonials_title => _clean_module_text($request->param('testimonials_title'), 100, 'Testimonials'),
            testimonials_intro => _clean_module_text($request->param('testimonials_intro'), 500, 'Reviews, recommendations, client stories, customer feedback, and community praise.'),
            testimonials_submissions_enabled => $request->param('testimonials_submissions_enabled') ? 1 : 0,
        });
        $self->{testimonials}->clear_settings_cache;
        $self->{content}->rebuild_all;
        1;
    };
    if (!$ok) {
        return $self->_module_testimonials_settings_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The Testimonials settings could not be saved.',
                'Check the title, intro, submission setting, and feature availability, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'settings.module_testimonials_saved',
        subject_type => 'settings',
        details      => { rebuilt => 1 },
    );
    return $self->_module_testimonials_settings_page($request, $session, $session_token, 'Testimonials saved and public site rebuilt.');
}

sub _testimonial_form {
    my ($self, $request, $session, $session_token, $id, $message) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $row = $id ? $self->{testimonials}->get($id) : undef;
    return $self->_not_found if $id && !$row;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $settings_nav = $self->_module_setup_nav('testimonials', $session, $settings);
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $action = $row ? '/admin/settings/modules/testimonials/' . int($row->{id}) . '/update' : '/admin/settings/modules/testimonials/create';
    my $heading = $row ? 'Edit Testimonial' : 'New Testimonial';
    my $author = escape_html($row ? $row->{author_name} : '');
    my $slug = escape_html($row ? $row->{slug} : '');
    my $author_title = escape_html($row ? $row->{author_title} : '');
    my $organization = escape_html($row ? $row->{organization} : '');
    my $quote = escape_html($row ? $row->{quote} : '');
    my $body_text = escape_html($row ? $row->{body} : '');
    my $email = escape_html($row ? $row->{submitter_email} : '');
    my $note = escape_html($row ? $row->{submission_note} : '');
    my $status_options = _testimonial_status_options($row ? ($row->{status} || 'draft') : 'draft');
    my $source_options = _testimonial_source_type_options($row ? ($row->{source_type} || 'manual') : 'manual');
    my $rating_options = _testimonial_rating_options($row ? $row->{rating} : '');
    my $image_options = $self->_directory_feature_image_options($row ? $row->{image_path} : '');
    my $directory_options = $self->_testimonial_directory_options($row ? $row->{related_directory_entry_id} : 0);
    my $booking_options = $self->_testimonial_booking_options($row ? $row->{related_booking_service_id} : 0);
    my $featured = $row && $row->{featured} ? 'checked' : '';
    my $sort_order = escape_html($row ? ($row->{sort_order} || 100) : 100);
    my $form_section_nav = _module_section_nav(
        'Testimonial editor sections',
        [ '#testimonial-content', 'Testimonial' ],
        [ '#testimonial-review', 'Review State' ],
        [ '#testimonial-related', 'Related Surface' ],
        [ '#testimonial-display', 'Display' ],
    );

    my $body = <<"HTML";
<section class="editor-workspace">
  $settings_nav
  <section class="panel">
    <div class="split">
      <div>
        <p class="eyebrow">Testimonials</p>
        <h1>$heading</h1>
