    </div>
    $notice
    $form_section_nav
    <form method="post" action="$action" class="settings-form settings-form--wide">
      <input type="hidden" name="csrf_token" value="$csrf">
      <section class="inspector-panel" id="testimonial-content">
        <h2>Testimonial</h2>
        <div class="field-row">
          <label>
            <span>Display name</span>
            <input name="author_name" value="$author" required maxlength="180">
          </label>
          <label>
            <span>Slug</span>
            <input name="slug" value="$slug" maxlength="160" placeholder="Generated from name">
          </label>
        </div>
        <div class="field-row">
          <label><span>Title or role</span><input name="author_title" value="$author_title" maxlength="180"></label>
          <label><span>Organization</span><input name="organization" value="$organization" maxlength="180"></label>
        </div>
