          <label><span>Source</span><select name="source_type">$source_options</select></label>
          <label><span>Rating</span><select name="rating">$rating_options</select></label>
        </div>
        <label><span>Submitter email optional</span><input name="submitter_email" type="email" value="$email" maxlength="180"></label>
        <label><span>Internal note</span><textarea name="submission_note" rows="4" maxlength="1000">$note</textarea></label>
