sub _testimonial_create {
    my ($self, $request, $session, $session_token) = @_;
    return $self->_testimonial_save($request, $session, $session_token, undef);
}

sub _testimonial_update {
    my ($self, $request, $session, $session_token, $id) = @_;
    return $self->_testimonial_save($request, $session, $session_token, $id);
}

sub _testimonial_save {
    my ($self, $request, $session, $session_token, $id) = @_;
    my $row = eval {
        my $saved = $self->{testimonials}->save_testimonial(
            _testimonial_args_from_request($request),
            id => $id,
            ip_address => $request->{remote_addr} || $request->{ip_address} || '',
            user_agent => $request->{user_agent} || '',
        );
        $self->{content}->rebuild_all;
        $saved;
    };
    if (!$row) {
        return $self->_testimonial_form(
            $request,
            $session,
            $session_token,
            $id,
            _admin_action_error(
                'The testimonial could not be saved.',
                'Check the display name, quote, email, rating, related entries, and status, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => $id ? 'testimonials.updated' : 'testimonials.created',
        subject_type => 'testimonial',
        subject_id   => $row->{id},
        details      => { rebuilt => 1 },
    );
    return DesertCMS::HTTP->redirect('/admin/settings/modules/testimonials?notice=testimonial-saved', { security_headers() });
}

sub _testimonial_status {
    my ($self, $request, $session, $session_token, $id, $action) = @_;
    my $ok = eval {
        my $row;
        if ($action eq 'publish') {
            $row = $self->{testimonials}->publish_testimonial($id);
        } elsif ($action eq 'reject') {
            $row = $self->{testimonials}->reject_testimonial($id);
        } else {
            $row = $self->{testimonials}->archive_testimonial($id);
        }
        $self->{content}->rebuild_all;
        $self->_audit_admin_action(
            $session,
            action       => 'testimonials.' . $action,
            subject_type => 'testimonial',
            subject_id   => $row->{id},
            details      => { rebuilt => 1 },
        );
        1;
    };
    return $self->_module_testimonials_settings_page(
        $request,
        $session,
        $session_token,
        $ok
            ? 'Testimonial updated and public site rebuilt.'
            : _admin_action_error('The testimonial status could not be changed.', 'Refresh the Testimonials page and try again.', $@)
    );
}

sub _testimonial_export {
    my ($self, $request, $session, $session_token) = @_;
    return DesertCMS::HTTP->response(
        status => 200,
        headers => {
            'Content-Type' => 'text/csv; charset=utf-8',
            'Content-Disposition' => 'attachment; filename="testimonials.csv"',
            security_headers(),
        },
        body => $self->{testimonials}->csv_export,
    );
}

sub _testimonial_admin_rows {
    my ($self, $csrf) = @_;
    my $rows = '';
    for my $row (@{ $self->{testimonials}->list_admin }) {
        my $id = int($row->{id});
        my $author = escape_html($row->{author_name} || 'Reviewer');
        my $quote = escape_html($row->{quote} || '');
        my $source = escape_html(DesertCMS::Testimonials::source_type_label($row->{source_type}));
        my $status_value = $row->{status} || 'draft';
        my $state = $status_value eq 'published' ? 'ok' : ($status_value eq 'pending' ? 'warn' : 'neutral');
        my $status = _fleet_state_pill($state, DesertCMS::Testimonials::status_label($status_value));
        my $rating = escape_html(DesertCMS::Testimonials::rating_label($row->{rating}) || 'No rating');
        my $related = escape_html($row->{related_directory_title} || $row->{related_booking_title} || '');
        my $publish = $status_value eq 'published' ? '' : <<"HTML";
<form method="post" action="/admin/settings/modules/testimonials/$id/publish" class="inline-form">
  <input type="hidden" name="csrf_token" value="$csrf">
  <button type="submit" class="button-link secondary button-link--compact">Approve</button>
</form>
HTML
        my $reject = $status_value eq 'rejected' ? '' : <<"HTML";
<form method="post" action="/admin/settings/modules/testimonials/$id/reject" class="inline-form" data-confirm-title="Reject this testimonial?" data-confirm-message="The testimonial stays in the database, but it will not appear publicly." data-confirm-action="Reject">
  <input type="hidden" name="csrf_token" value="$csrf">
  <button type="submit" class="button-link secondary button-link--compact button-link--warn">Reject</button>
</form>
HTML
        my $archive = $status_value eq 'archived' ? '' : <<"HTML";
<form method="post" action="/admin/settings/modules/testimonials/$id/archive" class="inline-form" data-confirm-title="Archive this testimonial?" data-confirm-message="The testimonial will leave the public page, but its record stays in the database." data-confirm-action="Archive">
  <input type="hidden" name="csrf_token" value="$csrf">
  <button type="submit" class="button-link secondary button-link--compact">Archive</button>
</form>
HTML
        $rows .= <<"HTML";
<tr>
  <td data-label="Testimonial"><strong>$author</strong><br><small>$quote</small></td>
  <td data-label="Source">$source</td>
  <td data-label="Status">$status</td>
  <td data-label="Rating">$rating</td>
  <td data-label="Related">$related</td>
  <td data-label="Actions" class="table-actions">
    <a class="button-link secondary button-link--compact" href="/admin/settings/modules/testimonials/$id/edit">Edit</a>
    $publish
    $reject
    $archive
  </td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(6, 'No testimonials yet.', 'Add praise manually or enable public submissions for moderated testimonials.');
}

sub _testimonial_status_options {
    my ($selected) = @_;
    $selected ||= 'draft';
    return join '', map {
        my $value = $_;
        my $label = DesertCMS::Testimonials::status_label($value);
        my $is_selected = $value eq $selected ? ' selected' : '';
        '<option value="' . escape_html($value) . '"' . $is_selected . '>' . escape_html($label) . '</option>';
    } @{ DesertCMS::Testimonials::statuses() };
}

sub _testimonial_source_type_options {
    my ($selected) = @_;
    $selected ||= 'manual';
    return join '', map {
        my $value = $_;
        my $label = DesertCMS::Testimonials::source_type_label($value);
        my $is_selected = $value eq $selected ? ' selected' : '';
        '<option value="' . escape_html($value) . '"' . $is_selected . '>' . escape_html($label) . '</option>';
    } @{ DesertCMS::Testimonials::source_types() };
}

sub _testimonial_rating_options {
    my ($selected) = @_;
    $selected = defined $selected ? "$selected" : '';
    my $html = '<option value="">No rating</option>';
    for my $rating (1 .. 5) {
        my $is_selected = $selected eq "$rating" ? ' selected' : '';
        $html .= '<option value="' . $rating . '"' . $is_selected . '>' . escape_html(DesertCMS::Testimonials::rating_label($rating)) . '</option>';
    }
    return $html;
}

sub _testimonial_directory_options {
    my ($self, $selected) = @_;
    $selected = int($selected || 0);
    my $rows = eval {
        $self->{db}->dbh->selectall_arrayref(
            q{
                SELECT id, title, status
                FROM directory_entries
                ORDER BY status = 'published' DESC, title ASC, id ASC
                LIMIT 500
            },
            { Slice => {} }
        );
    } || [];
    my $html = '<option value="">No directory link</option>';
    for my $row (@{$rows}) {
        my $id = int($row->{id} || 0);
        my $label = escape_html(($row->{title} || 'Directory entry') . ' (' . ($row->{status} || 'draft') . ')');
        my $is_selected = $id == $selected ? ' selected' : '';
        $html .= qq{<option value="$id"$is_selected>$label</option>};
    }
    return $html;
}

sub _testimonial_booking_options {
    my ($self, $selected) = @_;
    $selected = int($selected || 0);
    my $rows = eval {
        $self->{db}->dbh->selectall_arrayref(
            q{
                SELECT id, title, status
                FROM booking_services
                ORDER BY status = 'published' DESC, title ASC, id ASC
                LIMIT 500
            },
            { Slice => {} }
        );
    } || [];
    my $html = '<option value="">No booking service link</option>';
    for my $row (@{$rows}) {
        my $id = int($row->{id} || 0);
        my $label = escape_html(($row->{title} || 'Booking service') . ' (' . ($row->{status} || 'draft') . ')');
        my $is_selected = $id == $selected ? ' selected' : '';
        $html .= qq{<option value="$id"$is_selected>$label</option>};
    }
    return $html;
}

sub _testimonial_args_from_request {
    my ($request) = @_;
    return (
        author_name                => $request->param('author_name'),
        slug                       => $request->param('slug'),
        author_title               => $request->param('author_title'),
        organization               => $request->param('organization'),
        quote                      => $request->param('quote'),
        body                       => $request->param('body'),
        status                     => $request->param('status'),
        source_type                => $request->param('source_type'),
        rating                     => $request->param('rating'),
        submitter_email            => $request->param('submitter_email'),
        submission_note            => $request->param('submission_note'),
        related_directory_entry_id => $request->param('related_directory_entry_id'),
        related_booking_service_id => $request->param('related_booking_service_id'),
        image_path                 => $request->param('image_path'),
        featured                   => $request->param('featured'),
        sort_order                 => $request->param('sort_order'),
    );
}

sub _module_membership_settings_page {
    my ($self, $request, $session, $session_token, $message) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $settings_nav = $self->_module_setup_nav('membership', $session, $settings);
    my $membership_feature = $self->_module_feature_state($settings, 'membership');
    my $payments_feature = $self->_module_feature_state($settings, 'membership_payments');
    my $enabled_state = _module_status_html($membership_feature, $self->{config});
    my $payments_state = _module_status_html($payments_feature, $self->{config});
    my $enabled_control = _module_toggle_control($membership_feature, 'module_membership_enabled', 'Enable Membership / Gated Content', $self->{config});
    my $payment_readiness = $self->{membership}->payment_readiness;
    my $payments_summary = _fleet_state_pill($payment_readiness->{state}, $payment_readiness->{label})
        . '<small>' . escape_html($payment_readiness->{summary}) . '</small>';
    my $membership_title = escape_html($settings->{membership_title} || 'Members');
    my $membership_intro = escape_html($settings->{membership_intro} || 'Sign in for private pages, member resources, gated downloads, and client portal collections.');
    my $signup_checked = _setting_truthy($settings->{membership_signup_enabled}) ? 'checked' : '';
    my $notify_checked = _setting_truthy($settings->{membership_notify_postmark_enabled}) ? 'checked' : '';
    my $notify_email = escape_html($settings->{membership_notification_email} || '');
    my $feature_eyebrow = _admin_feature_eyebrow($self->{config});
    my $is_contributor_product = DesertCMS::CapabilityPolicy::contributor_product_mode($self->{config});
    my $save_label = $is_contributor_product ? 'Save member settings and rebuild' : 'Save Membership and rebuild';
    my $response_title = $is_contributor_product ? 'Members Feature' : 'Membership / Gated Content Module';
    my $group_rows = $self->_membership_group_rows;
    my $member_rows = $self->_membership_member_rows;
    my $invite_rows = $self->_membership_invite_rows;
    my $resource_rows = $self->_membership_resource_rows($csrf);
    my $payment_rows = $self->_membership_payment_rows;
    my $group_options = $self->_membership_group_options(0, 'No group');
    my $resource_group_options = $self->_membership_group_options(0, 'All members');
    my $media_options = $self->_membership_media_asset_options(0);
    my $resource_access_options = _membership_resource_access_options('members');
    my $section_nav = _module_section_nav(
