        [ '#module-settings', 'Portal Settings' ],
        [ '#module-members', 'Members' ],
        [ '#module-groups', 'Groups' ],
        [ '#module-invites', 'Invites' ],
        [ '#module-resources', 'Member Resources' ],
        [ '#module-payments', 'Membership Payments' ],
