sub _settings_upgrade_page {
    my ($self, $request, $session, $session_token, $message) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    if (!$message && $request->param('queued')) {
        $message = 'Upgrade staged and queued for the root worker.';
    } elsif (!$message && $request->param('existing')) {
        $message = 'That release archive is already queued, running, or applied. No duplicate job was created.';
    }
    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $settings_nav = $self->_settings_nav('upgrade', $session);
    my $upgrade_dir = escape_html(DesertCMS::Upgrade::upgrade_dir($self->{config}));
    my $app_root = escape_html(DesertCMS::Upgrade::default_app_root());
    my $app_version = escape_html(DesertCMS::Version::current());
    my $worker_cmd = escape_html('doas perl ' . DesertCMS::Upgrade::default_app_root() . '/tools/openbsd-apply-upgrade.pl --install-cron');
    my $job_rows = $self->_upgrade_job_rows;

    my $body = <<"HTML";
<section class="editor-workspace">
  $settings_nav
  <section class="panel">
    <div class="split">
      <div>
        <p class="eyebrow">Settings</p>
        <h1>Upgrade DesertCMS</h1>
        <p>Upload a DesertCMS release archive. The admin app stages it under the site data directory; the root worker backs up the current app, applies the release, runs migrations, rebuilds sites, and restarts services.</p>
      </div>
    </div>
    $notice
    <section class="inspector-panel">
      <h2>Current Install</h2>
      <dl class="health-list health-list--compact">
        <div><dt>Running version</dt><dd><span class="status-pill status-pill--neutral">v$app_version</span></dd></div>
        <div><dt>App root</dt><dd><code>$app_root</code></dd></div>
      </dl>
    </section>
    <form method="post" action="/admin/settings/upgrade/apply" enctype="multipart/form-data" class="settings-form settings-form--wide upgrade-form">
      <input type="hidden" name="csrf_token" value="$csrf">
      <section class="inspector-panel">
        <h2>Release Archive</h2>
        <label class="upgrade-drop" data-upgrade-drop>
          <input type="file" name="upgrade_archive" accept=".tar.gz,.tgz,application/gzip" required data-upgrade-input>
          <span class="upgrade-drop-main">Drop the newest DesertCMS <code>.tar.gz</code> release here</span>
          <span class="upgrade-drop-sub">The archive must contain the CMS app files, installer, tools, and default theme.</span>
          <span class="upgrade-file-state" data-upgrade-file-state>No archive selected</span>
        </label>
        <button type="submit">Stage and queue upgrade</button>
      </section>
      <section class="inspector-panel">
        <h2>Worker</h2>
        <dl class="health-list health-list--compact">
          <div><dt>Staging directory</dt><dd><code>$upgrade_dir</code></dd></div>
        </dl>
        <p class="muted">The root worker must be installed once on each server. New installs add it automatically; existing installs can run:</p>
        <pre class="mono-block">$worker_cmd</pre>
      </section>
    </form>
  </section>
  <section class="panel" id="upgrade-jobs">
    <h2>Recent Upgrade Jobs</h2>
    <table class="content-table compact-table admin-card-table">
      <thead><tr><th>Status</th><th>Release</th><th>Updated</th><th>Message</th></tr></thead>
      <tbody>$job_rows</tbody>
    </table>
  </section>
</section>
HTML

    return $self->_html_response('Upgrade DesertCMS', $body, $session);
}

sub _settings_upgrade_apply {
    my ($self, $request, $session, $session_token) = @_;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $job = eval {
        DesertCMS::Upgrade::stage_upload(
            $self->{config},
            upload                => $request->upload('upgrade_archive'),
            submitted_by_user_id  => $session->{user_id},
            submitted_by_username => $session->{username},
            channel               => $settings->{operations_upgrade_channel} || 'stable',
        );
    };
    if (!$job) {
        return $self->_settings_upgrade_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The upgrade archive could not be staged.',
                'Upload a valid DesertCMS runtime archive and confirm the upgrade directory is writable, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => $job->{reused} ? 'upgrade.existing_release_reused' : 'upgrade.queued',
        subject_type => 'upgrade_job',
        details      => { id => $job->{id} || '', filename => $job->{filename} || '', sha256 => $job->{sha256} || '' },
    );
    my $flag = $job->{reused} ? 'existing=1' : 'queued=1';
    return DesertCMS::HTTP->redirect("/admin/settings/upgrade?$flag", { security_headers() });
}

sub _upgrade_job_rows {
    my ($self) = @_;
    my $rows = '';
    for my $job (@{DesertCMS::Upgrade::latest_jobs($self->{config}, limit => 10)}) {
        my $status = escape_html($job->{status} || 'queued');
        my $kind = ($job->{kind} || 'upgrade') eq 'rollback' ? 'Rollback' : 'Upgrade';
        my $filename = escape_html($job->{filename} || basename($job->{archive} || 'release.tar.gz'));
        my $channel = escape_html($job->{channel} || '');
        my $sha = escape_html(substr($job->{sha256} || '', 0, 16));
        my $updated = escape_html(_format_time($job->{updated_at} || $job->{submitted_at}));
        my $message = escape_html($job->{message} || '');
        my $detail = $sha ? qq{<br><span class="muted">sha256 $sha...</span>} : '';
        $detail .= qq{<br><span class="muted">channel $channel</span>} if length $channel;
        my $class = $status eq 'done' ? 'ok' : $status eq 'failed' ? 'warn' : '';
        $rows .= <<"HTML";
<tr>
  <td data-label="Status"><span class="status-pill $class">$status</span></td>
  <td data-label="Job"><span class="status-pill status-pill--neutral">$kind</span><br><code>$filename</code>$detail</td>
  <td data-label="Updated">$updated</td>
  <td data-label="Message">$message</td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(4, 'No upgrade or rollback jobs yet.', 'Staged upgrades and queued rollbacks will appear here after they are submitted.');
}

