sub _settings_operations_save {
    my ($self, $request, $session, $session_token) = @_;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $interval = int($request->param('operations_backup_interval_hours') || 24);
    $interval = 1 if $interval < 1;
    $interval = 720 if $interval > 720;
    my $hook_url = _trim_text($request->param('operations_offsite_hook_url'));
    if (length $hook_url && $hook_url !~ m{\Ahttps?://}i) {
        return $self->_settings_operations_page($request, $session, $session_token, 'Offsite hook URL must start with http:// or https://.');
    }
    my $token = _trim_text($request->param('operations_offsite_hook_token'));
    $token = $settings->{operations_offsite_hook_token} || '' if !length $token;
    $token = '' if $request->param('operations_offsite_hook_token_clear');
    my $channel = lc(_trim_text($request->param('operations_upgrade_channel')) || 'stable');
    $channel = 'stable' unless $channel =~ /\A(?:stable|beta|nightly)\z/;

    DesertCMS::Settings::set_many($self->{config}, $self->{db}, {
        operations_backup_schedule_enabled => $request->param('operations_backup_schedule_enabled') ? 1 : 0,
        operations_backup_interval_hours   => $interval,
        operations_offsite_hook_url        => $hook_url,
        operations_offsite_hook_token      => $token,
        operations_upgrade_channel         => $channel,
    });
    $self->_audit_admin_action(
        $session,
        action       => 'operations.settings_saved',
        subject_type => 'settings',
        details      => { backup_interval_hours => $interval, offsite_hook_configured => length($hook_url) ? 1 : 0, upgrade_channel => $channel },
    );
    return $self->_settings_operations_page($request, $session, $session_token, 'Operations settings saved.');
}

sub _settings_operations_rebuild_all {
    my ($self, $request, $session, $session_token) = @_;
    my $summary = $self->{operations}->rebuild_all_sites;
    $self->_audit_admin_action($session, action => 'operations.rebuild_all', subject_type => 'operations', details => $summary);
    return $self->_settings_operations_page($request, $session, $session_token, _operations_summary_message('Rebuild all', $summary));
}

sub _settings_operations_backup_all {
    my ($self, $request, $session, $session_token) = @_;
    my $summary = $self->{operations}->backup_all_sites(user_id => $session->{user_id});
    $self->_audit_admin_action($session, action => 'operations.backup_all', subject_type => 'operations', details => _operation_audit_summary($summary));
    return $self->_settings_operations_page($request, $session, $session_token, _operations_summary_message('Backup all', $summary));
}

sub _settings_operations_submit_all_sitemaps {
    my ($self, $request, $session, $session_token) = @_;
