    return $self->_settings_operations_page($request, $session, $session_token, _operations_summary_message('Submit all sitemaps', $summary));
}

sub _settings_operations_test_restore {
    my ($self, $request, $session, $session_token) = @_;
    my $result = eval { $self->{operations}->test_restore(backup_id => int($request->param('backup_id') || 0)) };
    if (!$result) {
        return $self->_settings_operations_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The restore test could not be completed.',
                'Choose an available master backup and confirm the temporary restore directory is writable, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'operations.restore_tested',
        subject_type => 'backup',
        details      => { filename => $result->{filename}, file_count => $result->{file_count}, db_integrity => $result->{db_integrity} },
    );
    my $msg = 'Restore test passed for ' . ($result->{filename} || 'backup') . ': '
        . int($result->{file_count} || 0) . ' file(s), database integrity '
        . ($result->{db_integrity} || 'ok') . '.';
    return $self->_settings_operations_page($request, $session, $session_token, $msg);
}

sub _settings_operations_support_bundle {
    my ($self, $request, $session, $session_token) = @_;
    my $bundle = eval {
        $self->{operations}->create_support_bundle(
            created_by_user_id   => $session->{user_id},
            created_by_username  => $session->{username},
        );
    };
    if (!$bundle) {
        return $self->_settings_operations_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The support bundle could not be created.',
                'Check that the support bundle directory is writable, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'operations.support_bundle_created',
        subject_type => 'support_bundle',
        details      => { filename => $bundle->{filename}, bytes => $bundle->{bytes} },
    );
    return $self->_settings_operations_page($request, $session, $session_token, 'Support bundle created: ' . ($bundle->{filename} || 'bundle') . '.');
}

sub _settings_operations_download_support_bundle {
    my ($self, $request, $session, $session_token, $filename) = @_;
    my $path = eval { $self->{operations}->support_bundle_path($filename) };
    return $self->_not_found unless $path;
    open my $fh, '<:raw', $path or return $self->_not_found;
    local $/;
    my $body = <$fh>;
    close $fh;
    return DesertCMS::HTTP->response(
        status  => 200,
        headers => {
            'Content-Type'        => 'application/gzip',
            'Content-Disposition' => 'attachment; filename="' . basename($path) . '"',
            security_headers(),
        },
        body => $body,
    );
}

sub _settings_operations_rollback {
    my ($self, $request, $session, $session_token) = @_;
    my $job = eval {
        DesertCMS::Upgrade::queue_rollback(
            $self->{config},
            filename              => $request->param('backup_filename'),
            submitted_by_user_id  => $session->{user_id},
            submitted_by_username => $session->{username},
        );
    };
    if (!$job) {
        return $self->_settings_operations_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The rollback could not be queued.',
                'Choose an available app rollback backup and confirm the root worker is installed, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => $job->{reused} ? 'operations.rollback_reused' : 'operations.rollback_queued',
        subject_type => 'upgrade_job',
        details      => { id => $job->{id}, filename => $job->{filename}, sha256 => $job->{sha256} },
    );
    my $message = $job->{reused}
        ? 'That rollback is already queued, running, or applied.'
        : 'Rollback queued for the root worker.';
    return $self->_settings_operations_page($request, $session, $session_token, $message);
}

sub _operations_backup_options {
    my ($self) = @_;
    my $rows = eval { DesertCMS::Backup::list_backups($self->{config}, $self->{db}) } || [];
    my $html = '';
    for my $backup (@{$rows}) {
        my $id = int($backup->{id} || 0);
        my $label = escape_html(($backup->{filename} || 'backup') . ' - ' . _format_time($backup->{created_at}));
        $html .= qq{<option value="$id">$label</option>};
    }
    return $html || '<option value="">Create a master backup first</option>';
}

sub _operations_rollback_rows {
    my ($self, $csrf) = @_;
    my $rows = '';
    for my $backup (@{DesertCMS::Upgrade::available_rollbacks($self->{config})}) {
        my $filename = escape_html($backup->{filename} || '');
        my $created = escape_html(_format_time($backup->{mtime}));
        my $size = escape_html(_format_bytes($backup->{bytes} || 0));
        $rows .= <<"HTML";
<tr>
  <td data-label="Backup"><code>$filename</code></td>
  <td data-label="Created">$created</td>
  <td data-label="Size">$size</td>
  <td data-label="Action">
    <form method="post" action="/admin/settings/operations/rollback" class="inline-form" data-confirm-title="Queue this rollback?" data-confirm-message="The root worker will restore this DesertCMS app backup after creating a fresh safety backup of the current app." data-confirm-action="Queue rollback" data-loading-label="Queueing...">
      <input type="hidden" name="csrf_token" value="$csrf">
      <input type="hidden" name="backup_filename" value="$filename">
      <button type="submit">Queue rollback</button>
    </form>
  </td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(4, 'No app rollback backups found.', 'A rollback backup is created before each successful upgrade or rollback.');
}

sub _operations_support_bundle_rows {
    my ($self) = @_;
    my $rows = '';
    for my $bundle (@{$self->{operations}->support_bundles}) {
        my $filename = escape_html($bundle->{filename} || '');
        my $created = escape_html(_format_time($bundle->{mtime}));
        my $size = escape_html(_format_bytes($bundle->{bytes} || 0));
        $rows .= <<"HTML";
<tr>
  <td data-label="Bundle"><code>$filename</code></td>
  <td data-label="Created">$created</td>
  <td data-label="Size">$size</td>
  <td data-label="Download"><a class="button-link secondary" href="/admin/settings/operations/support-bundle/$filename">Download</a></td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(4, 'No support bundles yet.', 'Create a redacted support bundle when troubleshooting an install or preparing a support handoff.');
}

sub _operations_channel_options {
    my ($current) = @_;
    $current ||= 'stable';
    my @options = (
        [ stable  => 'Stable' ],
        [ beta    => 'Beta' ],
        [ nightly => 'Nightly' ],
    );
    my $html = '';
    for my $option (@options) {
        my ($value, $label) = @{$option};
        my $selected = $value eq $current ? ' selected' : '';
        $html .= '<option value="' . escape_html($value) . '"' . $selected . '>' . escape_html($label) . '</option>';
    }
    return $html;
}

sub _operations_notice {
    my ($request) = @_;
    return '' unless $request;
    return 'Operations settings saved.' if $request->param('saved');
    return '';
}

sub _operations_summary_message {
    my ($label, $summary) = @_;
    my $message = "$label finished. " . int($summary->{ok_count} || 0) . ' site(s) completed successfully; ' . int($summary->{failed} || 0) . ' need attention.';
    if ($summary->{failed}) {
        my @failed = grep { ($_->{status} || '') ne 'ok' } @{ $summary->{results} || [] };
        my @pieces;
        for my $row (@failed[0 .. (@failed > 2 ? 2 : $#failed)]) {
            next unless $row;
            push @pieces, ($row->{label} || $row->{site_id} || $row->{domain} || 'site') . ': ' . _clean_error($row->{error} || 'action did not complete');
        }
        $message .= ' Review these first: ' . join ' ', @pieces if @pieces;
    }
    return $message;
}

sub _operation_audit_summary {
    my ($summary) = @_;
    my %copy = %{$summary || {}};
    for my $row (@{ $copy{results} || [] }) {
        delete $row->{details}{archive} if ref $row->{details} eq 'HASH';
    }
    return \%copy;
}

sub _trim_text {
    my ($value) = @_;
    $value = '' unless defined $value;
    $value =~ s/^\s+|\s+\z//g;
    return $value;
}

sub _forms_submission_rows {
    my ($self) = @_;
    my $rows = '';
    for my $submission (@{$self->{forms}->recent_submissions(limit => 50)}) {
        my $id = int($submission->{id} || 0);
        my $created = escape_html(_format_time($submission->{created_at}));
        my $type = escape_html(DesertCMS::Forms::form_type_label($submission->{form_key}));
        my $name = escape_html($submission->{name} || 'Anonymous');
        my $email = escape_html($submission->{email} || '');
        my $from = length $email ? "$name<br><span class=\"muted\">$email</span>" : $name;
        my @details;
        push @details, 'Phone: ' . escape_html($submission->{phone}) if length($submission->{phone} || '');
        push @details, 'Organization: ' . escape_html($submission->{organization}) if length($submission->{organization} || '');
        push @details, 'Subject: ' . escape_html($submission->{subject}) if length($submission->{subject} || '');
        push @details, 'Preferred: ' . escape_html($submission->{preferred_date}) if length($submission->{preferred_date} || '');
        push @details, 'Event: ' . escape_html($submission->{event_date}) if length($submission->{event_date} || '');
        push @details, 'Guests: ' . escape_html($submission->{guest_count}) if defined $submission->{guest_count} && $submission->{guest_count} ne '';
        push @details, 'Budget: ' . escape_html($submission->{budget}) if length($submission->{budget} || '');
        my $details = @details ? join('<br>', @details) : '<span class="muted">No extra details</span>';
        my $message = $submission->{message} || '';
        $message = substr($message, 0, 320) . '...' if length($message) > 320;
        my $safe_message = escape_html($message);
        $safe_message =~ s/\n/<br>/g;
        my $files = _forms_submission_file_links($id, $submission);
        my $notification = escape_html($submission->{notification_status} || 'pending');
        my $notification_error = escape_html($submission->{notification_error} || '');
        my $notification_cell = '<span class="status-pill">' . $notification . '</span>';
        $notification_cell .= '<br><span class="muted">' . $notification_error . '</span>' if length $notification_error;
        my $status = escape_html($submission->{status} || 'new');
        $rows .= <<"HTML";
<tr>
  <td data-label="Received">$created</td>
  <td data-label="Type"><span class="status-pill status-pill--neutral">$type</span></td>
  <td data-label="From">$from</td>
  <td data-label="Details">$details</td>
  <td data-label="Message">$safe_message</td>
  <td data-label="Files">$files</td>
  <td data-label="Notification">$notification_cell</td>
  <td data-label="Status"><span class="status-pill">$status</span></td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(
        8,
        'No form submissions yet.',
        'Messages, quote requests, applications, intake forms, RSVPs, and uploaded files will appear here for review.'
    );
}

sub _forms_submission_upload {
    my ($self, $request, $session, $session_token, $submission_id, $upload_index) = @_;
    my $download = eval { $self->{forms}->submission_upload(id => $submission_id, index => $upload_index) };
    return $self->_not_found unless $download && $download->{path};

    open my $fh, '<:raw', $download->{path} or return $self->_not_found;
    local $/;
    my $body = <$fh>;
    close $fh;

    $self->_audit_admin_action(
        $session,
        action       => 'forms.upload_downloaded',
        subject_type => 'form_submission',
        subject_id   => int($submission_id || 0),
        details      => {
            filename => $download->{filename},
            mime     => $download->{mime},
            bytes    => int($download->{bytes} || 0),
        },
    );

    return DesertCMS::HTTP->response(
        status  => 200,
        headers => {
            'Content-Type'        => $download->{mime} || 'application/octet-stream',
            'Content-Disposition' => 'attachment; filename="' . _download_header_filename($download->{filename}) . '"',
            'Cache-Control'       => 'private, no-store',
            security_headers(),
        },
        body => $body,
    );
}

sub _forms_submission_file_links {
    my ($id, $submission) = @_;
    my $files = DesertCMS::Forms::submission_files($submission);
    return '<span class="muted">None</span>' unless @{$files};
    my @links;
    for my $index (0 .. $#{$files}) {
        my $file = $files->[$index] || {};
        my $name = escape_html($file->{filename} || 'upload');
        my $bytes = escape_html(_forms_bytes_label($file->{bytes} || 0));
        my $href = '/admin/settings/modules/forms/submissions/' . int($id) . '/uploads/' . int($index);
        push @links, qq{<a href="$href">$name</a><br><span class="muted">$bytes</span>};
    }
    return join '<br>', @links;
}

sub _forms_public_type_options {
    my ($settings, $selected) = @_;
    my %enabled = map { $_ => 1 } @{ DesertCMS::Forms::enabled_form_types($settings) };
    $selected = 'contact' unless $enabled{$selected || ''};
    my $html = '';
    for my $type (@{ DesertCMS::Forms::form_types() }) {
        next unless $enabled{$type->{key}};
        my $value = escape_html($type->{key});
        my $label = escape_html($type->{label});
        my $sel = ($type->{key} eq $selected) ? ' selected' : '';
        $html .= qq{<option value="$value"$sel>$label</option>};
    }
    return $html || '<option value="contact">Contact</option>';
}

sub _forms_enabled_type_controls {
    my ($settings) = @_;
    my %enabled = map { $_ => 1 } @{ DesertCMS::Forms::enabled_form_types($settings) };
    my $html = '';
    for my $type (@{ DesertCMS::Forms::form_types() }) {
        my $checked = $enabled{$type->{key}} ? 'checked' : '';
        my $key = escape_html($type->{key});
        my $label = escape_html($type->{label});
        my $description = escape_html($type->{description});
        $html .= qq{<label class="checkbox-field"><input type="checkbox" name="forms_type_$key" value="1" $checked><span>$label<small>$description</small></span></label>};
    }
    return $html;
}

sub _forms_type_count_summary {
    my ($counts) = @_;
    $counts ||= {};
    my @parts;
    for my $type (@{ DesertCMS::Forms::form_types() }) {
        my $count = int($counts->{$type->{key}} || 0);
        push @parts, escape_html($type->{label}) . ': ' . $count;
    }
    return join '<br>', @parts;
}

sub _clean_enabled_form_types {
    my ($request) = @_;
    my @keys;
    for my $type (@{ DesertCMS::Forms::form_types() }) {
        push @keys, $type->{key} if $request->param('forms_type_' . $type->{key});
    }
    @keys = ('contact') unless @keys;
    return join ',', @keys;
}

sub _clean_forms_upload_mb {
    my ($value) = @_;
    $value = 10 unless defined $value && $value =~ /\A\s*\d{1,3}\s*\z/;
    my $mb = int($value);
    $mb = 1 if $mb < 1;
    $mb = 64 if $mb > 64;
    return $mb;
}

sub _forms_upload_mb {
    my ($settings) = @_;
    return _clean_forms_upload_mb($settings->{forms_max_upload_mb});
}

sub _forms_truthy {
    my ($value) = @_;
    return 0 unless defined $value;
    return 0 if $value eq '' || $value eq '0';
    return 0 if $value =~ /\A(?:false|no|off)\z/i;
    return 1;
}

sub _forms_bytes_label {
    my ($bytes) = @_;
    $bytes = int($bytes || 0);
    return sprintf('%.1f MB', $bytes / 1024 / 1024) if $bytes >= 1024 * 1024;
    return int(($bytes + 1023) / 1024) . ' KB' if $bytes >= 1024;
    return $bytes . ' bytes';
}

sub _clean_module_text {
    my ($value, $max, $fallback) = @_;
    $value = '' unless defined $value;
    $value =~ s/\r\n?/\n/g;
    $value =~ s/[\x00-\x08\x0b\x0c\x0e-\x1f\x7f]+/ /g;
    $value =~ s/[ \t]+/ /g;
    $value =~ s/\n{3,}/\n\n/g;
    $value =~ s/^\s+|\s+\z//g;
    $value = substr($value, 0, $max || 500);
    return length $value ? $value : $fallback;
}

sub _clean_docs_source_dir {
    my ($value) = @_;
    $value = '' unless defined $value;
    $value =~ s/[\x00-\x1f\x7f]+//g;
    $value =~ s/^\s+|\s+\z//g;
    return '' unless length $value;
    die "Docs / Resource Hub source directory path is too long" if length($value) > 500;
    die "Docs / Resource Hub source directory must be an absolute path"
        unless File::Spec->file_name_is_absolute($value);
    die "Docs / Resource Hub source directory does not exist"
        unless -d $value;
    return $value;
}

sub _clean_postmark_sender_mode {
    my ($value) = @_;
    $value = lc($value || '');
    $value =~ s/^\s+|\s+\z//g;
    return $value eq 'inherit' ? 'inherit' : 'site';
}

sub _clean_email {
    my ($value) = @_;
    $value = lc($value || '');
    $value =~ s/^\s+|\s+\z//g;
    return '' unless $value =~ /\A[A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Za-z]{2,}\z/;
    return $value;
}

sub _settings_save {
    my ($self, $request, $session, $session_token) = @_;
    my $ok = eval {
        my %posted = %{ $request->{form} || {} };
        my %values;
        $values{contributor_domain_root} = $request->param('contributor_domain_root')
            if exists $posted{contributor_domain_root};
        $values{postmark_sender_mode} = _clean_postmark_sender_mode($request->param('postmark_sender_mode'))
            if exists $posted{postmark_sender_mode};
        $values{postmark_from_email} = $request->param('postmark_from_email')
            if exists $posted{postmark_from_email};
        $values{contributor_request_recipient_email} = $request->param('contributor_request_recipient_email')
            if exists $posted{contributor_request_recipient_email};
        my $postmark_token = $request->param('postmark_server_token');
        $values{postmark_server_token} = $postmark_token
            if exists $posted{postmark_server_token} && defined $postmark_token && length $postmark_token;
        my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
        if ((exists $posted{postmark_from_email} || exists $posted{postmark_server_token})
            && !length($settings->{postmark_webhook_token} || '')) {
            $values{postmark_webhook_token} = generate_webhook_token();
        }

        DesertCMS::Settings::set_many($self->{config}, $self->{db}, \%values);
        1;
    };

    if (!$ok) {
        return $self->_settings_contributors_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'Contributor email settings could not be saved.',
                'Check the sender email, receiving email, Postmark token, and contributor domain root, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'settings.contributors_saved',
        subject_type => 'settings',
        details      => { fields => [ sort grep { $_ ne 'csrf_token' && $_ ne 'postmark_server_token' } keys %{ $request->{form} || {} } ] },
    );
    return DesertCMS::HTTP->redirect(
        '/admin/settings/contributors?notice=contributors-saved',
        { security_headers() }
    );
}

sub _settings_contributors_test_email {
    my ($self, $request, $session, $session_token) = @_;
    my $to = $request->param('test_email') || '';
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $site_name = $settings->{site_name} || $self->{config}->get('site_name') || 'DesertCMS';
    my $base = $self->{config}->get('site_url') || 'http://localhost';
    $base =~ s{/+\z}{};
    my ($sent, $reason) = send_postmark(
        $self->{config},
        $self->{db},
        to         => $to,
        email_type => 'postmark_test',
        subject    => "DesertCMS contributor email test for $site_name",
        text_body  => join("\n\n",
            "This is a DesertCMS contributor email delivery test.",
            "Site: $site_name",
            "Admin URL: $base/admin",
            "If this arrived, Postmark sending is working for this CMS instance."
        ),
        html_body  => '<p>This is a DesertCMS contributor email delivery test.</p><p><strong>Site:</strong> '
            . escape_html($site_name)
            . '</p><p><a href="'
            . escape_html("$base/admin")
            . '">Open admin</a></p>',
    );
    $self->_audit_admin_action(
        $session,
        action       => 'postmark.test_email_sent',
        subject_type => 'email',
        details      => { to => $to, sent => $sent ? 1 : 0, reason => $reason || '' },
    );
    my $notice = $sent ? 'postmark-test-sent' : 'postmark-test-failed';
    return DesertCMS::HTTP->redirect(
        "/admin/settings/contributors?notice=$notice",
        { security_headers() }
    );
}

sub _settings_contributors_rotate_webhook_token {
    my ($self, $request, $session, $session_token) = @_;
    DesertCMS::Settings::set_many($self->{config}, $self->{db}, {
        postmark_webhook_token => generate_webhook_token(),
    });
    $self->_audit_admin_action(
        $session,
        action       => 'postmark.webhook_token_rotated',
        subject_type => 'settings',
    );
    return DesertCMS::HTTP->redirect(
        '/admin/settings/contributors?notice=postmark-webhook-rotated',
        { security_headers() }
    );
}

sub _theme_preset_choices {
    my ($self, $settings, $mode) = @_;
    $mode = $mode && $mode eq 'dark' ? 'dark' : 'light';
    my $selected = DesertCMS::SiteTheme::selected_preset_id($settings, $mode);
    my $input_name = "theme_${mode}_preset";
    my $html = '';
    for my $preset (@{DesertCMS::SiteTheme::presets_for_mode($mode)}) {
        my $id = escape_html($preset->{id});
        my $name = escape_html($preset->{name});
        my $mode_label = escape_html($preset->{mode});
        my $checked = $selected eq $preset->{id} ? 'checked' : '';
        my $vars = $preset->{vars};
        my $paper = escape_html($vars->{paper});
        my $panel = escape_html($vars->{panel});
        my $accent = escape_html($vars->{accent});
        my $support = escape_html($vars->{support});
        my $ink = escape_html($vars->{ink});
        my $vars_json = escape_html(_json_script($vars));
        $html .= <<"HTML";
<label class="theme-choice-card">
  <input type="radio" name="$input_name" value="$id" data-theme-preset-mode="$mode" data-theme-vars="$vars_json" $checked>
  <span class="theme-choice-meta"><strong>$name</strong><small>$mode_label preset</small></span>
  <span class="theme-swatches" aria-hidden="true">
    <i style="background:$paper"></i>
    <i style="background:$panel"></i>
    <i style="background:$accent"></i>
    <i style="background:$support"></i>
    <i style="background:$ink"></i>
  </span>
</label>
HTML
    }

    my $custom_checked = $selected eq 'custom' ? 'checked' : '';
    my $custom_label = $mode eq 'dark' ? 'Custom dark' : 'Custom light';
    $html .= <<"HTML";
<label class="theme-choice-card theme-choice-card--custom">
  <input type="radio" name="$input_name" value="custom" data-theme-preset-mode="$mode" data-theme-custom="1" $custom_checked>
  <span class="theme-choice-meta"><strong>Custom Theme</strong><small>$custom_label colors</small></span>
  <span class="theme-swatches" aria-hidden="true">
    <i></i><i></i><i></i><i></i><i></i>
  </span>
</label>
HTML
    return $html;
}

sub _font_select_options {
    my ($selected, $options, $fallback) = @_;
    $selected = DesertCMS::FontPackages::clean_font_id($selected, $fallback || 'sans');
    my %seen;
    my @pairs;
    for my $option (@{$options || []}) {
        my $id = $option->{id} || '';
        next unless length $id;
        next if $seen{$id}++;
        push @pairs, [ $id, $option->{label} || $id ];
    }
    if (!$seen{$selected}) {
        my $label = $selected =~ /\Apkg:([A-Za-z0-9._+-]+)\z/
            ? 'Selected package: ' . $1 . ' (not installed yet)'
            : $selected =~ /\Abundled:space-grotesk\z/
                ? 'Space Grotesk (bundled)'
            : $selected;
        push @pairs, [ $selected, $label ];
    }
    return _select_options($selected, \@pairs);
}

sub _font_package_panel {
    my ($self, $settings, %options) = @_;
    my $catalog = DesertCMS::FontPackages::read_catalog($self->{config});
    my $status = $catalog->{status} || 'missing';
    my $status_class = $status eq 'ok' ? 'ok' : ($status eq 'missing' ? 'status-pill--neutral' : 'warn');
    my $status_label = $status eq 'ok' ? 'Ready' : ($status eq 'missing' ? 'Not refreshed' : 'Needs attention');
    my $safe_status_label = escape_html($status_label);
    my $safe_status = escape_html($status);
    my $repo = escape_html($settings->{font_package_repo} || $catalog->{package_repo} || '');
    my $refreshed = escape_html(_format_time($catalog->{refreshed_at}));
    my $package_count = scalar @{ $catalog->{packages} || [] };
    my $installed_count = scalar grep { $_->{installed} } @{ $catalog->{packages} || [] };
    if ($options{contributor_product}) {
        return <<"HTML";
          <div class="font-package-panel">
            <div class="split">
              <div>
                <h4>Platform Fonts</h4>
                <p class="muted">Choose from the installed font options above. Catalog refreshes and package installs are handled by the platform.</p>
              </div>
              <span class="status-pill $status_class">$safe_status_label</span>
            </div>
            <dl class="health-list health-list--compact font-package-health">
              <div><dt>Catalog</dt><dd><span class="status-pill status-pill--neutral">$safe_status</span><small>Refreshed $refreshed</small></dd></div>
              <div><dt>Fonts</dt><dd><span class="status-pill status-pill--neutral">$installed_count installed</span><small>$package_count available from platform catalog data</small></dd></div>
            </dl>
          </div>
HTML
    }
    my $error_html = length($catalog->{error} || '')
        ? '<p class="notice error">' . escape_html(_admin_action_error(
            'The OpenBSD font catalog could not be refreshed.',
            'Install the font worker or check the package repository URL, then refresh the catalog again.',
            $catalog->{error}
        )) . '</p>'
        : '';
    my $config_path = $self->{config}->{path} || '/etc/desertcms.conf';
    my $worker_cmd = escape_html('doas perl ' . DesertCMS::Upgrade::default_app_root() . '/tools/openbsd-apply-font-packages.pl --install-cron --config ' . $config_path);
    my $package_rows = $self->_font_package_rows($catalog);
    my $job_rows = $self->_font_package_job_rows;

    return <<"HTML";
          <div class="font-package-panel">
            <div class="split">
              <div>
                <h4>OpenBSD Font Packages</h4>
                <p class="muted">Refresh the OpenBSD package catalog, queue font package installs, then select installed package fonts above. Rebuild publishes selected font files into <code>/assets/fonts/</code> and emits local <code>\@font-face</code> CSS.</p>
              </div>
              <span class="status-pill $status_class">$safe_status_label</span>
            </div>
            <dl class="health-list health-list--compact font-package-health">
              <div><dt>Catalog</dt><dd><span class="status-pill status-pill--neutral">$safe_status</span><small>Refreshed $refreshed</small></dd></div>
              <div><dt>Packages</dt><dd><span class="status-pill status-pill--neutral">$package_count found</span><small>$installed_count installed with local package data</small></dd></div>
            </dl>
            $error_html
            <div class="layout-control-grid">
              <label>
                <span>OpenBSD package repository URL</span>
                <input name="font_package_repo" value="$repo" placeholder="Optional PKG_PATH override">
              </label>
              <div class="form-action-card">
                <span>Catalog refresh</span>
                <button type="submit" class="secondary" formaction="/admin/site-settings/fonts/refresh" formmethod="post">Refresh OpenBSD catalog</button>
              </div>
            </div>
            <p class="muted">Install the root worker once on OpenBSD: <code>$worker_cmd</code></p>
            <table class="content-table compact-table font-package-table admin-card-table">
              <thead><tr><th>Package</th><th>Status</th><th>Web font files</th><th>Action</th></tr></thead>
              <tbody>$package_rows</tbody>
            </table>
            <h4>Recent Font Jobs</h4>
            <table class="content-table compact-table font-package-table admin-card-table">
              <thead><tr><th>Package</th><th>Status</th><th>Updated</th><th>Message</th></tr></thead>
              <tbody>$job_rows</tbody>
            </table>
          </div>
HTML
}

sub _font_package_rows {
    my ($self, $catalog) = @_;
    my $rows = '';
    for my $pkg (@{ $catalog->{packages} || [] }) {
        my $package = escape_html($pkg->{package} || $pkg->{stem} || '');
        my $label = escape_html($pkg->{label} || $pkg->{stem} || $pkg->{package} || 'OpenBSD Font');
        my $installed = $pkg->{installed} ? 1 : 0;
        my $font_count = scalar @{ $pkg->{font_files} || [] };
        my $status = $installed
            ? ($font_count ? '<span class="status-pill ok">Installed</span>' : '<span class="status-pill warn">Installed, no web files</span>')
            : '<span class="status-pill status-pill--neutral">Available</span>';
        my $files = $font_count ? "$font_count file(s)" : ($installed ? 'No TTF/OTF/WOFF files detected' : 'Install to inspect files');
        my $safe_files = escape_html($files);
        my $action = $installed
            ? '<span class="muted">Selectable after refresh</span>'
            : qq{<button type="submit" class="small secondary" name="font_package" value="$package" formaction="/admin/site-settings/fonts/install" formmethod="post">Queue install</button>};
        $rows .= <<"HTML";
<tr>
  <td data-label="Package"><strong>$label</strong><br><code>$package</code></td>
  <td data-label="Status">$status</td>
  <td data-label="Web font files">$safe_files</td>
  <td data-label="Action">$action</td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(
        4,
        'No font packages listed yet.',
        'Refresh the OpenBSD catalog to show installable font packages for Typography and Components.'
    );
}

sub _font_package_job_rows {
    my ($self) = @_;
    my $rows = '';
    for my $job (@{ DesertCMS::FontPackages::latest_jobs($self->{config}, limit => 8) }) {
        my $package = escape_html($job->{package} || '');
        my $status = escape_html($job->{status} || 'queued');
        my $class = ($job->{status} || '') eq 'done' ? 'ok' : (($job->{status} || '') eq 'failed' ? 'warn' : 'status-pill--neutral');
        my $updated = escape_html(_format_time($job->{updated_at} || $job->{submitted_at}));
        my $message = escape_html($job->{error} || $job->{message} || '');
        $rows .= <<"HTML";
<tr>
  <td data-label="Package"><code>$package</code></td>
  <td data-label="Status"><span class="status-pill $class">$status</span></td>
  <td data-label="Updated">$updated</td>
  <td data-label="Message">$message</td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(
        4,
        'No font package jobs yet.',
        'Queue a font package install from the catalog above; worker progress will appear here.'
    );
}

sub _select_options {
    my ($selected, $options) = @_;
    my $html = '';
    for my $option (@{$options || []}) {
        my ($value, $label) = @{$option};
        my $safe_value = escape_html($value);
        my $safe_label = escape_html($label);
        my $is_selected = defined $selected && $selected eq $value ? 'selected' : '';
        $html .= qq{<option value="$safe_value" $is_selected>$safe_label</option>};
    }
    return $html;
}

sub _clean_choice {
    my ($value, $fallback, @allowed) = @_;
    for my $allowed (@allowed) {
        return $allowed if defined $value && $value eq $allowed;
    }
    return $fallback;
}

sub _clean_int_range {
    my ($value, $min, $max, $fallback) = @_;
    return $fallback unless defined $value && "$value" =~ /\A[0-9]+\z/;
    my $int = int($value);
    return $fallback if $int < $min || $int > $max;
    return $int;
}

sub _clean_optional_int_range {
    my ($value, $min, $max) = @_;
    return '' unless defined $value && "$value" =~ /\A[0-9]+\z/;
    my $int = int($value);
    return '' if $int < $min || $int > $max;
    return $int;
}

sub _custom_theme_fields {
    my ($self, $settings) = @_;
    my $defaults = DesertCMS::SiteTheme::custom_settings_defaults();
    my @fields = (
        [ theme_custom_ink => 'Text' ],
        [ theme_custom_muted => 'Muted text' ],
        [ theme_custom_paper => 'Page background' ],
        [ theme_custom_panel => 'Panels' ],
        [ theme_custom_field => 'Fields' ],
        [ theme_custom_line => 'Lines' ],
        [ theme_custom_accent => 'Accent' ],
        [ theme_custom_accent_dark => 'Accent hover' ],
        [ theme_custom_support => 'Links' ],
        [ theme_custom_button_ink => 'Button text' ],
    );
    my $html = '';
    for my $field (@fields) {
        my ($name, $label) = @{$field};
        my $value = $self->_clean_theme_color($settings->{$name}, $defaults->{$name});
        my $safe_label = escape_html($label);
        $html .= qq{<label><span>$safe_label</span><input type="color" name="$name" value="$value"></label>};
    }
    return $html;
}

sub _clean_theme_preset {
    my ($self, $value, $mode) = @_;
    $mode = $mode && $mode eq 'dark' ? 'dark' : 'light';
    return 'custom' if defined $value && $value eq 'custom';
    for my $preset (@{DesertCMS::SiteTheme::presets_for_mode($mode)}) {
        return $preset->{id} if defined $value && $value eq $preset->{id};
    }
    return $mode eq 'dark' ? 'dark-archive' : 'light-archive';
}

sub _apply_theme_preset_recommended_fonts {
    my ($values, $current_settings) = @_;
    return unless $values && ref $values eq 'HASH';
    my %recommended;
    for my $id ($values->{theme_light_preset}, $values->{theme_dark_preset}) {
        my $fonts = DesertCMS::SiteTheme::recommended_fonts_for_preset($id);
        next unless $fonts && ref $fonts eq 'HASH';
        @recommended{keys %{$fonts}} = values %{$fonts};
    }
    return unless %recommended;

    my %defaults = (
        theme_heading_font => 'serif',
        theme_body_font    => 'serif',
        theme_ui_font      => 'sans',
    );
    for my $key (qw(theme_heading_font theme_body_font theme_ui_font)) {
        next unless exists $recommended{$key};
        my $current = DesertCMS::FontPackages::clean_font_id(($current_settings || {})->{$key}, $defaults{$key});
        my $submitted = DesertCMS::FontPackages::clean_font_id($values->{$key}, $defaults{$key});
        next unless $current eq $defaults{$key};
        next unless $submitted eq $defaults{$key};
        $values->{$key} = DesertCMS::FontPackages::clean_font_id($recommended{$key}, $defaults{$key});
    }
}

sub _clean_theme_color {
    my ($self, $value, $fallback) = @_;
    return $value if defined $value && $value =~ /\A#[0-9a-fA-F]{6}\z/;
    return $fallback if defined $fallback && $fallback =~ /\A#[0-9a-fA-F]{6}\z/;
    return '#000000';
}

sub _clean_tile_url {
    my ($value, $fallback) = @_;
    $value = '' unless defined $value;
    $value =~ s/^\s+|\s+$//g;
    return $fallback unless $value =~ /\{z\}/ && $value =~ /\{x\}/ && $value =~ /\{y\}/;
    return $value if $value =~ m{\Ahttps://[A-Za-z0-9._~:/?#\[\]@!\$&'()*+,;=%{}\-,]+\z};
    return $value if $value =~ m{\A/[A-Za-z0-9._~:/?#\[\]@!\$&'()*+,;=%{}\-,]+\z};
    return $fallback;
}

sub _clean_map_attribution {
    my ($value, $fallback) = @_;
    $value = '' unless defined $value;
    $value =~ s/[\r\n\t]+/ /g;
    $value =~ s/<\s*(?:script|iframe|object|embed|img|link|style)\b[^>]*>.*?<\s*\/\s*(?:script|iframe|object|embed|style)\s*>//gis;
    $value =~ s/<\s*(?:script|iframe|object|embed|img|link|style)\b[^>]*>//gis;
    $value =~ s/\son[a-z]+\s*=\s*(?:"[^"]*"|'[^']*'|[^\s>]+)//gi;
    $value =~ s/\s+/ /g;
    $value =~ s/^\s+|\s+$//g;
    return length $value ? substr($value, 0, 500) : $fallback;
}

sub _clean_map_coordinate {
    my ($value, $min, $max, $fallback) = @_;
    return $fallback unless defined $value && "$value" =~ /\A-?(?:[0-9]+(?:\.[0-9]+)?|\.[0-9]+)\z/;
    my $number = 0 + $value;
    return $fallback if $number < $min || $number > $max;
    return sprintf('%.6f', $number);
}

sub _clean_map_zoom {
    my ($value) = @_;
    return 5 unless defined $value && "$value" =~ /\A[0-9]+\z/;
    my $zoom = int($value);
    $zoom = 1 if $zoom < 1;
    $zoom = 19 if $zoom > 19;
    return $zoom;
}

sub _settings_admin_account_save {
    my ($self, $request, $session, $session_token) = @_;
    my $password = $request->param('password') || '';
    my $confirm = $request->param('password_confirm') || '';
    return $self->_settings_account_page($request, $session, $session_token, 'Admin passwords do not match.')
        if $password ne $confirm;

    my $ok = eval {
        $self->{auth}->update_admin_account(
            user_id  => $session->{user_id},
            username => $request->param('username'),
            email    => $request->param('email'),
            password => $password,
        );
        1;
    };
    if (!$ok) {
        return $self->_settings_account_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The admin account could not be saved.',
                'Check the username, email address, and password fields, then try again.',
                $@
            )
        );
    }
    return $self->_settings_account_page($request, $session, $session_token, 'Admin account saved.');
}

sub _settings_invite_send {
    my ($self, $request, $session, $session_token) = @_;
    my $message;
    my $ok = eval {
        my $invite = $self->{sites}->create_invite(
            email              => $request->param('email'),
            message            => $request->param('message'),
            blueprint_id       => $request->param('blueprint_id'),
            created_by_user_id => $session->{user_id},
        );
        my ($sent, $send_message) = $self->{sites}->send_invite_email($invite);
        $message = $sent
            ? 'Contributor invite sent.'
            : 'Contributor invite created, but email was not sent: ' . $send_message . '. Invite link: ' . $invite->{invite_url};
        1;
    };

    if (!$ok) {
        return $self->_settings_contributors_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The contributor invite could not be sent.',
                'Check the email address, Postmark setup, and contributor domain root, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'contributor_invite.sent',
        subject_type => 'contributor_invite',
        details      => { email => $request->param('email') || '' },
    );
    return $self->_settings_contributors_page($request, $session, $session_token, $message);
}

sub _settings_invite_revoke {
    my ($self, $request, $session, $session_token) = @_;
    my $ok = eval {
        $self->{sites}->revoke_invite(id => $request->param('invite_id'));
        1;
    };
    if (!$ok) {
        return $self->_settings_contributors_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The contributor invite could not be revoked.',
                'Refresh the page to confirm the invite is still pending, then try again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'contributor_invite.revoked',
        subject_type => 'contributor_invite',
        subject_id   => int($request->param('invite_id') || 0),
    );
    return $self->_settings_contributors_page($request, $session, $session_token, 'Invite revoked.');
}

sub _settings_site_action {
    my ($self, $request, $session, $session_token) = @_;
    my $ok = eval {
        $self->{sites}->request_site_action(
            site_id            => $request->param('site_id'),
            action             => $request->param('action'),
            created_by_user_id => $session->{user_id},
        );
        1;
    };
    if (!$ok) {
        return $self->_settings_sites_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'The contributor site action could not be queued.',
                'Check the site status and provisioning queue, then try the action again.',
                $@
            )
        );
    }
    $self->_audit_admin_action(
        $session,
        action       => 'contributor_site.' . ($request->param('action') || 'action') . '_queued',
        subject_type => 'contributor_site',
        details      => { site_id => $request->param('site_id') || '', action => $request->param('action') || '' },
    );
    return DesertCMS::HTTP->redirect(
        '/admin/settings/sites?notice=site-action-queued',
        { security_headers() }
    );
}

sub _settings_site_grant_access {
    my ($self, $request, $session, $session_token) = @_;
    my $result;
    my $ok = eval {
        $result = $self->{sites}->grant_access(
            site_id            => $request->param('site_id'),
            email              => $request->param('email'),
            created_by_user_id => $session->{user_id},
        );
        1;
    };
    if (!$ok) {
        return $self->_settings_sites_page(
            $request,
            $session,
            $session_token,
            _admin_action_error(
                'Contributor access could not be granted.',
                'Check the email address and contributor site status, then try again.',
                $@
            )
        );
    }
    my $message = $result->{sent}
        ? 'Contributor site access granted and emailed to ' . $result->{email} . '.'
        : 'Contributor access was created, but the email was not sent. Fix the email issue shown in the Delivery Log, then grant access again if the contributor still needs the link. Details: ' . _clean_error($result->{reason} || 'email failed') . '.';
    $self->_audit_admin_action(
        $session,
        action       => 'contributor_site.access_granted',
        subject_type => 'contributor_site',
        details      => {
            site_id  => $result->{site_id} || $request->param('site_id') || '',
            domain   => $result->{domain} || '',
            email    => $result->{email} || $request->param('email') || '',
            username => $result->{username} || '',
            emailed  => $result->{sent} ? 1 : 0,
        },
    );
    my $notice = $result->{sent} ? 'site-access-granted' : 'site-access-email-failed';
    return DesertCMS::HTTP->redirect(
        "/admin/settings/sites?notice=$notice",
        { security_headers() }
    );
}

sub _invite_accept_get {
    my ($self, $request, $token, $message) = @_;
    my $invite = $self->{sites}->invite_by_token($token);
    my $body;
    if (!$invite || $invite->{status} ne 'pending' || $invite->{expires_at} <= now()) {
        $body = q{
<section class="panel auth-panel">
  <h1>Invite Unavailable</h1>
  <p>This invite is expired, revoked, or already accepted.</p>
</section>
};
        return $self->_public_module_response(
            title       => 'Invite Unavailable',
            description => 'This contributor invite is unavailable.',
            path        => '/admin/invite/' . $token,
            content     => $body,
            context     => 'contributors',
            status      => 410,
        );
    }

    my $notice = $message ? '<p class="notice error">' . escape_html($message) . '</p>' : '';
    my $safe_email = escape_html($invite->{email});
    $body = <<"HTML";
<section class="panel auth-panel">
  <h1>Create Contributor Site</h1>
  <p class="muted">$safe_email</p>
  $notice
  <form method="post" action="/admin/invite/$token" class="stack">
    <label>
      <span>First name</span>
      <input name="first_name" autocomplete="given-name" required>
    </label>
    <label>
      <span>Last initial</span>
      <input name="last_initial" maxlength="1" autocomplete="family-name" required>
    </label>
    <button type="submit">Create site</button>
  </form>
</section>
HTML
    return $self->_public_module_response(
        title       => 'Create Contributor Site',
        description => 'Accept a contributor invite and request a site.',
        path        => '/admin/invite/' . $token,
        content     => $body,
        context     => 'contributors',
    );
}

sub _invite_accept_post {
    my ($self, $request, $token) = @_;
    my $site;
    my $ok = eval {
        $site = $self->{sites}->accept_invite(
            token        => $token,
            first_name   => $request->param('first_name'),
            last_initial => $request->param('last_initial'),
        );
        1;
    };
    if (!$ok) {
        return $self->_invite_accept_get($request, $token, $@ || 'Could not accept invite.');
    }

    my $domain = escape_html($site->{domain});
    my $body = <<"HTML";
<section class="panel auth-panel">
  <h1>Site Requested</h1>
  <p>Your contributor site has been queued for provisioning.</p>
  <p><strong>$domain</strong></p>
</section>
HTML
    return $self->_public_module_response(
        title       => 'Site Requested',
        description => 'Your contributor site request has been received.',
        path        => '/admin/invite/' . $token,
        content     => $body,
        context     => 'contributors',
    );
}

sub _send_password_reset_email {
    my ($self, $email, $url) = @_;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $site_name = $settings->{site_name} || $self->{config}->get('site_name') || 'DesertCMS';
    my $subject = "Reset your $site_name admin password";
    my $text = join "\n\n",
        "A password reset was requested for your $site_name admin account.",
        "Use this link to choose a new password:",
        $url,
        "If you did not request this, ignore this email.";
    my $html = '<p>A password reset was requested for your '
        . escape_html($site_name)
        . ' admin account.</p><p><a href="'
        . escape_html($url)
        . '">Choose a new password</a></p><p>If you did not request this, ignore this email.</p>';
    return send_postmark(
        $self->{config},
        $self->{db},
        to         => $email,
        email_type => 'admin_password_reset',
        subject    => $subject,
        text_body  => $text,
        html_body  => $html,
    );
}

sub _absolute_admin_url {
    my ($self, $path) = @_;
    return $self->_absolute_url($path);
}

sub _absolute_url {
    my ($self, $path) = @_;
    my $base = $self->{config}->get('site_url') || 'http://localhost';
    $base =~ s{/+\z}{};
    $path = "/$path" unless $path =~ m{\A/};
    return $base . $path;
}

sub _is_shop_host {
    my ($self, $request) = @_;
    my $shop_host = $self->{shop}->shop_host;
    return 0 unless length $shop_host;
    my $host = lc($request->{host} || '');
    $host =~ s/:\d+\z//;
    return $host eq $shop_host ? 1 : 0;
}

sub _shop_route {
    my ($prefix, $path) = @_;
    $path ||= '/';
    $path = '/' . $path unless $path =~ m{\A/};
    $prefix ||= '';
    $prefix =~ s{/+\z}{};
    return $path if !length $prefix;
    return $prefix if $path eq '/';
    return $prefix . $path;
}

sub _event_schema_json {
    my ($config, $event, $occurrence) = @_;
    my $base = $config->get('site_url') || '';
    $base =~ s{/+\z}{};
    my $key = $occurrence->{occurrence_key} || DesertCMS::Events::occurrence_key($event, $occurrence->{starts_at});
    my $url = $base . '/events/' . ($event->{slug} || '') . "/$key/";
    my $data = {
        '@context' => 'https://schema.org',
        '@type'    => 'Event',
        name       => $event->{title} || 'Event',
        description => $event->{summary} || '',
        startDate  => _schema_datetime($occurrence->{starts_at}, $event->{timezone}, $event->{all_day}),
        endDate    => _schema_datetime($occurrence->{ends_at}, $event->{timezone}, $event->{all_day}),
        eventStatus => 'https://schema.org/EventScheduled',
        eventAttendanceMode => 'https://schema.org/OfflineEventAttendanceMode',
        url        => $url,
    };
    $data->{image} = $base . $event->{feature_image_path}
        if length($base) && length($event->{feature_image_path} || '');
    if ($event->{location_label} || $event->{location_enabled}) {
        $data->{location} = {
            '@type' => 'Place',
            name    => $event->{location_label} || 'Event location',
        };
        if (defined $event->{location_lat} && defined $event->{location_lng}) {
            $data->{location}{geo} = {
                '@type' => 'GeoCoordinates',
                latitude => 0 + $event->{location_lat},
                longitude => 0 + $event->{location_lng},
            };
        }
    }
    my $json = encode_json($data);
    $json =~ s{<}{\\u003c}g;
    $json =~ s{>}{\\u003e}g;
    $json =~ s{&}{\\u0026}g;
    return $json;
}

sub _schema_datetime {
    my ($epoch, $timezone, $all_day) = @_;
    my $dt = DesertCMS::DateTimeLite->from_epoch(epoch => int($epoch || 0), time_zone => $timezone || 'UTC');
    return sprintf('%04d-%02d-%02d', $dt->year, $dt->month, $dt->day) if $all_day;
    return sprintf('%04d-%02d-%02dT%02d:%02d:%02d%s',
        $dt->year, $dt->month, $dt->day, $dt->hour, $dt->minute, $dt->second, $dt->strftime('%z'));
}

sub _ics_utc {
    my ($epoch) = @_;
    my @t = gmtime(int($epoch || 0));
    return sprintf('%04d%02d%02dT%02d%02d%02dZ', $t[5] + 1900, $t[4] + 1, $t[3], $t[2], $t[1], $t[0]);
}

sub _ics_date {
    my ($epoch, $timezone) = @_;
    my $dt = DesertCMS::DateTimeLite->from_epoch(epoch => int($epoch || 0), time_zone => $timezone || 'UTC');
    return sprintf('%04d%02d%02d', $dt->year, $dt->month, $dt->day);
}

sub _ics_text {
    my ($text) = @_;
    $text = '' unless defined $text;
    $text =~ s/\\/\\\\/g;
    $text =~ s/\r?\n/\\n/g;
    $text =~ s/,/\\,/g;
    $text =~ s/;/\\;/g;
    return $text;
}

sub _media_filter_tabs_html {
    my ($active_filter, $counts, $query, $category, $collection) = @_;
    $active_filter = DesertCMS::Media::library_filter_key($active_filter);
    $counts = {} unless ref $counts eq 'HASH';
    my $html = '<nav class="media-filter-tabs" aria-label="Media library filters" data-media-filter-tabs>';
    for my $def (_media_filter_defs()) {
        my ($key, $label) = @{$def};
        my $active = $key eq $active_filter;
        my $href = _media_library_href($key, $query, $category, $collection);
        my $class = $active ? ' class="active"' : '';
        my $current = $active ? ' aria-current="page"' : '';
        my $safe_label = escape_html($label);
        my $count = int($counts->{$key} || 0);
        $html .= qq{<a href="$href"$class$current><span>$safe_label</span><strong>$count</strong></a>};
    }
    $html .= '</nav>';
    return $html;
}

sub _media_library_href {
    my ($filter, $query, $category, $collection) = @_;
    $filter = DesertCMS::Media::library_filter_key($filter);
    $query = DesertCMS::Media::library_search_query($query);
    my @category_terms = DesertCMS::Media::media_organization_terms($category);
    $category = $category_terms[0] || '';
    my @collection_terms = DesertCMS::Media::media_organization_terms($collection);
    $collection = $collection_terms[0] || '';
    my @params;
    push @params, 'filter=' . _query_escape($filter) unless $filter eq 'all';
    push @params, 'q=' . _query_escape($query) if length $query;
    push @params, 'category=' . _query_escape($category) if length $category;
    push @params, 'collection=' . _query_escape($collection) if length $collection;
    return '/admin/media' . (@params ? '?' . join('&', @params) : '');
}

sub _query_escape {
    my ($value) = @_;
    $value = '' unless defined $value;
    $value =~ s/([^A-Za-z0-9\-._~])/sprintf('%%%02X', ord($1))/eg;
    return $value;
}

sub _media_search_form_html {
    my ($active_filter, $query, $match_count, $total_count, $category, $collection) = @_;
    my $safe_query = escape_html($query || '');
    my $safe_filter = escape_html(DesertCMS::Media::library_filter_key($active_filter));
    my $safe_category = escape_html($category || '');
    my $safe_collection = escape_html($collection || '');
    my $clear_href = escape_html(_media_library_href($active_filter, '', $category, $collection));
    my $match = int($match_count || 0);
    my $total = int($total_count || 0);
    my $unit = $total == 1 ? 'asset' : 'assets';
    my $detail = length($query || '')
        ? "$match of $total $unit match this search and organization filter."
        : "Search titles, descriptions, filenames, snippets, categories, tags, collections, and file type metadata across $total $unit.";
    my $clear = length($query || '') ? qq{<a class="button-link secondary" href="$clear_href">Clear</a>} : '';
    return <<"HTML";
    <form method="get" action="/admin/media" class="media-search-form" role="search" data-media-library-search>
      <input type="hidden" name="filter" value="$safe_filter">
      <input type="hidden" name="category" value="$safe_category">
      <input type="hidden" name="collection" value="$safe_collection">
      <label>
        <span>Search media</span>
        <input type="search" name="q" value="$safe_query" placeholder="Title, filename, category, tag, PDF, CSV, MP3...">
        <small>@{[escape_html($detail)]}</small>
      </label>
      <button type="submit" class="secondary">Search</button>
      $clear
    </form>
HTML
}

sub _media_organization_filters_html {
    my ($assets, $active_filter, $query, $category, $collection) = @_;
    my $categories = DesertCMS::Media::library_organization_terms($assets, 'category_text');
    my $collections = DesertCMS::Media::library_organization_terms($assets, 'collections_text');
    return '' unless @{$categories || []} || @{$collections || []};
    my $safe_filter = escape_html(DesertCMS::Media::library_filter_key($active_filter));
    my $safe_query = escape_html(DesertCMS::Media::library_search_query($query));
    my $category_options = _media_org_options($categories, $category, 'All categories');
    my $collection_options = _media_org_options($collections, $collection, 'All collections');
    my $clear_href = escape_html(_media_library_href($active_filter, $query));
    return <<"HTML";
    <form method="get" action="/admin/media" class="media-organization-filters" data-media-organization-filters>
      <input type="hidden" name="filter" value="$safe_filter">
      <input type="hidden" name="q" value="$safe_query">
      <label>
        <span>Category</span>
        <select name="category">$category_options</select>
      </label>
      <label>
        <span>Collection</span>
        <select name="collection">$collection_options</select>
      </label>
      <button type="submit" class="secondary">Apply filters</button>
      <a class="button-link secondary" href="$clear_href">Clear organization</a>
    </form>
HTML
}

sub _media_org_options {
    my ($terms, $selected, $empty_label) = @_;
    $selected = lc(($selected || ''));
    my $html = '<option value="">' . escape_html($empty_label || 'All') . '</option>';
    for my $term (@{ $terms || [] }) {
        my $safe = escape_html($term);
        my $is_selected = lc($term) eq $selected ? ' selected' : '';
        $html .= qq{<option value="$safe"$is_selected>$safe</option>};
    }
    return $html;
}

sub _media_filter_defs {
    return (
        [ all       => 'All' ],
        [ images    => 'Images' ],
        [ documents => 'Documents' ],
        [ audio     => 'Audio' ],
        [ video     => 'Video' ],
        [ resources => 'Resources' ],
        [ unused    => 'Unused' ],
        [ published => 'Published' ],
        [ private   => 'Private Source Only' ],
    );
}

sub _media_filter_empty_message {
    my ($filter, $query) = @_;
    $filter = DesertCMS::Media::library_filter_key($filter);
    if (length($query || '')) {
        return ['No media matched this search.', 'Try a title, filename, file type such as PDF, CSV, MP3, or text from a stored snippet.'];
    }
    return ['No images found.', 'Upload JPG, PNG, or WebP files to create public optimized derivatives.']
        if $filter eq 'images';
    return ['No documents found.', 'Upload PDFs, text, spreadsheets, presentations, or resource files to store private source assets.']
        if $filter eq 'documents';
    return ['No audio files found.', 'Upload MP3, M4A, WAV, OGG, WebM audio, or FLAC files as private source assets.']
        if $filter eq 'audio';
    return ['No video files found.', 'Upload MP4, M4V, MOV, WebM, or OGV files as private source assets.']
        if $filter eq 'video';
    return ['No public resources yet.', 'Publish a private source file when it should be available as a public Resource block.']
        if $filter eq 'resources';
    return ['No unused media found.', 'Every visible asset is currently referenced by content, shop listings, or order records.']
        if $filter eq 'unused';
    return ['No published media found.', 'Images publish optimized derivatives automatically. Private source files become public only after you publish them as resources.']
        if $filter eq 'published';
    return ['No private-source-only assets found.', 'Private source assets appear here until an image derivative or public resource URL is available.']
        if $filter eq 'private';
    return ['No media uploaded yet.', 'Upload images to create public optimized derivatives, or upload documents, audio, video, and resource files as private source assets.'];
}

sub _media_resource_publish_lock {
    my ($feature) = @_;
    return ('Resource Downloads is not available.', '/admin/billing', 'View Billing')
        unless $feature;
    return ('Resource Downloads is available.', '/admin/media?filter=resources', 'View Resources')
        if $feature->{enabled};
    return ('Resource Downloads requires a plan upgrade before new public resource files can be published.', '/admin/billing', 'View Billing')
        if $feature->{locked_by_plan};
    return ('Resource Downloads is managed by the platform for this site.', '/admin/billing', 'View Billing')
        if $feature->{managed_by_master};
    return ('Resource Downloads is turned off. Enable it in Features before publishing new public resource files.', '/admin/settings/modules', 'Open Features');
}

sub _media_lifecycle_large_mb {
    my ($value) = @_;
    return 10 unless defined $value && "$value" =~ /\A[0-9]+\z/;
    my $mb = int($value);
    $mb = 1 if $mb < 1;
    $mb = 1024 if $mb > 1024;
    return $mb;
}

sub _media_lifecycle_retention_days {
    my ($value) = @_;
    return 90 unless defined $value && "$value" =~ /\A[0-9]+\z/;
    my $days = int($value);
    $days = 1 if $days < 1;
    $days = 3650 if $days > 3650;
    return $days;
}

sub _media_lifecycle_empty_audit {
    my ($large_mb, $retention_days) = @_;
    my $large_min_bytes = _media_lifecycle_large_mb($large_mb) * 1024 * 1024;
    $retention_days = _media_lifecycle_retention_days($retention_days);
    return {
        summary => {
            missing_sources_count     => 0,
            missing_sources_bytes     => 0,
            orphaned_resources_count  => 0,
            orphaned_resources_bytes  => 0,
            stale_derivatives_count   => 0,
            stale_derivatives_bytes   => 0,
            large_unused_count        => 0,
            large_unused_bytes        => 0,
            large_min_bytes           => $large_min_bytes,
            retention_unused_count    => 0,
            retention_unused_bytes    => 0,
            retention_days            => $retention_days,
            retention_before          => time - ($retention_days * 86400),
        },
        large_min_bytes  => $large_min_bytes,
        retention_days   => $retention_days,
        retention_before => time - ($retention_days * 86400),
        missing_sources  => [],
        orphaned_resources => [],
        stale_derivatives => [],
        large_unused     => [],
        retention_unused => [],
    };
}

sub _media_lifecycle_summary_html {
    my ($summary) = @_;
    $summary ||= {};
    my $threshold = _format_bytes(int($summary->{large_min_bytes} || 0));
    my $missing = int($summary->{missing_sources_count} || 0);
    my $orphaned = int($summary->{orphaned_resources_count} || 0);
    my $stale = int($summary->{stale_derivatives_count} || 0);
    my $unused = int($summary->{large_unused_count} || 0);
    my $retention = int($summary->{retention_unused_count} || 0);
    my $retention_days = int($summary->{retention_days} || 90);
    return '<section class="metric-grid">'
        . _metric_card('Missing Sources', $missing, _format_bytes(int($summary->{missing_sources_bytes} || 0)), $missing ? 'warn' : 'ok')
        . _metric_card('Orphaned Resources', $orphaned, _format_bytes(int($summary->{orphaned_resources_bytes} || 0)), $orphaned ? 'warn' : 'ok')
        . _metric_card('Stale Derivatives', $stale, _format_bytes(int($summary->{stale_derivatives_bytes} || 0)), $stale ? 'warn' : 'ok')
        . _metric_card('Large Unused', $unused, _format_bytes(int($summary->{large_unused_bytes} || 0)) . ' at ' . $threshold . '+', $unused ? 'warn' : 'ok')
        . _metric_card('Retention', $retention, _format_bytes(int($summary->{retention_unused_bytes} || 0)) . ' older than ' . $retention_days . ' days', $retention ? 'warn' : 'ok')
        . '</section>';
}

sub _media_preview_jobs_panel_html {
    my ($summary, $csrf, $can_manage) = @_;
    $summary ||= {};
    my $candidates = int($summary->{candidates} || 0);
    my $queued = int($summary->{queued} || 0);
    my $running = int($summary->{running} || 0);
    my $done = int($summary->{done} || 0);
    my $failed = int($summary->{failed} || 0);
    my $skipped = int($summary->{skipped} || 0);
    my $safe_csrf = escape_html($csrf || '');
    my $actions = $can_manage ? <<"HTML" : '<p class="muted">Your role can view preview-job status, but cannot queue or process media preview jobs.</p>';
      <form method="post" action="/admin/media/previews/queue" class="inline-form" data-loading-label="Queueing...">
        <input type="hidden" name="csrf_token" value="$safe_csrf">
        <button type="submit" class="small secondary">Queue missing previews</button>
      </form>
      <form method="post" action="/admin/media/previews/process" class="inline-form" data-loading-label="Processing...">
        <input type="hidden" name="csrf_token" value="$safe_csrf">
        <button type="submit" class="small">Process queued previews</button>
      </form>
HTML
    return <<"HTML";
  <section class="panel">
    <div class="split">
      <div>
        <h2>Private Preview Jobs</h2>
        <p>Queue and retry private PDF thumbnails or video poster frames when optional server tooling becomes available.</p>
      </div>
      <div class="actions">
        $actions
      </div>
    </div>
    <section class="metric-grid">
      @{[_metric_card('Needs Preview', $candidates, 'PDF or video assets without generated private previews', $candidates ? 'warn' : 'ok')]}
      @{[_metric_card('Queued', $queued, $running ? "$running running" : 'Waiting for processing', $queued || $running ? 'warn' : 'ok')]}
      @{[_metric_card('Generated', $done, 'Completed preview jobs', 'ok')]}
      @{[_metric_card('Failed', $failed, "$skipped skipped", $failed ? 'warn' : 'ok')]}
    </section>
  </section>
HTML
}

sub _media_lifecycle_section {
    my (%args) = @_;
    my $entries = ref $args{entries} eq 'ARRAY' ? $args{entries} : [];
    my $safe_title = escape_html($args{title} || 'Media lifecycle');
    my $safe_detail = escape_html($args{detail} || '');
    my $count = scalar @{$entries};
    my $cleanup = '';
    if ($count && $args{cleanup_action}) {
        my $button_class = $args{danger} ? 'danger' : 'secondary';
        my $safe_action = escape_html($args{cleanup_action});
        my $safe_label = escape_html($args{cleanup_label} || 'Clean up');
        my $safe_confirm_title = escape_html($args{confirm_title} || 'Clean up media files?');
        my $safe_confirm_message = escape_html($args{confirm_message} || 'This action updates media files on disk.');
        my $safe_csrf = escape_html($args{csrf} || '');
        my $safe_large_mb = escape_html(_media_lifecycle_large_mb($args{large_mb}));
        my $safe_retention_days = escape_html(_media_lifecycle_retention_days($args{retention_days}));
        $cleanup = <<"HTML";
      <form method="post" action="/admin/media/lifecycle/cleanup" class="inline-form" data-confirm-title="$safe_confirm_title" data-confirm-message="$safe_confirm_message" data-confirm-action="$safe_label" data-loading-label="Cleaning up...">
        <input type="hidden" name="csrf_token" value="$safe_csrf">
        <input type="hidden" name="cleanup_action" value="$safe_action">
        <input type="hidden" name="large_mb" value="$safe_large_mb">
        <input type="hidden" name="retention_days" value="$safe_retention_days">
        <button type="submit" class="small $button_class">$safe_label</button>
      </form>
HTML
    }

    my $rows = '';
    for my $entry (@{$entries}) {
        my $label = $entry->{name} || $entry->{rel} || 'Media file';
        my $id = int($entry->{id} || 0);
        my $id_html = $id ? '<small>Media #' . $id . '</small>' : '';
        my $kind = $entry->{kind} || '';
        if (!length $kind && ($entry->{rel} || '') =~ /\.([A-Za-z0-9]+)\z/) {
            $kind = uc($1);
        }
        $kind ||= 'file';
        my $bytes = $entry->{byte_label} || _format_bytes(int($entry->{bytes} || 0));
        my $location = $entry->{public_path} || $entry->{rel} || $entry->{storage_path} || $entry->{path} || '';
        my $reason = $entry->{reason} || '';
        my $safe_label = escape_html($label);
        my $safe_kind = escape_html($kind);
        my $safe_bytes = escape_html($bytes);
        my $safe_location = escape_html($location);
        my $safe_reason = escape_html($reason);
        my $location_html = length $safe_location ? "<code>$safe_location</code>" : '<span class="muted">No path recorded</span>';
        $rows .= <<"HTML";
<tr>
  <td data-label="Item"><strong>$safe_label</strong>$id_html</td>
  <td data-label="Type">$safe_kind</td>
  <td data-label="Size">$safe_bytes</td>
  <td data-label="Location">$location_html</td>
  <td data-label="Reason">$safe_reason</td>
</tr>
HTML
    }
    $rows ||= _admin_empty_row(5, $args{empty} || 'No lifecycle findings.', $args{detail} || '');

    return <<"HTML";
  <section class="panel">
    <div class="split">
      <div>
        <h2>$safe_title</h2>
        <p>$safe_detail</p>
      </div>
      <div class="actions">
        $cleanup
      </div>
    </div>
    <table class="content-table compact-table admin-card-table">
      <thead><tr><th>Item</th><th>Type</th><th>Size</th><th>Location</th><th>Reason</th></tr></thead>
      <tbody>$rows</tbody>
    </table>
  </section>
HTML
}

sub _media_quota_status_html {
    my ($config, $settings, $assets) = @_;
    return '' unless $config && DesertCMS::CapabilityPolicy::contributor_product_mode($config);
    $settings ||= {};
    my $quota_mb = $settings->{contributor_media_quota_mb};
    return '' unless defined $quota_mb && "$quota_mb" =~ /\A[0-9]+\z/ && int($quota_mb) > 0;

    my $quota_bytes = int($quota_mb) * 1024 * 1024;
    my $used_bytes = _media_storage_used_bytes($assets);
    my $remaining_bytes = $quota_bytes > $used_bytes ? $quota_bytes - $used_bytes : 0;
    my $upload_limit = _media_upload_limit_bytes($config, $settings);
    my $pct = _percent($used_bytes, $quota_bytes);
    my $meter = _usage_meter(_format_bytes($used_bytes) . ' of ' . _format_bytes($quota_bytes) . ' media storage', $pct);
    my $remaining = escape_html(_format_bytes($remaining_bytes));
    my $upload = $upload_limit > 0 ? escape_html(_format_bytes($upload_limit)) : 'the server limit';
    my $notice = _media_storage_pressure_notice_html(
        used_bytes       => $used_bytes,
        quota_bytes      => $quota_bytes,
        remaining_bytes  => $remaining_bytes,
        upload_limit     => $upload_limit,
        billing_href     => '/admin/billing',
        billing_label    => 'View Billing',
    );

    return <<"HTML";
    <section class="media-quota-status" aria-label="Media storage usage">
      <div class="billing-usage-grid">$meter</div>
      <p class="muted">Remaining storage: $remaining. Per-file upload limit: $upload.</p>
      $notice
    </section>
HTML
}

sub _billing_media_pressure_notice_html {
    my ($usage) = @_;
    $usage ||= {};
    return '' unless $usage->{available};
    return _media_storage_pressure_notice_html(
        used_bytes      => int($usage->{media_bytes} || 0),
        quota_bytes     => int($usage->{media_quota_bytes} || 0),
        remaining_bytes => int($usage->{media_remaining_bytes} || 0),
        upload_limit    => int($usage->{media_upload_limit_bytes} || 0),
    );
}

sub _media_storage_pressure_notice_html {
    my (%args) = @_;
    my $quota = int($args{quota_bytes} || 0);
    return '' unless $quota > 0;
    my $used = int($args{used_bytes} || 0);
    my $remaining = int($args{remaining_bytes} || 0);
    my $upload_limit = int($args{upload_limit} || 0);
    my $pct = _percent($used, $quota);
    my @messages;

    if ($pct >= 100 || $remaining <= 0) {
        push @messages, 'Media storage is full. Delete unused assets or upgrade before uploading more.';
    } elsif ($pct >= 90) {
        push @messages, 'Media storage is nearly full. ' . _format_bytes($remaining) . ' remains on this plan.';
    } elsif ($pct >= 80) {
        push @messages, 'Media storage is approaching the plan limit. ' . _format_bytes($remaining) . ' remains on this plan.';
    }

    if ($upload_limit > 0 && $remaining > 0 && $remaining < $upload_limit) {
        push @messages, 'Remaining storage is lower than the per-file upload limit, so large uploads may be blocked even when the file is under ' . _format_bytes($upload_limit) . '.';
    }

    return '' unless @messages;
    my $class = ($pct >= 100 || $remaining <= 0) ? 'notice error' : 'notice';
    my $safe = escape_html(join(' ', @messages));
    my $link = '';
    if ($args{billing_href}) {
        my $href = escape_html($args{billing_href});
        my $label = escape_html($args{billing_label} || 'View Billing');
        $link = qq{ <a href="$href">$label</a>.};
    }
    return qq{<p class="$class">$safe$link</p>};
}

sub _media_storage_used_bytes {
    my ($assets) = @_;
    my $total = 0;
    for my $asset (@{ $assets || [] }) {
        next unless ref $asset eq 'HASH';
        $total += int($asset->{bytes} || 0);
    }
    return $total;
}

sub _media_upload_limit_note {
    my ($config, $settings) = @_;
    my $limit = _media_upload_limit_bytes($config, $settings);
    return 'Upload limit follows the web server configuration.' unless $limit > 0;
    my $label = _format_bytes($limit);
    return 'Current per-file upload limit: ' . $label . '. Storage usage counts separately against the current plan.'
        if $config && DesertCMS::CapabilityPolicy::contributor_product_mode($config);
    return 'Current per-file upload limit: ' . $label . '.';
}

sub _media_upload_limit_bytes {
    my ($config, $settings) = @_;
    $settings ||= {};
    my $server_cap = $config ? int($config->get('max_request_body_bytes') || 0) : 0;
    if ($config && DesertCMS::CapabilityPolicy::contributor_product_mode($config)) {
        my $plan_mb = $settings->{contributor_media_upload_limit_mb};
        if (defined $plan_mb && "$plan_mb" =~ /\A[0-9]+\z/ && int($plan_mb) > 0) {
            my $plan_cap = int($plan_mb) * 1024 * 1024;
            return $server_cap if $server_cap > 0 && $server_cap < $plan_cap;
            return $plan_cap;
        }
    }
    return $server_cap;
}

sub _media_bulk_selected_ids {
    my ($request) = @_;
    my $form = $request->{form} || {};
    my %seen;
    my @ids;
    for my $key (sort keys %{$form}) {
        next unless $key =~ /\Amedia_id_([0-9]+)\z/;
        my $id = int($1);
        next unless $id > 0 && !$seen{$id}++;
        push @ids, $id;
    }
    return @ids;
}

sub _media_bulk_action_label {
    my ($action) = @_;
    return 'Published selected resources' if ($action || '') eq 'publish_resources';
    return 'Unpublished selected resources' if ($action || '') eq 'unpublish_resources';
    return 'Deleted selected unused media' if ($action || '') eq 'delete_unused';
    return 'Applied selected metadata' if ($action || '') eq 'apply_metadata';
    return 'Bulk media action';
}

sub _admin_price {
    my ($cents) = @_;
    $cents = int($cents || 0);
    return '' unless $cents > 0;
    return sprintf('%.2f', $cents / 100);
}

sub _media_owner_html {
    my ($asset, $config) = @_;
    my $site_id = $asset->{owner_site_id} || _config_owner_site_id($config);
    my $domain = $asset->{owner_domain} || ($config ? ($config->get('contributor_domain') || _url_host($config->get('site_url'))) : '');
    my $name = $asset->{owner_display_name} || ($config ? ($config->get('contributor_owner_name') || $config->get('site_name')) : '');
    my $uploader = $asset->{uploaded_by_username} || '';
    $site_id = 'main' unless length $site_id;
    $name = $site_id eq 'main' ? 'Main deployment' : $site_id unless length $name;

    my $safe_name = escape_html($name);
    my $safe_site_id = escape_html($site_id);
    my $safe_domain = escape_html($domain);
    my $safe_uploader = escape_html($uploader);
    my $domain_html = length $safe_domain ? qq{<span>$safe_domain</span>} : '';
    my $uploader_html = length $safe_uploader ? qq{<span>Uploaded by $safe_uploader</span>} : '';
    return <<"HTML";
<div class="media-owner">
  <span class="owner-pill">$safe_site_id</span>
  <div><strong>$safe_name</strong>$domain_html$uploader_html</div>
</div>
HTML
}

sub _media_organization_html {
    my ($asset) = @_;
    my $category = $asset->{category_text} || '';
    my @tags = DesertCMS::Media::media_organization_terms($asset->{tags_text});
    my @collections = DesertCMS::Media::media_organization_terms($asset->{collections_text});
    return '' unless length($category) || @tags || @collections;
    my @chips;
    push @chips, '<span><b>Category</b> ' . escape_html($category) . '</span>' if length $category;
    push @chips, map { '<span><b>Tag</b> ' . escape_html($_) . '</span>' } @tags;
    push @chips, map { '<span><b>Collection</b> ' . escape_html($_) . '</span>' } @collections;
    return '<div class="media-organization">' . join('', @chips) . '</div>';
}

sub _media_preview_html {
    my ($asset) = @_;
    my $kind = DesertCMS::Media::asset_kind($asset);
    my $url = escape_html($asset->{public_path} || '');
    my $alt = escape_html($asset->{alt_text} || '');
    if ($kind eq 'image' && length $url) {
        return qq{<img src="$url" alt="$alt">};
    }

    my $preview = _media_preview_meta($asset);
    my $label = escape_html($preview->{label} || _media_kind_label($kind));
    my $ext = escape_html($preview->{extension} || _media_extension_label($asset->{original_name}));
    $ext = 'FILE' unless length $ext;
    my $status = DesertCMS::Media::public_policy($asset) eq 'public_resource_download'
        ? 'Public resource'
        : 'Private source';
    my $detail = escape_html($preview->{detail} || join(' - ', grep { length } ($preview->{family_label} || '', $preview->{byte_label} || '')));
    my $detail_html = length $detail ? "<small>$detail</small>" : '';
    my $heading = escape_html($preview->{text_heading} || '');
    my $heading_html = length $heading ? qq{<b>$heading</b>} : '';
    my $snippet = escape_html($preview->{snippet} || '');
    my $snippet_html = length $snippet ? qq{<em>$snippet</em>} : '';
    my $visual_url = escape_html($preview->{visual_url} || '');
    my $visual_label = escape_html($preview->{visual_preview_label} || '');
    my $visual_detail = escape_html($preview->{visual_preview_detail} || '');
    if (length $visual_url) {
        my $caption = length $visual_label || length $visual_detail
            ? '<small>' . join(' - ', grep { length } ($visual_label, $visual_detail)) . '</small>'
            : '';
        return <<"HTML";
<div class="media-document-preview media-document-preview--visual">
  <img src="$visual_url" alt="">
  <span>$ext</span>
  <strong>$status</strong>
  <small>$label</small>
  $caption
  $heading_html
  $snippet_html
</div>
HTML
    }
    my $visual_note = length($preview->{visual_preview_label} || '')
        ? '<small>' . escape_html(join(' - ', grep { length } ($preview->{visual_preview_label} || '', $preview->{visual_preview_detail} || ''))) . '</small>'
        : '';
    return <<"HTML";
<div class="media-document-preview">
  <span>$ext</span>
  <strong>$status</strong>
  <small>$label</small>
  $detail_html
  $visual_note
  $heading_html
  $snippet_html
</div>
HTML
}

sub _media_summary_html {
    my ($asset) = @_;
    my $kind = DesertCMS::Media::asset_kind($asset);
    my $preview = _media_preview_meta($asset);
    my $bytes = $preview->{byte_label} || _format_bytes(int($asset->{bytes} || 0));
    if ($kind eq 'image') {
        my $width = int($asset->{width} || 0);
        my $height = int($asset->{height} || 0);
        my $dims = $width && $height ? "$width x $height optimized image" : 'Optimized image derivative';
        return '<p>' . escape_html("$dims, source $bytes") . '</p>';
    }
    my $label = $preview->{type_label} || $preview->{label} || _media_kind_label($kind);
    my $policy = DesertCMS::Media::public_policy($asset) eq 'public_resource_download'
        ? 'public download'
        : 'private source';
    return '<p>' . escape_html("$label, $policy $bytes") . '</p>';
}

sub _media_preview_meta {
    my ($asset) = @_;
    my $meta = eval { decode_json($asset->{derivatives_json} || '{}') } || {};
    my $preview = ref $meta->{preview} eq 'HASH' ? { %{$meta->{preview}} } : {};
    my $document = ref $meta->{document} eq 'HASH' ? $meta->{document} : {};
    my $private_preview = ref $meta->{private_preview} eq 'HASH' ? $meta->{private_preview} : {};
    $preview->{label} ||= $document->{type_label} || _media_kind_label(DesertCMS::Media::asset_kind($asset));
    $preview->{type_label} ||= $document->{type_label} || $preview->{label};
    $preview->{family_label} ||= $document->{family_label} || '';
    $preview->{byte_label} ||= $document->{byte_label} || _format_bytes(int($asset->{bytes} || 0));
    $preview->{extension} ||= $document->{extension} || _media_extension_label($asset->{original_name});
    $preview->{detail} ||= join ' - ', grep { length } ($preview->{family_label} || '', $preview->{byte_label} || '');
    if (($private_preview->{path} || '') && ($private_preview->{mime} || '') =~ m{\Aimage/}) {
        $preview->{visual_url} = '/admin/media/' . int($asset->{id} || 0) . '/preview';
    }
    $preview->{visual_preview_kind} ||= $private_preview->{kind} || '';
    $preview->{visual_preview_status} ||= $private_preview->{status} || '';
    $preview->{visual_preview_label} ||= $private_preview->{label} || '';
    $preview->{visual_preview_detail} ||= $private_preview->{detail} || '';
    for my $key (qw(visual_preview_kind visual_preview_status visual_preview_label visual_preview_detail duration_label title artist album year technical_label)) {
        $preview->{$key} ||= $private_preview->{$key} if length($private_preview->{$key} || '');
    }
    if (!$preview->{snippet} && ref $document->{text_preview} eq 'HASH') {
        $preview->{snippet} = $document->{text_preview}{snippet} || '';
    }
    return $preview;
}

sub _media_kind_label {
    my ($kind) = @_;
    return 'Document/resource file' if ($kind || '') eq 'document';
    return 'Audio source file' if ($kind || '') eq 'audio';
    return 'Video source file' if ($kind || '') eq 'video';
    return 'Image' if ($kind || '') eq 'image';
    return 'Source asset';
}

sub _media_extension_label {
    my ($name) = @_;
    my ($ext) = ($name || '') =~ /\.([A-Za-z0-9]+)\z/;
    return uc($ext || '');
}

sub _download_header_filename {
    my ($filename) = @_;
    $filename = basename($filename || 'source-asset');
    $filename =~ s/[\r\n"\\\/]+/-/g;
    $filename =~ s/^\.+//;
    return length($filename) ? $filename : 'source-asset';
}

sub _media_usage_html {
    my ($usage) = @_;
    $usage ||= {};
    my @parts;
    if ($usage->{content_count}) {
        my $count = int($usage->{content_count});
        push @parts, $count . ($count == 1 ? ' page/post' : ' pages/posts');
    }
    if ($usage->{shop_listing_count}) {
        my $count = int($usage->{shop_listing_count});
        push @parts, $count . ($count == 1 ? ' shop listing' : ' shop listings');
    }
    if ($usage->{shop_order_count}) {
        my $count = int($usage->{shop_order_count});
        push @parts, $count . ($count == 1 ? ' order record' : ' order records');
    }
    return '' unless @parts;
    my $class = $usage->{content_count} ? 'media-usage is-blocked' : 'media-usage';
    my $text = escape_html('Used by ' . join(', ', @parts));
    return qq{<p class="$class">$text</p>};
}

sub _media_quality_html {
    my ($quality) = @_;
    $quality ||= {};
    my $kind = $quality->{asset_kind} || '';
    if ($kind ne 'image') {
        my $public = ($quality->{public_policy} || '') eq 'public_resource_download';
        if ($quality->{ok}) {
            return $public
                ? '<p class="media-quality is-ok">Public resource ready. Source download stays admin-only.</p>'
                : '<p class="media-quality is-ok">Private source ready. Admin download only.</p>';
        }
        my @issues = grep { defined $_ && length $_ } @{$quality->{issues} || []};
        my $issue_text = @issues ? join(' ', @issues) : 'Needs media search review.';
        my $suffix = $public ? ' Public resource.' : ' Private source only.';
        return '<p class="media-quality is-warn">' . escape_html($issue_text . $suffix) . '</p>';
    }
    my $count = int($quality->{responsive_count} || 0);
    my $responsive = $count == 1 ? '1 responsive size' : "$count responsive sizes";
    if ($quality->{ok}) {
        return '<p class="media-quality is-ok">SEO ready, ' . escape_html($responsive) . '.</p>';
    }
    my @issues = grep { defined $_ && length $_ } @{$quality->{issues} || []};
    my $issue_text = @issues ? join(' ', @issues) : 'Needs media search review.';
    return '<p class="media-quality is-warn">' . escape_html($issue_text . " $responsive.") . '</p>';
}

sub _config_owner_site_id {
    my ($config) = @_;
    return '' unless $config;
    my $configured = $config->get('contributor_site_id') || '';
    return $configured if length $configured;
    my $path = $config->{path} || '';
    $path =~ s{\\}{/}g;
    return $1 if $path =~ m{/desertcms-([a-z0-9-]+)\.conf\z};
    my $data_dir = $config->get('data_dir') || '';
    $data_dir =~ s{\\}{/}g;
    return $1 if $data_dir =~ m{/desertcms-sites/([a-z0-9-]+)\z};
    return 'main';
}

sub _setting_truthy {
    my ($value) = @_;
    return 0 unless defined $value;
    return 0 if $value eq '' || $value eq '0';
    return 0 if $value =~ /\A(?:false|no|off)\z/i;
    return 1;
}

sub _clean_shop_domain {
    my ($value) = @_;
    $value = lc($value || '');
    $value =~ s/^\s+|\s+\z//g;
    $value = $1 if $value =~ m{\Ahttps?://([^/:/]+)}i;
    $value =~ s/^\.+|\.+\z//g;
    return '' unless length $value;
    die "Shop host must be a normal domain"
        unless $value =~ /\A[a-z0-9](?:[a-z0-9-]{0,61}[a-z0-9])?(?:\.[a-z0-9](?:[a-z0-9-]{0,61}[a-z0-9])?)+\z/;
    return $value;
}

sub _clean_shop_url {
    my ($value) = @_;
    $value = '' unless defined $value;
    $value =~ s/^\s+|\s+\z//g;
    $value =~ s{/+\z}{} unless $value =~ m{\Ahttps?://[^/]+/\z}i;
    return '' unless length $value;
    die "Shop URL must start with http:// or https://"
        unless $value =~ m{\Ahttps?://}i;
    die "Shop URL contains unsupported characters"
        unless $value =~ m{\Ahttps?://[A-Za-z0-9.-]+(?::[0-9]{1,5})?(?:/[A-Za-z0-9._~:/?#\[\]@!\$&'()*+,;=%-]*)?\z};
    return $value;
}

sub _url_host {
    my ($url) = @_;
    return lc($1) if defined $url && $url =~ m{\Ahttps?://([^/:/]+)}i;
    return '';
}

sub _clean_stripe_secret {
    my ($value, $kind) = @_;
    $value = '' unless defined $value;
    $value =~ s/^\s+|\s+\z//g;
    return '' unless length $value;
    if ($kind eq 'sk') {
        die "Stripe secret key must start with sk_test_ or sk_live_"
            unless $value =~ /\Ask_(?:test|live)_[A-Za-z0-9_]+\z/;
    } elsif ($kind eq 'whsec') {
        die "Stripe webhook secret must start with whsec_"
            unless $value =~ /\Awhsec_[A-Za-z0-9_]+\z/;
    }
    return $value;
}

sub _clean_webhook_tolerance {
    my ($value) = @_;
    $value = 300 unless defined $value && "$value" =~ /\S/;
    die "Webhook tolerance must be a number of seconds"
        unless "$value" =~ /\A[0-9]+\z/;
    my $seconds = int($value);
    die "Webhook tolerance must be between 60 and 3600 seconds"
        unless $seconds >= 60 && $seconds <= 3600;
    return $seconds;
}

sub _clean_stripe_api_base {
    my ($value) = @_;
    $value = 'https://api.stripe.com/v1/checkout/sessions'
        unless defined $value && "$value" =~ /\S/;
    $value =~ s/^\s+|\s+\z//g;
    die "Stripe API endpoint must start with https://"
        unless $value =~ m{\Ahttps://}i;
    die "Stripe API endpoint contains unsupported characters"
        unless $value =~ m{\Ahttps://[A-Za-z0-9.-]+(?::[0-9]{1,5})?(?:/[A-Za-z0-9._~:/?#\[\]@!\$&'()*+,;=%-]*)?\z};
    return $value;
}

sub _contributor_request_rows {
    my ($self, $csrf) = @_;
    my $rows = '';
    for my $request (@{$self->{contributor_requests}->list_requests(limit => 50)}) {
        my $id = int($request->{id});
        my $name = escape_html($request->{name});
        my $email = escape_html($request->{email});
        my ($status_label, $status_class) = $self->_contributor_request_lifecycle($request);
        my $status = escape_html($status_label);
        my $status_class_attr = length $status_class ? ' ' . escape_html($status_class) : '';
        my $next_step = escape_html($self->_contributor_request_next_step($request));
        my $email_warning = $self->_contributor_request_email_warning_inline($request);
        my $submitted = escape_html(_format_time($request->{submitted_at}));
        my $review_url = "/admin/settings/contributors/requests/$id";
        my $actions = qq{<a class="button-link secondary" href="$review_url">Review</a>};
        if (($request->{status} || '') ne 'approved' && ($request->{status} || '') ne 'denied') {
            my $blueprint_options = $self->_blueprint_options($request->{blueprint_id});
            $actions .= <<"HTML";
<form method="post" action="/admin/settings/contributors/requests/$id/approve" class="inline-form" data-loading-label="Queueing...">
  <input type="hidden" name="csrf_token" value="$csrf">
  <select name="blueprint_id" aria-label="Contributor blueprint">$blueprint_options</select>
  <button type="submit" class="button-link secondary">Approve</button>
</form>
<form method="post" action="/admin/settings/contributors/requests/$id/deny" class="inline-form" data-confirm-title="Deny this contributor request?" data-confirm-message="This sends the not-selected email and closes this request. The applicant cannot submit again with this email for 30 days." data-confirm-action="Deny request" data-loading-label="Sending...">
  <input type="hidden" name="csrf_token" value="$csrf">
  <button type="submit" class="button-link secondary">Deny</button>
</form>
HTML
        }
        $rows .= <<"HTML";
<tr>
  <td data-label="Name">$name</td>
  <td data-label="Email">$email</td>
  <td data-label="Status"><div class="onboarding-row-status"><span class="status-pill$status_class_attr">$status</span><small>$next_step</small>$email_warning</div></td>
  <td data-label="Submitted">$submitted</td>
  <td data-label="Actions" class="table-actions">$actions</td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(5, 'No contributor requests yet.', 'Requests submitted from /contributors/apply/ will appear here for review.');
}

sub _contributor_request_review_page {
    my ($self, $request, $session, $session_token, $id, $message) = @_;
    my $csrf = $self->{auth}->csrf_token($session_token);
    my $row = $self->{contributor_requests}->request_by_id($id);
    return $self->_not_found unless $row;
    $self->{contributor_requests}->mark_reviewing($id) if ($row->{status} || '') eq 'new';
    $row = $self->{contributor_requests}->request_by_id($id);

    my $notice = $message ? '<p class="notice">' . escape_html($message) . '</p>' : '';
    my $settings_nav = $self->_settings_nav('contributors', $session);
    my $name = escape_html($row->{name});
    my $email = escape_html($row->{email});
    my $phone = escape_html($row->{phone});
    my $age = int($row->{age} || 0);
    my $application_text = escape_html($row->{application_text} || $row->{bio} || '');
    my $bio = escape_html($row->{bio} || '');
    my ($status_label, $status_class) = $self->_contributor_request_lifecycle($row);
    my $status = escape_html($status_label);
    my $status_class_attr = length $status_class ? ' ' . escape_html($status_class) : '';
    my $submitted = escape_html(_format_time($row->{submitted_at}));
    my $domain = escape_html($row->{domain} || '');
    my $progress_html = $self->_contributor_request_progress($row);
    my $email_panel = $self->_contributor_request_email_panel($row);
    my $site_line = $domain ? qq{<div><dt>Contributor site</dt><dd><a href="https://$domain/">$domain</a></dd></div>} : '';
    my $archive_line = '';
    if (($row->{archived_site_filename} || '') ne '') {
        my $filename = escape_html($row->{archived_site_filename});
        my $archived_at = escape_html(_format_time($row->{archived_site_at}));
        $archive_line = qq{<div><dt>Archived site</dt><dd>$filename} . ($archived_at ? qq{ on $archived_at} : '') . qq{</dd></div>};
    }
    my $profile_status = $self->_contributor_request_archived($row)
        ? 'Archived with destroyed site'
        : $self->_contributor_profile_complete($row)
        ? 'Complete' . ($row->{profile_completed_at} ? ' on ' . _format_time($row->{profile_completed_at}) : '')
        : (($row->{status} || '') eq 'approved' ? 'Waiting for profile form' : 'Not requested yet');
    my $profile_status_safe = escape_html($profile_status);
    my $profile_preview = _request_image_preview($row->{profile_photo_path}, $row->{profile_photo_mime}, $row->{name});
    my $application_showcase_preview = _request_showcase_preview($row, application => 1);
    my $profile_showcase_preview = _request_showcase_preview($row);
    my $profile_section = $self->_contributor_profile_complete($row) ? <<"HTML" : '';
    <section class="inspector-panel">
      <h2>Public Profile</h2>
      <dl class="health-list health-list--compact">
        <div><dt>Status</dt><dd>$profile_status_safe</dd></div>
      </dl>
      <h3>Bio</h3>
      <p>$bio</p>
      <h3>Portrait</h3>
      $profile_preview
      <h3>Profile Samples</h3>
      <div class="request-showcase-grid">$profile_showcase_preview</div>
    </section>
HTML
    my $disabled = (($row->{status} || '') eq 'approved' || ($row->{status} || '') eq 'denied') ? 'disabled' : '';
    my $blueprint_options = $self->_blueprint_options($row->{blueprint_id});

    my $body = <<"HTML";
<section class="editor-workspace">
  $settings_nav
  <section class="panel">
    <div class="split">
      <div>
        <p class="eyebrow">Contributor Request</p>
        <h1>$name</h1>
        <p>Review the submitted contributor application and queue onboarding when approved.</p>
      </div>
      <a class="button-link secondary" href="/admin/settings/contributors">Back to Contributors</a>
    </div>
    $notice
    $progress_html
    $email_panel
    <section class="inspector-panel">
      <h2>Request</h2>
      <dl class="health-list health-list--compact">
        <div><dt>Status</dt><dd><span class="status-pill$status_class_attr">$status</span></dd></div>
        <div><dt>Submitted</dt><dd>$submitted</dd></div>
        <div><dt>Email</dt><dd><a href="mailto:$email">$email</a></dd></div>
        <div><dt>Phone</dt><dd>$phone</dd></div>
        <div><dt>Age</dt><dd>$age</dd></div>
        <div><dt>Profile</dt><dd>$profile_status_safe</dd></div>
        $site_line
        $archive_line
      </dl>
      <h3>Why They Want To Join</h3>
      <p>$application_text</p>
    </section>
    <section class="inspector-panel">
      <h2>Application Samples</h2>
      <div class="request-showcase-grid">$application_showcase_preview</div>
    </section>
    $profile_section
    <section class="inspector-panel">
      <h2>Decision</h2>
      <form method="post" action="/admin/settings/contributors/requests/$id/approve" class="stack" data-loading-label="Queueing...">
        <input type="hidden" name="csrf_token" value="$csrf">
        <label>
          <span>Contributor blueprint</span>
          <select name="blueprint_id" $disabled>$blueprint_options</select>
        </label>
        <label>
          <span>Approval note</span>
          <textarea name="note" rows="3" placeholder="Optional internal note"></textarea>
        </label>
        <button type="submit" $disabled>Approve and create contributor site</button>
      </form>
      <form method="post" action="/admin/settings/contributors/requests/$id/deny" class="stack" data-confirm-title="Deny this contributor request?" data-confirm-message="This sends the not-selected email and closes this request. The applicant cannot submit again with this email for 30 days." data-confirm-action="Deny request" data-loading-label="Sending...">
        <input type="hidden" name="csrf_token" value="$csrf">
        <label>
          <span>Denial note</span>
          <textarea name="note" rows="3" placeholder="Optional internal note"></textarea>
        </label>
        <button type="submit" class="secondary" $disabled>Deny and email applicant</button>
      </form>
    </section>
  </section>
</section>
HTML

    return $self->_html_response('Contributor Request', $body, $session);
}

sub _contributor_request_action {
    my ($self, $request, $session, $session_token, $id, $action) = @_;
    my $notice = '';
    my $ok = eval {
        if ($action eq 'approve') {
            my $row = $self->{contributor_requests}->approve(
                id    => $id,
                note  => $request->param('note'),
                blueprint_id => $request->param('blueprint_id'),
                sites => $self->{sites},
            );
            $self->{content}->rebuild_all;
            $self->_audit_admin_action(
                $session,
                action       => 'contributor_request.approved',
                subject_type => 'contributor_request',
                subject_id   => int($id || 0),
                details      => {
                    email        => $row->{email} || '',
                    site_id      => $row->{site_id} || '',
                    domain       => $row->{domain} || '',
                    email_sent   => $row->{approval_email_sent} ? 1 : 0,
                    email_reason => $row->{approval_email_reason} || '',
                },
            );
            $notice = $row->{approval_email_sent}
                ? 'request-approved-email-sent'
                : 'request-approved-email-failed';
        } elsif ($action eq 'deny') {
            my $row = $self->{contributor_requests}->deny(
                id   => $id,
                note => $request->param('note'),
            );
            $self->_audit_admin_action(
                $session,
                action       => 'contributor_request.denied',
                subject_type => 'contributor_request',
                subject_id   => int($id || 0),
                details      => {
                    email        => $row->{email} || '',
                    email_sent   => $row->{denial_email_sent} ? 1 : 0,
                    email_reason => $row->{denial_email_reason} || '',
                },
            );
            $notice = $row->{denial_email_sent}
                ? 'request-denied-email-sent'
                : 'request-denied-email-failed';
        } else {
            die "unsupported request action";
        }
        1;
    };
    if (!$ok) {
        return $self->_contributor_request_review_page(
            $request,
            $session,
            $session_token,
            $id,
            _admin_action_error(
                'The contributor request decision could not be saved.',
                'Check the request status and selected blueprint, then try again.',
                $@
            )
        );
    }
    return DesertCMS::HTTP->redirect(
        '/admin/settings/contributors?notice=' . ($notice || 'contributors-saved'),
        { security_headers() }
    );
}

sub _request_image_preview {
    my ($path, $mime, $alt) = @_;
    my $src = _data_uri_for_image($path, $mime);
    return _admin_empty_panel('No portrait available.', 'The portrait appears here after the approved contributor completes the profile form.') unless length $src;
    my $safe_alt = escape_html($alt || 'Contributor photo');
    return qq{<img class="request-review-image" src="$src" alt="$safe_alt">};
}

sub _request_showcase_preview {
    my ($row, %args) = @_;
    my $files = $args{application}
        ? DesertCMS::ContributorRequests::application_showcase_files($row)
        : DesertCMS::ContributorRequests::showcase_files($row);
    my $html = '';
    for my $file (@{$files}) {
        my $path = $file->{path} || '';
        my $mime = $file->{mime_type} || '';
        my $name = escape_html($file->{filename} || basename($path || 'Showcase piece'));
        my $src = _data_uri_for_image($path, $mime);
        my $preview = length $src
            ? qq{<img src="$src" alt="$name">}
        : '<span class="muted">Preview unavailable. Check that the stored file still exists.</span>';
        $html .= qq{<figure class="request-showcase-card">$preview<figcaption>$name</figcaption></figure>};
    }
    return $html || _admin_empty_panel(
        'No sample images stored.',
        $args{application}
            ? 'Optional application samples appear here when the applicant uploads them with the request.'
            : 'Profile samples appear here after the approved contributor completes the profile form.'
    );
}

sub _contributor_profile_complete {
    my ($self, $row) = @_;
    return 0 unless $row && ($row->{status} || '') eq 'approved';
    return 1 if $row->{profile_completed_at};
    return (($row->{bio} || '') ne '' && ($row->{public_profile_image_path} || '') ne '') ? 1 : 0;
}

sub _contributor_request_next_step {
    my ($self, $row) = @_;
    return 'Open the application.' unless $row;
    my $status = $row->{status} || '';
    return 'Review the application.' if $status eq 'new';
    return 'Approve with a blueprint or deny.' if $status eq 'reviewing';
    return 'No further onboarding action.' if $status eq 'denied';
    return 'Open the request.' unless $status eq 'approved';

    my $site = $self->_contributor_request_site($row);
    my $queue = $self->_contributor_request_latest_queue($row);
    return 'Review the failed provisioning job.' if $queue && ($queue->{status} || '') eq 'failed';
    return 'Wait for the contributor profile form.' unless $self->_contributor_profile_complete($row);
    return 'Wait for provisioning to finish.' if $site && ($site->{status} || '') eq 'pending_provision';
    return 'Review billing status.' if $site && ($site->{billing_status} || '') eq 'past_due';
    return 'Contributor onboarding is complete.' if $site && ($site->{status} || '') eq 'active';
    return 'Review contributor site status.';
}

sub _contributor_request_progress {
    my ($self, $row) = @_;
    my $status = $row->{status} || '';
    my $site = $self->_contributor_request_site($row);
    my $queue = $self->_contributor_request_latest_queue($row);
    my $profile_complete = $self->_contributor_profile_complete($row);
    my $site_status = $site ? ($site->{status} || '') : '';
    my $queue_status = $queue ? ($queue->{status} || '') : '';
    my $billing_status = $site ? ($site->{billing_status} || 'comped') : '';
    my $plan_name = $site ? ($site->{service_plan_name} || 'Free Tier') : 'Not assigned';

    my @steps = (
        {
            label  => 'Request',
            state  => 'done',
            detail => 'Application received ' . _format_time($row->{submitted_at}),
        },
        {
            label  => 'Review',
            state  => ($status eq 'new') ? 'active' : 'done',
            detail => $status eq 'new' ? 'Open the application to begin review.' : 'Request review has started.',
        },
        {
            label  => 'Decision',
            state  => $status eq 'approved' ? 'done' : ($status eq 'denied' ? 'warn' : 'pending'),
            detail => $status eq 'approved'
                ? 'Approved and queued for contributor site creation.'
                : ($status eq 'denied' ? 'Denied applicant.' : 'Approve with a blueprint or deny.'),
        },
        {
            label  => 'Profile',
            state  => $profile_complete ? 'done' : ($status eq 'approved' ? 'active' : 'pending'),
            detail => $profile_complete
                ? 'Public bio and portrait completed.'
                : ($status eq 'approved' ? 'Waiting for the applicant to complete the emailed profile form.' : 'Profile link is sent after approval.'),
        },
        {
            label  => 'Provision',
            state  => ($queue_status eq 'failed') ? 'warn'
                : ($site_status eq 'active' ? 'done'
                : (($site_status eq 'pending_provision' || $queue_status eq 'queued' || $queue_status eq 'running') ? 'active' : 'pending')),
            detail => $queue_status eq 'failed'
                ? ($queue->{error_text} || 'Provisioning stopped before the contributor site was ready. Review the job in Master Control, fix the failing step, then retry it.')
                : ($site_status ? "Site status: $site_status" : 'Contributor site is created after approval.'),
            action => $queue && $queue->{id} ? '/admin/settings/master-control/provisioning/' . int($queue->{id}) : '',
        },
        {
            label  => 'Billing',
            state  => $billing_status eq 'past_due' ? 'warn' : ($site ? 'done' : 'pending'),
            detail => $site
                ? "Plan: $plan_name, billing: $billing_status"
                : 'The default free tier is assigned when the site row is created.',
        },
    );

    my $items = join '', map { $self->_contributor_progress_step($_) } @steps;
    return <<"HTML";
<section class="inspector-panel onboarding-progress-panel">
  <h2>Onboarding Progress</h2>
  <ol class="onboarding-progress">$items</ol>
</section>
HTML
}

sub _contributor_progress_step {
    my ($self, $step) = @_;
    my $label = escape_html($step->{label} || '');
    my $state = $step->{state} || 'pending';
    $state = 'pending' unless $state =~ /\A(?:done|active|pending|warn)\z/;
    my $detail = escape_html($step->{detail} || '');
    my $action = '';
    if ($step->{action}) {
        my $href = escape_html($step->{action});
        $action = qq{<a class="button-link secondary button-link--compact" href="$href">Review job</a>};
    }
    return <<"HTML";
<li class="onboarding-progress-step onboarding-progress-step--$state">
  <span>$label</span>
  <p>$detail</p>
  $action
</li>
HTML
}

sub _contributor_request_site {
    my ($self, $row) = @_;
    return undef unless $row;
    my @where;
    my @params;
    if (length($row->{site_id} || '')) {
        push @where, q{(s.site_id <> '' AND s.site_id = ?)};
        push @params, $row->{site_id};
    }
    if (length($row->{domain} || '')) {
        push @where, q{(s.domain <> '' AND s.domain = ?)};
        push @params, $row->{domain};
    }
    return undef unless @where;
    my $where = join ' OR ', @where;
    return eval {
        $self->{db}->dbh->selectrow_hashref(
            qq{
                SELECT s.*, p.name AS service_plan_name
                FROM contributor_sites s
                LEFT JOIN service_plans p ON p.id = s.service_plan_id
                WHERE $where
                ORDER BY s.updated_at DESC, s.id DESC
                LIMIT 1
            },
            undef,
            @params
        );
    };
}

sub _contributor_request_latest_queue {
    my ($self, $row) = @_;
    return undef unless $row && length($row->{site_id} || '');
    return eval {
        $self->{db}->dbh->selectrow_hashref(
            q{
                SELECT *
                FROM site_provisioning_queue
                WHERE site_id = ?
                ORDER BY updated_at DESC, id DESC
                LIMIT 1
            },
            undef,
            $row->{site_id}
        );
    };
}

sub _contributor_request_latest_applicant_failure {
    my ($self, $row) = @_;
    return undef unless $row && length($row->{email} || '');
    return eval {
        $self->{db}->dbh->selectrow_hashref(
            q{
                SELECT *
                FROM email_delivery_logs
                WHERE lower(to_email) = lower(?)
                  AND email_type IN ('contributor_request_approved', 'contributor_request_denied', 'contributor_access_grant')
                  AND status IN ('failed', 'bounced', 'spam', 'complaint')
                ORDER BY updated_at DESC, id DESC
                LIMIT 1
            },
            undef,
            $row->{email}
        );
    };
}

sub _contributor_request_email_warning_inline {
    my ($self, $row) = @_;
    my $failure = $self->_contributor_request_latest_applicant_failure($row);
    return '' unless $failure;
    my $reason = escape_html($failure->{reason} || 'No provider detail was recorded.');
    return qq{<small class="onboarding-email-warning">Email needs attention: $reason</small>};
}

sub _contributor_request_email_panel {
    my ($self, $row) = @_;
    return '' unless $row && length($row->{email} || '');
    my $logs = eval {
        $self->{db}->dbh->selectall_arrayref(
            q{
                SELECT *
                FROM email_delivery_logs
                WHERE lower(to_email) = lower(?)
                  AND email_type IN ('contributor_request_approved', 'contributor_request_denied', 'contributor_access_grant')
                ORDER BY updated_at DESC, id DESC
                LIMIT 4
            },
            { Slice => {} },
            $row->{email}
        );
    } || [];

    my $items = '';
    for my $log (@{$logs}) {
        my $status = escape_html($log->{status} || 'unknown');
        my $class = ($log->{status} || '') =~ /\A(?:sent|delivered|opened|clicked)\z/ ? 'ok'
            : (($log->{status} || '') =~ /\A(?:failed|bounced|spam|complaint)\z/ ? 'warn' : 'status-pill--neutral');
        my $type = escape_html($log->{email_type} || 'email');
        my $subject = escape_html($log->{subject} || '');
        my $reason = escape_html($log->{reason} || '');
        my $when = escape_html(_format_time($log->{updated_at} || $log->{created_at}));
        $items .= <<"HTML";
<li>
  <span class="status-pill $class">$status</span>
  <strong>$type</strong>
  <small>$when</small>
  <em>$subject</em>
  <em>$reason</em>
</li>
HTML
    }
    $items ||= '<li><span class="status-pill status-pill--neutral">No applicant emails yet</span><small>Approval, denial, and access emails for this applicant will appear here.</small></li>';
    return <<"HTML";
<section class="inspector-panel onboarding-email-panel">
  <h2>Email Delivery</h2>
  <ul class="onboarding-email-list">$items</ul>
</section>
HTML
}

sub _contributor_request_lifecycle {
    my ($self, $row) = @_;
    my $status = $row ? ($row->{status} || '') : '';
    return ('new', 'warn') unless length $status;
    return ('new', 'warn') if $status eq 'new';
    return ('reviewing', 'warn') if $status eq 'reviewing';
    return ('denied', 'warn') if $status eq 'denied';
    return ($status, '') unless $status eq 'approved';

    my $site_status = $row->{contributor_site_status} || '';
    return ('approved - archived site', 'warn') if $self->_contributor_request_archived($row);
    return ('approved - provisioning queued', 'warn') if $site_status eq 'pending_provision';
    return ('approved - site disabled', 'warn') if $site_status eq 'disabled';
    return ('approved - destroy pending', 'warn') if $site_status eq 'destroy_pending';
    if ($site_status eq 'active') {
        return $self->_contributor_profile_complete($row)
            ? ('approved - active', 'ok')
            : ('approved - profile pending', 'warn');
    }
    return ('approved - site removed', 'warn')
        unless ($row->{site_id} || '') ne '' || ($row->{domain} || '') ne '';
    return $self->_contributor_profile_complete($row)
        ? ('approved - site status unknown', 'warn')
        : ('approved - profile pending', 'warn');
}

sub _contributor_request_archived {
    my ($self, $row) = @_;
    return 0 unless $row && ($row->{status} || '') eq 'approved';
    return 1 if ($row->{archived_site_filename} || '') ne '' || int($row->{archived_site_at} || 0) > 0;
    return 0;
}

sub _data_uri_for_image {
    my ($path, $mime) = @_;
    return '' unless defined $path && -f $path;
    $mime = lc($mime || '');
    return '' unless $mime =~ /\Aimage\/(?:jpeg|png|webp)\z/;
    return '' if -s $path > 12 * 1024 * 1024;
    open my $fh, '<:raw', $path or return '';
    local $/;
    my $body = <$fh>;
    close $fh;
    my $encoded = encode_base64($body || '', '');
    return "data:$mime;base64,$encoded";
}

sub _contributor_site_rows {
    my ($self, $csrf, $mode) = @_;
    $mode ||= 'active';
    my $rows = '';
    for my $site (@{$self->{sites}->list_sites}) {
        my $status_value = $site->{status} || '';
        next if $mode eq 'disabled' && $status_value ne 'disabled';
        next if $mode ne 'disabled' && $status_value eq 'disabled';
        my $site_id = escape_html($site->{site_id});
        my $domain = escape_html($site->{domain});
        my $owner = escape_html($site->{owner_email} || ($site->{display_name} || ''));
        my $blueprint = escape_html(_site_blueprint_label($site));
        my $status = escape_html($status_value);
        my $actions = $self->_site_action_buttons($csrf, $site);
        $rows .= <<"HTML";
<tr>
  <td data-label="Site"><strong>$domain</strong><br><span class="muted">$site_id</span></td>
  <td data-label="Owner">$owner</td>
  <td data-label="Blueprint">$blueprint</td>
  <td data-label="Status"><span class="status-pill">$status</span></td>
  <td data-label="Actions" class="table-actions">$actions</td>
</tr>
HTML
    }
    my $empty = $mode eq 'disabled'
        ? 'No disabled contributor sites.'
        : 'No active contributor sites yet.';
    return $rows || _admin_empty_row(5, $empty, 'Contributor site lifecycle actions will be available after a site exists in this state.');
}

sub _archived_site_rows {
    my ($self, $archives) = @_;
    my $rows = '';
    for my $archive (@{$archives || []}) {
        my $name = $archive->{display_name} || '';
        if ($name !~ /\S/) {
            my $first = $archive->{owner_first_name} || '';
            my $last = $archive->{owner_last_initial} || '';
            $name = join ' ', grep { /\S/ } ($first, $last);
        }
        $name = $archive->{owner_email} || $archive->{site_id} || 'Archived site' if $name !~ /\S/;
        my $safe_name = escape_html($name);
        my $owner = escape_html($archive->{owner_email} || '');
        my $owner_html = length $owner ? qq{<br><a href="mailto:$owner">$owner</a>} : '';
        my $site_id = escape_html($archive->{site_id} || '');
        my $domain = escape_html($archive->{domain} || '');
        my $filename = escape_html($archive->{archive_filename} || '');
        my $path = escape_html($archive->{archive_path} || '');
        my $archived = escape_html(_format_time($archive->{archived_at}));
        my $size = escape_html(_format_bytes($archive->{archive_bytes} || 0));
        $rows .= <<"HTML";
<tr>
  <td data-label="Contributor"><strong>$safe_name</strong>$owner_html<br><span class="muted">$site_id</span></td>
  <td data-label="Domain">$domain</td>
  <td data-label="Archive"><code>$filename</code><br><span class="muted">$path</span></td>
  <td data-label="Archived">$archived</td>
  <td data-label="Size">$size</td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(5, 'No archived contributor sites.', 'Destroyed contributor sites are archived before removal and will be listed here.');
}

sub _site_blueprint_label {
    my ($site) = @_;
    return 'Default' unless $site;
    my $snapshot = eval { decode_json($site->{blueprint_snapshot_json} || '{}') } || {};
    if ($snapshot->{name}) {
        my $category = $snapshot->{category} ? DesertCMS::Blueprints::vertical_label($snapshot->{category}) : '';
        return length $category ? "$category - $snapshot->{name}" : $snapshot->{name};
    }
    return 'Blueprint #' . int($site->{blueprint_id}) if $site->{blueprint_id};
    return 'Default';
}

sub _site_action_buttons {
    my ($self, $csrf, $site) = @_;
    my $site_id = escape_html($site->{site_id});
    my @actions;
    if (($site->{status} || '') eq 'disabled') {
        push @actions, _site_action_form($csrf, $site_id, 'enable', 'Enable');
    } elsif (($site->{status} || '') ne 'destroyed' && ($site->{status} || '') ne 'destroy_pending') {
        push @actions, _site_action_form($csrf, $site_id, 'disable', 'Disable');
    }
    if (($site->{status} || '') ne 'destroyed' && ($site->{status} || '') ne 'destroy_pending') {
        push @actions, _site_action_form($csrf, $site_id, 'destroy', 'Destroy');
    }
    if (($site->{status} || '') eq 'active') {
        push @actions, <<"HTML";
<form method="post" action="/admin/settings/sites/grant" class="inline-form grant-access-form">
  <input type="hidden" name="csrf_token" value="$csrf">
  <input type="hidden" name="site_id" value="$site_id">
  <input name="email" type="email" placeholder="access\@example.com" required>
  <button type="submit" class="button-link secondary">Grant access</button>
</form>
HTML
    }
    return join ' ', @actions;
}

sub _site_action_form {
    my ($csrf, $site_id, $action, $label) = @_;
    my $attrs = ' data-loading-label="Queueing..."';
    if ($action eq 'destroy') {
        $attrs = ' data-confirm-title="Archive and destroy this contributor site?" data-confirm-message="The worker will create a private full-site archive, remove the live subCMS, clear master surfacing references, and reload webserver config after validation." data-confirm-action="Destroy site" data-loading-label="Queueing..."';
    } elsif ($action eq 'disable') {
        $attrs = ' data-confirm-title="Disable this contributor site?" data-confirm-message="The site will be removed from active service but its files and database will be preserved for later enable or destroy." data-confirm-action="Disable site" data-loading-label="Queueing..."';
    }
    return <<"HTML";
<form method="post" action="/admin/settings/sites/action" class="inline-form"$attrs>
  <input type="hidden" name="csrf_token" value="$csrf">
  <input type="hidden" name="site_id" value="$site_id">
  <input type="hidden" name="action" value="$action">
  <button type="submit" class="button-link secondary">$label</button>
</form>
HTML
}

sub _contributor_invite_rows {
    my ($self, $csrf) = @_;
    my $rows = '';
    for my $invite (@{$self->{sites}->list_invites}) {
        my $email = escape_html($invite->{email});
        my $status = escape_html($invite->{status});
        my $blueprint = escape_html($invite->{blueprint_name} || 'Default');
        my $domain = escape_html($invite->{domain} || '');
        my $action = '';
        if (($invite->{status} || '') eq 'pending') {
            my $id = int($invite->{id});
            $action = <<"HTML";
<form method="post" action="/admin/settings/invites/revoke" class="inline-form" data-confirm-title="Revoke this invite?" data-confirm-message="The invite link will stop working and the recipient will need a new invite before they can join." data-confirm-action="Revoke" data-loading-label="Deleting...">
  <input type="hidden" name="csrf_token" value="$csrf">
  <input type="hidden" name="invite_id" value="$id">
  <button type="submit" class="button-link secondary">Revoke</button>
</form>
HTML
        }
        $rows .= <<"HTML";
<tr>
  <td data-label="Email">$email</td>
  <td data-label="Status"><span class="status-pill">$status</span></td>
  <td data-label="Blueprint">$blueprint</td>
  <td data-label="Domain">$domain</td>
  <td data-label="Actions" class="table-actions">$action</td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(5, 'No contributor invites yet.', 'Sent invitations will appear here until accepted, expired, or revoked.');
}

sub _contributor_queue_rows {
    my ($self, $csrf) = @_;
    my $rows = '';
    for my $job (@{$self->{sites}->queue_rows}) {
        my $id = int($job->{id} || 0);
        my $site_id = escape_html($job->{site_id});
        my $action = escape_html($job->{action});
        my $status = _queue_status_pill($job->{status});
        my $step = escape_html($job->{last_step_label} || 'Not started');
        my $step_status = $job->{last_step_status} || '';
        my $step_html = $step_status ? _queue_event_status_pill($step_status) . '<small>' . $step . '</small>' : $step;
        my $updated = escape_html(_format_time($job->{updated_at}));
        my $actions = qq{<a class="button-link secondary" href="/admin/settings/master-control/provisioning/$id">Review</a>};
        if (($job->{status} || '') eq 'failed' && defined $csrf) {
            $actions .= <<"HTML";
<form method="post" action="/admin/settings/master-control/provisioning/$id/retry" class="inline-form">
  <input type="hidden" name="csrf_token" value="$csrf">
  <button type="submit" class="button-link secondary">Retry</button>
</form>
HTML
        }
        $rows .= <<"HTML";
<tr>
  <td data-label="Site">$site_id</td>
  <td data-label="Action">$action</td>
  <td data-label="Status">$status</td>
  <td data-label="Last step">$step_html</td>
  <td data-label="Updated">$updated</td>
  <td data-label="Actions" class="table-actions">$actions</td>
</tr>
HTML
    }
    return $rows || _admin_empty_row(6, 'No queued provisioning work.', 'Contributor site lifecycle jobs will appear here when invites, approvals, disables, or destroys are queued.');
}

sub _require_login {
    my ($self, $request, $handler) = @_;
    my $cookie_name = $self->{config}->get('session_cookie');
    my $token = $request->cookie($cookie_name);
    my $session = $self->{auth}->session_from_token($token);
    if (!$session) {
        return DesertCMS::HTTP->redirect('/admin/login', { security_headers() });
    }
    if (($session->{force_password_change} || 0)
        && $request->{path} ne '/admin/account/setup'
        && $request->{path} ne '/admin/logout') {
        return DesertCMS::HTTP->redirect('/admin/account/setup', { security_headers() });
    }
    if (my $redirect = $self->_contributor_product_route_redirect($request)) {
        return DesertCMS::HTTP->redirect($redirect, { security_headers() });
    }
    if (!DesertCMS::Governance::allowed($self->{config}, $session->{role}, $request->{method}, $request->{path})) {
        $self->_audit_admin_action(
            $session,
            action       => 'auth.forbidden',
            subject_type => 'route',
            details      => { method => $request->{method}, path => $request->{path}, role => $session->{role} || '' },
        );
        return $self->_forbidden;
    }
    return $handler->($session, $token);
}

sub _contributor_product_route_redirect {
    my ($self, $request) = @_;
    return '' unless DesertCMS::CapabilityPolicy::contributor_product_mode($self->{config});
    return '' unless ($request->{method} || 'GET') eq 'GET';
    my $path = $request->{path} || '';
    return '/admin/settings/account' if $path eq '/admin/settings';
    return '/admin/site-settings?section=theme' if $path eq '/admin/theme';
    return '/admin/pages/new' if $path eq '/admin/content/new';
    return '';
}

sub _audit_admin_action {
    my ($self, $session, %args) = @_;
    eval {
        $self->{auth}->record_audit(
            actor_user_id => $session ? $session->{user_id} : undef,
            action        => $args{action},
            subject_type  => $args{subject_type},
            subject_id    => $args{subject_id},
            details       => $args{details} || {},
        );
        1;
    };
}

sub _require_post {
    my ($self, $request, $handler) = @_;
    return $self->_method_not_allowed unless $request->{method} eq 'POST';

    return $self->_require_login($request, sub {
        my ($session, $token) = @_;
        if (!$self->{auth}->verify_csrf($token, $request->param('csrf_token'))) {
            return $self->_forbidden;
        }
        return $handler->($session, $token);
    });
}

sub _request_too_large {
    my ($self, $request) = @_;
    my %headers = (
        'Content-Type' => 'text/plain; charset=utf-8',
        security_headers(),
    );
    return DesertCMS::HTTP->response(
        status  => 413,
        headers => \%headers,
        body    => "Request body is too large\n",
    );
}

sub _html_response {
    my ($self, $title, $body, $session) = @_;
    my $product_mode = DesertCMS::CapabilityPolicy::contributor_product_mode($self->{config}) ? 'contributor' : 'master';
    my $nav = '';
    if ($session) {
        $nav = $product_mode eq 'contributor'
            ? $self->_contributor_product_nav($title, $session)
            : $self->_admin_primary_nav($title, $session);
    }
    my $settings = eval { DesertCMS::Settings::all($self->{config}, $self->{db}) } || {};
    my $default_theme_mode = DesertCMS::SiteTheme::default_mode($settings);
    my %headers = (
        'Content-Type' => 'text/html; charset=utf-8',
        $self->_admin_security_headers,
    );
    return DesertCMS::HTTP->response(
        status  => 200,
        headers => \%headers,
        body    => DesertCMS::HTTP->html_page(
            title => $title,
            body => $body,
            user_nav => $nav,
            brand => _admin_brand_html($settings),
            default_theme_mode => $default_theme_mode,
            admin_css_version => _admin_css_cache_key($settings),
            product_mode => $product_mode,
        ),
    );
}

sub _admin_primary_nav {
    my ($self, $title, $session) = @_;
    my $role = $session ? $session->{role} : 'owner';
    my @links = (
        [ analytics => '/admin',          'Analytics', 'view_home' ],
        [ editor    => '/admin/editor',   'Editor',    'view_content' ],
        [ modules   => '/admin/settings/modules', 'Modules', 'view_features' ],
        [ accounts  => '/admin/accounts', 'Accounts', 'view_features' ],
        [ notifications => '/admin/notifications', 'Notifications', 'view_notifications' ],
        [ security  => '/admin/settings/security', 'Security', 'view_security_center' ],
        [ backups   => '/admin/backups',  'Backups',   'view_operations' ],
    );
    my $settings = eval { DesertCMS::Settings::all($self->{config}, $self->{db}) } || {};
    if (DesertCMS::Commerce::is_contributor_instance($self->{config})) {
        push @links, [ billing => '/admin/billing', 'Billing', 'view_usage' ];
    }
    push @links, [ settings => '/admin/settings', 'Settings', 'view_settings' ];

    my $active = _admin_primary_nav_active_key($title || '');
    my $html = '<nav class="admin-primary-nav" id="admin-primary-nav" aria-label="Admin sections">';
    for my $link (@links) {
        my ($key, $href, $label, $capability) = @{$link};
        next if $key eq 'accounts' && !DesertCMS::Modules::enabled($settings, 'accounts');
        next if $capability
            && !DesertCMS::CapabilityPolicy::has($self->{config}, $role, $capability);
        my $class = $key eq $active ? ' class="active" aria-current="page"' : '';
        $html .= qq{<a href="$href"$class>$label</a>};
    }
    $html .= '</nav>';
    return $html;
}

sub _contributor_product_nav {
    my ($self, $title, $session) = @_;
    my $role = DesertCMS::Governance::normalize_role(
        $session ? $session->{role} : 'owner',
        'contributor'
    );
    my $settings = eval { DesertCMS::Settings::all($self->{config}, $self->{db}) } || {};
    my @links = _contributor_product_nav_links($self->{config}, $role, settings => $settings);
    my $active = _contributor_primary_nav_active_key($title || '');
    my $html = '<nav class="contributor-product-nav" id="admin-primary-nav" aria-label="Hosted site builder sections" data-product-nav="contributor">';
    for my $link (@links) {
        my ($key, $href, $label) = @{$link};
        my $class = $key eq $active ? ' class="active" aria-current="page"' : '';
        $html .= qq{<a href="$href"$class>$label</a>};
    }
    $html .= '</nav>';
    return $html;
}

sub _contributor_product_nav_links {
    my ($config, $role, %args) = @_;
    $role ||= 'owner';
    my $settings = $args{settings} || {};
    my @core = (
        [ home         => '/admin',        'Home',         'view_home' ],
        [ site_builder => '/admin/editor', 'Site Builder', 'view_content' ],
        [ pages        => '/admin/pages',  'Pages',        'view_content' ],
        [ media        => '/admin/media',  'Media',        'view_media' ],
    );
    splice @core, 3, 0, [ posts => '/admin/posts', 'Posts', 'view_content' ]
        if DesertCMS::Modules::enabled($settings, 'posts');
    my @manage = (
        [ notifications => '/admin/notifications', 'Notifications', 'view_notifications' ],
        [ billing => '/admin/billing',          'Billing', 'view_usage' ],
        [ account => '/admin/settings/account', 'Account', 'manage_account' ],
        [ help    => '/admin/help',             'Help',    'view_home' ],
    );
    my @catalog = (
        @core,
        [ design   => '/admin/site-settings?section=theme', 'Design',   'view_design' ],
        [ features => '/admin/settings/modules',            'Features', 'view_features' ],
        @manage,
    );
    return grep {
        !$_->[3] || DesertCMS::CapabilityPolicy::has($config, $role, $_->[3])
    } @catalog;
}

sub _admin_primary_nav_active_key {
    my ($title) = @_;
    return 'analytics' if $title eq 'Analytics';
    return 'accounts' if $title eq 'Accounts';
    return 'notifications' if $title eq 'Notifications';
    return 'security' if $title eq 'Security Center';
    return 'backups' if $title eq 'Backups';
    return 'modules' if _module_surface_title($title);
    return 'billing' if $title eq 'Billing';
    return 'settings' if $title =~ /\A(?:Settings|Dashboard Settings|Master Control|Provisioning Job|Admin Account|Governance|Federated Content Review|Contributors|Contributor Request|Contributor Blueprints|Service Plans|Contributor Sites|Realtime Service|Upgrade DesertCMS|Operations and Recovery)\b/;
    return 'editor' if $title =~ /\A(?:Editor|Templates|Sections|Post Comments|Media|Navigation|Redirects|Theme|Site Settings|Rebuild Complete)\b/;
    return '';
}

sub _contributor_primary_nav_active_key {
    my ($title) = @_;
    return 'home' if $title eq 'Home' || $title eq 'Analytics';
    return 'notifications' if $title eq 'Notifications';
    return 'home' if $title eq 'Dashboard Settings';
    return 'pages' if $title =~ /\APages\b/;
    return 'posts' if $title =~ /\APosts\b/;
    return 'media' if $title =~ /\AMedia\b/;
    return 'design' if $title =~ /\A(?:Site Settings|Site Basics|Design|Theme)\b/;
    return 'features' if _module_surface_title($title);
    return 'billing' if $title eq 'Billing';
    return 'account' if $title eq 'Admin Account' || $title eq 'Account';
    return 'help' if $title eq 'Help';
    return 'site_builder' if $title =~ /\A(?:Editor|Templates|Sections|Post Comments|Navigation|Redirects|Rebuild Complete)\b/;
    return '';
}

sub _module_surface_title {
    my ($title) = @_;
    return 0 unless defined $title && length $title;
    return $title =~ /\A(?:Features|Modules|Posts|Accounts|Live Streaming|Forums|Social|Notifications Module|Notifications Feature|Security Center Module|Security Center Feature|Shop|Shop \/ Catalog|Events|Directory|Bookings|Bookings \/ Appointments|Membership|Membership \/ Gated Content|Newsletter|Donations|Donations \/ Fundraising|Testimonials|Testimonials \/ Reviews|Map Module|Map Feature|Map \/ Locations Module|Map \/ Locations Feature|Gallery Module|Gallery Feature|Showcase Module|Showcase Feature|Forms Module|Forms Feature|Documentation Module|Documentation Feature|Docs \/ Resource Hub Module|Docs \/ Resource Hub Feature)\b/ ? 1 : 0;
}

sub _admin_brand_html {
    my ($settings) = @_;
    $settings ||= {};
    my $name = escape_html($settings->{site_name} || 'DesertCMS');
    my $logo = $settings->{site_logo_admin_path} || $settings->{site_logo_nav_path} || $settings->{site_logo_path} || '';
    if ($logo =~ m{\A/assets/site/logo(?:-admin|-nav)?\.png\z}) {
        my $src = escape_html($logo);
        return qq{<img class="admin-brand-logo" src="$src" alt="$name">};
    }
    return $name;
}

sub _admin_security_headers {
    my ($self) = @_;
    my $settings = eval { DesertCMS::Settings::all($self->{config}, $self->{db}) } || {};
    return security_headers(img_src => _map_tile_origins($settings));
}

sub _admin_css_cache_key {
    my ($settings) = @_;
    $settings ||= {};
    my @keys = qw(
        theme_preset theme_light_preset theme_dark_preset theme_default_mode
        theme_custom_name theme_custom_mode theme_custom_ink theme_custom_muted
        theme_custom_paper theme_custom_panel theme_custom_field theme_custom_line
        theme_custom_accent theme_custom_accent_dark theme_custom_support theme_custom_button_ink
        theme_heading_font theme_body_font theme_ui_font theme_heading_scale theme_body_scale
        theme_button_style theme_button_radius theme_card_style theme_card_radius
        theme_unsplash_enabled unsplash_access_key theme_background_effect theme_motion_effect theme_lighting_effect
        theme_box_transparency theme_outline_transparency theme_box_shape theme_gradient_style
        site_background_image_path site_content_width site_spacing_scale site_logo_size site_logo_fit
        site_logo_focal_x site_logo_focal_y site_logo_max_width_px site_logo_max_height_px
    );
    my $fingerprint = join "\0", map { $_ . '=' . ($settings->{$_} // '') } @keys;
    return '20260706a-' . substr(sha256_hexstr($fingerprint), 0, 12);
}

sub _map_tile_origins {
    my ($settings) = @_;
    my %origins;
    for my $url (
        $settings->{map_street_tile_url},
        $settings->{map_satellite_tile_url},
        'https://tile.openstreetmap.org/{z}/{x}/{y}.png',
        'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}',
    ) {
        next unless defined $url;
        if ($url =~ m{\A(https://[A-Za-z0-9.-]+(?::[0-9]+)?)/}i) {
            $origins{$1} = 1;
        }
    }
    return [ sort keys %origins ];
}

sub _admin_css {
    my ($self) = @_;
    my $settings = DesertCMS::Settings::all($self->{config}, $self->{db});
    my $css = DesertCMS::SiteTheme::css_vars($settings, config => $self->{config}) . <<'CSS';
:root { color-scheme: light; --danger: #a23a2f; --ok-ink: #0b525b; --ok-bg: #d9f2ef; --warn-ink: #75520d; --warn-bg: #fff0c2; --chart-1: var(--support); --chart-2: var(--accent); --chart-3: #6d5bd0; --chart-4: #2f855a; --chart-5: #b83280; --chart-6: #4a5568; --shadow: 0 10px 28px rgba(16, 32, 51, 0.08); --focus-ring: color-mix(in srgb, var(--accent) 28%, transparent); }
:root[data-theme="dark"] { color-scheme: dark; --danger: #ff9a86; --ok-ink: #071225; --ok-bg: var(--support); --warn-ink: #071225; --warn-bg: var(--accent); --chart-1: var(--support); --chart-2: var(--accent); --chart-3: #a994ff; --chart-4: #65d890; --chart-5: #ff8bc7; --chart-6: #bac7c2; --shadow: 0 10px 30px rgba(0, 0, 0, 0.24); --focus-ring: color-mix(in srgb, var(--accent) 32%, transparent); }
* { box-sizing: border-box; }
body { margin: 0; font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif; background: var(--paper); color: var(--ink); line-height: 1.45; }
.topbar { min-height: 64px; display: flex; align-items: center; justify-content: space-between; gap: 18px; padding: 12px 28px; border-bottom: 1px solid var(--line); background: var(--panel); position: relative; }
.brand { min-height: 36px; min-width: 0; display: inline-flex; align-items: center; color: var(--ink); font-weight: 700; text-decoration: none; overflow-wrap: anywhere; }
