.dashboard-alerts { display: grid; grid-template-columns: minmax(170px, 0.22fr) minmax(0, 1fr); gap: 14px; align-items: start; padding: 14px; border: 1px solid color-mix(in srgb, var(--warn-ink) 34%, var(--line)); border-radius: 8px; background: color-mix(in srgb, var(--warn-bg) 52%, var(--panel)); box-shadow: var(--shadow); }
.dashboard-alerts > div { display: grid; gap: 4px; min-width: 0; padding-right: 14px; border-right: 1px solid color-mix(in srgb, var(--warn-ink) 24%, var(--line)); }
