.dashboard-alerts li { min-width: 0; padding: 9px 10px; border: 1px solid color-mix(in srgb, var(--warn-ink) 24%, var(--line)); border-radius: 6px; background: var(--panel); color: var(--warn-ink); font-size: 12px; font-weight: 800; line-height: 1.35; overflow-wrap: anywhere; }
.metric-grid { display: grid; grid-template-columns: repeat(4, minmax(0, 1fr)); gap: 14px; align-items: stretch; }
.metric-card { position: relative; overflow: hidden; display: grid; grid-template-rows: min-content 1fr min-content; align-items: stretch; gap: 10px; min-width: 0; min-height: 132px; padding: 18px; border: 1px solid var(--line); border-radius: 8px; background: color-mix(in srgb, var(--panel) 92%, var(--field)); box-shadow: var(--shadow); }
.metric-card > * { min-width: 0; }
.metric-card span,
.metric-card strong,
.metric-card small { overflow-wrap: anywhere; }
.metric-card::before { content: ""; position: absolute; left: 0; top: 0; bottom: 0; width: 4px; background: var(--accent); }
.metric-card--ok::before { background: var(--ok-ink); }
.metric-card--warn { border-color: color-mix(in srgb, var(--warn-ink) 36%, var(--line)); background: color-mix(in srgb, var(--warn-bg) 34%, var(--panel)); }
.metric-card--warn::before { background: var(--warn-ink); }
.metric-card--neutral::before { background: var(--muted); }
.metric-card span { color: var(--muted); font-size: 12px; font-weight: 800; text-transform: uppercase; letter-spacing: 0.08em; }
.metric-card strong { align-self: end; font-size: 34px; line-height: 1; letter-spacing: 0; font-variant-numeric: tabular-nums; overflow-wrap: anywhere; }
.metric-card small { align-self: end; color: var(--muted); font-size: 13px; line-height: 1.35; overflow-wrap: anywhere; }
.metric-card--warn small { color: var(--warn-ink); font-weight: 800; }
.dashboard-main-grid { display: grid; gap: 18px; align-items: start; }
.dashboard-main-grid .panel { min-width: 0; }
.dashboard-content-grid { display: grid; grid-template-columns: minmax(480px, 1.12fr) minmax(360px, 0.88fr); gap: 18px; align-items: start; }
.dashboard-stack { min-width: 0; display: grid; gap: 18px; align-content: start; }
.dashboard-stack--primary { min-width: 0; }
.dashboard-stack--secondary { min-width: 0; }
.dashboard-card { display: grid; align-content: start; gap: 16px; min-width: 0; padding: 22px; overflow: hidden; }
.dashboard-card--compact { min-height: 200px; }
.dashboard-card--medium { min-height: 240px; }
.dashboard-card--large { min-height: 360px; }
.dashboard-card--full,
.dashboard-card--wide { width: 100%; }
.dashboard-card--tall { min-height: 340px; }
.panel-heading { display: flex; align-items: flex-start; justify-content: space-between; gap: 12px; }
.panel-heading h2 { margin: 0; font-size: 18px; letter-spacing: 0; }
.panel-heading p { margin: 4px 0 0; font-size: 13px; }
.compact-table { margin-top: 0; font-size: 13px; }
.compact-table td { overflow-wrap: anywhere; }
.dashboard-table-wrap { min-width: 0; overflow: auto; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
.dashboard-table { margin: 0; background: transparent; }
.dashboard-table th,
.dashboard-table td { background: transparent; }
.delivery-log-scroll { min-width: 0; max-height: 492px; overflow: auto; border: 1px solid var(--line); border-radius: 8px; background: var(--field); overscroll-behavior: contain; }
.delivery-log-table { margin: 0; border: 0; background: transparent; }
.delivery-log-table th,
.delivery-log-table td { background: transparent; }
.delivery-log-table thead th { position: sticky; top: 0; z-index: 1; background: var(--panel); box-shadow: 0 1px 0 var(--line); }
.admin-alert-panel { display: grid; grid-template-columns: minmax(220px, 0.9fr) minmax(0, 1.6fr); gap: 12px; align-items: start; margin: 0 0 14px; padding: 14px; border: 1px solid color-mix(in srgb, var(--warn-ink) 34%, var(--line)); border-radius: 8px; background: color-mix(in srgb, var(--warn-bg) 48%, var(--panel)); }
.admin-alert-panel > div { min-width: 0; display: grid; gap: 5px; }
.admin-alert-panel strong { color: var(--ink); line-height: 1.25; }
.admin-alert-panel p { margin: 0; color: var(--warn-ink); font-size: 13px; font-weight: 800; line-height: 1.4; }
.admin-alert-panel ul { min-width: 0; display: grid; gap: 8px; margin: 0; padding: 0; list-style: none; }
.admin-alert-panel li { min-width: 0; display: grid; grid-template-columns: auto minmax(0, 1fr); gap: 4px 8px; align-items: center; padding: 9px 10px; border: 1px solid color-mix(in srgb, var(--warn-ink) 22%, var(--line)); border-radius: 6px; background: var(--panel); }
.admin-alert-panel li small,
.admin-alert-panel li em { grid-column: 2; min-width: 0; color: var(--muted); font-size: 12px; font-style: normal; font-weight: 700; line-height: 1.35; overflow-wrap: anywhere; }
.admin-alert-panel li em { color: var(--warn-ink); }
.onboarding-flow { display: grid; gap: 12px; margin: 18px 0 20px; padding: 16px; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
.onboarding-flow-heading { display: flex; align-items: flex-start; justify-content: space-between; gap: 14px; }
.onboarding-flow-heading h2 { margin: 0 0 4px; font-size: 18px; letter-spacing: 0; }
.onboarding-flow-heading p { margin: 0; font-size: 13px; line-height: 1.4; }
.onboarding-stage-grid { display: grid; grid-template-columns: repeat(5, minmax(0, 1fr)); gap: 8px; }
.onboarding-stage-grid--billing { grid-template-columns: repeat(3, minmax(0, 1fr)); }
.onboarding-stage-card { min-width: 0; display: grid; gap: 7px; align-content: start; min-height: 118px; padding: 12px; border: 1px solid var(--line); border-radius: 8px; background: var(--panel); }
.onboarding-stage-card span,
.onboarding-progress-step span { color: var(--muted); font-size: 11px; font-weight: 900; text-transform: uppercase; letter-spacing: 0.08em; }
.onboarding-stage-card strong { min-width: 0; overflow-wrap: anywhere; }
.onboarding-stage-card small { color: var(--muted); font-size: 12px; font-weight: 700; line-height: 1.35; }
.onboarding-row-status { display: grid; gap: 5px; align-items: start; justify-items: start; min-width: 0; }
.onboarding-row-status small { max-width: 30ch; color: var(--muted); font-size: 12px; font-weight: 700; line-height: 1.35; }
.onboarding-email-warning { padding: 6px 8px; border: 1px solid color-mix(in srgb, var(--warn-ink) 26%, var(--line)); border-radius: 6px; background: color-mix(in srgb, var(--warn-bg) 42%, var(--panel)); color: var(--warn-ink) !important; }
.onboarding-progress-panel { gap: 16px; }
.onboarding-progress { display: grid; grid-template-columns: repeat(6, minmax(0, 1fr)); gap: 8px; margin: 0; padding: 0; list-style: none; counter-reset: onboarding-step; }
.onboarding-progress-step { position: relative; min-width: 0; display: grid; gap: 7px; align-content: start; min-height: 124px; padding: 12px; border: 1px solid var(--line); border-radius: 8px; background: var(--field); counter-increment: onboarding-step; }
.onboarding-progress-step::before { content: counter(onboarding-step); width: 26px; height: 26px; display: inline-grid; place-items: center; border-radius: 999px; background: var(--panel); color: var(--muted); font-size: 12px; font-weight: 900; }
.onboarding-progress-step--done { border-color: color-mix(in srgb, var(--ok-bg) 72%, var(--line)); background: color-mix(in srgb, var(--ok-bg) 30%, var(--field)); }
.onboarding-progress-step--done::before { background: var(--ok-bg); color: var(--ok-ink); }
.onboarding-progress-step--active { border-color: color-mix(in srgb, var(--accent) 42%, var(--line)); background: color-mix(in srgb, var(--support) 18%, var(--field)); }
.onboarding-progress-step--active::before { background: var(--accent); color: var(--button-ink); }
.onboarding-progress-step--warn { border-color: color-mix(in srgb, var(--warn-ink) 34%, var(--line)); background: color-mix(in srgb, var(--warn-bg) 40%, var(--field)); }
.onboarding-progress-step--warn::before { background: var(--warn-bg); color: var(--warn-ink); }
.onboarding-progress-step p { margin: 0; color: var(--ink); font-size: 12px; font-weight: 700; line-height: 1.4; overflow-wrap: anywhere; }
.onboarding-email-list { display: grid; gap: 8px; margin: 0; padding: 0; list-style: none; }
.onboarding-email-list li { min-width: 0; display: grid; grid-template-columns: auto minmax(0, 1fr) auto; gap: 6px 10px; align-items: center; padding: 10px; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
.onboarding-email-list li small,
.onboarding-email-list li em { min-width: 0; color: var(--muted); font-size: 12px; font-style: normal; font-weight: 700; line-height: 1.35; overflow-wrap: anywhere; }
.onboarding-email-list li em { grid-column: 2 / -1; }
.dashboard-empty { min-height: 140px; display: grid; place-items: center; align-content: center; gap: 7px; padding: 20px; border: 1px dashed color-mix(in srgb, var(--muted) 45%, var(--line)); border-radius: 8px; background: color-mix(in srgb, var(--field) 80%, var(--panel)); text-align: center; }
.dashboard-empty-mark { width: 34px; height: 34px; border: 1px solid var(--line); border-radius: 999px; background: linear-gradient(180deg, var(--panel), var(--field)); position: relative; }
.dashboard-empty-mark::before,
.dashboard-empty-mark::after { content: ""; position: absolute; left: 9px; right: 9px; border-radius: 999px; background: var(--muted); opacity: 0.65; }
.dashboard-empty-mark::before { top: 11px; height: 3px; }
.dashboard-empty-mark::after { top: 19px; height: 3px; }
.dashboard-empty strong { color: var(--ink); font-size: 15px; }
.dashboard-empty small { max-width: 36ch; color: var(--muted); line-height: 1.4; }
.health-list { display: grid; grid-template-columns: repeat(3, minmax(0, 1fr)); gap: 12px; margin: 18px 0 0; }
.health-list--compact { grid-template-columns: repeat(2, minmax(0, 1fr)); margin: 0; }
.health-list div { min-width: 0; display: grid; gap: 5px; min-height: 82px; padding: 14px; border: 1px solid var(--line); border-radius: 6px; background: var(--field); }
.health-list--compact div { min-height: 68px; padding: 12px; }
.health-list dt { min-width: 0; color: var(--muted); font-size: 12px; font-weight: 800; text-transform: uppercase; letter-spacing: 0.08em; overflow-wrap: anywhere; }
.health-list dd { min-width: 0; margin: 0; font-weight: 700; overflow-wrap: anywhere; }
.health-list dd > * { min-width: 0; }
.status-pill { box-sizing: border-box; max-width: 100%; min-width: 0; display: inline-flex; align-items: center; justify-content: center; min-height: 26px; border-radius: 999px; padding: 4px 10px; font-size: 12px; font-weight: 800; line-height: 1.2; text-align: center; white-space: normal; overflow-wrap: anywhere; word-break: break-word; }
.status-pill.ok { color: var(--ok-ink); background: var(--ok-bg); }
.status-pill.warn { color: var(--warn-ink); background: var(--warn-bg); }
.status-pill.danger { color: var(--danger); background: color-mix(in srgb, var(--danger) 10%, var(--field)); border: 1px solid color-mix(in srgb, var(--danger) 42%, var(--line)); }
.status-pill--neutral { color: var(--muted); background: var(--field); border: 1px solid var(--line); }
.master-control-overview { display: grid; grid-template-columns: minmax(220px, 0.85fr) minmax(0, 2.15fr); gap: 12px; align-items: stretch; margin: 18px 0 14px; }
.master-control-score { min-width: 0; display: grid; gap: 8px; align-content: center; padding: 16px; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
.master-control-score--healthy { border-color: color-mix(in srgb, var(--ok-bg) 70%, var(--line)); background: color-mix(in srgb, var(--ok-bg) 36%, var(--field)); }
.master-control-score--attention,
.master-control-score--failed { border-color: color-mix(in srgb, var(--warn-bg) 70%, var(--line)); background: color-mix(in srgb, var(--warn-bg) 34%, var(--field)); }
.master-control-score span,
.master-control-metrics dt,
.master-status-heading p,
.master-maintenance-strip p { color: var(--muted); font-size: 12px; font-weight: 800; line-height: 1.35; text-transform: uppercase; letter-spacing: 0.08em; }
.master-control-score strong { font-size: clamp(24px, 4vw, 38px); line-height: 1; color: var(--ink); }
.master-control-score small,
.master-control-metrics small { color: var(--muted); font-size: 12px; line-height: 1.35; }
.master-control-metrics { display: grid; grid-template-columns: repeat(4, minmax(0, 1fr)); gap: 8px; margin: 0; }
.master-control-metrics div { min-width: 0; display: grid; gap: 6px; align-content: start; min-height: 74px; padding: 12px; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
.master-control-metrics dd { min-width: 0; display: grid; gap: 5px; margin: 0; font-weight: 800; overflow-wrap: anywhere; }
.master-control-metrics dd strong { font-size: 22px; line-height: 1.05; }
.master-maintenance-strip { display: grid; grid-template-columns: minmax(0, 1fr) auto auto; gap: 10px; align-items: center; margin: 0 0 16px; padding: 12px; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
.master-maintenance-strip > * { min-width: 0; }
.master-maintenance-strip strong { display: block; margin-bottom: 4px; color: var(--ink); overflow-wrap: anywhere; }
.master-maintenance-strip p { margin: 0; text-transform: none; letter-spacing: 0; font-weight: 700; }
.master-maintenance-strip form { margin: 0; }
.master-status-group { margin-top: 14px; }
.master-status-heading { display: flex; justify-content: space-between; gap: 12px; align-items: start; margin-bottom: 12px; }
.master-status-heading > div { min-width: 0; }
.master-status-heading h2 { margin-bottom: 4px; overflow-wrap: anywhere; }
.master-status-heading p { margin: 0; text-transform: none; letter-spacing: 0; font-weight: 700; overflow-wrap: anywhere; }
.fleet-table--summary th,
.fleet-table--summary td { vertical-align: top; }
.fleet-site-identity,
.fleet-cell-stack { display: grid; gap: 7px; min-width: 0; }
.fleet-site-identity > strong { line-height: 1.25; }
.fleet-site-identity a,
.fleet-cell-stack a { overflow-wrap: anywhere; word-break: break-word; }
.fleet-inline-actions { display: flex; flex-wrap: wrap; gap: 6px; margin-top: 8px; }
.fleet-inline-actions .inline-form { margin: 0; }
.button-link--compact { min-height: 32px; padding: 5px 10px; font-size: 12px; }
.button-link--warn { border-color: var(--warn-ink); color: var(--warn-ink); }
.fleet-provider-list { margin-top: 0; }
.fleet-provider-list dd { display: grid; gap: 6px; }
.fleet-provider-list small,
.fleet-status-stack small { display: block; color: var(--muted); font-size: 12px; line-height: 1.35; overflow-wrap: anywhere; }
.provider-readiness-detail-grid { display: grid; grid-template-columns: repeat(2, minmax(0, 1fr)); gap: 14px; margin-top: 14px; }
.provider-readiness-detail { min-width: 0; display: grid; gap: 12px; padding-top: 14px; border-top: 1px solid var(--line); }
.provider-readiness-heading { min-width: 0; display: flex; justify-content: space-between; align-items: flex-start; gap: 12px; flex-wrap: wrap; }
.provider-readiness-heading > div { min-width: 0; }
.provider-readiness-heading h3 { min-width: 0; margin: 0 0 4px; font-size: 15px; letter-spacing: 0; overflow-wrap: anywhere; }
.provider-readiness-heading p { margin: 0; font-size: 12px; line-height: 1.4; }
.provider-readiness-actions { min-width: 0; display: flex; justify-content: flex-end; gap: 8px; flex-wrap: wrap; }
.provider-check-list { margin: 0; }
.provider-endpoint-grid { min-width: 0; display: grid; gap: 10px; }
.provider-endpoint-row { min-width: 0; display: grid; gap: 5px; padding: 12px; border: 1px solid var(--line); border-radius: 6px; background: var(--field); }
.provider-endpoint-row strong { min-width: 0; font-size: 13px; line-height: 1.25; overflow-wrap: anywhere; }
.provider-endpoint-row code { min-width: 0; max-width: 100%; white-space: normal; overflow-wrap: anywhere; word-break: break-word; }
.provider-endpoint-row small { min-width: 0; color: var(--muted); font-size: 12px; line-height: 1.35; overflow-wrap: anywhere; }
.fleet-table td { vertical-align: top; }
.fleet-table td > small { display: block; margin-top: 7px; color: var(--muted); font-size: 12px; line-height: 1.35; }
.fleet-mini-list { display: grid; gap: 6px; min-width: 130px; margin: 0; }
.fleet-mini-list div { display: flex; align-items: center; justify-content: space-between; gap: 8px; }
.fleet-mini-list dt { color: var(--muted); font-size: 11px; font-weight: 800; text-transform: uppercase; letter-spacing: 0.08em; }
.fleet-mini-list dd { margin: 0; }
.fleet-status-stack { display: grid; gap: 8px; min-width: 150px; }
.fleet-status-stack div { display: grid; gap: 4px; }
.fleet-status-stack span:first-child { color: var(--muted); font-size: 11px; font-weight: 800; text-transform: uppercase; letter-spacing: 0.08em; }
.template-preview-list { display: grid; grid-template-columns: repeat(auto-fit, minmax(260px, 1fr)); gap: 12px; }
.template-preview-card { display: grid; gap: 8px; padding: 14px; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
.template-preview-card span { color: var(--muted); font-size: 12px; font-weight: 800; text-transform: uppercase; letter-spacing: 0.08em; }
.template-preview-card strong { font-size: 15px; line-height: 1.35; }
.template-preview-card pre { max-height: 180px; overflow: auto; margin: 0; white-space: pre-wrap; overflow-wrap: anywhere; font: 12px/1.45 ui-monospace, SFMono-Regular, Consolas, monospace; color: var(--muted); }
.fleet-alert-list { display: grid; gap: 6px; min-width: 180px; margin: 0; padding: 0; list-style: none; }
.fleet-alert-list li { padding: 7px 9px; border: 1px solid color-mix(in srgb, var(--warn-bg) 70%, var(--line)); border-radius: 6px; background: color-mix(in srgb, var(--warn-bg) 42%, var(--panel)); color: var(--warn-ink); font-size: 12px; font-weight: 800; line-height: 1.35; }
.bar-chart { display: grid; gap: 12px; margin-top: 16px; padding: 14px; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
.bar-row { display: grid; grid-template-columns: minmax(92px, 1fr) minmax(120px, 2fr) 42px; align-items: center; gap: 10px; font-size: 13px; }
.bar-row span { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; color: var(--muted); }
.bar-row strong { text-align: right; }
.bar-track { height: 10px; border-radius: 999px; background: var(--panel); border: 1px solid var(--line); overflow: hidden; }
.bar-track i { display: block; height: 100%; min-width: 2px; border-radius: inherit; background: linear-gradient(90deg, var(--support), var(--accent)); }
.trend-chart { display: grid; grid-template-columns: repeat(7, minmax(0, 1fr)); gap: 12px; min-height: 220px; padding: 16px; align-items: end; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
.trend-day { min-width: 0; display: grid; grid-template-rows: 24px 150px 20px 18px; gap: 6px; align-items: end; text-align: center; color: var(--muted); font-size: 12px; }
.trend-day strong { color: var(--ink); font-size: 14px; }
.trend-bar { height: 150px; display: flex; align-items: flex-end; border: 1px solid var(--line); border-radius: 8px; background: var(--panel); overflow: hidden; }
.trend-bar i { display: block; width: 100%; height: var(--bar-height); min-height: 2px; border-radius: 7px 7px 3px 3px; background: linear-gradient(180deg, var(--support), var(--accent)); box-shadow: inset 0 -10px 18px rgba(0, 0, 0, 0.08); transition: height 160ms ease; }
.trend-day span { font-weight: 800; color: var(--ink); }
.trend-day small { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
.rank-chart { display: grid; gap: 10px; padding: 14px; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
.rank-row { display: grid; grid-template-columns: minmax(0, 1fr) 92px 42px; gap: 10px; align-items: center; min-height: 42px; font-size: 13px; }
.rank-row div { min-width: 0; display: grid; gap: 3px; }
.rank-row span { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; font-weight: 800; color: var(--ink); }
.rank-row small { color: var(--muted); overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
.rank-track { display: block; height: 12px; border-radius: 999px; background: var(--panel); border: 1px solid var(--line); overflow: hidden; }
.rank-track b { display: block; height: 100%; min-width: 2px; border-radius: inherit; background: linear-gradient(90deg, var(--support), var(--accent)); }
.rank-row strong { text-align: right; }
.donut-summary { display: grid; grid-template-columns: 150px minmax(0, 1fr); gap: 18px; align-items: center; padding: 14px; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
.donut-chart { width: 150px; aspect-ratio: 1; border-radius: 50%; display: grid; place-items: center; position: relative; box-shadow: inset 0 0 0 1px var(--line); }
.donut-chart::after { content: ""; position: absolute; inset: 28px; border-radius: 50%; background: var(--panel); border: 1px solid var(--line); }
.donut-chart span,
.donut-chart small { position: relative; z-index: 1; }
.donut-chart span { align-self: end; color: var(--ink); font-size: 26px; font-weight: 900; line-height: 1; }
.donut-chart small { align-self: start; color: var(--muted); font-size: 12px; font-weight: 800; }
.donut-legend { display: grid; gap: 9px; margin: 0; padding: 0; list-style: none; }
.donut-legend li { display: grid; grid-template-columns: 12px minmax(0, 1fr); column-gap: 8px; row-gap: 2px; align-items: center; font-size: 13px; }
.donut-legend li span { width: 12px; height: 12px; border-radius: 3px; background: var(--dot-color); }
.donut-legend li strong { min-width: 0; overflow-wrap: anywhere; white-space: normal; }
.donut-legend li em { grid-column: 2; color: var(--muted); font-style: normal; font-size: 12px; }
.coverage-meter { display: grid; gap: 7px; padding: 12px; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
.coverage-meter div { display: flex; align-items: center; justify-content: space-between; gap: 12px; }
.coverage-meter span { color: var(--muted); font-size: 12px; font-weight: 800; text-transform: uppercase; letter-spacing: 0.08em; }
.coverage-meter strong { font-size: 16px; }
.coverage-meter i { height: 10px; border-radius: 999px; overflow: hidden; background: var(--panel); border: 1px solid var(--line); }
.coverage-meter b { display: block; height: 100%; border-radius: inherit; background: linear-gradient(90deg, var(--support), var(--accent)); }
.coverage-meter small { color: var(--muted); font-size: 12px; }
.usage-meter { display: grid; gap: 6px; min-width: 130px; }
.usage-meter div { display: flex; align-items: center; justify-content: space-between; gap: 10px; }
.usage-meter span { color: var(--muted); font-size: 12px; font-weight: 700; }
.usage-meter strong { font-size: 12px; }
.usage-meter i { display: block; height: 8px; border-radius: 999px; overflow: hidden; background: var(--field); border: 1px solid var(--line); }
.usage-meter b { display: block; height: 100%; min-width: 2px; border-radius: inherit; background: var(--support); }
.usage-meter.warn b { background: var(--danger); }
.billing-usage-stack { display: grid; gap: 14px; }
.billing-usage-grid { display: grid; grid-template-columns: repeat(3, minmax(0, 1fr)); gap: 14px; }
.billing-media-breakdown { display: grid; grid-template-columns: repeat(auto-fit, minmax(170px, 1fr)); gap: 10px; margin: 0; }
.billing-media-breakdown div { min-width: 0; display: grid; gap: 6px; padding: 12px; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
.billing-media-breakdown dt { color: var(--muted); font-size: 11px; font-weight: 800; text-transform: uppercase; letter-spacing: 0.08em; }
.billing-media-breakdown dd { min-width: 0; display: grid; gap: 4px; margin: 0; }
.billing-media-breakdown dd span { color: var(--muted); font-size: 12px; font-weight: 900; }
.billing-media-breakdown dd strong { color: var(--ink); font-size: 20px; line-height: 1.1; overflow-wrap: anywhere; }
.billing-media-breakdown dd small { color: var(--muted); font-size: 12px; line-height: 1.35; overflow-wrap: anywhere; }
.billing-plan-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(min(100%, 270px), 1fr)); gap: 14px; align-items: stretch; }
.billing-plan-card { min-width: 0; display: grid; grid-template-rows: min-content min-content 1fr min-content; gap: 14px; min-height: 420px; padding: 16px; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
.billing-plan-card--current { border-color: color-mix(in srgb, var(--accent) 55%, var(--line)); background: color-mix(in srgb, var(--support) 12%, var(--field)); box-shadow: 0 12px 28px rgba(16, 32, 51, 0.10); }
.billing-plan-card--blocked { border-style: dashed; }
.billing-plan-card-head { min-width: 0; display: grid; gap: 10px; align-content: start; }
.billing-plan-card-head h3 { margin: 0 0 6px; font-size: 20px; line-height: 1.15; letter-spacing: 0; overflow-wrap: anywhere; }
.billing-plan-card-head p { margin: 0; color: var(--muted); line-height: 1.45; }
.billing-plan-badges { display: flex; flex-wrap: wrap; gap: 6px; align-items: center; }
.billing-plan-price { min-width: 0; display: flex; align-items: flex-end; gap: 8px; flex-wrap: wrap; padding: 12px 0; border-top: 1px solid var(--line); border-bottom: 1px solid var(--line); }
.billing-plan-price strong { color: var(--ink); font-size: 30px; line-height: 1; letter-spacing: 0; }
.billing-plan-price small { min-width: 0; color: var(--muted); font-size: 12px; font-weight: 800; line-height: 1.25; text-transform: uppercase; letter-spacing: 0.08em; overflow-wrap: anywhere; }
.billing-plan-features { display: grid; gap: 0; margin: 0; padding: 0; list-style: none; border: 1px solid var(--line); border-radius: 8px; overflow: hidden; background: var(--panel); }
.billing-plan-features li { min-width: 0; display: grid; grid-template-columns: minmax(0, 1fr) auto; gap: 10px; align-items: center; padding: 10px 12px; border-bottom: 1px solid var(--line); }
.billing-plan-features li:last-child { border-bottom: 0; }
.billing-plan-features span { min-width: 0; color: var(--muted); font-size: 12px; font-weight: 800; text-transform: uppercase; letter-spacing: 0.08em; overflow-wrap: anywhere; }
.billing-plan-features strong { min-width: 0; color: var(--ink); font-size: 13px; line-height: 1.25; text-align: right; overflow-wrap: anywhere; }
.billing-plan-action { align-self: end; display: grid; gap: 8px; min-width: 0; }
.billing-plan-action .billing-plan-form { margin: 0; }
.billing-plan-action .button-link { width: 100%; }
.billing-plan-action small { color: var(--muted); font-size: 12px; line-height: 1.35; overflow-wrap: anywhere; }
.mini-table th,
.mini-table td { padding: 8px 10px; }
.editor-workspace { display: grid; gap: 18px; }
.editor-nav { min-width: 0; display: flex; align-items: center; gap: 8px; flex-wrap: wrap; padding: 8px; border: 1px solid var(--line); border-radius: 8px; background: var(--panel); box-shadow: var(--shadow); }
.editor-nav a { min-width: 0; max-width: 100%; display: inline-flex; align-items: center; justify-content: center; min-height: 34px; border-radius: 6px; padding: 7px 12px; color: var(--muted); text-align: center; text-decoration: none; font-size: 14px; font-weight: 800; line-height: 1.2; white-space: normal; overflow-wrap: anywhere; }
.editor-nav a:hover,
.editor-nav a.active { background: var(--field); color: var(--accent); }
.service-plan-feature-groups { display: grid; gap: 14px; }
.service-plan-feature-group { min-width: 0; display: grid; gap: 12px; padding: 14px; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
.service-plan-feature-group-head { min-width: 0; display: grid; gap: 4px; }
.service-plan-feature-group-head h3 { min-width: 0; margin: 0; font-size: 16px; letter-spacing: 0; overflow-wrap: anywhere; }
.service-plan-feature-group-head p { min-width: 0; margin: 0; color: var(--muted); line-height: 1.4; overflow-wrap: anywhere; }
.service-plan-feature-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(min(100%, 240px), 1fr)); gap: 10px; }
.service-plan-feature-option { align-items: start; padding: 12px; border: 1px solid var(--line); border-radius: 8px; background: var(--panel); }
.service-plan-feature-option small { display: block; min-width: 0; margin-top: 4px; color: var(--muted); font-size: 12px; font-weight: 700; line-height: 1.35; overflow-wrap: anywhere; }
.feature-checklist { display: grid; grid-template-columns: repeat(auto-fit, minmax(min(100%, 220px), 1fr)); gap: 10px; }
.feature-checklist .checkbox-field { align-items: start; padding: 12px; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
.editor-hero { display: flex; align-items: flex-start; justify-content: space-between; gap: 24px; }
.workflow-grid { min-width: 0; display: grid; grid-template-columns: repeat(auto-fit, minmax(min(100%, 230px), 1fr)); gap: 14px; }
.workflow-card { min-width: 0; display: grid; gap: 8px; min-height: 190px; padding: 18px; border: 1px solid var(--line); border-radius: 8px; background: var(--panel); color: var(--ink); text-decoration: none; box-shadow: var(--shadow); }
.workflow-card:hover { border-color: var(--accent); }
.workflow-card span,
.template-choice span { color: var(--accent); font-size: 12px; font-weight: 800; text-transform: uppercase; letter-spacing: 0.08em; }
.workflow-card span,
.workflow-card strong,
.workflow-card p,
.workflow-card small { min-width: 0; overflow-wrap: anywhere; }
.workflow-card strong { font-size: 20px; line-height: 1.2; }
.workflow-card p { margin: 0; }
.workflow-card small { align-self: end; color: var(--muted); font-weight: 800; }
.contributor-topbar { min-height: 70px; align-items: center; }
.contributor-topbar .brand { flex: 0 0 auto; max-width: min(28vw, 280px); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; overflow-wrap: normal; }
.contributor-topbar .brand::after { content: "Site Builder"; margin-left: 10px; padding: 3px 7px; border: 1px solid var(--line); border-radius: 999px; color: var(--muted); background: var(--field); font-size: 11px; font-weight: 900; text-transform: uppercase; letter-spacing: 0.08em; }
.contributor-topbar-actions { flex: 1 1 auto; min-width: 0; }
.contributor-product-nav { flex: 1 1 auto; min-width: 0; max-width: 980px; display: flex; align-items: center; justify-content: flex-end; gap: 6px; flex-wrap: wrap; padding: 4px; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
.contributor-product-nav a { background: var(--panel); }
.contributor-product-nav a.active,
.contributor-product-nav a[aria-current="page"] { box-shadow: inset 0 0 0 1px color-mix(in srgb, var(--accent) 22%, transparent); }
.contributor-help-surface { display: grid; gap: 18px; margin-top: 22px; }
.contributor-help-surface .settings-summary-strip { grid-template-columns: repeat(auto-fit, minmax(min(100%, 220px), 1fr)); margin: 0; }
.contributor-help-surface .workflow-grid { margin: 0; }
.contributor-account-panel .contributor-account-form { margin-top: 22px; }
.contributor-quick-grid { grid-template-columns: repeat(auto-fit, minmax(min(100%, 190px), 1fr)); }
.contributor-feature-list { display: grid; gap: 8px; }
.contributor-feature-list article { min-width: 0; display: grid; grid-template-columns: minmax(0, 1fr) minmax(0, auto); gap: 5px 10px; align-items: center; padding: 10px 12px; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
.contributor-feature-list strong { min-width: 0; overflow-wrap: anywhere; }
.contributor-feature-list small { grid-column: 1 / -1; color: var(--muted); font-size: 12px; font-weight: 700; overflow-wrap: anywhere; }
.contributor-suggestion-list { display: grid; gap: 8px; margin: 0; padding: 0; list-style: none; }
.contributor-suggestion-list li { min-width: 0; display: grid; grid-template-columns: auto minmax(0, 1fr) auto; gap: 10px; align-items: center; padding: 10px 12px; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
.contributor-suggestion-list span { display: inline-flex; justify-content: center; min-width: 62px; padding: 4px 8px; border-radius: 999px; color: var(--warn-ink); background: var(--warn-bg); font-size: 11px; font-weight: 900; text-transform: uppercase; letter-spacing: 0.08em; }
.contributor-suggestion-list div { min-width: 0; display: grid; gap: 3px; }
.contributor-suggestion-list strong { min-width: 0; font-size: 13px; line-height: 1.3; overflow-wrap: anywhere; }
.contributor-suggestion-list small { color: var(--muted); font-size: 12px; line-height: 1.35; overflow-wrap: anywhere; }
.contributor-suggestion-list .button-link { white-space: normal; }
.contributor-checklist { display: grid; gap: 8px; margin: 0; padding: 0; list-style: none; }
.contributor-checklist li { min-width: 0; display: grid; grid-template-columns: auto minmax(0, 1fr); gap: 10px; align-items: center; padding: 10px 12px; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
.contributor-checklist span { min-width: 58px; justify-content: center; display: inline-flex; padding: 4px 8px; border-radius: 999px; color: var(--muted); background: var(--panel); border: 1px solid var(--line); font-size: 11px; font-weight: 900; text-transform: uppercase; letter-spacing: 0.08em; }
.contributor-checklist .is-done span { color: var(--ok-ink); background: var(--ok-bg); border-color: transparent; }
.contributor-checklist strong { min-width: 0; font-size: 13px; line-height: 1.3; overflow-wrap: anywhere; }
.composer { display: grid; gap: 18px; }
.composer-topbar { display: flex; align-items: flex-start; justify-content: space-between; gap: 24px; padding: 18px 0 8px; border-bottom: 1px solid var(--line); }
.composer-form { display: grid; grid-template-columns: minmax(0, 1fr) 320px; gap: 24px; align-items: start; }
.template-picker { display: grid; gap: 14px; padding: 18px 0 8px; border-bottom: 1px solid var(--line); }
.template-picker h2 { margin: 0; font-size: 18px; letter-spacing: 0; }
.template-choice-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(210px, 1fr)); gap: 12px; }
.template-choice { display: grid; gap: 6px; min-height: 126px; padding: 14px; border: 1px solid var(--line); border-radius: 8px; background: var(--panel); color: var(--ink); text-decoration: none; }
.template-choice:hover,
.template-choice.active { border-color: var(--accent); box-shadow: 0 10px 26px rgba(16, 32, 51, 0.08); }
.template-choice strong { font-size: 16px; line-height: 1.25; }
.template-choice small { color: var(--muted); line-height: 1.4; }
.writing-canvas { min-width: 0; display: grid; gap: 18px; background: var(--panel); border: 1px solid var(--line); border-radius: 8px; padding: 28px; box-shadow: var(--shadow); }
.title-field span { color: var(--muted); }
.title-field input { min-height: 64px; padding: 0; border: 0; border-bottom: 1px solid var(--line); border-radius: 0; font-size: 42px; line-height: 1.1; font-weight: 800; background: transparent; }
.title-field input:focus { outline: 0; border-color: var(--accent); }
.editor-inspector { position: sticky; top: 20px; display: grid; gap: 16px; }
.post-settings-drawer { align-self: start; }
.inspector-panel { display: grid; gap: 14px; background: var(--panel); border: 1px solid var(--line); border-radius: 8px; padding: 18px; }
.inspector-panel h2 { margin: 0; font-size: 15px; line-height: 1.2; letter-spacing: 0; }
.commerce-model-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(210px, 1fr)); gap: 10px; }
.commerce-model-option { display: grid; grid-template-columns: 18px minmax(0, 1fr); align-items: start; gap: 10px; min-height: 92px; padding: 12px; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
.commerce-model-option input { margin-top: 3px; }
.commerce-model-option span { min-width: 0; display: grid; gap: 5px; }
.commerce-model-option strong { font-size: 14px; line-height: 1.25; }
.commerce-model-option small { color: var(--muted); font-size: 12px; line-height: 1.35; }
.publish-panel { border-color: rgba(11, 107, 87, 0.35); }
.meta-list { display: grid; gap: 10px; }
.meta-list div { display: grid; gap: 3px; padding-bottom: 10px; border-bottom: 1px solid var(--line); }
.meta-list div:last-child { border-bottom: 0; padding-bottom: 0; }
.meta-list span { color: var(--muted); font-size: 12px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.08em; }
.meta-list strong { font-size: 14px; line-height: 1.35; }
.meta-list a { color: var(--accent); overflow-wrap: anywhere; }
.search-preview { display: grid; gap: 5px; padding: 12px; border: 1px solid var(--line); border-radius: 6px; background: var(--field); }
.search-preview span { color: var(--muted); font-size: 12px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.08em; }
.search-preview strong { color: var(--support); font-size: 16px; line-height: 1.3; }
.search-preview p { margin: 0; color: var(--muted); font-size: 13px; line-height: 1.4; }
.search-health { margin: 14px 0 18px; }
.search-health a { color: var(--support); overflow-wrap: anywhere; }
.layout-control-grid { display: grid; grid-template-columns: repeat(2, minmax(0, 1fr)); gap: 14px; }
.layout-control-grid label { min-width: 0; }
.layout-control-grid + .settings-subsection { margin-top: 4px; }
.form-action-card { display: grid; align-content: end; gap: 8px; min-width: 0; }
.form-action-card span { display: block; margin: 0 0 2px; font-size: 14px; color: var(--muted); }
.font-package-panel { display: grid; gap: 14px; margin-top: 14px; padding: 16px; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
.font-package-panel h4 { margin: 0; font-size: 15px; letter-spacing: 0; }
.font-package-health { margin: 0; }
.font-package-table code { overflow-wrap: anywhere; white-space: normal; }
.search-engine-grid { display: grid; grid-template-columns: repeat(2, minmax(0, 1fr)); gap: 16px; margin-top: 18px; }
.search-engine-card { display: grid; align-content: start; gap: 12px; padding: 16px; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
.search-engine-card h3 { margin: 0; font-size: 16px; letter-spacing: 0; }
.connection-status { min-width: 0; display: grid; gap: 5px; min-height: 54px; padding: 10px; border: 1px solid var(--line); border-radius: 6px; background: var(--panel); overflow-wrap: anywhere; }
.connection-status strong,
.connection-status small { min-width: 0; line-height: 1.35; overflow-wrap: anywhere; }
.connection-status small { color: var(--muted); }
h1 { margin: 0 0 14px; font-size: 30px; line-height: 1.15; letter-spacing: 0; }
p { line-height: 1.55; color: var(--muted); }
.eyebrow { margin: 0 0 8px; text-transform: uppercase; letter-spacing: 0.08em; font-size: 12px; color: var(--accent); font-weight: 700; }
.muted { color: var(--muted); }
label { min-width: 0; }
label span { min-width: 0; display: block; margin: 0 0 6px; font-size: 14px; color: var(--muted); overflow-wrap: anywhere; }
input, select, textarea { width: 100%; min-width: 0; min-height: 44px; border: 1px solid var(--line); border-radius: 6px; padding: 10px 12px; font: inherit; background: var(--field); color: var(--ink); }
input:focus-visible, select:focus-visible, textarea:focus-visible { border-color: var(--accent); outline: 3px solid var(--focus-ring); outline-offset: 0; }
input[type="checkbox"] { width: 18px; min-height: 18px; accent-color: var(--accent); }
textarea { resize: vertical; line-height: 1.45; }
.mono-field { font-family: ui-monospace, SFMono-Regular, Consolas, "Liberation Mono", monospace; font-size: 13px; line-height: 1.55; }
button { max-width: 100%; min-width: 0; min-height: 42px; border: 0; border-radius: 6px; padding: 7px 16px; background: var(--accent); color: var(--button-ink); font: inherit; font-weight: 700; line-height: 1.2; text-align: center; white-space: normal; overflow-wrap: anywhere; cursor: pointer; transition: background 140ms ease, border-color 140ms ease, color 140ms ease, box-shadow 140ms ease; }
button:hover { background: var(--accent-dark); }
button:focus-visible, .button-link:focus-visible, .icon-link:focus-visible { outline: 3px solid var(--focus-ring); outline-offset: 2px; }
button.small { min-height: 32px; padding: 0 10px; font-size: 13px; }
button.secondary { background: transparent; color: var(--accent); border: 1px solid var(--accent); }
button.secondary:hover { background: color-mix(in srgb, var(--accent) 9%, var(--panel)); color: var(--accent); }
button.danger { background: transparent; color: var(--danger); border: 1px solid var(--danger); }
button.danger:hover { background: var(--danger); color: var(--paper); }
button:disabled,
button[aria-disabled="true"],
.button-link[aria-disabled="true"] { opacity: 0.64; cursor: not-allowed; }
button:disabled:hover,
button[aria-disabled="true"]:hover { background: var(--accent); }
button.secondary:disabled:hover,
button.secondary[aria-disabled="true"]:hover { background: transparent; color: var(--accent); }
button.danger:disabled:hover,
button.danger[aria-disabled="true"]:hover { background: transparent; color: var(--danger); }
button.is-loading,
.button-link.is-loading { display: inline-flex; align-items: center; justify-content: center; gap: 8px; pointer-events: none; }
button.is-loading::before,
.button-link.is-loading::before { content: ""; width: 14px; height: 14px; flex: 0 0 14px; border: 2px solid currentColor; border-right-color: transparent; border-radius: 999px; animation: admin-spin 0.75s linear infinite; }
form.is-submitting { cursor: progress; }
@keyframes admin-spin { to { transform: rotate(360deg); } }
.theme-toggle { flex: 0 0 38px; width: 38px; max-width: 38px; height: 38px; min-width: 38px; min-height: 38px; display: inline-grid; place-items: center; padding: 0; line-height: 1; overflow: hidden; background: transparent; color: var(--accent); border: 1px solid var(--line); }
.theme-toggle:hover { background: var(--field); }
.admin-menu-toggle { display: none; flex: 0 0 38px; width: 38px; max-width: 38px; height: 38px; min-width: 38px; min-height: 38px; place-items: center; padding: 0; line-height: 1; overflow: hidden; background: transparent; color: var(--accent); border: 1px solid var(--line); border-radius: 6px; }
.admin-menu-toggle:hover { background: var(--field); }
.admin-menu-toggle:focus-visible { outline: 2px solid var(--accent); outline-offset: 3px; }
.admin-menu-icon { width: 20px; height: 20px; fill: none; stroke: currentColor; stroke-width: 2; stroke-linecap: round; stroke-linejoin: round; }
.theme-icon { width: 18px; height: 18px; fill: none; stroke: currentColor; stroke-width: 2; stroke-linecap: round; stroke-linejoin: round; }
.theme-toggle .theme-icon { display: block; }
.theme-toggle .theme-icon--sun { display: none; }
:root[data-theme="dark"] .theme-toggle .theme-icon--moon { display: none; }
:root[data-theme="dark"] .theme-toggle .theme-icon--sun { display: block; }
:root:not([data-theme="dark"]) .theme-toggle .theme-icon--moon { display: block; }
:root:not([data-theme="dark"]) .theme-toggle .theme-icon--sun { display: none; }
.sr-only { position: absolute; width: 1px; height: 1px; padding: 0; margin: -1px; overflow: hidden; clip: rect(0, 0, 0, 0); white-space: nowrap; border: 0; }
.button-link { max-width: 100%; min-width: 0; display: inline-flex; align-items: center; justify-content: center; min-height: 42px; border-radius: 6px; padding: 7px 16px; background: var(--accent); color: var(--button-ink); text-align: center; text-decoration: none; font-weight: 700; line-height: 1.2; white-space: normal; overflow-wrap: anywhere; transition: background 140ms ease, border-color 140ms ease, color 140ms ease, box-shadow 140ms ease; }
.button-link:hover { background: var(--accent-dark); }
.button-link.secondary { background: transparent; color: var(--accent); border: 1px solid var(--accent); }
.button-link.secondary:hover { background: color-mix(in srgb, var(--accent) 9%, var(--panel)); color: var(--accent); }
.button-link[aria-disabled="true"] { pointer-events: none; }
.content-table { width: 100%; margin-top: 24px; border-collapse: collapse; }
.content-table th, .content-table td { padding: 12px 10px; border-bottom: 1px solid var(--line); text-align: left; vertical-align: middle; }
.content-table th { font-size: 12px; color: var(--muted); text-transform: uppercase; letter-spacing: 0.08em; }
.content-table a { color: var(--accent); font-weight: 700; text-decoration: none; }
.content-table td > * { max-width: 100%; }
.content-table td p,
.content-table td li,
.content-table td code,
.content-table td small,
.content-table td strong,
.content-table td span { min-width: 0; overflow-wrap: anywhere; word-break: break-word; }
.admin-card-table td[data-label] { vertical-align: top; }
.admin-card-table .status-pill { max-width: 100%; justify-content: center; text-align: center; line-height: 1.2; }
.admin-card-table td code,
.admin-card-table td small,
.admin-card-table td .muted,
.admin-card-table td a { max-width: 100%; overflow-wrap: anywhere; word-break: break-word; }
.admin-empty-row td { padding: 0; border-bottom: 0; }
.admin-empty-state { display: grid; gap: 5px; padding: 18px; border: 1px dashed var(--line); border-radius: 8px; background: var(--field); color: var(--muted); }
.admin-empty-state > * { min-width: 0; max-width: 100%; overflow-wrap: anywhere; }
.admin-empty-state strong { color: var(--ink); font-size: 15px; }
.admin-empty-state small { color: var(--muted); line-height: 1.4; }
.admin-empty-state code { white-space: normal; word-break: break-word; }
.row-actions { min-width: 0; display: flex; align-items: center; justify-content: flex-end; gap: 12px; flex-wrap: wrap; }
.row-actions form, .actions form { margin: 0; }
.icon-link { position: relative; width: 34px; min-width: 34px; height: 34px; min-height: 34px; display: inline-grid; place-items: center; border: 1px solid var(--line); border-radius: 999px; padding: 0; color: var(--accent); background: var(--field); text-decoration: none; }
.icon-link:hover { border-color: var(--accent); background: var(--panel); }
.icon-link--button { font: inherit; cursor: pointer; }
.icon-link--danger { color: var(--danger); }
.icon-link--danger:hover { border-color: var(--danger); background: color-mix(in srgb, var(--danger) 8%, var(--panel)); color: var(--danger); }
.admin-action-icon { width: 17px; height: 17px; fill: none; stroke: currentColor; stroke-width: 2; stroke-linecap: round; stroke-linejoin: round; }
.icon-link-count { position: absolute; right: -7px; top: -7px; min-width: 18px; height: 18px; display: inline-flex; align-items: center; justify-content: center; border: 1px solid var(--paper); border-radius: 999px; padding: 0 5px; background: var(--accent); color: var(--button-ink); font-size: 10px; font-weight: 800; line-height: 1; }
.comment-admin-list { display: grid; gap: 12px; margin-top: 22px; }
.comment-admin-item { display: grid; grid-template-columns: minmax(0, 1fr) auto; gap: 16px; align-items: start; padding: 14px; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
.comment-admin-main { min-width: 0; display: grid; gap: 10px; }
