.theme-preview-header { min-width: 0; display: flex; align-items: center; justify-content: space-between; gap: 16px; padding: calc(16px + var(--site-header-padding-y, 0px)) var(--site-header-padding-x, 32px); border-bottom: 1px solid var(--line); background: var(--panel); color: var(--ink); font-family: var(--preview-ui-font); }
