.theme-preview-type-samples strong { color: var(--ink); font: 900 22px/1.1 var(--preview-heading-font); overflow-wrap: anywhere; }
.theme-preview-type-samples p { margin: 0; color: var(--muted); font: 15px/1.45 var(--preview-body-font); overflow-wrap: anywhere; }
.theme-preview-type-samples button { min-height: 34px; justify-self: start; border: 1px solid var(--site-button-border); border-radius: var(--site-button-radius); padding: 0 12px; background: var(--site-button-bg); color: var(--site-button-color); box-shadow: var(--site-button-shadow); font: 900 13px/1 var(--preview-ui-font); }
.theme-preview-footer { min-width: 0; display: flex; align-items: flex-start; justify-content: space-between; gap: 16px; flex-wrap: wrap; padding: 18px 26px; border-top: 1px solid var(--line); background: var(--panel); color: var(--muted); font: 700 13px/1.35 var(--preview-ui-font); }
