.visual-contributor-request-button { width: max-content; min-height: 40px; display: inline-flex; align-items: center; padding: 0 16px; border-radius: 6px; background: var(--accent); color: #fff; font: 700 13px/1 system-ui, sans-serif; }
.upgrade-form { grid-template-columns: minmax(0, 1.2fr) minmax(280px, 0.8fr); align-items: start; }
.upgrade-drop { position: relative; display: grid; gap: 8px; min-height: 164px; padding: 24px; place-items: center; text-align: center; border: 1px dashed var(--accent); border-radius: 8px; background: color-mix(in srgb, var(--field) 82%, var(--accent) 18%); cursor: pointer; }
.upgrade-drop.is-dragging { border-style: solid; background: color-mix(in srgb, var(--field) 68%, var(--support) 32%); box-shadow: inset 0 0 0 1px var(--support); }
.upgrade-drop.has-file { border-style: solid; background: color-mix(in srgb, var(--field) 74%, var(--support) 26%); }
