.mono-block { overflow-x: auto; margin: 8px 0 0; padding: 12px; border: 1px solid var(--line); border-radius: 6px; background: var(--field); color: var(--ink); font-size: 13px; line-height: 1.45; white-space: pre-wrap; }
.theme-mode-grid { display: grid; grid-template-columns: repeat(2, minmax(0, 1fr)); gap: 16px; }
.theme-mode-panel { display: grid; align-content: start; gap: 12px; min-width: 0; padding: 14px; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
