.theme-choice-card input { position: absolute; inset: 12px 12px auto auto; width: 18px; min-height: 18px; }
.theme-choice-card:has(input:checked) { border-color: var(--accent); box-shadow: 0 0 0 3px color-mix(in srgb, var(--accent) 18%, transparent); }
