.location-status { color: var(--muted); font-size: 13px; font-weight: 700; overflow-wrap: anywhere; }
.location-map { min-height: 300px; border: 1px solid var(--line); border-radius: 8px; overflow: hidden; background: var(--field); }
.location-map .slippy-map-toolbar { top: 10px; left: 10px; right: 10px; }
