.visual-editor-shell.preview-mode--mobile .visual-image-text.image-text--right figure { order: 0; }
.preview-site-header,
.preview-site-footer { display: flex; align-items: center; justify-content: space-between; gap: 20px; padding: 18px 26px; border-bottom: 1px solid var(--line); background: var(--field); font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif; }
.preview-site-header a { color: var(--ink); font-weight: 800; text-decoration: none; }
