.visual-block hr { margin: 28px 0; border: 0; border-top: 1px solid var(--line); }
.visual-block-settings { min-width: 0; position: absolute; left: 14px; top: 14px; z-index: 3; display: flex; align-items: center; gap: 8px; flex-wrap: wrap; max-width: min(620px, calc(100% - 28px)); padding: 9px; border: 1px solid var(--line); border-radius: 8px; background: color-mix(in srgb, var(--panel) 96%, transparent); box-shadow: 0 14px 34px rgba(16, 32, 51, 0.16); backdrop-filter: blur(12px); font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif; font-size: 13px; line-height: 1.25; opacity: 0; visibility: hidden; pointer-events: none; transform: translateY(-6px); transition: opacity 120ms ease, transform 120ms ease, visibility 120ms ease; }
