.visual-content-ref-card { display: grid; grid-template-columns: minmax(150px, 0.42fr) minmax(0, 1fr); gap: 16px; align-items: stretch; margin: 8px 0; padding: 14px; border: 1px solid var(--line); border-radius: 8px; background: var(--panel); color: var(--ink); font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif; box-shadow: 0 8px 20px rgba(16, 32, 51, 0.08); }
