.module-grid { display: grid; gap: 16px; margin: 18px 0; }
.module-card { min-width: 0; display: grid; grid-template-columns: minmax(0, 1fr) minmax(170px, auto); gap: 18px; align-items: start; padding: 18px; border: 1px solid var(--line); border-radius: 8px; background: var(--field); }
.module-card--enabled { border-left: 4px solid var(--support); }
