sub _map_js {
    my ($self) = @_;
    DesertCMS::Theme::install_default($self->{config});
    my $path = File::Spec->catfile($self->{config}->get('theme_dir'), 'default', 'assets', 'map.js');
    open my $fh, '<', $path or die "cannot read map asset $path: $!";
    local $/;
    my $js = <$fh>;
    close $fh;
    return DesertCMS::HTTP->response(
        status  => 200,
        headers => {
            'Content-Type'  => 'application/javascript; charset=utf-8',
            'Cache-Control' => 'public, max-age=300',
        },
        body => $js,
    );
}

sub _editor_js {
    my $js = <<'JS';
(function () {
  document.documentElement.classList.add('has-js');

  function parseJson(value, fallback) {
    try {
      var parsed = JSON.parse(value || '');
      return Array.isArray(parsed) ? parsed : fallback;
    } catch (error) {
      return fallback;
    }
  }

  function imageOptions(media, selected) {
    if (!media.length) {
      return '<option value="">Upload an image in Media first</option>';
    }
    return media.map(function (asset) {
      var src = asset.src || '';
      var name = asset.name || src;
      var filename = asset.filename && asset.filename !== name ? (' - ' + asset.filename) : '';
      var search = assetSearchText(asset);
      var isSelected = src === selected ? ' selected' : '';
      return '<option value="' + escapeAttr(src) + '" data-search="' + escapeAttr(search) + '"' + isSelected + '>' + escapeHtml(name + filename) + '</option>';
