    var lastSubmitter = null;
    var activeConfirm = null;
    function submitterText(submitter) {
      if (!submitter) {
        return '';
      }
      return (submitter.getAttribute('data-loading-label') || submitter.getAttribute('aria-label') || submitter.getAttribute('title') || submitter.textContent || submitter.value || '').trim();
    }
    function loadingLabelFor(form, submitter) {
      var explicit = (submitter && submitter.getAttribute('data-loading-label')) || form.getAttribute('data-loading-label');
      if (explicit) {
        return explicit;
      }
      var text = submitterText(submitter).toLowerCase();
      var action = (form.getAttribute('action') || '').toLowerCase();
      var haystack = text + ' ' + action;
      if (/destroy|delete|remove|revoke/.test(haystack)) {
        return 'Deleting...';
      }
      if (/disable/.test(haystack)) {
        return 'Disabling...';
      }
      if (/enable/.test(haystack)) {
        return 'Enabling...';
      }
      if (/restore|rollback/.test(haystack)) {
        return 'Preparing...';
      }
      if (/backup/.test(haystack)) {
        return 'Backing up...';
      }
      if (/rebuild|publish|submit-search|search-engines/.test(haystack)) {
        return 'Rebuilding...';
      }
      if (/queue|retry|stage|upgrade|provision|approve/.test(haystack)) {
        return 'Queueing...';
      }
      if (/send|email|invite|deny/.test(haystack)) {
        return 'Sending...';
      }
      if (/upload|import/.test(haystack)) {
        return 'Uploading...';
      }
      if (/save|settings|update/.test(haystack)) {
        return 'Saving...';
      }
      return 'Working...';
    }
    function submitButtonsFor(form, submitter) {
      var buttons = Array.prototype.slice.call(form.querySelectorAll('button:not([type]), button[type="submit"], input[type="submit"]'));
      if (submitter && buttons.indexOf(submitter) === -1) {
        buttons.push(submitter);
      }
      return buttons;
    }
    function setSubmitterLoading(button, label) {
      if (!button || button.getAttribute('data-loading-ready') === '1') {
        return;
      }
      button.setAttribute('data-loading-ready', '1');
      button.setAttribute('aria-disabled', 'true');
      button.classList.add('is-loading');
      button.disabled = true;
      if (button.tagName === 'INPUT') {
        button.setAttribute('data-original-value', button.value || '');
        button.value = label;
        return;
      }
      if (button.classList.contains('icon-link')) {
        button.setAttribute('aria-label', label);
        button.setAttribute('title', label);
        return;
      }
      button.setAttribute('data-original-text', button.textContent || '');
      button.textContent = label;
    }
    function applyFormLoading(form, submitter) {
      if (!form || form.getAttribute('data-no-loading') === '1') {
