      if (form.getAttribute('data-submitting') === '1') {
        return false;
      }
      form.setAttribute('data-submitting', '1');
      form.classList.add('is-submitting');
      form.setAttribute('aria-busy', 'true');
      var label = loadingLabelFor(form, submitter);
      submitButtonsFor(form, submitter).forEach(function (button) {
        setSubmitterLoading(button, label);
      });
      return true;
    }
    function closeConfirm() {
      if (!activeConfirm) {
        return;
      }
      activeConfirm.remove();
      activeConfirm = null;
      document.body.classList.remove('has-admin-modal');
    }
    function openConfirm(options, onConfirm) {
      closeConfirm();
      var backdrop = document.createElement('div');
      backdrop.className = 'confirm-backdrop';
      backdrop.setAttribute('role', 'presentation');
      var dialog = document.createElement('section');
      dialog.className = 'confirm-dialog';
      dialog.setAttribute('role', 'dialog');
      dialog.setAttribute('aria-modal', 'true');
      dialog.setAttribute('aria-labelledby', 'admin-confirm-title');
      dialog.innerHTML = '<h2 class="confirm-title" id="admin-confirm-title"></h2><p class="confirm-message"></p><div class="confirm-actions"><button type="button" class="secondary" data-confirm-cancel>Cancel</button><button type="button" class="danger" data-confirm-accept></button></div>';
      dialog.querySelector('.confirm-title').textContent = options.title || 'Confirm action';
      dialog.querySelector('.confirm-message').textContent = options.message || 'This action changes stored site data.';
      dialog.querySelector('[data-confirm-accept]').textContent = options.action || 'Continue';
      backdrop.appendChild(dialog);
      document.body.appendChild(backdrop);
      document.body.classList.add('has-admin-modal');
      activeConfirm = backdrop;
      var cancelButton = dialog.querySelector('[data-confirm-cancel]');
      var acceptButton = dialog.querySelector('[data-confirm-accept]');
      var escapeListener;
      function closeThisConfirm() {
        document.removeEventListener('keydown', escapeListener);
        closeConfirm();
      }
      cancelButton.addEventListener('click', closeThisConfirm);
      acceptButton.addEventListener('click', function () {
        closeThisConfirm();
        onConfirm();
      });
      backdrop.addEventListener('click', function (event) {
        if (event.target === backdrop) {
          closeThisConfirm();
        }
      });
      escapeListener = function (event) {
        if (event.key === 'Escape') {
          closeThisConfirm();
        }
      };
      document.addEventListener('keydown', escapeListener);
      acceptButton.focus();
    }
    function confirmOptionsFor(form, submitter) {
      var source = submitter && submitter.hasAttribute('data-confirm-title') ? submitter : form;
      if (!source || !source.getAttribute('data-confirm-title')) {
        return null;
      }
      return {
        title: source.getAttribute('data-confirm-title') || 'Confirm action',
        message: source.getAttribute('data-confirm-message') || 'This action changes stored site data.',
        action: source.getAttribute('data-confirm-action') || submitterText(submitter) || 'Continue'
      };
    }
    document.addEventListener('click', function (event) {
      var button = event.target && event.target.closest ? event.target.closest('button:not([type]), button[type="submit"], input[type="submit"]') : null;
      if (button && button.form) {
        lastSubmitter = button;
      }
    }, true);
    document.addEventListener('submit', function (event) {
      var form = event.target;
      if (!form || form.tagName !== 'FORM') {
        return;
      }
      var submitter = event.submitter || (lastSubmitter && lastSubmitter.form === form ? lastSubmitter : null);
      if (form.getAttribute('data-submitting') === '1') {
        event.preventDefault();
        return;
      }
      var options = confirmOptionsFor(form, submitter);
      if (options && form.getAttribute('data-confirmed') !== '1') {
        event.preventDefault();
        openConfirm(options, function () {
          form.setAttribute('data-confirmed', '1');
          if (form.requestSubmit) {
            if (submitter) {
              form.requestSubmit(submitter);
            } else {
              form.requestSubmit();
            }
          } else {
            applyFormLoading(form, submitter);
            HTMLFormElement.prototype.submit.call(form);
          }
        });
        return;
      }
      form.removeAttribute('data-confirmed');
      if (!applyFormLoading(form, submitter)) {
        event.preventDefault();
      }
    }, true);
