    var actionMenuMedia = window.matchMedia('(max-width: 820px)');
    function setupTableActionMenus() {
      Array.prototype.forEach.call(document.querySelectorAll('.admin-card-table td.table-actions'), function (cell) {
        if (cell.getAttribute('data-action-menu-ready') === '1') {
          return;
        }
        var actionable = Array.prototype.filter.call(cell.children, function (child) {
          return child.matches && child.matches('a, button, form, details');
        });
        if (actionable.length < 2) {
          return;
        }
        var details = document.createElement('details');
        details.className = 'table-action-menu';
        var summary = document.createElement('summary');
        summary.textContent = 'Actions';
        var panel = document.createElement('div');
        panel.className = 'table-action-menu-panel';
        while (cell.firstChild) {
          panel.appendChild(cell.firstChild);
        }
        details.appendChild(summary);
        details.appendChild(panel);
        cell.appendChild(details);
        cell.setAttribute('data-action-menu-ready', '1');
      });
      syncTableActionMenus();
    }
    function syncTableActionMenus() {
      var mobile = actionMenuMedia.matches;
      Array.prototype.forEach.call(document.querySelectorAll('.table-action-menu'), function (menu) {
        if (mobile) {
          if (!menu.hasAttribute('data-user-open')) {
            menu.open = false;
          }
        } else {
          menu.open = true;
          menu.removeAttribute('data-user-open');
        }
      });
    }
    setupTableActionMenus();
    Array.prototype.forEach.call(document.querySelectorAll('.table-action-menu'), function (menu) {
      menu.addEventListener('toggle', function () {
        if (actionMenuMedia.matches && menu.open) {
          menu.setAttribute('data-user-open', '1');
        } else if (!menu.open) {
          menu.removeAttribute('data-user-open');
        }
      });
    });
    if (actionMenuMedia.addEventListener) {
      actionMenuMedia.addEventListener('change', syncTableActionMenus);
    } else if (actionMenuMedia.addListener) {
      actionMenuMedia.addListener(syncTableActionMenus);
    }

    Array.prototype.forEach.call(document.querySelectorAll('[data-media-bulk-form]'), function (form) {
      var selectAll = form.querySelector('[data-media-select-all]');
      var countNode = form.querySelector('[data-media-selected-count]');
      var checkboxes = Array.prototype.slice.call(document.querySelectorAll('[data-media-select][form="' + form.id + '"]'));
      function syncMediaBulkSelection() {
        var checked = checkboxes.filter(function (box) { return box.checked; }).length;
        var total = checkboxes.length;
        if (countNode) {
          countNode.textContent = checked + ' selected';
        }
        if (selectAll) {
          selectAll.checked = total > 0 && checked === total;
          selectAll.indeterminate = checked > 0 && checked < total;
        }
      }
      if (selectAll) {
        selectAll.addEventListener('change', function () {
          checkboxes.forEach(function (box) {
            box.checked = selectAll.checked;
          });
          syncMediaBulkSelection();
        });
      }
      checkboxes.forEach(function (box) {
        box.addEventListener('change', syncMediaBulkSelection);
      });
      syncMediaBulkSelection();
    });

    var shopContributorSelect = document.querySelector('[data-shop-contributor-select]');
    var shopContributorFilter = document.querySelector('[data-shop-contributor-filter]');
    var shopFilterClear = document.querySelector('[data-shop-filter-clear]');
    var shopFilterCount = document.querySelector('[data-shop-filter-count]');
    var shopEmptyFilter = document.querySelector('[data-shop-empty-filter]');
    var shopItemCards = Array.prototype.slice.call(document.querySelectorAll('[data-shop-item-card]'));
    function updateShopContributorFilter() {
      if ((!shopContributorFilter && !shopContributorSelect) || !shopItemCards.length) {
        return;
      }
      var selected = shopContributorSelect ? shopContributorSelect.value.trim().toLowerCase() : '';
      var query = shopContributorFilter ? shopContributorFilter.value.trim().toLowerCase() : '';
      var visible = 0;
      shopItemCards.forEach(function (card) {
        var haystack = (card.getAttribute('data-contributor-search') || card.getAttribute('data-contributor-name') || '').toLowerCase();
        var name = (card.getAttribute('data-contributor-name') || '').toLowerCase();
        var match = (!selected || name === selected) && (!query || haystack.indexOf(query) !== -1);
        card.hidden = !match;
        if (match) {
          visible++;
        }
      });
      if (shopFilterCount) {
        var total = shopItemCards.length;
        var totalUnit = total === 1 ? 'item' : 'items';
        shopFilterCount.textContent = (selected || query) ? (visible + ' of ' + total + ' ' + totalUnit) : (total + ' ' + totalUnit);
      }
      if (shopEmptyFilter) {
        shopEmptyFilter.hidden = visible > 0 || (!selected && !query);
      }
    }
    if (shopContributorFilter) {
      shopContributorFilter.addEventListener('input', updateShopContributorFilter);
      updateShopContributorFilter();
    }
    if (shopContributorSelect) {
      shopContributorSelect.addEventListener('change', updateShopContributorFilter);
      updateShopContributorFilter();
    }
    if (shopFilterClear) {
      shopFilterClear.addEventListener('click', function () {
        if (shopContributorSelect) {
          shopContributorSelect.value = '';
        }
        if (shopContributorFilter) {
          shopContributorFilter.value = '';
        }
        updateShopContributorFilter();
        if (shopContributorSelect) {
          shopContributorSelect.focus();
        } else if (shopContributorFilter) {
          shopContributorFilter.focus();
        }
      });
    }

    (function initUpgradeDrop() {
      var drop = document.querySelector('[data-upgrade-drop]');
      var input = document.querySelector('[data-upgrade-input]');
      var state = document.querySelector('[data-upgrade-file-state]');
      if (!drop || !input || !state) {
        return;
      }
      function sizeLabel(bytes) {
        if (!Number.isFinite(bytes) || bytes <= 0) {
          return '';
        }
        if (bytes >= 1024 * 1024) {
          return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
        }
        return Math.max(1, Math.round(bytes / 1024)) + ' KB';
      }
      function updateSelectedFile() {
        var file = input.files && input.files.length ? input.files[0] : null;
        if (!file) {
          drop.classList.remove('has-file');
          state.textContent = 'No archive selected';
          return;
        }
        drop.classList.add('has-file');
        var label = file.name || 'Selected archive';
        var size = sizeLabel(file.size);
        state.textContent = size ? (label + ' - ' + size) : label;
      }
      input.addEventListener('change', updateSelectedFile);
      ['dragenter', 'dragover'].forEach(function (eventName) {
        drop.addEventListener(eventName, function () {
          drop.classList.add('is-dragging');
        });
      });
      ['dragleave', 'drop'].forEach(function (eventName) {
        drop.addEventListener(eventName, function () {
          drop.classList.remove('is-dragging');
          window.setTimeout(updateSelectedFile, 0);
        });
      });
      updateSelectedFile();
    }());

    var typeSelect = document.querySelector('select[name="type"]');
