    (function initLocationMap() {
      var mapNode = document.querySelector('[data-location-map]');
      if (!mapNode) {
        return;
      }
      var latField = document.querySelector('[data-location-lat]');
      var lngField = document.querySelector('[data-location-lng]');
      var enabledField = document.querySelector('[data-location-enabled]');
      var status = document.querySelector('[data-location-status]');
      var clearButton = document.querySelector('[data-location-clear]');
      var configScript = mapNode.querySelector('[data-map-config]');
      var config = {};
      try {
        config = JSON.parse(configScript ? configScript.textContent || '{}' : '{}') || {};
      } catch (error) {
        config = {};
      }
      function formatCoord(value) {
        var number = Number(value);
        return Number.isFinite(number) ? number.toFixed(6) : '';
      }
      function updateStatus() {
        var lat = latField ? latField.value : '';
        var lng = lngField ? lngField.value : '';
        if (status) {
          status.textContent = lat && lng ? 'Pinned at ' + lat + ', ' + lng : 'No location pinned. Click the map to drop a pin.';
        }
      }
      config.onChange = function (point) {
        if (latField) {
          latField.value = formatCoord(point.lat);
        }
        if (lngField) {
          lngField.value = formatCoord(point.lng);
        }
        if (enabledField) {
          enabledField.checked = true;
        }
        updateStatus();
      };
      if (!window.DesertMap || typeof window.DesertMap.create !== 'function') {
        if (status) {
          status.textContent = 'Map editor could not load.';
        }
        return;
      }
      var mapApi = window.DesertMap.create(mapNode, config);
      if (clearButton) {
        clearButton.addEventListener('click', function () {
          if (latField) {
            latField.value = '';
          }
          if (lngField) {
            lngField.value = '';
          }
          if (enabledField) {
            enabledField.checked = false;
          }
          if (mapApi && mapApi.setPins) {
            mapApi.setPins([]);
          }
          updateStatus();
        });
      }
      updateStatus();
    }());

    Array.prototype.forEach.call(document.querySelectorAll('[data-preview-mode-bar]'), function (bar) {
