          blocks[index].layout = readField(node, 'layout');
          blocks[index].size = readField(node, 'size');
        } else if (blocks[index].type === 'image_text') {
          blocks[index].src = readField(node, 'src');
          blocks[index].alt = readField(node, 'alt');
          blocks[index].caption = readField(node, 'caption');
          blocks[index].html = readRichField(node, 'text');
          blocks[index].text = plainTextFromRichHtml(blocks[index].html);
          blocks[index].align = normalizeAlign(blocks[index].align);
          blocks[index].font = normalizeTextFont(readField(node, 'font') || blocks[index].font);
          blocks[index].text_size = normalizeTextSize(readField(node, 'text_size') || blocks[index].text_size);
          blocks[index].image_side = readField(node, 'image_side');
        } else if (blocks[index].type === 'video') {
          blocks[index].url = readField(node, 'url');
          blocks[index].title = readField(node, 'title');
          blocks[index].caption = readField(node, 'caption');
        } else if (blocks[index].type === 'link') {
          blocks[index].url = readField(node, 'url');
          blocks[index].label = readField(node, 'label');
          blocks[index].description = readField(node, 'description');
        } else if (blocks[index].type === 'resource') {
          blocks[index].src = readField(node, 'src');
          blocks[index].label = readField(node, 'label');
          blocks[index].description = readField(node, 'description');
          blocks[index].button_label = readField(node, 'button_label');
        } else if (blocks[index].type === 'content_ref') {
          blocks[index].target_id = Math.max(0, parseInt(readField(node, 'target_id') || 0, 10) || 0);
          blocks[index].style = /^(card|feature)$/.test(readField(node, 'style') || '') ? readField(node, 'style') : 'card';
        } else if (blocks[index].type === 'contributor_request') {
          blocks[index].title = readField(node, 'title');
          blocks[index].intro = readField(node, 'intro');
          blocks[index].button_label = readField(node, 'button_label');
        } else if (blocks[index].type === 'social') {
          blocks[index].platform = readField(node, 'platform');
          blocks[index].url = readField(node, 'url');
          blocks[index].label = readField(node, 'label');
        } else if (blocks[index].type === 'code') {
          blocks[index].code = readField(node, 'code');
          blocks[index].language = cleanCodeLanguage(readField(node, 'language'));
        }
      });
      sync();
    }

    function richFieldFor(button) {
      var node = button.closest('.visual-block');
      return node ? node.querySelector('[data-rich-field="true"]') : null;
    }

    function textStyleTarget(node) {
      return node ? node.querySelector('[data-style-target="true"]') : null;
    }

    function applyTextStyleToNode(node, block) {
      var target = textStyleTarget(node);
      if (!target) {
        return;
      }
      target.classList.remove(
        'visual-font--serif', 'visual-font--sans', 'visual-font--mono',
        'visual-size--small', 'visual-size--normal', 'visual-size--large'
      );
      textStyleClass(block).split(/\s+/).forEach(function (className) {
        if (className) {
          target.classList.add(className);
        }
      });
    }

    function applyRichCommand(button) {
      var command = button.getAttribute('data-rich-command') || '';
      var field = richFieldFor(button);
      if (!field) {
        return;
      }
      restoreRichSelection(field);
      if (command === 'createLink') {
        saveRichSelection(field);
        var url = cleanRichHref(window.prompt('Link URL') || '');
        if (!url) {
          restoreRichSelection(field);
          return;
        }
        restoreRichSelection(field);
        document.execCommand('createLink', false, url);
      } else if (/^(bold|italic|underline|strikeThrough|insertUnorderedList|insertOrderedList|removeFormat)$/.test(command)) {
        document.execCommand(command, false, null);
      }
      saveRichSelection(field);
      refreshRichToolbarState(field);
      updateFromDom();
    }

    function applyRichColor(button) {
      var color = cleanRichColor(button.getAttribute('data-rich-color') || '');
      var field = richFieldFor(button);
      if (!field || !color || !window.getSelection) {
        return;
      }
      restoreRichSelection(field);
      var selection = window.getSelection();
      if (!selection || !selection.rangeCount) {
        return;
      }
      var range = selection.getRangeAt(0);
      if (!nodeContains(field, range.startContainer) || !nodeContains(field, range.endContainer)) {
        return;
      }
      var span = document.createElement('span');
      span.setAttribute('style', 'color: ' + color);
      if (range.collapsed) {
        span.appendChild(document.createTextNode('emphasis'));
      } else {
        span.appendChild(range.extractContents());
      }
      range.insertNode(span);
      range.selectNodeContents(span);
      selection.removeAllRanges();
      selection.addRange(range);
      field.innerHTML = sanitizeRichHtml(field.innerHTML || '');
      placeCaretAtEnd(field);
      refreshRichToolbarState(field);
      updateFromDom();
    }

    function applyRichAlign(button) {
      var align = normalizeAlign(button.getAttribute('data-rich-align') || '');
      var node = button.closest('.visual-block');
      if (!node) {
        return;
      }
      updateFromDom();
      var index = Number(node.getAttribute('data-index'));
      if (!blocks[index]) {
        return;
      }
      blocks[index].align = align;
      var field = node.querySelector('[data-rich-field="true"]');
      if (field) {
        field.classList.remove('visual-text-align--left', 'visual-text-align--center', 'visual-text-align--right');
        field.classList.add(alignClass(align));
      }
      var target = textStyleTarget(node);
      if (target) {
        target.classList.remove('visual-text-align--left', 'visual-text-align--center', 'visual-text-align--right');
        target.classList.add(alignClass(align));
      }
      Array.prototype.forEach.call(node.querySelectorAll('[data-rich-align]'), function (alignButton) {
        var isActive = alignButton.getAttribute('data-rich-align') === align;
        alignButton.classList.toggle('is-active', isActive);
        alignButton.setAttribute('aria-pressed', isActive ? 'true' : 'false');
      });
      sync();
      if (field) {
        restoreRichSelection(field);
        refreshRichToolbarState(field);
      }
    }

    function blockForTool(button) {
      var node = button.closest('.visual-block');
      if (!node) {
        return { node: null, index: -1, block: null };
      }
      var index = Number(node.getAttribute('data-index'));
      return { node: node, index: index, block: blocks[index] || null };
    }

    function refreshFontMenu(node, block) {
      if (!node || !block) {
        return;
      }
      Array.prototype.forEach.call(node.querySelectorAll('[data-font-choice]'), function (button) {
        button.classList.toggle('is-active', button.getAttribute('data-font-choice') === normalizeTextFont(block.font));
      });
    }

    function applyFontChoice(button) {
      var state = blockForTool(button);
      if (!state.block) {
        return;
      }
      updateFromDom();
      state.block.font = normalizeTextFont(button.getAttribute('data-font-choice'));
      applyTextStyleToNode(state.node, state.block);
      refreshFontMenu(state.node, state.block);
      var menu = button.closest('.font-menu');
      if (menu) {
        menu.hidden = true;
      }
      sync();
      var field = state.node.querySelector('[data-rich-field="true"]');
      if (field) {
        restoreRichSelection(field);
      }
    }

    function stepTextSize(current, direction) {
      var sizes = ['small', 'normal', 'large'];
      var index = sizes.indexOf(normalizeTextSize(current));
      index = index < 0 ? 1 : index;
      index += direction === 'up' ? 1 : -1;
      index = Math.max(0, Math.min(sizes.length - 1, index));
      return sizes[index];
    }

    function applyFontStep(button) {
      var state = blockForTool(button);
      if (!state.block) {
        return;
      }
      updateFromDom();
      state.block.text_size = stepTextSize(state.block.text_size, button.getAttribute('data-font-step'));
      applyTextStyleToNode(state.node, state.block);
      sync();
      var field = state.node.querySelector('[data-rich-field="true"]');
      if (field) {
        restoreRichSelection(field);
      }
    }

    function toggleFontMenu(button) {
      var state = blockForTool(button);
      if (!state.node) {
        return;
      }
      Array.prototype.forEach.call(list.querySelectorAll('.font-menu'), function (menu) {
        if (!button.parentNode || menu.parentNode !== button.parentNode) {
          menu.hidden = true;
        }
      });
      var menu = button.parentNode ? button.parentNode.querySelector('.font-menu') : null;
      if (menu) {
        refreshFontMenu(state.node, state.block);
        menu.hidden = !menu.hidden;
      }
    }

  function mediaPreview(src, alt) {
    return src
      ? '<img src="' + escapeAttr(src) + '" alt="' + escapeAttr(alt || '') + '">'
      : '<div class="media-empty">Upload or choose an image</div>';
  }

  function contentRefPreview(block) {
    var item = contentById[String(block.target_id || '')];
    var style = /^(card|feature)$/.test(block.style || '') ? block.style : 'card';
    if (!item) {
      return '<div class="content-ref-card content-ref-card--empty"><div><span>Featured</span><strong>Choose a page or post</strong><p>Use the edit button to select the story this section should link to.</p></div></div>';
    }
    var image = item.image ? '<figure><img src="' + escapeAttr(item.image) + '" alt="' + escapeAttr(item.title || '') + '"></figure>' : '';
    var status = item.status === 'published' ? '' : 'Draft';
    var type = (item.type || 'page').charAt(0).toUpperCase() + (item.type || 'page').slice(1);
    var meta = status ? type + ' - ' + status : type;
    var excerpt = item.excerpt ? '<p>' + escapeHtml(item.excerpt) + '</p>' : '';
    var url = item.url ? '<small>' + escapeHtml(item.url) + '</small>' : '';
    return '<div class="content-ref-card content-ref-card--' + escapeAttr(style) + ' visual-content-ref-card">' +
      image +
      '<div><span>' + escapeHtml(meta) + '</span><strong>' + escapeHtml(item.title || 'Untitled') + '</strong>' + excerpt + url + '</div>' +
      '</div>';
  }

  function resourcePreview(block) {
    var asset = resourceBySrc[String(block.src || '')] || {};
    var extension = asset.extension || 'FILE';
    var label = block.label || asset.name || 'Choose a resource';
    var description = block.description || asset.description || '';
    var button = block.button_label || 'Download';
    var empty = block.src ? '' : ' visual-resource-card--empty';
    var metaParts = [];
    if (asset.type_label) { metaParts.push(asset.type_label); }
    if (asset.filename || block.src) { metaParts.push(asset.filename || block.src); }
    if (asset.byte_label) { metaParts.push(asset.byte_label); }
    var meta = metaParts.length ? metaParts.join(' - ') : 'Publish a resource in Media first';
    return '<div class="resource-card visual-resource-card' + empty + '">' +
      '<span class="resource-card-badge">' + escapeHtml(extension) + '</span>' +
      '<div><strong>' + inlineField('label', label, 'Resource title', 'visual-link-title') + '</strong>' +
      textField('description', description, 'Short description...', 'visual-link-description') +
      '<small>' + escapeHtml(meta) + '</small></div>' +
      '<span class="resource-card-action">' + inlineField('button_label', button, 'Download', 'visual-resource-action-text') + '</span>' +
      '</div>';
  }

  function spacingControls(block) {
      return '<label class="spacing-control"><span>Spacing</span><select data-field="spacing">' + optionList([
        { value: 'default', label: 'Default' },
        { value: 'compact', label: 'Compact' },
        { value: 'spacious', label: 'Spacious' },
        { value: 'none', label: 'None' }
      ], normalizeSpacing(block && block.spacing)) + '</select></label>';
    }

  function blockSettings(label, html, className, block) {
      var extra = className ? ' ' + className : '';
      return '<div class="visual-block-settings' + extra + '" role="toolbar" aria-label="' + escapeAttr(label || 'Block tools') + '"><span class="tool-label">' + escapeHtml(label || 'Tools') + '</span>' + html + spacingControls(block) + '<button type="button" class="icon-button tool-close" data-close-tools aria-label="Close ' + escapeAttr(label || 'block') + ' tools" title="Close">' + icon('close') + '</button></div>';
    }

    function fieldRequiresRender(name) {
      return /^(src|layout|size|image_side|level|platform|target_id|style|spacing)$/.test(name || '');
    }

    function render() {
      list.innerHTML = '';
      blocks.forEach(function (block, index) {
        var node = document.createElement('article');
        block.spacing = normalizeSpacing(block.spacing);
        node.className = 'visual-block visual-block--' + block.type + ' visual-block-spacing--' + block.spacing;
        node.draggable = true;
        node.setAttribute('data-index', String(index));

        var fields = '';
        if (block.type === 'image') {
          fields =
            '<figure class="visual-image media-figure media-figure--' + escapeAttr(block.layout) + ' media-figure--' + escapeAttr(block.size) + '">' +
            mediaPreview(block.src, block.alt) +
            '<figcaption>' + inputField('caption', block.caption, 'Caption') + '</figcaption>' +
            '</figure>' +
            blockSettings(
              'Image',
              mediaPickerControl('Image', 'image', media, block.src) +
              '<label><span>Alt text</span>' + inputField('alt', block.alt, 'Describe the image') + '</label>' +
              '<div class="field-row">' +
              '<label><span>Layout</span><select data-field="layout">' + optionList([
              { value: 'full', label: 'Full row' },
              { value: 'left', label: 'Left, text wraps' },
              { value: 'right', label: 'Right, text wraps' },
              { value: 'center', label: 'Centered' }
              ], block.layout) + '</select></label>' +
              '<label><span>Size</span><select data-field="size">' + optionList([
              { value: 'small', label: 'Small' },
              { value: 'medium', label: 'Medium' },
              { value: 'large', label: 'Large' },
              { value: 'full', label: 'Full width' }
              ], block.size) + '</select></label>' +
              '</div>',
              '',
              block
            );
        } else if (block.type === 'image_text') {
          fields =
            '<section class="visual-image-text image-text image-text--' + escapeAttr(block.image_side) + '">' +
            '<figure>' + mediaPreview(block.src, block.alt) + '<figcaption>' + inputField('caption', block.caption, 'Caption') + '</figcaption></figure>' +
            '<div>' + richTextField('text', block.html, block.text, 'Write text beside this image...', 'visual-rich-text ' + alignClass(block.align) + ' ' + textStyleClass(block)).replace('data-rich-field="true"', 'data-rich-field="true" data-style-target="true"') + '</div>' +
            '</section>' +
            blockSettings(
              'Image + Text',
              richTextToolbar(block.align) +
              fontToolControls(block) +
              mediaPickerControl('Image', 'image', media, block.src) +
              '<label><span>Alt text</span>' + inputField('alt', block.alt, 'Describe the image') + '</label>' +
              '<label><span>Image side</span><select data-field="image_side">' + optionList([
                { value: 'left', label: 'Image left' },
                { value: 'right', label: 'Image right' }
              ], block.image_side) + '</select></label>',
              'visual-block-settings--rich visual-block-settings--wide',
              block
            );
        } else if (block.type === 'heading') {
          fields =
            '<h' + Number(block.level) + ' class="' + alignClass(block.align) + ' ' + textStyleClass(block) + '" data-style-target="true">' + inlineField('text', block.text, 'Section heading', 'visual-heading-text') + '</h' + Number(block.level) + '>' +
            blockSettings('Heading', alignToolbar(block.align) + fontToolControls(block) + '<label><span>Level</span><select data-field="level">' + optionList([
              { value: '2', label: 'Section heading' },
              { value: '3', label: 'Subheading' }
            ], String(block.level)) + '</select></label>', 'visual-block-settings--rich visual-block-settings--wide', block);
        } else if (block.type === 'quote') {
          fields =
            blockSettings('Quote', alignToolbar(block.align) + fontToolControls(block) + '<label><span>Citation</span>' + inputField('citation', block.citation, 'Citation') + '</label>', 'visual-block-settings--rich visual-block-settings--wide', block) +
            '<blockquote class="' + alignClass(block.align) + ' ' + textStyleClass(block) + '" data-style-target="true"><p>' + inlineField('text', block.text, 'Quote text...', 'visual-quote-text') + '</p>' + (block.citation ? '<cite>' + escapeHtml(block.citation) + '</cite>' : '') + '</blockquote>';
        } else if (block.type === 'divider') {
          fields = blockSettings('Divider', '<span class="tool-note">Use this to separate page sections.</span>', '', block) + '<hr>';
        } else if (block.type === 'code') {
          fields =
            '<label class="visual-code-editor">' +
            '<span>Code</span>' +
            '<textarea data-field="code" rows="9" spellcheck="false" placeholder="Paste or write code...">' + escapeHtml(block.code || '') + '</textarea>' +
            '</label>' +
            blockSettings('Code', '<label><span>Language</span>' + inputField('language', block.language, 'perl, html, css...') + '</label>', 'visual-block-settings--side', block);
        } else if (block.type === 'video') {
          fields =
            '<figure class="video-block">' +
            '<div class="video-frame video-frame--placeholder"><span>Video preview</span></div>' +
            '<figcaption>' + inputField('caption', block.caption, 'Caption') + '</figcaption>' +
            '</figure>' +
            blockSettings(
              'Video',
              '<label><span>Video URL</span>' + inputField('url', block.url, 'https://youtube.com/watch?v=...') + '</label>' +
              '<label><span>Title</span>' + inputField('title', block.title, 'Video title') + '</label>',
              '',
              block
            );
        } else if (block.type === 'link') {
          fields =
            '<div class="link-card visual-link-card"><span>Link</span><strong>' + inlineField('label', block.label, 'Link title', 'visual-link-title') + '</strong>' + textField('description', block.description, 'Short description...', 'visual-link-description') + '</div>' +
            blockSettings('Link', '<label><span>URL</span>' + inputField('url', block.url, 'https://example.com') + '</label>', '', block);
        } else if (block.type === 'resource') {
          fields =
            resourcePreview(block) +
            blockSettings(
              'Resource',
              mediaPickerControl('Resource', 'resource', resources, block.src),
              'visual-block-settings--wide',
              block
            );
        } else if (block.type === 'content_ref') {
          fields =
            contentRefPreview(block) +
            blockSettings(
              'Featured',
              '<label><span>Page or post</span><select data-field="target_id">' + contentOptions(contentItems, block.target_id) + '</select></label>' +
              '<label><span>Style</span><select data-field="style">' + optionList([
                { value: 'card', label: 'Compact card' },
                { value: 'feature', label: 'Large feature' }
              ], block.style) + '</select></label>',
              'visual-block-settings--wide',
              block
            );
        } else if (block.type === 'contributor_request') {
          fields =
            '<section class="visual-contributor-request-card">' +
            '<h2>' + inlineField('title', block.title, 'Request to become a contributor', 'visual-heading-text') + '</h2>' +
            textField('intro', block.intro, 'Short introduction...', 'visual-link-description') +
            '<div class="visual-contributor-request-grid" aria-hidden="true">' +
            '<span class="visual-contributor-request-field"></span>' +
            '<span class="visual-contributor-request-field"></span>' +
            '<span class="visual-contributor-request-field"></span>' +
            '<span class="visual-contributor-request-field"></span>' +
            '</div>' +
            '<span class="visual-contributor-request-button">' + escapeHtml(block.button_label || 'Submit request') + '</span>' +
            '</section>' +
            blockSettings(
              'Contributor Form',
              '<label><span>Button</span>' + inputField('button_label', block.button_label, 'Submit request') + '</label>',
              'visual-block-settings--side visual-block-settings--wide',
              block
            );
        } else if (block.type === 'social') {
          fields =
            '<div class="social-link visual-social-card">' + socialIcon(block.platform) + '<strong>' + inlineField('label', socialEditorHandle(block.platform, block.label, block.url), '@username', 'visual-social-label') + '</strong></div>' +
            blockSettings(
              'Social',
              '<div class="field-row">' +
              '<label><span>Platform</span><select data-field="platform">' + optionList([
                { value: 'instagram', label: 'Instagram' },
                { value: 'x', label: 'X' },
                { value: 'facebook', label: 'Facebook' },
                { value: 'youtube', label: 'YouTube' },
                { value: 'vimeo', label: 'Vimeo' },
                { value: 'website', label: 'Website' },
                { value: 'email', label: 'Email' }
              ], block.platform) + '</select></label>' +
              '<label><span>URL</span>' + inputField('url', block.url, 'https://... or mailto:...') + '</label>' +
              '</div>',
              '',
              block
            );
        } else {
          fields = blockSettings('Text', richTextToolbar(block.align) + fontToolControls(block), 'visual-block-settings--rich visual-block-settings--wide', block) + richTextField('text', block.html, block.text, 'Write directly on the page...', 'visual-rich-text ' + alignClass(block.align) + ' ' + textStyleClass(block)).replace('data-rich-field="true"', 'data-rich-field="true" data-style-target="true"');
        }

        node.innerHTML =
          '<div class="visual-block-head">' +
          '<button type="button" class="drag-handle" title="Drag section">Drag</button>' +
          '<span class="block-kind">' + escapeHtml(labelFor(block.type)) + '</span>' +
          '<button type="button" class="icon-button" data-edit-tools aria-label="Edit ' + escapeAttr(labelFor(block.type)) + ' tools" title="Edit ' + escapeAttr(labelFor(block.type)) + '">' + icon('edit') + '</button>' +
          '<button type="button" class="small secondary" data-duplicate>Duplicate</button>' +
          '<button type="button" class="small secondary" data-remove>Remove</button>' +
          '</div>' +
          fields;

        node.addEventListener('dragstart', function () {
          draggingIndex = index;
          node.classList.add('dragging');
        });
        node.addEventListener('dragend', function () {
          draggingIndex = null;
          node.classList.remove('dragging');
        });
        node.addEventListener('dragover', function (event) {
          event.preventDefault();
        });
        node.addEventListener('drop', function (event) {
          event.preventDefault();
          if (draggingIndex === null || draggingIndex === index) {
            return;
          }
          updateFromDom();
          var moved = blocks.splice(draggingIndex, 1)[0];
          blocks.splice(index, 0, moved);
          render();
          sync();
        });

        list.appendChild(node);
      });

      Array.prototype.forEach.call(list.querySelectorAll('[contenteditable="true"]'), function (field) {
        field.addEventListener('input', function () {
          if (field.getAttribute('data-rich-field') === 'true') {
            saveRichSelection(field);
            refreshRichToolbarState(field);
          }
          updateFromDom();
        });
        field.addEventListener('keyup', function () {
          if (field.getAttribute('data-rich-field') === 'true') {
            saveRichSelection(field);
            refreshRichToolbarState(field);
          }
        });
        field.addEventListener('mouseup', function () {
          if (field.getAttribute('data-rich-field') === 'true') {
            saveRichSelection(field);
            refreshRichToolbarState(field);
          }
        });
        field.addEventListener('focus', function () {
          if (field.getAttribute('data-rich-field') === 'true') {
            saveRichSelection(field);
            refreshRichToolbarState(field);
          }
        });
        field.addEventListener('blur', function () {
          if (field.getAttribute('data-rich-field') === 'true') {
            saveRichSelection(field);
          }
          updateFromDom();
        });
      });

      setupMediaPickerSearches(list);

      Array.prototype.forEach.call(list.querySelectorAll('input, select, textarea'), function (field) {
        field.addEventListener('input', function () {
          updateFromDom();
          var fieldName = field.getAttribute('data-field');
          if (fieldName === 'src') {
            var inputAltField = field.closest('.visual-block').querySelector('[data-field="alt"]');
            var inputAsset = mediaBySrc[field.value];
            if (inputAltField && inputAsset && !inputAltField.value) {
              inputAltField.value = inputAsset.alt || '';
              updateFromDom();
            }
          }
          if (fieldRequiresRender(fieldName)) {
            render();
          } else if (/^(font|text_size)$/.test(fieldName || '')) {
            var styleNode = field.closest('.visual-block');
            var styleIndex = styleNode ? Number(styleNode.getAttribute('data-index')) : -1;
            if (blocks[styleIndex]) {
              applyTextStyleToNode(styleNode, blocks[styleIndex]);
            }
          }
        });
        field.addEventListener('change', function () {
          updateFromDom();
          var fieldName = field.getAttribute('data-field');
          if (fieldName === 'src') {
            var changeAltField = field.closest('.visual-block').querySelector('[data-field="alt"]');
            var changeAsset = mediaBySrc[field.value];
            if (changeAltField && changeAsset && !changeAltField.value) {
              changeAltField.value = changeAsset.alt || '';
              updateFromDom();
            }
          }
          if (fieldRequiresRender(fieldName)) {
            render();
          } else if (/^(font|text_size)$/.test(fieldName || '')) {
            var styleNode = field.closest('.visual-block');
            var styleIndex = styleNode ? Number(styleNode.getAttribute('data-index')) : -1;
            if (blocks[styleIndex]) {
              applyTextStyleToNode(styleNode, blocks[styleIndex]);
            }
          }
        });
      });

      Array.prototype.forEach.call(list.querySelectorAll('[data-rich-command]'), function (button) {
        button.addEventListener('mousedown', function (event) {
          saveRichSelection(richFieldFor(button));
          event.preventDefault();
          event.stopPropagation();
        });
        button.addEventListener('click', function (event) {
          event.preventDefault();
          event.stopPropagation();
          applyRichCommand(button);
        });
      });

      Array.prototype.forEach.call(list.querySelectorAll('[data-rich-align]'), function (button) {
        button.addEventListener('mousedown', function (event) {
          saveRichSelection(richFieldFor(button));
          event.preventDefault();
          event.stopPropagation();
        });
        button.addEventListener('click', function (event) {
          event.preventDefault();
          event.stopPropagation();
          applyRichAlign(button);
        });
      });

      Array.prototype.forEach.call(list.querySelectorAll('[data-rich-color]'), function (button) {
        button.addEventListener('mousedown', function (event) {
          saveRichSelection(richFieldFor(button));
          event.preventDefault();
          event.stopPropagation();
        });
        button.addEventListener('click', function (event) {
          event.preventDefault();
          event.stopPropagation();
          applyRichColor(button);
        });
      });

      Array.prototype.forEach.call(list.querySelectorAll('[data-font-menu]'), function (button) {
        button.addEventListener('mousedown', function (event) {
          saveRichSelection(richFieldFor(button));
          event.preventDefault();
          event.stopPropagation();
        });
        button.addEventListener('click', function (event) {
          event.preventDefault();
          event.stopPropagation();
          toggleFontMenu(button);
        });
      });

      Array.prototype.forEach.call(list.querySelectorAll('[data-font-choice]'), function (button) {
        button.addEventListener('mousedown', function (event) {
          saveRichSelection(richFieldFor(button));
          event.preventDefault();
          event.stopPropagation();
        });
        button.addEventListener('click', function (event) {
          event.preventDefault();
          event.stopPropagation();
          applyFontChoice(button);
        });
      });

      Array.prototype.forEach.call(list.querySelectorAll('[data-font-step]'), function (button) {
        button.addEventListener('mousedown', function (event) {
          saveRichSelection(richFieldFor(button));
          event.preventDefault();
          event.stopPropagation();
        });
        button.addEventListener('click', function (event) {
          event.preventDefault();
          event.stopPropagation();
          applyFontStep(button);
        });
      });

      Array.prototype.forEach.call(list.querySelectorAll('[data-edit-tools]'), function (button) {
        button.addEventListener('mousedown', function (event) {
          var node = button.closest('.visual-block');
          var field = node ? node.querySelector('[data-rich-field="true"]') : null;
          if (field) {
            saveRichSelection(field);
            event.preventDefault();
          }
        });
        button.addEventListener('click', function (event) {
          event.preventDefault();
          event.stopPropagation();
          updateFromDom();
          var node = button.closest('.visual-block');
          var wasOpen = node.classList.contains('is-editing');
          Array.prototype.forEach.call(list.querySelectorAll('.visual-block.is-editing'), function (openNode) {
            openNode.classList.remove('is-editing');
          });
          if (!wasOpen) {
            node.classList.add('is-editing');
          }
          sync();
        });
      });

      Array.prototype.forEach.call(list.querySelectorAll('[data-close-tools]'), function (button) {
        button.addEventListener('click', function (event) {
          event.preventDefault();
          event.stopPropagation();
          updateFromDom();
          var node = button.closest('.visual-block');
          if (node) {
            node.classList.remove('is-editing');
          }
          sync();
        });
      });

      Array.prototype.forEach.call(list.querySelectorAll('[data-remove]'), function (button) {
        button.addEventListener('click', function () {
          updateFromDom();
          var index = Number(button.closest('.visual-block').getAttribute('data-index'));
          blocks.splice(index, 1);
          if (!blocks.length) {
            blocks.push({ type: 'text', text: '', html: '', align: 'left', font: 'serif', text_size: 'normal', spacing: 'default' });
          }
          render();
          sync();
        });
      });

      Array.prototype.forEach.call(list.querySelectorAll('[data-duplicate]'), function (button) {
        button.addEventListener('click', function () {
          updateFromDom();
          var index = Number(button.closest('.visual-block').getAttribute('data-index'));
          var copy = normalizeBlock(JSON.parse(JSON.stringify(blocks[index] || { type: 'text', text: '' })));
          blocks.splice(index + 1, 0, copy);
          render();
          sync();
        });
      });
    }

    Array.prototype.forEach.call(editor.querySelectorAll('[data-add-block]'), function (button) {
      button.addEventListener('click', function () {
        updateFromDom();
        var type = button.getAttribute('data-add-block');
        if (type === 'image') {
          blocks.push({ type: 'image', src: media[0] ? media[0].src : '', alt: media[0] ? (media[0].alt || '') : '', caption: '', layout: 'full', size: 'large' });
        } else if (type === 'image_text') {
          blocks.push({ type: 'image_text', src: media[0] ? media[0].src : '', alt: media[0] ? (media[0].alt || '') : '', caption: '', text: '', html: '', align: 'left', font: 'serif', text_size: 'normal', image_side: 'left' });
        } else if (type === 'video') {
          blocks.push({ type: 'video', url: '', title: '', caption: '' });
        } else if (type === 'link') {
          blocks.push({ type: 'link', url: '', label: '', description: '' });
        } else if (type === 'resource') {
          blocks.push({
            type: 'resource',
            src: resources[0] ? resources[0].src : '',
            label: resources[0] ? (resources[0].name || '') : '',
            description: resources[0] ? (resources[0].description || '') : '',
            button_label: 'Download'
          });
        } else if (type === 'content_ref') {
          blocks.push({ type: 'content_ref', target_id: contentItems[0] ? Number(contentItems[0].id || 0) : 0, style: 'card' });
        } else if (type === 'contributor_request') {
          blocks.push({ type: 'contributor_request', title: 'Request to become a contributor', intro: 'Submit your contact details, optional sample images, and why you want to join.', button_label: 'Submit request' });
        } else if (type === 'social') {
          blocks.push({ type: 'social', platform: 'instagram', url: '', label: '' });
        } else if (type === 'heading') {
          blocks.push({ type: 'heading', text: '', level: 2, align: 'left', font: 'serif', text_size: 'normal' });
        } else if (type === 'quote') {
          blocks.push({ type: 'quote', text: '', citation: '', align: 'left', font: 'serif', text_size: 'normal' });
        } else if (type === 'code') {
          blocks.push({ type: 'code', code: '', language: '' });
        } else if (type === 'divider') {
          blocks.push({ type: 'divider' });
        } else {
          blocks.push({ type: 'text', text: '', html: '', align: 'left', font: 'serif', text_size: 'normal' });
        }
        render();
        sync();
      });
    });

    setupSectionInsert();
    var insertSectionButton = editor.querySelector('[data-insert-section]');
    if (insertSectionButton) {
      insertSectionButton.addEventListener('click', function () {
        var picker = editor.querySelector('[data-section-picker]');
        insertReusableSection(picker ? picker.value : '');
      });
    }

    var form = editor.closest('form');
    if (form) {
      form.addEventListener('submit', updateFromDom);
    }

    render();
    sync();
  });
})();
JS

